window.HADITH_CACHE["abu-dawud_3"] = {"1501":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ عَطَاءٍ وَطَاوُسٍ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ احْتَجَمَ وَهُوَ مُحْرِمٌ","id":"Telah menceritakan kepada Kami [Ahmad bin Hanbal], telah menceritakan kepada Kami [Sufyan] dari ['Amr bin Dinar] dari ['Atha`] dan [Thawus] dari [Ibnu Abbas] bahwa Nabi shallallahu 'alaihi wasallam berbekam dalam keadaan berihram. "},"1502":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا هِشَامٌ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ احْتَجَمَ وَهُوَ مُحْرِمٌ فِي رَأْسِهِ مِنْ دَاءٍ كَانَ بِهِ","id":"Telah menceritakan kepada Kami [Utsman bin Abu Syaibah] telah menceritakan kepada Kami [Yazid bin Harun], telah mengabarkan kepada Kami [Hisyam] dari [Ikrimah] dari [Ibnu Abbas] bahwa Rasulullah shallAllahu wa'alaihi wa sallam dalam keadaan berihram berbekam pada kepalanya karena suatu penyakit yang beliau derita. "},"1503":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ قَتَادَةَ عَنْ أَنَسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ احْتَجَمَ وَهُوَ مُحْرِمٌ عَلَى ظَهْرِ الْقَدَمِ مِنْ وَجَعٍ كَانَ بِهِقَالَ أَبُو دَاوُد سَمِعْت أَحْمَدَ قَالَ ابْنُ أَبِي عَرُوبَةَ أَرْسَلَهُ يَعْنِي عَنْ قَتَادَةَ","id":"Telah menceritakan kepada Kami [Ahmad bin Hanbal], telah menceritakan kepada Kami [Abdur Razzaq], telah mengabarkan kepada Kami [Ma'mar] dari [Qatadah] dari [Anas] bahwa Rasulullah shallAllahu wa'alaihi wa sallam dalam keadaan berihram berbekam pada punggung telapak kaki karena suatu penyakit yang beliau derita. Abu Daud berkata; saya mendengar [Ahmad] berkata; [Ibnu 'Arubah] memursalkan hadits tersebut dari [Qatadah]. "},"1504":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا سُفْيَانُ عَنْ أَيُّوبَ بْنِ مُوسَى عَنْ نُبَيْهِ بْنِ وَهْبٍ قَالَاشْتَكَى عُمَرُ بْنُ عُبَيْدِ اللَّهِ بْنِ مَعْمَرٍ عَيْنَيْهِ فَأَرْسَلَ إِلَى أَبَانَ بْنِ عُثْمَانَ قَالَ سُفْيَانُ وَهُوَ أَمِيرُ الْمَوْسِمِ مَا يَصْنَعُ بِهِمَا قَالَ اضْمِدْهُمَا بِالصَّبِرِ فَإِنِّي سَمِعْتُ عُثْمَانَ رَضِيَ اللَّهُ عَنْهُ يُحَدِّثُ ذَلِكَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَحَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ ابْنِ عُلَيَّةَ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ نُبَيْهِ بْنِ وَهْبٍ بِهَذَا الْحَدِيثِ","id":"Telah menceritakan kepada Kami [Ahmad bin Hanbal], telah menceritakan kepada Kami [Sufyan] dari [Ayyub bin Musa] dari [Nubaih bin Wahb], ia berkata; Umar bin 'Ubaidullah bin Ma'mar merasakan sakit kedua matanya, kemudian ia mengirim utusan kepada [Aban bin Utsman]. -Sufyan berkata; ia adalah pemimpin haji- Umar bertanya apa yang harus ia lakukan terhadap kedua mata tersebut? Aban berkata; balutlah keduanya menggunakan shabir (suatu bahan yang rasanya pahit) karena aku mendengar [Utsman] radliallahu 'anhu menceritakan hal tersebut dari Rasulullah shallla Allahu 'alaihi wa sallam. Telah menceritakan kepada Kami [Utsman bin Abu Syaibah], telah menceritakan kepada Kami [Ismail bin Ibrahim bin 'Ulayyah] dari [Ayyub] dari [Nafi'] dari [Nubaih bin Wahb] dengan hadits ini. "},"1505":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ إِبْرَاهِيمَ بْنِ عَبْدِ اللَّهِ بْنِ حُنَيْنٍ عَنْ أَبِيهِأَنَّ عَبْدَ اللَّهِ بْنَ عَبَّاسٍ وَالْمِسْوَرَ بْنَ مَخْرَمَةَ اخْتَلَفَا بِالْأَبْوَاءِ فَقَالَ ابْنُ عَبَّاسٍ يَغْسِلُ الْمُحْرِمُ رَأْسَهُ وَقَالَ الْمِسْوَرُ لَا يَغْسِلُ الْمُحْرِمُ رَأْسَهُ فَأَرْسَلَهُ عَبْدُ اللَّهِ بْنُ عَبَّاسٍ إِلَى أَبِي أَيُّوبَ الْأَنْصَارِيِّ فَوَجَدَهُ يَغْتَسِلُ بَيْنَ الْقَرْنَيْنِ وَهُوَ يُسْتَرُ بِثَوْبٍ قَالَ فَسَلَّمْتُ عَلَيْهِ قَالَ مَنْ هَذَا قُلْتُ أَنَا عَبْدُ اللَّهِ بْنُ حُنَيْنٍ أَرْسَلَنِي إِلَيْكَ عَبْدُ اللَّهِ بْنُ عَبَّاسٍ أَسْأَلُكَ كَيْفَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَغْسِلُ رَأْسَهُ وَهُوَ مُحْرِمٌ قَالَ فَوَضَعَ أَبُو أَيُّوبَ يَدَهُ عَلَى الثَّوْبِ فَطَأْطَأَهُ حَتَّى بَدَا لِي رَأْسُهُ ثُمَّ قَالَ لِإِنْسَانٍ يَصُبُّ عَلَيْهِ اصْبُبْ قَالَ فَصَبَّ عَلَى رَأْسِهِ ثُمَّ حَرَّكَ أَبُو أَيُّوبَ رَأْسَهُ بِيَدَيْهِ فَأَقْبَلَ بِهِمَا وَأَدْبَرَ ثُمَّ قَالَ هَكَذَا رَأَيْتُهُ يَفْعَلُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada Kami [Abdullah bin Maslamah] dari [Malik] dari [Zaid bin Aslam] dari [Ibrahim bin Abdullah bin Hunain] dari [ayahnya] bahwa Abdullah bin Abbas serta Al Miswar bin Makhramah telah berselisih di Abwa`. Ibnu Abbas berkata; orang yang berihram boleh mencuci kepalanya, sedangkan Al Miswar berkata; tidak boleh orang yang berihram mencuci rambut kepalanya. Kemudian Abdullah bin Abbas mengutusku kepada [Abu Ayyub Al Anshari], kemudian aku mendapatinya sedang mandi di antara dua dinding sumur, dan ia ditutupi menggunakan kain. Abdullah bin Hunain berkata; kemudian aku mengucapkan salam kepadanya, ia berkata; siapakah ini? Aku katakan; saya, Abdullah bin Hunain, Abdullah bin Abbas telah mengutusku kepada anda untuk bertanya kepada anda; bagaimana Rasulullah shallAllahu wa'alaihi wa sallam mencuci kepalanya sementara beliau dalam keadaan berihram? Abdullah bin Hunain berkata; kemudian Abu Ayyub meletakkan tangannya pada kain dan merendahkan hingga nampak kepalanya, kemudian kemudian ia berkata kepada seseorang agar menuangkan air ke kepalanya; tuangkan! Umar berkata; kemudian ia menungankan pada kepalannya kemudian Abu Ayyub menggerakkan kepalanya dengan kedua tangannya, ia menggerakkan kedepan dan ke belakang. Kemudian berkata; demikianlah aku melihat beliau shallallahu 'alaihi wasallam melakukannya. "},"1506":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ نُبَيْهِ بْنِ وَهْبٍ أَخِي بَنِي عَبْدِ الدَّارِأَنَّ عُمَرَ بْنَ عُبَيْدِ اللَّهِ أَرْسَلَ إِلَى أَبَانَ بْنِ عُثْمَانَ بْنِ عَفَّانَ يَسْأَلُهُ وَأَبَانُ يَوْمَئِذٍ أَمِيرُ الْحَاجِّ وَهُمَا مُحْرِمَانِ إِنِّي أَرَدْتُ أَنْ أُنْكِحَ طَلْحَةَ بْنَ عُمَرَ ابْنَةَ شَيْبَةَ بْنِ جُبَيْرٍ فَأَرَدْتُ أَنْ تَحْضُرَ ذَلِكَ فَأَنْكَرَ ذَلِكَ عَلَيْهِ أَبَانُ وَقَالَ إِنِّي سَمِعْتُ أَبِي عُثْمَانَ بْنَ عَفَّانَ يَقُولُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَنْكِحُ الْمُحْرِمُ وَلَا يُنْكِحُحَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ أَنَّ مُحَمَّدَ بْنَ جَعْفَرٍ حَدَّثَهُمْ حَدَّثَنَا سَعِيدٌ عَنْ مَطَرٍ ويَعْلَى بْنِ حَكِيمٍ عَنْ نَافِعٍ عَنْ نُبَيْهِ بْنِ وَهْبٍ عَنْ أَبَانَ بْنِ عُثْمَانَ عَنْ عُثْمَانَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَكَرَ مِثْلَهُ زَادَ وَلَا يَخْطُبُ","id":"Telah menceritakan kepada Kami [Al Qa'nabi] dari [Malik] dari [Nafi'] dari [Nubaih bin Wahb] saudara Bani Abduddar bahwa Umar bin 'Ubaidullah mengutusnya datang kepada [Aban bin Utsman bin 'Affan] untuk bertanya kepadanya, dan pada saat itu Aban adalah pemimpin haji, dan mereka berdua sedang berihram. Ia berkata; aku ingin menikahkan anak wanita Syaibah bin Jubair dengan Thalhah bin Umar, aku ingin engkau menghadirinya. Kemudian Aban mengingkari hal tersebut, dan berkata; sesungguhnya aku mendengar ayahku yaitu [Utsman bin Affan] berkata; Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Orang yang berihram tidak boleh menikah dan tidak boleh menikahkan.\" Telah menceritakan kepada Kami [Qutaibah bin Sa'id] bahwa [Muhammad bin Ja'far] telah menceritakan kepada mereka, telah menceritakan kepada Kami [Sa'id] dari [Mathar] dan [Ya'la bin Hakim] dari [Nafi'] dari [Nubaih bin Wahb] dari [Aban bin Utsman] dari [Utsman] bahwa Rasulullah shallAllahu wa'alaihi wa sallam ….. -ia menyebutkan seperti hadits tersebut, dan menambahkan kata: dan tidak boleh melamar."},"1507":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ حَبِيبِ بْنِ الشَّهِيدِ عَنْ مَيْمُونِ بْنِ مِهْرَانَ عَنْ يَزِيدَ بْنِ الْأَصَمِّ ابْنِ أَخِي مَيْمُونَةَ عَنْ مَيْمُونَةَ قَالَتْتَزَوَّجَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ حَلَالَانِ بِسَرِفَ","id":"Telah menceritakan kepada Kami [Musa bin Ismail] telah menceritakan kepada Kami [Hammad] dari [Habib bin Asy Syahid] dari [Maimun bin Mihran] dari [Yazid bin Al Asham] anak saudara laki-laki Maimunah, dari [Maimunah], ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam menikahiku di Saraf sementara Kami dalam keadaan tidak berihram. "},"1508":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَزَوَّجَ مَيْمُونَةَ وَهُوَ مُحْرِمٌحَدَّثَنَا ابْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا سُفْيَانُ عَنْ إِسْمَعِيلَ بْنِ أُمَيَّةَ عَنْ رَجُلٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ قَالَ وَهِمَ ابْنُ عَبَّاسٍ فِي تَزْوِيجِ مَيْمُونَةَ وَهُوَ مُحْرِمٌ","id":"Telah menceritakan kepada Kami [Musaddad] telah menceritakan kepada Kami [Hammad bin Zaid] dari [Ayyub] dari [Ikrimah] dari [Ibnu Abbas] bahwa Nabi shallallahu 'alaihi wasallam menikahi Maimunah dalam keadaan berihram. Telah menceritakan kepada Kami Ibnu Basysyar, telah menceritakan kepada Kami Abdurrahman bin Mahdi, telah menceritakan kepada Kami Sufyan dari Ismail bin Umayyah dari seorang laki-laki dari Sa'id bin Al Musayyab, ia berkata; Ibnu Abbas telah salah mengenai pernikahan Maimunah dan beliau dalam keadaan berihram. "},"1509":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِسُئِلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَمَّا يَقْتُلُ الْمُحْرِمُ مِنْ الدَّوَابِّ فَقَالَ خَمْسٌ لَا جُنَاحَ فِي قَتْلِهِنَّ عَلَى مَنْ قَتَلَهُنَّ فِي الْحِلِّ وَالْحُرُمِ الْعَقْرَبُ وَالْفَأْرَةُ وَالْحِدَأَةُ وَالْغُرَابُ وَالْكَلْبُ الْعَقُورُ","id":"Telah menceritakan kepada Kami [Ahmad bin Hanbal], telah menceritakan kepada Kami [Sufyan bin 'Uyainah] dari [Az Zuhri] dari [Salim] dari [ayahnya] Nabi shallallahu 'alaihi wasallam ditanya mengenai apa saja yang boleh dibunuh orang yang berihram dari binatang melata? Kemudian beliau berkata: \"Lima binatang yang tidak ada dosa bagi orang yang membunuhnya di luar tanah haram dan di tanah haram, yaitu; kalajengking, tikus, rajawali, gagak, dan anjing buas.\""},"1510":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ بَحْرٍ حَدَّثَنَا حَاتِمُ بْنُ إِسْمَعِيلَ حَدَّثَنِي مُحَمَّدُ بْنُ عَجْلَانَ عَنْ الْقَعْقَاعِ بْنِ حَكِيمٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ خَمْسٌ قَتْلُهُنَّ حَلَالٌ فِي الْحُرُمِ الْحَيَّةُ وَالْعَقْرَبُ وَالْحِدَأَةُ وَالْفَأْرَةُ وَالْكَلْبُ الْعَقُورُ","id":"Telah menceritakan kepada Kami [Ali bin Bahr], telah menceritakan kepada Kami [Hatim bin Isma'il], telah menceritakan kepada Kami [Muhammad bin 'Ajlan] dari [Al Qa'qa' bin Hakim] dari [Abu Shalih] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: lima binatang yang boleh dibunuh di tanah suci adalah: ular, kalajengking, burung rajawali, tikus dan anjing buas. "},"1511":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا هُشَيْمٌ حَدَّثَنَا يَزِيدُ بْنُ أَبِي زِيَادٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ أَبِي نُعْمٍ الْبَجَلِيُّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ عَمَّا يَقْتُلُ الْمُحْرِمُ قَالَ الْحَيَّةُ وَالْعَقْرَبُ وَالْفُوَيْسِقَةُ وَيَرْمِي الْغُرَابَ وَلَا يَقْتُلُهُ وَالْكَلْبُ الْعَقُورُ وَالْحِدَأَةُ وَالسَّبُعُ الْعَادِي","id":"Telah menceritakan kepada Kami [Ahmad bin Hanbal], telah menceritakan kepada Kami [Husyaim] telah menceritakan kepada Kami [Yazid bin Abu Ziyad] telah menceritakan kepada Kami [Abdurrahman bin Abu Nu'm Al Bajali] dari [Abu Sa'id Al Khudri] bahwa Nabi shallallahu 'alaihi wasallam ditanya mengenai apa yang boleh dibunuh orang yang berihram. Beliau berkata: \"Ular, kalajengking, binatang menjijikkan (tikus), -dan beliau melempar gagak dan tidak membunuhnya- serta anjing buas, rajawali dan binatang buas yang biasa.\""},"1512":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ حَدَّثَنَا سُلَيْمَانُ بْنُ كَثِيرٍ عَنْ حُمَيْدٍ الطَّوِيلِ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ الْحَارِثِ عَنْ أَبِيهِوَكَانَ الْحَارِثُ خَلِيفَةُ عُثْمَانَ عَلَى الطَّائِفِ فَصَنَعَ لِعُثْمَانَ طَعَامًا فِيهِ مِنْ الْحَجَلِ وَالْيَعَاقِيبِ وَلَحْمِ الْوَحْشِ قَالَ فَبَعَثَ إِلَى عَلِيِّ بْنِ أَبِي طَالِبٍ فَجَاءَهُ الرَّسُولُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَخْبِطُ لِأَبَاعِرَ لَهُ فَجَاءَهُ وَهُوَ يَنْفُضُ الْخَبَطَ عَنْ يَدِهِ فَقَالُوا لَهُ كُلْ فَقَالَ أَطْعِمُوهُ قَوْمًا حَلَالًا فَأَنَا حُرُمٌ فَقَالَ عَلِيٌّ رَضِيَ اللَّهُ عَنْهُ أَنْشُدُ اللَّهَ مَنْ كَانَ هَا هُنَا مِنْ أَشْجَعَ أَتَعْلَمُونَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَهْدَى إِلَيْهِ رَجُلٌ حِمَارَ وَحْشٍ وَهُوَ مُحْرِمٌ فَأَبَى أَنْ يَأْكُلَهُ قَالُوا نَعَمْ","id":"Telah menceritakan kepada Kami [Muhammad bin Katsir], telah menceritakan kepada Kami [Sulaiman bin Katsir] dari [Humaid Ath Thawil] dari [Ishaq bin Abdullah bin Al Harits] dari [ayahnya] dan Al Harits adalah wakil Utsman di Thaif, kemudian ia membuat makanan untuk Utsman yang berisi burung puyuh betina dan jantan, serta daging keledai liar. Ia berkata; kemudian Al Harits mengirim utusan kepada [Ali bin Abu Thalib]. Kemudian Rasulullah shallAllahu wa'alaihi wa sallam datang kepadanya sementara ia sedang merontokkan daun-daun pohon untuk makan unta-untanya, beliau datang kepadanya sementara ia menghilangkan daun-daun yang rontok tersebut dari tangannya. Mereka berkata kepadanya; makanlah. Kemudian ia berkata; berikan makanan tersebut kepada orang-orang yang tidak berihram, aku sedang berihram. Kemudian Ali berkata; aku bertanya dengan nama Allah kepada orang-orang di sini yang berasal dari Asyja', tahukah kalian bahwa Rasulullah shallAllahu wa'alaihi wa sallam telah diberi keledai liar oleh seseorang sementara beliau sedang berihram, dan beliau enggan untuk memakannya? Mereka berkata; ya. "},"1513":{"ar":"حَدَّثَنَا أَبُو سَلَمَةَ مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ قَيْسٍ عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍ أَنَّهُ قَالَ يَا زَيْدَ بْنَ أَرْقَمَهَلْ عَلِمْتَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُهْدِيَ إِلَيْهِ عَضُدُ صَيْدٍ فَلَمْ يَقْبَلْهُ وَقَالَ إِنَّا حُرُمٌ قَالَ نَعَمْ","id":"Telah menceritakan kepada Kami [Abu Salamah Mua bin Isma'il], telah menceritakan kepada Kami [Hammad] dari [Qais] dari ['Atha`] dari [Ibnu Abbas] bahwa ia berkata; wahai [Zaid bin Arqam], apakah engkau mengetahui bahwa Rasulullah shallAllahu wa'alaihi wa sallam telah diberi hadiah paha binatang buruan dan beliau tidak menerimannya, dan beliau mengatakan; sesungguhnya Kami sedang berihram? Ia berkata; ya. "},"1514":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا يَعْقُوبُ يَعْنِي الْإِسْكَنْدَرَانِيَّ الْقَارِيَّ عَنْ عَمْرٍو عَنْ الْمُطَّلِبِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ صَيْدُ الْبَرِّ لَكُمْ حَلَالٌ مَا لَمْ تَصِيدُوهُ أَوْ يُصَدْ لَكُمْقَالَ أَبُو دَاوُد إِذَا تَنَازَعَ الْخَبَرَانِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُنْظَرُ بِمَا أَخَذَ بِهِ أَصْحَابُهُ","id":"Telah menceritakan kepada Kami [Qutaibah bin Sa'id], telah menceritakan kepada Kami [Ya'qub yaitu Al Iskandarani Al Qari] dari ['Amr] dari [Al Muththalib] dari [Jabir bin Abdullah] radliallahu 'anhu berkata: aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hewan buruan darat adalah halal bagi kalian selama kalian bukan yang berburu atau tidak diburu untuk kalian.\" Abu Daud berkata; apabila dua hadits dari Nabi Shalla Allahu 'alaihi wa sallam bertentangan maka dilihat manakah uang diambil para sahabatnya. "},"1515":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ أَبِي النَّضْرِ مَوْلَى عُمَرَ بْنِ عُبَيْدِ اللَّهِ التَّيْمِيِّ عَنْ نَافِعٍ مَوْلَى أَبِي قَتَادَةَ الْأَنْصَارِيِّ عَنْ أَبِي قَتَادَةَأَنَّهُ كَانَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى إِذَا كَانَ بِبَعْضِ طَرِيقِ مَكَّةَ تَخَلَّفَ مَعَ أَصْحَابٍ لَهُ مُحْرِمِينَ وَهُوَ غَيْرُ مُحْرِمٍ فَرَأَى حِمَارًا وَحْشِيًّا فَاسْتَوَى عَلَى فَرَسِهِ قَالَ فَسَأَلَ أَصْحَابَهُ أَنْ يُنَاوِلُوهُ سَوْطَهُ فَأَبَوْا فَسَأَلَهُمْ رُمْحَهُ فَأَبَوْا فَأَخَذَهُ ثُمَّ شَدَّ عَلَى الْحِمَارِ فَقَتَلَهُ فَأَكَلَ مِنْهُ بَعْضُ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبَى بَعْضُهُمْ فَلَمَّا أَدْرَكُوا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَأَلُوهُ عَنْ ذَلِكَ فَقَالَ إِنَّمَا هِيَ طُعْمَةٌ أَطْعَمَكُمُوهَا اللَّهُ تَعَالَى","id":"Telah menceritakan kepada Kami [Abdullah bin Maslamah] dari [Malik] dari [Abu An Nadhr] mantan budak Umar bin 'Ubaidullah At Taimi dari [Nafi'] mantan budak Abu Qatadah Al Anshari, dari [Abu Qatadah] bahwa ia pernah bersama Rasulullah shallAllahu wa'alaihi wa sallam hingga setelah beliau berada di sebagian jalan di Mekkah ia tertinggal bersama para sahabatnya yang sedang berihram, sementara ia tidak berihram. Kemudian ia melihat seekor keledai liar. Lalu ia naik kudanya dan meminta kepada para sahabatnya agar memberikan cambuk kepadanya. Kemudian mereka menolak, lalu ia meminta tombaknya kepada mereka, kemudian mereka menolak. Lalu ia mengambilnya kemudian mengejar keledai tersebut dan membunuhnya. Sebagian sahabat Rasulullah shallAllahu wa'alaihi wa sallam memakannya, dan sebagian yang lain menolak. Kemudian tatkala mereka telah mendapati Rasulullah shallAllahu wa'alaihi wa sallam, maka mereka bertanya kepadanya mengenai hal tersebut, lalu beliau bersabda: sesungguhnya itu adalah makanan yang telah Allah ta'ala berikan kepada kalian. "},"1516":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا حَمَّادٌ عَنْ مَيْمُونِ بْنِ جَابَانَ عَنْ أَبِي رَافِعٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْجَرَادُ مِنْ صَيْدِ الْبَحْرِ","id":"Telah menceritakan kepada Kami [Muhammad bin Isa] telah menceritakan kepada Kami [Hammad] dari [Maimun bin Jaban] dari [Abu Rafi'] dari [Abu Hurairah] dari Nabi shalla Allahu 'alaihi wa sallam, beliau bersabda: belalang adalah termasuk binatang buruan laut. "},"1517":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ حَبِيبٍ الْمُعَلِّمِ عَنْ أَبِي الْمُهَزِّمِ عَنْ أَبِي هُرَيْرَةَ قَالَأَصَبْنَا صِرْمًا مِنْ جَرَادٍ فَكَانَ رَجُلٌ مِنَّا يَضْرِبُ بِسَوْطِهِ وَهُوَ مُحْرِمٌ فَقِيلَ لَهُ إِنَّ هَذَا لَا يَصْلُحُ فَذُكِرَ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّمَا هُوَ مِنْ صَيْدِ الْبَحْرِسَمِعْت أَبَا دَاوُد يَقُولُ أَبُو الْمُهَزِّمِ ضَعِيفٌ وَالْحَدِيثَانِ جَمِيعًا وَهْمٌ","id":"Telah menceritakan kepada Kami [Musaddad], telah menceritakan kepada Kami [Abdul Warits] dari [Habib Al Mu'allim] dari [Abu Al Muhazzim] dari [Abu Hurairah], ia berkata; Kami mendapatkan sekelompok belalang, dan seseorang diantara Kami memukul menggunakan cambuknya sementara ia sedang berihram. Kemudian dikatakan kepadanya; sesungguhnya hal ini tidak layak. Kemudian hal tersebut diceritakan kepada Nabi shallallahu 'alaihi wasallam, lalu beliau bersabda: \"Sesungguhnya belalang merupakan diantara buruan laut.\" Aku mendengar Abu Daud berkata; Abu Al Muhazzim adalah dha'if, dan kedua hadits tersebut seluruhnya adalah lemah. "},"1518":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ مَيْمُونِ بْنِ جَابَانَ عَنْ أَبِي رَافِعٍ عَنْ كَعْبٍ قَالَالْجَرَادُ مِنْ صَيْدِ الْبَحْرِ","id":"Telah menceritakan kepada Kami [Musa bin Isma'il], telah menceritakan kepada Kami [Hammad] dari [Maimun bin Jaban] dari [Rafi'] dari [Ka'bin], ia berkata; belalang merupakan diantara buruan laut. "},"1519":{"ar":"حَدَّثَنَا وَهْبُ بْنُ بَقِيَّةَ عَنْ خَالِدٍ الطَّحَّانِ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ أَبِي قِلَابَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ كَعْبِ بْنِ عُجْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ بِهِ زَمَنَ الْحُدَيْبِيَةِ فَقَالَ قَدْ آذَاكَ هَوَامُّ رَأْسِكَ قَالَ نَعَمْ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ احْلِقْ ثُمَّ اذْبَحْ شَاةً نُسُكًا أَوْ صُمْ ثَلَاثَةَ أَيَّامٍ أَوْ أَطْعِمْ ثَلَاثَةَ آصُعٍ مِنْ تَمْرٍ عَلَى سِتَّةِ مَسَاكِينَ","id":"Telah menceritakan kepada Kami [Wahb bin Baqiyyah] dari [Khalid Ath Thahhan] dari [Khalid Al Hadzdza`] dari [Abu Qilabah] dari [Abdurrahman bin Abu Laila] dari [Ka'b bin 'Ujrah] bahwa Rasulullah shallAllahu wa'alaihi wa sallam melewatinya pada zaman terjadinya perjanjian Hudaibiyah. Kemudian beliau berkata: Sungguh kutu kepalamu telah mengganggumu. Ia berkata; ya. Kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Gundullah rambutmu, kemudian sembelihlah kambing sebagai kurban, atau berpuasalah tiga hari, atau berilah makan tiga sha' kurma kepada enam orang miskin!\""},"1520":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ دَاوُدَ عَنْ الشَّعْبِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ كَعْبِ بْنِ عُجْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَهُ إِنْ شِئْتَ فَانْسُكْ نَسِيكَةً وَإِنْ شِئْتَ فَصُمْ ثَلَاثَةَ أَيَّامٍ وَإِنْ شِئْتَ فَأَطْعِمْ ثَلَاثَةَ آصُعٍ مِنْ تَمْرٍ لِسِتَّةِ مَسَاكِينَ","id":"Telah menceritakan kepada Kami [Musa bin Isma'i] telah menceritakan kepada Kami [Hammad] dari [Daud] dari [Asy Sya'bi] dari [Abdurrahman bin Abu Laila] dari [Ka'b bin 'Ujrah] bahwa Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Apabila engkau menghendaki maka sembelihlah hewan sembelihan, dan apabila engkau menghendaki maka berpuasalah tiga hari, dan jika engkau menghendaki maka berilah makan tiga sha' kurma kepada enam orang miskin.\""},"1521":{"ar":"حَدَّثَنَا ابْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الْوَهَّابِ ح و حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ وَهَذَا لَفْظُ ابْنِ الْمُثَنَّى عَنْ دَاوُدَ عَنْ عَامِرٍ عَنْ كَعْبِ بْنِ عُجْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ بِهِ زَمَنَ الْحُدَيْبِيَةِ فَذَكَرَ الْقِصَّةَ فَقَالَ أَمَعَكَ دَمٌ قَالَ لَا قَالَ فَصُمْ ثَلَاثَةَ أَيَّامٍ أَوْ تَصَدَّقْ بِثَلَاثَةِ آصُعٍ مِنْ تَمْرٍ عَلَى سِتَّةِ مَسَاكِينَ بَيْنَ كُلِّ مِسْكِينَيْنِ صَاعٌ","id":"Telah menceritakan kepada Kami [Ibnu Al Mutsanna] telah menceritakan kepada Kami [Abdul Wahhab]. Telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada Kami [Nashr bin Ali], telah menceritakan kepada Kami [Yazid bin Zurai'] dan ini adalah lafazh Ibnu Al Mutsanna dari [Daud] dari ['Amir] dari [Ka'b bin 'Ujrah] bahwa Rasulullah shallAllahu wa'alaihi wa sallam melewatinya pada zaman terjadinya perjanjian Hudaibiyah….. kemudian ia menyebutkan kisah tersebut. Kemudian beliau berkata: \"Apakah engkau membawa dam (kambing atau sejenisnya)?\" Ia berkata; tidak. Beliau bersabda: \"Berpuasalah tiga hari atau bersedekahlah tiga sha' kurma kepada enam orang miskin, untuk setiap dua orang miskin satu sha'.\""},"1522":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا اللَّيْثُ عَنْ نَافِعٍ أَنَّ رَجُلًا مِنْ الْأَنْصَارِ أَخْبَرَهُ عَنْ كَعْبِ بْنِ عُجْرَةَوَكَانَ قَدْ أَصَابَهُ فِي رَأْسِهِ أَذًى فَحَلَقَ فَأَمَرَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُهْدِيَ هَدْيًا بَقَرَةً","id":"Telah menceritakan kepada Kami [Qutaibah bin Sa'id], telah menceritakan kepada Kami [Al Laits] dari [Nafi'] bahwa [seorang laki-laki anshar] telah mengabarkan kepadanya dari [Ka'b bin 'Ujrah] dan ia telah tertimpa sesuatu yang mengganggu. Kemudian Nabi shallallahu 'alaihi wasallam memerintahkannya agar menyembelih hewan kurban sapi. "},"1523":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مَنْصُورٍ حَدَّثَنَا يَعْقُوبُ حَدَّثَنِي أَبِي عَنْ ابْنِ إِسْحَقَ حَدَّثَنِي أَبَانُ يَعْنِي ابْنَ صَالِحٍ عَنْ الْحَكَمِ بْنِ عُتَيْبَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ كَعْبِ بْنِ عُجْرَةَ قَالَأَصَابَنِي هَوَامُّ فِي رَأْسِي وَأَنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَامَ الْحُدَيْبِيَةِ حَتَّى تَخَوَّفْتُ عَلَى بَصَرِي فَأَنْزَلَ اللَّهُ سُبْحَانَهُ وَتَعَالَى فِيَّ{ فَمَنْ كَانَ مِنْكُمْ مَرِيضًا أَوْ بِهِ أَذًى مِنْ رَأْسِهِ }الْآيَةَ فَدَعَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لِي احْلِقْ رَأْسَكَ وَصُمْ ثَلَاثَةَ أَيَّامٍ أَوْ أَطْعِمْ سِتَّةَ مَسَاكِينَ فَرَقًا مِنْ زَبِيبٍ أَوْ انْسُكْ شَاةً فَحَلَقْتُ رَأْسِي ثُمَّ نَسَكْتُحَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ عَبْدِ الْكَرِيمِ بْنِ مَالِكٍ الْجَزَرِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ كَعْبِ بْنِ عُجْرَةَ فِي هَذِهِ الْقِصَّةِ زَادَ أَيُّ ذَلِكَ فَعَلْتَ أَجْزَأَ عَنْكَ","id":"Telah menceritakan kepada Kami [Muhammad bin Manshur], telah menceritakan kepada Kami [Ya'qub], telah menceritakan kepadaku [ayahku], dari [Ibnu Ishaq], telah menceritakan kepadaku [Aban yaitu Ibnu Shalih] dari [Al Hakam bin 'Utaibah] dari [Abdurrahman bin Abu Laila], dari [Ka'b 'Ujrah], ia berkata; aku terserang kutu kepala, sementara aku bersama Rasulullah shallAllahu wa'alaihi wa sallam pada tahun terjadinya perjanjian Hudaibiyah hingga aku mengkhawatirkan mataku. Kemudian Allah subhanahu wa ta'ala menurunkan wahyu mengenaiku: \"Jika ada di antaramu yang sakit atau ada gangguan di kepalanya (lalu ia bercukur), maka wajiblah atasnya berfid-yah, yaitu: berpuasa atau bersedekah atau berkorban.\" Kemudian Rasulullah shallAllahu wa'alaihi wa sallam memanggilku dan berkata kepadaku: \"Gundullah rambutmu, dan berpuasalah tiga hari atau berilah makan enam orang miskin, satu faraq kismis, atau sembelihlah seekor kambing!\" kemudian aku menggundul rambutku dan menyembelih kurban. Telah menceritakan kepada Kami [Abdullah bin Maslamah Al Qa'nabi] dari [Malik] dari [Abdul Karim bin Malik Al Jazari] dari [Abdurrahman bin Abu Laila] dari [Ka'b bin 'Ujrah] dalam kisah ini, ia menambahkan kata: \"Apapun yang engkau lakukan dari hal tersebut maka telah sah darimu.\""},"1524":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ حَجَّاجٍ الصَّوَّافِ حَدَّثَنِي يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ عِكْرِمَةَ قَالَ سَمِعْتُ الْحَجَّاجَ بْنَ عَمْرٍو الْأَنْصَارِيَّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كُسِرَ أَوْ عَرِجَ فَقَدْ حَلَّ وَعَلَيْهِ الْحَجُّ مِنْ قَابِلٍقَالَ عِكْرِمَةُ سَأَلْتُ ابْنَ عَبَّاسٍ وَأَبَا هُرَيْرَةَ عَنْ ذَلِكَ فَقَالَا صَدَقَ حَدَّثَنَا مُحَمَّدُ بْنُ الْمُتَوَكِّلِ الْعَسْقَلَانِيُّ وَسَلَمَةُ قَالَا حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ عِكْرِمَةَ عَنْ عَبْدِ اللَّهِ بْنِ رَافِعٍ عَنْ الْحَجَّاجِ بْنِ عَمْرٍو عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ كُسِرَ أَوْ عَرِجَ أَوْ مَرِضَ فَذَكَرَ مَعْنَاهُ قَالَ سَلَمَةُ بْنُ شَبِيبٍ قَالَ أَنْبَأَنَا مَعْمَرٌ","id":"Telah menceritakan kepada Kami [Musaddad], telah menceritakan kepada Kami [Yahya] dari [Hajjaj Ash Shawwaf], telah menceritakan kepadaku [Yahya bin Abu Katsir] dari [Ikrimah], ia berkata; saya mendengar [Al Hajjaj bin 'Amr Al Anshari] berkata; Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Barang siapa yang kakinya retak atau pincang maka ia telah bertahallul, dan ia wajib melakukan haji pada tahun yang akan datang.\" [Ikrimah] berkata; aku bertanya kepada [Ibnu Abbas] dan [Abu Hurairah] mengenai hal tersebut, kemudian mereka berkata; benar. Telah menceritakan kepada Kami [Muhammad bin Al Mutawakkil Al 'Asqalani] dan [Salamah], mereka berkata; telah menceritakan kepada Kami [Abdurrazzaq] dari [Ma'mar] dari [Yahya bin Abu Katsir] dari [Ikrimah] dari [Abdullah bin Rafi'] dari [Al Hajjaj bin 'Amr] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barang siapa yang tulangnya retak, atau pincang atau sakit….. kemudian ia menyebutkan hadits yang semakna denganya. Salamah bin Syabib telah berkata; telah memberitakan kepada Kami Ma'mar."},"1525":{"ar":"حَدَّثَنَا النُّفَيْلِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ عَمْرِو بْنِ مَيْمُونٍ قَالَ سَمِعْتُ أَبَا حَاضِرٍ الْحِمْيَرِيَّ يُحَدِّثُ أَبِي مَيْمُونَ بْنَ مِهْرَانَ قَالَخَرَجْتُ مُعْتَمِرًا عَامَ حَاصَرَ أَهْلُ الشَّامِ ابْنَ الزُّبَيْرِ بِمَكَّةَ وَبَعَثَ مَعِي رِجَالٌ مِنْ قَوْمِي بِهَدْيٍ فَلَمَّا انْتَهَيْنَا إِلَى أَهْلِ الشَّامِ مَنَعُونَا أَنْ نَدْخُلَ الْحَرَمَ فَنَحَرْتُ الْهَدْيَ مَكَانِي ثُمَّ أَحْلَلْتُ ثُمَّ رَجَعْتُ فَلَمَّا كَانَ مِنْ الْعَامِ الْمُقْبِلِ خَرَجْتُ لِأَقْضِيَ عُمْرَتِي فَأَتَيْتُ ابْنَ عَبَّاسٍ فَسَأَلْتُهُ فَقَالَ أَبْدِلْ الْهَدْيَ فَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ أَصْحَابَهُ أَنْ يُبَدِّلُوا الْهَدْيَ الَّذِي نَحَرُوا عَامَ الْحُدَيْبِيَةِ فِي عُمْرَةِ الْقَضَاءِ","id":"Telah menceritakan kepada Kami [An Nufaili], Telah menceritakan kepada Kami [Muhammad bin Salamah] dari [Muhammad bin Ishaq] dari ['Amr bin Maimun], ia berkata; saya mendengar [Abu Hadhir Al Himyari] menceritakan kepada ayahku yaitu Maimun bin Mahran, ia berkata; aku keluar untuk melaksanakan umrah pada tahun ketika penduduk Syam mengepung Ibnu Az Zubair di Mekkah, dan orang-orang dari kaumku mengirim hewan kurban bersamaku, ketika Kami sampai kepada penduduk Syam, mereka melarang Kami untuk memasuki tanah suci, maka aku menyembelih binatang sembelihanku ditempatku kemudian aku bertahallul dan kembali. Ketika pada tahun berikutnya aku keluar untuk melakukan umrahku, lalu aku mendatangi [Ibnu Abbas] dan bertanya kepadanya -tentang kejadian tersebut- kemudian ia menjawab: gantilah hewan sembelihanmu, karena Rasulullah shallallahu 'alaihi wasallam memerintahkan para sahabatnya untuk mengganti hewan sembelihannya yang telah mereka sembelih pada waktu terjadi perjanjian Hudaibiyah pada peristiwa umratul qadha (mengganti umrah). "},"1526":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ نَافِعٍأَنَّ ابْنَ عُمَرَ كَانَ إِذَا قَدِمَ مَكَّةَ بَاتَ بِذِي طَوًى حَتَّى يُصْبِحَ وَيَغْتَسِلَ ثُمَّ يَدْخُلَ مَكَّةَ نَهَارًا وَيَذْكُرُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ فَعَلَهُ","id":"Telah menceritakan kepada Kami [Muhammad bin 'Ubaid], telah menceritakan kepada Kami [Hammad bin Zaid] dari [Ayyub] dari [Nafi'] bahwa [Ibnu Umar] apabila datang ke Mekkah, beliau bermalam di Dzu Thuwa hingga pagi, dan beliau mandi kemudian masuk Mekkah pada siang hari, dan ia menyebutkan dari Nabi shallallahu 'alaihi wasallam bahwa beliau telah melakukannya. "},"1527":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ جَعْفَرٍ الْبَرْمَكِيُّ حَدَّثَنَا مَعِنٌ عَنْ مَالِكٍ ح و حَدَّثَنَا مُسَدَّدٌ وَابْنُ حَنْبَلٍ عَنْ يَحْيَى ح و حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ جَمِيعًا عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَدْخُلُ مَكَّةَ مِنْ الثَّنِيَّةِ الْعُلْيَا قَالَا عَنْ يَحْيَى إِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَدْخُلُ مَكَّةَ مِنْ كَدَاءَ مِنْ ثَنِيَّةِ الْبَطْحَاءِ وَيَخْرُجُ مِنْ الثَّنِيَّةِ السُّفْلَى زَادَ الْبَرْمَكِيُّ يَعْنِي ثَنِيَّتَيْ مَكَّةَوَحَدِيثُ مُسَدَّدٍ أَتَمُّ","id":"Telah menceritakan kepada Kami [Abdullah bin Ja'far Al Barmaki], telah menceritakan kepada Kami [Ma'n] dari [Malik], dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada Kami [Musaddad] dan [Ibnu Hanbal] dari [Yahya]. Telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada Kami [Utsman bin Abu Syaibah], telah menceritakan kepada Kami [Abu Usamah] semuanya dari ['Ubaidullah], dari [Nafi'] dari [Ibnu Umar] bahwa Nabi shallallahu 'alaihi wasallam memasuki Mekkah, dari Kada` dari Tsaniyah Al Bathha`, dan beliau keluar dari Tsaniyah yang rendah. Al Barmaki menambahkan yaitu dua Tsaniyah yang ada di Mekkah. Dan hadits Musaddad lebih sempurna. "},"1528":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَخْرُجُ مِنْ طَرِيقِ الشَّجَرَةِ وَيَدْخُلُ مِنْ طَرِيقِ الْمُعَرَّسِ","id":"Telah menceritakan kepada Kami [Utsman bin Abu Syaibah], telah menceritakan kepada Kami [Abu Usamah] dari ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar] bahwa Nabi shallallahu 'alaihi wasallam keluar dari jalan pohon (yang berada di samping Masjid Dzul Hulaifah), dan masuk melalui jalan Al Mu'arras. "},"1529":{"ar":"حَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْدَخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَامَ الْفَتْحِ مِنْ كَدَاءَ مِنْ أَعْلَى مَكَّةَ وَدَخَلَ فِي الْعُمْرَةِ مِنْ كُدًىقَالَ وَكَانَ عُرْوَةُ يَدْخُلُ مِنْهُمَا جَمِيعًا وَكَانَ أَكْثَرُ مَا كَانَ يَدْخُلُ مِنْ كُدًى وَكَانَ أَقْرَبَهُمَا إِلَى مَنْزِلِهِ","id":"Telah menceritakan kepada Kami [Harun bin Abdullah], telah menceritakan kepada Kami [Abu Usamah], telah menceritakan kepada Kami [Hisyam bin 'Urwah] dari [ayahnya] dari [Aisyah] radliallahu 'anha, ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam masuk pada tahun terjadinya penaklukan Mekkah dari Kada`, dari bagian Mekkah paling tinggi, dan beliau masuk pada saat umrah dari Kuda (Tsaniyah yang paling rendah). Ia berkata; dan 'Urwah memasuki dari keduanya, yang paling sering ia memasuki dari Kuda dan itu adalah yang lebih dekat dari rumahnya. "},"1530":{"ar":"حَدَّثَنَا ابْنُ الْمُثَنَّى حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا دَخَلَ مَكَّةَ دَخَلَ مِنْ أَعْلَاهَا وَخَرَجَ مِنْ أَسْفَلِهَا","id":"Telah menceritakan kepada Kami [Ibnu Al Mutsanna], telah menceritakan kepada Kami [Sufyan bin 'Uyainah] dari [Hisyam bin 'Urwah] dari [ayahnya] dari [Aisyah] bahwa Nabi shallallahu 'alaihi wasallam apabila masuk Mekkah, beliau memasuki dari bagian Mekkah yang paling atas, dan keluar dari paling bawah. "},"1531":{"ar":"حَدَّثَنَا يَحْيَى بْنُ مُعِينٍ أَنَّ مُحَمَّدَ بْنَ جَعْفَرٍ حَدَّثَهُمْ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ أَبَا قَزْعَةَ يُحَدِّثُ عَنْ الْمُهَاجِرِ الْمَكِّيِّ قَالَسُئِلَ جَابِرُ بْنُ عَبْدِ اللَّهِ عَنْ الرَّجُلِ يَرَى الْبَيْتَ يَرْفَعُ يَدَيْهِ فَقَالَ مَا كُنْتُ أَرَى أَحَدًا يَفْعَلُ هَذَا إِلَّا الْيَهُودَ وَقَدْ حَجَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ يَكُنْ يَفْعَلُهُ","id":"Telah menceritakan kepada Kami [Yahya bin Ma'in] bahwa [Muhammad bin Ja'far] menceritakan kepada mereka; telah menceritakan kepada Kami [Syu'bah], ia berkata; saya mendengar [Abu Qaz'ah] menceritakan dari [Al Muhajir Al Makki], ia berkata; [Jabir bin Abdillah] ditanya mengenai seseorang yang ketika melihat Ka'bah ia mengangkat kedua tangannya? Dia menjawab: aku tidak pernah melihat seorang pun yang melakukan itu kecuali orang yahudi, Kami telah melaksanakan haji bersama Rasulullah shallla Allahu 'alaihi wa sallam dan beliau tidak melakukan perbuatan tersebut. "},"1532":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا سَلَّامُ بْنُ مِسْكِينٍ حَدَّثَنَا ثَابِتٌ الْبُنَانِيُّ عَنْ عَبْدِ اللَّهِ بْنِ رَبَاحٍ الْأَنْصَارِيِّ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمَّا دَخَلَ مَكَّةَ طَافَ بِالْبَيْتِ وَصَلَّى رَكْعَتَيْنِ خَلْفَ الْمَقَامِ يَعْنِي يَوْمَ الْفَتْحِ","id":"Telah menceritakan kepada Kami [Muslim bin Ibrahim], telah menceritakan kepada Kami [Sallam bin Miskin], telah menceritakan kepada Kami [Tsabit Al Bunani] dari [Abdullah bin Rabah Al Anshari] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam tatkala memasuki Mekkah beliau berthowaf di Ka'bah dan melakukan shalat dua raka'at di belakang Maqam, yaitu pada saat penaklukan Mekkah. "},"1533":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا بَهْزُ بْنُ أَسَدٍ وَهَاشِمٌ يَعْنِي ابْنَ الْقَاسِمِ قَالَا حَدَّثَنَا سُلَيْمَانُ بْنُ الْمُغِيرَةِ عَنْ ثَابِتٍ عَنْ عَبْدِ اللَّهِ بْنِ رَبَاحٍ عَنْ أَبِي هُرَيْرَةَ قَالَأَقْبَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَخَلَ مَكَّةَ فَأَقْبَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الْحَجَرِ فَاسْتَلَمَهُ ثُمَّ طَافَ بِالْبَيْتِ ثُمَّ أَتَى الصَّفَا فَعَلَاهُ حَيْثُ يَنْظُرُ إِلَى الْبَيْتِ فَرَفَعَ يَدَيْهِ فَجَعَلَ يَذْكُرُ اللَّهَ مَا شَاءَ أَنْ يَذْكُرَهُ وَيَدْعُوهُ قَالَ وَالْأَنْصَارُ تَحْتَهُ قَالَ هَاشِمٌ فَدَعَا وَحَمِدَ اللَّهَ وَدَعَا بِمَا شَاءَ أَنْ يَدْعُوَ","id":"Telah menceritakan kepada Kami [Ahmad bin Hanbal], telah menceritakan kepada Kami [Bahz bin Asad], serta [Hasyim yaitu Ibnu Al Qasim], mereka berkata; telah menceritakan kepada Kami [Sulaiman bin Al Mughirah] dari [Tsabit] dari [Abdullah bin Rabah] dari [Abu Hurairah], ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam datang lalu memasuki Mekkan dan menghadap ke Hajar Aswad, serta mengusapnya kemudian melakukan thawaf di Ka'bah, kemudian mendatangi bukit Shafa dan menaikinya, dimana beliau melihat ke Ka'bah dan beliau mengangkat kedua tangannya, dan berdzikir kepada Allah dengan dzikir yang beliau kehendaki, dan beliau berdoa kepadaNya. Abu Hurairah berkata; sementara orang-orang anshar berada di bawah beliau. Hasyim berkata; kemudian beliau berdoa dan memuji Allah. Beliau berdoa dengan doa yang beliau kehendaki. "},"1534":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَابِسِ بْنِ رَبِيعَةَ عَنْ عُمَرَأَنَّهُ جَاءَ إِلَى الْحَجَرِ فَقَبَّلَهُ فَقَالَ إِنِّي أَعْلَمُ أَنَّكَ حَجَرٌ لَا تَنْفَعُ وَلَا تَضُرُّ وَلَوْلَا أَنِّي رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُقَبِّلُكَ مَا قَبَّلْتُكَ","id":"Telah menceritakan kepada Kami [Muhammad bin Katsir], telah mengabarkan kepada Kami [Sufyan] dari [Al A'masy] dari [Ibrahim] dari ['Abis bin Rabi'ah] dari [Umar] bahwa ia datang ke Hajar Aswad, kemudian menciumnya dan berkata; sungguh aku mengetahui bahwa engkau hanya sekedar batu yang tidak bermanfaat, dan tidak membawa madharat, seandainya aku tidak melihat Rasulullah shallAllahu wa'alaihi wa sallam menciummu maka aku tidak akan menciummu. "},"1535":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا لَيْثٌ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَ قَالَلَمْ أَرَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمْسَحُ مِنْ الْبَيْتِ إِلَّا الرُّكْنَيْنِ الْيَمَانِيَّيْنِ","id":"Telah menceritakan kepada Kami [Abu Al Walid Ath Thayalisi], telah menceritakan kepada Kami [Laits] dari [Ibnu Syihab] dari [Salim] dari [Ibnu Umar], ia berkata; aku tidak pernah melihat Rasulullah shallAllahu wa'alaihi wa sallam mengusap bagian dari Ka'bah kecuali dua rukun yamani. "},"1536":{"ar":"حَدَّثَنَا مَخْلَدُ بْنُ خَالِدٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَأَنَّهُ أُخْبِرَ بِقَوْلِ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا إِنَّ الْحِجْرَ بَعْضُهُ مِنْ الْبَيْتِ فَقَالَ ابْنُ عُمَرَ وَاللَّهِ إِنِّي لَأَظُنُّ عَائِشَةَ إِنْ كَانَتْ سَمِعَتْ هَذَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي لَأَظُنُّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَتْرُكْ اسْتِلَامَهُمَا إِلَّا أَنَّهُمَا لَيْسَا عَلَى قَوَاعِدِ الْبَيْتِ وَلَا طَافَ النَّاسُ وَرَاءَ الْحِجْرِ إِلَّا لِذَلِكَ","id":"Telah menceritakan kepada Kami [Makhlad bin Khalid], telah menceritakan kepada Kami [Abdurrazzaq], telah mengabarkan kepada Kami [Ma'mar] dari [Az Zuhri] dari [Salim] dari [Ibnu Umar] bahwa ia telah diberi kabar mengenai perkataan Aisyah radliallahu 'anha; sesungguhnya Hajar Aswad sebagiannya merupakan bagian dari Ka'bah. Kemudian Ibnu Umar berkata; demi Allah sungguh aku mengira apabila Aisyah mendengar hal ini dari Rasulullah shallAllahu wa'alaihi wa sallam sesungguhnya aku yakin Rasulullah shallAllahu wa'alaihi wa sallam tidak meninggalkan untuk mengusap keduanya, hanya saja keduanya tidak berada di atas pondasi Ka'bah, dan orang-orang tidak akan berthawaf di belakang hajar kecuali karena hal tersebut."},"1537":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ عَبْدِ الْعَزِيزِ بْنِ أَبِي رَوَّادٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَدَعُ أَنْ يَسْتَلِمَ الرُّكْنَ الْيَمَانِيَ وَالْحَجَرَ فِي كُلِّ طَوْفَةٍقَالَ وَكَانَ عَبْدُ اللَّهِ بْنُ عُمَرَ يَفْعَلُهُ","id":"Telah menceritakan kepada Kami [Musaddad], telah menceritakan kepada Kami [Yahya] dari [Abdul 'Aziz bin Abu Rawwad] dari [Nafi'] dari [Ibnu Umar], ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam tidak meninggalkan untuk mengusap rukun yamani dan hajar aswad pada setiap thawaf. Nafi' berkata; dan Abdullah bin Umar melakukan hal tersebut. "},"1538":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ يَعْنِي ابْنَ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَافَ فِي حَجَّةِ الْوَدَاعِ عَلَى بَعِيرٍ يَسْتَلِمُ الرُّكْنَ بِمِحْجَنٍ","id":"Telah menceritakan kepada Kami [Ahmad bin Shalih], telah menceritakan kepada Kami [Ibnu Wahb], telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dari ['Ubaidullah yaitu Ibnu Abdullah bin 'Utbah] dari [Ibnu Abbas] bahwa Rasulullah shallAllahu wa'alaihi wa sallam melakukan thawaf pada saat haji wada' di atas unta, dan mengusap rukun menggunakan tongkat. "},"1539":{"ar":"حَدَّثَنَا مُصَرِّفُ بْنُ عَمْرٍو الْيَامِيُّ حَدَّثَنَا يُونُسُ يَعْنِي ابْنَ بُكَيْرٍ حَدَّثَنَا ابْنُ إِسْحَقَ حَدَّثَنِي مُحَمَّدُ بْنُ جَعْفَرِ بْنِ الزُّبَيْرِ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي ثَوْرٍ عَنْ صَفِيَّةَ بِنْتِ شَيْبَةَ قَالَتْلَمَّا اطْمَأَنَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَكَّةَ عَامَ الْفَتْحِ طَافَ عَلَى بَعِيرٍ يَسْتَلِمُ الرُّكْنَ بِمِحْجَنٍ فِي يَدِهِ قَالَتْ وَأَنَا أَنْظُرُ إِلَيْهِ","id":"Telah menceritakan kepada Kami [Musharrif bin 'Amr Al Yami], telah menceritakan kepada Kami [Yunus yaitu Ibnu Bukair], telah menceritakan kepada Kami [Ibnu Ishaq], telah menceritakan kepadaku [Muhammad bin Ja'far bin Az Zubair] dari ['Ubaidullah bin Abdullah bin Abu Tsaur], dari [Shafiyah binti Syaibah], ia berkata; tatkala Rasulullah shallAllahu wa'alaihi wa sallam tinggal di Mekkah pada saat penaklukan Mekkah, beliau berthawaf di atas unta dan menyentuh rukun menggunakan tongkat di tangannya. Shafiyah berkata; dan aku melihat beliau. "},"1540":{"ar":"حَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ وَمُحَمَّدُ بْنُ رَافِعٍ الْمَعْنَى قَالَا حَدَّثَنَا أَبُو عَاصِمٍ عَنْ مَعْرُوفٍ يَعْنِي ابْنَ خَرَّبُوذَ الْمَكِّيَّ حَدَّثَنَا أَبُو الطُّفَيْلِ قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَطُوفُ بِالْبَيْتِ عَلَى رَاحِلَتِهِ يَسْتَلِمُ الرُّكْنَ بِمِحْجَنِهِ ثُمَّ يُقَبِّلُهُ زَادَ مُحَمَّدُ بْنُ رَافِعٍ ثُمَّ خَرَجَ إِلَى الصَّفَا وَالْمَرْوَةِ فَطَافَ سَبْعًا عَلَى رَاحِلَتِهِ","id":"Telah menceritakan kepada Kami [Harun bin Abdullah] dan [Muhammad bin Rafi'] secara makna, mereka berkata; telah menceritakan kepada Kami [Abu 'Ashim] dari [Ma'ruf yaitu Ibnu Kharrabudz Al Makki], telah menceritakan kepada Kami [Abu Ath Thufail], ia berkata; saya melihat Nabi shallallahu 'alaihi wasallam berthawaf di Ka'bah di atas kendaraannya, dan mengusap rukun menggunakan tongkatnya, kemudian beliau menciumnya. Muhammad bin Rafi' menambahkan; kemudian beliau keluar menuju bukit Shafa serta Marwa dan melakukan thawaf sebanyak tujuh kali diatas kendaraannya. "},"1541":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا يَحْيَى عَنْ ابْنِ جُرَيْجٍ أَخْبَرَنِي أَبُو الزُّبَيْرِ أَنَّهُ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُطَافَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَجَّةِ الْوَدَاعِ عَلَى رَاحِلَتِهِ بِالْبَيْتِ وَبِالصَّفَا وَالْمَرْوَةِ لِيَرَاهُ النَّاسُ وَلِيُشْرِفَ وَلِيَسْأَلُوهُ فَإِنَّ النَّاسَ غَشُوهُ","id":"Telah menceritakan kepada Kami [Ahmad bin Hanbal], telah menceritakan kepada Kami [Yahya] dari [Ibnu Juraij], telah mengabarkan kepadaku [Abu Az Zubair] bahwa ia mendengar [Jabir bin Abdullah] berkata; Nabi shallallahu 'alaihi wasallam melaksanakan thawaf mengelilingi pada haji wada' di Ka'bah dan Shafa serta Marwa di atas kendaraannya agar orang-orang melihatnya dan untuk membimbing dan agar orang-orang bertanya kepadanya. Karena sesungguhnya orang-orang telah mengelilingi beliau. "},"1542":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا خَالِدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا يَزِيدُ بْنُ أَبِي زِيَادٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدِمَ مَكَّةَ وَهُوَ يَشْتَكِي فَطَافَ عَلَى رَاحِلَتِهِ كُلَّمَا أَتَى عَلَى الرُّكْنِ اسْتَلَمَ الرُّكْنَ بِمِحْجَنٍ فَلَمَّا فَرَغَ مِنْ طَوَافِهِ أَنَاخَ فَصَلَّى رَكْعَتَيْنِ","id":"Telah menceritakan kepada Kami [Musaddad], telah menceritakan kepada Kami [Khalid bin Abdullah], telah menceritakan kepada Kami [Yazid bin Abu Ziyad] dari [Ikrimah] dari [Ibnu Abbas] bahwa Rasulullah shallAllahu wa'alaihi wa sallam datang ke Mekkah dalam keadaan sakit. Kemudian beliau berthawaf di atas kendaraannya, setiap kali beliau datang ke rukun maka beliau mengusap rukun tersebut menggunakan tongkat. Kemudian tatkala telah selesai dari thawafnya beliau menderumkan unta dan melakukan shalat dua raka'at. "},"1543":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ نَوْفَلٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ زَيْنَبَ بِنْتِ أَبِي سَلَمَةَ عَنْ أُمِّ سَلَمَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهَا قَالَتْشَكَوْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنِّي أَشْتَكِي فَقَالَ طُوفِي مِنْ وَرَاءِ النَّاسِ وَأَنْتِ رَاكِبَةٌ قَالَتْ فَطُفْتُ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَئِذٍ يُصَلِّي إِلَى جَنْبِ الْبَيْتِ وَهُوَ يَقْرَأُ بِالطُّورِ وَكِتَابٍ مَسْطُورٍ","id":"Telah menceritakan kepada Kami [Al Qa'nabi] dari [Malik] dari [Muhammad bin Abdurrahman bin Naufal] dari ['Urwah bin Az Zubair] dari [Zainab binti Abu Salamah] dari [Ummu Salamah] isteri Nabi shallallahu 'alaihi wasallam bahwa ia berkata; aku mengeluhkan kepada Rasulullah shallAllahu wa'alaihi wa sallam bahwa aku sedang sakit. Kemudian beliau berkata: \"Berthawaflah di belakang orang-orang dengan menaiki kendaraan.\" Ummu Salamah berkata; kemudian aku melakukan thawaf sementara Rasulullah shallAllahu wa'alaihi wa sallam pada saat itu melakukan shalat di samping Ka'bah, dan beliau membaca Surat Ath Thur. "},"1544":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ ابْنِ جُرَيْجٍ عَنْ ابْنِ يَعْلَى عَنْ يَعْلَى قَالَطَافَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُضْطَبِعًا بِبُرْدٍ أَخْضَرَ","id":"Telah menceritakan kepada Kami [Muhammad bin Katsir], telah mengabarkan kepada Kami [Sufyan] dari [Ibnu Juraij] dari [Ibnu Ya'la] dari [Ya'la], ia berkata; Nabi shallallahu 'alaihi wasallam berthawaf dalam keadaan memakai kain hijau dan membuka pundak sebelah kanan. "},"1545":{"ar":"حَدَّثَنَا أَبُو سَلَمَةَ مُوسَى حَدَّثَنَا حَمَّادٌ عَنْ عَبْدِ اللَّهِ بْنِ عُثْمَانَ بْنِ خُثَيْمٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَصْحَابَهُ اعْتَمَرُوا مِنْ الْجِعْرَانَةِ فَرَمَلُوا بِالْبَيْتِ وَجَعَلُوا أَرْدِيَتَهُمْ تَحْتَ آبَاطِهِمْ قَدْ قَذَفُوهَا عَلَى عَوَاتِقِهِمْ الْيُسْرَى","id":"Telah menceritakan kepada Kami [Abu Salamah Musa], telah menceritakan kepada Kami [Hammad] dari [Abdullah bin Utsman bin Khutsaim] dari [Sa'id bin Jubair] dari [Ibnu Abbas] bahwa Rasulullah shallAllahu wa'alaihi wa sallam dan para sahabatnya melakukan umrah dari Al Ji'ranah, dan mereka berlari-lari kecil di Ka'bah dan meletakkan selendang mereka di bawah ketiak mereka, dan melemparkan di atas pundak kiri. "},"1546":{"ar":"حَدَّثَنَا أَبُو سَلَمَةَ مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ حَدَّثَنَا أَبُو عَاصِمٍ الْغَنَوِيُّ عَنْ أَبِي الطُّفَيْلِ قَالَقُلْتُ لِابْنِ عَبَّاسٍ يَزْعُمُ قَوْمُكَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ رَمَلَ بِالْبَيْتِ وَأَنَّ ذَلِكَ سُنَّةٌ قَالَ صَدَقُوا وَكَذَبُوا قُلْتُ وَمَا صَدَقُوا وَمَا كَذَبُوا قَالَ صَدَقُوا قَدْ رَمَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَذَبُوا لَيْسَ بِسُنَّةٍ إِنَّ قُرَيْشًا قَالَتْ زَمَنَ الْحُدَيْبِيَةِ دَعُوا مُحَمَّدًا وَأَصْحَابَهُ حَتَّى يَمُوتُوا مَوْتَ النَّغَفِ فَلَمَّا صَالَحُوهُ عَلَى أَنْ يَجِيئُوا مِنْ الْعَامِ الْمُقْبِلِ فَيُقِيمُوا بِمَكَّةَ ثَلَاثَةَ أَيَّامٍ فَقَدِمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالْمُشْرِكُونَ مِنْ قِبَلِ قُعَيْقِعَانَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِأَصْحَابِهِ ارْمُلُوا بِالْبَيْتِ ثَلَاثًا وَلَيْسَ بِسُنَّةٍ قُلْتُ يَزْعُمُ قَوْمُكَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَافَ بَيْنَ الصَّفَا وَالْمَرْوَةِ عَلَى بَعِيرِهِ وَأَنَّ ذَلِكَ سُنَّةٌ فَقَالَ صَدَقُوا وَكَذَبُوا قُلْتُ مَا صَدَقُوا وَمَا كَذَبُوا قَالَ صَدَقُوا قَدْ طَافَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ الصَّفَا وَالْمَرْوَةِ عَلَى بَعِيرِهِ وَكَذَبُوا لَيْسَ بِسُنَّةٍ كَانَ النَّاسُ لَا يُدْفَعُونَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَا يُصْرَفُونَ عَنْهُ فَطَافَ عَلَى بَعِيرٍ لِيَسْمَعُوا كَلَامَهُ وَلِيَرَوْا مَكَانَهُ وَلَا تَنَالُهُ أَيْدِيهِمْ","id":"Telah menceritakan kepada Kami [Abu Salamah Musa bin Isma'il], telah menceritakan kepada Kami [Hammad], telah menceritakan kepada Kami [Abu 'Ashim Al Ghanawi] dari [Abu Ath Thufail], ia berkata; aku katakan kepada [Ibnu Abbas]; orang-orang mengaku bahwa Rasulullah shallAllahu wa'alaihi wa sallam telah berlari-lari kecil di Ka'bah, dan hal tersebut sunah. Ia berkata; mereka benar, dan berdusta. Aku katakan; kebenaran apakah yang mereka katakan, dan kedustaan apa yang mereka ucapkan? Ia berkata; mereka telah benar, Rasulullah shallAllahu wa'alaihi wa sallam telah berlari-lari kecil, dan mereka bedusta, hal tersebut bukanlah sunah. Sesungguhnya orang-orang Quraisy berkata pada zaman terjadinya perjanjian hudaibiyah; biarkan Muhammad dan para sahabatnya hingga mereka bati seperti matinya ulatm. Kemudian tatkala mereka berdamai dengan beliau agar mereka datang pada tahun yang akan datang dan bermukim di Mekkah selama tiga hari. Kemudian Rasulullah shallAllahu wa'alaihi wa sallam datang sementara orang-orang musyrik dari arah Qu'aiqi'an. Lalu Rasulullah shallAllahu wa'alaihi wa sallam berkata kepada para sahabatnya: \"Berlari-lari kecillah di Ka'bah sebanyak tiga kali, dan bukanlah sesuatu yang sunah.\" Aku katakana; kaummu mengaku bahwa Rasulullah shallAllahu wa'alaihi wa sallam berthawaf antara Shafa dan Marwa di atas untanya, dan hal tersebut merupakan sesuatu yang sunah. Kemudian ia berkata; mereka telah benar dan berdusta. Aku katakan; kebenaran apakah yang mereka katakan? Dan kedustaan apakah yang mereka ucapkan? Ia berkata; mereka benar, Rasulullah shallAllahu wa'alaihi wa sallam telah melakukan thawaf antara Shafa dan Marwa di atas untanya, dan mereka berdusta, karena hal tersebut bukanlah sunah. Dahulu orang-orang tidak ditolak dari Rasulullah shallAllahu wa'alaihi wa sallam dan tidak dipalingkan dari beliau, beliau melakukan thawaf di atas untanya agar mereka mendengar perkataannya dan melihat tempatnya, serta tidak bisa dicapai tangan mereka. "},"1547":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ أَنَّهُ حَدَّثَ عَنْ ابْنِ عَبَّاسٍ قَالَقَدِمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَكَّةَ وَقَدْ وَهَنَتْهُمْ حُمَّى يَثْرِبَ فَقَالَ الْمُشْرِكُونَ إِنَّهُ يَقْدَمُ عَلَيْكُمْ قَوْمٌ قَدْ وَهَنَتْهُمْ الْحُمَّى وَلَقُوا مِنْهَا شَرًّا فَأَطْلَعَ اللَّهُ سُبْحَانَهُ نَبِيَّهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى مَا قَالُوهُ فَأَمَرَهُمْ أَنْ يَرْمُلُوا الْأَشْوَاطَ الثَّلَاثَةَ وَأَنْ يَمْشُوا بَيْنَ الرُّكْنَيْنِ فَلَمَّا رَأَوْهُمْ رَمَلُوا قَالُوا هَؤُلَاءِ الَّذِينَ ذَكَرْتُمْ أَنَّ الْحُمَّى قَدْ وَهَنَتْهُمْ هَؤُلَاءِ أَجْلَدُ مِنَّاقَالَ ابْنُ عَبَّاسٍ وَلَمْ يَأْمُرْهُمْ أَنْ يَرْمُلُوا الْأَشْوَاطَ كُلَّهَا إِلَّا إِبْقَاءً عَلَيْهِمْ","id":"Telah menceritakan kepada Kami [Musaddad bin Zaid] dari [Hammad bin Zaid] dari [Ayyub] dari [Sa'id bin Jubair] bahwa ia menceritakan dari [Ibnu Abbas], ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam datang ke Mekkah, dalam keadaan lemah karena sakit demam di Madinah. Kemudian orang-orang musyrik berkata; sesungguhnya datang kepada kalian sebuah kaum yang menjadi lemah karena demam, dan mereka menjumpai keburukan. Kemudian Allah subhanah memperlihatkan kepada NabiNya shallallahu 'alaihi wasallam apa yang mereka katakana. Kemudian beliau memerintahkan mereka agar berlari-lari kecil tiga kali putaran, dan berjalan diantara dua rukun. Kemudian tatkala orang-orang musyrik melihat mereka berlari-lari kecil maka mereka berkata; mereka orang-orang yang kalian sebutkan bahwa demam telah melemahkan mereka, mereka adalah orang yang lebih kuat daripada kita. Ibnu Abbad berkata; dan beliau tidak memerintahkan mereka untuk berlari-lari kecil seluruh putaran, kecuali sebagai belas kasihan terhadap mereka. "},"1548":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ عَمْرٍو حَدَّثَنَا هِشَامُ بْنُ سَعْدٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ أَبِيهِ قَالَ سَمِعْتُ عُمَرَ بْنَ الْخَطَّابِ يَقُولُفِيمَ الرَّمَلَانُ الْيَوْمَ وَالْكَشْفُ عَنْ الْمَنَاكِبِ وَقَدْ أَطَّأَ اللَّهُ الْإِسْلَامَ و��نَفَى الْكُفْرَ وَأَهْلَهُ مَعَ ذَلِكَ لَا نَدَعُ شَيْئًا كُنَّا نَفْعَلُهُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada Kami [Ahmad bin Hanbal], telah menceritakan kepada Kami [Abdul Malik bin 'Amr], telah menceritakan kepada Kami [Hisyam bin Sa'd] dari [Zaid bin Aslam] dari [ayahnya], ia berkata; saya mendengar [Umar bin Al Khathab] berkata; untuk apa hari ini berlari-lari kecil, dan membuka pundak kanan? Sementara Allah telah mengokohkan Islam dan menghilangkan kekafiran dan pelakunya? Bersamaan itu kita tidak meninggalkan sesuatupun yang dahulu kita lakukan pada zaman Rasulullah shallAllahu wa'alaihi wa sallam? "},"1549":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عِيسَى بْنُ يُونُسَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ أَبِي زِيَادٍ عَنْ الْقَاسِمِ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا جُعِلَ الطَّوَافُ بِالْبَيْتِ وَبَيْنَ الصَّفَا وَالْمَرْوَةِ وَرَمْيُ الْجِمَارِ لِإِقَامَةِ ذِكْرِ اللَّهِ","id":"Telah menceritakan kepada Kami [Musaddad], telah menceritakan kepada Kami [Isa bin Yunus], telah menceritakan kepada Kami ['Ubaidullah bin Abu Ziyad] dari [Al Qasim] dari [Aisyah], ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Sesungguhnya dijadikannya thawaf di Ka'bah, antara Shafa dan Marwah serta melempar jumrah adalah untuk menegakkan dzikir kepada Allah.\""},"1550":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سُلَيْمَانَ الْأَنْبَارِيُّ حَدَّثَنَا يَحْيَى بْنُ سُلَيْمٍ عَنْ ابْنِ خُثَيْمٍ عَنْ أَبِي الطُّفَيْلِ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اضْطَبَعَ فَاسْتَلَمَ وَكَبَّرَ ثُمَّ رَمَلَ ثَلَاثَةَ أَطْوَافٍ وَكَانُوا إِذَا بَلَغُوا الرُّكْنَ الْيَمَانِيَ وَتَغَيَّبُوا مِنْ قُرَيْشٍ مَشَوْا ثُمَّ يَطْلُعُونَ عَلَيْهِمْ يَرْمُلُونَ تَقُولُ قُرَيْشٌ كَأَنَّهُمْ الْغِزْلَانُ قَالَ ابْنُ عَبَّاسٍ فَكَانَتْ سُنَّةً","id":"Telah menceritakan kepada Kami [Muhammad bin Sulaiman Al Anbari], telah menceritakan kepada Kami [Yahya bin Sulaim] dari [Ibnu Khutsaim] dari [Abu Ath Thufail] dari [Ibnu Abbas] bahwa Nabi shallallahu 'alaihi wasallam membuka pundak kanan, dan mengusap hajar aswad, serta bertakbir kemudian berlari-lari kecil sebanyak tiga kali putaran. Mereka apabila telah sampai di Rukun Yamani dan tersembunyi dari orang-orang Quraisy maka mereka berjalan, kemudian menampakkan diri kepada mereka dengan berlari-lari kecil. Orang-orang Quraisy berkata; seolah-olah mereka adalah adalah kijang. Ibnu Abbas berkata; dan itu menjadi sesuatu yang sunah. "},"1551":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ عُثْمَانَ بْنِ خُثَيْمٍ عَنْ أَبِي الطُّفَيْلِ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَصْحَابَهُ اعْتَمَرُوا مِنْ الْجِعْرَانَةِ فَرَمَلُوا بِالْبَيْتِ ثَلَاثًا وَمَشَوْا أَرْبَعًا","id":"Telah menceritakan kepada Kami [Musa bin Isma'il], telah menceritakan kepada Kami [Hammad], telah mengabarkan kepada Kami [Abdullah bin Utsman bin Khutsaim] dari [Abu Ath Thufail] dari [Ibnu Abbas] bahwa Rasulullah shallAllahu wa'alaihi wa sallam dan para sahabatnya melakukan umrah dari Al Ji'ranah dan berlari-lari kecil di Ka'bah sebanyak tiga kali putaran dan berjalan empat kali. "},"1552":{"ar":"حَدَّثَنَا أَبُو كَامِلٍ حَدَّثَنَا سُلَيْمُ بْنُ أَخْضَرَ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍأَنَّ ابْنَ عُمَرَ رَمَلَ مِنْ الْحَجَرِ إِلَى الْحَجَرِ وَذَكَرَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَعَلَ ذَلِكَ","id":"Telah menceritakan kepada Kami [Abu Kamil], telah menceritakan kepada Kami [Sulaim bin Akhdhar], telah menceritakan kepada Kami ['Ubaidullah] dari [Nafi] bahwa [Ibnu Umar] berlari-lari kecil dari Hajar Aswad hingga Hajar Aswad, dan ia menyebutkan bahwa Rasulullah shallAllahu wa'alaihi wa sallam melakukan hal tersebut. "},"1553":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عِيسَى بْنُ يُونُسَ حَدَّثَنَا ابْنُ جُرَيْجٍ عَنْ يَحْيَى بْنِ عُبَيْدٍ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ السَّائِبِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا بَيْنَ الرُّكْنَيْنِ{ رَبَّنَا آتِنَا فِي الدُّنْيَا حَسَنَةً وَفِي الْآخِرَةِ حَسَنَةً وَقِنَا عَذَابَ النَّارِ }","id":"Telah menceritakan kepada Kami [Musaddad], telah menceritakan kepada Kami [Isa bin Yunus], telah menceritakan kepada Kami [Ibnu Juraij], dari [Yahya bin Ubaid] dari [ayahnya] dari [Abdullah bin As Saib], ia berkata; saya mendengar Rasulullah shallAllahu wa'alaihi wa sallam mengucapkan diantara dua rukun: \"RABBANAA AATINAA FID DUNYAA HASANAH, WA FIL AAKHIRATI HASANAH, WA QINAA 'ADZAABANNAAR\" (Wahai Tuhan Kami, berikanlah kepada Kami di dunia kebaikan dan di Akhirat kebaikan dan lindungilah Kami dari adzab Neraka). "},"1554":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا يَعْقُوبُ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا طَافَ فِي الْحَجِّ وَالْعُمْرَةِ أَوَّلَ مَا يَقْدَمُ فَإِنَّهُ يَسْعَى ثَلَاثَةَ أَطْوَافٍ وَيَمْشِي أَرْبَعًا ثُمَّ يُصَلِّي سَجْدَتَيْنِ","id":"Telah menceritakan kepada Kami [Qutaiba bin Sa'id], telah menceritakan kepada Kami [Ya'qub] dari [Musa bin 'Uqbah] dari [Nafi'] dari [Ibnu Umar] bahwa Rasulullah shallAllahu wa'alaihi wa sallam apabila berthawaf ketika melakukan haji dan umrah pertama kali yang beliau lakukan adalah berlari-lari kecil tiga putaran dan berjalan biasa empat putaran, kemudian melakukan shalat dua raka'at. "},"1555":{"ar":"حَدَّثَنَا ابْنُ السَّرْحِ وَالْفَضْلُ بْنُ يَعْقُوبَ وَهَذَا لَفْظُهُ قَالَا حَدَّثَنَا سُفْيَانُ عَنْ أَبِي الزُّبَيْرِ عَنْ عَبْدِ اللَّهِ بْنِ بَابَاهَ عَنْ جُبَيْرِ بْنِ مُطْعِمٍيَبْلُغُ بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَمْنَعُوا أَحَدًا يَطُوفُ بِهَذَا الْبَيْتِ وَيُصَلِّي أَيَّ سَاعَةٍ شَاءَ مِنْ لَيْلٍ أَوْ نَهَارٍ قَالَ الْفَضْلُ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَا بَنِي عَبْدِ مَنَافٍ لَا تَمْنَعُوا أَحَدًا","id":"Telah menceritakan kepada Kami [Ibnu As Sarh] dan [Al Fadhl bin Ya'qub], dan ini adalah lafazhnya. Mereka berkata; telah menceritakan kepada Kami [Sufyan] dari [Abu Az Zubair] dari [Abdullah bin Babah] dari [Jubair bin Muth'im] yang sampai kepada Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Janganlah melarang seorang pun untuk melakukan thawaf di Ka'bah, dan melakukan shalat pada saat kapanpun yang ia kehendaki, malam atau siang.\" Al Fadhl berkata; sesungguhnya Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Wahai bani Abdu Manaf, janganlah kalian melarang seorang pun….\""},"1556":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا يَحْيَى عَنْ ابْنِ جُرَيْجٍ قَالَ أَخْبَرَنِي أَبُو الزُّبَيْرِ قَالَ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُلَمْ يَطُفْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَا أَصْحَابُهُ بَيْنَ الصَّفَا وَالْمَرْوَةِ إِلَّا طَوَافًا وَاحِدًا طَوَافَهُ الْأَوَّلَ","id":"Telah menceritakan kepada Kami [Ahmad bin Hanbal], telah menceritakan kepada Kami [Yahya] dari [Ibnu Juraij], ia berkata; telah mengabarkan kepadaku [Abu Az Zubair], ia berkata; saya mendengar [Jabir bin Abdullah] berkata; Nabi shallallahu 'alaihi wasallam dan para sahabatnya tidak tidak melakukan thawaf antara Shafa dan Marwa kecuali satu kali thawaf, yaitu thawaf beliau yang pertama."},"1557":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ أَصْحَابَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الَّذِينَ كَانُوا مَعَهُ لَمْ يَطُوفُوا حَتَّى رَمَوْا الْجَمْرَةَ","id":"Telah menceritakan kepada Kami [Qutaibah bin Sa'id], telah menceritakan kepada Kami [Malik bin Anas] dari [Ibnu Syihab] dari ['Urwah], dari [Aisyah] bahwa para sahabat Rasulullah shallAllahu wa'alaihi wa sallam yang bersama beliau tidak melakukan thawaf hingga mereka melempar jumrah. "},"1558":{"ar":"حَدَّثَنَا الرَّبِيعُ بْنُ سُلَيْمَانَ الْمُؤَذِّنُ أَخْبَرَنِي الشَّافِعِيُّ عَنْ ابْنِ عُيَيْنَةَ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ عَطَاءٍ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَهَا طَوَافُكِ بِالْبَيْتِ وَبَيْنَ الصَّفَا وَالْمَرْوَةِ يَكْفِيكِ لِحَجَّتِكِ وَعُمْرَتِكِقَالَ الشَّافِعِيُّ كَانَ سُفْيَانُ رُبَّمَا قَالَ عَنْ عَطَاءٍ عَنْ عَائِشَةَ وَرُبَّمَا قَالَ عَنْ عَطَاءٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِعَائِشَةَ رَضِيَ اللَّهُ عَنْهَا","id":"Telah menceritakan kepada Kami [Ar Rabi' bin Sulaiman Al Muadzin], telah mengabarkan kepadaku [Asy Syafi'i] dari [Ibnu 'Uyainah], dari [Abu Najih] dari ['Atho`], dari [Aisyah] radliallahu 'anha bahwa Rasulullah shallallahu 'alaihi wasallam berkata kepadanya: \"Thawafmu di ka'bah dan sa'imu antara Shafa dan Marwa cukup bagimu sebagai pelaksanaan haji dan umrah.\" Syafii berkata; Sufyan terkadang berkata; dari 'Atha` bahwa Nabi shalla Allahu 'alaihi wa sallam berkata kepada Aisyah radliallahu 'anha…….. "},"1559":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرُ بْنُ عَبْدِ الْحَمِيدِ عَنْ يَزِيدَ بْنِ أَبِي زِيَادٍ عَنْ مُجَاهِدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ صَفْوَانَ قَالَلَمَّا فَتَحَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَكَّةَ قُلْتُ لَأَلْبَسَنَّ ثِيَابِي وَكَانَتْ دَارِي عَلَى الطَّرِيقِ فَلَأَنْظُرَنَّ كَيْفَ يَصْنَعُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَانْطَلَقْتُ فَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ خَرَجَ مِنْ الْكَعْبَةِ هُوَ وَأَصْحَابُهُ وَقَدْ اسْتَلَمُوا الْبَيْتَ مِنْ الْبَابِ إِلَى الْحَطِيمِ وَقَدْ وَضَعُوا خُدُودَهُمْ عَلَى الْبَيْتِ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَسْطَهُمْ","id":"Telah menceritakan kepada Kami [Utsman bin Abu Syaibah], telah menceritakan kepada Kami [Jarir bin Abdul Hamid], dari [Yazid bin Abu Ziyad] dari [Mujahid] dari [Abdurrahman bin Shafwan], ia berkata; tatkala Rasulullah shallAllahu wa'alaihi wa sallam menaklukkan Kota Mekkah aku katakan; sungguh aku akan memakai pakaianku -dan rumahku berada di jalan-, kemudian aku akan melihat bagaimana Rasulullah shallAllahu wa'alaihi wa sallam berbuat. Kemudian aku pergi dan melihat Nabi shallallahu 'alaihi wasallam telah keluar dari Ka'bah bersama para sahabatnya. Dan mereka telah mengusap Ka'bah dari pintu hingga Al Hathim (bagian antara pintu dan rukun). Dan mereka telah meletakkan pipi mereka pada Ka'bah sementara shallallahu 'alaihi wasallam berada di tengah mereka. "},"1560":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عِيسَى بْنُ يُونُسَ حَدَّثَنَا الْمُثَنَّى بْنُ الصَّبَّاحِ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ قَالَطُفْتُ مَعَ عَبْدِ اللَّهِ فَلَمَّا جِئْنَا دُبُرَ الْكَعْبَةِ قُلْتُ أَلَا تَتَعَوَّذُ قَالَ نَعُوذُ بِاللَّهِ مِنْ النَّارِ ثُمَّ مَضَى حَتَّى اسْتَلَمَ الْحَجَرَ وَأَقَامَ بَيْنَ الرُّكْنِ وَالْبَابِ فَوَضَعَ صَدْرَهُ وَوَجْهَهُ وَذِرَاعَيْهِ وَكَفَّيْهِ هَكَذَا وَبَسَطَهُمَا بَسْطًا ثُمَّ قَالَ هَكَذَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَفْعَلُهُ","id":"Telah menceritakan kepada Kami [Musaddad], telah menceritakan kepada Kami [Isa bin Yunus], telah menceritakan kepada Kami [Al Mutsanna bin Ash Shabah] dar ['Amr bin Syu'aib] dari [ayahnya], ia berkata; aku melaksanakan thawaf bersama [Abdullah], ketika sampai dibelakang Ka'bah aku berkata: apakah kamu tidak meminta perlindungan? Dia berkata; Kami berlindung kepada Allah dari Neraka. kemudian dia pergi hingga mengusap hajar aswad dan berdiri diantara rukun dan pintu Ka'bah lalu dia meletakkan dadanya, wajahnya, lengan dan telapak tangannya dengan membentangkannya demikian, kemudian berkata; beginilah aku melihat Rasulullah shallla Allahu 'alaihi wa sallam melakukannya. "},"1561":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ بْنِ مَيْسَرَةَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا السَّائِبُ بْنُ عَمْرٍو الْمَخْزُومِيُّ حَدَّثَنِي مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ السَّائِبِ عَنْ أَبِيهِأَنَّهُ كَانَ يَ��ُودُ ابْنَ عَبَّاسٍ فَيُقِيمُهُ عِنْدَ الشُّقَّةِ الثَّالِثَةِ مِمَّا يَلِي الرُّكْنَ الَّذِي يَلِي الْحَجَرَ مِمَّا يَلِي الْبَابَ فَيَقُولُ لَهُ ابْنُ عَبَّاسٍ أُنْبِئْتُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي هَا هُنَا فَيَقُولُ نَعَمْ فَيَقُومُ فَيُصَلِّي","id":"Telah menceritakan kepada Kami ['Ubaidullah bin Umar bin Maisarah], telah menceritakan kepada Kami [Yahya bin Sa'id], telah menceritakan kepada Kami [As Saib bin 'Amr Al Makhzumi], telah menceritakan kepadaku [Muhammad bin Abdullah bin As Saib], dari [ayahnya] bahwa ia menuntun Ibnu Abbas dan memberdirikannya di sisi ketiga setelah rukun yang terletak setelah hajar aswad, yang terletak setelah pintu. Ibnu Abbas berkata kepadanya; aku telah diberitahu bahwa Rasulullah shallAllahu wa'alaihi wa sallam melakukan shalat di sini. Kemudian As Saib berkata; ya. Kemudian ia berdiri dan melakukan shalat. "},"1562":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ هِشَامِ بْنِ عُرْوَةَ ح و حَدَّثَنَا ابْنُ السَّرْحِ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ مَالِكٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ أَنَّهُ قَالَقُلْتُ لِعَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا يَوْمَئِذٍ حَدِيثُ السِّنِّ أَرَأَيْتِ قَوْلَ اللَّهِ تَعَالَى{ إِنَّ الصَّفَا وَالْمَرْوَةَ مِنْ شَعَائِرِ اللَّهِ }فَمَا أَرَى عَلَى أَحَدٍ شَيْئًا أَنْ لَا يَطَّوَّفَ بِهِمَا قَالَتْ عَائِشَةُ كَلَّا لَوْ كَانَ كَمَا تَقُولُ كَانَتْ فَلَا جُنَاحَ عَلَيْهِ أَنْ لَا يَطَّوَّفَ بِهِمَا إِنَّمَا أُنْزِلَتْ هَذِهِ الْآيَةُ فِي الْأَنْصَارِ كَانُوا يُهِلُّونَ لِمَنَاةَ وَكَانَتْ مَنَاةُ حَذْوَ قُدَيْدٍ وَكَانُوا يَتَحَرَّجُونَ أَنْ يَطُوفُوا بَيْنَ الصَّفَا وَالْمَرْوَةِ فَلَمَّا جَاءَ الْإِسْلَامُ سَأَلُوا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَلِكَ فَأَنْزَلَ اللَّهُ تَعَالَى{ إِنَّ الصَّفَا وَالْمَرْوَةَ مِنْ شَعَائِرِ اللَّهِ }","id":"Telah menceritakan kepada Kami [Al Qa'nabi] dari [Malik] dari [Hisyam bin 'Urwah]. Dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada Kami [Ibnu As Sarh], telah menceritakan kepada Kami [Ibnu Wahb] dari [Malik] dari [Hisyam bin 'Urwah] dari [ayahnya] bahwa ia berkata; aku katakan kepada [Aisyah] isteri Nabi shallallahu 'alaihi wasallam dan pada saat itu aku adalah orang yang baru remaja; bagaimana pendapatmu mengenai firman Allah ta'ala: \"Sesungguhnya Shafaa dan Marwa adalah sebagian dari syi'ar Allah.\" Aku melihat tidak ada dosa sedikitpun atas seseorang untuk tidak melakukan sa'i antara keduanya. Aisyah berkata; tidak, seandainya sebagaimana yang engkau katakan maka ayatnya berbunyi: FALAA JUNAAHA 'ALAIHI ALLAA YATHTHAWWAFU BIHIMAA (maka tidak ada dosa baginya untuk tidak mengerjakan sa'i antara keduanya). Sesungguhnya ayat ini diturunkan mengenai orang-orang anshar, dahulu mereka bertalbiyah untuk Manah (nama berhala), dan Manah satu berhadapan dengan Qudaid (nama tempat antara Mekkah dan Madinah). Dan mereka enggan untuk melakukan thawaf antara Shafa dan Marwah, kemudian tatkala Islam datang, mereka bertanya kepada Rasulullah shallAllahu wa'alaihi wa sallam mengenai hal tersebut. Kemudian Allah ta'ala menurunkan ayat: \"Sesungguhnya Shafaa dan Marwa adalah sebagian dari syi'ar Allah\"."},"1563":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا خَالِدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا إِسْمَعِيلُ بْنُ أَبِي خَالِدٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي أَوْفَىأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اعْتَمَرَ فَطَافَ بِالْبَيْتِ وَصَلَّى خَلْفَ الْمَقَامِ رَكْعَتَيْنِ وَمَعَهُ مَنْ يَسْتُرُهُ مِنْ النَّاسِ فَقِيلَ لِعَبْدِ اللَّهِ أَدَخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْكَعْبَةَ قَالَ لَاحَدَّثَنَا تَمِيمُ بْنُ الْمُنْتَصِرِ أَخْبَرَنَا إِسْحَقُ بْنُ يُوسُفَ أَخْبَرَنَا شَرِيكٌ عَنْ إِسْمَعِيلَ بْنِ أَبِي خَالِدٍ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ أَبِي أَوْفَى بِهَذَا الْحَدِيثِ زَادَ ثُمَّ أَتَى الصَّفَا وَالْمَرْوَةَ فَسَعَى بَيْنَهُمَا سَبْعًا ثُمَّ حَلَقَ رَأْسَهُ","id":"Telah menceritakan kepada Kami [Musaddad], telah menceritakan kepada Kami [Khalid bin Abdullah], telah menceritakan kepada Kami [Isma'il bin Abu Khalid] dari [Abdullah bin Abu Aufa] bahwa Rasulullah shallAllahu wa'alaihi wa sallam melakukan umrah dan berthawaf di Ka'bah, serta melakukan shalat di belakang maqam dua raka'at. Dan beliau bersama orang yang menutupinya dari orang-orang. Kemudian Abdullah ditanya; apakah Rasulullah shallAllahu wa'alaihi wa sallam memasuki Ka'bah? Ia berkata; tidak. Telah menceritakan kepada Kami [Tamim bin Al Amuntashir], telah mengabarkan kepada Kami [Ishaq bin Yusuf], telah mengabarkan kepada Kami [Syarik], dari [Isma'il bin Abu Khalid], ia berkata; saya mendengar [Abdullah bin Abu Aufa] dengan hadits ini, ia menambahkan kata; kemudian beliau datang ke Shafa dan Marwa kemudian melakukan sa'i antara keduanya sebanyak tujuh kali, kemudian mencukur rambut kepalanya. "},"1564":{"ar":"حَدَّثَنَا النُّفَيْلِيُّ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا عَطَاءُ بْنُ السَّائِبِ عَنْ كَثِيرِ بْنِ جُمْهَانَأَنَّ رَجُلًا قَالَ لِعَبْدِ اللَّهِ بْنِ عُمَرَ بَيْنَ الصَّفَا وَالْمَرْوَةِ يَا أَبَا عَبْدِ الرَّحْمَنِ إِنِّي أَرَاكَ تَمْشِي وَالنَّاسُ يَسْعَوْنَ قَالَ إِنْ أَمْشِ فَقَدْ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمْشِي وَإِنْ أَسْعَ فَقَدْ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْعَى وَأَنَا شَيْخٌ كَبِيرٌ","id":"Telah menceritakan kepada Kami [An Nufaili], telah menceritakan kepada Kami [Zuhair], telah menceritakan kepada Kami ['Atho` bin As Saib], dari [Katsir bin Jamhan] bahwa seseorang berkata kepada [Abdullah bin Umar] diantara Shafa dan Marwa: wahai Abu Abdurrahman aku melihatmu berjalan antara Shafa dan Marwa, sementara orang-orang berlari-laki kecil? Dia menjawab: Kalau aku berjalan karena aku telah melihat Rasulullah shallallahu 'alaihi wasallam berjalan, dan kalau aku berlari-lari kecil karena aku juga telah melihat Rasulullah shallallahu 'alaihi wasallam berlari-lari kecil. Sementara aku sekarang aku sudah tua. "},"1565":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ وَعُثْمَانُ بْنُ أ��بِي شَيْبَةَ وَهِشَامُ بْنُ عَمَّارٍ وَسُلَيْمَانُ بْنُ عَبْدِ الرَّحْمَنِ الدِّمَشْقِيَّانِ وَرُبَّمَا زَادَ بَعْضُهُمْ عَلَى بَعْضٍ الْكَلِمَةَ وَالشَّيْءَ قَالُوا حَدَّثَنَا حَاتِمُ بْنُ إِسْمَعِيلَ حَدَّثَنَا جَعْفَرُ بْنُ مُحَمَّدٍ عَنْ أَبِيهِ قَالَدَخَلْنَا عَلَى جَابِرِ بْنِ عَبْدِ اللَّهِ فَلَمَّا انْتَهَيْنَا إِلَيْهِ سَأَلَ عَنْ الْقَوْمِ حَتَّى انْتَهَى إِلَيَّ فَقُلْتُ أَنَا مُحَمَّدُ بْنُ عَلِيِّ بْنِ حُسَيْنٍ فَأَهْوَى بِيَدِهِ إِلَى رَأْسِي فَنَزَعَ زِرِّي الْأَعْلَى ثُمَّ نَزَعَ زِرِّي الْأَسْفَلَ ثُمَّ وَضَعَ كَفَّهُ بَيْنَ ثَدْيَيَّ وَأَنَا يَوْمَئِذٍ غُلَامٌ شَابٌّ فَقَالَ مَرْحَبًا بِكَ وَأَهْلًا يَا ابْنَ أَخِي سَلْ عَمَّا شِئْتَ فَسَأَلْتُهُ وَهُوَ أَعْمَى وَجَاءَ وَقْتُ الصَّلَاةِ فَقَامَ فِي نِسَاجَةٍ مُلْتَحِفًا بِهَا يَعْنِي ثَوْبًا مُلَفَّقًا كُلَّمَا وَضَعَهَا عَلَى مَنْكِبِهِ رَجَعَ طَرَفَاهَا إِلَيْهِ مِنْ صِغَرِهَا فَصَلَّى بِنَا وَرِدَاؤُهُ إِلَى جَنْبِهِ عَلَى الْمِشْجَبِ فَقُلْتُ أَخْبِرْنِي عَنْ حَجَّةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ بِيَدِهِ فَعَقَدَ تِسْعًا ثُمَّ قَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَكَثَ تِسْعَ سِنِينَ لَمْ يَحُجَّ ثُمَّ أُذِّنَ فِي النَّاسِ فِي الْعَاشِرَةِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَاجٌّ فَقَدِمَ الْمَدِينَةَ بَشَرٌ كَثِيرٌ كُلُّهُمْ يَلْتَمِسُ أَنْ يَأْتَمَّ بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَيَعْمَلَ بِمِثْلِ عَمَلِهِ فَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَخَرَجْنَا مَعَهُ حَتَّى أَتَيْنَا ذَا الْحُلَيْفَةِ فَوَلَدَتْ أَسْمَاءُ بِنْتُ عُمَيْسٍ مُحَمَّدَ بْنَ أَبِي بَكْرٍ فَأَرْسَلَتْ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَيْفَ أَصْنَعُ فَقَالَ اغْتَسِلِي وَاسْتَذْفِرِي بِثَوْبٍ وَأَحْرِمِي فَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْمَسْجِدِ ثُمَّ رَكِبَ الْقَصْوَاءَ حَتَّى إِذَا اسْتَوَتْ بِهِ نَاقَتُهُ عَلَى الْبَيْدَاءِ قَالَ جَابِرٌ نَظَرْتُ إِلَى مَدِّ بَصَرِي مِنْ بَيْنِ يَدَيْهِ مِنْ رَاكِبٍ وَمَاشٍ وَعَنْ يَمِينِهِ مِثْلُ ذَلِكَ وَعَنْ يَسَارِهِ مِثْلُ ذَلِكَ وَمِنْ خَلْفِهِ مِثْلُ ذَلِكَ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ أَظْهُرِنَا وَعَلَيْهِ يَنْزِلُ الْقُرْآنُ وَهُوَ يَعْلَمُ تَأْوِيلَهُ فَمَا عَمِلَ بِهِ مِنْ شَيْءٍ عَمِلْنَا بِهِ فَأَهَلَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالتَّوْحِيدِ لَبَّيْكَ اللَّهُمَّ لَبَّيْكَ لَبَّيْكَ لَا شَرِيكَ لَكَ لَبَّيْكَ إِنَّ الْحَمْدَ وَالنِّعْمَةَ لَكَ وَالْمُلْكَ لَا شَرِيكَ لَكَ وَأَهَلَّ النَّاسُ بِهَذَا الَّذِي يُهِلُّونَ بِهِ فَلَمْ يَرُدَّ عَلَيْهِمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَيْئًا مِنْهُ وَلَزِمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَلْبِيَتَهُ قَالَ جَابِرٌ لَسْنَا نَنْوِي إِلَّا الْحَجَّ لَسْنَا نَعْرِفُ الْعُمْرَةَ حَتَّى إِذَا أَتَيْنَا الْبَيْتَ مَعَهُ اسْتَلَمَ الرُّكْنَ فَرَمَلَ ثَلَاثًا وَمَشَى أَرْبَعًا ثُمَّ تَقَدَّمَ إِلَى مَقَامِ إِبْرَاهِيمَ فَقَرَأَ{ وَاتَّخِذُوا مِنْ مَقَامِ إِبْرَاهِيمَ مُصَلًّى }فَجَعَلَ الْمَقَامَ بَيْنَهُ وَبَيْنَ الْبَيْتِ قَالَ فَكَانَ أَبِي يَقُولُ قَالَ ابْنُ نُفَيْلٍ وَعُثْمَانُ وَلَا أَعْلَمُهُ ذَكَرَهُ إِلَّا عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ سُلَيْمَانُ وَلَا أَعْلَمُهُ إِلَّا قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي الرَّكْعَتَيْنِ بِقُلْ هُوَ اللَّهُ أَحَدٌ وَقُلْ يَا أَيُّهَا الْكَافِرُونَ ثُمَّ رَجَعَ إِلَى الْبَيْتِ فَاسْتَلَمَ الرُّكْنَ ثُمَّ خَرَجَ مِنْ الْبَابِ إِلَى الصَّفَا فَلَمَّا دَنَا مِنْ الصَّفَا قَرَأَ{ إِنَّ الصَّفَا وَالْمَرْوَةَ مِنْ شَعَائِرِ اللَّهِ }نَبْدَأُ بِمَا بَدَأَ اللَّهُ بِهِ فَبَدَأَ بِالصَّفَا فَرَقِيَ عَلَيْهِ حَتَّى رَأَى الْبَيْتَ فَكَبَّرَ اللَّهَ وَوَحَّدَهُ وَقَالَ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ يُحْيِي وَيُمِيتُ وَهُوَ عَلَى كُلِّ شَيْءٍ قَدِيرٌ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ أَنْجَزَ وَعْدَهُ وَنَصَرَ عَبْدَهُ وَهَزَمَ الْأَحْزَابَ وَحْدَهُ ثُمَّ دَعَا بَيْنَ ذَلِكَ وَقَالَ مِثْلَ هَذَا ثَلَاثَ مَرَّاتٍ ثُمَّ نَزَلَ إِلَى الْمَرْوَةِ حَتَّى إِذَا انْصَبَّتْ قَدَمَاهُ رَمَلَ فِي بَطْنِ الْوَادِي حَتَّى إِذَا صَعَدَ مَشَى حَتَّى أَتَى الْمَرْوَةَ فَصَنَعَ عَلَى الْمَرْوَةِ مِثْلَ مَا صَنَعَ عَلَى الصَّفَا حَتَّى إِذَا كَانَ آخِرُ الطَّوَافِ عَلَى الْمَرْوَةِ قَالَ إِنِّي لَوْ اسْتَقْبَلْتُ مِنْ أَمْرِي مَا اسْتَدْبَرْتُ لَمْ أَسُقْ الْهَدْيَ وَلَجَعَلْتُهَا عُمْرَةً فَمَنْ كَانَ مِنْكُمْ لَيْسَ مَعَهُ هَدْيٌ فَلْيُحْلِلْ وَلْيَجْعَلْهَا عُمْرَةً فَحَلَّ النَّاسُ كُلُّهُمْ وَقَصَّرُوا إِلَّا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَنْ كَانَ مَعَهُ هَدْيٌ فَقَامَ سُرَاقَةُ بْنُ جُعْشُمٍ فَقَالَ يَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلِعَامِنَا هَذَا أَمْ لِلْأَبَدِ فَشَبَّكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَصَابِعَهُ فِي الْأُخْرَى ثُمَّ قَالَ دَخَلَتْ الْعُمْرَةُ فِي الْحَجِّ هَكَذَا مَرَّتَيْنِ لَا بَلْ لِأَبَدِ أَبَدٍ لَا بَلْ لِأَبَدِ أَبَدٍ قَالَ وَقَدِمَ عَلِيٌّ رَضِيَ اللَّهُ عَنْهُ مِنْ الْيَمَنِ بِبُدْنِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَوَجَدَ فَاطِمَةَ رَضِيَ اللَّهُ عَنْهَا مِمَّنْ حَلَّ وَلَبِسَتْ ثِيَابًا صَبِيغًا وَاكْتَحَلَتْ فَأَنْكَرَ عَلِيٌّ ذَلِكَ عَلَيْهَا وَقَالَ مَنْ أَمَرَكِ بِهَذَا فَقَالَتْ أَبِي فَكَانَ عَلِيٌّ يَقُولُ بِالْعِرَاقِ ذَهَبْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُحَرِّشًا عَلَى فَاطِمَةَ فِي الْأَمْرِ الَّذِي صَنَعَتْهُ مُسْتَفْتِيًا لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الَّذِي ذَكَرَتْ عَنْهُ فَأَخْبَرْتُهُ أَنِّي أَنْكَرْتُ ذَلِكَ عَلَيْهَا فَقَالَتْ إِنَّ أَبِي أَمَرَنِي بِهَذَا فَقَالَ صَدَقَتْ صَدَقَتْ مَاذَا قُلْتَ حِينَ فَرَضْتَ الْحَجَّ قَالَ قُلْتُ اللَّهُمَّ إِنِّي أُهِلُّ بِمَا أَهَلَّ بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَإِنَّ مَعِيَ الْهَدْيَ فَلَا تَحْلِلْ قَالَ وَكَانَ جَمَاعَةُ الْهَدْيِ الَّذِي قَدِمَ بِهِ عَلِيٌّ مِنْ الْيَمَنِ وَالَّذِي أَتَى بِهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْمَدِينَةِ مِائَةً فَحَلَّ النَّاسُ كُلُّهُمْ وَقَصَّرُوا إِلَّا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَنْ كَانَ مَعَهُ هَدْيٌ قَالَ فَلَمَّا كَانَ يَوْمُ التَّرْوِيَةِ وَوَجَّهُوا إِلَى مِنًى أَهَلُّوا بِالْحَجِّ فَرَكِبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى بِمِنًى الظُّهْرَ وَالْعَصْرَ وَالْمَغْرِبَ وَالْعِشَاءَ وَالصُّبْحَ ثُمَّ مَكَثَ قَلِيلًا حَتَّى طَلَعَتْ الشَّمْسُ وَأَمَرَ بِقُبَّةٍ لَهُ مِنْ شَعْرٍ فَضُرِبَتْ بِنَمِرَةٍ فَسَارَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَا تَشُكُّ قُرَيْشٌ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاقِفٌ عِنْدَ الْمَشْعَرِ الْحَرَامِ بِالْمُزْدَلِفَةِ كَمَا كَانَتْ قُرَيْشٌ تَصْنَعُ فِي الْجَاهِلِيَّةِ فَأَجَازَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى أَتَى عَرَفَةَ فَوَجَدَ الْقُبَّةَ قَدْ ضُرِبَتْ لَهُ بِنَمِرَةٍ فَنَزَلَ بِهَا حَتَّى إِذَا زَاغَتْ الشَّمْسُ أَمَرَ بِالْقَصْوَاءِ فَرُحِلَتْ لَهُ فَرَكِبَ حَتَّى أَتَى بَطْنَ الْوَادِي فَخَطَبَ النَّاسَ فَقَالَ إِنَّ دِمَاءَكُمْ وَأَمْوَالَكُمْ عَلَيْكُمْ حَرَامٌ كَحُرْمَةِ يَوْمِكُمْ هَذَا فِي شَهْرِكُمْ هَذَا فِي بَلَدِكُمْ هَذَا أَلَا إِنَّ كُلَّ شَيْءٍ مِنْ أَمْرِ الْجَاهِلِيَّةِ تَحْتَ قَدَمَيَّ مَوْضُوعٌ وَدِمَاءُ الْجَاهِلِيَّةِ مَوْضُوعَةٌ وَأَوَّلُ دَمٍ أَضَعُهُ دِمَاؤُنَا دَمُ قَالَ عُثْمَانُ دَمُ ابْنُ رَبِيعَةَ و قَالَ سُلَيْمَانُ دَمُ رَبِيعَةَ بْنِ الْحَارِثِ بْنِ عَبْدِ الْمُطَّلِبِ و قَالَ بَعْضُ هَؤُلَاءِ كَانَ مُسْتَرْضَعًا فِي بَنِي سَعْدٍ فَقَتَلَتْهُ هُذَيْلٌ وَرِبَا الْجَاهِلِيَّةِ مَوْضُوعٌ وَأَوَّلُ رِبًا أَضَعُهُ رِبَانَا رِبَا عَبَّاسِ بْنِ عَبْدِ الْمُطَّلِبِ فَإِنَّهُ مَوْضُوعٌ كُلُّهُ اتَّقُوا اللَّهَ فِي النِّسَاءِ فَإِنَّكُمْ أَخَذْتُمُوهُنَّ بِأَمَانَةِ اللَّهِ وَاسْتَحْلَلْتُمْ فُرُوجَهُنَّ بِكَلِمَةِ اللَّهِ وَإِنَّ لَكُمْ عَلَيْهِنَّ أَنْ لَا يُوطِئْنَ فُرُشَكُمْ أَحَدًا تَكْرَهُونَهُ فَإِنْ فَعَلْنَ فَاضْرِبُوهُنَّ ضَرْبًا غَيْرَ مُبَرِّحٍ وَلَهُنَّ عَلَيْكُمْ رِزْقُهُنَّ وَكِسْوَتُهُنَّ بِالْمَعْرُوفِ وَإِنِّي قَدْ تَرَكْتُ فِيكُمْ مَا لَنْ تَضِلُّوا بَعْدَهُ إِنْ اعْتَصَمْتُمْ بِهِ كِتَابَ اللَّهِ وَأَنْتُمْ مَسْئُولُونَ عَنِّي فَمَا أَنْتُمْ قَائِلُونَ قَالُوا نَشْهَدُ أَنَّكَ قَدْ بَلَّغْتَ وَأَدَّيْتَ وَنَصَحْتَ ثُمَّ قَالَ بِأُصْبُعِهِ السَّبَّابَةِ يَرْفَعُهَا إِلَى السَّمَاءِ وَيَنْكُبُهَا إِلَى النَّاسِ اللَّهُمَّ اشْهَدْ اللَّهُمَّ اشْهَدْ اللَّهُمَّ اشْهَدْ ثُمَّ أَذَّنَ بِلَالٌ ثُمَّ أَقَامَ فَصَلَّى الظُّهْرَ ثُمَّ أَقَامَ فَصَلَّى الْعَصْرَ وَلَمْ يُصَلِّ بَيْنَهُمَا شَيْئًا ثُمَّ رَكِبَ الْقَصْوَاءَ حَتَّى أَتَى الْمَوْقِفَ فَجَعَلَ بَطْنَ نَاقَتِهِ الْقَصْوَاءِ إِلَى الصَّخَرَاتِ وَجَعَلَ حَبْلَ الْمُشَاةِ بَيْنَ يَدَيْهِ فَاسْتَقْبَلَ الْقِبْلَةَ فَلَمْ يَزَلْ وَاقِفًا حَتَّى غَرَبَتْ الشَّمْسُ وَذَهَبَتْ الصُّفْرَةُ قَلِيلًا حِينَ غَابَ الْقُرْصُ وَأَرْدَفَ أُسَامَةَ خَلْفَهُ فَدَفَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَس","id":"Telah menceritakan kepada Kami [Abdullah bin Muhammad An Nufaili], [Utsman bin Abu Syaibah], [Hisyam bin 'Ammar] serta [Sulaiman bin Abdurrahman Ad Dimasyqi], dan kemungkinan sebagian mereka menambahkan atas sebagian yang lain satu kalimat. Mereka mengatakan; telah menceritakan kepada Kami [Hatim bin Isma'il], telah menceritakan kepada Kami [Ja'far bin Muhammad] dari [ayahnya], ia berkata; Kami menemui [Jabir bin Abdullah], kemudian tatkala Kami sampai kepadanya ia bertanya mengenai orang-orang tersebut hingga sampai kepadaku. Aku katakan; aku adalah Muhammad bin Ali bin Husain. Kemudian ia mengulurkan tangannya ke kepalaku dan melepas kancing bajuku yang atas, kemudian melepas kancing bajuku yang paling bawah, kemudian meletakkan telapak tangannya antara dua putting susu dan aku pada saat itu adalah seorang anak muda. Kemudian ia berkata; selamat datang untukmu wahai saudaraku. Bertanyalah apa yang engkau kehendaki. Kemudian aku bertanya kepadanya sementara ia adalah orang yang buta. Kemudian datang waktu shalat, lalu ia berdiri dengan memakai baju yang ditangkapkan sebagiannya kepada sebagian yang lain, setiap kali ia meletakkan di atas pundaknya maka kedua ujungnya akan kembali kepadanya karena kecilnya pakaian tersebut. Kemudian ia melakukan shalat bersama Kami sementara selendangnya ke sampingnya di atas tempat untuk sangkutan pakaian. Lalu aku katakan; beritahukan kepada Kami mengenai haji Rasulullah shallAllahu wa'alaihi wa sallam! Kemudian ia memberikan isyarat dengan tangannya dan ia menghitung sembilan. Kemudian berkata; sesungguhnya Rasulullah shallAllahu wa'alaihi wa sallam tinggal selama sembilan tahun tidak melakukan haji, kemudian diumumkan di antara orang-orang pada tahun ke sembilan bahwa Rasulullah shallAllahu wa'alaihi wa sallam hendak melakukan haji. Kemudian orang-orang banyak yang datang ke Madinah, seluruh mereka ingin mengikuti Rasulullah shallAllahu wa'alaihi wa sallam dan melakukan seperti apa yang beliau lakukan. Kemudian Rasulullah shallAllahu wa'alaihi wa sallam keluar dan Kami pun keluar bersamanya hingga Kami sampai ke Dzul Hulaifah, dan Asma` binti 'Umais melahirkan Muhammad bin Abu Bakr. Lalu ia mengirim utusan kepada Rasulullah shallAllahu wa'alaihi wa sallam bertanya; apa yang aku lakukan? Kemudian beliau bersabda: \"Mandilah dan balutlah farjimu (kemaluanmu) menggunakan kain, dan berihramlah.\" Lalu Rasulullah shallAllahu wa'alaihi wa sallam melakukan shalat di masjid, kemudian menaiki unta Al Qashwa`, hingga setelah untanya berada di atas Al Baida`…. -Jabir berkata; aku melihat ke arah sejauh mataku memandang di hadapanku, dari orang-orang yang berkendaraan dan yang berjalan dan dari samping kanannya seperti itu, dan dari samping kirinya seperti itu, dan dari belakangnya seperti itu. Dan Rasulullah shallAllahu wa'alaihi wa sallam berada di antara Kami, dan kepadanya turun Al Qur'an, dan beliau mengetahui takwilnya. Apa yang beliau lakukan maka Kami melakukannya, kemudian beliau bertalbiyah dengan kalimat tauhid: LABBAIKALLAAHUMMA LABBAIK, LABBAIKA LAA SYARIIKA LAKA LABBAIK INNAL HAMDA WAN NI'MATA WAL MULKA LAA SYARII KALAK. (ya Allah, aku memenuhi seruanMu, aku memenuhi seruanMu, aku memenuhi seruanMu. Tidak ada sekutu bagiMu, aku memenuhi seruanMu, sesungguhnya segala puji, kenikmatan dan seluruh kerajaan adalah milikMu, tidak ada sekutu bagiMu). Dan orang-orang bertalbiyah dengan talbiyah yang mereka ucapan ini, dan Rasulullah shallAllahu wa'alaihi wa sallam tidak menolak sedikitpun dari hal tersebut, dan Rasulullah shallAllahu wa'alaihi wa sallam terus mengucapkan talbiyahnya. Jabir berkata; Kami hanya berniat untuk melakukan haji, Kami tidak mengetahui bagaimana umrah itu, hingga Kami sampai ke Ka'bah bersama beliau. Beliau mengusap rukun dan berlari-lari kecil tiga kali putaran dan berjalan biasa sebanyak empat kali putaran kemudian maju ke Maqam Ibrahim dan membaca ayat: \"Dan jadikanlah sebagian maqam Ibrahim tempat shalat.\" Kemudian beliau menjadikan Maqam Ibrahim antara beliau dan Ka'bah. Perowi berkata; [ayahku] berkata; [Ibnu Nufail] dan [Utsman] berkata; …. -dan aku tidak mengetahuinya kecuali berasal dari Nabi shallallahu 'alaihi wasallam- [Sulaiman] mengatakan; dan aku tidak mengetahuinya kecuali mengatakan; Rasulullah shallAllahu wa'alaihi wa sallam dalam dua raka'at membaca Surat Al Ikhlas dan Surat Al Kaafiruun. Kemudian beliau kembali ke Ka'bah dan mengusap rukun kemudian keluar dari pintu menuju Shafa. Kemudian tatkala telah mendekati Shafa beliau membaca: \"INNASH SHAFA WAL MARWATA MIN SYA'AAIRILLAAH, NABDAU BIMAA BADA-ALLAAHU BIHI.\" (Sesungguhnya Shafaa dan Marwa adalah sebagian dari syi'ar Allah. Kita memulai seperti yang Allah mulai). Kemudian beliau memulai dari Shafa, beliau menaikinya hingga melihat Ka'bah, kemudian bertakbir serta mentauhidkan Allah. Beliau mengucapkan: \"LAA ILAAHA ILALLAAHU WAHDAHU LAA SYARIIKA LAHU, LAHUL MULKU WA LAHUL HAMDU YUHYII WA YUMIITU WA HUWA 'ALAA KULLI SYAI IN QADIIR. LAA ILAAHA ILLALLAAHU WAHDAH, ANJAZA WA'DAH WA NASHARA 'ABDAH, WA HAZAMAL AHZAABA WAHDAH.\" (Tidak ada tuhan yang berhak disembah kecuali Allah semata tidak ada sekutu bagiNya, milikNya seluruh kerajaan dan bagiNya segala puji, Dia Yang menghidupkan dan Yang mematikan dan Dia Maha Mampu melakukan segala sesuatu. Tidak ada tuhan yang berhak disembah kecuali Allah semata, Dia menyelamatkan dengan sendirian, dan menolong hambaNya serta mengalahkan kelompok-kelompok musuh sendirian). Kemudian beliau berdoa diantara hal tersebut dan mengucapkan seperti itu tiga kali, kemudian beliau turun ke Marwa hingga setelah kedua telapak kakinya menginjak padanya, beliau berlari-lari kecil di tengah lembah, hingga setelah naik beliau berjalan hingga sampai ke Marwa, dan di atas Marwa beliau melakukan seperti yang beliau lakukan di Shafa. Hingga setelah akhir thawaf di atas Marwa beliau mengatakan: \"\"Jika dulu tampak kepadaku perkara yang terlihat saat ini maka aku tidak akan membawa hewan kurban dan menjadikannya umrah, maka barang siapa diantara kalian yang tidak membawa hewan kurban maka hendaknya ia bertahallul dan menjadikannya umrah.\" Kemudian orang-orang bertahallul semua dan memotong rambut, kecuali Nabi shallallahu 'alaihi wasallam dan orang-orang yang membawa hewan kurban. Kemudian Suraqah bin Ju'syam berkata; wahai Rasulullah, apakah untuk tahun kita ini saja atau untuk selamanya? Kemudian Rasulullah shallAllahu wa'alaihi wa sallam menjalin jari-jarinya kemudian berkata: \"Telah masuk umrah dalam haji seperti ini.\" Beliau mengucapkannya dua kali.\"Tidak, melainkan untuk selamanya.\" Ali radliallahu 'anhu datang dari Yaman membawa unta Nabi shallallahu 'alaihi wasallam dan ia mendapati Fathimah radliallahu 'anha diantara orang-orang yang telah bertahallul dan memakai pakaian yang longgar serta bercelak. Kemudian Ali mengingkarinyadna berkata; siapakah yang memerintahkanmu melakukan hal ini? Fathimah berkata; ayahku. Ali di Irak pernah berkata; aku datang kepada Rasulullah shallAllahu wa'alaihi wa sallam untuk memprovokasi terhadap Fathimah mengenai perkara yang ia perbuat dan meminta fatwa kepada Rasulullah shallAllahu wa'alaihi wa sallam mengenai apa yang telah ia sebutkan. Lalu aku beritahukan kepada beliau bahwa aku mengingkari apa yang ia perbuat tersebut. Lalu Fathimah berkata; sesungguhnya ayahku telah memerintahkan hal ini kepadaku. Kemudian Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Ia benar, ia benar. Apakah yang engkau ucapkan ketika hendak berhaji?\" Ali berkata; aku ucapkan: ALLAAHUMMA INNII UHILLU BIMAA AHALLA BIHI RASUULULLAH SHALLALLAHU 'ALAIHI WASALLAM. (ya Allah, aku bertalbiyah dengan talbiyah Rasulullah shallAllahu wa'alaihi wa sallam). Beliau mengatakan: \"Sesungguhnya aku membawa hewan kurban, maka janganlah engkau bertahallul.\" Dan sekelompok hewan kurban yang dibawa Ali dri Yaman dan yang dibawa Nabi shallallahu 'alaihi wasallam dari Madinah berjumlah seratus. Kemudian semua orang bertahallul dan memotong rambut kecuali Nabi shallallahu 'alaihi wasallam dan orang-orang yang membawa hewan kurban. Kemudian tatkala pada Hari Tarwiyah dan mereka mengarahkan ke Mina, mereka bertalbiyah untuk melakukan haji. Kemudian Rasulullah shallAllahu wa'alaihi wa sallam menaiki kendaraan dan melakukan shalat di Zhuhur, Ashar, Maghrib dan Isya`serta Subuh di Mina, kemudian beliau tinggal beberapa saat hingga terbit matahari, dan memerintahkan untuk mendirikkan Qubbah untuk beliau yang terbuat dari rambut. Kemudian Qubbah tersebut di dirikan di daerah Namirah, lalu Rasulullah shallAllahu wa'alaihi wa sallam berjalan dan orang-orang Quraisy tidak ragu bahwa Rasulullah shallAllahu wa'alaihi wa sallam berwukuf di Masy'ar Haram di Muzdalifah sebagaimana dahulu orang-orang Quraisy melakukannya pada masa Jahiliyah. Kemudian Rasulullah shallAllahu wa'alaihi wa sallam lewat hingga sampai ke Arafah dan mendapati Qubbah telah didirikan untuk beliau di Namirah. Kemudian beliau singgah di sana hingga setelah matahari tenggelam beliau memerintahkan agar untanya yang bernama Qashwa` dipersiapkan, kemudian diberi pelana lalu beliau pergi ke tengah bukit dan berkhutbah dan berkata: \"Sesungguhnya darah dan harta kalian adalah haram seperti haramnya hari kalian ini, pada bulan kalian ini dan di Negeri kalian ini. Ketahuilah sesungguhnya segala perkara pada masa jahiliyah ditinggalkan di bawah kedua kakiku, darah pada masa jahiliyah telah digugurkan dan darah pertama yang digugurkan adalah darah Kami - Utsman berkata; yaitu darah Ibnu Rabi'ah. Sedangkan Sulaiman mengatakan; darah Rabi'ah bin Al Harits bin Abdul Muththalib. Sebagian mereka mengatakan; dahulu ia disusui di kalangan orang-orang Bani Sa'd, kemudian ia dibunuh oleh orang-orang Hudzail- dan riba jahiliyah telah dibatalkan, riba pertama yang aku batalkan adalah riba Kami yaitu riba Abbas bin Abdul Muththalib, sesungguhnya riba tersebut semuanya dibatalkan. Bertakwalah kalian kepada Allah dalam menghadapi para wanita, sesungguhnya kalian mengambil mereka dengan amanah Allah, dan menghalalkan farji kalian dengan kalimat Allah, sesungguhnya hak kalian atas mereka adalah supaya mereka tidak mempersilahkan orang yang tidak kalian sukai memasuki rumah kalian, apabila mereka melakukan hal tersebut maka pukullah mereka dengan pukulan yang tidak menyakitkan. Mereka memiliki hak atas kalian untuk memberikan makan serta pakaian kepada mereka dengan cara yang baik. Dan aku telah meninggalkan pada kalian sesuatu yang kalian tidak akan tersesat setelahnya apabila kalian berpegang teguh dengannya, yaitu Kitab Allah (Al Qur'an). Kalian mendapatkan pertanyaan mengenai diriku, apakah pendapat kalian?\" Mereka menjawab; Kami bersaksi bahwa anda telah menyampaikan dan menunaikan risalah serta memberikan nasehat. Kemudian beliau bersabda dengan mengangkat jari telunjuknya ke langit dan mengarahkan kepada orang-orang beliau mengatakan: \"Ya Allah, saksikanlah, ya Allah saksikanlah.\" Kemudian Bilal mengumandangkan adzan dan iqamah satu kali. Kemudian beliau melakukan shalat Zhuhur kemudian berdiri dan melakukan shalat Ashar serta tidak melakukan shalat apapun di antara keduanya. Kemudian beliau menaiki Al Qaswa` hingga sampai ke tempat wuquf dan menempatkan perut untanya yaitu Al Qashwa` menghadap bebetuan, dan menempatkan Hablul Musyah (yaitu tempat mereka berkumpul) di hadapan beliau kemudian beliau menghadap Kiblat, dan beliau tetap berdiri hingga matahari tengelam dan warna kuning telah menghilang sedikit hingga bulatannya telah tenggelam. Lalu beliau memboncengkan Usamah di belakangnya kemudian berjalan dan menarik tali kendali unta beliau yang bernama Qashwa` hingga kepalanya menyentuh pangkal pelananya, dan beliau berkata dengan tangannya yang kanan: \"Tenang wahai manusia, tenanglah wahai manusia.\" Setiap kali kepalanya mendekati tali maka beliau mengendorkan sedikit, hingga naik dan beliau sampai di Muzdalifah, lalu beliau menjama' shalat Maghrib serta Isya` dengan satu adzan dan dua iqamah, [Utsman] mengatakan; dan beliau tidak melakukan shalat sunah sedikitpun diantara keduanya. Kemudian lafazh mereka sama, yaitu; Kemudian beliau berbaring hingga setelah terbit fajar beliau melakukan shalat Subuh ketika telah jelas waktu subuh. [Sulaiman] mengatakan; dengan satu adzan dan iqamah. Kemudian lafazh mereka sama, yaitu; Kemudian beliau menunggangi Qashwa` hingga berdiri di atas Masy'ar Al Haram, dan menaikinya. [Utsman] dan [Sulaiman] berkata; dan menghadap ke Kiblat. Lalu beliau memuji kepada Allah mengagungkan serta bertahlil. [Utsman] menambahkan; dan mentauhidkanNya. Beliau terus berdiri hingga cahaya pagi sangat menyebar, kemudian beliau bertolak sebelum matahari terbit, dan memboncengkan Al Fadhl bin Al Abbas, ia adalah laki-laki yang berambut indah, putih dan indah bersinar. Kemudian setelah Nabi shallallahu 'alaihi wasallam bertolak beliau melewati beberapa orang wanita yang berlari, lalu Al Fadhl mulai melihat kepada mereka dan Nabi shallallahu 'alaihi wasallam meletakkan tangannya di wajah Al Fadhl kemudian Al Fadhl memalingkan wajahnya ke sisi yang lain. Lalu Nabi shallallahu 'alaihi wasallam memindahkan tangannya ke sisi yang lain dan Al Fadhl memalingkan wajahnya ke sisi yang lain dengan tetap melihat, hingga setelah sampai di Muhassir beliau menggerakkan sedikit kemudian menelusuri jalan tengah yang mengeluarkanmu ke Jumrah Kubra hingga sampai Jumrah yang padanya terdapat pohon, kemudian beliau melempar dengan tujuh kerikil dan bertakbir pada setiap lemparan kerikil seperti kerikil khadzaf (ketapel). Beliau melempar dari tengah bukit kemudian pergi ke tempat penyembelihan dan menyembelih enam puluh tiga unta menggunakan tangannya, dan memerintahkan Ali lalu ia menyembelih yang tersisa dan beliau ikut serta menyembelih unta beliau, kemudian memerintahkan dari setiap seekor unta dikerjakan lebih dari dua orang kemudian di letakkan di dalam kuwali lalu dimasak. Mereka berdua makan sebagian dagingnya dan minum sebagian kuahnya. [Sulaiman] berkata; kemudian beliau menunggang kendaraan dan kembali ke Ka'bah dan melakukan shalat Zhuhur di Mekkah kemudian mendatangi Bani Abdul Muththalib sementara mereka mengambil air Zamzam, kemudian beliau bersabda: \"Minumlah wahai Bani Abdul Muththalib, seandainya orang-orang tidak akan mengalahkan kalian dalam memberi minum, sungguh aku akan minum bersama kalian.\" Kemudian mereka memberi beliau satu ember kemudian beliau minum sebagian darinya."},"1566":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ حَدَّثَنَا سُلَيْمَانُ يَعْنِي ابْنَ بِلَالٍ ح و حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا عَبْدُ الْوَهَّابِ الثَّقَفِيُّ الْمَعْنَى وَاحِدٌ عَنْ جَعْفَرِ بْنِ مُحَمَّدٍ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى الظُّهْرَ وَالْعَصْرَ بِأَذَانٍ وَاحِدٍ بِعَرَفَةَ وَلَمْ يُسَبِّحْ بَيْنَهُمَا وَإِقَامَتَيْنِ وَصَلَّى الْمَغْرِبَ وَالْعِشَاءَ بِجَمْعٍ بِأَذَانٍ وَاحِدٍ وَإِقَامَتَيْنِ وَلَمْ يُسَبِّحْ بَيْنَهُمَاقَالَ أَبُو دَاوُد هَذَا الْحَدِيثُ أَسْنَدَهُ حَاتِمُ بْنُ إِسْمَعِيلَ فِي الْحَدِيثِ الطَّوِيلِ وَوَافَقَ حَاتِمَ بْنَ إِسْمَعِيلَ عَلَى إِسْنَادِهِ مُحَمَّدُ بْنُ عَلِيٍّ الْجُعْفِيُّ عَنْ جَعْفَرٍ عَنْ أَبِيهِ عَنْ جَابِرٍ إِلَّا أَنَّهُ قَالَ فَصَلَّى الْمَغْرِبَ وَالْعَتَمَةَ بِأَذَانٍ وَإِقَامَةٍ","id":"Telah menceritakan kepada Kami [Abdullah bin Maslamah], telah menceritakan kepada Kami [Sulaiman yaitu Ibnu Bilal]. Telah diriwayatkan melalui jalur yang lain: Telah menceritakan kepada Kami [Ahmad bin Hanbal], telah menceritakan kepada Kami [Abdul Wahhab Ats Tsaqafi] dan maknanya satu, dari [Ja'far bin Muhammad], dari [ayahnya], bahwa Nabi shallallahu 'alaihi wasallam melakukan Shalat Zhuhur, dan 'Ashar dengan satu adzan di 'Arafah. Dan tidak melakukan shalat sunah serta dua iqamah. Beliau melakukan Shalat Maghrib, serta Isya` dijama', dengan satu adzan dan dua iqamah, serta tidak melakukan shalat sunah diantara keduanya. Abu Daud berkata; hadits ini di sanadkan oleh [Hatim bin Isma'il] dalam hadits yang panjang dan sanad Hatim bin Isma'il telah disepakati oleh [Muhammad bin Ali Al Ju'fi], dari [Ja'far], dari [ayahnya] dari [Jabir] hanya saja ia berkata; kemudian melakukan Shalat Maghrib serta 'Isya` dengan satu adzan dan satu iqamah."},"1567":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا جَعْفَرٌ حَدَّثَنَا أَبِي عَنْ جَابِرٍ قَالَثُمَّ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ نَحَرْتُ هَا هُنَا وَمِنًى كُلُّهَا مَنْحَرٌ وَوَقَفَ بِعَرَفَةَ فَقَالَ قَدْ وَقَفْتُ هَا هُنَا وَعَرَفَةُ كُلُّهَا مَوْقِفٌ وَوَقَفَ بِالْمُزْدَلِفَةِ فَقَالَ قَدْ وَقَفْتُ هَا هُنَا وَمُزْدَلِفَةُ كُلُّهَا مَوْقِفٌحَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ عَنْ جَعْفَرٍ بِإِسْنَادِهِ زَادَ فَانْحَرُوا فِي رِحَالِكُمْ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ عَنْ جَعْفَرٍ حَدَّثَنِي أَبِي عَنْ جَابِرٍ فَذَكَرَ هَذَا الْحَدِيثَ وَأَدْرَجَ فِي الْحَدِيثِ عِنْدَ قَوْلِهِ{ وَاتَّخِذُوا مِنْ مَقَامِ إِبْرَاهِيمَ مُصَلًّى }قَالَ فَقَرَأَ فِيهِمَا بِالتَّوْحِيدِ وَقُلْ يَا أَيُّهَا الْكَافِرُونَ وَقَالَ فِيهِ قَالَ عَلِيٌّ رَضِيَ اللَّهُ عَنْهُ بِالْكُوفَةِ قَالَ أَبِي هَذَا الْحَرْفُ لَمْ يَذْكُرْهُ جَابِرٌ فَذَهَبْتُ مُحَرِّشًا وَذَكَرَ قِصَّةَ فَاطِمَةَ رَضِيَ اللَّهُ عَنْهَا","id":"Telah menceritakan kepada Kami [Ahmad bin Hanbal], telah menceritakan kepada Kami [Yahya bin Sa'id], telah menceritakan kepada Kami [ja'far], telah menceritakan kepada Kami [ayahku], dari [Jabir], ia berkata; kemudian Nabi bersabda: \"Aku telah menyembelih di sini, dan Mina seluruhnya adalah tempat menyembelih.\" Kemudian beliau berwukuf di Arafah dan mengatakan: \"Aku telah berwukuf di sini, dan Arafah seluruhnya adalah tempat untuk wukuf.\" Dan beliau berwukuf di Muzdalifah serta mengatakan: \"Aku telah berwukuf di sini, dan Muzdalifah seluruhnya adalah empat berwukuf.\" Telah menceritakan kepada Kami [Musaddad], telah menceritakan kepada Kami [Hafsh bin Ghiyats] dari [Ja'far] dengan sanadnya dan ia menambahkan kata: \"Sembelihlah di tempat-tempat tinggal kalian!\" Telah menceritakan kepada Kami [Ya'qub bin Ibrahim], telah menceritakan kepada Kami [Yahya bin Sa'id Al Qaththan], dari [Ja'far], telah menceritakan kepadaku [ayahku], dari [Jabir] …. kemudian ia menyebutkan hadits ini. Dan ia menyebutkan dalam hadits secara bertahap pada firmanNya: \"Dan jadikanlah sebahagian maqam Ibrahim tempat shalat.\" Kemudian beliau membaca pada dua raka'at tersebut Surat Al Ikhlash dan Al Kaafiruun. Dalam hadits tersebut Ja'far mengatakan; Ali radliallahu 'anhu di Kufah berkata; …….. ayahku mengatakan; kata ini tidak disebutkan Jabir, kemudian aku pergi untuk memprovokasi ….. Dan ia menyebutkan kisah Fathimah radliallahu 'anha. "},"1568":{"ar":"حَدَّثَنَا هَنَّادٌ عَنْ أَبِي مُعَاوِيَةَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْكَانَتْ قُرَيْشٌ وَمَنْ دَانَ دِينَهَا يَقِفُونَ بِالْمُزْدَلِفَةِ وَكَانُوا يُسَمَّوْنَ الْحُمُسَ وَكَانَ سَائِرُ الْعَرَبِ يَقِفُونَ بِعَرَفَةَ قَالَتْ فَلَمَّا جَاءَ الْإِسْلَامُ أَمَرَ اللَّهُ تَعَالَى نَبِيَّهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَأْتِيَ عَرَفَاتٍ فَيَقِفَ بِهَا ثُمَّ يُفِيضُ مِنْهَا فَذَلِكَ قَوْلُهُ تَعَالَى{ ثُمَّ أَفِيضُوا مِنْ حَيْثُ أَفَاضَ النَّاسُ }","id":"Telah menceritakan kepada Kami [Hannad] dari [Abu Mu'awiyah] dari [Hisyam bin 'Urwah] dari [bapaknya] dari [Aisyah], ia berkata; dahulu orang-orang Quraisy dan orang-orang yang beragama seperti agama mereka berwukuf di Muzdalifah mereka dinamakan Al Humusa, sedangkan orang-orang Arab yang lain berwukuf di Arafah. Ketika Islam datang, Allah memerintahkan NabiNya shalla Allahu 'alaihi wa sallam untuk datang ke Arafah dan wukuf disana kemudian bertolak darinya, dan itulah yang dimaksud dari Firman Allah: \"Kemudian bertolaklah kamu dari tempat bertolaknya orang-orang banyak ('Arafah).\""},"1569":{"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا الْأَحْوَصُ بْنُ جَوَّابٍ الضَّبِّىُّ حَدَّثَنَا عَمَّارُ بْنُ رُزَيْقٍ عَنْ سُلَيْمَانَ الْأَعْمَشِ عَنْ الْحَكَمِ عَنْ مِقْسَمٍ عَنْ ابْنِ عَبَّاسٍ قَالَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الظُّهْرَ يَوْمَ التَّرْوِيَةِ وَالْفَجْرَ يَوْمَ عَرَفَةَ بِمِنًى","id":"Telah menceritakan kepada Kami [Zuhair bin Harb], telah menceritakan kepada Kami [Al Ahwash bin Jawwab Adh Dhabbi], telah menceritakan kepada Kami ['Ammar bin Ruzaiq] dari [Sulaiman Al A'masy] dari [Al Hakam] dari [Miqsam] dari [Ibnu Abbas], ia berkata: Rasulullah shallallahu 'alaihi wasallam melakukan Shalat Zhuhur pada hari Tarwiyah dan Shalat Subuh pada hari Arafah di Mina. "},"1570":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا إِسْحَقُ الْأَزْرَقُ عَنْ سُفْيَانَ عَنْ عَبْدِ الْعَزِيزِ بْنِ رَفِيعٍ قَالَ سَأَلْتُ أَنَسَ بْنَ مَالِكٍ قُلْتُأَخْبِرْنِي بِشَيْءٍ عَقَلْتَهُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيْنَ صَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الظُّهْرَ يَوْمَ التَّرْوِيَةِ فَقَالَ بِمِنًى قُلْتُ فَأَيْنَ صَلَّى الْعَصْرَ يَوْمَ النَّفْرِ قَالَ بِالْأَبْطَحِ ثُمَّ قَالَ افْعَلْ كَمَا يَفْعَلُ أُمَرَاؤُكَ","id":"Telah menceritakan kepada Kami [Ahmad bin Ibrahim], telah menceritakan kepada Kami [Ishaq Al Azraq] dari [Sufyan] dari [Abdul Aziz bin Rafi'], ia berkata; saya bertanya kepada [Anas bin Malik], aku katakan; beritahukan kepadaku sesuatu yang engkau ketahui dari Rasulullah shallAllahu wa'alaihi wa sallam, dimana beliau melakukan Shalat Zhuhur pada Hari Tarwiyah?! Ia berkata; di Mina. Aku katakan; dimanakah beliau melakukan Shalat 'Ashar pada Hari Nafar? Ia berkata; Di Abthah. Kemudian ia berkata; lakukan seperti yang dilakukan para pemimpin kalian. "},"1571":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا أَبِي عَنْ ابْنِ إِسْحَقَ حَدَّثَنِي نَافِعٌ عَنْ ابْنِ عُمَرَ قَالَغَدَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ مِنًى حِينَ صَلَّى الصُّبْحَ صَبِيحَةَ يَوْمِ عَرَفَةَ حَتَّى أَتَى عَرَفَةَ فَنَزَلَ بِنَمِرَةَ وَهِيَ مَنْزِلُ الْإِمَامِ الَّذِي يَنْزِلُ بِهِ بِعَرَفَةَ حَتَّى إِذَا كَانَ عِنْدَ صَلَاةِ الظُّهْرِ رَاحَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُهَجِّرًا فَجَمَعَ بَيْنَ الظُّهْرِ وَالْعَصْرِ ثُمَّ خَطَبَ النَّاسَ ثُمَّ رَاحَ فَوَقَفَ عَلَى الْمَوْقِفِ مِنْ عَرَفَةَ","id":"Telah menceritakan kepada Kami [Ahmad bin Hanbal], telah menceritakan kepada Kami [Ya'qub], telah menceritakan kepada Kami [ayahku], dari [Ibnu Ishaq], telah menceritakan kepadaku [Nafi'] dari [Ibnu Umar], ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam pergi dari Mina ketika telah melaksanakan Shalat Subuh, pagi hari Arafah hingga beliau sampai di Arafah dan singgah di Namirah. Dan itu adalah tempat singgal pemimpin yang singgah padanya di Arafah hingga pada saat Shalat Zhuhur Rasulullah shallAllahu wa'alaihi wa sallam berangkat pada saat pertengahan siang, kemudian beliau menjama' Shalat Zhuhur dan 'Ashar, kemudian berkhutbah kepada orang-orang, lalu berangkat dan berwukuf pada tempat wukuf di 'Arafah. "},"1572":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا نَافِعُ بْنُ عُمَرَ عَنْ سَعِيدِ بْنِ حَسَّانَ عَنْ ابْنِ عُمَرَ قَالَلَمَّا أَنْ قَتَلَ الْحَجَّاجُ ابْنَ الزُّبَيْرِ أَرْسَلَ إِلَى ابْنِ عُمَرَ أَيَّةُ سَاعَةٍ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرُوحُ فِي هَذَا الْيَوْمِ قَالَ إِذَا كَانَ ذَلِكَ رُحْنَافَلَمَّا أَرَادَ ابْنُ عُمَرَ أَنْ يَرُوحَ قَالُوا لَمْ تَزِغْ الشَّمْسُ قَالَ أَزَاغَتْ قَالُوا لَمْ تَزِغْ أَوْ زَاغَتْ قَالَ فَلَمَّا قَالُوا قَدْ زَاغَتْ ارْتَحَلَ","id":"Telah menceritakan kepada Kami [Ahmad bin Hanbal], telah menceritakan kepada Kami [Waki'], telah menceritakan kepada Kami [Nafi' bin Umar], dari [Sa'id bin Hassan] dari [Ibnu Umar], ia berkata; ketika Al Hajjaj membunuh Ibnu Az Zubair, ia mengutus seseorang kepada Ibnu Umar untuk bertanya tentang kapankah Rasulullah shallallahu 'alaihi wasallam pergi pada hari seperti ini? Dia berkata: jika telah saatnya Kami akan bepergian. Ketika Ibnu Umar hendak pergi, mereka berkata; matahari belum tergelincir! Ibnu Umar berkata; apakah sudah tergelincir? Mereka menjawab: belum! Ketika mereka mengatakan bahwa matahari telah tergelincir dia berangkat pergi. "},"1573":{"ar":"حَدَّثَنَا هَنَّادٌ عَنْ ابْنِ أَبِي زَائِدَةَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ رَجُلٍ مِنْ بَنِي ضَمْرَةَ عَنْ أَبِيهِ أَوْ عَمِّهِ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ عَلَى الْمِنْبَرِ بِعَرَفَةَ","id":"Telah menceritakan kepada Kami [Hannad], dari [Ibnu Abu Zaidah], telah menceritakan kepada Kami [Sufyan bin 'Uyainah], dari [Zaid bin Aslam], dari [seseorang dari Bani Dhamrah] dari [ayahnya] atua pamannya, ia berkata; aku melihat Rasulullah shallAllahu wa'alaihi wa sallam berada di atas mimbar di 'Arafah. "},"1574":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ دَاوُدَ عَنْ سَلَمَةَ بْنِ نُبَيْطٍ عَنْ رَجُلٍ مِنْ الْحَيِّ عَنْ أَبِيهِ نُبَيْطٍأَنَّهُ رَأَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاقِفًا بِعَرَفَةَ عَلَى بَعِيرٍ أَحْمَرَ يَخْطُبُ","id":"Telah menceritakan kepada Kami [Musaddad], telah menceritakan kepada Kami [Abdullah bin Daud] dari [Salamah bin Nubaith] dari [seorang laki-laki] dari Al Hayy, dari [ayahnya yaitu Nubaith], bahwa ia melihat Nabi shallallahu 'alaihi wasallam berdiri di 'Arafah di atas unta mererah beliau berkhutbah. "},"1575":{"ar":"حَدَّثَنَا هنَّادُ بْنُ السَّرِيِّ وَعُثْمَانُ بْنُ أَبِي شَيْبَةَ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ عَبْدِ الْمَجِيدِ قَالَ حَدَّثَنِي الْعَدَّاءُ بْنُ خَالِدِ بْنِ هَوْذَةَ قَالَ هَنَّادٌ عَنْ عَبْدِ الْمَجِيدِ أَبِي عَمْرٍو قَالَ حَدَّثَنِي خَالِدُ بْنُ الْعَدَّاءِ بْنِ هَوْذَةَ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ النَّاسَ يَوْمَ عَرَفَةَ عَلَى بَعِيرٍ قَائِمٌ فِي الرِّكَابَيْنِقَالَ أَبُو دَاوُد رَوَاهُ ابْنُ الْعَلَاءِ عَنْ وَكِيعٍ كَمَا قَالَ هَنَّادٌ حَدَّثَنَا عَبَّاسُ بْنُ عَبْدِ الْعَظِيمِ حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ حَدَّثَنَا عَبْدُ الْمَجِيدِ أَبُو عَمْرٍو عَنْ الْعَدَّاءِ بْنِ خَالِدٍ بِمَعْنَاهُ","id":"Telah menceritakan kepada Kami [Hannad bin As Sari], serta [Utsman bin Abu Syaibah], mereka berkata; telah menceritakan kepada Kami [Waki'] dari [Abdul Majid], ia berkata; telah menceritakan kepadaku [Al 'Adda` bin Khalid bin Haudzah], [Hannad] berkata; dari [Abdul Majid Abu 'Amr], ia berkata; telah menceritakan kepadaku [Khalid bin Al 'Adda` bin Khalid bin Haudzah], ia berkata; saya melihat Rasulullah shallAllahu wa'alaihi wa sallam berkhutbah kepada orang-orang pada Hari 'Arafah di atas unta, kedua kakinya berada dalam dua sanggurdi. Abu Daud berkata; hadits tersebut diriwayatkan oleh [Ibnu Al 'Ala`] dari [Waki'], sebagaimana yang dikatakan [Hannad]; telah menceritakan kepada Kami [Abbas bin Abdul 'Azhim], telah menceritakan kepada Kami ['Utsman bin Umar], telah menceritakan kepada Kami [Abdul Majid Abu 'Amr] dari [Al 'Ala` bin Khalid] dengan maknanya. "},"1576":{"ar":"حَدَّثَنَا ابْنُ نُفَيْلٍ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو يَعْنِي ابْنَ دِينَارٍ عَنْ عَمْرِو بْنِ عَبْدِ اللَّهِ بْنِ صَفْوَانَ عَنْ يَزِيدَ بْنِ شَيْبَانَ قَالَأَتَانَا ابْنُ مِرْبَعٍ الْأَنْصَارِيُّ وَنَحْنُ بِعَرَفَةَ فِي مَكَانٍ يُبَاعِدُهُ عَمْرُو عَنْ الْإِمَامِ فَقَالَ أَمَا إِنِّي رَسُولُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَيْكُمْ يَقُولُ لَكُمْ قِفُوا عَلَى مَشَاعِرِكُمْ فَإِنَّكُمْ عَلَى إِرْثٍ مِنْ إِرْثِ أَبِيكُمْ إِبْرَاهِيمَ","id":"Telah menceritakan kepada Kami [Ibnu Nufail], telah menceritakan kepada Kami [Sufyan] dari ['Amr yaitu Ibnu Dinar] dari ['Amr bin Abdullah bin Shafwan] dari [Yazid bin Syaiban], ia berkata; [Ibnu Mirba' Al Anshari] mendatangi Kami ketika Kami di Arafah di tempat yang di anggap jauh oleh 'Amr dari imam. Dia berkata: ketahuilah bahwa aku adalah seorang utusan Rasulullah shallallahu 'alaihi wasallam kepada kalian, beliau mengatakan kepada kalian: \"Wukuflah kalian di masy'ar kalian karena kalian berada pada warisan bapak kalian yaitu Ibrahim.\""},"1577":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ حَدَّثَنَا سُفْيَانُ عَنْ الْأَعْمَشِ ح و حَدَّثَنَا وَهْبُ بْنُ بَيَانٍ حَدَّثَنَا عُبَيْدَةُ حَدَّثَنَا سُلَيْمَانُ الْأَعْمَشُ الْمَعْنَى عَنْ الْحَكَمِ عَنْ مِقْسَمٍ عَنْ ابْنِ عَبَّاسٍ قَالَأَفَاضَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ عَرَفَةَ وَعَلَيْهِ السَّكِينَةُ وَرَدِيفُهُ أُسَامَةُ وَقَالَ أَيُّهَا النَّاسُ عَلَيْكُمْ بِالسَّكِينَةِ فَإِنَّ الْبِرَّ لَيْسَ بِإِيجَافِ الْخَيْلِ وَالْإِبِلِ قَالَ فَمَا رَأَيْتُهَا رَافِعَةً يَدَيْهَا عَادِيَةً حَتَّى أَتَى جَمْعًا زَادَ وَهْبٌ ثُمَّ أَرْدَفَ الْفَضْلَ بْنَ الْعَبَّاسِ وَقَالَ أَيُّهَا النَّاسُ إِنَّ الْبِرَّ لَيْسَ بِإِيجَافِ الْخَيْلِ وَالْإِبِلِ فَعَلَيْكُمْ بِالسَّكِينَةِ قَالَ فَمَا رَأَيْتُهَا رَافِعَةً يَدَيْهَا حَتَّى أَتَى مِنًى","id":"Telah menceritakan kepada Kami [Muhammad bin Katsir], telah menceritakan kepada Kami [Sufyan] dari [Al A'masy]. Dan diriwayatkan dari jalur yang lain: Telah menceritakan kepada Kami [Wahb bin Bayan], telah menceritakan kepada Kami ['Ubaidah], telah menceritakan kepada Kami [Sulaiman Al A'masy] secara makna, dari [Al Hakam] dari [Miqsam] dari [Ibnu Abbas], ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam bertolak dari 'Arafah dalam keadaan tenang, dan memboncengkan Usamah. Beliau mengatakan: \"Wahai para manusia, hendaknya kalian dalam keadaan tenang, sesungguhnya kebaikan tidak dengan mempercepat lari kuda dan unta.\" Ibnu Abbas berkata; aku tidak melihatnya unta tersebut mengangkat kedua tangannya seperti biasa hingga beliau sampai ke Muzdalifah. [Wahb] menambahkan; kemudian beliau memboncengkan Al Fadhl bin Al Abbas, dan berkata: \"Wahai manusia, sesungguhnya kebaikan bukanlah dengan mempercepat lari kuda dan unta, hendaknya kalian dalam keadaan tenang.\" Ia berkata; aku tidak melihat unta tersebut mengangkat kedua tangannya hingga beliau sampai ke Mina."},"1578":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ بْنِ يُونُسَ حَدَّثَنَا زُهَيْرٌ ح و حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ وَهَذَا لَفْظُ حَدِيثِ زُهَيْرٍ حَدَّثَنَا إِبْرَاهِيمُ بْنُ عُقْبَةَ أَخْبَرَنِي كُرَيْبٌ أَنَّهُ سَأَلَ أُسَامَةَ بْنَ زَيْدٍقُلْتُ أَخْبِرْنِي كَيْفَ فَعَلْتُمْ أَوْ صَنَعْتُمْ عَشِيَّةَ رَدِفْتَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ جِئْنَا الشِّعْبَ الَّذِي يُنِيخُ النَّاسُ فِيهِ لِلْمُعَرَّسِ فَأَنَاخَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَاقَتَهُ ثُمَّ بَالَ وَمَا قَالَ زُهَيْرٌ أَهْرَاقَ الْمَاءَ ثُمَّ دَعَا بِالْوَضُوءِ فَتَوَضَّأَ وُضُوءًا لَيْسَ بِالْبَالِغِ جِدًّا قُلْتُ يَا رَسُولَ اللَّهِ الصَّلَاةُ قَالَ الصَّلَاةُ أَمَامَكَ قَالَ فَرَكِبَ حَتَّى قَدِمْنَا الْمُزْدَلِفَةَ فَأَقَامَ الْمَغْرِبَ ثُمَّ أَنَاخَ النَّاسُ فِي مَنَازِلِهِمْ وَلَمْ يَحِلُّوا حَتَّى أَقَامَ الْعِشَاءَ وَصَلَّى ثُمَّ حَلَّ النَّاسُ زَادَ مُحَمَّدٌ فِي حَدِيثِهِ قَالَ قُلْتُ كَيْفَ فَعَلْتُمْ حِينَ أَصْبَحْتُمْ قَالَ رَدِفَهُ الْفَضْلُ وَانْطَلَقْتُ أَنَا فِي سُبَّاقِ قُرَيْشٍ عَلَى رِجْلَيَّحَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَيَّاشٍ عَنْ زَيْدِ بْنِ عَلِيٍّ عَنْ أَبِيهِ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي رَافِعٍ عَنْ عَلِيٍّ قَالَ ثُمَّ أَرْدَفَ أُسَامَةَ فَجَعَلَ يُعْنِقُ عَلَى نَاقَتِهِ وَالنَّاسُ يَضْرِبُونَ الْإِبِلَ يَمِينًا وَشِمَالًا لَا يَلْتَفِتُ إِلَيْهِمْ وَيَقُولُ السَّكِينَةَ أَيُّهَا النَّاسُ وَدَفَعَ حِينَ غَابَتْ الشَّمْسُ","id":"Telah menceritakan kepada Kami [Ahmad bin Abdullah bin Yunus], telah menceritakan kepada Kami [Zuhair]. Dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada Kami [Muhammad bin Katsir], telah mengabarkan kepada Kami [Sufyan] dan ini adalah lafazh hadits Zuhair, telah menceritakan kepada Kami [Ibrahim bin 'Uqbah], telah mengabarkan kepadaku [Kuraib] bahwa ia bertanya kepada [Usamah bin Zaid], aku katakan; beritahukan kepadaku apa yang kalian perbuat pada sore hari ketika engkau membonceng Rasulullah shallAllahu wa'alaihi wa sallam!? Ia berkata; Kami datang ke jalan bukit yang padanya orang-orang menderumkan untanya untuk singgah di Al Mu'arras (tempat singgah untuk tidur dan istirahat pada akhir malam). Lalu Rasulullah shallAllahu wa'alaihi wa sallam menderumkan untanya kemudian buang air kecil. -Zuhair tidak mengatakan; beliau menyiramkan air-. Kemudian beliau meminta tempat berwudhu lalu beliau berwudhu, tidak berlebihan sekali. Aku katakan; wahai rasul, Shalat! Beliau mengatakan: \"Shalat di depanmu.\" Usamah berkata; lalu beliau naik unta hingga Kami sampai ke Muzdalifah. Beliau melakukan shalat Maghrib kemudian orang-orang menderumkan unta di tempat-tempat persinggahan mereka, dan mereka tidak bertahallul, hingga beliau mendirikan shalat 'Isya` dan melakukan shalat, kemudian orang-orang bertahallul. - [Muhammad] dalam haditsnya menambahkan; [Kuraib] berkata; apa yang kalian lakukan ketika pagi hari? Ia berkata; Beliau memboncengkan Al Fadhl, sedangkan aku pergi bersama orang-orang Quraisy yang pergi cepat dengan berjalan kaki. Telah menceritakan kepada Kami [Ahmad bin Hanbal], telah menceritakan kepada Kami [Yahya bin Adam], telah menceritakan kepada Kami [Sufyan] dari [Abdurrahman bin 'Ayyasy] dari [Zaid bin Ali] dari [ayahnya] dari ['Ubaidullah bin Abu Rafi'] dari [Ali] ia berkata; kemudian beliau memboncengkan Usamah, dan beliau memperlambat jalan untanya sementara orang-orang memukul unta kanan dan kiri, dan beliau tidak menoleh kepada mereka dan berkata: \"Tenanglah wahai manusia.\" Dan beliau bertolak ketika matahari tenggelam. "},"1579":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ أَنَّهُ قَالَسُئِلَ أُسَامَةُ بْنُ زَيْدٍ وَأَنَا جَالِسٌ كَيْفَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسِيرُ فِي حَجَّةِ الْوَدَاعِ حِينَ دَفَعَ قَالَ كَانَ يَسِيرُ الْعَنَقَ فَإِذَا وَجَدَ فَجْوَةً نَصَّقَالَ هِشَامٌ النَّصُّ فَوْقَ الْعَنَقِ","id":"Telah menceritakan kepada Kami [Al Qa'nabi] dari [Malik] dari [Hisyam bin 'Urwah], dari [ayahnya], bahwa ia berkata; [Usamah bin Zaid] ditanya sementara aku dalam keadaan duduk; bagaimana Rasulullah shallAllahu wa'alaihi wa sallam berjalan pada waktu haji wada' ketika beliau bertolak? Ia berkata; beliau berjalan pelan, kemudian apabila beliau mendapatkan kelapangan beliau mempercepat jalannya. Hisyam berkata; Nash (jalan cepat) adalah lebih dari 'anaq (jalan pelan). "},"1580":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا أَبِي عَنْ ابْنِ إِسْحَقَ حَدَّثَنِي إِبْرَاهِيمُ بْنُ عُقْبَةَ عَنْ كُرَيْبٍ مَوْلَى عَبْدِ اللَّهِ بْنِ عَبَّاسٍ عَنْ أُسَامَةَ قَالَكُنْتُ رِدْفَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا وَقَعَتْ الشَّمْسُ دَفَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada Kami [Ahmad bin Hanbal], telah menceritakan kepada Kami [Ya'qub], telah menceritakan kepada Kami [ayahku] dari [Ibnu Ishaq], telah menceritakan kepadaku [Ibrahim bin 'Uqbah] dari [Kuraib mantan budak Abdullah bin Abbas] dari [Usamah], ia berkata; aku membonceng Nabi shallallahu 'alaihi wasallam, kemudian tatkala matahari terbenam Rasulullah shallAllahu wa'alaihi wa sallam bertolak. "},"1581":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ كُرَيْبٍ مَوْلَى عَبْدِ اللَّهِ بْنِ عَبَّاسٍ عَنْ أُسَامَةَ بْنِ زَيْدٍ أَنَّهُ سَمِعَهُ يَقُولُدَفَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ عَرَفَةَ حَتَّى إِذَا كَانَ بِالشِّعْبِ نَزَلَ فَبَالَ فَتَوَضَّأَ وَلَمْ يُسْبِغْ الْوُضُوءَ قُلْتُ لَهُ الصَّلَاةُ فَقَالَ الصَّلَاةُ أَمَامَكَ فَرَكِبَ فَلَمَّا جَاءَ الْمُزْدَلِفَةَ نَزَلَ فَتَوَضَّأَ فَأَسْبَغَ الْوُضُوءَ ثُمَّ أُقِيمَتْ الصَّلَاةُ فَصَلَّى الْمَغْرِبَ ثُمَّ أَنَاخَ كُلُّ إِنْسَانٍ بَعِيرَهُ فِي مَنْزِلِهِ ثُمَّ أُقِيمَتْ الْعِشَاءُ فَصَلَّاهَا وَلَمْ يُصَلِّ بَيْنَهُمَا شَيْئًا","id":"Telah menceritakan kepada Kami [Abdullah bin Maslamah] dari [Malik] dari [Musa bin 'Uqbah] dari [Kuraib] mantan budak Abdullah bin Abbas, dari [Usamah bin Zaid] bahwa ia mendengarnya berkata; Rasulullah shallAllahu wa'alaihi wa sallam bertolak dari 'Arafah hingga ketika sampai di jalan bukit, beliau turun dan buang air kecil lalu berwudhu, dan beliau tidak melebihkan wudhu. Aku katakan kepada beliau; Shalat! Beliau mengatakan: Shalat ada di depanmu. Kemudian beliau naik kendaraan dan tatkala telah sampai di Muzdalifah beliau turun dan berwudhu dan tidak melebihkan wudhunya. Kemudian didirikan shalat dan beliau melakukan shalat Maghrib, kemudian setiap orang menderumkan untanya di tempat persinggahannya, kemudian didirikan Shalat Isya`, lalu beliau melaksanakan shalat tersebut dan tidak melakukan shalat apapun diantara keduanya. "},"1582":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى الْمَغْرِبَ وَالْعِشَاءَ بِالْمُزْدَلِفَةِ جَمِيعًاحَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا حَمَّادُ بْنُ خَالِدٍ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ الزُّهْرِيِّ بِإِسْنَادِهِ وَمَعْنَاهُ وَقَالَ بِإِقَامَةٍ إِقَامَةِ جَمْعٍ بَيْنَهُمَا قَالَ أَحْمَدُ قَالَ وَكِيعٌ صَلَّى كُلَّ صَلَاةٍ بِإِقَامَةٍ حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا شَبَابَةُ ح و حَدَّثَنَا مَخْلَدُ بْنُ خَالِدٍ الْمَعْنَى أَخْبَرَنَا عُثْمَانُ بْنُ عُمَرَ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ الزُّهْرِيِّ بِإِسْنَادِ ابْنِ حَنْبَلٍ عَنْ حَمَّادٍ وَمَعْنَاهُ قَالَ بِإِقَامَةٍ وَاحِدَةٍ لِكُلِّ صَلَاةٍ وَلَمْ يُنَادِ فِي الْأُولَى وَلَمْ يُسَبِّحْ عَلَى إِثْرِ وَاحِدَةٍ مِنْهُمَا قَالَ مَخْلَدٌ لَمْ يُنَادِ فِي وَاحِدَةٍ مِنْهُمَا","id":"Telah menceritakan kepada Kami [Abdullah bin Maslamah], dari [Malik] dari [Ibnu Syihab] dari [Salim bin Abdullah], dari [Abdullah bin Umar] bahwa Rasulullah shallAllahu wa'alaihi wa sallam melakukan Shalat Maghrib dan Isya` di Muzdalifah. Telah menceritakan kepada Kami [Ahmad bin Hanbal], telah menceritakan kepada Kami [Hammad bin Khalid], dari [Ibnu Abu Dzi`bin], dari [Az Zuhri] dengan sanad serta maknanya. Dan ia berkata; dengan satu iqamah jama' antara keduanya. [Ahmad] berkata; [Waki'] berkata; beliau melakukan setiap shalat dengan satu iqamah. Telah menceritakan kepada Kami [Utsman bin Abu Syaibah], telah menceritakan kepada Kami [Syababah]. Dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada Kami [Makhlad bin Khalid] secara makna, telah mengabarkan kepada Kami [Utsman bin Umar] dari [Ibnu Abu Dzi`b] dari [Az Zuhri] dengan sanad Ahmad bin Hanbal dari Hammad dan dengan maknanya: Ia berkata; dengan satu iqamah untuk setiap shalat dan tidak mengumandangkan adzan pada shalat pertama serta tidak melakukan shalat sunah setelah melakukan setiap shalat diantara kedua shalat tersebut. Makhlad berkata; tidak mengumandangkan adzan pada satu pun diantara kedua shalat tersebut."},"1583":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي إِسْحَقَ عَنْ عَبْدِ اللَّهِ بْنِ مَالِكٍ قَالَصَلَّيْتُ مَعَ ابْنِ عُمَرَ الْمَغْرِبَ ثَلَاثًا وَالْعِشَاءَ رَكْعَتَيْنِ فَقَالَ لَهُ مَالِكُ بْنُ الْحَارِثِ مَا هَذِهِ الصَّلَاةُ قَالَ صَلَّيْتُهُمَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي هَذَا الْمَكَانِ بِإِقَامَةٍ وَاحِدَةٍحَدَّثَنَا مُحَمَّدُ بْنُ سُلَيْمَانَ الْأَنْبَارِيُّ حَدَّثَنَا إِسْحَقُ يَعْنِي ابْنَ يُوسُفَ عَنْ شَرِيكٍ عَنْ أَبِي إِسْحَقَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ وَعَبْدِ اللَّهِ بْنِ مَالِكٍ قَالَا صَلَّيْنَا مَعَ ابْنِ عُمَرَ بِالْمُزْدَلِفَةِ الْمَغْرِبَ وَالْعِشَاءَ بِإِقَامَةٍ وَاحِدَةٍ فَذَكَرَ مَعْنَى حَدِيثِ ابْنِ كَثِيرٍ","id":"Telah menceritakan kepada Kami [Muhammad bin Katsir], telah menceritakan kepada Kami [Sufyan] dari [Abu Ishaq] dari [Abdullah bin Malik], ia berkata; saya melakukan shalat Maghrib dan Isya` bersama [Ibnu Umar] dua raka'at. Malik bin Al Harits berkata kepadanya; shalat apakah ini? Ia berkata; aku melakukan shalat keduanya bersama Rasulullah shallAllahu wa'alaihi wa sallam di tempat ini dengan satu iqamah. Telah menceritakan kepada Kami [Muhammad bin Sulaiman Al Anbari], telah menceritakan kepada Kami [Ishaq yaitu Yusuf] dari [Syarik] dari [Abu Ishaq] dari [Sa'id bin Jubair] dan [Abdullah bin Malik], mereka berkata; Kami melakukan shalat Maghrib dan Isya` bersama [Ibnu Umar] di Muzdalifah dengan satu iqamah. Kemudian ia menyebutkan makna hadits Ibnu Katsir. "},"1584":{"ar":"حَدَّثَنَا ابْنُ الْعَلَاءِ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ إِسْمَعِيلَ عَنْ أَبِي إِسْحَقَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَأَفَضْنَا مَعَ ابْنِ عُمَرَ فَلَمَّا بَلَغْنَا جَمْعًا صَلَّى بِنَا الْمَغْرِبَ وَالْعِشَاءَ بِإِقَامَةٍ وَاحِدَةٍ ثَلَاثًا وَاثْنَتَيْنِ فَلَمَّا انْصَرَفَ قَالَ لَنَا ابْنُ عُمَرَ هَكَذَا صَلَّى بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي هَذَا الْمَكَانِ","id":"Telah menceritakan kepada Kami [Ibnu Al 'Ala`], telah menceritakan kepada Kami [Abu Usamah], dari [Isma'il] dari [Abu Ishaq] dari [Sa'id bin Jubair], ia berkata; Kami bertolak bersama [Ibnu Umar], kemudian tatkala Kami telah sampai di Muzdalifah beliau melakukan Shalat Maghrib dan Isya` bersama Kami dengan satu iqamah sebanyak tiga dan dua raka'at. Kemudian tatkala telah selesai, Ibnu Umar berkata kepada Kami; demikianlah Rasulullah shallAllahu wa'alaihi wa sallam melakukan shalat bersama Kami di tempat ini. "},"1585":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ شُعْبَةَ حَدَّثَنِي سَلَمَةُ بْنُ كُهَيْلٍ قَالَ رَأَيْتُ سَعِيدَ بْنَ جُبَيْرٍأَقَامَ بِجَمْعٍ فَصَلَّى الْمَغْرِبَ ثَلَاثًا ثُمَّ صَلَّى الْعِشَاءَ رَكْعَتَيْنِ ثُمَّ قَالَ شَهِدْتُ ابْنَ عُمَرَ صَنَعَ فِي هَذَا الْمَكَانِ مِثْلَ هَذَا وَقَالَ شَهِدْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَنَعَ مِثْلَ هَذَا فِي هَذَا الْمَكَانِ","id":"Telah menceritakan kepada Kami [Musaddad], telah menceritakan kepada Kami [Yahya] dari [Syu'bah], telah menceritakan kepadaku [Salamah bin Kuhail], ia berkata; aku melihat [Sa'id bin Jubair] tinggal di Muzdalifah dan melakukan shalat Maghrib tiga raka'at kemudian Shalat Isya` dua raka'at. Kemudian ia berkata; aku menyaksikan [Ibnu Umar] melakukan seperti ini di tempat ini. Dan ia berkata; aku menyaksikan Rasulullah shallAllahu wa'alaihi wa sallam melakukan seperti ini di tempat ini."},"1586":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا أَبُو الْأَحْوَصِ حَدَّثَنَا أَشْعَثُ بْنُ سُلَيْمٍ عَنْ أَبِيهِ قَالَأَقْبَلْتُ مَعَ ابْنِ عُمَرَ مِنْ عَرَفَاتٍ إِلَى الْمُزْدَلِفَةِ فَلَمْ يَكُنْ يَفْتُرُ مِنْ التَّكْبِيرِ وَالتَّهْلِيلِ حَتَّى أَتَيْنَا الْمُزْدَلِفَةَ فَأَذَّنَ وَأَقَامَ أَوْ أَمَرَ إِنْسَانًا فَأَذَّنَ وَأَقَامَ فَصَلَّى بِنَا الْمَغْرِبَ ثَلَاثَ رَكَعَاتٍ ثُمَّ الْتَفَتَ إِلَيْنَا فَقَالَ الصَّلَاةُ فَصَلَّى بِنَا الْعِشَاءَ رَكْعَتَيْنِ ثُمَّ دَعَا بِعَشَائِهِقَالَ وَأَخْبَرَنِي عِلَاجُ بْنُ عَمْرٍو بِمِثْلِ حَدِيثِ أَبِي عَنْ ابْنِ عُمَرَ قَالَ فَقِيلَ لِابْنِ عُمَرَ فِي ذَلِكَ فَقَالَ صَلَّيْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَكَذَا","id":"Telah menceritakan kepada Kami [Musaddad], telah menceritakan kepada Kami [Abu Al Ahwash], telah menceritakan kepada Kami [Asy'ats bin Sulaim], dari [ayahnya], ia berkata; aku datang bersama [Ibnu Umar] dari Arafah menuju Muzdalifah, dan ia tidak berhenti mengucapkan takbir serta tahlil hingga Kami sampai di Muzdalifah. Kemudian ia mengumandangkan adzan dan iqamah, atau memerintahkan orang untuk mengumandangkan adzan dan iqamah. Kemudian ia melakukan shalat Maghirb tiga raka'at bersama Kami. Kemudian ia berpaling kepada Kami. Ia berkata; Shalat. Kemudian ia melakukan shalat Isya` dua raka'at bersama Kami. Kemudian meminta makan malamnya. Abu Daud berkata; telah mengabarkan kepadaku ['Ilaj bin 'Amr] seperti hadits ayahku dari Ibnu Umar. Kemudian [Ibnu Umar] ditanya mengenai hal tersebut; kemudian ia berkata; aku pernah melakukan shalat seperti ini bersama Rasulullah shallAllahu wa'alaihi wa sallam."},"1587":{"ar":"حَدَّثَنَا مُسَدَّدٌ أَنَّ عَبْدَ الْوَاحِدِ بْنَ زَيَادٍ وَأَبَا عَوَانَةَ وَأَبَا مُعَاوِيَةَ حَدَّثُوهُمْ عَنْ الْأَعْمَشِ عَنْ عِمَارَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ عَنْ ابْنِ مَسْعُودٍ قَالَمَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى صَلَاةً إِلَّا لِوَقْتِهَا إِلَّا بِجَمْعٍ فَإِنَّهُ جَمَعَ بَيْنَ الْمَغْرِبِ وَالْعِشَاءِ بِجَمْعٍ وَصَلَّى صَلَاةَ الصُّبْحِ مِنْ الْغَدِ قَبْلَ وَقْتِهَا","id":"Telah menceritakan kepada Kami [Musaddad] bahwa [Abdul Wahid bin Ziyad] dan [Abu 'Awanah] dan [Abu Mu'awiyah] telah menceritakan kepada mereka dari [Al A'masy] dari ['Imarah] dari [Abdurrahman bin Yazid] dari [Ibnu Mas'ud], ia berkata; aku tidak melihat Rasulullah shallAllahu wa'alaihi wa sallam melakukan shalat apapun kecuali pada waktunya kecuali dengan menjama', sesungguhnya beliau menjama' Shalat Maghrib dan Isya` dan melakukan shalat Subuh keesokan hari sebelum waktunya. "},"1588":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَيَّاشٍ عَنْ زَيْدِ بْنِ عَلِيٍّ عَنْ أَبِيهِ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي رَافِعٍ عَنْ عَلِيٍّ قَالَفَلَمَّا أَصْبَحَ يَعْنِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَوَقَفَ عَلَى قُزَحَ فَقَالَ هَذَا قُزَحُ وَهُوَ الْمَوْقِفُ وَجَمْعٌ كُلُّهَا مَوْقِفٌ وَنَحَرْتُ هَا هُنَا وَمِنًى كُلُّهَا مَنْحَرٌ فَانْحَرُوا فِي رِحَالِكُمْ","id":"Telah menceritakan kepada Kami [Ahmad bin Hanbal], telah menceritakan kepada Kami [Yahya bin Adam], telah menceritakan kepada Kami [Sufyan] dari [Abdurrahman bin 'Ayyasy] dari [Zaid bin Ali] dari [ayahnya] dari ['Ubaidullah bin Abu Rafi'] dari [Ali] ia berkata; ketika pagi hari Nabi shalla Allahu 'alaihi wa sallam berdiri di Quzah lalu berkata: \"Ini adalah Quzah dan merupakan tempat wukuf, dan Muzdalifah seluruhnya adalah tempat berwukuf, aku menyembelih disini dan Mina semuanya adalah tempat menyembelih, maka sembelihlah ditempat kalian tinggal. "},"1589":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ عَنْ جَعْفَرِ بْنِ مُحَمَّدٍ عَنْ أَبِيهِ عَنْ جَابِرٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَقَفْتُ هَا هُنَا بِعَرَفَةَ وَعَرَفَةُ كُلُّهَا مَوْقِفٌ وَوَقَفْتُ هَا هُنَا بِجَمْعٍ وَجَمْعٌ كُلُّهَا مَوْقِفٌ وَنَحَرْتُ هَا هُنَا وَمِنًى كُلُّهَا مَنْحَرٌ فَانْحَرُوا فِي رِحَالِكُمْ","id":"Telah menceritakan kepada Kami [Musaddad] telah menceritakan kepada Kami [Hafsh bin Ghiyats] dari [Ja'far bin Muhammad] dari [ayahnya] dari [Jabir] bahwa Nabi shalla Allahu 'alaihi wa sallam berkata: \"Aku berwukuf disini, yaitu di Arafah, dan Arafah seluruhnya adalah tempat wukuf dan aku berwukuf di sini, yaitu di Muzdalifah dan Muzdalifah seluruhnya adalah tempat berwukuf. Aku menyembelih disini dan Mina semuanya adalah tempat menyembelih, maka sembelihlah kalian ditempat kalian tinggal. "},"1590":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ أُسَامَةَ بْنِ زَيْدٍ عَنْ عَطَاءٍ قَالَ حَدَّثَنِي جَابِرُ بْنُ عَبْدِ اللَّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كُلُّ عَرَفَةَ مَوْقِفٌ وَكُلُّ مِنًى مَنْحَرٌ وَكُلُّ الْمُزْدَلِفَةِ مَوْقِفٌ وَكُلُّ فِجَاجِ مَكَّةَ طَرِيقٌ وَمَنْحَرٌ","id":"Telah menceritakan kepada Kami [Al Hasan bin Ali], telah menceritakan kepada Kami [Abu Usamah] dari [Usamah bin Zaid] dari ['Atha`], ia berkata; telah menceritakan kepadaku [Jabir bin Abdullah] bahwa Rasulullah shallAllahu wa'alaihi wa sallam berkata; seluruh Arafah adalah tempat berwukuf, dan seluruh Mina adalah tempat menyembelih, serta seluruh Muzdalifah adalah tempat berwukuf, dan seluruh jalan Mekkah adalah jalan dan tempat menyembelih. "},"1591":{"ar":"حَدَّثَنَا ابْنُ كَثِيرٍ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي إِسْحَقَ عَنْ عَمْرِو بْنِ مَيْمُونٍ قَالَ قَالَ عُمَرُ بْنُ الْخَطَّابِكَانَ أَهْلُ الْجَاهِلِيَّةِ لَا يُفِيضُونَ حَتَّى يَرَوْا الشَّمْسَ عَلَى ثَبِيرٍ فَخَالَفَهُمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَفَعَ قَبْلَ طُلُوعِ الشَّمْسِ","id":"Telah menceritakan kepada Kami [Ibnu Katsir], telah menceritakan kepada Kami [Sufyan] dari [Abu Ishaq] dari ['Amr bin Maimun], ia berkata; [Umar bin Al Khathab] berkata; orang-orang jahiliyah tidak bertolak hingga mereka melihat matahari di atas Gunung Tsabir, kemudian Nabi shallallahu 'alaihi wasallam menyelisihi mereka, dan beliau bertolak sebelum matahari terbit. "},"1592":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا سُفْيَانُ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ أَبِي يَزِيدَ أَنَّهُ سَمِعَ ابْنَ عَبَّاسٍ يَقُولُأَنَا مِمَّنْ قَدَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْلَةَ الْمُزْدَلِفَةِ فِي ضَعْفَةِ أَهْلِهِ","id":"Telah menceritakan kepada Kami [Ahmad bin Hanbal], telah menceritakan kepada Kami [Sufyan], telah mengabarkan kepadaku ['Ubaidullah bin Abu Yazid] bahwa ia mendengar [Ibnu Abbas] berkata; aku merupakan diantara orang yang didahulukan oleh Rasulullah shallAllahu wa'alaihi wa sallam pada malam di Muzdalifah, diantara isteri dan anak-anak keluarganya."},"1593":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ قَالَ حَدَّثَنِي سَلَمَةُ بْنُ كُهَيْلٍ عَنْ الْحَسَنِ الْعُرَنِيِّ عَنْ ابْنِ عَبَّاسٍ قَالَقَدَّمَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْلَةَ الْمُزْدَلِفَةِ أُغَيْلِمَةَ بَنِي عَبْدِ الْمُطَّلِبِ عَلَى حُمُرَاتٍ فَجَعَلَ يَلْطَخُ أَفْخَاذَنَا وَيَقُولُ أُبَيْنِيَّ لَا تَرْمُوا الْجَمْرَةَ حَتَّى تَطْلُعَ الشَّمْسُقَالَ أَبُو دَاوُد اللَّطْخُ الضَّرْبُ اللَّيِّنُ","id":"Telah menceritakan kepada Kami [Muhammad bin Katsir], telah mengabarkan kepada Kami [Sufyan], ia berkata; telah menceritakan kepadaku [Salamah bin Kuhail] dari [Al Hasan Al 'Urabi] dari [Ibnu Abbas], ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam mendahulukan Kami pada malam di Muzdalifah yaitu anak-anak Bani Abdul Muththalib di atas keledai. Kemudian beliau menepuk paha Kami dan berkata: \"Wahai anak-anakku, janganlah melempar jumrah hingga matahari terbit.\" Abu Daud berkata; Al Lathkhu (menepuk) adalah memukul dengan ringan. "},"1594":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا الْوَلِيدُ بْنُ عُقْبَةَ حَدَّثَنَا حَمْزَةُ الزَّيَّاتُ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُقَدِّمُ ضُعَفَاءَ أَهْلِهِ بِغَلَسٍ وَيَأْمُرُهُمْ يَعْنِي لَا يَرْمُونَ الْجَمْرَةَ حَتَّى تَطْلُعَ الشَّمْسُ","id":"Telah menceritakan kepada Kami [Utsman bin Abu Syaibah], telah menceritakan kepada Kami [Al Walid bin 'Uqbah], telah menceritakan kepada Kami [Hamzah Az Zayyat] dari [Habib bin Abu Tsabit] dari ['Atho`] dari [Ibnu Abbas], ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam mendahulukan orang-orang lemah diantara keluarganya pada saat malam yang gelap, dan memerintahkan mereka agar tidak melempar jumrah hingga matahari terbit. "},"1595":{"ar":"حَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ عَنْ الضَّحَّاكِ يَعْنِي ابْنَ عُثْمَانَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ أَنَّهَا قَالَتْأَرْسَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِأُمِّ سَلَمَةَ لَيْلَةَ النَّحْرِ فَرَمَتْ الْجَمْرَةَ قَبْلَ الْفَجْرِ ثُمَّ مَضَتْ فَأَفَاضَتْ وَكَانَ ذَلِكَ الْيَوْمُ الْيَوْمَ الَّذِي يَكُونُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَعْنِي عِنْدَهَا","id":"Telah menceritakan kepada Kami [Harun bin Abdullah], telah menceritakan kepada Kami [Ibnu Abu Fudaik], dari [Adh Dhahhak yaitu Ibnu Utsman] dari [Hisyam bin 'Urwah] dari [ayahanya] dari [Aisyah] bahwa ia berkata; Nabi shallallahu 'alaihi wasallam mengutus seseorang untuk menemani Ummu Salamah pada malam Hari Nahr untuk melontar jumrah, maka dia melontar jumrah sebelum fajar kemudian berlalu dan pergi. Dan hari itu adalah hari dimana Rasulullah shallla Allahu 'alaihi wa sallam menggilirnya. "},"1596":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ خَلَّادٍ الْبَاهِلِيُّ حَدَّثَنَا يَحْيَى عَنْ ابْنِ جُرَيْجٍ أَخْبَرَنِي عَطَاءٌ أَخْبَرَنِي مُخْبِرٌ عَنْ أَسْمَاءَأَنَّهَا رَمَتْ الْجَمْرَةَ قُلْتُ إِنَّا رَمَيْنَا الْجَمْرَةَ بِلَيْلٍ قَالَتْ إِنَّا كُنَّا نَصْنَعُ هَذَا عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada Kami [Muhammad bin Khallad Al Bahili], telah menceritakan kepada Kami [Yahya] dari [Ibnu Juraij], telah mengabarkan kepadaku ['Atha`], telah mengabarkan kepadaku [Seseorang] dari [Asma`] bahwa ia melempar jumrah. Aku katakan; sesungguhnya Kami melempar jumrah pada malam hari. Ia berkata; sesungguhnya Kami melakukan hal ini pada masa Rasulullah shallAllahu wa'alaihi wa sallam. "},"1597":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ حَدَّثَنَا سُفْيَانُ حَدَّثَنِي أَبُو الزُّبَيْرِ عَنْ جَابِرٍ قَالَأَفَاضَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلَيْهِ السَّكِينَةُ وَأَمَرَهُمْ أَنْ يَرْمُوا بِمِثْلِ حَصَى الْخَذْفِ وَأَ��ْضَعَ فِي وَادِي مُحَسِّرٍ","id":"Telah menceritakan kepada Kami [Muhammad bin Katsir], telah menceritakan kepada Kami [Sufyan], telah menceritakan kepadaku [Abu Az Zubair] dari [Jabir], ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam bertolak dengan tenang, dan memerintahkan orang-orang agar melempar dengan kerikil untuk melempar, dan beliau mempercepat unta di lembah Muhassir. "},"1598":{"ar":"حَدَّثَنَا مُؤَمَّلُ بْنُ الْفَضْلِ حَدَّثَنَا الْوَلِيدُ حَدَّثَنَا هِشَامٌ يَعْنِي ابْنَ الْغَازِ حَدَّثَنَا نَافِعٌ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَفَ يَوْمَ النَّحْرِ بَيْنَ الْجَمَرَاتِ فِي الْحَجَّةِ الَّتِي حَجَّ فَقَالَ أَيُّ يَوْمٍ هَذَا قَالُوا يَوْمُ النَّحْرِ قَالَ هَذَا يَوْمُ الْحَجِّ الْأَكْبَرِ","id":"Telah menceritakan kepada Kami [Muammal bin Al Fadhl], telah menceritakan kepada Kami [Al Walid], telah menceritakan kepada Kami [Hisyam yaitu Ibnu Al Ghaz], telah menceritakan kepada Kami [Nafi'] dari [Ibnu Umar] bahwa Rasulullah shallAllahu wa'alaihi wa sallam berdiri pada hari Nahr (penyembelihan) diantara jumrah-jumrah pada waktu beliau berhaji, lalu berkata: hari apakah ini? Mereka menjawab; Hari Nahr! Beliau berkata: \"Ini adalah hari haji akbar.\""},"1599":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ فَارِسٍ أَنَّ الْحَكَمَ بْنَ نَافِعٍ حَدَّثَهُمْ حَدَّثَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ حَدَّثَنِي حُمَيْدُ بْنُ عَبْدِ الرَّحْمَنِ أَنَّ أَبَا هُرَيْرَةَ قَالَبَعَثَنِي أَبُو بَكْرٍ فِيمَنْ يُؤَذِّنُ يَوْمَ النَّحْرِ بِمِنًى أَنْ لَا يَحُجَّ بَعْدَ الْعَامِ مُشْرِكٌ وَلَا يَطُوفَ بِالْبَيْتِ عُرْيَانٌ وَيَوْمُ الْحَجِّ الْأَكْبَرِ يَوْمُ النَّحْرِ وَالْحَجُّ الْأَكْبَرُ الْحَجُّ","id":"Telah menceritakan kepada Kami [Muhammad bin Yahya bin Faris] bahwa [Al Hakam bin Nafi'] menceritakan kepada mereka; telah menceritakan kepada Kami [Syu'aib] dari [Az Zuhri], telah menceritakan kepadaku [Humaid bin Abdurrahman] bahwa [Abu Hurairah] berkata; [Abu Bakr] mengutusku diantara orang-orang yang mengumumkan pada Hari Nahr di Mina; Tidak boleh ada orang musyrik setelah tahun ini yang melakukan thawaf dengan telanjang, dan hari Haji Akbar adalah Hari Nahr, dan Haji Akbar adalah haji. "},"1600":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا إِسْمَعِيلُ حَدَّثَنَا أَيُّوبُ عَنْ مُحَمَّدٍ عَنْ أَبِي بَكْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَطَبَ فِي حَجَّتِهِ فَقَالَ إِنَّ الزَّمَانَ قَدْ اسْتَدَارَ كَهَيْئَتِهِ يَوْمَ خَلَقَ اللَّهُ السَّمَوَاتِ وَالْأَرْضَ السَّنَةُ اثْنَا عَشَرَ شَهْرًا مِنْهَا أَرْبَعَةٌ حُرُمٌ ثَلَاثٌ مُتَوَالِيَاتٌ ذُو الْقِعْدَةِ وَذُو الْحِجَّةِ وَالْمُحَرَّمُ وَرَجَبُ مُضَرَ الَّذِي بَيْنَ جُمَادَى وَشَعْبَانَحَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ فَيَّاضٍ حَدَّثَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا أَيُّوبُ السَّخْتِيَانِيُّ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ ابْنِ أَبِي بَكْرَةَ عَنْ أَبِي بَكْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَعْنَاهُ قَالَ أَبُو دَاوُد سَمَّاهُ ابْنُ عَوْنٍ فَقَالَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرَةَ عَنْ أَبِي بَكْرَةَ فِي هَذَا الْحَدِيثِ","id":"Telah menceritakan kepada Kami [Musaddad] telah menceritakan kepada Kami [Isma'il] telah menceritakan kepada Kami [Ayyub] dari [Muhammad] dari [Abu Bakrah] bahwa Nabi shallallahu 'alaihi wasallam berkhutbah pada saat berhaji, dan berkata; \"Sesungguhnya zaman telah berputar seperti keadaannya pada hari Allah menciptakan langit dan bumi, satu tahun adalah dua belas bulan, diantaranya terdapat empat bulan haram, tiga bulan berturut-turut adalah Dzul Qa'dah, Dzul Hijjah, Al Muharram dan Rajab Mudhar yang berada di antara Jumadi dan Sya'ban.\" Telah menceritakan kepada Kami [Muhammad bin Yahya bin Fayyadh], telah menceritakan kepada Kami [Abdul Wahhab], telah menceritakan kepada Kami [Ayyub As Sakhtiyani] dari [Muhammad bin Sirin] dari [Ibnu Abu Bakrah], dari [Abu Bakrah], dari Nabi shallallahu 'alaihi wasallam dengan maknanya. Abu Daud berkata; [Ibnu 'Aun] menyebutkannya, ia berkata; dari [Abdurrahman bin Abu Bakrah] dari [Abu Bakrah] dalam hadits ini."},"1601":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ حَدَّثَنَا سُفْيَانُ حَدَّثَنِي بُكَيْرُ بْنُ عَطَاءٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَعْمَرَ الدِّيلِيِّ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ بِعَرَفَةَ فَجَاءَ نَاسٌ أَوْ نَفَرٌ مِنْ أَهْلِ نَجْدٍ فَأَمَرُوا رَجُلًا فَنَادَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَيْفَ الْحَجُّ فَأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلًا فَنَادَى الْحَجُّ الْحَجُّ يَوْمُ عَرَفَةَ مَنْ جَاءَ قَبْلَ صَلَاةِ الصُّبْحِ مِنْ لَيْلَةِ جَمْعٍ فَتَمَّ حَجُّهُ أَيَّامُ مِنًى ثَلَاثَةٌ فَمَنْ تَعَجَّلَ فِي يَوْمَيْنِ فَلَا إِثْمَ عَلَيْهِ وَمَنْ تَأَخَّرَ فَلَا إِثْمَ عَلَيْهِ قَالَ ثُمَّ أَرْدَفَ رَجُلًا خَلْفَهُ فَجَعَلَ يُنَادِي بِذَلِكَقَالَ أَبُو دَاوُد وَكَذَلِكَ رَوَاهُ مِهْرَانُ عَنْ سُفْيَانَ قَالَ الْحَجُّ الْحَجُّ مَرَّتَيْنِ وَرَوَاهُ يَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ عَنْ سُفْيَانَ قَالَ الْحَجُّ مَرَّةً","id":"Telah menceritakan kepada Kami [Muhammad bin Katsir], telah menceritakan kepada Kami [Sufyan] telah menceritakan kepadaku [Bukair bin 'Atha`] dari [Abdurrahman bin Ya'mar Ad Dili], ia berkata; aku datang kepada Nabi shallallahu 'alaihi wasallam dan beliau sedang di Arafah. Kemudian datang beberapa orang dari penduduk Najed, kemudian mereka memerintahkan seorang laki-laki untuk bertanya kepada Rasulullah shallAllahu wa'alaihi wa sallam; bagaimana berhaji itu? Kemudian Rasulullah shallAllahu wa'alaihi wa sallam memerintahkan seseorang agar mengumumkan; haji adalah pada hari 'Arafah, barang siapa yang datang sebelum shalat Subuh semenjak malam di Muzdalifah maka Hajinya telah sempurna, hari-hari di Mina ada tiga, barang siapa yang menyegerakan dalam dua hari maka tidak ada dosa padanya dan barang siapa yang menunda maka tidak ada dosa baginya. Abdurrahman berkata; kemudian beliau memboncengkan seorang laki-laki di belakangnya dan menyerukan hal tersebut. Abu Daud berkata; dan demikianlah hadits yang diriwayatkan [Mihran] dari [Sufyan], ia berkata; haji, haji …… (ia menyebutkan dua kali). Dan telah diriwayatkan [Yahya Al Qaththan] dari [Sufyan], ia berkata; haji ….. (ia menyebutkan satu kali). "},"1602":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ إِسْمَعِيلَ حَدَّثَنَا عَامِرٌ أَخْبَرَنِي عُرْوَةُ بْنُ مُضَرِّسٍ الطَّائِيُّ قَالَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْمَوْقِفِ يَعْنِي بِجَمْعٍ قُلْتُ جِئْتُ يَا رَسُولَ اللَّهِ مِنْ جَبَلِ طَيِّئٍ أَكْلَلْتُ مَطِيَّتِي وَأَتْعَبْتُ نَفْسِي وَاللَّهِ مَا تَرَكْتُ مِنْ حَبْلٍ إِلَّا وَقَفْتُ عَلَيْهِ فَهَلْ لِي مِنْ حَجٍّ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَدْرَكَ مَعَنَا هَذِهِ الصَّلَاةَ وَأَتَى عَرَفَاتَ قَبْلَ ذَلِكَ لَيْلًا أَوْ نَهَارًا فَقَدْ تَمَّ حَجُّهُ وَقَضَى تَفَثَهُ","id":"Telah menceritakan kepada Kami [Musaddad] telah menceritakan kepada Kami [Yahya] dari [Isma'il], telah menceritakan kepada Kami ['Amir], telah mengabarkan kepadaku ['Urwah bin Mudharris Ath Thai], ia berkata; aku pernah datang kepada Rasulullah shallAllahu wa'alaihi wa sallam di tempat wukuf yaitu di Muzdalifah. Aku katakan; wahai rasul, aku datang dari Gunung Thayyi`, aku telah membuat kendaraanku letih dan melelahkan diriku. Demi Allah tidaklah aku meninggalkan pasir yang memanjang melainkan aku berhenti padanya. Apakah aku mendapatkan haji? Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Barang siapa yang mendapati Shalat ini bersama Kami, dan telah datang ke Arafah sebelum itu pada malam hari atau siang hari maka sungguh telah sempurna hajinya dan menghilangkan kotoran yang ada pada badannya.\""},"1603":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ حُمَيْدٍ الْأَعْرَجِ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ التَّيْمِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ مُعَاذٍ عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَخَطَبَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ النَّاسَ بِمِنًى وَنَزَّلَهُمْ مَنَازِلَهُمْ فَقَالَ لِيَنْزِلْ الْمُهَاجِرُونَ هَا هُنَا وَأَشَارَ إِلَى مَيْمَنَةِ الْقِبْلَةِ وَالْأَنْصَارُ هَا هُنَا وَأَشَارَ إِلَى مَيْسَرَةِ الْقِبْلَةِ ثُمَّ لِيَنْزِلْ النَّاسُ حَوْلَهُمْ","id":"Telah menceritakan kepada Kami [Ahmad bin Hanbal] telah menceritakan kepada Kami [Abdurrazzaq] telah mengabarkan kepada Kami [Ma'mar] dari [Humaid Al A'raj] dari [Muhammad bin Ibrahim At Taimi] dari [Abdurrahman bin Mu'adz] dari [seorang sahabat] Nabi shallallahu 'alaihi wasallam, ia berkata; Nabi shallallahu 'alaihi wasallam berkhutbah kepada orang-orang di Mina, dan menempatkan mereka di tempat-tempat singgah mereka. Beliau bersabda: \"Hendaknya orang-orang muhajirin singgah di sini -beliau menunjukkan kepada sisi kanan kiblat-, dan orang-orang anshar di sini -beliau menunjukkan ke sisi kiri kiblat. Kemudian hendaknya orang-orang singgah diantara mereka. "},"1604":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا ابْنُ الْمُبَارَكِ عَنْ إِبْرَاهِيمَ بْنِ نَافِعٍ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ أَبِيهِ عَنْ رَجُلَيْنِ مِنْ بَنِي بَكْرٍ قَالَارَأَيْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ بَيْنَ أَوْسَطِ أَيَّامِ التَّشْرِيقِ وَنَحْنُ عِنْدَ رَاحِلَتِهِ وَهِيَ خُطْبَةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الَّتِي خَطَبَ بِمِنًى","id":"Telah menceritakan kepada Kami [Muhammad bin Al 'Ala`], telah menceritakan kepada Kami [Ibnu Al Mubarak] dari [Ibrahim bin Nafi'] dari [Ibnu Abu Najih] dari [ayahnya] dari [dua orang] dari Bani Bakr, mereka berkata; Kami melihat Rasulullah shallAllahu wa'alaihi wa sallam berkhutbah di pertengahan hari-hari tasyriq sementara Kami berada disisi kendaraannya. Khutbah itu adalah khutbah beliau di Mina. "},"1605":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو عَاصِمٍ حَدَّثَنَا رَبِيعَةُ بْنُ عَبْدِ الرَّحْمَنِ بْنِ حُصَيْنٍ حَدَّثَتْنِي جَدَّتِي سَرَّاءُ بِنْتُ نَبْهَانَ وَكَانَتْ رَبَّةُ بَيْتٍ فِي الْجَاهِلِيَّةِ قَالَتْخَطَبَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الرُّءُوسِ فَقَالَ أَيُّ يَوْمٍ هَذَا قُلْنَا اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ أَلَيْسَ أَوْسَطَ أَيَّامِ التَّشْرِيقِقَالَ أَبُو دَاوُد وَكَذَلِكَ قَالَ عَمُّ أَبِي حُرَّةَ الرَّقَاشِيِّ إِنَّهُ خَطَبَ أَوْسَطَ أَيَّامِ التَّشْرِيقِ","id":"Telah menceritakan kepada Kami [Muhammad bin Basysyar] telah menceritakan kepada Kami [Abu 'Ashim], telah menceritakan kepada Kami [Rabi'ah bin Abdurrahman bin Hushain], telah menceritakan kepada Kami [nenekku yaitu Sarra` binti Nabhan], ia adalah seorang wanita yang mengurusi Ka'bah pada masa jahiliyah, ia berkata; Rasulullah shallla Allahu 'alaihi wa sallam berkhutbah kepada Kami pada hari Ru-us (hari kedua dari Hari Tasyriq). Beliau bertanya: \"Hari apakah ini?\" Kami menjawab; Allah dan Rasul-Nya yang lebih mengetahui. Beliau berkata: \"Bukankah ini adalah pertengahan hari Tasyriq?\" Abu Daud berkata; begitu pula yang dikatakan paman Abu Hurrah Ar Raqasyi; sesungguhnya beliau berkhutbah dipertengahan hari Tasyriq. "},"1606":{"ar":"حَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا هِشَامُ بْنُ عَبْدِ الْمَلِكِ حَدَّثَنَا عِكْرِمَةُ حَدَّثَنِي الْهِرْمَاسُ بْنُ زِيَادٍ الْبَاهِلِيُّ قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ النَّاسَ عَلَى نَاقَتِهِ الْعَضْبَاءِ يَوْمَ الْأَضْحَى بِمِنًى","id":"Telah menceritakan kepada Kami [Harun bin Abdullah], telah menceritakan kepada Kami [Hisyam bin Abdul Malik], telah menceritakan kepada Kami [Ikrimah], telah menceritakan kepadaku [Al Hirmas bin Ziyad Al Bahili], ia berkata; aku melihat Nabi shallallahu 'alaihi wasallam berkhutbah kepada Nabi shallallahu 'alaihi wasallam di atas untanya yaitu Al 'Adhba` pada hari Raya Adhha di Mina. "},"1607":{"ar":"حَدَّثَنَا مُؤَمَّلٌ يَعْنِي ابْنَ الْفَضْلِ الْحَرَّانِيَّ حَدَّثَنَا الْوَلِيدُ حَدَّثَنَا ابْنُ جَابِرٍ حَدَّثَنَا سُلَيْمُ بْنُ عَامِرٍ الْكَلَاعِيُّ سَمِعْتُ أَبَا أُمَامَةَ يَقُولُسَم��عْتُ خُطْبَةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِنًى يَوْمَ النَّحْرِ","id":"Telah menceritakan kepada Kami [Muammal yaitu Ibnu Al Fadhl Al Harrani], telah menceritakan kepada Kami [Al Walid], telah menceritakan kepada Kami [Ibnu Jabir], telah menceritakan kepada Kami [Sulaim bin 'Amir Al Kala'i]; saya mendengar [Abu Umamah] berkata; saya mendengar Khutbah Rasulullah shallallahu 'alaihi wasallam di Mina pada Hari Nahr. "},"1608":{"ar":"حَدَّثَنَا عَبْدُ الْوَهَّابِ بْنُ عَبْدِ الرَّحِيمِ الدِّمَشْقِيُّ حَدَّثَنَا مَرْوَانُ عَنْ هِلَالِ بْنِ عَامِرٍ الْمُزْنِيِّ حَدَّثَنِي رَافِعُ بْنُ عَمْرٍو الْمُزْنِيُّ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ النَّاسَ بِمِنًى حِينَ ارْتَفَعَ الضُّحَى عَلَى بَغْلَةٍ شَهْبَاءَ وَعَلِيٌّ رَضِيَ اللَّهُ عَنْهُ يُعَبِّرُ عَنْهُ وَالنَّاسُ بَيْنَ قَاعِدٍ وَقَائِمٍ","id":"Telah menceritakan kepada Kami [Abdul Wahhab bin Abdurrahim Ad Dimasyqi], telah menceritakan kepada Kami [Marwan] dari [Hilal bin 'Amir Al Muzni], telah menceritakan kepadaku [Rafi' bin 'Amr Al Muzni], ia berkata; saya melihat Rasulullah shallallahu 'alaihi wasallam berkhutbah kepada orang-orang di Mina ketika matahari pagi telah naik diatas bighal yang warnanya putih kehitam-hitaman. Sementara Ali Bin Abu Thalib radliallahu 'anhu menyampaikan khutbah beliau sementara orang-orang ada yang berdiri dan ada yang duduk. "},"1609":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ حُمَيْدٍ الْأَعْرَجِ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ التَّيْمِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ مُعَاذٍ التَّيْمِيِّ قَالَخَطَبَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ بِمِنًى فَفُتِحَتْ أَسْمَاعُنَا حَتَّى كُنَّا نَسْمَعُ مَا يَقُولُ وَنَحْنُ فِي مَنَازِلِنَا فَطَفِقَ يُعَلِّمُهُمْ مَنَاسِكَهُمْ حَتَّى بَلَغَ الْجِمَارَ فَوَضَعَ أُصْبُعَيْهِ السَّبَّابَتَيْنِ ثُمَّ قَالَ بِحَصَى الْخَذْفِ ثُمَّ أَمَرَ الْمُهَاجِرِينَ فَنَزَلُوا فِي مُقَدَّمِ الْمَسْجِدِ وَأَمَرَ الْأَنْصَارَ فَنَزَلُوا مِنْ وَرَاءِ الْمَسْجِدِ ثُمَّ نَزَلَ النَّاسَ بَعْدَ ذَلِكَ","id":"Telah menceritakan kepada Kami [Musaddad], telah menceritakan kepada Kami [Abdul Warits] dari [Humaid Al A'raj] dari [Muhammad bin Ibrahim At Taimi] dari [Abdurrahman bin Mu'dz At Taimi], ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam berkhutbah kepada Kami sementara Kami berada di Mina. Pendengaran Kami terbuka hingga Kami mendengar apa yang beliau ucapkan sementara Kami berada di tempat singgah Kami. Beliau mengajarkan kepada mereka ibadah haji mereka hingga sampai melempar jumrah. Kemudian beliau meletakkan kedua jari telunjuknya kemudian mengatakan: \"Dengan kerikil khadzaf (seukuran untuk ketapel).\" Kemudian memerintahkan orang-orang muhajirin untuk singgah di depan masjid, dan memerintahkan orang-orang anshar untuk singgah di belakang masjid, kemudian orang-orang singgah setelah itu. "},"1610":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ مُحَمَّدُ بْنُ خَلَّادٍ الْبَاهِلِيُّ حَدَّثَنَا يَحْيَى عَنْ ابْنِ جُرَيْجٍ حَدَّثَنِي حَرِيزٌ أَوْ أَبُو حَرِيزٍ الشَّكّ مِنْ يَحْيَى أَنَّهُ سَمِعَ عَبْدَ الرَّحْمَنِ بْنَ فَرُّوخٍ يَسْأَلُ ابْنَ عُمَرَ قَالَإِنَّا نَتَبَايَعُ بِأَمْوَالِ النَّاسِ فَيَأْتِي أَحَدُنَا مَكَّةَ فَيَبِيتُ عَلَى الْمَالِ فَقَالَ أَمَّا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَبَاتَ بِمِنًى وَظَلَّ","id":"Telah menceritakan kepada Kami [Abu Bakr Muhammad bin Khallad Al Bahili], telah menceritakan kepada Kami [Yahya] dari [Ibnu Juraij], telah menceritakan kepada Kami [Hariz atau Abu Hariz] -ada keraguan dari Yahya- bahwa ia mendengar Abdurrahman bin Farrukh bertanya kepada [Ibnu Umar]; Kami menjualkan barang-barang orang, kemudian salah seorang dari Kami datang ke Mekkah dan bermalam dalam keadaan menjaga harta? Ibnu Umar berkata; adapun Rasulullah shallallahu 'alaihi wasallam beliau siang dan malam berada di Mina. "},"1611":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا ابْنُ نُمَيْرٍ وَأَبُو أُسَامَةَ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَاسْتَأْذَنَ الْعَبَّاسُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَبِيتَ بِمَكَّةَ لَيَالِيَ مِنًى مِنْ أَجْلِ سِقَايَتِهِ فَأَذِنَ لَهُ","id":"Telah menceritakan kepada Kami [Utsman bin Abu Syaibah], telah menceritakan kepada Kami [Ibnu Numair] dan [Abu Usamah] dari ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar], ia berkata; Al Abbas meminta idzin kepada Rasulullah shallAllahu wa'alaihi wa sallam untuk bermalam di Mekkah pada malam-malam hari di Mina karena tugasnya untuk memberi minum (orang-orang yang berhaji), kemudian beliau memberikan idzin kepadanya. "},"1612":{"ar":"حَدَّثَنَا مُسَدَّدٌ أَنَّ أَبَا مُعَاوِيَةَ وَحَفْصَ بْنَ غِيَاثٍ حَدَّثَاهُ وَحَدِيثُ أَبِي مُعَاوِيَةَ أَتَمُّ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ قَالَصَلَّى عُثْمَانُ بِمِنًى أَرْبَعًا فَقَالَ عَبْدُ اللَّهِ صَلَّيْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَكْعَتَيْنِوَمَعَ أَبِي بَكْرٍ رَكْعَتَيْنِ وَمَعَ عُمَرَ رَكْعَتَيْنِ زَادَ عَنْ حَفْصٍ وَمَعَ عُثْمَانَ صَدْرًا مِنْ إِمَارَتِهِ ثُمَّ أَتَمَّهَا زَادَ مِنْ هَا هُنَا عَنْ أَبِي مُعَاوِيَةَ ثُمَّ تَفَرَّقَتْ بِكُمْ الطُّرُقُ فَلَوَدِدْتُ أَنْ لِي مِنْ أَرْبَعِ رَكَعَاتٍ رَكْعَتَيْنِ مُتَقَبَّلَتَيْنِ قَالَ الْأَعْمَشُ فَحَدَّثَنِي مُعَاوِيَةَ بْنُ قُرَّةَ عَنْ أَشْيَاخِهِ أَنَّ عَبْدَ اللَّهِ صَلَّى أَرْبَعًا قَالَ فَقِيلَ لَهُ عِبْتَ عَلَى عُثْمَانَ ثُمَّ صَلَّيْتُ أَرْبَعًا قَالَ الْخِلَافُ شَرٌّ حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ أَخْبَرَنَا ابْنُ الْمُبَارَكِ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ أَنَّ عُثْمَانَ إِنَّمَا صَلَّى بِمِنًى أَرْبَعًا لِأَنَّهُ أَجْمَعَ عَلَى الْإِقَامَةِ بَعْدَ الْحَجِّ حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ عَنْ أَبِي الْأَحْوَصِ عَنْ الْمُغِيرَةِ عَنْ إِبْرَاهِيمَ قَالَ إِنَّ عُثْمَانَ صَلَّى أَرْبَعًا لِأَنَّهُ اتَّخَذَهَا وَطَنًا حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ أَخْبَرَنَا ابْنُ الْمُبَارَكِ عَنْ يُونُسَ عَنْ الزُّهْرِيِّ قَالَ لَمَّا اتَّخَذَ عُثْمَانُ الْأَمْوَالَ بِالطَّائِفِ وَأَرَادَ أَنْ يُقِيمَ بِهَا صَلَّى أَرْبَعًا قَالَ ثُمَّ أَخَذَ بِهِ الْأَئِمَّةُ بَعْدَهُ حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ أَيُّوبَ عَنْ الزُّهْرِيِّ أَنَّ عُثْمَانَ بْنَ عَفَّانَ أَتَمَّ الصَّلَاةَ بِمِنًى مِنْ أَجْلِ الْأَعْرَابِ لِأَنَّهُمْ كَثُرُوا عَامَئِذٍ فَصَلَّى بِالنَّاسِ أَرْبَعًا لِيُعَلِّمَهُمْ أَنَّ الصَّلَاةَ أَرْبَعٌ","id":"Telah menceritakan kepada Kami [Musaddad] bahwa [Abu Mu'awiyah] dan [Hafsh bin Ghiyats] menceritakan kepadanya. Dan hadits Abu Mu'awiyah lebih sempurna. Dari [Al A'masy] dari [Ibrahim] dari [Abdurrahman bin Yazid], ia berkata; Utsman melakukan shalat empat raka'at di Mina. Kemudian [Abdullah] berkata; aku melakukan shalat bersama Nabi shallallahu 'alaihi wasallam dua raka'at, bersama Abu Bakr dua raka'at dan bersama Umar dua raka'at. Ia tambahkan dari [Hafsh] kata; dan pada awal kepemimpinan Utsman, kemudian ia menyempurnakannya. Ia tambahkan dari sini dari Abu Mu'awiyah kata; kemudian jalan kalian berpencar, sungguh aku berharap dari empat raka'at aku memiliki dua raka'at yang diterima. [Al A'masy] berkata; kemudian [Mu'awiyah bin Qurrah] telah menceritakan kepadaku dari [para gurunya] bahwa [Abdullah] melakukan shalat empat raka'at. Kemudian dikatakan kepadanya; engkau mencela Utsman kemudian engkau melakukan shalat empat raka'at. Ia berkata; perselisihan adalah buruk. Telah menceritakan kepada Kami [Muhammad bin Al 'Ala`], telah mengabarkan kepada Kami [Ibnu Al Mubarak] dari [Ma'mar] dari [Az Zuhri] bahwa [Utsman] melakukan shalat empat raka'at di Mina karena ia berniat untuk bermukim setelah haji. Telah menceritakan kepada Kami [Hannad bin As Sarri] dari [Abu Al Ahwash] dari [Al Mughirah] dari [Ibrahim], ia berkata; sesungguhnya [Utsman] melakukan shalat empat dua raka'at karena ia menjadikan Mekkah sebagai tempat tinggal. Telah menceritakan kepada Kami [Muhammad bin Al 'Ala`], telah mengabarkan kepada Kami [Ibnu Al Mubarak] dari [Yunus] dari [Az Zuhri], ia berkata; tatakala [Utsman] memiliki harta di Thaif dan ingin bermukim di sana maka ia melakukan shalat empat dua raka'at. Ia berkata; kemudian para imam mengambil pendapat tersebut. Telah menceritakan kepada Kami [Musa bin Isma'il], telah menceritakan kepada Kami [Hammad] dari [Ayyub] dari [Az Zuhri] bahwa [Utsman bin Affan] menyempurnakan shalat di Mina karena orang-orang badui banyak pada tahun tersebut. Maka ia melakukan shalat bersama orang-orang empat raka'at untuk memberitahukan kepada mereka bahwa shalat adalah empat raka'at."},"1613":{"ar":"حَدَّثَنَا النُّفَيْلِيُّ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا أَبُو إِسْحَقَ حَدَّثَنِي حَارِثَةُ بْنُ وَهْبٍ الْخُزَاعِيُّ وَكَانَتْ أُمُّهُ تَحْتَ عُمَرَ فَوَلَدَتْ لَهُ عُبَيْدَ اللَّهِ بْنَ عُمَرَ قَالَصَلَّيْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِنًى وَالنَّاسُ أَكْثَرُ مَا كَانُوا فَصَلَّى بِنَا رَكْعَتَيْنِ فِي حَجَّةِ الْوَدَاعِقَالَ أَبُو دَاوُد حَارِثَةُ بْنُ خُزَاعَةَ وَدَارُهُمْ بِمَكَّةَ","id":"Telah menceritakan kepada Kami [An Nufaili], telah menceritakan kepada Kami [Zuhair], telah menceritakan kepada Kami [Abu Ishaq], telah menceritakan kepadaku [Haritsah bin Wahb Al Khuza'i] dan ibunya adalah istri Umar, kemudian melahirkan 'Ubaidullah bin Umar. Haritsah berkata; aku melakukan shalat bersama Rasulullah shallAllahu wa'alaihi wa sallam di Mina sementara orang-orang sangat banyak, kemudian beliau melakukan shalat dua rakaat pada waktu haji wada'. Abu Daud berkata: Haritsah bin Khuza'ah dan rumah mereka ada di Mekkah. "},"1614":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مَهْدِيٍّ حَدَّثَنِي عَلِيُّ بْنُ مُسْهِرٍ عَنْ يَزِيدَ بْنِ أَبِي زِيَادٍ أَخْبَرَنَا سُلَيْمَانُ بْنُ عَمْرِو بْنِ الْأَحْوَصِ عَنْ أُمِّهِ قَالَتْرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْمِي الْجَمْرَةَ مِنْ بَطْنِ الْوَادِي وَهُوَ رَاكِبٌ يُكَبِّرُ مَعَ كُلِّ حَصَاةٍ وَرَجُلٌ مِنْ خَلْفِهِ يَسْتُرُهُ فَسَأَلْتُ عَنْ الرَّجُلِ فَقَالُوا الْفَضْلُ بْنُ الْعَبَّاسِ وَازْدَحَمَ النَّاسُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أَيُّهَا النَّاسُ لَا يَقْتُلْ بَعْضُكُمْ بَعْضًا وَإِذَا رَمَيْتُمْ الْجَمْرَةَ فَارْمُوا بِمِثْلِ حَصَى الْخَذْفِ","id":"Telah menceritakan kepada Kami [Ibrahim bin Mahdi], telah menceritakan kepadaku [Ali bin Mushir] dari [Yazid bin Abu Ziyad], telah mengabarkan kepada Kami [Sulaiman bin 'Amr bin Al Ahwash] dari [ibunya], ia berkata; saya melihat Rasulullah shallAllahu wa'alaihi wa sallam melempar jumrah dari tengah bukit, dalam keadaan berkendaraan. Beliau bertakbir bersama setiap lemparan kerikil. Dan orang yang ada dibelakang menutupi beliau. Kemudian aku tanyakan mengenai orang tersebut, lalu mereka mengatakan; Al Fadhl bin Al Abbas. Orang-orang dalam keadaan berdesak-desakan, kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Wahai para manusia, janganlah sebagian kalian membunuh sebagian yang lain, apabila kalian melempar jumrah maka lemparlah dengan kerikil sebesar kerikil khadzaf (kerikil untuk ketapel). "},"1615":{"ar":"حَدَّثَنَا أَبُو ثَوْرٍ إِبْرَاهِيمُ بْنُ خَالِدٍ وَوَهْبُ بْنُ بَيَانٍ قَالَا حَدَّثَنَا عُبَيْدَةُ عَنْ يَزِيدَ بْنِ أَبِي زِيَادٍ عَنْ سُلَيْمَانَ بْنِ عَمْرِو بْنِ الْأَحْوَصِ عَنْ أُمِّهِ قَالَتْرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَ جَمْرَةِ الْعَقَبَةِ رَاكِبًا وَرَأَيْتُ بَيْنَ أَصَابِعِهِ حَجَرًا فَرَمَى وَرَمَى النَّاسُحَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا ابْنُ إِدْرِيسَ حَدَّثَنَا يَزِيدُ بْنُ أَبِي زِيَادٍ بِإِسْنَادِهِ فِي مِثْلِ هَذَا الْحَدِيثِ زَادَ وَلَمْ يَقُمْ عِنْدَهَا","id":"Telah menceritakan kepada Kami [Abu Tsaur Ibrahim bin Khalid], dan [Wahb bin Bayan], mereka berkata; telah menceritakan kepada Kami ['Ubaidah] dari [Yazid bin Abu Ziyad] dari [Sulaiman bin 'Amr bin Al Ahwash] dari [ibunya], ia berkata; aku melihat Rasulullah shallAllahu wa'alaihi wa sallam ketika melempar jumrah 'aqabah beliau dalam keadaan berdiri. Dan aku aku melihat diantara jari-jarinya terdapat batu, kemudian beliau melempar dan orang-orang pun melempar. Telah menceritakan kepada Kami [Muhammad bin Al 'Ala`], telah menceritakan kepada Kami [Ibnu Idris], telah menceritakan kepada Kami [Yazid bin Abu Ziyad] dengan sanadnya dalam hadits seperti ini, dan ia menambahkan kata; dan beliau tidak berdiri ketika melemparnya. "},"1616":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ حَدَّثَنَا عَبْدُ اللَّهِ يَعْنِي ابْنَ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّهُ كَانَ يَأْتِي الْجِمَارَ فِي الْأَيَّامِ الثَّلَاثَةِ بَعْدَ يَوْمِ النَّحْرِ مَاشِيًا ذَاهِبًا وَرَاجِعًا وَيُخْبِرُ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَفْعَلُ ذَلِكَ","id":"Telah menceritakan kepada Kami [Al Qa'nabi], telah menceritakan kepada Kami [Abdullah bin Umar] dari [Nafi'] dari [Ibnu Ibnu Umar] bahwa ia datang ke jumrah pada tiga hari setelah hari Nahr dengan berjalan kaki pulang pergi, dan ia mengabarkan bahwa Nabi shallallahu 'alaihi wasallam melakukan hal tersebut. "},"1617":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ ابْنِ جُرَيْجٍ أَخْبَرَنِي أَبُو الزُّبَيْرِ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْمِي عَلَى رَاحِلَتِهِ يَوْمَ النَّحْرِ يَقُولُ لِتَأْخُذُوا مَنَاسِكَكُمْ فَإِنِّي لَا أَدْرِي لَعَلِّي لَا أَحُجُّ بَعْدَ حَجَّتِي هَذِهِ","id":"Telah menceritakan kepada Kami [Ahmad bin Hanbal] telah menceritakan kepada Kami [Yahya bin Sa'id] dari [Ibnu Juraij], telah mengabarkan kepadaku [Abu Az Zubair], saya mendengar [Jabir bin Abdullah] berkata; saya melihat Rasulullah shallAllahu wa'alaihi wa sallam melempar jumrah di atas kendaraannya pada hari Nahr. Beliau berkata: \"Ambillah dariku ibadah haji kalian, sesungguhnya aku tidak tahu barangkali aku tidak akan melakukan haji setelah hajiku ini.\""},"1618":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ الزُّهْرِيُّ حَدَّثَنَا سُفْيَانُ عَنْ مِسْعَرٍ عَنْ وَبَرَةَ قَالَسَأَلْتُ ابْنَ عُمَرَ مَتَى أَرْمِي الْجِمَارَ قَالَ إِذَا رَمَى إِمَامُكَ فَارْمِ فَأَعَدْتُ عَلَيْهِ الْمَسْأَلَةَ فَقَالَ كُنَّا نَتَحَيَّنُ زَوَالَ الشَّمْسِ فَإِذَا زَالَتْ الشَّمْسُ رَمَيْنَا","id":"Telah menceritakan kepada Kami [Abdullah bin Muhammad Az Zuhri], telah menceritakan kepada Kami [Sufyan] dari [Mas'ar] dari [Wabarah], ia berkata; aku bertanya kepada [Ibnu Umar]; kapankah aku boleh melontar jumrah? Ia menjawab; apabila pemimpinmu telah melempar maka lemparlah! Aku mengulangi pertanyaanku kepadanya, kemudian ia berkata; Kami menunggu saat-saat tergelincirnya matahari, apabila matahari telah tergelincir maka Kami melempar. "},"1619":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ بَحْرٍ وَعَبْدُ اللَّهِ بْنُ سَعِيدٍ الْمَعْنَى قَالَا حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْأَفَاضَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ آخِرِ يَوْمِهِ حِينَ صَلَّى الظُّهْرَ ثُمَّ رَجَعَ إِلَى مِنًى فَمَكَثَ بِهَا لَيَالِيَ أَيَّامِ التَّشْرِيقِ يَرْمِي الْجَمْرَةَ إِذَا زَالَتْ الشَّمْسُ كُلُّ جَمْرَةٍ بِسَبْعِ حَصَيَاتٍ يُكَبِّرُ مَعَ كُلِّ حَصَاةٍ وَيَقِفُ عِنْدَ الْأُولَى وَالثَّانِيَةِ فَيُطِيلُ الْقِيَامَ وَيَتَضَرَّعُ وَيَرْمِي الثَّالِثَةَ وَلَا يَقِفُ عِنْدَهَا","id":"Telah menceritakan kepada Kami [Ali bin Bahr] dan [Abdullah bin Sa'id] secara makna, mereka berkata; telah menceritakan kepada Kami [Abu Khalid Al Ahmar] dari [Muhammad bin Ishaq] dari [Abdurrahman bin Al Qasim] dari [ayahnya] dari [Aisyah] ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam melakukan thawaf ifadhah pada hari terakhirnya ketika telah melakukan Shalat Zhuhur, kemudian beliau kembali ke Mina dan tinggal di sana beberapa malam, pada Hari-hari Tasyriq. Beliau melempar jumrah apabila matahari telah tergelincir. Setiap jumrah dengan tujuh kerikil, beliau bertakbir bersama setiap lemparan kerikil, beliau berdiri pada jumrah pertama dan kedua kemudian berdiri lama dan merendah diri, serta melempar ketiga dan tidak berdiri pada jumrah ketiga. "},"1620":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ وَمُسْلِمُ بْنُ إِبْرَاهِيمَ الْمَعْنَى قَالَا حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ عَنْ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ عَنْ ابْنِ مَسْعُودٍ قَالَلَمَّا انْتَهَى إِلَى الْجَمْرَةِ الْكُبْرَى جَعَلَ الْبَيْتَ عَنْ يَسَارِهِ وَمِنًى عَنْ يَمِينِهِ وَرَمَى الْجَمْرَةَ بِسَبْعِ حَصَيَاتٍ وَقَالَ هَكَذَا رَمَى الَّذِي أُنْزِلَتْ عَلَيْهِ سُورَةُ الْبَقَرَةِ","id":"Telah menceritakan kepada Kami [Hafsh bin Umar], serta [Muslim bin Ibrahim] secara makna. Mereka berkata; telah menceritakan kepada Kami [Syu'bah] dari [Al Hakam] dari [Ibrahim] dari [Abdurrahman bin Yazid] dari [Ibnu Mas'ud], ia berkata; tatkala beliau telah sampai pada jumrah kubra beliau menjadikan Ka'bar berada di sisi kirinya dan Mina di sisi kanannya, beliau melempar jumrah dengan tujuh kerikil. Ibnu Mas'ud berkata; demikianlah orang yang kepadanya diturunkan Surat Al Baqarah melempar. "},"1621":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ اللَّهِ وَمُحَمَّدُ ابْنَيْ أَبِي بَكْرٍ عَنْ أَبِيهِمَا عَنْ أَبِي الْبَدَّاحِ بْنِ عَدِيٍّ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَخَّصَ لِلرِّعَاءِ أَنْ يَرْمُوا يَوْمًا وَيَدَعُوا يَوْمًا","id":"Telah menceritakan kepada Kami [Musaddad], telah menceritakan kepada Kami [Sufyan] dari [Abdullah] dan [Muhammad] dua anak Abu Bakr, dari [ayah mereka], dari [Abu Al Baddah bin 'Adi] dari [ayahnya] bahwa Nabi shallallahu 'alaihi wasallam memberikan keringanan untuk para penggembala untuk melempar satu hari dan tidak melempar satu hari. "},"1622":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ الْمُبَارَكِ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ قَالَ سَمِعْتُ أَبَا مِجْلَزٍ يَقُولُسَأَلْتُ ابْنَ عَبَّاسٍ عَنْ شَيْءٍ مِنْ أَمْرِ الْجِمَارِ قَالَ مَا أَدْرِي أَرَمَاهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِسِتٍّ أَوْ بِسَبْعٍ","id":"Telah menceritakan kepada Kami [Abdurrahman bin Al Mubarak], telah menceritakan kepada Kami [Khalid bin Al Harits], telah menceritakan kepada Kami [Syu'bah] dari [Qatadah], ia berkata; saya mendengar [Abu Mijlaz] berkata; saya bertanya kepada [Ibnu Abbas] mengenai sebagian perkara jumrah. Ia berkata; aku tidak tahu apakah Rasulullah shallAllahu wa'alaihi wa sallam melemparnya dengan enam atau tujuh kerikil. "},"1623":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنِ زِيَادٍ حَدَّثَنَا الْحَجَّاجُ عَنْ الزُّهْرِيِّ عَنْ عَمْرَةَ بِنْتِ عَبْدِ الرَّحْمَنِ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا رَمَى أَحَدُكُمْ جَمْرَةَ الْعَقَبَةِ فَقَدْ حَلَّ لَهُ كُلُّ شَيْءٍ إِلَّا النِّسَاءَقَالَ أَبُو دَاوُد هَذَا حَدِيثٌ ضَعِيفٌ الْحَجَّاجُ لَمْ يَرَ الزُّهْرِيَّ وَلَمْ يَسْمَعْ مِنْهُ","id":"Telah menceritakan kepada Kami [Musaddad], telah menceritakan kepada Kami [Abdul Wahid bin Ziyad], telah menceritakan kepada Kami [Al Hajjaj] dari [Az Zuhri] dari ['Amrah binti Abdurrahman] dari [Aisyah], ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Apabila salah seorang diantara kalian melempar jumrah 'aqabah, maka telah halal baginya segala sesuatu, kecuali wanita.\" Abu Daud berkata; hadits ini adalah hadits dha'if. Al Hajjaj tidak melihat Az Zuhri dan tidak mendengar darinya. "},"1624":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اللَّهُمَّ ارْحَمْ الْمُحَلِّقِينَ قَالُوا يَا رَسُولَ اللَّهِ وَالْمُقَصِّرِينَ قَالَ اللَّهُمَّ ارْحَمْ الْمُحَلِّقِينَ قَالُوا يَا رَسُولَ اللَّهِ وَالْمُقَصِّرِينَ قَالَ وَالْمُقَصِّرِينَ","id":"Telah menceritakan kepada Kami [Al Qa'nabi] dari [Malik] dari [Nafi'] dari [Abdullah bin Umar] bahwa Rasulullah shallAllahu wa'alaihi wa sallam mengucapkan: \"ALLAAHUMMARHAM Al MUHALLIQIIN.\" (Ya Allah, rahmatilah orang-orang yang menggundul rambut kepalanya!) Para sahabat berkata; dan orang-orang yang memendekkan rambutnya wahai Rasulullah! Rasulullah shallAllahu wa'alaihi wa sallam mengucapkan: \"ALLAAHUMMARHAM Al MUHALLIQIIN.\" (Ya Allah, rahmatilah orang-orang yang menggundul rambut kepalanya!) Para sahabat berkata; dan orang-orang yang memendekkan rambutnya wahai Rasulullah! Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"WAL MUQASHSHIRIIN.\" (dan orang-orang yang memendekkan rambut kepalanya). "},"1625":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا يَعْقُوبُ يَعْنِي الْإِسْكَنْدَرَانِيَّ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَلَقَ رَأْسَهُ فِي حَجَّةِ الْوَدَاعِ","id":"Telah menceritakan kepada Kami [Qutaibah], telah menceritakan kepada Kami [Ya'qub yaitu Al Iskandarani] dari [Musa bin 'Uqbah] dari [Nafi'] dari [Ibnu Umar] bahwa Rasulullah shallAllahu wa'alaihi wa sallam menggundul rambut kepalanya pada saat haji wada'. "},"1626":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا حَفْصٌ عَنْ هِشَامٍ عَنْ ابْنِ سِيرِينَ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَمَى جَمْرَةَ الْعَقَبَةِ يَوْمَ النَّحْرِ ثُمَّ رَجَعَ إِلَى مَنْزِلِهِ بِمِنًى فَدَعَا بِذِبْحٍ فَذُبِحَ ثُمَّ دَعَا بِالْحَلَّاقِ فَأَخَذَ بِشِقِّ رَأْسِهِ الْأَيْمَنِ فَحَلَقَهُ فَجَعَلَ يَقْسِمُ بَيْنَ مَنْ يَلِيهِ الشَّعْرَةَ وَالشَّعْرَتَيْنِ ثُمَّ أَخَذَ بِشِقِّ رَأْسِهِ الْأَيْسَرِ فَحَلَقَهُ ثُمَّ قَالَ هَا هُنَا أَبُو طَلْحَةَ فَدَفَعَهُ إِلَى أَبِي طَلْحَةَحَدَّثَنَا عُبَيْدُ بْنُ هِشَامٍ أَبُو نُعَيْمٍ الْحَلَبِيُّ وَعَمْرُو بْنُ عُثْمَانَ الْمَعْنَى قَالَا حَدَّثَنَا سُفْيَانُ عَنْ هِشَامِ بْنِ حَسَّانَ بِإِسْنَادِهِ بِهَذَا قَالَ فِيهِ قَالَ لِلْحَالِقِ ابْدَأْ بِشِقِّي الْأَيْمَنِ فَاحْلِقْهُ","id":"Telah menceritakan kepada Kami [Muhammad bin Al 'Ala`], telah menceritakan kepada Kami [Hafsh] dari [Hisyam] dari [Ibnu Sirin] dari [Anas bin Malik] bahwa Rasulullah shallallahu 'alaihi wasallam melempar jumrah 'aqabah pada hari Nahr kemudian beliau kembali ke perkemahannya di Mina lalu beliau meminta hewan kurban dan beliau menyembelih, kemudian beliau memanggil tukang cukur, beliau membagikan rambut kepada orang-orang yang berada di sekitarnya kemudian lalu tukang cukur tersebut mencukur kepala sebelah kiri kemudian beliau berkata: \"Apakah di sini ada Abu Thalhah?\" Lalu beliau menyerahkan rambut tersebut kepada Abu Thalhah. Telah menceritakan kepada Kami ['Ubaid bin Hisyam Abu Nu'aim Al Halabi] dan ['Amr bin Utsman] secara makna, mereka berdua berkata; telah menceritakan kepada Kami [Sufyan] dari [Hisyam bin Hassan] dengan sanad ini dalam hadits tersebut ia berkata; beliau berkata kepada tukang cukur: \"Mulailah dari sebelah kanan, dan gundullah!\". "},"1627":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ أَخْبَرَنَا يَزِيدُ بْنُ زُرَيْعٍ أَخْبَرَنَا خَالِدٌ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْ��ِ وَسَلَّمَ كَانَ يُسْأَلُ يَوْمَ مِنًى فَيَقُولُ لَا حَرَجَ فَسَأَلَهُ رَجُلٌ فَقَالَ إِنِّي حَلَقْتُ قَبْلَ أَنْ أَذْبَحَ قَالَ اذْبَحْ وَلَا حَرَجَ قَالَ إِنِّي أَمْسَيْتُ وَلَمْ أَرْمِ قَالَ ارْمِ وَلَا حَرَجَ","id":"Telah menceritakan kepada Kami [Nashr bin Ali], telah mengabarkan kepada Kami [Yazid bin Zurai'], telah mengabarkan kepada Kami [Khalid] dari [Ikrimah] dari [Ibnu Abbas] bahwa Nabi shallallahu 'alaihi wasallam ditanya pada hari di Mina dan beliau menjawab: \"Tidak mengapa\". Kemudian seseorang bertanya; sesungguhnya saya telah menggundul rambutku sebelum aku menyembelih. Beliau menjawab: \"Sembelihlah, tidak mengapa!\" Ia berkata; saya pada sore hari belum melempar jumrah. Beliau menjawab: \"Lemparlah, tidak mengapa!\""},"1628":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْحَسَنِ الْعَتَكِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ بَكْرٍ حَدَّثَنَا ابْنُ جُرَيْجٍ قَالَ بَلَغَنِي عَنْ صَفِيَّةَ بِنْتِ شَيْبَةَ بْنِ عُثْمَانَ قَالَتْ أَخْبَرَتْنِي أُمُّ عُثْمَانَ بِنْتُ أَبِي سُفْيَانَ أَنَّ ابْنَ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ عَلَى النِّسَاءِ حَلْقٌ إِنَّمَا عَلَى النِّسَاءِ التَّقْصِيرُ","id":"Telah menceritakan kepada Kami [Muhammad bin Al Hasan Al 'Ataki], telah menceritakan kepada Kami [Muhammad bin Bakr], telah menceritakan kepada Kami [Ibnu Juraij], ia berkata; telah sampai kepadaku dari [Shafiyyah binti Syaibah bin Utsman], ia berkata; telah mengabarkan kepadaku [Ummu Utsman binti Abu Sufyan] bahwa [Ibnu Abbas] berkata: Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya yang wajib atas wanita adalah mengurangi.\""},"1629":{"ar":"حَدَّثَنَا أَبُو يَعْقُوبَ الْبَغْدَادِيُّ ثِقَةٌ حَدَّثَنَا هِشَامُ بْنُ يُوسُفَ عَنْ ابْنِ جُرَيْجٍ عَنْ عَبْدِ الْحَمِيدِ بْنِ جُبَيْرِ بْنِ شَيْبَةَ عَنْ صَفِيَّةَ بِنْتِ شَيْبَةَ قَالَتْ أَخْبَرَتْنِي أُمُّ عُثْمَانَ بِنْتُ أَبِي سُفْيَانَ أَنَّ ابْنَ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ عَلَى النِّسَاءِ الْحَلْقُ إِنَّمَا عَلَى النِّسَاءِ التَّقْصِيرُ","id":"Telah menceritakan kepada Kami [Abu Ya'qub Al Baghdadi], ia adalah orang-orang Tsiqah, telah menceritakan kepada Kami [Hisyam bin Yusuf] dari [Ibnu Juraij] dari [Abdul Hamid bin Jubair bin Syaibah] dari [Shafiyyah binti Syaibah], ia berkata; telah mengabarkan kepadaku [Ummu Utsman binti Abu Sufyan] bahwa [Ibnu Abbas] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wanita tidak wajib menggundul rambut akan tetapi yang wajib atas wanita adalah mengurangi.\""},"1630":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مَخْلَدُ بْنُ يَزِيدَ وَيَحْيَى بْنُ زَكَرِيَّا عَنْ ابْنِ جُرَيْجٍ عَنْ عِكْرِمَةَ بْنِ خَالِدٍ عَنْ ابْنِ عُمَرَ قَالَاعْتَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَبْلَ أَنْ يَحُجَّ","id":"Telah menceritakan kepada Kami [Utsman bin Abu Syaibah], telah menceritakan kepada Kami [Makhlad bin Yazid] dan [Yahya bin Zakariya] dari [Ibnu Juraij] dari [Ikrimah bin Khalid] dari [Ibnu Umar], ia berkata; Rasulullah shallallahu 'alaihi wasallam melaksanakan umrah sebelum melaksanakan haji. "},"1631":{"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ عَنْ ابْنِ أَبِي زَائِدَةَ حَدَّثَنَا ابْنُ جُرَيْجٍ وَمُحَمَّدُ بْنُ إِسْحَقَ عَنْ عَبْدِ اللَّهِ بْنِ طَاوُسٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ قَالَوَاللَّهِ مَا أَعْمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَائِشَةَ فِي ذِي الْحِجَّةِ إِلَّا لِيَقْطَعَ بِذَلِكَ أَمْرَ أَهْلِ الشِّرْكِ فَإِنَّ هَذَا الْحَيَّ مِنْ قُرَيْشٍ وَمَنْ دَانَ دِينَهُمْ كَانُوا يَقُولُونَ إِذَا عَفَا الْوَبَرْ وَبَرَأَ الدَّبَرْ وَدَخَلَ صَفَرْ فَقَدْ حَلَّتْ الْعُمْرَةُ لِمَنْ اعْتَمَرْ فَكَانُوا يُحَرِّمُونَ الْعُمْرَةَ حَتَّى يَنْسَلِخَ ذُو الْحِجَّةِ وَالْمُحَرَّمُ","id":"Telah menceritakan kepada Kami [Hannad bin As Sarri] dari [Ibnu Abu Zaidah] telah menceritakan kepada kami [Ibnu Juraij] dan [Muhammad bin Ishaq] dari [Abdullah bin Thawus] dari [ayahnya] dari [Ibnu Abbas], ia berkata; demi Allah, tidaklah Rasulullah shallAllahu wa'alaihi wa sallam mengumrahkan Aisyah pada Bulan Dzul Hijjah melainkan agar dengan hal tersebut beliau membantah perkara ahli syirik. Sesungguhnya sebuah kampung Quraisy dan orang-orang yang berkeyakinan seperti keyakinan mereka dahulu mengatakan; apabila rambut unta telah tumbuh, dan luka telah sembuh serta telah masuk Bulan Shafar maka telah halal umrah bagi orang yang berumrah. Dan mereka mengharamkan umrah hingga berlalu Bulan Dzul Hijjah dan Muharram. "},"1632":{"ar":"حَدَّثَنَا أَبُو كَامِلٍ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ إِبْرَاهِيمَ بْنِ مُهَاجِرٍ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ أَخْبَرَنِي رَسُولُ مَرْوَانَ الَّذِي أُرْسِلَ إِلَى أُمِّ مَعْقَلٍ قَالَتْكَانَ أَبُو مَعْقَلٍ حَاجًّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا قَدِمَ قَالَتْ أُمُّ مَعْقَلٍ قَدْ عَلِمْتَ أَنَّ عَلَيَّ حَجَّةً فَانْطَلَقَا يَمْشِيَانِ حَتَّى دَخَلَا عَلَيْهِ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنَّ عَلَيَّ حَجَّةً وَإِنَّ لِأَبِي مَعْقَلٍ بَكْرًا قَالَ أَبُو مَعْقَلٍ صَدَقَتْ جَعَلْتُهُ فِي سَبِيلِ اللَّهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْطِهَا فَلْتَحُجَّ عَلَيْهِ فَإِنَّهُ فِي سَبِيلِ اللَّهِ فَأَعْطَاهَا الْبَكْرَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنِّي امْرَأَةٌ قَدْ كَبِرْتُ وَسَقِمْتُ فَهَلْ مِنْ عَمَلٍ يُجْزِئُ عَنِّي مِنْ حَجَّتِي قَالَ عُمْرَةٌ فِي رَمَضَانَ تُجْزِئُ حَجَّةً","id":"Telah menceritakan kepada Kami [Abu Kamil] telah menceritakan kepada Kami [Abu 'Awanah] dari [Ibrahim bin Muhajir] dari [Abu Bakr bin Abdurrahman], telah mengabarkan kepadaku [utusan Marwan] yang dikirim kepada [Ummu Ma'qil], ia berkata; dahulu Abu Ma'qil pernah berhaji bersama Rasulullah shallAllahu wa'alaihi wa sallam, kemudian tatkala ia datang, Ummu Ma'qil berkata; sungguh engkau telah mengetahui bahwa aku wajib berhaji. Kemudian mereka berdua berjalan hingga menemui beliau. Ummu Ma'qil berkata; wahai Rasulullah, sesungguhnya saya wajib berhaji, dan sesungguhnya Abu Ma'qil memiliki unta muda. Abu Ma'qil berkata; ia benar, saya telah menjadikannya di jalan Allah. Maka Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Berikan kepadanya, dan silahkan ia berhaji dengan mengendarainya, sesungguhnya hal tersebut adalah di jalan Allah.\" Kemudian Abu Ma'qil memberikan unta muda tersebut kepadanya. Lalu Ummu Ma'qil berkata; wahai Rasulullah, sesungguhnya saya adalah seorang wanita yang telah tua, dan sakit. Apakah ada amalan yang mencukupkanku dari melakukan haji? Beliau menjawab: \"Umrah pada Bulan Ramadhan, mencukupkan dari melakukan haji.\""},"1633":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَوْفٍ الطَّائِيُّ حَدَّثَنَا أَحْمَدُ بْنُ خَالِدٍ الْوَهْبِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَقَ عَنْ عِيسَى بْنِ مَعْقَلِ بْنِ أُمِّ مَعْقَلٍ الْأَسَدِيِّ أَسَدِ خُزَيْمَةَ حَدَّثَنِي يُوسُفُ بْنُ عَبْدِ اللَّهِ بْنِ سَلَامٍ عَنْ جَدَّتِهِ أُمِّ مَعْقَلٍ قَالَتْلَمَّا حَجَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَجَّةَ الْوَدَاعِ وَكَانَ لَنَا جَمَلٌ فَجَعَلَهُ أَبُو مَعْقِلٍ فِي سَبِيلِ اللَّهِ وَأَصَابَنَا مَرَضٌ وَهَلَكَ أَبُو مَعْقِلٍ وَخَرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا فَرَغَ مِنْ حَجِّهِ جِئْتُهُ فَقَالَ يَا أُمَّ مَعْقِلٍ مَا مَنَعَكِ أَنْ تَخْرُجِي مَعَنَا قَالَتْ لَقَدْ تَهَيَّأْنَا فَهَلَكَ أَبُو مَعْقِلٍ وَكَانَ لَنَا جَمَلٌ هُوَ الَّذِي نَحُجُّ عَلَيْهِ فَأَوْصَى بِهِ أَبُو مَعْقِلٍ فِي سَبِيلِ اللَّهِ قَالَ فَهَلَّا خَرَجْتِ عَلَيْهِ فَإِنَّ الْحَجَّ فِي سَبِيلِ اللَّهِ فَأَمَّا إِذْ فَاتَتْكِ هَذِهِ الْحَجَّةُ مَعَنَا فَاعْتَمِرِي فِي رَمَضَانَ فَإِنَّهَا كَحَجَّةٍ فَكَانَتْ تَقُولُ الْحَجُّ حَجَّةٌ وَالْعُمْرَةُ عُمْرَةٌ وَقَدْ قَالَ هَذَا لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا أَدْرِي أَلِيَ خَاصَّةً","id":"Telah menceritakan kepada Kami [Muhammad bin 'Auf Ath Thai], telah menceritakan kepada Kami [Ahmad bin Khalid Al Wahbi], telah menceritakan kepada Kami [Muhammad bin Ishaq] dari [Isa bin Ma'qil bin Ummu Ma'qil Al Asadi] yaitu Asad Khuzaimah, telah menceritakan kepadaku [Yusuf bin Abdullah bin Salam] dari [Neneknya yaitu Ummu Ma'qil], ia berkata; tatkala Rasulullah shallAllahu wa'alaihi wa sallam melakukan haji wada', dan Kami memiliki seekor unta, Abu Ma'qil menjadikannya di jalan Allah sementara Kami terserang penyakit. Dan Abu Ma'qil meninggal. Nabi shallallahu 'alaihi wasallam meninggal, dan tatkala telah selesai dari hajinya aku datang kepada beliau, lalu beliau berkata: \"Wahai Ummu Ma'qil, apa yang menghalangimu untuk keluar bersama Kami?\" ia berkata; sungguh saya telah bersiap-siap namun Abu Ma'qil meninggal, dan Kami memiliki seekor unta yang Kami gunakan untuk berhaji. Kemudian Abu Ma'qil berwasiat agar unta tersebut untuk di jalan Allah. Beliau berkata: \"Tidakkah engkau keluar dengan mengendarainya? Sesungguhnya haji adalah di jalan Allah, adapun apabila engkau telah tertinggal haji ini bersama Kami maka lakukanlah umrah pada Bulan Ramadhan, karena sesungguhnya umrah tersebut seperti haji.\" Ummu Ma'qil pernah berkata; haji adalah haji dan umrah adalah umrah. Dan Rasulullah shallAllahu wa'alaihi wa sallam telah mengatakan hal ini kepadaku, aku tidak tahu apakah hal khusus untukku? "},"1634":{"ar":"حَدَّثَنَا مُسَدَّدٌ وَحَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ عَامِرٍ الْأَحْوَلِ عَنْ بَكْرِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ قَالَأَرَادَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْحَجَّ فَقَالَتْ امْرَأَةٌ لِزَوْجِهَا أَحِجَّنِي مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى جَمَلِكَ فَقَالَ مَا عِنْدِي مَا أُحِجُّكِ عَلَيْهِ قَالَتْ أَحِجَّنِي عَلَى جَمَلِكَ فُلَانٍ قَالَ ذَاكَ حَبِيسٌ فِي سَبِيلِ اللَّهِ عَزَّ وَجَلَّ فَأَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ امْرَأَتِي تَقْرَأُ عَلَيْكَ السَّلَامَ وَرَحْمَةَ اللَّهِ وَإِنَّهَا سَأَلَتْنِي الْحَجَّ مَعَكَ قَالَتْ أَحِجَّنِي مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ مَا عِنْدِي مَا أُحِجُّكِ عَلَيْهِ فَقَالَتْ أَحِجَّنِي عَلَى جَمَلِكَ فُلَانٍ فَقُلْتُ ذَاكَ حَبِيسٌ فِي سَبِيلِ اللَّهِ فَقَالَ أَمَا إِنَّكَ لَوْ أَحْجَجْتَهَا عَلَيْهِ كَانَ فِي سَبِيلِ اللَّهِ قَالَ وَإِنَّهَا أَمَرَتْنِي أَنْ أَسْأَلَكَ مَا يَعْدِلُ حَجَّةً مَعَكَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقْرِئْهَا السَّلَامَ وَرَحْمَةَ اللَّهِ وَبَرَكَاتِهِ وَأَخْبِرْهَا أَنَّهَا تَعْدِلُ حَجَّةً مَعِي يَعْنِي عُمْرَةً فِي رَمَضَانَ","id":"Telah menceritakan kepada Kami [Musaddad], telah menceritakan kepada Kami [Abdul Warits] dari [Amir Al Ahwal] dari [Bakr bin Abdullah] dari [Ibnu Abbas], ia berkata; Rasulullah shallAllahu wa'alaihi wa sallam hendak melakukan haji, kemudian seorang wanita berkata kepada suaminya; hajikan saya bersama Rasulullah shallAllahu wa'alaihi wa sallam di atas untamu! Kemudian beliau berkata; aku tidak memiliki sesuatu untuk membawamu berhaji. Ia berkata; hajikan saya di atas untamu Fulani! Ia berkata; itu adalah unta yang tertahan untuk di jalan Allah 'azza wajalla. Kemudian ia datang kepada Rasulullah shallAllahu wa'alaihi wa sallam dan berkata; sesungguhnya isteriku mengucapkan salam dan rahmat kepadamu. Dan ia meminta kepadaku untuk melakukan haji bersamamu. Ia berkata; hajikan aku bersama Rasulullah shallAllahu wa'alaihi wa sallam Fulani! Lalu aku mengatakan unta itu adalah unta yang tertahan di jalan Allah. Kemudian beliau berkata: \"Sesungguhnya apabila engkau menghajikannya di atas unta tersebut maka hal itu adalah di jalan Allah.\" Ia berkata; dan ia memintaku untuk bertanya kepada anda, apakah yang sama dengan haji bersama anda? Kemudian Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Sampaikan salam dan rahmat serta berkah kepadanya. Umrah pada Bulan Ramadhan adalah sama dengan haji bersamaku.\""},"1635":{"ar":"حَدَّثَنَا عَبْدُ الْأَعْلَى بْنُ حَمَّادٍ حَدَّثَنَا دَاوُدُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اعْتَمَرَ عُمْرَتَيْنِ عُمْرَةً فِي ذِي الْقِعْدَةِ وَعُمْرَةً فِي شَوَّالٍ","id":"Telah menceritakan kepada Kami [Abdul A'la bin Hammad], telah menceritakan kepada Kami [Daud bin Abdurrahman] dari [Hisyam bin 'Urwah] dari [ayahnya] dari [Aisyah] bahwa Rasulullah shallAllahu wa'alaihi wa sallam melakukan umrah dua kali, yaitu umrah pada Bulan Dzul Qa'dah dan Umrah pada Bulan Syawal. "},"1636":{"ar":"حَدَّثَنَا النُّفَيْلِيُّ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا أَبُو إِسْحَقَ عَنْ مُجَاهِدٍ قَالَسُئِلَ ابْنُ عُمَرَ كَمْ اعْتَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَرَّتَيْنِ فَقَالَتْ عَائِشَةُ لَقَدْ عَلِمَ ابْنُ عُمَرَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ اعْتَمَرَ ثَلَاثًا سِوَى الَّتِي قَرَنَهَا بِحَجَّةِ الْوَدَاعِ","id":"Telah menceritakan kepada kami [An Nufaili], telah menceritakan kepada kami [Zuhair], telah menceritakan kepada kami [Abu Ishaq] dari [Mujahid], ia berkata; [Ibnu Umar] ditanya; Berapa kali Rasulullah shallallahu 'alaihi wasallam melakukan umrah? Ia berkata; Dua kali. 'Aisyah berkata; Sungguh, Ibnu Umar mengetahui bahwa Rasulullah shallallahu 'alaihi wasallam telah melaksanakan umrah sebanyak tiga kali selain umrah yang beliau laksanakan bersamaan dengan haji wada'. "},"1637":{"ar":"حَدَّثَنَا النُّفَيْلِيُّ وَقُتَيْبَةُ قَالَا حَدَّثَنَا دَاوُدُ بْنُ عَبْدِ الرَّحْمَنِ الْعَطَّارُ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَاعْتَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْبَعَ عُمَرٍ عُمْرَةَ الْحُدَيْبِيَةِ وَالثَّانِيَةَ حِينَ تَوَاطَئُوا عَلَى عُمْرَةٍ مَنْ قَابِلٍ وَالثَّالِثَةَ مِنْ الْجِعْرَانَةِ وَالرَّابِعَةَ الَّتِي قَرَنَ مَعَ حَجَّتِهِ","id":"Telah menceritakan kepada kami [An Nufaili] dan [Qutaibah], mereka berkata; telah menceritakan kepada kami [Daud bin Abdurrahman Al 'Aththar] dari ['Amr bin Dinar] dari [Ikrimah] dari [Ibnu Abbas], ia berkata; Rasulullah shallallahu 'alaihi wasallam melaksanakan umrah sebanyak empat kali, yaitu: pertama, umrah Hudaibiyah, kedua ketika mereka bersepakat untuk melakukan umrah pada tahun mendatang, ketiga umrah dari Al Ji'ranah, dan keempat umrah yang beliau laksanakan bersamaan dengan haji beliau. "},"1638":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ وَهُدْبَةُ بْنُ خَالِدٍ قَالَا حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ أَنَسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اعْتَمَرَ أَرْبَعَ عُمَرٍ كُلَّهُنَّ فِي ذِي الْقِعْدَةِ إِلَّا الَّتِي مَعَ حَجَّتِهِقَالَ أَبُو دَاوُد أَتْقَنْتُ مِنْ هَا هُنَا مِنْ هُدْبَةَ وَسَمِعْتُهُ مِنْ أَبِي الْوَلِيدِ وَلَمْ أَضْبِطْهُ عُمْرَةً زَمَنَ الْحُدَيْبِيَةِ أَوْ مِنْ الْحُدَيْبِيَةِ وَعُمْرَةَ الْقَضَاءِ فِي ذِي الْقِعْدَةِ وَعُمْرَةً مِنْ الْجِعْرَانَةِ حَيْثُ قَسَمَ غَنَائِمَ حُنَيْنٍ فِي ذِي الْقِعْدَةِ وَعُمْرَةً مَعَ حَجَّتِهِ","id":"Telah menceritakan kepada kami [Abu Al Walid Ath Thayalisi], serta [Hudbah bin Khalid], mereka berkata; telah menceritakan kepada kami [Hammam] dari [Qatadah] dari [Anas] bahwa Rasulullah shallallahu 'alaihi wasallam melaksanakan umrah sebanyak empat kali, seluruhnya pada bulan Dzul Qa'dah kecuali umrah yang beliau laksanakan bersamaan dengan haji beliau. Abu Daud berkata; Dari sini aku hafal dari Hudbah, dan aku mendengarnya dari Abu Al Walid, dan belum menelitinya secara sempurna yaitu umrah pada saat berada di Hudaibiyah, atau dari Hudaibiyah, umrah qadha` (umratul qadha`) pada Bulan Dzul Hijjah, umrah dari Al Ji'ranah dimana beliau membagi harta rampasan perang pada Bulan Dzul Qa'dah serta umrah bersamaan dengan haji beliau. "},"1639":{"ar":"حَدَّثَنَا عَبْدُ الْأَعْلَى بْنُ حَمَّادٍ حَدَّثَنَا دَاوُدُ بْنُ عَبْدِ الرَّحْمَنِ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ عُثْمَانَ بْنِ خُثَيْمٍ عَنْ يُوسُفَ بْنِ مَاهَكَ عَنْ حَفْصَةَ بِنْتِ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرٍ عَنْ أَبِيهَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِعَبْدِ الرَّحْمَنِ يَا عَبْدَ الرَّحْمَنِ أَرْدِفْ أُخْتَكَ عَائِشَةَ فَأَعْمِرْهَا مِنْ التَّنْعِيمِ فَإِذَا هَبَطْتَ بِهَا مِنْ الْأَكَمَةِ فَلْتُحْرِمْ فَإِنَّهَا عُمْرَةٌ مُتَقَبَّلَةٌ","id":"Telah menceritakan kepada kami [Abdul A'la bin Hammad], telah menceritakan kepada kami [Daud bin Abdurrahman], telah menceritakan kepadaku [Abdullah bin Utsman bin Khutsaim] dari [Yusuf bin Mahik] dari [Hafshah binti Abdurrahman bin Abu Bakr] dari [ayahnya] bahwa Rasulullah shallallahu 'alaihi wasallam berkata kepada Abdurrahman: \"Boncengkan saudarimu 'Aisyah, dan umrahkan dia dari Tan'im, apabila engkau telah sampai di anak bukit hendaknya ia melakukan umrah, sesungguhnya umrah tersebut adalah umrah yang diterima (sah pelaksanaannya).\""},"1640":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا سَعِيدُ بْنُ مُزَاحِمِ بْنِ أَبِي مُزَاحِمٍ حَدَّثَنِي أَبِي مُزَاحِمٍ عَنْ عَبْدِ الْعَزِيزِ بْنِ عَبْدِ اللَّهِ بْنِ أَسِيدٍ عَنْ مُحَرِّشٍ الْكَعْبِيِّ قَالَدَخَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْجِعْرَانَةِ فَجَاءَ إِلَى الْمَسْجِدِ فَرَكَعَ مَا شَاءَ اللَّهُ ثُمَّ أَحْرَمَ ثُمَّ اسْتَوَى عَلَى رَاحِلَتِهِ فَاسْتَقْبَلَ بَطْنَ سَرِفَ حَتَّى لَقِيَ طَرِيقَ الْمَدِينَةِ فَأَصْبَحَ بِمَكَّةَ كَبَائِتٍ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id], telah menceritakan kepada kami [Sa'id bin Muzahim bin Abu Muzahim], telah menceritakan kepadaku [Abu Muzahim] dari [Abdul 'Aziz bin Abdullah bin Usaid] dari [Muharrisy Al Ka'bi], ia berkata; Nabi shallallahu 'alaihi wasallam memasuki Al Ji'ranah, kemudian beliau datang ke masjid dan melakukan shalat sebanyak yang Allah kehendaki, kemudian beliau berada di atas kendaraannya dan menghadap ke arah Sarif, hingga beliau bertemu dengan jalan menuju Madinah, dan pada pagi hari beliau seperti orang yang bermalam di Mekkah. "},"1641":{"ar":"حَدَّثَنَا دَاوُدُ بْنُ رُشَيْدٍ حَدَّثَنَا يَحْيَى بْنُ زَكَرِيَّا حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَقَ عَنْ أَبَانَ بْنِ صَالِحٍ وَعَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقَامَ فِي عُمْرَةِ الْقَضَاءِ ثَلَاثًا","id":"Telah menceritakan kepada kami [Daud bin Rusyaid], telah menceritakan kepada kami [Yahya bin Zakariya], telah menceritakan kepada kami [Muhammad bin Ishaq] dari [Aban bin Shalih] dan dari [Ibnu Abu Najih] dari [Mujahid] dari [Ibnu Abbas] bahwa Rasulullah shallallahu 'alaihi wasallam bermukim di Mekkah pada waktu umratul qadha selama tiga hari. "},"1642":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفَاضَ يَوْمَ النَّحْرِ ثُمَّ صَلَّى الظُّهْرَ بِمِنًى يَعْنِي رَاجِعًا","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal], telah menceritakan kepada kami [Abdurrazzaq], telah mengabarkan kepada kami ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar] bahwa Nabi shallallahu 'alaihi wasallam melakukan thawaf ifadhah pada hari nahr kemudian melakukan shalat Zhuhur di Mina ketika, yaitu dalam keadaan kembali kepadanya. "},"1643":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ وَيَحْيَى بْنُ مَعِينٍ الْمَعْنَى وَاحِدٌ قَالَا حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ حَدَّثَنَا أَبُو عُبَيْدَةَ بْنُ عَبْدِ اللَّهِ بْنِ زَمْعَةَ عَنْ أَبِيهِ وَعَنْ أُمِّهِ زَيْنَبَ بِنْتِ أَبِي سَلَمَةَ عَنْ أُمِّ سَلَمَةَيُحَدِّثَانِهِ جَمِيعًا ذَاكَ عَنْهَا قَالَتْ كَانَتْ لَيْلَتِي الَّتِي يَصِيرُ إِلَيَّ فِيهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَسَاءَ يَوْمِ النَّحْرِ فَصَارَ إِلَيَّ وَدَخَلَ عَلَيَّ وَهْبُ بْنُ زَمْعَةَ وَمَعَهُ رَجُلٌ مِنْ آلِ أَبِي أُمَيَّةَ مُتَقَمِّصَيْنِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِوَهْبٍ هَلْ أَفَضْتَ أَبَا عَبْدِ اللَّهِ قَالَ لَا وَاللَّهِ يَا رَسُولَ اللَّهِ قَالَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْزِعْ عَنْكَ الْقَمِيصَ قَالَ فَنَزَعَهُ مِنْ رَأْسِهِ وَنَزَعَ صَاحِبُهُ قَمِيصَهُ مِنْ رَأْسِهِ ثُمَّ قَالَ وَلِمَ يَا رَسُولَ اللَّهِ قَالَ إِنَّ هَذَا يَوْمٌ رُخِّصَ لَكُمْ إِذَا أَنْتُمْ رَمَيْتُمْ الْجَمْرَةَ أَنْ تَحِلُّوا يَعْنِي مِنْ كُلِّ مَا حُرِمْتُمْ مِنْهُ إِلَّا النِّسَاءَ فَإِذَا أَمْسَيْتُمْ قَبْلَ أَنْ تَطُوفُوا هَذَا الْبَيْتَ صِرْتُمْ حُرُمًا كَهَيْئَتِكُمْ قَبْلَ أَنْ تَرْمُوا الْجَمْرَةَ حَتَّى تَطُوفُوا بِهِ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] dan [Yahya bin Ma'in] dengan makna yang sama, mereka berkata; telah menceritakan kepada kami [Ibnu Abu 'Adi] dari [Muhammad bin Ishaq], telah menceritakan kepada kami [Abu 'Ubaidah bin Abdullah bin Zam'ah] dari [ayahnya] dari [ibunya yaitu Zainab binti Abu Salamah] dari [Ummu Salamah], mereka semua menceritakan kepadanya hal tersebut dari Ummu Salamah, ia berkata; pada malam bagianku yang seharusnya Rasulullah shallallahu 'alaihi wasallam datang kepadaku adalah sore hari nahr. Wahb bin Zam'ah serta seseorang dari keluarga Umayyah dengan memakai jubah datang dan menemuiku. Lalu Rasulullah shallallahu 'alaihi wasallam berkata kepada Wahb: \"Apakah engkau telah melakukan thawaf ifadhah wahai Abu Abdullah?\" Ia berkata; demi Allah, belum wahai Rasulullah! Beliau berkata: \"Lepaskan jubah darimu!\" Abu Salamah berkata; kemudian ia melepas jubah tersebut dari kepalanya dan temannya pun melepas jubahnya. Kemudian Wahb bin Zam'ah berkata; kenapa wahai Rasulullah? Beliau berkata: \"Sesungguhnya ini adalah hari diberinya kalian keringanan apabila kalian melempar jumrah dari setiap apa yang haram bagi kalian kecuali bercampur dengan wanita. Apabila kalian berada di sore hari sebelum melakukan thawaf di Ka'bah, maka kalian dalam keadaan sedang berihram seperti keadaan kalian sebelum melempar jumrah, hingga kalian melakukan thawaf di Ka'bah.\""},"1644":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي الزُّبَيْرِ عَنْ عَائِشَةَ وَابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخَّرَ طَوَافَ يَوْمِ النَّحْرِ إِلَى اللَّيْلِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar], telah menceritakan kepada kami [Abdurrahman], telah menceritakan kepada kami [Sufyan] dari [Abu Az Zubair] dari [Aisyah] dan [Ibnu Abbas] bahwa Nabi shallallahu 'alaihi wasallam menunda thawaf pada hari nahr (hari raya kurban) hingga malam. "},"1645":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ أَخْبَرَنَا ابْنُ وَهْبٍ حَدَّثَنِي ابْنُ جُرَيْجٍ عَنْ عَطَاءِ بْنِ أَبِي رَبَاحٍ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَرْمُلْ فِي السَّبْعِ الَّذِي أَفَاضَ فِيهِ","id":"Telah menceritakan kepada kami [Sulaiman bin Daud], telah mengabarkan kepada kami [Ibnu Wahb], telah menceritakan kepadaku [Ibnu Juraij], dari ['Atha` bin Abu Rabah] dari [Ibnu Abbas] bahwa Nabi shallallahu 'alaihi wasallam tidak melaksanakan raml (berjalan cepat) pada tujuh putaran thawaf ifadhah. "},"1646":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ حَدَّثَنَا سُفْيَانُ عَنْ سُلَيْمَانَ الْأَحْوَلِ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ النَّاسُ يَنْصَرِفُونَ فِي كُلِّ وَجْهٍ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَنْفِرَنَّ أَحَدٌ حَتَّى يَكُونَ آخِرُ عَهْدِهِ الطَّوَافَ بِالْبَيْتِ","id":"Telah menceritakan kepada kami [Nashr bin Ali], telah menceritakan kepada kami [Sufyan] dari [Sulaiman Al Ahwal] dari [Thawus] dari [Ibnu Abbas], ia berkata; orang-orang pergi dalam segala keadaan (berkelompok dan tidak berkelompok), kemudian Nabi shallallahu 'alaihi wasallam berkata: \"Janganlah seorang pun (dari kalian) meninggalkan Mekkah kembali kepada keluarganya, hingga (ibadah) terakhir ia lakukan adalah thawaf di Ka'bah.\""},"1647":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَكَرَ صَفِيَّةَ بِنْتَ حُيَيٍّ فَقِيلَ إِنَّهَا قَدْ حَاضَتْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَعَلَّهَا حَابِسَتُنَا قَالُوا يَا رَسُولَ اللَّهِ إِنَّهَا قَدْ أَفَاضَتْ فَقَالَ فَلَا إِذًا","id":"Telah menceritakan kepada kami [Al Qa'nabi], dari [Malik] dari [Hisyam bin 'Urwah], dari [ayahnya] dari [Aisyah] bahwa Rasulullah shallallahu 'alaihi wasallam menyebut-nyebut Shafiyah bintu Huyai, kemudian dikatakan kepada beliau; sesungguhnya ia mengalami haid. Lalu beliau berkata: \"Kemungkinan ia akan menahan kita (keluar dari Mekkah).\" Para sahabat berkata; wahai Rasulullah, sesungguhnya ia telah melakukan thawaf ifadhah. Kemudian beliau berkata: \"Jika demikian, ia tidak akan menahan kita.\""},"1648":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَوْنٍ أَخْبَرَنَا أَبُو عَوَانَةَ عَنْ يَعْلَى بْنِ عَطَاءٍ عَنْ الْوَلِيدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ الْحَارِثِ بْنِ عَبْدِ اللَّهِ بْنِ أَوْسٍ قَالَأَتَيْتُ عُمَرَ بْنَ الْخَطَّابِ فَسَأَلْتُهُ عَنْ الْمَرْأَةِ تَطُوفُ بِالْبَيْتِ يَوْمَ النَّحْرِ ثُمَّ تَحِيضُ قَالَ لِيَكُنْ آخِرُ عَهْدِهَا بِالْبَيْتِ قَالَ فَقَالَ الْحَارِثُ كَذَلِكَ أَفْتَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَقَالَ عُمَرُ أَرِبْتَ عَنْ يَدَيْكَ سَأَلْتَنِي عَنْ شَيْءٍ سَأَلْتَ عَنْهُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِكَيْ مَا أُخَالِفَ","id":"Telah menceritakan kepada kami ['Amr bin 'Aun], telah mengabarkan kepada kami [Abu 'Awanah] dari [Ya'la bin 'Atha`] dari [Al Walid bin Abdurrahman] dari [Al Harits bin Abdullah bin Aus], ia berkata; aku pernah mendatangi Umar bin Al Khathab dan bertanya kepadanya mengenai seorang wanita yang melakukan thawaf di Ka'bah pada hari nahr (hari raya kurban), kemudian ia mengalami haid. Umar berkata; hendaknya akhir masanya adalah di Ka'bah. Al Walid berkata; kemudian Al Harits berkata; demikianlah Rasulullah saallallahu 'alaihi wa sallam memberikan fatwa kepadaku. Al Harits berkata; kemudian Umar berkata; Apakah engkau merasa ragu hingga engkau menanyakan kepadaku sesuatu yang engkau tanyakan kepada Rasulullah shallallahu 'alaihi wasallam, agar aku menyelisihi beliau? "},"1649":{"ar":"حَدَّثَنَا وَهْبُ بْنُ بَقِيَّةَ عَنْ خَالِدٍ عَنْ أَفْلَحَ عَنْ الْقَاسِمِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْأَحْرَمْتُ مِنْ التَّنْعِيمِ بِعُمْرَةٍ فَدَخَلْتُ فَقَضَيْتُ عُمْرَتِي وَانْتَظَرَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْأَبْطَحِ حَتَّى فَرَغْتُ وَأَمَرَ النَّاسَ بِالرَّحِيلِ قَالَتْ وَأَتَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْبَيْتَ فَطَافَ بِهِ ثُمَّ خَرَجَ","id":"Telah menceritakan kepada kami [Wahb bin Baqiyyah] dari [Khalid], dari [Aflah] dari [Al Qasim] dari [Aisyah] radliallahu 'anha, ia berkata; aku melakukan umrah dari Tan'im, aku memasukinya dan melakukan umrahku dan Rasulullah shallallahu 'alaihi wasallam menantiku di Al Abthah hingga selesai melakukan umrah, dan beliau memerintahkan orang-orang agar pergi (keluar dari Mekkah). Aisyah berkata; Rasulullah shallallahu 'alaihi wasallam datang ke Ka'bah dan melaksanakan thawaf, kemudian keluar. "},"1650":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو بَكْرٍ يَعْنِي الْحَنَفِيَّ حَدَّثَنَا أَفْلَحُ عَنْ الْقَاسِمِ عَنْ عَائِشَةَ قَالَتْخَرَجْتُ مَعَهُ تَعْنِي مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي النَّفْرِ الْآخِرِ فَنَزَلَ الْمُحَصَّبَ قَالَ أَبُو دَاوُد وَلَمْ يَذْكُرْ ابْنُ بَشَّارٍ قِصَّةَ بَعْثِهَا إِلَى التَّنْعِيمِ فِي هَذَا الْحَدِيثِ قَالَتْ ثُمَّ جِئْتُهُ بِسَحَرٍ فَأَذَّنَ فِي أَصْحَابِهِ بِالرَّحِيلِ فَارْتَحَلَ فَمَرَّ بِالْبَيْتِ قَبْلَ صَلَاةِ الصُّبْحِ فَطَافَ بِهِ حِينَ خَرَجَ ثُمَّ انْصَرَفَ مُتَوَجِّهًا إِلَى الْمَدِينَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar], telah menceritakan kepada kami [Abu Bakr Al Hanafi], telah menceritakan kepada kami [Aflah] dari [Al Qasim] dari [Aisyah], ia berkata; aku keluar bersama Rasulullah shallallahu 'alaihi wasallam pada rombongan yang terakhir, dan beliau singgah di Muhashshab. Abu Daud berkata; Ibnu Basysyar tidak menyebutkan kisah pengiriman Aisyah ke Tan'im dalam hadits ini. Aisyah berkata; kemudian aku datang kepada beliau pada waktu sahur, lalu beliau mengizinkan para sahabatnya untuk berangkat (keluar Mekkah), beliau melewati Ka'bah sebelum shalat Subuh dan melakukan thawaf padanya ketika beliau keluar kemudian pergi menuju Madinah. "},"1651":{"ar":"حَدَّثَنَا يَحْيَى بْنُ مَعِينٍ حَدَّثَنَا هِشَامُ بْنُ يُوسُفَ عَنْ ابْنِ جُرَيْجٍ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ أَبِي يَزِيدَ أَنَّ عَبْدَ الرَّحْمَنِ بْنَ طَارِقٍ أَخْبَرَهُ عَنْ أُمِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا جَازَ مَكَانًا مِنْ دَارِ يَعْلَى نَسِيَهُ عُبَيْدُ اللَّهِ اسْتَقْبَلَ الْبَيْتَ فَدَعَا","id":"Telah menceritakan kepada kami [Yahya bin Ma'in], telah menceritakan kepada kami [Hisyam bin Yusuf] dari [Ibnu Juraij], telah mengabarkan kepadaku ['Ubaidullah bin Abu Yazid] bahwa [Abdurrahman bin Thariq] telah mengabarkan kepadanya dari [ibunya] bahwa Rasulullah shallallahu 'alaihi wasallam apabila melewati suatu tempat di Daru Ya'la -Ubaidullah lupa- beliau menghadap kiblat dan lansung berdo'a. "},"1652":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْإِنَّمَا نَزَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمُحَصَّبَ لِيَكُونَ أَسْمَحَ لِخُرُوجِهِ وَلَيْسَ بِسُنَّةٍ فَمَنْ شَاءَ نَزَلَهُ وَمَنْ شَاءَ لَمْ يَنْزِلْهُ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal], telah menceritakan kepada kami [Yahya bin Sa'id] dari [Hisyam] dari [ayahnya] dari [Aisyah], ia berkata; sesungguhnya Rasulullah shallallahu 'alaihi wasallam singgah di Al Muhashshab agar beliau mudah untuk keluar, hal tersebut bukanlah perkara yang sunnah. Maka barangsiapa yang ingin singgah padanya, ia boleh singgah, dan barangsiapa yang tidak ingin singgah padanya, maka ia boleh tidak singgah. "},"1653":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ وَعُثْمَانُ بْنُ أَبِي شَيْبَةَ الْمَعْنَى ح و حَدَّثَنَا مُسَدَّدٌ قَالُوا حَدَّثَنَا سُفْيَانُ حَدَّثَنَا صَالِحُ بْنُ كَيْسَانَ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ قَالَ قَالَ أَبُو رَافِعٍلَمْ يَأْمُرْنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ أُنْزِلَهُ وَلَكِنْ ضَرَبْتُ قُبَّتَهُ فَنَزَلَهُ قَالَ مُسَدَّدٌ وَكَانَ عَلَى ثَقَلِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ عُثْمَانُ يَعْنِي فِي الْأَبْطَحِ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal], dan [Utsman bin Abu Syaibah] secara makna. Dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Musaddad], mereka berkata; telah menceritakan kepada kami [Sufyan], telah menceritakan kepada kami [Shalih bin Kaisan] dari [Sulaiman bin Yasar], ia berkata; [Abu Rafi'] berkata; Rasulullah shallallahu 'alaihi wasallam tidak memerintahkanku agar mensinggahkan beliau, akan tetapi aku mendirikan tenda beliau, kemudian beliau pun singgah padanya. Musaddad berkata; Abu Rafi' pada saat itu berada di atas hewan yang membawa perbekalan Nabi shallallahu 'alaihi wasallam. Utsman berkata: bahwa itu terjadi di Al Abthah. "},"1654":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عَلِيِّ بْنِ حُسَيْنٍ عَنْ عَمْرِو بْنِ عُثْمَانَ عَنْ أُسَامَةَ بْنِ زَيْدٍ قَالَقُلْتُ يَا رَسُولَ اللَّهِ أَيْنَ تَنْزِلُ غَدًا فِي حَجَّتِهِ قَالَ هَلْ تَرَكَ لَنَا عَقِيْلٌ مَنْزِلًا ثُمَّ قَالَ نَحْنُ نَازِلُونَ بِخَيْفِ بَنِي كِنَانَةَ حَيْثُ قَاسَمَتْ قُرَيْشٌ عَلَى الْكُفْرِ يَعْنِي الْمُحَصَّبَوَذَلِكَ أَنْ بَنِي كِنَانَةَ حَالَفَتْ قُرَيْشًا عَلَى بَنِي هَاشِمٍ أَنْ لَا يُنَاكِحُوهُمْ وَلَا يُبَايِعُوهُمْ وَلَا يُؤْوُوهُمْ قَالَ الزُّهْرِيُّ وَالْخَيْفُ الْوَادِي حَدَّثَنَا مَحْمُودُ بْنُ خَالِدٍ حَدَّثَنَا عُمَرُ حَدَّثَنَا أَبُو عَمْرٍو يَعْنِي الْأَوْزَاعِيَّ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ حِينَ أَرَادَ أَنْ يَنْفِرَ مِنْ مِنًى نَحْنُ نَازِلُونَ غَدًا فَذَكَرَ نَحْوَهُ وَلَمْ يَذْكُرْ أَوَّلَهُ وَلَا ذَكَرَ الْخَيْفَ الْوَادِي","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal], telah menceritakan kepada kami [Abdurrazzaq], telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Ali bin Husain] dari ['Amr bin Utsman], dari [Usamah bin Zaid], ia berkata; aku katakan pada saat beliau melakukan haji; wahai Rasulullah, dimana engaku besok akan singgah? Beliau bertanya: \"Apakah 'Aqil (ibnu Abi Thalib) meninggalkan tempat singgah untuk kita?\" kemudian beliau bersabda: \"Kita akan singgah di lembah (padang) Bani Kinanah yang bernama Al Muhashshab, di tempat itulah orang-orang Quraisy saling bersumpah di atas kekafiran. Yang terjadi adalah bahwa Bani Kinanah bersumpah kepada orang-orang Quraisy atas Bani Hasyim bahwa mereka tidak akan menikahkan mereka, tidak berjual beli dengan mereka, serta tidak melindungi mereka.\" Az Zuhri berkata; Khaif adalah sebuah bukit. Telah menceritakan kepada kami [Mahmud bin Khalid], telah menceritakan kepada kami [Umar], telah menceritakan kepada kami [Abu 'Amr yaitu Al Auza'i] dari [Az Zuhri] dari [Abu Salamah] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda ketika hendak kembali dari Mina: \"Kita akan singgah besok….\" Kemudian ia menyebutkan permulaannya dan tidak menyebutkan Lembah Khaif. "},"1655":{"ar":"حَدَّثَنَا مُوسَى أَبُو سَلَمَةَ حَدَّثَنَا حَمَّادٌ عَنْ حُمَيْدٍ عَنْ بَكْرِ بْنِ عَبْدِ اللَّهِ وَأَيُّوبَ عَنْ نَافِعٍأَنَّ ابْنَ عُمَرَ كَانَ يَهْجَعُ هَجْعَةً بِالْبَطْحَاءِ ثُمَّ يَدْخُلُ مَكَّةَ وَيَزْعُمُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَفْعَلُ ذَلِكَ","id":"Telah menceritakan kepada kami [Musa Abu Salamah], telah menceritakan kepada kami [Hammad] dari [Humaid], dari [Bakr bin Abdullah] serta [Ayyub] dari [Nafi'] bahwa [Ibnu Umar] tidur di Al Bathha`, kemudian masuk ke Mekkah dan mengaku bahwa Rasulullah shallallahu 'alaihi wasallam melakukan hal tersebut. "},"1656":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ أَخْبَرَنَا حُمَيْدٌ عَنْ بَكْرِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عُمَرَ وَأَيُّوبُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى الظُّهْرَ وَالْعَصْرَ وَالْمَغْرِبَ وَالْعِشَاءَ بِالْبَطْحَاءِ ثُمَّ هَجَعَ بِهَا هَجْعَةً ثُمَّ دَخَلَ مَكَّةَوَكَانَ ابْنُ عُمَرَ يَفْعَلُهُ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal], telah menceritakan kepada kami ['Affan], telah menceritakan kepada kami [Hammad bin Salamah], telah mengabarkan kepada kami [Humaid] dari [Bakr bin Abdullah] dari [Ibnu Umar] dan [Ayyub], dari [Nafi'] bahwa Nabi shallallahu 'alaihi wasallam melakukan Shalat Zhuhur dan 'Ashar, Maghrib serta Isya` di Al Bathha` lalu tidur di sana kemudian masuk ke Mekkah, dan Ibnu Umar melakukan hal tersebut. "},"1657":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ عِيسَى بْنِ طَلْحَةَ بْنِ عُبَيْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ الْعَاصِ أَنَّهُ قَالَوَقَفَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَجَّةِ الْوَدَاعِ بِمِنًى يَسْأَلُونَهُ فَجَاءَهُ رَجُلٌ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي لَمْ أَشْعُرْ فَحَلَقْتُ قَبْلَ أَنْ أَذْبَحَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اذْبَحْ وَلَا حَرَجَ وَجَاءَ رَجُلٌ آخَرُ فَقَالَ يَا رَسُولَ اللَّهِ لَمْ أَشْعُرْ فَنَحَرْتُ قَبْلَ أَنْ أَرْمِيَ قَالَ ارْمِ وَلَا حَرَجَ قَالَ فَمَا سُئِلَ يَوْمَئِذٍ عَنْ شَيْءٍ قُدِّمَ أَوْ أُخِّرَ إِلَّا قَالَ اصْنَعْ وَلَا حَرَجَ","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Ibnu Syihab] dari [Isa bin Thalhah bin 'Ubaidullah] dari [Abdullah bin 'Amr bin Al 'Ash] bahwa ia berkata; Rasulullah shallallahu 'alaihi wasallam berdiri pada waktu haji wada' di Mina, mereka bertanya kepada beliau, kemudian seorang laki-laki datang dan berkata; wahai Rasulullah, sesungguhnya aku tidak mengetahui, sehingga aku menyembelih sebelum melempar jumrah. Beliau berkata: \"Lemparlah, tidak mengapa!\" Abdullah bin 'Amr berkata; tidaklah beliau pada saat itu ditanya mengenai sesuatu yang didahulukan atau diakhirkan melainkan beliau mengatakan: \"Lakukanlah, tidak mengapa!\""},"1658":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ الشَّيْبَانِيِّ عَنْ زِيَادِ بْنِ عِلَاقَةَ عَنْ أُسَامَةَ بْنِ شَرِيكٍ قَالَخَرَجْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَاجًّا فَكَانَ النَّاسُ يَأْتُونَهُ فَمَنْ قَالَ يَا رَسُولَ اللَّهِ سَعَيْتُ قَبْلَ أَنْ أَطُوفَ أَوْ قَدَّمْتُ شَيْئًا أَوْ أَخَّرْتُ شَيْئًا فَكَانَ يَقُولُ لَا حَرَجَ لَا حَرَجَ إِلَّا عَلَى رَجُلٍ اقْتَرَضَ عِرْضَ رَجُلٍ مُسْلِمٍ وَهُوَ ظَالِمٌ فَذَلِكَ الَّذِي حَرِجَ وَهَلَكَ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah], telah menceritakan kepada kami [Jarir] dari [Asy Syaibani] dari [Ziyad bin 'Ilaqah] dari [Usamah bin Syarik], ia berkata; aku keluar bersama Nabi shallallahu 'alaihi wasallam untuk melakukan haji. Dan orang-orang datang kepada beliau, maka ada yang mengatakan; wahai Rasulullah, aku telah melakukan sa'i sebelum melakukan thawaf. Atau aku telah mendahulukan sesuatu dan mengakhirkan sesuatu. Dan beliau mengatakan: \"Tidak mengapa, tidak mengapa.\" Kecuali terhadap seseorang yang telah mencoreng kehormatan seorang muslim dan ia berbuat kedzaliman, maka itulah orang yang berdosa lagi binasa. "},"1659":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ حَدَّثَنِي كَثِيرُ بْنُ كَثِيرِ بْنِ الْمُطَّلِبِ بْنِ أَبِي وِدَاعَةَ عَنْ بَعْضِ أَهْلِهِ عَنْ جَدِّهِأَنَّهُ رَأَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي مِمَّا يَلِي بَابَ بَنِي سَهْمٍ وَالنَّاسُ يَمُرُّونَ بَيْنَ يَدَيْهِ وَلَيْسَ بَيْنَهُمَا سُتْرَةٌ قَالَ سُفْيَانُ لَيْسَ بَيْنَهُ وَبَيْنَ الْكَعْبَةِ سُتْرَةٌقَالَ سُفْيَانُ كَانَ ابْنُ جُرَيْجٍ أَخْبَرَنَا عَنْهُ قَالَ أَخْبَرَنَا كُثَيْرٌ عَنْ أَبِيهِ قَالَ فَسَأَلْتُهُ فَقَالَ لَيْسَ مِنْ أَبِي سَمِعْتُهُ وَلَكِنْ مِنْ بَعْضِ أَهْلِي عَنْ جَدِّي","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal], telah menceritakan kepada kami [Sufyan bin 'Uyainah], telah menceritakan kepadaku [Katsir bin Katsir bin Al Muththalib bin Abu Wida'ah] dari [sebagian keluarganya], dari [Kakeknya], bahwa ia telah melihat Nabi shallallahu 'alaihi wasallam melakukan shalat di tempat yang terletak setelah pintu Bani Sahm, sementara orang-orang lewat di hadapannya, dan tidak ada sutrah (pembatas shalat) antara keduanya. Sufyan berkata; tidak ada sutrah antara beliau dan Ka'bah. Sufyan berkata; [Ibnu Juraij] telah mengabarkan kepada kami mengenai hal tersebut. Ia berkata; telah mengabarkan kepada kami [Kutsair] dari [ayahnya], ia berkata; aku bertanya kepadanya kemudian ia berkata; bukan dari ayahku aku mendengarnya, akan tetapi dari sebagian keluargaku, dari kakekku. "},"1660":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنِي يَحْيَى يَعْنِي ابْنَ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَلَمَّا فَتَحَ اللَّهُ تَعَالَى عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَكَّةَ قَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيهِمْ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ ثُمَّ قَالَ إِنَّ اللَّهَ حَبَسَ عَنْ مَكَّةَ الْفِيلَ وَسَلَّطَ عَلَيْهَا رَسُولَهُ وَالْمُؤْمِنِينَ وَإِنَّمَا أُحِلَّتْ لِي سَاعَةً مِنْ النَّهَارِ ثُمَّ هِيَ حَرَامٌ إِلَى يَوْمِ الْقِيَامَةِ لَا يُعْضَدُ شَجَرُهَا وَلَا يُنَفَّرُ صَيْدُهَا وَلَا تَحِلُّ لُقْطَتُهَا إِلَّا لِمُنْشِدٍ فَقَالَ عَبَّاسٌ أَوْ قَالَ قَالَ الْعَبَّاسُ يَا رَسُولَ اللَّهِ إِلَّا الْإِذْخِرَ فَإِنَّهُ لِقُبُورِنَا وَبُيُوتِنَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا الْإِذْخِرَقَالَ أَبُو دَاوُد وَزَادَنَا فِيهِ ابْنُ الْمُصَفَّى عَنْ الْوَلِيدِ فَقَامَ أَبُو شَاهٍ رَجُلٌ مِنْ أَهْلِ الْيَمَنِ فَقَالَ يَا رَسُولَ اللَّهِ اكْتُبُوا لِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اكْتُبُوا لِأَبِي شَاهٍ قُلْتُ لِلْأَوْزَاعِيِّ مَا قَوْلُهُ اكْتُبُوا لِأَبِي شَاهٍ قَالَ هَذِهِ الْخُطْبَةُ الَّتِي سَمِعَهَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ مُجَاهِدٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ فِي هَذِهِ الْقِصَّةِ قَالَ وَلَا يُخْتَلَى خَلَاهَا","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal], telah menceritakan kepada kami [Al Walid bin Muslim], telah menceritakan kepada kami [Al Auza'i], telah menceritakan kepadaku [Yahya bin Abu Katsir] dari [Abu Salamah], dari [Abu Hurairah], ia berkata; tatkala Allah Ta'ala menaklukkan Mekkah melalui Rasulullah shallallahu 'alaihi wasallam, beliau berdiri diantara mereka lalu memuji Allah kemudian berkata: \"Sesungguhnya Allah telah menahan gajah dari Ka'bah, dan Allah menguasakan Ka'bah kepada rasulNya serta orang-orang mukmin. Sesungguhnya hal itu dihalalkan bagiku sesaat pada waktu siang, kemudian haram hingga hari Kiamat, tidak boleh pohonnya ditebang, tidak boleh hewan buruannya diusir, dan tidak halal barang temuannya kecuali bagi orang yang hendak mengumumkan.\" Kemudian Abbas berkata; wahai Rasulullah, kecuali idzkhir, karena tanaman tersebut untuk kuburan dan rumah kami. Kemudian Rasulullah shallallahu 'alaihi wasallam berkata: \"Kecuali idzkhir.\" Abu Daud berkata; dan [Ibnu Al Mushthafa] menambahkan padanya dari [Al Walid]; kemudian Abu Syah yaitu seorang laki-laki dari penduduk Yaman berdiri dan berkata; wahai Rasulullah, tuliskan untukku! Kemudian Rasulullah shallallahu 'alaihi wasallam berkata: \"Tuliskan untuk Abu Syah!\" Aku katakan kepada Al Auza'i; apakah ucapan Rasulullah shallallahu 'alaihi wasallam: \"Tuliskan untuk Abu Syah!\" Ia berkata; khutbah yang ia dengar dari Rasulullah shallallahu 'alaihi wasallam. Telah menceritakan kepada kami [Utsman bin Abu Syaibah], telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Mujahid] dari [Thawus] dari [Ibnu Abbas] mengenai kisah ini, ia berkata; dan tidak boleh dipotong tanamannya. "},"1661":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا إِسْرَائِيلُ عَنْ إِبْرَاهِيمَ بْنِ مُهَاجِرٍ عَنْ يُوسُفَ بْنِ مَاهَكَ عَنْ أُمِّهِ عَنْ عَائِشَةَ قَالَتْقُلْتُ يَا رَسُولَ اللَّهِ أَلَا نَبْنِي لَكَ بِمِنًى بَيْتًا أَوْ بِنَاءً يُظِلُّكَ مِنْ الشَّمْسِ فَقَالَ لَا إِنَّمَا هُوَ مُنَاخُ مَنْ سَبَقَ إِلَيْهِ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal], telah menceritakan kepada kami [Abdurrahman bin Mahdi], telah menceritakan kepada kami [Israil] dari [Ibrahim bin Muhajir] dari [Yusuf bin Mahik] dari [ibunya] dari [Aisyah], ia berkata; aku katakan; wahai Rasulullah, tidakkah kami bangun untukmu sebuah rumah atau bangunan yang dapat menaungimu dari matahari di Mina? Kemudian beliau berkata; sesungguhnya Mina adalah tempat berhenti bagi orang yang datang lebih dahulu. "},"1662":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا أَبُو عَاصِمٍ عَنْ جَعْفَرِ بْنِ يَحْيَى بْنِ ثَوْبَانَ أَخْبَرَنِي عِمَارَةُ بْنُ ثَوْبَانَ حَدَّثَنِي مُوسَى بْنُ بَاذَانَ قَالَأَتَيْتُ يَعْلَى بْنَ أُمَيَّةَ فَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ احْتِكَارُ الطَّعَامِ فِي الْحَرَمِ إِلْحَادٌ فِيهِ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali], telah menceritakan kepada kami [Abu 'Ashim] dari [Ja'far bin Yahya bin Tsauban], telah mengabarkan kepada kami ['Imarah bin Tsauban], telah menceritakan kepadaku [Musa bin Badzan]; ia berkata; aku telah mendatangi [Ya'la bin Umayyah] dan dia berkata; sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Penimbunan makanan di tanah Haram merupakan perbuatan kufur yang dilakukan di dalamnya. "},"1663":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَوْنٍ حَدَّثَنَا خَالِدٌ عَنْ حُمَيْدٍ عَنْ بَكْرِ بْنِ عَبْدِ اللَّهِ قَالَقَالَ رَجُلٌ لِابْنِ عَبَّاسٍ مَا بَالُ أَهْلِ هَذَا الْبَيْتِ يَسْقُونَ النَّبِيذَ وَبَنُو عَمِّهِمْ يَسْقُونَ اللَّبَنَ وَالْعَسَلَ وَالسَّوِيقَ أَبُخْلٌ بِهِمْ أَمْ حَاجَةٌ فَقَالَ ابْنُ عَبَّاسٍ مَا بِنَا مِنْ بُخْلٍ وَلَا بِنَا مِنْ حَاجَةٍ وَلَكِنْ دَخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى رَاحِلَتِهِ وَخَلْفَهُ أُسَامَةُ بْنُ زَيْدٍ فَدَعَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِشَرَابٍ فَأُتِيَ بِنَبِيذٍ فَشَرِبَ مِنْهُ وَدَفَعَ فَضْلَهُ إِلَى أُسَامَةَ بْنِ زَيْدٍ فَشَرِبَ مِنْهُ ثُمَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحْسَنْتُمْ وَأَجْمَلْتُمْ كَذَلِكَ فَافْعَلُوا فَنَحْنُ هَكَذَا لَا نُرِيدُ أَنْ نُغَيِّرَ مَا قَالَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami ['Amr bin 'Aun], telah menceritakan kepada kami [Khalid] dari [Humaid] dari [Bakr bin Abdullah], ia berkata; seorang laki-laki berkata kepada [Ibnu Abbas]; kenapa penghuni rumah ini memberi minum nabidz (minuman rendaman kurma, anggur atau yang lainnya), sementara anak-anak paman mereka minum susu, madu dan sawiq (makanan yang terbuat dari gandum dicampur dengan mentega)? Apakah ada sifat kikir pada mereka atau sebuah kebutuhan? Ibnu Abbas berkata; kami tidak kikir, dan kami tidak butuh, akan tetapi Rasulullah shallallahu 'alaihi wasallam pernah berada di atas kendaraannya dan dibelangnya Usamah bin Zaid. Kemudian beliau meminta minum, lalu beliau diberi nabidz lalu beliau minum sebagian darinya dan memberikan sisanya kepada Usamah bin Zaid, dan ia pun minum sebagian darinya. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kalian telah bertindak baik, memang demikian yang sepatutnya kalian lakukan.\" Maka, kami seperti demikian dan tidak ingin mengubah apa yang Rasulullah shallallahu 'alaihi wasallam katakan. "},"1664":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ حَدَّثَنَا عَبْدُ الْعَزِيزِ يَعْنِي الدَّرَاوَرْدِيَّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ حُمَيْدٍأَنَّهُ سَمِعَ عُمَرَ بْنَ عَبْدِ الْعَزِيزِ يَسْأَلُ السَّائِبَ بْنَ يَزِيدَ هَلْ سَمِعْتَ فِي الْإِقَامَةِ بِمَكَّةَ شَيْئًا قَالَ أَخْبَرَنِي ابْنُ الْحَضْرَمِيِّ أَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لِلْمُهَاجِرِينَ إِقَامَةٌ بَعْدَ الصَّدْرِ ثَلَاثًا","id":"Telah menceritakan kepada kami [Al Qa'nabi], telah menceritakan kepada kami [Abdul Aziz Ad Darawardi], dari [Abdurrahman bin Humaid] bahwa ia mendengar Umar bin Abdul Aziz bertanya kepada [As Saib bin Yazid]; apakah engkau pernah mendengar sesuatu mengenai bermukim di Mekkah? Ia berkata; telah mengabarkan kepadaku [Ibnu Al Hadhrami], bahwa ia mendengar Rasulullah shallallahu 'alaihi wasallam berkata kepada orang-orang muhajirin: \"(Lama) bermukim (di Mekkah) setelah menunaikan ibadah haji adalah tiga hari.\""},"1665":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ الْكَعْبَةَ هُوَ وَأُسَامَةُ بْنُ زَيْدٍ وَعُثْمَانُ بْنُ طَلْحَةَ الْحَجَبِيُّ وَبِلَالٌ فَأَغْلَقَهَا عَلَيْهِ فَمَكَثَ فِيهَا قَالَ عَبْدُ اللَّهِ بْنُ عُمَرَ فَسَأَلْتُ بِلَالًا حِينَ خَرَجَ مَاذَا صَنَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ جَعَلَ عَمُودًا عَنْ يَسَارِهِ وَعَمُودَيْنِ عَنْ يَمِينِهِ وَثَلَاثَةَ أَعْمِدَةٍ وَرَاءَهُ وَكَانَ الْبَيْتُ يَوْمَئِذٍ عَلَى سِتَّةِ أَعْمِدَةٍ ثُمَّ صَلَّىحَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ إِسْحَقَ الْأَذْرَمِيُّ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ مَالِكٍ بِهَذَا الْحَدِيثِ لَمْ يَذْكُرْ السَّوَارِيَ قَالَ ثُمَّ صَلَّى وَبَيْنَهُ وَبَيْنَ الْقِبْلَةِ ثَلَاثَةُ أَذْرُعٍ حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَعْنَى حَدِيثِ الْقَعْنَبِيِّ قَالَ وَنَسِيتُ أَنْ أَسْأَلَ��ُ كَمْ صَلَّى","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Nafi'] dari [Abdullah bin Umar] bahwa Rasulullah shallallahu 'alaihi wasallam memasuki mekkah bersama Usamah bin Zaid dan Utsman bin Thalhah Al Hajabi, dan Bilal, kemudian beliau menutup pintunya dan tingggal di dalamnya. Abdullah bin Umar berkata; aku bertanya kepada [Bilal] ketika ia keluar; apa yang Rasulullah shallallahu 'alaihi wasallam lakukan? Ia berkata; beliau menjadikan satu tiang berada di sebelah kirinya dan dua tiang berada di sebelah kanannya, serta tiga tiang berada di belakang beliau. Ka'bah pada saat itu memiliki enam tiang, kemudian beliau melakukan shalat. Telah menceritakan kepada kami [Abdullah bin Muhammad bin Ishaq Al Adzrami], telah menceritakan kepada kami [Abdurrahman bin Mahdi] dari [Malik] dengan hadits ini, ia tidak menyebutkan beberapa tiang. Ia mengatakan; kemudian beliau melakukan shalat diantara beliau dan kiblat berjarak tiga hasta. Telah menceritakan kepada kami [Utsman bin Abu Syaibah], telah menceritakan kepada kami [Abu Usamah] dari ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam seperti makna hadits Al Qa'nabi, dan aku lupa bertanya kepadanya; berapa raka'at beliau melakukan shalat? "},"1666":{"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا جَرِيرٌ عَنْ يَزِيدَ بْنِ أَبِي زِيَادٍ عَنْ مُجَاهِدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ صَفْوَانَ قَالَقُلْتُ لِعُمَرَ بْنِ الْخَطَّابِ كَيْفَ صَنَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ دَخَلَ الْكَعْبَةَ قَالَ صَلَّى رَكْعَتَيْنِ","id":"Telah menceritakan kepada kami [Zuhair bin Harb], telah menceritakan kepada kami [Jarir] dari [Yazid bin Abu Ziyad] dari [Mujahid] dari [Abdurrahman bin Shafwan], ia berkata; aku katakan kepada [Umar bin Al Khathab]; apa yang dilakukan Rasulullah shallallahu 'alaihi wasallam ketika masuk ke ka'bah? Dia menjawab; beliau melakukan shalat dua rakaat. "},"1667":{"ar":"حَدَّثَنَا أَبُو مَعْمَرٍ عَبْدُ اللَّهِ بْنُ عَمْرِو بْنِ أَبِي الْحَجَّاجِ حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ أَيُّوبَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمَّا قَدِمَ مَكَّةَ أَبَى أَنْ يَدْخُلَ الْبَيْتَ وَفِيهِ الْآلِهَةُ فَأَمَرَ بِهَا فَأُخْرِجَتْ قَالَ فَأُخْرِجَ صُورَةُ إِبْرَاهِيمَ وَإِسْمَعِيلَ وَفِي أَيْدِيهِمَا الْأَزْلَامُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَاتَلَهُمْ اللَّهُ وَاللَّهِ لَقَدْ عَلِمُوا مَا اسْتَقْسَمَا بِهَا قَطُّ قَالَ ثُمَّ دَخَلَ الْبَيْتَ فَكَبَّرَ فِي نَوَاحِيهِ وَفِي زَوَايَاهُ ثُمَّ خَرَجَ وَلَمْ يُصَلِّ فِيهِ","id":"Telah menceritakan kepada kami [Abu Ma'mar Abdullah bin 'Amr bin Abu Al Hajjaj], telah menceritakan kepada kami [Abdul Warits] dari [Ayyub] dari [Ikrimah] dari [Ibnu Abbas] bahwa Nabi Shallallahu 'alaihi sallam tatkala tiba di Mekkah, beliau menolak untuk masuk ke Ka'bah selama di dalamnya masih terdapat patung-patung yang disembah, maka beliau memerintahkan untuk mengeluarkan patung-patung tersebut, maka dikeluarkanlah patung-patung tersebut. Ibnu Abbas berkata; kemudian dikeluarkanlah patung berbentuk Nabi Ibrahim dan Ismail yang di tangan kedua patung tersebut terdapat anak-anak panah. Kemudian Rasulullah shlallallahu 'alaihi wa sallam berkata; semoga Allah memerangi mereka (orang musyrikin)! Demi Allah, sesungguhnya mereka (orang-orang musyrik) mengetahui bahwasanya mereka berdua tidak pernah mengundi nasib dengannya. Kemudian beliau masuk ke dalam ka'bah dan mengucapkan takbir pada penjuru-penjuru serta pojok-pojoknya, kemudian beliau keluar dan melakukan shalat di luar Ka'bah. "},"1668":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ حَدَّثَنَا عَبْدُ الْعَزِيزِ عَنْ عَلْقَمَةَ عَنْ أُمِّهِ عَنْ عَائِشَةَ أَنَّهَا قَالَتْكُنْتُ أُحِبُّ أَنْ أَدْخُلَ الْبَيْتَ فَأُصَلِّيَ فِيهِ فَأَخَذَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَدِي فَأَدْخَلَنِي فِي الْحِجْرِ فَقَالَ صَلِّي فِي الْحِجْرِ إِذَا أَرَدْتِ دُخُولَ الْبَيْتِ فَإِنَّمَا هُوَ قَطْعَةٌ مِنْ الْبَيْتِ فَإِنَّ قَوْمَكِ اقْتَصَرُوا حِينَ بَنَوْا الْكَعْبَةَ فَأَخْرَجُوهُ مِنْ الْبَيْتِ","id":"Telah menceritakan kepada kami [Al Qa'nabi], telah menceritakan kepada kami [Abdul Aziz] dari ['Alqamah] dari [ibunya] dari [Aisyah], ia berkata; aku ingin memasuki Ka'bah dan melakukan shalat di dalamnya. Kemudian Rasulullah shallallahu 'alaihi wasallam menggandeng tanganku dan memasukkanku ke dalam Hijr, dan beliau berkata: \"Apabila engkau hendak memasuki Ka'bah, sesungguhnya Hijr tersebut merupakan bagian dari Ka'bah. Sesungguhnya kaummu menguranginya ketika membangun Ka'bah, dan mengeluarkan Hijr dari Ka'bah.\""},"1669":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ دَاوُدَ عَنْ إِسْمَعِيلَ بْنِ عَبْدِ الْمَلِكِ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي مُلَيْكَةَ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ مِنْ عِنْدِهَا وَهُوَ مَسْرُورٌ ثُمَّ رَجَعَ إِلَيَّ وَهُوَ كَئِيبٌ فَقَالَ إِنِّي دَخَلْتُ الْكَعْبَةَ وَلَوْ اسْتَقْبَلْتُ مِنْ أَمْرِي مَا اسْتَدْبَرْتُ مَا دَخَلْتُهَا إِنِّي أَخَافُ أَنْ أَكُونَ قَدْ شَقَقْتُ عَلَى أُمَّتِي","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Abdullah bin Daud], dari [Isma'il bin Abdul Malik] dari [Abdullah bin Abu Mulaikah] dari [Aisyah] bahwa Nabi Shallallahu 'alaihi sallam keluar dari sisinya dalam keadaan senang kemudian kembali kepadaku dalam keadaan sedih, lalu berkata: aku masuk ke dalam Ka'bah, sekiranya aku telah mengetahui (mendapatkan petunjuk) apa yang aku lakukan sekarang, maka aku tidak akan memasukinya, sebab aku khawatir akan menyusahkan umatku. "},"1670":{"ar":"حَدَّثَنَا ابْنُ السَّرْحِ وَسَعِيدُ بْنُ مَنْصُورٍ وَمُسَدَّدٌ قَالُوا حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ الْحَجَبِيِّ حَدَّثَنِي خَالِي عَنْ أُمِّي صَفِيَّةَ بِنْتِ شَيْبَةَ قَالَتْ سَمِعْتُ الَأسْلَمِيَّةَ تَقُولُقُلْتُ لِعُثْمَانَ مَا قَالَ لَكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ دَعَاكَ قَالَ قَالَ إِنِّي نَسِيتُ أَنْ آمُرَكَ أَنْ تُخَمِّرَ الْقَرْنَيْنِ فَإِنَّهُ لَيْسَ يَنْبَغِي أَنْ يَكُونَ فِي الْبَيْتِ شَيْءٌ يَشْغَلُ الْمُصَلِّيَ قَالَ ابْنُ السَّرْحِ خَالِي مُسَافِعُ بْنُ شَيْبَةَ","id":"Telah menceritakan kepada kami [Ibnu As Sarh] dan [Sa'id bin Manshur] serta [Musaddad], mereka berkata; telah menceritakan kepada kami [Sufyan] dari [Manshur Al Hajabi], telah menceritakan kepadaku [pamanku], dari [ibuku yaitu Shafiyyah binti Syaibah], ia berkata; aku mendengar [Al Aslamiyyah] berkata; aku katakan kepada [Utsman]; apa yang Rasulullah shallallahu 'alaihi wasallam katakan kepadamu ketika beliau memanggilmu? Ia berkata; aku lupa untuk memerintahkanmu agar menutupi dua tanduk (kambing), sesungguhnya tidak selayaknya di Ka'bah terdapat sesuatu yang menyibukkan orang yang melakukan shalat. Ibnu As Sarh berkata; pamanku adalah Musafi' bin Syaibah. "},"1671":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مُحَمَّدٍ الْمُحَارِبِيُّ عَنْ الشَّيْبَانِيِّ عَنْ وَاصِلٍ الْأَحْدَبِ عَنْ شَقِيقٍ عَنْ شَيْبَةَ يَعْنِي ابْنَ عُثْمَانَ قَالَقَعَدَ عُمَرُ بْنُ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ فِي مَقْعَدِكَ الَّذِي أَنْتَ فِيهِ فَقَالَ لَا أَخْرُجُ حَتَّى أَقْسِمَ مَالَ الْكَعْبَةِ قَالَ قُلْتُ مَا أَنْتَ بِفَاعِلٍ قَالَ بَلَى لَأَفْعَلَنَّ قَالَ قُلْتُ مَا أَنْتَ بِفَاعِلٍ قَالَ لِمَ قُلْتُ لِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ رَأَى مَكَانَهُ وَأَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ وَهُمَا أَحْوَجُ مِنْكَ إِلَى الْمَالِ فَلَمْ يُخْرِجَاهُ فَقَامَ فَخَرَجَ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal], telah menceritakan kepada kami [Abdurrahman bin Muhammad Al Muharibi], dari [Asy Syaibani] dari [Washil Al Ahdab] dari [Syaqiq] dari [Syaibah bin Utsman], ia berkata; [Umar bin Al Khathab] radliallahu 'anhu pernah duduk ditempat yang engkau duduki, lalu ia berkata; aku tidak akan keluar hingga membagikan harta Ka'bah. Syaibah berkata; aku katakan; engkau tidak akan melakukannya. Ia berkata; benar, sungguh aku akan melakukannya. Syaibah berkata; engkau tidak akan melakukannya. Ia berkata; kenapa? Aku katakan; karena Rasulullah shallallahu 'alaihi wasallam telah melihat tempatnya, begitu juga Abu Bakr radliallahu 'anhu, dan mereka berdua lebih membutuhkan harta tersebut daripada dirimu, namun mereka berdua tidak mengeluarkan harta tersebut. Kemudian ia berdiri lalu keluar. "},"1672":{"ar":"حَدَّثَنَا حَامِدُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْحَارِثِ عَنْ مُحَمَّدِ بْنِ عَبْدِ اللَّهِ بْنِ إِنْسَانٍ الطَّائِفِيِّ عَنْ أَبِيهِ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ الزُّبَيْرِ قَالَلَمَّا أَقْبَلْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ لِيَّةَ حَتَّى إِذَا كُنَّا عِنْدَ السِّدْرَةِ وَقَفَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي طَرَفِ الْقَرْنِ الْأَسْوَدِ حَذْوَهَا فَاسْتَقْبَلَ نَخِبًا بِبَصَرِهِ و قَالَ مَرَّةً وَادِيَهُ وَوَقَفَ حَتَّى اتَّقَفَ النَّاسُ كُلُّهُمْ ثُمَّ قَالَ إِنَّ صَيْدَ وَجٍّ وَعِضَاهَهُ حَرَامٌ مُحَرَّمٌ لِلَّهِ وَذَلِكَ قَبْلَ نُزُولِهِ الطَّائِفَ وَحِصَارِهِ لِثَقِيفٍ","id":"Telah menceritakan kepada kami [Hamid bin Yahya], telah menceritakan kepada kami [Abdullah bin Al Harits] dari [Muhammad bin Abdullah bin Insan Ath Thai] dari [ayahnya] dari ['Urwah bin Az Zubair] dari [Az Zubair], ia berkata; tatkala kami bersama Rasulullah shallallahu 'alaihi wasallam datang dari Liyyah (gunung dekat dengan Thaif), hingga setelah kami sampai pada sebuah pohon bidara Rasulullah shallallahu 'alaihi wasallam berdiri pada pinggir Al Qarn Al Aswad (gunung kecil di Hijaz dekat dengan Thaif) sejajar dengannya, beliau menghadap ke arah Nakhib (bukit di Thaif) dengan pandangan beliau. Terkadang Az Zubair berkata; bukitnya. Beliau berdiri hingga seluruh orang berdiri, kemudian beliau bersabda: \"Sesungguhnya hewan buruan di Wajj (bukit di Thaif) serta pohon-pohonnya yang berduri adalah haram dan diharamkan oleh Allah.\" Dan hal tersebut terjadi sebelum beliau singgah dan mengepung Tsaqif. "},"1673":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيِّبِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تُشَدُّ الرِّحَالُ إِلَّا إِلَى ثَلَاثَةِ مَسَاجِدَ مَسْجِدِ الْحَرَامِ وَمَسْجِدِي هَذَا وَالْمَسْجِدِ الْأَقْصَى","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Sa'id bin Al Musayyab] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak boleh diniatkan melakukan perjalanan dengan tujuan beribadah padanya kecuali ke tiga masjid, yaitu; Masjid Al Haram, Masjidku ini dan Masjid Al Aqsha.\""},"1674":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ التَّيْمِيِّ عَنْ أَبِيهِ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَمَا كَتَبْنَا عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا الْقُرْآنَ وَمَا فِي هَذِهِ الصَّحِيفَةِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَدِينَةُ حَرَامٌ مَا بَيْنَ عَائِرَ إِلَى ثَوْرٍ فَمَنْ أَحْدَثَ حَدَثًا أَوْ آوَى مُحْدِثًا فَعَلَيْهِ لَعْنَةُ اللَّهِ وَالْمَلَائِكَةِ وَالنَّاسِ أَجْمَعِينَ لَا يُقْبَلُ مِنْهُ عَدْلٌ وَلَا صَرْفٌ وَذِمَّةُ الْمُسْلِمِينَ وَاحِدَةٌ يَسْعَى بِهَا أَدْنَاهُمْ فَمَنْ أَخْفَرَ مُسْلِمًا فَعَلَيْهِ لَعْنَةُ اللَّهِ وَالْمَلَائِكَةِ وَالنَّاسِ أَجْمَعِينَ لَا يُقْبَلُ مِنْهُ عَدْلٌ وَلَا صَرْفٌ وَمَنْ وَالَى قَوْمًا بِغَيْرِ إِذْنِ مَوَالِيهِ فَعَلَيْهِ لَعْنَةُ اللَّهِ وَالْمَلَائِكَةِ وَالنَّاسِ أَجْمَعِينَ لَا يُقْبَلُ مِنْهُ عَدْلٌ وَلَا صَرْفٌحَدَّثَنَا ابْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ عَنْ أَبِي حَسَّانَ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ فِي هَذِهِ الْقِصَّةِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يُخْتَلَى خَلَاهَا وَلَا يُنَفَّرُ صَيْدُهَا وَلَا تُلْتَقَطُ لُقَطَتُهَا إِلَّا لِمَنْ أَشَادَ بِهَا وَلَا يَصْلُحُ لِرَجُلٍ أَنْ يَحْمِلَ فِيهَا السِّلَاحَ لِقِتَالٍ وَلَا يَصْلُحُ أَنْ يُقْطَعَ مِنْهَا شَجَرَةٌ إِلَّا أَنْ يَعْلِفَ رَجُلٌ بَعِيرَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir], telah mengabarkan kepada kami [Sufyan] dari [Al A'masy] dari [Ibrahim At Taimi] dari [ayahnya] dari [Ali] radliallahu 'anhu, ia berkata; kami tidak mencatat dari Rasulullah shallallahu 'alaihi wasallam kecuali Al Qur'an, dan apa yang ada dalam lembaran ini. Ali berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Madinah adalah haram antara 'Air hingga Tsaur (keduanya adalah nama gunung di Madinah). Barangsiapa yang melakukan perkara dosa atau melindungi orang yang berbuat kejahatan maka baginya laknat Allah, para malaikat serta seluruh manusia, tidak diterima darinya amalan wajib dan yang sunnah. Perlindungan orang muslim adalah satu, orang yang paling rendah dapat memberikannya. Barangsiapa yang membatalkan perjanjian dan keamanan seorang muslim maka baginya laknat Allah, para malaikat serta seluruh manusia, tidak diterima darinya amalan wajib dan yang sunnah. Telah menceritakan kepada kami [Ibnu Al Mutsanna], telah menceritakan kepada kami [Abdushshamad], telah menceritakan kepada kami [Hammam], telah menceritakan kepada kami [Qatadah], dari [Abu Hassan] dari [Ali] radliallahu 'anhu dalam kisah ini dari Nabi shallallahu 'alaihi wasallam, beliau berkata: \"Tidak boleh dipotong tanamannya, tidak boleh di usir hewan buruannya dan tidak boleh diambil barang temuannya, kecuali bagi orang yang mengumumkannya, dan tidak selayaknya bagi seseorang di tempat tersebut membawa senjata untuk berperang dan tidak selayaknya ada sebuah pohon yang ditebang keculai seseorang yang hendak memberi makan untanya.\""},"1675":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ أَنَّ زَيْدَ بْنَ الْحُبَابِ حَدَّثَهُمْ حَدَّثَنَا سُلَيْمَانُ بْنُ كِنَانَةَ مَوْلَى عُثْمَانَ بْنِ عَفَّانَ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ أَبِي سُفْيَانَ عَنْ عَدِيِّ بْنِ زَيْدٍ قَالَحَمَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلَّ نَاحِيَةٍ مِنْ الْمَدِينَةِ بَرِيدًا بَرِيدًا لَا يُخْبَطُ شَجَرُهُ وَلَا يُعْضَدُ إِلَّا مَا يُسَاقُ بِهِ الْجَمَلُ","id":"Telah menceritakan kepada kami [Muhammad bin Al 'Ala`] bahwa [Zaid bin Al Hubab], telah menceritakan kepada mereka; telah menceritakan kepada kami [Sulaiman bin Kinanah] mantan budak Utsman bin Affan, telah mengabarkan kepada kami [Abdullah bin Abu Sufyan] dari [Adi bin Zaid], ia berkata; Rasulullah shallallahu 'alaihi wasallam membuat batas bagi Madinah kepada setiap sudut dari Madinah berjarak satu barid (empat farsakh), pohonnya tidak boleh ditebang kecuali yang digunakan untuk menggiring onta. "},"1676":{"ar":"حَدَّثَنَا أَبُو سَلَمَةَ حَدَّثَنَا جَرِيرٌ يَعْنِي ابْنَ حَازِمٍ حَدَّثَنِي يَعْلَى بْنُ حَكِيمٍ عَنْ سُلَيْمَانَ بْنِ أَبِي عَبْدِ اللَّهِ قَالَرَأَيْتُ سَعْدَ بْنَ أَبِي وَقَّاصٍ أَخَذَ رَجُلًا يَصِيدُ فِي حَرَمِ الْمَدِينَةِ الَّذِي حَرَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَلَبَهُ ثِيَابَهُ فَجَاءَ مَوَالِيهِ فَكَلَّمُوهُ فِيهِ فَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَرَّمَ هَذَا الْحَرَمَ وَقَالَ مَنْ أَخَذَ أَحَدًا يَصِيدُ فِيهِ فَلْيَسْلُبْهُ ثِيَابَهُ فَلَا أَرُدُّ عَلَيْكُمْ طُعْمَةً أَطْعَمَنِيهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَكِنْ إِنْ شِئْتُمْ دَفَعْتُ إِلَيْكُمْ ثَمَنَهُ","id":"Telah menceritakan kepada kami [Abu Usamah], telah menceritakan kepada kami [Jarir bin Hazim], telah menceritakan kepadaku [Ya'la bin Hakim] dari [Sulaiman bin Abu Abdullah], ia berkata; aku melihat [Sa'd bin Abu Waqqash] menangkap seorang laki-laki yang berburu di tanah haram Madinah yang telah diharamkan Rasulullah shallallahu 'alaihi wasallam. Kemudian ia melucuti pakaiannya, kemudian para walinya datang kepadanya dan berbicara dengannya mengenai orang tersebut. Lalu Sa'd berkata; sesungguhnya Rasulullah shallallahu 'alaihi wasallam telah mengharamkan tanah haram ini, dan berkata: \"Barangsiapa yang menangkap seseorang yang berburu padanya (di tanah Haram), maka hendaknya ia melucuti pakaiannya.\" Maka aku tidak akan mengembalikan kepada kalian apa yang telah diberikan Rasulullah shallallahu 'alaihi wasallam kepadaku. Akan tetapi, apabila kalian mau, maka aku akan serahkan uang seharga barang tersebut kepada kalian. "},"1677":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا ابْنُ أَبِي ذِئْبٍ عَنْ صَالِحٍ مَوْلَى التَّوْأَمَةِ عَنْ مَوْلًى لِسَعْدٍأَنَّ سَعْدًا وَجَدَ عَبِيدًا مِنْ عَبِيدِ الْمَدِينَةِ يَقْطَعُونَ مِنْ شَجَرِ الْمَدِينَةِ فَأَخَذَ مَتَاعَهُمْ وَقَالَ يَعْنِي لِمَوَالِيهِمْ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْهَى أَنْ يُقْطَعَ مِنْ شَجَرِ الْمَدِينَةِ شَيْءٌ وَقَالَ مَنْ قَطَعَ مِنْهُ شَيْئًا فَلِمَنْ أَخَذَهُ سَلَبُهُ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah], telah menceritakan kepada kami [Yazid bin Harun], telah mengabarkan kepada kami [Ibnu Abu Dzi`bin] dari [Shalih] mantan budak At Tauamah, dari [mantan budak Sa'd], bahwa [Sa'd] telah mendapati seorang budak di antara budak-budak Madinah yang menebangi pohon di Madinah. Kemudian ia mengambil barang-barang mereka dan berkata kepada para wali mereka; aku telah mendengar Rasulullah shallallahu 'alaihi wasallam melarang menebang pohon di Madinah, dan beliau berkata: \"Barangsiapa yang menebang sebagian pohon di Madinah, maka sesuatu yang dilucuti darinya adalah milik orang yang menangkapnya.\""},"1678":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ حَفْصٍ أَبُو عَبْدِ الرَّحْمَنِ الْقَطَّانُ حَدَّثَنَا مُحَمَّدُ بْنُ خَالِدٍ أَخْبَرَنِي خَارِجَةُ بْنُ الْحَارِثِ الْجُهَنِيُّ أَخْبَرَنِي أَبِي عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يُخْبَطُ وَلَا يُعْضَدُ حِمَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَكِنْ يُهَشُّ هَشًّا رَفِيقًا","id":"Telah menceritakan kepada kami [Muhammad bin Hafsh Abu Abdurrahman Al Qathtan], telah menceritakan kepada kami [Muhammad bin Khalid], telah mengabarkan kepadaku [Kharijah bin Al Harits Al Juhani], telah mengabarkan kepadaku [ayahku], dari [Jabir bin Abdullah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: larangan ditebang dan potongnya pohon adalah aturan yang ditetapkan Rasulullah shallallahu 'alaihi wasallam, akan tetapi boleh digoyangkan dengan pelan agar daunnya berjatuhan. "},"1679":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى ح حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ عَنْ ابْنِ نُمَيْرٍ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَأْتِي قِبَاءَ مَاشِيًا وَرَاكِبًا زَادَ ابْنُ نُمَيْرٍ وَيُصَلِّي رَكْعَتَيْنِ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Yahya], dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Utsman bin Abu Syaibah] dari [Ibnu Numair] dari ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar] bahwa Rasulullah shallallahu 'alaihi wasallam pernah datang ke Masjid Quba` dengan berjalan kaki dan juga berkendaraan. Ibnu Numair menambahkan dan melakukan shalat dua raka'at. "},"1680":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَوْفٍ حَدَّثَنَا الْمُقْرِئُ حَدَّثَنَا حَيْوَةُ عَنْ أَبِي صَخْرٍ حُمَيْدِ بْنِ زِيَادٍ عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ بْنِ قُسَيْطٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا مِنْ أَحَدٍ يُسَلِّمُ عَلَيَّ إِلَّا رَدَّ اللَّهُ عَلَيَّ رُوحِي حَتَّى أَرُدَّ عَلَيْهِ السَّلَامَ","id":"Telah menceritakan kepada kami [Muhammad bin 'Auf], telah menceritakan kepada kami [Al Muqri`], telah menceritakan kepada kami [Haiwah], dari [Abu Shakhr Humaid bin Ziyad] dari [Yazid bin Abdullah bin Qusaith] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam berkata: \"Tidaklah seseorang memberikan salam kepadaku melainkan Allah akan mengembalikan nyawaku hingga aku membalas salamnya.\""},"1681":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ قَرَأْتُ عَلَى عَبْدِ اللَّهِ بْنِ نَافِعٍ أَخْبَرَنِي ابْنُ أَبِي ذِئْبٍ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَجْعَلُوا بُيُوتَكُمْ قُبُورًا وَلَا تَجْعَلُوا قَبْرِي عِيدًا وَصَلُّوا عَلَيَّ فَإِنَّ صَلَاتَكُمْ تَبْلُغُنِي حَيْثُ كُنْتُمْ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih], aku membacakan kepada [Abdullah bin Nafi'], telah mengabarkan kepadaku [Ibnu Abu Dzi`bin] dari [Sa'id Al Maqburi], dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian jadikan rumah-rumah kalian sebagai kuburan (tidak pernah dilaksanakan di dalamnya shalat dan juga tidak pernah dikumandangkan ayat-ayat Al Quran, sehingga seperti kuburan), dan jangan kalian jadikan kuburanku sebagai 'id (hari raya, yakni tempat yang selalu dikunjungi dan didatangi pada setiap waktu dan saat), bershalawatlah kepadaku, sesungguhnya shalawat kalian akan sampai kepadaku di manapun kalian berada.\""},"1682":{"ar":"حَدَّثَنَا حَامِدُ بْنُ يَحْيَى حَدَّثَنَا مُحَمَّدُ بْنُ مَعْنٍ الْمَدَنِيُّ أَخْبَرَنِي دَاوُدُ بْنُ خَالِدٍ عَنْ رَبِيعَةَ بْنِ أَبِي عَبْدِ الرَّحْمَنِ عَنْ رَبِيعَةَ يَعْنِي ابْنَ الْهُدَيْرِ قَالَ مَا سَمِعْتُ طَلْحَةَ بْنَ عُبَيْدِ اللَّهِ يُحَدِّثُعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدِيثًا قَطُّ غَيْرَ حَدِيثٍ وَاحِدٍ قَالَ قُلْتُ وَمَا هُوَ قَالَ خَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُرِيدُ قُبُورَ الشُّهَدَاءِ حَتَّى إِذَا أَشْرَفْنَا عَلَى حَرَّةِ وَاقِمٍ فَلَمَّا تَدَلَّيْنَا مِنْهَا وَإِذَا قُبُورٌ بِمَحْنِيَّةٍ قَالَ قُلْنَا يَا رَسُولَ اللَّهِ أَقُبُورُ إِخْوَانِنَا هَذِهِ قَالَ قُبُورُ أَصْحَابِنَا فَلَمَّا جِئْنَا قُبُورَ الشُّهَدَاءِ قَالَ هَذِهِ قُبُورُ إِخْوَانِنَا","id":"Telah menceritakan kepada kami [Hamid bin Yahya], telah menceritakan kepada kami [Muhammad bin Ma'n Al Madini], telah mengabarkan kepadaku [Daud bin Khalid] dari [Rabi'ah bin Abu Abdurrahman] dari [Rabi'ah bin Al Hudair], ia berkata; aku tidak mendengar [Thalhah bin 'Ubaidullah] menceritakan hadits dari Rasulullah shallallahu 'alaihi wasallam kecuali satu hadits, Rabi'ah bin Hudair berkata; aku katakan; apakah hadits tersebut? Ia berkata; kami pernah keluar bersama Rasulullah shallallahu 'alaihi wasallam, beliau ingin pergi ke kuburan orang-orang yang mati syahid, hingga kami berada di atas tanah bebatuan yang (dikenal dengan nama) Waqim, kemudian tatkala kami telah dekat dari kuburan tersebut ternyata terdapat kuburan di tempat tikungan. Rabi'ah bin Hudair berkata; kami katakan; wahai Rasulullah, apakah ini kuburan saudara-saudara kita? Beliau berkata: \"Ini adalah kuburan sahabat-sahabat kita.\" Kemudian tatkala kami sampai pada kuburan orang-orang yang mati syahid beliau bersabda: \"Ini adalah kuburan saudara-saudara kita.\""},"1683":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَاخَ بِالْبَطْحَاءِ الَّتِي بِذِي الْحُلَيْفَةِ فَصَلَّى بِهَافَكَانَ عَبْدُ اللَّهِ بْنُ عُمَرَ يَفْعَلُ ذَلِكَ","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik], dari [Nafi'], dari [Abdullah bin Umar] bahwa Rasulullah shallallahu 'alaihi wasallam menderumkan untanya di Al Bathha` yang berada di Dzul Hulaifah, kemudian beliau melakukan shalat padanya. Dan Abdullah bin Umar melakukan hal tersebut. "},"1684":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ قَالَ قَالَ مَالِكٌلَا يَنْبَغِي لِأَحَدٍ أَنْ يُجَاوِزَ الْمُعَرَّسِ إِذَا قَفَلَ رَاجِعًا إِلَى الْمَدِينَةِ حَتَّى يُصَلِّيَ فِيهَا مَا بَدَا لَهُ لِأَنَّهُ بَلَغَنِي أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَرَّسَ بِهِقَالَ أَبُو دَاوُد سَمِعْتُ مُحَمَّدَ بْنَ إِسْحَقَ الْمَدَنِيَّ قَالَ الْمُعَرَّسُ عَلَى سِتَّةِ أَمْيَالٍ مِنْ الْمَدِينَةِ","id":"Telah menceritakan kepada kami [Al Qa'nabi], ia berkata; [Malik] berkata; tidak selayaknya seseorang melampaui Al Mu'arras apabila ia kembali ke Madinah hingga ia melakukan shalat padanya sesuai keinginannya, karena telah sampai kepadaku bahwa Rasulullah shallallahu 'alaihi wasallam singgah di akhir malam untuk istirahat padanya. Abu Daud berkata; aku mendengar Muhammad bin Ishak Al Madani berkata; Al Mu'arras jaraknya enam mil dari Madinah. "},"1685":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ قَالَإِنِّي لَأَمْشِي مَعَ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ بِمِنًى إِذْ لَقِيَهُ عُثْمَانُ فَاسْتَخْلَاهُ فَلَمَّا رَأَى عَبْدُ اللَّهِ أَنْ لَيْسَتْ لَهُ حَاجَةٌ قَالَ لِي تَعَالَ يَا عَلْقَمَةُ فَجِئْتُ فَقَالَ لَهُ عُثْمَانُ أَلَا نُزَوِّجُكَ يَا أَبَا عَبْدِ الرَّحْمَنِ بِجَارِيَةٍ بِكْرٍ لَعَلَّهُ يَرْجِعُ إِلَيْكَ مِنْ نَفْسِكَ مَا كُنْتَ تَعْهَدُ فَقَالَ عَبْدُ اللَّهِ لَئِنْ قُلْتَ ذَاكَ لَقَدْ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ اسْتَطَاعَ مِنْكُمْ الْبَاءَةَ فَلْيَتَزَوَّجْ فَإِنَّهُ أَغَضُّ لِلْبَصَرِ وَأَحْصَنُ لِلْفَرْجِ وَمَنْ لَمْ يَسْتَطِعْ مِنْكُمْ فَعَلَيْهِ بِالصَّوْمِ فَإِنَّهُ لَهُ وِجَاءٌ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah], telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Ibrahim] dari ['Alqamah], ia berkata; sungguh aku pernah berjalan bersama [Abdullah bin Mas'ud] di Mina, tiba-tiba ia bertemu dengan Utsman, kemudian ia mengajaknya menyendiri. Kemudian tatkala Abdullah melihat bahwa ia tidak memiliki keperluan dengannya ia berkata kepadaku; kemarilah wahai 'Alqamah! Kemudian aku datang. Kemudian Utsman berkata kepadanya; maukah kami menikahkanmu wahai Abu Abdurrahman dengan seorang gadis, agar kembali kepadamu semangat dan keperkasaanmu seperti dahulu? Kemudian Abdullah berkata; jika engkau mengatakan demikian sungguh aku telah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa di antara kalian yang memiliki kemampuan maka hendaknya ia menikah, karena hal tersebut lebih dapat menundukkan pandangannya dan lebih menjaga kemaluannya, dan barangsiapa di antara kalian yang belum mampu maka hendaknya ia berpuasa, karena puasa adalah kendali baginya.\""},"1686":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى يَعْنِي ابْنَ سَعِيدٍ حَدَّثَنِي عُبَيْدُ اللَّهِ حَدَّثَنِي سَعِيدُ بْنُ أَبِي سَعِيدٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تُنْكَحُ النِّسَاءُ لِأَرْبَعٍ لِمَالِهَا وَلِحَسَبِهَا وَلِجَمَالِهَا وَلِدِينِهَا فَاظْفَرْ بِذَاتِ الدِّينِ تَرِبَتْ يَدَاكَ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Yahya bin Sa'id], telah menceritakan kepadaku ['Ubaidullah], telah menceritakan kepadaku [Sa'id bin Abu Sa'id], dari [ayahnya], dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau berkata: \"Wanita dinikahi karena empat perkara, yaitu: karena hartanya, keturunannya, kecantikannya dan karena agamannya. Carilah yang memiliki agama yang baik, maka engkau akan beruntung.\""},"1687":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ أَخْبَرَنَا الْأَعْمَشُ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَزَوَّجْتَ قُلْتُ نَعَمْ قَالَ بِكْرًا أَمْ ثَيِّبًا فَقُلْتُ ثَيِّبًا قَالَ أَفَلَا بِكْرٌ تُلَاعِبُهَا وَتُلَاعِبُكَ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal], telah menceritakan kepada kami [Abu Mu'awiyah], telah mengabarkan kepada kami [Al A'masy] dari [Salim bin Abu Al Ja'd] dari [Jabir bin Abdullah], ia berkata; Rasulullah shallallahu 'alaihi wasallam berkata kepadaku: \"Apakah engkau telah menikah?\" Aku katakan; Iya. Beliau bertanya: \"Gadis atau janda?\" Aku katakan; janda. Beliau berkata: \"Mengapa engkau tidak menikah dengan seorang gadis, sehingga engkau dapat bercanda dengannya dan dia bercanda denganmu?\""},"1688":{"ar":"قَالَ أَبُو دَاوُد كَتَبَ إِلَيَّ حُسَيْنُ بْنُ حُرَيْثٍ الْمَرْوَزِيُّ حَدَّثَنَا الْفَضْلُ بْنُ مُوسَى عَنْ الْحُسَيْنِ بْنِ وَاقِدٍ عَنْ عُمَارَةَ بْنِ أَبِي حَفْصَةَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ امْرَأَتِي لَا تَمْنَعُ يَدَ لَامِسٍ قَالَ غَرِّبْهَا قَالَ أَخَافُ أَنْ تَتْبَعَهَا نَفْسِي قَالَ فَاسْتَمْتِعْ بِهَا","id":"Abu Daud berkata; [Husain bin Huraits Al Marwazi] menulis surat kepadaku; telah menceritakan kepada kami [Al Fadhl bin Musa] dari [Al Husain bin Waqid] dari ['Umarah bin Abu Hafsh] dari [Ikrimah] dari [Ibnu Abbas], ia berkata; seorang laki-laki datang kepada Nabi shallallahu 'alaihi wasallam dan berkata; istriku tidak menolak tangan orang yang menyentuhnya. Beliau menjawab: Ceraikanlah dia! Dia berkata lagi; aku khawatir diriku sangat berhasrat kepadanya (sangat mencintainya). Beliau berkata: \"Kalau begitu, bersenang-senanglah dengannya!\""},"1689":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا مُسْتَلِمُ بْنُ سَعِيدٍ ابْنَ أُخْتِ مَنْصُورِ بْنِ زَاذَانَ عَنْ مَنْصُورٍ يَعْنِي ابْنَ زَاذَانَ عَنْ مُعَاوِيَةَ بْنِ قُرَّةَ عَنْ مَعْقِلِ بْنِ يَسَارٍ قَالَجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنِّي أَصَبْتُ امْرَأَةً ذَاتَ حَسَبٍ وَجَمَالٍ وَإِنَّهَا لَا تَلِدُ أَفَأَتَزَوَّجُهَا قَالَ لَا ثُمَّ أَتَاهُ الثَّانِيَةَ فَنَهَاهُ ثُمَّ أَتَاهُ الثَّالِثَةَ فَقَالَ تَزَوَّجُوا الْوَدُودَ الْوَلُودَ فَإِنِّي مُكَاثِرٌ بِكُمْ الْأُمَمَ","id":"Telah menceritakan kepada kami [Ahmad bin Ibrahim], telah menceritakan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Mustalim bin Sa'id anak saudari Manshur bin Zadzan], dari [Manshur bin Zadzan] dari [Mu'awiyah bin Qurrah] dari [Ma'qil bin Yasar], ia berkata; seorang laki-laki datang kepada Nabi Shallallahu 'alaihi sallam lalu berkata; sesungguhnya aku mendapati seorang wanita yang mempunyai keturunan yang baik dan cantik, akan tetapi dia mandul, apakah aku boleh menikahinya? Beliau menjawab: \"Tidak.\" Kemudian dia datang lagi kedua kalinya dan beliau melarangnya, kemudian ia datang ketiga kalinya lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Nikahkanlah wanita-wanita yang penyayang dan subur (banyak keturunan), karena aku akan berbangga kepada umat yang lain dengan banyaknya kalian.\""},"1690":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُحَمَّدٍ التَّيْمِيُّ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ بْنِ الْأَخْنَسِ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ مَرْثَدَ بْنَ أَبِي مَرْثَدٍ الْغَنَوِيَّ كَانَ يَحْمِلُ الْأَسَارَى بِمَكَّةَ وَكَانَ بِمَكَّةَ بَغِيٌّ يُقَالُ لَهَا عَنَاقُ وَكَانَتْ صَدِيقَتَهُ قَالَ جِئْتُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ أَنْكِحُ عَنَاقَ قَالَ فَسَكَتَ عَنِّي فَنَزَلَتْ{ وَالزَّانِيَةُ لَا يَنْكِحُهَا إِلَّا زَانٍ أَوْ مُشْرِكٌ }فَدَعَانِي فَقَرَأَهَا عَلَيَّ وَقَالَ لَا تَنْكِحْهَا","id":"Telah menceritakan kepada kami [Ibrahim bin Muhammad At Taimi], telah menceritakan kepada kami [Yahya], dari ['Ubaidullah bin Al Akhnas] dari ['Amr bin Syu'aib] dari [ayahnya], dari [kakeknya] bahwa Martsad bin Abu Martsad Al Ghanawi membawa tawanan dari Mekkah dan di Mekkah terdapat seorang pelacur yang dikenal dengan nama 'Anaq dan dia dahulu adalah teman wanitanya. Martsad berkata; Aku menemui Nabi Shallallahu 'alaihi sallam lalu aku berkata; wahai Rasulullah, bolehkah aku menikahi 'Anaq? Martsad berkata; kemudian beliau diam, lalu turun ayat: \" Seorang wanita pezina tidaklah boleh dinikahi kecuali oleh seorang laki-laki pezina atau orang musyrik\". Lalu beliau memanggilku dan membacakan ayat tersebut di hadapanku seraya bersabda, \"Janganlah kamu menikahinya.\""},"1691":{"ar":"حَدَّثَنَا مُسَدَّدٌ وَأَبُو مَعْمَرٍ قَالَا حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ حَبِيبٍ حَدَّثَنِي عَمْرُو بْنُ شُعَيْبٍ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَنْكِحُ الزَّانِي الْمَجْلُودُ إِلَّا مِثْلَهُو قَالَ أَبُو مَعْمَرٍ حَدَّثَنِي حَبِيبٌ الْمُعَلِّمُ عَنْ عَمْرِو بْنِ شُعَيْبٍ","id":"Telah menceritakan kepada kami [Musaddad] dan [Abu Ma'mar], mereka berkata; telah menceritakan kepada kami [Abdul Warits] dari [Habib], telah menceritakan kepadaku ['Amr bin Syu'aib] dari [Sa'id Al Maqburi] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang pezina yang didera tidak boleh menikah kecuali dengan wanita seperti dirinya.\" [Abu Ma'mar] berkata; telah menceritakan kepadaku [Habib Al Mu'allim] dari ['Amr bin Syu'aib]. "},"1692":{"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ حَدَّثَنَا عَبْثَرٌ عَنْ مُطَرِّفٍ عَنْ عَامِرٍ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَعْتَقَ جَارِيَتَهُ وَتَزَوَّجَهَا كَانَ لَهُ أَجْرَانِ","id":"Telah menceritakan kepada kami [Hannad bin As Sari], telah menceritakan kepada kami ['Abtsar] dari [Mutharrif] dari ['Amir] dari [Abu Burdah] dari [Abu Musa], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang membebaskan budak wanita dan menikahinya, maka baginya dua pahala.\""},"1693":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَوْنٍ أَخْبَرَنَا أَبُو عَوَانَةَ عَنْ قَتَادَةَ وَعَبْدِ الْعَزِيزِ بْنِ صُهَيْبٍ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْتَقَ صَفِيَّةَ وَجَعَلَ عِتْقَهَا صَدَاقَهَا","id":"Telah menceritakan kepada kami ['Amr bin 'Aun], telah mengabarkan kepada kami [Abu 'Awanah] dari [Qatadah] dan [Abdul Aziz bin Shuhaib] dari [Anas bin Malik] bahwa Nabi shallallahu 'alaihi wasallam telah membebaskan Shafiyyah dan menjadikan pembebasannya sebagai maharnya. "},"1694":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَحْرُمُ مِنْ الرَّضَاعَةِ مَا يَحْرُمُ مِنْ الْوِلَادَةِ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] dari [Malik] dari [Abdullah bin Dinar] dari [Sulaiman bin Yasar] dari ['Urwah] dari [Aisyah] isteri Nabi shallallahu 'alaihi wasallam bahwa Nabi shallallahu 'alaihi wasallam berkata: \"Sesuatu yang diharamkan karena persusuan, diharamkan seperti (diharamkan) karena nasab (keturunan).\""},"1695":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ حَدَّثَنَا زُهَيْرٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ عُرْوَةَ عَنْ زَيْنَبَ بِنْتِ أُمِّ سَلَمَةَ عَنْ أُمِّ سَلَمَةَأَنَّ أُمَّ حَبِيبَةَ قَالَتْ يَا رَسُولَ اللَّهِ هَلْ لَكَ فِي أُخْتِي قَالَ فَأَفْعَلُ مَاذَا قَالَتْ فَتَنْكِحُهَا قَالَ أُخْتَكِ قَالَتْ نَعَمْ قَالَ أَوَتُحِبِّينَ ذَلِكَ قَالَتْ لَسْتُ بِمُخْلِيَةٍ بِكَ وَأَحَبُّ مَنْ شَرِكَنِي فِي خَيْرٍ أُخْتِي قَالَ فَإِنَّهَا لَا تَحِلُّ لِي قَالَتْ فَوَاللَّهِ لَقَدْ أُخْبِرْتُ أَنَّكَ تَخْطُبُ دُرَّةَ أَوْ ذُرَّةَ شَكَّ زُهَيْرٌ بِنْتَ أَبِي سَلَمَةَ قَالَ بِنْتَ أُمِّ سَلَمَةَ قَالَتْ نَعَمْ قَالَ أَمَا وَاللَّهِ لَوْ لَمْ تَكُنْ رَبِيبَتِي فِي حِجْرِي مَا حَلَّتْ لِي إِنَّهَا ابْنَةُ أَخِي مِنْ الرَّضَاعَةِ أَرْضَعَتْنِي وَأَبَاهَا ثُوَيْبَةُ فَلَا تَعْرِضْنَ عَلَيَّ بَنَاتِكُنَّ وَلَا أَخَوَاتِكُنَّ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad An Nufaili], telah menceritakan kepada kami [Zuhair], dari [Hisyam bin 'Urwah] dari ['Urwah] dari [Zainab binti Ummu Salamah] bahwa [Ummu Salamah] berkata; wahai Rasulullah, apakah engkau memiliki keinginan terhadap saudariku? Beliau berkata: \"Apa yang meski aku lakukan?\" Ia berkata; engkau menikahinya. Beliau berkata: \"Saudarimu?\" Ia berkata; Iya. Beliau berkata: \"Apakah engkau menginginkan hal tersebut?\" Ia berkata; bukan aku saja yang memilikimu, dan orang yang paling aku sukai untuk bersekutu denganku dalam kebaikan adalah saudariku. Beliau bersabda: \"Ia tidak halal bagiku.\" Ummu Habibah berkata; sungguh aku telah diberitahu bahwa engkau hendak meminang Durrah atau Dzurrah -Zuhair merasa ragu dalam hal tersebut- binti Abu Salamah. Beliau berkata: \"Binti Ummu Salamah?\" Ia berkata; Iya. Beliau berkata: \"Ketahuilah, demi Allah, seandainya ia bukan anak isteriku yang ada dalam pemeliharaanku, tidaklah ia halal bagiku, karena ia adalah anak saudaraku sepersusuan. Aku dan ayahnya telah disusui oleh Tsuwaibah, maka janganlah kalian menawarkan anak-anak dan saudara-saudara wanita kalian kepadaku."},"1696":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ الْعَبْدِيُّ أَخ��بَرَنَا سُفْيَانُ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْدَخَلَ عَلَيَّ أَفْلَحُ بْنُ أَبِي الْقُعَيْسِ فَاسْتَتَرْتُ مِنْهُ قَالَ تَسْتَتِرِينَ مِنِّي وَأَنَا عَمُّكِ قَالَتْ قُلْتُ مِنْ أَيْنَ قَالَ أَرْضَعَتْكِ امْرَأَةُ أَخِي قَالَتْ إِنَّمَا أَرْضَعَتْنِي الْمَرْأَةُ وَلَمْ يُرْضِعْنِي الرَّجُلُ فَدَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَحَدَّثْتُهُ فَقَالَ إِنَّهُ عَمُّكِ فَلْيَلِجْ عَلَيْكِ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir Al 'Abdi], telah mengabarkan kepada kami [Sufyan] dari [Hisyam bin 'Urwah] dari ['Urwah] dari [Aisyah] radliallahu 'anha, ia berkata; Aflah bin Abu Al Qu'ais menemuiku, kemudian aku menutup diri darinya. Ia berkata; apakah engkau menutup diri dariku? Aku adalah pamanmu. Aisyah berkata; aku katakan; dari mana? Ia berkata; engkau telah disusui isteri saudaraku. Aisyah berkata; sesungguhnya aku disusui oleh seorang wanita dan tidak disusui oleh seorang laki-laki. Kemudian Rasulullah shallallahu 'alaihi wasallam menemuiku dan aku menceritakannya kepada beliau. Lalu beliau berkata: \"Sesungguhnya ia adalah pamanmu, maka silahkan ia menemuimu.\""},"1697":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ ح و حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ أَشْعَثَ بْنِ سُلَيْمٍ عَنْ أَبِيهِ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ الْمَعْنَى وَاحِدٌأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَلَيْهَا وَعِنْدَهَا رَجُلٌ قَالَ حَفْصٌ فَشَقَّ ذَلِكَ عَلَيْهِ وَتَغَيَّرَ وَجْهُهُ ثُمَّ اتَّفَقَا قَالَتْ يَا رَسُولَ اللَّهِ إِنَّهُ أَخِي مِنْ الرَّضَاعَةِ فَقَالَ انْظُرْنَ مَنْ إِخْوَانُكُنَّ فَإِنَّمَا الرَّضَاعَةُ مِنْ الْمَجَاعَةِ","id":"Telah menceritakan kepada kami [Hafsh bin Umar], telah menceritakan kepada kami [Syu'bah], dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Muhammad bin Katsir], telah mengabarkan kepada kami [Sufyan] dari [Asy'ats bin Sulaim] dari [ayahnya] dari [Masruq] dari [Aisyah] dengan makna yang sama bahwa Rasulullah shallallahu 'alaihi wasallam menemuinya dan terdapat seorang laki-laki yang bersamanya -Hafsh berkata; hal tersebut terasa berat bagi beliau dan raut wajah beliau berubah. Kemudian Syu'bah dan Muhammad bin Katsir sama bersepakat mengatakan; Aisyah berkata; wahai Rasulallah, dia adalah saudaraku sepersusuan. Beliau berkata: \"Lihatlah siapa saudara-saudara sepersusuan kalian, sesungguhnya persusuan itu adalah karena lapar.\""},"1698":{"ar":"حَدَّثَنَا عَبْدُ السَّلَامِ بْنُ مُطَهَّرٍ أَنَّ سُلَيْمَانَ بْنَ الْمُغِيرَةِ حَدَّثَهُمْ عَنْ أَبِي مُوسَى عَنْ أَبِيهِ عَنْ ابْنٍ لِعَبْدِ اللَّهِ بْنِ مَسْعُودٍ عَنْ ابْنِ مَسْعُودٍ قَالَلَا رِضَاعَ إِلَّا مَا شَدَّ الْعَظْمَ وَأَنْبَتَ اللَّحْمَفَقَالَ أَبُو مُوسَى لَا تَسْأَلُونَا وَهَذَا الْحَبْرُ فِيكُمْ حَدَّثَنَا مُحَمَّدُ بْنُ سُلَيْمَانَ الْأَنْبَارِيُّ حَدَّثَنَا وَكِيعٌ عَنْ سُلَيْمَانَ بْنِ الْمُغِيرَةِ عَنْ أَبِي مُوسَى الْهِلَالِيِّ عَنْ أَبِيهِ عَنْ ابْنِ مَسْعُودٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَعْنَاهُ وَقَالَ أَنْشَزَ الْعَظْمَ","id":"Telah menceritakan kepada kami [Abdussalam bin Muthahhar] bahwa [Sulaiman bin Al Mughirah], menceritakan kepada mereka dari [Abu Musa] dari [ayahnya] dari [Ibnu Abdullah bin Mas'ud] dari [Ibnu Mas'ud], ia berkata; Tidaklah (dianggap) persusuan kecuali yang dapat menguatkan tulang dan menumbuhkan daging. Abu Musa berkata; jangan kalian bertanya kepada kami sementara orang alim ini berada di antara kalian. Telah menceritakan kepada kami [Muhammad bin Sulaiman Al Anbari], telah menceritakan kepada kami [Waki'] dari [Sulaiman bin Al Mughirah] dari [Abu Musa Al Hilali], dari [ayahnya] dari [Ibnu Mas'ud] dari Nabi shallallahu 'alaihi wasallam dengan makna yang sama dengannya, dan ia berkata; serta menumbuhkan tulang. "},"1699":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا عَنْبَسَةُ حَدَّثَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ حَدَّثَنِي عُرْوَةُ بْنُ الزُّبَيْرِ عَنْ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأُمِّ سَلَمَةَأَنَّ أَبَا حُذَيْفَةَ بْنَ عُتْبَةَ بْنِ رَبِيعَةَ بْنِ عَبْدِ شَمْسٍ كَانَ تَبَنَّى سَالِمًا وَأَنْكَحَهُ ابْنَةَ أَخِيهِ هِنْدَ بِنْتَ الْوَلِيدِ بْنِ عُتْبَةَ بْنِ رَبِيعَةَ وَهُوَ مَوْلًى لِامْرَأَةٍ مِنْ الْأَنْصَارِ كَمَا تَبَنَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَيْدًا وَكَانَ مَنْ تَبَنَّى رَجُلًا فِي الْجَاهِلِيَّةِ دَعَاهُ النَّاسُ إِلَيْهِ وَوُرِّثَ مِيرَاثَهُ حَتَّى أَنْزَلَ اللَّهُ سُبْحَانَهُ وَتَعَالَى فِي ذَلِكَ{ ادْعُوهُمْ لِآبَائِهِمْ إِلَى قَوْلِهِ فَإِخْوَانُكُمْ فِي الدِّينِ وَمَوَالِيكُمْ }فَرُدُّوا إِلَى آبَائِهِمْ فَمَنْ لَمْ يُعْلَمْ لَهُ أَبٌ كَانَ مَوْلًى وَأَخًا فِي الدِّينِ فَجَاءَتْ سَهْلَةُ بِنْتُ سُهَيْلِ بْنِ عَمْرٍو الْقُرَشِيِّ ثُمَّ الْعَامِرِيِّ وَهِيَ امْرَأَةُ أَبِي حُذَيْفَةَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنَّا كُنَّا نَرَى سَالِمًا وَلَدًا وَكَانَ يَأْوِي مَعِي وَمَعَ أَبِي حُذَيْفَةَ فِي بَيْتٍ وَاحِدٍ وَيَرَانِي فُضْلًا وَقَدْ أَنْزَلَ اللَّهُ عَزَّ وَجَلَّ فِيهِمْ مَا قَدْ عَلِمْتَ فَكَيْفَ تَرَى فِيهِ فَقَالَ لَهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْضِعِيهِ فَأَرْضَعَتْهُ خَمْسَ رَضَعَاتٍ فَكَانَ بِمَنْزِلَةِ وَلَدِهَا مِنْ الرَّضَاعَةِ فَبِذَلِكَ كَانَتْ عَائِشَةُ رَضِيَ اللَّهُ عَنْهَا تَأْمُرُ بَنَاتِ أَخَوَاتِهَا وَبَنَاتِ إِخْوَتِهَا أَنْ يُرْضِعْنَ مَنْ أَحَبَّتْ عَائِشَةُ أَنْ يَرَاهَا وَيَدْخُلَ عَلَيْهَا وَإِنْ كَانَ كَبِيرًا خَمْسَ رَضَعَاتٍ ثُمَّ يَدْخُلُ عَلَيْهَا وَأَبَتْ أُمُّ سَلَمَةَ وَسَائِرُ أَزْوَاجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُدْخِلْنَ عَلَيْهِنَّ بِتِلْكَ الرَّضَاعَةِ أَحَدًا مِنْ النَّاسِ حَتَّى يَرْضَعَ فِي الْمَهْدِ وَقُلْنَ لِعَائِشَةَ وَاللَّهِ مَا نَدْرِي لَعَلَّهَا كَانَتْ رُخْصَةً مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِسَالِمٍ دُونَ النَّاسِ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih], telah menceritakan kepada kami ['Anbasah], telah menceritakan kepadaku [Yunus] dari [Ibnu Syihab], telah menceritakan kepadaku ['Urwah bin Az Zubair], dari [Aisyah] isteri Nabi shallallahu 'alaihi wasallam serta [Ummu Salamah] bahwa Abu Hudzaifah bin 'Utbah bin Rabi'ah bin Abdu Syams pernah mengangkat Salim sebagai anak, dan menikahkannya dengan anak saudaranya yaitu Hindun binti Al Walid bin 'Utbah bin Rabi'ah, sementara Salim adalah mantan budak seorang wanita anshar, sebagaimana Rasulullah shallallahu 'alaihi wasallam mengangkat Zaid sebagai anak. Dahulu pada masa jahiliyah orang yang mengangkat seseorang sebagai anak, maka orang-orang memanggilnya dengan menisbatkannya kepadanya dan diberi warisannya hingga Allah subhanahu wa ta'ala menurunkan wahyu mengenai hal tersebut: \"Panggilah mereka (anak-anak angkat itu) dengan (memakai) nama bapak-bapak mereka; itulah yang lebih adil pada sisi Allah, dan jika kamu tidak mengetahui bapak-bapak mereka, maka (panggilah mereka sebagai) saudara-saudaramu seagama dan maula-maulamu.\" Kemudian mereka dikembalikan nasabnya kepada bapak-bapak mereka, sedangkan yang tidak diketahui ayahnya maka ia adalah seorang maula dan saudara seagama. Kemudian Sahlah binti Suhail bin 'Amr Al Qurasyi Al 'Amiri yang merupakan isteri Abu Hudzaifah datang dan berkata; wahai Rasulullah, sesungguhnya dahulu kami melihat Salim masih kecil, dan ia tinggal bersamaku dan bersama Abu Hudzaifah dalam satu rumah. Ia melihatku dalam keadaan memakai pakaian kerja, sedangkan Allah 'azza wajalla telah menurunkan wahyu yang engkau mengerti, maka bagaimana pendapat engkau dalam hal tersebut? Kemudian Nabi shallallahu 'alaihi wasallam berkata kepadanya: \"Susuilah dia!\" Lalu Sahlah menyusuinya lima kali susuan, maka Salim sama seperti anaknya sepersusuan. Oleh karena itu Aisyah memerintahkan anak-anak wanita saudari-saudarinya serta anak-anak wanita saudara-saudaranya agar menyusui orang yang ia ingin melihat serta menemuinya walaupun ia adalah orang dewasa sebanyak lima kali susuan, kemudian orang tersebut dapat menemuinya. Sedangkan Ummu Salamah dan isteri-isteri Nabi yang lain menolak memasukkan seseorang kepada mereka dengan persusuan tersebut kecuali menyusu pada saat masih bayi. Dan mereka berkata kepada Aisyah; demi Allah, kami tidak tahu, kemungkinan hal tersebut merupakan keringanan dari Nabi shallallahu 'alaihi wasallam untuk Salim, bukan orang selainnya. "},"1700":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرِ بْنِ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَزْمٍ عَنْ عَمْرَةَ بِنْتِ عَبْدِ الرَّحْمَنِ عَنْ عَائِشَةَ أَنَّهَا قَالَتْكَانَ فِيمَا أَنْزَلَ اللَّهُ عَزَّ وَجَلَّ مِنْ الْقُرْآنِ عَشْرُ رَضَعَاتٍ يُحَرِّمْنَ ثُمَّ نُسِخْنَ بِخَمْسٍ مَعْلُومَاتٍ يُحَرِّمْنَ فَتُوُفِّيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُنَّ مِمَّا يُقْرَأُ مِنْ الْقُرْآنِ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah Al Qa'nabi], dari [Malik] dari [Abdullah bin Abu Bakr bin Muhammad bin 'Amr bin Hazm] dari ['Amrah binti Abdurrahman], dari [Aisyah] bahwa ia berkata; dahulu di antara ayat yang diturunkan adalah sepuluh kali susuan mengharamkan (untuk dinikahi). Kemudian ayat tersebut dinaskh (dihapus) menjadi lima kali susuan mengharamkan (untuk dinikahi). Lalu Nabi Shallallahu 'alaihi sallam meninggal dan ayat tersebut termasuk di antara bagian Al Qur'an yang dibaca. "},"1701":{"ar":"حَدَّثَنَا مُسَدَّدُ بْنُ مُسَرْهَدٍ حَدَّثَنَا إِسْمَعِيلُ عَنْ أَيُّوبَ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُحَرِّمُ الْمَصَّةُ وَلَا الْمَصَّتَانِ","id":"Telah menceritakan kepada kami [Musaddad bin Musarhd], telah menceritakan kepada kami [Isma'il] dari [Ayyub] dari [Ibnu Abu Mulaikah] dari [Abdullah bin Az Zubair] dari [Aisyah] radliallahu 'anha, ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Satu kali isapan dan dua kali isapan tidaklah mengharamkan.\""},"1702":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ حَدَّثَنَا أَبُو مُعَاوِيَةَ ح و حَدَّثَنَا ابْنُ الْعَلَاءِ حَدَّثَنَا ابْنُ إِدْرِيسَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ حَجَّاجِ بْنِ حَجَّاجٍ عَنْ أَبِيهِ قَالَقُلْتُ يَا رَسُولَ اللَّهِ مَا يُذْهِبُ عَنِّي مَذَمَّةَ الرَّضَاعَةِ قَالَ الْغُرَّةُ الْعَبْدُ أَوْ الْأَمَةُ قَالَ النُّفَيْلِيُّ حَجَّاجُ بْنُ حَجَّاجٍ الْأَسْلَمِيُّ وَهَذَا لَفْظُهُ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad An Nufaili], telah menceritakan kepada kami [Abu Mu'awiyah], dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Ibnu Al 'Ala`], telah menceritakan kepada kami [Ibnu Idris] dari [Hisyam bin 'Urwah] dari [ayahnya] dari [Hajjaj] dari [ayahnya], ia berkata; aku katakan; wahai Rasulullah, apakah yang dapat menghilangkan hak persusuan? Beliau berkata: \"Seorang budak laki-laki atau seorang budak wanita.\""},"1703":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا دَاوُدُ بْنُ أَبِي هِنْدٍ عَنْ عَامِرٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُنْكَحُ الْمَرْأَةُ عَلَى عَمَّتِهَا وَلَا الْعَمَّةُ عَلَى بِنْتِ أَخِيهَا وَلَا الْمَرْأَةُ عَلَى خَالَتِهَا وَلَا الْخَالَةُ عَلَى بِنْتِ أُخْتِهَا وَلَا تُنْكَحُ الْكُبْرَى عَلَى الصُّغْرَى وَلَا الصُّغْرَى عَلَى الْكُبْرَى","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad An Nufaili], telah menceritakan kepada kami [Zuhair], telah menceritakan kepada kami [Daud bin Abu Hindun], dari ['Amir], dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak boleh seorang wanita dinikahi sebagai madu bibinya (saudari ayah), dan seorang bibi dinikahi sebagai madu anak wanita saudara laki-lakinya, dan tidak boleh seorang wanita dinikahi sebagai madu bibinya (saudari ibu) dan seorang bibi sebagai madu bagi anak wanita saudara wanitanya. Dan tidak boleh seorang kakak wanita dinikahi sebagai madu adik wanitanya, dan adik wanita dinikahi sebagai madu kakak wanitanya.\""},"1704":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا عَنْبَسَةُ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي قَبِيصَةُ بْنُ ذُؤَيْبٍ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُجْمَعَ بَيْنَ الْمَرْأَةِ وَخَالَتِهَا وَبَيْنَ الْمَرْأَةِ وَعَمَّتِهَا","id":"Telah menceritakan kepada kami [Ahmad bin Shalih], telah menceritakan kepada kami ['Anbasah], telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab], telah mengabarkan kepadaku [Qabishah bin Dzuaib] bahwa ia mendengar [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam melarang menggabungkan (dalam satu perkawinan) antara seorang wanita dengan bibi (saudara wanita ibu) serta seorang wanita dengan bibi (saudara wanita ayah). "},"1705":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ حَدَّثَنَا خَطَّابُ بْنُ الْقَاسِمِ عَنْ خُصَيْفٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَرِهَ أَنْ يُجْمَعَ بَيْنَ الْعَمَّةِ وَالْخَالَةِ وَبَيْنَ الْخَالَتَيْنِ وَالْعَمَّتَيْنِ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad An Nufaili], telah menceritakan kepada kami [Khaththab bin Al Qasim], dari [Khushaif] dari [Ikrimah] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam bahwa beliau tidak menyukai untuk menggabungkan (dalam satu perkawinan) antara seorang bibi (dari pihak bapak) dengan bibi (dari pihak ibu), serta antara dua bibi (dari pihak ibu) dengan dua bibi (dari pihak ayah). "},"1706":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ الْمِصْرِيُّ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّهُ سَأَلَ عَائِشَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَعَنْ قَوْلِ اللَّهِ تَعَالَى{ وَإِنْ خِفْتُمْ أَلَّا تُقْسِطُوا فِي الْيَتَامَى فَانْكِحُوا مَا طَابَ لَكُمْ مِنْ النِّسَاءِ }قَالَتْ يَا ابْنَ أُخْتِي هِيَ الْيَتِيمَةُ تَكُونُ فِي حِجْرِ وَلِيِّهَا فَتُشَارِكُهُ فِي مَالِهِ فَيُعْجِبُهُ مَالُهَا وَجَمَالُهَا فَيُرِيدُ وَلِيُّهَا أَنْ يَتَزَوَّجَهَا بِغَيْرِ أَنْ يُقْسِطَ فِي صَدَاقِهَا فَيُعْطِيَهَا مِثْلَ مَا يُعْطِيهَا غَيْرُهُ فَنُهُوا أَنْ يَنْكِحُوهُنَّ إِلَّا أَنْ يُقْسِطُوا لَهُنَّ وَيَبْلُغُوا بِهِنَّ أَعْلَى سُنَّتِهِنَّ مِنْ الصَّدَاقِ وَأُمِرُوا أَنْ يَنْكِحُوا مَا طَابَ لَهُمْ مِنْ النِّسَاءِ سِوَاهُنَّ قَالَ عُرْوَةُ قَالَتْ عَائِشَةُ ثُمَّ إِنَّ النَّاسَ اسْتَفْتَوْا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَ هَذِهِ الْآيَةِ فِيهِنَّ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ وَيَسْتَفْتُونَكَ فِي النِّسَاءِ قُلْ اللَّهُ يُفْتِيكُمْ فِيهِنَّ وَمَا يُتْلَى عَلَيْكُمْ فِي الْكِتَابِ فِي يَتَامَى النِّسَاءِ اللَّاتِي لَا تُؤْتُونَهُنَّ مَا كُتِبَ لَهُنَّ وَتَرْغَبُونَ أَنْ تَنْكِحُوهُنَّ }قَالَتْ وَالَّذِي ذَكَرَ اللَّهُ أَنَّهُ يُتْلَى عَلَيْهِمْ فِي الْكِتَابِ الْآيَةُ الْأُولَى الَّتِي قَالَ اللَّهُ سُبْحَانَهُ فِيهَا{ وَإِنْ خِفْتُمْ أَلَّا تُقْسِطُوا فِي الْيَتَامَى فَانْكِحُوا مَا طَابَ لَكُمْ مِنْ النِّسَاءِ }قَالَتْ عَائِشَةُ وَقَوْلُ اللَّهِ عَزَّ وَجَلَّ فِي الْآيَةِ الْآخِرَةِ{ وَتَرْغَبُونَ أَنْ تَنْكِحُوهُنَّ }هِيَ رَغْبَةُ أَحَدِكُمْ عَنْ يَتِيمَتِهِ الَّتِي تَكُونُ فِي حِجْرِهِ حِينَ تَكُونُ قَلِيلَةَ الْمَالِ وَالْجَمَالِ فَنُهُوا أَنْ يَنْكِحُوا مَا رَغِبُوا فِي مَالِهَا وَجَمَالِهَا مِنْ يَتَامَى النِّسَاءِ إِلَّا بِالْقِسْطِ مِنْ أَجْلِ رَغْبَتِهِمْ عَنْهُنَّ قَالَ يُونُسُ وَقَالَ رَبِيعَةُ فِي قَوْلِ اللَّهِ عَزَّ وَجَلَّ{ وَإِنْ خِفْتُمْ أَلَّا تُقْسِطُوا فِي الْيَتَامَى }قَالَ يَقُولُ اتْرُكُوهُنَّ إِنْ خِفْتُمْ فَقَدْ أَحْلَلْتُ لَكُمْ أَرْبَعًا","id":"Telah menceritakan kepada kami [Ahmad bin 'Amr bin As Sarh Al Mishri], telah menceritakan kepada kami [Ibnu Wahb], telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab], ia berkata; telah mengabarkan kepadaku ['Urwah bin Az Zubair] bahwa ia pernah bertanya kepada [Aisyah] radliallahu 'anha istri Rasulullah shallallahu 'alaihi wasallam mengenai firman Allah: \"Dan jika kamu takut tidak akan dapat berlaku adil terhadap (hak-hak) perempuan yang yatim (bilamana kamu mengawininya), maka kawinilah wanita-wanita (lain) yang kamu senangi.\" Dia berkata: wahai anak saudariku, yang dimaksud adalah wanita yatim yang berada di bawah asuhan seorang walinya, kemudian wanita tersebut berserikat dalam hartanya, kemudian walinya tertarik dengan hartanya dan kecantikannya. Kemudian walinya tersebut ingin menikahinya dengan tanpa berbuat adil dalam memberikan maharnya, dia memberikannya sebagaimana yang diberikan orang lain. Maka mereka dilarang untuk menikahi para wanita yatim tersebut kecuali bersikap adil kepada mereka dan memberikan mahar yang lebih tinggi dari mahar mereka yang biasa. Dan para wali tersebut diperintahkan untuk menikahi wanita lain yang mereka senangi. Urwah berkata; Aisyah berkata; kemudian orang-orang meminta fatwa kepada Rasulullah shallallahu 'alaihi wasallam setelah turunnya ayat mengenai mereka ini. Lalu Allah menurunkan \"Dan mereka minta fatwa kepadamu tentang para wanita. Katakanlah: \"Allah memberi fatwa kepadamu tentang mereka, dan apa yang dibacakan kepadamu dalam Al Quran (juga memfatwakan) tentang para wanita yatim yang kamu tidak memberikan kepada mereka apa yang ditetapkan untuk mereka, sedang kamu ingin mengawini mereka).\" Aisyah berkata; yang Allah sebutkan bahwa sesuatu tersebut yang dibacakan atas mereka dalam Al Qur'an adalah ayat pertama yang Allah firmankan: \"(Dan jika kamu takut tidak akan dapat berlaku adil terhadap (hak-hak) perempuan yang yatim (bilamana kamu mengawininya), Maka kawinilah wanita-wanita (lain) yang kamu senangi) \". Aisyah berkata: sedangkan firman Allah dalam ayat terakhir: \"(sedang kamu ingin mengawini mereka), \" adalah ketidaksenangan salah seorang di antara kalian kepada wanita yatimnya yang berada dalam asuhannya ketika kecantikan dan harta mereka sedikit. Maka mereka dilarang menikahi wanita yatim yang ingin dinikahinya karena kecantikan dan hartanya kecuali dengan keadilan karena ketidak senangan kepada mereka. Yunus berkata; Rabi'ah berkata tentang firman Allah: \"(Dan jika kamu takut tidak akan dapat berlaku adil terhadap (hak-hak) perempuan yang yatim (bilamana kamu mengawininya). Maka kawinilah wanita-wanita (lain) yang kamu senangi), \" ia berkata; tinggalkanlah mereka, dan jika kamu khawatir tidak dapat menahan nafsu, maka Aku telah menghalalkan bagi kalian empat wanita. "},"1707":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ بْنِ سَعْدٍ حَدَّثَنِي أَبِي عَنْ الْوَلِيدِ بْنِ كَثِيرٍ حَدَّثَنِي مُحَمَّدُ بْنُ عَمْرِو بْنِ حَلْحَلَةَ الدِّيْلِيُّ أَنَّ ابْنَ شِهَابٍ حَدَّثَهُ أَنَّ عَلِيَّ بْنَ الْحُسَيْنِ حَدَّثَهُأَنَّهُمْ حِينَ قَدِمُوا الْمَدِينَةَ مِنْ عِنْدِ يَزِيدَ بْنِ مُعَاوِيَةَ مَقْتَلَ الْحُسَيْنِ بْنِ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُمَا لَقِيَهُ الْمِسْوَرُ بْنُ مَخْرَمَةَ فَقَالَ لَهُ هَلْ لَكَ إِلَيَّ مِنْ حَاجَةٍ تَأْمُرُنِي بِهَا قَالَ فَقُلْتُ لَهُ لَا قَالَ هَلْ أَنْتَ مُعْطِيَّ سَيْفَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِنِّي أَخَافُ أَنْ يَغْلِبَكَ الْقَوْمُ عَلَيْهِ وَايْمُ اللَّهِ لَئِنْ أَعْطَيْتَنِيهِ لَا يُخْلَصُ إِلَيْهِ أَبَدًا حَتَّى يُبْلَغَ إِلَى نَفْسِي إِنَّ عَلِيَّ بْنَ أَبِي طَالِبٍ رَضِيَ اللَّهُ عَنْهُ خَطَبَ بِنْتَ أَبِي جَهْلٍ عَلَى فَاطِمَةَ رَضِيَ اللَّهُ عَنْهَا فَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَخْطُبُ النَّاسَ فِي ذَلِكَ عَلَى مِنْبَرِهِ هَذَا وَأَنَا يَوْمَئِذٍ مُحْتَلِمٌ فَقَالَ إِنَّ فَاطِمَةَ مِنِّي وَأَنَا أَتَخَوَّفُ أَنْ تُفْتَنَ فِي دِينِهَا قَالَ ثُمَّ ذَكَرَ صِهْرًا لَهُ مِنْ بَنِي عَبْدِ شَمْسٍ فَأَثْنَى عَلَيْهِ فِي مُصَاهَرَتِهِ إِيَّاهُ فَأَحْسَنَ قَالَ حَدَّثَنِي فَصَدَقَنِي وَوَعَدَنِي فَوَفَّى لِي وَإِنِّي لَسْتُ أُحَرِّمُ حَلَالًا وَلَا أُحِلُّ حَرَامًا وَلَكِنْ وَاللَّهِ لَا تَجْتَمِعُ بِنْتُ رَسُولِ اللَّهِ وَبِنْتُ عَدُوِّ اللَّهِ مَكَانًا وَاحِدًا أَبَدًاحَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ فَارِسٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ وَعَنْ أَيُّوبَ عَنْ ابْنِ أَبِي مُلَيْكَةَ بِهَذَا الْخَبَرِ قَالَ فَسَكَتَ عَلِيٌّ عَنْ ذَلِكَ النِّكَاحِ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal], telah menceritakan kepada kami [Ya'qub bin Ibrahim bin Sa'd], telah menceritakan kepadaku [ayahku] dari [Al Walid bin Katsir], telah menceritakan kepadaku [Muhammad bin 'Amr bin Halhalah Ad Dili], bahwa [Ibnu Syihab] telah menceritakan kepadanya bahwa [Ali bin Al Husain] telah menceritakan kepada mereka ketika datang ke Madinah dari sisi Yazid bin Mu'awiyah pada waktu terbunuhnya Al Husain bin Ali radliallahu 'anhuma [Al Miswar bin Makhramah] menemuinya dan berkata; apakah engkau memiliki keperluan kepadaku? Ali bin Al Husain berkata; aku katakan kepadanya; tidak. Ia berkata; apakah engkau akan memberikan pedang Rasulullah shallallahu 'alaihi wasallam kepadaku? Sesungguhnya aku khawatir orang-orang mengalahkanmu untuk mendapatkannya. Demi Allah, apabila engkau memberikannya kepadaku maka tidak akan ada orang yang dapat mengambilnya hingga nyawaku di cabut. Sesungguhnya Ali bin Abu Thalib radliallahu 'anhu meminang anak wanita Abu Jahl sebagai madu Fathimah radliallahu 'anha, lalu aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda ketika sedang berkhutbah kepada orang-orang mengenai hal tersebut di atas mimbar beliau ini, sementara pada saat itu aku adalah orang yang sudah baligh: \"Sesungguhnya Fathimah adalah bagian dariku dan aku khawatir ia terfitnah dalam agamanya.\" Kemudian beliau menyebutkan besan beliau yang berasal dari Bani Abdu Syams, kemudian beliau memujinya dalam berbesanan dengan beliau. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ia berbicara kepadaku dan membenarkanku, berjanji kepadaku dan menepati janjinya kepadaku, sesungguhnya aku tidak mengharamkan sesuatu yang halal dan menghalalkan sesuatu yang haram. Akan tetapi demi Allah, tidak boleh berkumpul anak wanita Rasulullah dan anak wanita musuh Allah dalam satu tempat untuk selamanya.\" Telah menceritakan kepada kami [Muhammad bin Yahya bin Faris], telah menceritakan kepada kami [Abdurrazzaq], telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari ['Urwah] dari [Ayyub] dari [Ibnu Abu Mulaikah] dengan khabar ini. Ia berkata; Ali menahan dari pernikahan tersebut. "},"1708":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ وَقُتَيْبَةُ بْنُ سَعِيدٍ الْمَعْنَى قَالَ أَحْمَدُ حَدَّثَنَا اللَّيْثُ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ عُبَيْدِ اللَّهِ بْنِ أَبِي مُلَيْكَةَ الْقُرَشِيُّ التَّيْمِيُّ أَنَّ الْمِسْوَرَ بْنَ مَخْرَمَةَ حَدَّثَهُأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْمِنْبَرِ يَقُولُ إِنَّ بَنِي هِشَامِ بْنِ الْمُغِيرَةِ اسْتَأْذَنُونِي أَنْ يُنْكِحُوا ابْنَتَهُمْ مِنْ عَلِيِّ بْنِ أَبِي طَالِبٍ فَلَا آذَنُ ثُمَّ لَا آذَنُ ثُمَّ لَا آذَنُ إِلَّا أَنْ يُرِيدَ ابْنُ أَبِي طَالِبٍ أَنْ يُطَلِّقَ ابْنَتِي وَيَنْكِحَ ابْنَتَهُمْ فَإِنَّمَا ابْنَتِي بَضْعَةٌ مِنِّي يُرِيبُنِي مَا أَرَابَهَا وَيُؤْذِينِي مَا آذَاهَاوَالْإِخْبَارُ فِي حَدِيثِ أَحْمَدَ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus], dan [Qutaibah bin Sa'id] secara makna, Ahmad berkata; telah menceritakan kepada kami [Al Laits], telah menceritakan kepadaku [Abdullah bin 'Ubaidullah bin Abu Mulaikah Al Qurasyi At Taimi] bahwa [Al Miswar bin Makhramah] telah menceritakan kepadanya bahwa ia mendengar Rasulullah shallallahu 'alaihi wasallam di atas mimbar berkata: \"Sesungguhnya Bani Hisyam bin Al Mughirah telah meminta izin kepadaku untuk menikahkan anak wanita mereka dengan Ali bin Abu Thalib, maka aku tidak memberikan izin, kemudian tidak memberikan izin, kemudian tidak memberikan izin, kecuali Ibnu Abu Thalib ingin menceraikan anak wanitaku dan menikahi anak wanita mereka. Sesungguhnya anak wanitaku adalah bagian dariku, meragukannya apa yang meragukanku dan menyakitiku apa yang menyakitinya.\" Dan pengabaran ada dalam hadits Ahmad. "},"1709":{"ar":"حَدَّثَنَا مُسَدَّدُ بْنُ مُسَرْهَدٍ حَدَّثَنَا عَبْدُ الْ��َارِثِ عَنْ إِسْمَعِيلَ بْنِ أُمَيَّةَ عَنْ الزُّهْرِيِّ قَالَكُنَّا عِنْدَ عُمَرَ بْنِ عَبْدِ الْعَزِيزِ فَتَذَاكَرْنَا مُتْعَةَ النِّسَاءِ فَقَالَ لَهُ رَجُلٌ يُقَالُ لَهُ رَبِيعُ بْنُ سَبْرَةَ أَشْهَدُ عَلَى أَبِي أَنَّهُ حَدَّثَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْهَا فِي حَجَّةِ الْوَدَاعِ","id":"Telah menceritakan kepada kami [Musaddad bin Musarhad], telah menceritakan kepada kami [Abdul Warits] dari [Isma'il bin Umayyah] dari [Az Zuhri], ia berkata; kami pernah berada di sisi Umar bin Abdul Aziz, kemudian kami saling menyebutkan menikahi wanita secara mut'ah. Lalu terdapat seorang laki-laki yang dipanggil [Rabi' bin Sabrah] yang berkata; aku bersaksi atas [ayahku] bahwa ia telah menceritakan bahwa Rasulullah shallallahu 'alaihi wasallam telah melarang darinya pada saat haji wada'. "},"1710":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ فَارِسٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ رَبِيعِ بْنِ سَبْرَةَ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَرَّمَ مُتْعَةَ النِّسَاءِ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya bin Faris], telah menceritakan kepada kami [Abdurrazzaq], telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Rabi' bin Sabrah] dari [ayahnya] bahwa Nabi shallallahu 'alaihi wasallam telah mengharamkan menikahi wanita secara mut'ah. "},"1711":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ ح و حَدَّثَنَا مُسَدَّدُ بْنُ مُسَرْهَدٍ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ كِلَاهُمَا عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الشِّغَارِزَادَ مُسَدَّدٌ فِي حَدِيثِهِ قُلْتُ لِنَافِعٍ مَا الشِّغَارُ قَالَ يَنْكِحُ ابْنَةَ الرَّجُلِ وَيُنْكِحُهُ ابْنَتَهُ بِغَيْرِ صَدَاقٍ وَيَنْكِحُ أُخْتَ الرَّجُلِ وَيُنْكِحُهُ أُخْتَهُ بِغَيْرِ صَدَاقٍ","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik], dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Musaddad bin Musarhad], telah menceritakan kepada kami [Yahya] dari ['Ubaidullah], keduanya dari [Nafi'] dari [Ibnu Umar] bahwa Rasulullah shallallahu 'alaihi wasallam telah melarang dari nikah syighar. Musaddad menambahkan dalam haditsnya; aku katakan kepada Nafi'; apakah syighar itu? Ia berkata; seseorang menikahi anak wanita seseorang dengan imbalan ia menikahkan anak wanitanya dengan wali dari wanita yang dinikahi tersebut tanpa mahar, serta seseorang menikahi saudari seseorang dan orang tersebut menikahkannya dengan saudarinya tanpa mahar. "},"1712":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ فَارِسٍ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَبِي عَنْ ابْنِ إِسْحَقَ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ هُرْمُزَ الْأَعْرَجُأَنَّ الْعَبَّاسَ بْنَ عَبْدِ اللَّهِ بْنِ الْعَبَّاسِ أَنْكَحَ عَبْدَ الرَّحْمَنِ بْنَ الْحَكَمِ ابْنَتَهُ وَأَنْكَحَهُ عَبْدُ الرَّحْمَنِ ابْنَتَهُ وَكَانَا جَعَلَا صَدَاقًا فَكَتَبَ مُعَاوِيَةُ إِلَى مَرْوَانَ يَأْمُرُهُ بِالتَّفْرِيقِ بَيْنَهُمَا وَقَالَ فِي كِتَابِهِ هَذَا الشِّغَارُ الَّذِي نَهَى عَنْهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya bin Faris], telah menceritakan kepada kami [Ya'qub bin Ibrahim], telah menceritakan kepada kami [ayahku] dari [Ibnu Ishaq], telah menceritakan kepadaku [Abdurrahman bin Hurmuz Al A'raj], bahwa Al Abbas bin Abdullah bin Al Abbas telah menikahkan Abdurrahman bin Al Hakam dengan anak wanitanya, dan Abdurrahman menikahkannya dengan anak wanitanya dan mereka berdua memberikan mahar. Kemudian [Mu'awiyah] menulis surat kepada Marwan dan memerintahkannya agar menceraikan antara keduanya. Dan dalam suratnya ia mengatakan; ini adalah syighar yang dilarang Rasulullah shallallahu 'alaihi wasallam. "},"1713":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنِي إِسْمَعِيلُ عَنْ عَامِرٍ عَنْ الْحَارِثِ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَ إِسْمَعِيلُ وَأُرَاهُ قَدْ رَفَعَهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَعَنَ اللَّهُ الْمُحَلِّلَ وَالْمُحَلَّلَ لَهُحَدَّثَنَا وَهْبُ بْنُ بَقِيَّةَ عَنْ خَالِدٍ عَنْ حُصَيْنٍ عَنْ عَامِرٍ عَنْ الْحَارِثِ الْأَعْوَرِ عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَرَأَيْنَا أَنَّهُ عَلِيٌّ عَلَيْهِ السَّلَام عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَعْنَاهُ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus], telah menceritakan kepada kami [Zuhair], telah menceritakan kepadaku [Isma'il] dari [Amir] dari [Al Harits] dari [Ali] radliallahu 'anhu, Isma'il berkata; aku melihat ia merafa'kan hadits ini kepada Nabi shallallahu 'alaihi wasallam, bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Semoga Allah melaknat muhallil (seseorang yang menikahi wanita yang telah dicerai tiga kali oleh suaminya untuk diceraikan lagi agar halal dinikahi kembali oleh suaminya yang pertama, dan ini dilakukan atas perintah suami pertama tersebut) dan muhallal lahu (seseorang -suami pertama- yang menyurh orang lain agar menikahi isterinya yang telah dicerai tiga kali agar halal dinikahi kembali). Telah menceritakan kepada kami [Wahb bin Baqiyyah] dari [Khalid] dari [Hushain] dari [Amir] dari [Al Harits Al A'war] dari seorang sahabat Nabi shallallahu 'alaihi wasallam, ia berkata; kami melihat bahwa ia adakah [Ali] radliallahu 'anhu, dari Nabi shallallahu 'alaihi wasallam dengan makna yang sama. "},"1714":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ وَعُثْمَانُ بْنُ أَبِي شَيْبَةَ وَهَذَا لَفْظُ إِسْنَادِهِ وَكِلَاهُمَا عَنْ وَكِيعٍ حَدَّثَنَا الْحَسَنُ بْنُ صَالِحٍ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّمَا عَبْدٍ تَزَوَّجَ بِغَيْرِ إِذْنِ مَوَالِيهِ فَهُوَ عَاهِرٌ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] serta [Utsman bin Abu Syaibah], dan ini adalah lafazh sanadnya. Keduanya berasal dari [Waki'], telah menceritakan kepada kami [Al Hasan bin Shalih] dari [Abdullah bin Muhammad bin 'Aqil] dari [Jabir], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapapun budak yang menikah tanpa seizin tuannya, maka ia adalah pezina.\""},"1715":{"ar":"حَدَّثَنَا عُقْبَةُ بْنُ مُكْرَمٍ حَدَّثَنَا أَبُو قُتَيْبَةَ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا نَكَحَ الْعَبْدُ بِغَيْرِ إِذْنِ مَوْلَاهُ فَنِكَاحُهُ بَاطِلٌقَالَ أَبُو دَاوُد هَذَا الْحَدِيثُ ضَعِيفٌ وَهُوَ مَوْقُوفٌ وَهُوَ قَوْلُ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا","id":"Telah menceritakan kepada kami ['Uqbah bin Mukram], telah menceritakan kepada kami [Abu Qutaibah] dari [Abdullah bin Umar], dari [Nafi'], dari [Ibnu Umar] bahwa Nabi Shallallahu 'alaihi sallam bersabda: Apabila seorang budak menikah tanpa izin dari tuannya, maka nikahnya batal. Abu Daud berkata; hadits ini lemah dan mauquf, hanya perkataan Ibnu Umar radliallahu 'anhuma. "},"1716":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَخْطُبُ الرَّجُلُ عَلَى خِطْبَةِ أَخِيهِ","id":"Telah menceritakan kepada kami [Ahmad bin 'Amr bin As Sarh], telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Sa'id bin Al Musayyab] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak boleh seorang laki-laki meminang pinangan saudaranya.\""},"1717":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَخْطُبْ أَحَدُكُمْ عَلَى خِطْبَةِ أَخِيهِ وَلَا يَبِعْ عَلَى بَيْعِ أَخِيهِ إِلَّا بِإِذْنِهِ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali], telah menceritakan kepada kami [Abdullah bin Numair] dari ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah salah seorang diantara kalian meminang pinangan saudaranya, dan janganlah ia menjual sesuatu yang sedang dalam penawaran saudaranya kecuali dengan seizinnya.\""},"1718":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ زِيَادٍ حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَقَ عَنْ دَاوُدَ بْنِ حُصَيْنٍ عَنْ وَاقِدِ بْنِ عَبْدِ الرَّحْمَنِ يَعْنِي ابْنَ سَعْدِ بْنِ مُعَاذٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا خَطَبَ أَحَدُكُمْ الْمَرْأَةَ فَإِنْ اسْتَطَاعَ أَنْ يَنْظُرَ إِلَى مَا يَدْعُوهُ إِلَى نِكَاحِهَا فَلْيَفْعَلْقَالَ فَخَطَبْتُ جَارِيَةً فَكُنْتُ أَتَخَبَّأُ لَهَا حَتَّى رَأَيْتُ مِنْهَا مَا دَعَانِي إِلَى نِكَاحِهَا وَتَزَوُّجِهَا فَتَزَوَّجْتُهَا","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Abdul Wahid bin Ziyad], telah menceritakan kepada kami [Muhammad bin Ishaq], dari [Daud bin Hushain], dari [Waqid bin Abdurrahman bin Sa'd bin Mu'adz] dari [Jabir bin Abdullah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang di antara kalian meminang seorang wanita, jika ia mampu untuk melihat sesuatu yang mendorongannya untuk menikahinya hendaknya ia melakukannya.\" Jabir berkata; kemudian aku meminang seorang gadis dan aku bersembunyi untuk melihatnya hingga aku melihat darinya apa yang mendorongku untuk menikahinya, lalu aku pun menikahinya. "},"1719":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ أَخْبَرَنَا ابْنُ جُرَيْجٍ عَنْ سُلَيْمَانَ بْنِ مُوسَى عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّمَا امْرَأَةٍ نَكَحَتْ بِغَيْرِ إِذْنِ مَوَالِيهَا فَنِكَاحُهَا بَاطِلٌ ثَلَاثَ مَرَّاتٍ فَإِنْ دَخَلَ بِهَا فَالْمَهْرُ لَهَا بِمَا أَصَابَ مِنْهَا فَإِنْ تَشَاجَرُوا فَالسُّلْطَانُ وَلِيُّ مَنْ لَا وَلِيَّ لَهُحَدَّثَنَا الْقَعْنَبِيُّ حَدَّثَنَا ابْنُ لَهِيعَةَ عَنْ جَعْفَرٍ يَعْنِي ابْنَ رَبِيعَةَ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَعْنَاهُ قَالَ أَبُو دَاوُد جَعْفَرٌ لَمْ يَسْمَعْ مِنْ الزُّهْرِيِّ كَتَبَ إِلَيْهِ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir], telah mengabarkan kepada kami [Sufyan], telah mengabarkan kepada kami [Ibnu Juraij], dari [Sulaiman bin Musa] dari [Az Zuhri] dari [Urwah], dari [Aisyah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap wanita yang menikah tanpa seizin walinya, maka pernikahannya adalah batal.\" Beliau mengucapkannya sebanyak tiga kali. Apabila ia tleah mencampurinya maka baginya mahar karena apa yang ia peroleh darinya, kemudian apabila mereka berselisih maka penguasa adalah wali bagi orang yang tidak memiliki wali. Telah menceritakan kepada kami [Al Qa'nabi], telah menceritakan kepada kami [Ibnu Luhai'ah], dari [Ja'far bin Rabi'ah], dari [Ibnu Syihab] dari ['Urwah] dari [Aisyah] dari Nabi shallallahu 'alaihi wasallam semakna dengannya. Abu Daud berkata; jal'far tidak mendengar dari Az Zuhri, ia menulis surat kepadanya. "},"1720":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ قُدَامَةَ بْنِ أَعْيَنَ حَدَّثَنَا أَبُو عُبَيْدَةَ الْحَدَّادُ عَنْ يُونُسَ وَإِسْرَائِيلَ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَىأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا نِكَاحَ إِلَّا بِوَلِيٍّقَالَ أَبُو دَاوُد وَهُوَ يُونُسُ عَنْ أَبِي بُرْدَةَ وَإِسْرَائِيلُ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي بُرْدَةَ","id":"Telah menceritakan kepada kami [Muhammad bin Qudamah bin A'yan], Telah menceritakan kepada kami [Abu 'Ubaidah Al Haddad] dari [Yunus], dan [Israil] dari [Abu Ishaq] dari [Abu Burdah] dari [Abu Musa] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak ada (tidak sah) pernikahan kecuali dengan wali.\" Abu Daud berkata; Yunus meriwayatkan dari Abu Burddah, sedangkan Israil meriwayatkan dari Abu Ishaq dari Abu Burdah. "},"1721":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ فَارِسٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ أُمِّ حَبِيبَةَأَنَّهَا كَانَتْ عِنْدَ ابْنِ جَحْشٍ فَهَلَكَ عَنْهَا وَكَانَ فِيمَنْ هَاجَرَ إِلَى أَرْضِ الْحَبَشَةِ فَزَوَّجَهَا النَّجَاشِيُّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهِيَ عِنْدَهُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya bin Faris], telah menceritakan kepada kami [Abdurrazzaq] dari [Ma'mar] dari [Az Zuhri] dari ['Urwah bin Az Zubai] dari [Ummu Habibah], bahwa ia dahulu adalah isteri Ibnu Jahsy, kemudian Ibnu Jahsy meninggal. Ia adalah di antara orang-orang yang berhijrah ke Negeri Habasyah, kemudian An Najasyi menikahkan Ummu Habibah dengan Rasulullah shallallahu 'alaihi wasallam, sementara Ummu Habibah bersama dengan mereka. "},"1722":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنِي أَبُو عَامِرٍ حَدَّثَنَا عَبَّادُ بْنُ رَاشِدٍ عَنْ الْحَسَنِ حَدَّثَنِي مَعْقِلُ بْنُ يَسَارٍ قَالَكَانَتْ لِي أُخْتٌ تُخْطَبُ إِلَيَّ فَأَتَانِي ابْنُ عَمٍّ لِي فَأَنْكَحْتُهَا إِيَّاهُ ثُمَّ طَلَّقَهَا طَلَاقًا لَهُ رَجْعَةٌ ثُمَّ تَرَكَهَا حَتَّى انْقَضَتْ عِدَّتُهَا فَلَمَّا خُطِبَتْ إِلَيَّ أَتَانِي يَخْطُبُهَا فَقُلْتُ لَا وَاللَّهِ لَا أُنْكِحُهَا أَبَدًا قَالَ فَفِيَّ نَزَلَتْ هَذِهِ الْآيَةُ{ وَإِذَا طَلَّقْتُمْ النِّسَاءَ فَبَلَغْنَ أَجَلَهُنَّ فَلَا تَعْضُلُوهُنَّ أَنْ يَنْكِحْنَ أَزْوَاجَهُنَّ }الْآيَةَ قَالَ فَكَفَّرْتُ عَنْ يَمِينِي فَأَنْكَحْتُهَا إِيَّاهُ","id":"Telah menceritakan kepada kami [Muhammad Al Mutsanna], telah menceritakan kepadaku [Abu 'Amir], telah menceritakan kepada kami ['Abbad bin Rasyid] dari [Al Hasan], telah menceritakan kepadaku [Ma'qil bin Yasar], ia berkata; dahulu aku memiliki seorang saudara wanita, kemudian anak pamanku datang kepadaku, lalu aku menikahkan saudara wanitaku dengannya. Kemudian ia mencerainya, dengan perceraian yang memiliki kemungkinan untuk kembali, kemudian ia membiarkannya hinga habis masa iddahnya. Kemudian tatkala saudariku tersebut dipinang ia datang kepadaku untuk meminangnya. Lalu aku katakan; tidak, demi Allah, aku tidak akan menikahkannya denganmu selamanya. Ma'qil berkata; kemudian turunlah ayat ini mengenai diriku: \"Apabila kamu mentalak isteri-isterimu, lalu habis masa iddahnya, maka janganlah kamu (para wali) menghalangi mereka kawin lagi dengan bakal suaminya.\" Ma'qil berkata; kemudian aku membayar kafarah sumpahku, lalu menikahkan saudariku dengannya. "},"1723":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هِشَامٌ ح و حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا هَمَّامٌ ح و حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ الْمَعْنَى عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ سَمُرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَيُّمَا امْرَأَةٍ زَوَّجَهَا وَلِيَّانِ فَهِيَ لِلْأَوَّلِ مِنْهُمَا وَأَيُّمَا رَجُلٍ بَاعَ بَيْعًا مِنْ رَجُلَيْنِ فَهُوَ لِلْأَوَّلِ مِنْهُمَا","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim], telah menceritakan kepada kami [Hisyam], dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Muhammad bin Katsir], telah mengabarkan kepada kami [Hammam], dan telah diriwayatkan dari jalur yang lain: telah menceritakan kepada kami [Musa bin Isma'il], telah menceritakan kepada kami [Hammad] secara makna, dari [Qatadah] dari [Al Hasan] dari [Samurah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Setiap wanita yang dinikahkan oleh dua orang wali, maka ia menjadi hak bagi wali yang pertama di antara keduanya. Dan setiap orang yang menjual sesuatu kepada dua orang, maka barang tersebut menjadi hak bagi orang pertama (membeli) di antara mereka berdua.\""},"1724":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا أَسْبَاطُ بْنُ مُحَمَّدٍ حَدَّثَنَا الشَّيْبَانِيُّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ الشَّيْبَانِيُّ وَذَكَرَهُ عَطَاءٌ أَبُو الْحَسَنِ السُّوَائِيُّ وَلَا أَظُنُّهُ إِلَّا عَنْ ابْنِ عَبَّاسٍفِي هَذِهِ الْآيَةِ{ لَا يَحِلُّ لَكُمْ أَنْ تَرِثُوا النِّسَاءَ كَرْهًا وَلَا تَعْضُلُوهُنَّ }قَالَ كَانَ الرَّجُلُ إِذَا مَاتَ كَانَ أَوْلِيَاؤُهُ أَحَقَّ بِامْرَأَتِهِ مِنْ وَلِيِّ نَفْسِهَا إِنْ شَاءَ بَعْضُهُمْ زَوَّجَهَا أَوْ زَوَّجُوهَا وَإِنْ شَاءُوا لَمْ يُزَوِّجُوهَا فَنَزَلَتْ هَذِهِ الْآيَةُ فِي ذَلِكَ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'], telah menceritakan kepada kami [Asbath bin Muhammad], Telah menceritakan kepada kami [Asy Syaibani] dari [Ikrimah] dari [Ibnu Abbas], [Asy Syaibani] berkata; dan telah disebutkan oleh ['Atha` Abu Al Hasan As Suwai], dan aku kira berasal dari [Ibnu Abbas] mengenai ayat: \"Tidak halal bagi kamu mempusakai (mewariskan) wanita dengan jalan paksa dan janganlah kamu menyusahkan mereka.\" Ia berkata; dahulu apabila seorang laki-laki meninggal, maka para walinya lebih berhak terhadap istrinya daripada wali wanita tersebut, apabila sebagian mereka berkehendak maka mereka akan menikahkannya dan apabila mereka berkehendak maka mereka tidak menikahkannya. Kemudian turunlah ayat ini mengenai hal tersebut."},"1725":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ ثَابِتٍ الْمَرْوَزِيُّ حَدَّثَنِي عَلِيُّ بْنُ حُسَيْنِ بْنِ وَاقِدٍ عَنْ أَبِيهِ عَنْ يَزِيدَ النَّحْوِيِّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ{ لَا يَحِلُّ لَكُمْ أَنْ تَرِثُوا النِّسَاءَ كَرْهًا وَلَا تَعْضُلُوهُنَّ لِتَذْهَبُوا بِبَعْضِ مَا آتَيْتُمُوهُنَّ إِلَّا أَنْ يَأْتِينَ بِفَاحِشَةٍ مُبَيِّنَةٍ }وَذَلِكَ أَنَّ الرَّجُلَ كَانَ يَرِثُ امْرَأَةَ ذِي قَرَابَتِهِ فَيَعْضُلُهَا حَتَّى تَمُوتَ أَوْ تَرُدَّ إِلَيْهِ صَدَاقَهَا فَأَحْكَمَ اللَّهُ عَنْ ذَلِكَ وَنَهَى عَنْ ذَلِكَحَدَّثَنَا أَحْمَدُ بْنُ شَبُّوَيْهِ الْمَرْوَزِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عُثْمَانَ عَنْ عِيسَى بْنِ عُبَيْدٍ عَنْ عُبَيْدِ اللَّهِ مَوْلَى عُمَرَ عَنْ الضَّحَّاكِ بِمَعْنَاهُ قَالَ فَوَعَظَ اللَّهُ ذَلِكَ","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad bin Tsabit Al Marwazi], telah menceritakan kepadaku [Ali bin Husain bin Waqid] dari [ayahnya] dari [Yazid An Nahwi], dari [Ikrimah] dari [Ibnu Abbas], ia berkata; \"Tidak halal bagi kalian untuk mewariskan wanita secara paksa, dan janganlah kamu menyusahkan mereka karena hendak mengambil kembali sebagian dari apa yang telah kamu berikan kepadanya, terkecuali bila mereka melakukan pekerjaan keji yang nyata.\" Yang demikian itu adalah bahwa seorang laki-laki mewarisi isteri kerabatnya, kemudian ia menyusahkannya hingga meninggal atau wanita tersebut mengembalikan kepadanya maharnya. Kemudian Allah menetapkan dari hal tersebut dan melarang dari hal tersebut. Telah menceritakan kepada kami [Ahmad bin Syabbuwaih Al Marwazi], telah menceritakan kepada kami [Abdullah bin Utsman] dari [Isa bin 'Ubaid] dari ['Ubaidullah] mantan budak Umar, dari [Adh Dhahhak], dengan makna yang sama. Ia berkata; kemudian Allah memberikan nasehat hal tersebut. "},"1726":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَبَانُ حَدَّثَنَا يَحْيَى عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تُنْكَحُ الثَّيِّبُ حَتَّى تُسْتَأْمَرَ وَلَا الْبِكْرُ إِلَّا بِإِذْنِهَا قَالُوا يَا رَسُولَ اللَّهِ وَمَا إِذْنُهَا قَالَ أَنْ تَسْكُتَ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim], Telah menceritakan kepada kami [Aban], telah menceritakan kepada kami [Yahya] dari [Abu Salamah] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Seorang janda tidak boleh dinikahkan hingga ia dimintai pertimbangan, dan seorang gadis tidak boleh dinikahkan kecuali dengan seizinnya.\" Para sahabat bertanya; wahai Rasulullah, bagaimana izinya? Beliau bersabda: \"Dengan cara diam.\""},"1727":{"ar":"حَدَّثَنَا أَبُو كَامِلٍ حَدَّثَنَا يَزِيدُ يَعْنِي ابْنَ زُرَيْعٍ ح و حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ الْمَعْنَى حَدَّثَنِي مُحَمَّدُ بْنُ عَمْرٍو حَدَّثَنَا أَبُو سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تُسْتَأْمَرُ الْيَتِيمَةُ فِي نَفْسِهَا فَإِنْ سَكَتَتْ فَهُوَ إِذْنُهَا وَإِنْ أَبَتْ فَلَا جَوَازَ عَلَيْهَاوَالْإِخْبَارُ فِي حَدِيثِ يَزِيدَ قَالَ أَبُو دَاوُد وَكَذَلِكَ رَوَاهُ أَبُو خَالِدٍ سُلَيْمَانُ بْنُ حَيَّانَ وُمُعَاذُ بْنُ مُعَاذٍ عَنْ مُحَمَّدِ بْنِ عَمْرٍو حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا ابْنُ إِدْرِيسَ عَنْ مُحَمَّدِ بْنِ عَمْرٍو بِهَذَا الْحَدِيثِ بِإِسْنَادِهِ زَادَ فِيهِ قَالَ فَإِنْ بَكَتْ أَوْ سَكَتَتْ زَادَ بَكَتْ قَالَ أَبُو دَاوُد وَلَيْسَ بَكَتْ بِمَحْفُوظٍ وَهُوَ وَهْمٌ فِي الْحَدِيثِ الْوَهْمُ مِنْ ابْنِ إِدْرِيسَ أَوْ مِنْ مُحَمَّدِ بْنِ الْعَلَاءِ قَالَ أَبُو دَاوُد وَرَوَاهُ أَبُو عَمْرٍو ذَكْوَانُ عَنْ عَائِشَةَ قَالَتْ يَا رَسُولَ اللَّهِ إِنَّ الْبِكْرَ تَسْتَحِي أَنْ تَتَكَلَّمَ قَالَ سُكَاتُهَا إِقْرَارُهَا","id":"Telah menceritakan kepada kami [Abu Kamil], telah menceritakan kepada kami [Yazid bin Zurai'], dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepadaku [Musa bin Isma'il], telah menceritakan kepada kami [Hammad] secara makna. Telah menceritakan kepadaku [Muhammad bin 'Amr], telah menceritakan kepada kami [Abu Salamah] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang wanita yatim dimintai pertimbangan terhadap dirinya, apabila ia diam maka hal itu adalah izinnya, dan apabila ia menolak maka tidak boleh memaksakannya.\" Hadits Yazid dengan menggunakan bentuk pengabaran. Abu Daud berkata; begitu juga hadits tersebut diriwayatkan oleh [Abu Khalid Sulaiman bin Hayyan], serta [Mu'adz bin Mu'adz] dari [Muhammad bin 'Amr] telah menceritakan kepada kami [Muhammad bin Al 'Ala`], telah menceritakan kepada kami [Ibnu Idris], dari [Muhammad bin 'Amr] dengan hadits ini dengan sanadnya, dalam hadits tersebut ia menambahkan; beliau berkata: \"Apabila ia menangis atau diam, \" ia menambahkan kata \"menangis.\" Abu Daud berkata; kata \"menangis\" bukanlah sesuatu yang terhafalkan (terjaga), hal itu adalah sebuah kesalahan. Dalam hadits tersebut terdapat kesalahan dari Ibnu Idris, atau dari Muhammad bin Al 'Ala`. Abu Daud berkata; dan hadits tersebut diriwayatkan oleh [Abu 'Amr Dzakwan] dari [Aisyah], ia berkata; wahai Rasulullah, sesungguhnya seorang gadis akan merasa malu untuk berbicara. Beliau berkata; diamnya adalah persetujuannya. "},"1728":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُعَاوِيَةُ بْنُ هِشَامٍ عَنْ سُفْيَانَ عَنْ إِسْمَعِيلَ بْنِ أُمَيَّةَ حَدَّثَنِي الثِّقَةُ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ آمِرُوا النِّسَاءَ فِي بَنَاتِهِنَّ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah], telah menceritakan kepada kami [Mu'awiyah bin Hisyam], dari [Sufyan], dari [Isma'il bin Umayyah], telah menceritakan kepadaku [orang yang tsiqah] dari [Ibnu Umar], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ajaklah para wanita untuk bermusyawarah mengenai anak-anak wanita mereka!\""},"1729":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا حُسَيْنُ بْنُ مُحَمَّدٍ حَدَّثَنَا جَرِيرُ بْنُ حَازِمٍ عَنْ أَيُّوبَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ جَارِيَةً بِكْرًا أَتَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَتْ أَنَّ أَبَاهَا زَوَّجَهَا وَهِيَ كَارِهَةٌ فَخَيَّرَهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَحَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ عِكْرِمَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذَا الْحَدِيثِ قَالَ أَبُو دَاوُد لَمْ يَذْكُرْ ابْنَ عَبَّاسٍ وَكَذَلِكَ رَوَاهُ النَّاسُ مُرْسَلًا مَعْرُوفٌ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah], telah menceritakan kepada kami [Husain bin Muhammad], telah menceritakan kepada kami [Jarir bin Hazim], dari [Ayyub], dari [Ikrimah] dari [Ibnu Abbas], bahwa seorang gadis datang kepada Nabi shallallahu 'alaihi wasallam dan menyebutkan bahwa ayahnya telah menikahkannya sementara ia tidak senang. Kemudian beliau beliau memberikan pilihan. Telah menceritakan kepada kami [Muhammad bin 'Ubaid], telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Ikrimah] dari Nabi shallallahu 'alaihi wasallam dengan hadits ini. Abu Daud berkata; Muhammad bin 'Ubaid tidak menyebutkan Ibnu Abbas. Begitu pula hadits tersebut telah diriwayatkan oleh beberapa ulama secara mursal adalah sesuatu yang telah diketahui. "},"1730":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ وَعَبْدُ اللَّهِ بْنُ مَسْلَمَةَ قَالَا أَخْبَرَنَا مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ الْفَضْلِ عَنْ نَافِعِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْأَيِّمُ أَحَقُّ بِنَفْسِهَا مِنْ وَلِيِّهَا وَالْبِكْرُ تُسْتَأْذَنُ فِي نَفْسِهَا وَإِذْنُهَا صُمَاتُهَاوَهَذَا لَفْظُ الْقَعْنَبِيِّ حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا سُفْيَانُ عَنْ زِيَادِ بْنِ سَعْدٍ عَنْ عَبْدِ اللَّهِ بْنِ الْفَضْلِ بِإِسْنَادِهِ وَمَعْنَاهُ قَالَ الثَّيِّبُ أَحَقُّ بِنَفْسِهَا مِنْ وَلِيِّهَا وَالْبِكْرُ يَسْتَأْمِرُهَا أَبُوهَا قَالَ أَبُو دَاوُد أَبُوهَا لَيْسَ بِمَحْفُوظٍ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus], serta [Abdullah bin Maslamah], mereka berkata; telah mengabarkan kepada kami [Malik], dari [Abdullah bin Al Fadhl] dari [Nafi' bin Jubair] dari [Ibnu Abbas], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang janda lebih berhak terhadap dirinya daripada walinya, seorang gadis dimintai izinnya dalam urusan dirinya, dan izinnya adalah diamnya.\" Lafazh ini adalah lafazh Al Qa'nabi. Telah menceritakan kepada kami [Ahmad bin Hanbal], telah menceritakan kepada kami [Sufyan], dari [Ziyad bin Sa'd] dari [Abdullah bin Al Fadhl] dengan sanad serta maknanya, beliau bersabda: \"Seorang janda lebih berhak terhadap dirinya daripada walinya, dan seorang gadis dimintai pertimbangannya oleh ayahnya.\" Abu Daud berkata; kata \"ayahnya\" bukanlah sesuatu yang dihafal (dijaga). "},"1731":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ صَالِحِ بْنِ كَيْسَانَ عَنْ نَافِعِ بْنِ جُبَيْرِ بْنِ مُطْعِمٍ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيْسَ لِلْوَلِيِّ مَعَ الثَّيِّبِ أَمْرٌ وَالْيَتِيمَةُ تُسْتَأْمَرُ وَصَمْتُهَا إِقْرَارُهَا","id":"Telah menceritakan kepada kami [Al Hasan bin Ali], telah menceritakan kepada kami [Abdurrazzaq], telah mengabarkan kepada kami [Ma'mar] dari [Shalih bin Kaisan] dari [Nafi' bin Jubair bin Muth'im] dari [Ibnu Abbas] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang wali tidak memiliki kuasa memaksa terhadap seorang janda, dan seorang wanita yatim dimintai pertimbangannya, dan diamnya adalah persetujuannya.\""},"1732":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ عَنْ عَبْدِ الرَّحْمَنِ وَمُجَمِّعٍ ابْنَيْ يَزِيدَ الْأَنْصَارِيَّيْنِ عَنْ خَنْسَاءَ بِنْتِ خِذَامٍ الْأَنْصَارِيَّةِأَنَّ أَبَاهَا زَوَّجَهَا وَهِيَ ثَيِّبٌ فَكَرِهَتْ ذَلِكَ فَجَاءَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَتْ ذَلِكَ لَهُ فَرَدَّ نِكَاحَهَا","id":"Telah menceritakan kepada kami [Al Qa'nabi], dari [Malik], dari [Abdurrahman bin Al Qasim], dari [ayahnya] dari [Abdurrahman] dan [Mujammi'], keduanya adalah anak Yazid Al Anshari dari [Khansa` binti Khidzam Al Anshariyyah], bahwa ayahnya telah menikahkannya sementara ia adalah seorang janda, kemudian ia tidak menyukai hal tersebut, lalu datang kepada Rasulullah shallallahu 'alaihi wasallam dan menceritakan hal tersebut kepada beliau. Maka beliau menolak pernikahannya."},"1733":{"ar":"حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ غِيَاثٍ حَدَّثَنَا حَمَّادٌ حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَأَنَّ أَبَا هِنْدٍ حَجَمَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْيَافُوخِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا بَنِي بَيَاضَةَ أَنْكِحُوا أَبَا هِنْدٍ وَأَنْكِحُوا إِلَيْهِ وَقَالَ وَإِنْ كَانَ فِي شَيْءٍ مِمَّا تَدَاوُونَ بِهِ خَيْرٌ فَالْحِجَامَةُ","id":"Telah menceritakan kepada kami [Abdul Wahid bin Ghiyats], telah menceritakan kepada kami [Hammad], telah menceritakan kepada kami [Muhammad bin 'Amr], dari [Abu Salamah] dari [Abu Hurairah], bahwa Abu Hindun telah membekam Nabi shallallahu 'alaihi wasallam pada bagian ubun-ubun, kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Wahai Bani Bayadhah, nikahkanlah Abu Hindun, dan nikahkanlah anak-anak wanitanya.\" Dan beliau bersabda: \"Seandainya ada sesuatu yang lebih baik yang kalian gunakan untuk berobat, maka sesuatu tersebut adalah berbekam.\""},"1734":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ وَمُحَمَّدُ بْنُ الْمُثَنَّى الْمَعْنَى قَالَا حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ بْنِ مِقْسَمٍ الثَّقَفِيُّ مِنْ أَهْلِ الطَّائِفِ حَدَّثَتْنِي سَارَةُ بِنْتُ مِقْسَمٍ أَنَّهَا سَمِعَتْ مَيْمُونَةَ بِنْتَ كَرْدَمٍ قَالَتْخَرَجْتُ مَعَ أَبِي فِي حَجَّةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَنَا إِلَيْهِ أَبِي وَهُوَ عَلَى نَاقَةٍ لَهُ فَوَقَفَ لَهُ وَاسْتَمَعَ مِنْهُ وَمَعَهُ دِرَّةٌ كَدِرَّةِ الْكُتَّابِ فَسَمِعْتُ الْأَعْرَابَ وَالنَّاسَ وَهُمْ يَقُولُونَ الطَّبْطَبِيَّةَ الطَّبْطَبِيَّةَ الطَّبْطَبِيَّةَ فَدَنَا إِلَيْهِ أَبِي فَأَخَذَ بِقَدَمِهِ فَأَقَرَّ لَهُ وَوَقَفَ عَلَيْهِ وَاسْتَمَعَ مِنْهُ فَقَالَ إِنِّي حَضَرْتُ جَيْشَ عِثْرَانَ قَالَ ابْنُ الْمُثَنَّى جَيْشَ غِثْرَانَ فَقَالَ طَارِقُ بْنُ الْمُرَقَّعِ مَنْ يُعْطِينِي رُمْحًا بِثَوَابِهِ قُلْتُ وَمَا ثَوَابُهُ قَالَ أُزَوِّجُهُ أَوَّلَ بِنْتٍ تَكُونُ لِي فَأَعْطَيْتُهُ رُمْحِي ثُمَّ غِبْتُ عَنْهُ حَتَّى عَلِمْتُ أَنَّهُ قَدْ وُلِدَ لَهُ جَارِيَةٌ وَبَلَغَتْ ثُمَّ جِئْتُهُ فَقُلْتُ لَهُ أَهْلِي جَهِّزْهُنَّ إِلَيَّ فَحَلَفَ أَنْ لَا يَفْعَلَ حَتَّى أُصْدِقَهُ صَدَاقًا جَدِيدًا غَيْرَ الَّذِي كَانَ بَيْنِي وَبَيْنَهُ وَحَلَفْتُ لَا أُصْدِقُ غَيْرَ الَّذِي أَعْطَيْتُهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَبِقَرْنِ أَيِّ النِّسَاءِ هِيَ الْيَوْمَ قَالَ قَدْ رَأَتْ الْقَتِيرَ قَالَ أَرَى أَنْ تَتْرُكَهَا قَالَ فَرَاعَنِي ذَلِكَ وَنَظَرْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا رَأَى ذَلِكَ مِنِّي قَالَ لَا تَأْثَمُ وَلَا يَأْثَمُ صَاحِبُكَقَالَ أَبُو دَاوُد الْقَتِيرُ الشَّيْبُ حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي إِبْرَاهِيمُ بْنُ مَيْسَرَةَ أَنَّ خَالَتَهُ أَخْبَرَتْهُ عَنِ امْرَأَةٍ قَالَتْ هِيَ مُصَدَّقَةٌ امْرَأَةُ صِدْقٍ قَالَتْ بَيْنَا أَبِي فِي غَزَاةٍ فِي الْجَاهِلِيَّةِ إِذْ رَمِضُوا فَقَالَ رَجُلٌ مَنْ يُعْطِينِي نَعْلَيْهِ وَأُنْكِحُهُ أَوَّلَ بِنْتٍ تُولَدُ لِي فَخَلَعَ أَبِي نَعْلَيْهِ فَأَلْقَاهُمَا إِلَيْهِ فَوُلِدَتْ لَهُ جَارِيَةٌ فَبَلَغَتْ وَذَكَرَ نَحْوَهُ لَمْ يَذْكُرْ قِصَّةَ الْقَتِيرِ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali], serta [Muhammad bin Al Mutsanna] secara makna, mereka berkata; telah menceritakan kepada kami [Yazid bin Harun], telah mengabarkan kepada kami [Abdullah bin Yazid bin Miqsam Ats Tsaqafi] yang merupakan penduduk Thaif, telah menceritakan kepadaku [Sarah binti Miqsam] bahwa ia mendengar [Maimunah binti Kardam] berkata; aku pernah keluar bersama ayahku pada saat Rasulullah shallallahu 'alaihi wasallam melakukan haji. Aku melihat Rasulullah shallallahu 'alaihi wasallam, kemudian ayahku mendekat kepada beliau sementera beliau berada di atas untanya. Kemudian beliau berhenti dan mendengar darinya dengan membawa cambuk seperti cambuk orang mengajar anak-anak. Kemudian aku mendengar orang-orang badui serta orang-orang yang lain mereka berkata; jangan bersuara! Jangan bersuara! Jangan bersuara! Kemudian ayahku mendekat kepada beliau, mengambil posisi di hadapan beliau, dan mengakui risalah serta kenabian beliau dan beliau berhenti serta mendengarkan darinya. Kemudian ia berkata; sesungguhnya aku telah menghadiri pasukan 'Itsran -Ibnu Al Mutsanna menyebutnya; pasukan Ghitsran- kemudian Thariq bin Al Muraqqa' berkata; siapa yang memberiku tombak akan mendapatkan balasannya. Aku katakan; apakah balasannya? Ia berkata; aku akan menikahkannya dengan anak perempuanku yang pertama. Lalu aku memberikan tombakku kepadanya, kemudian aku menghilang darinya hingga aku mengetahui bahwa anak wanitanya telah lahir dan telah mencapai usia baligh. Kemudian aku mendatanginya dan aku katakan kepadanya; persiapkan isteriku agar datang kepadaku. Kemudian ia bersumpah bahwa ia tidak akan melakukannya kecuali aku memberinya mahar baru bukan mahar yang dahulu aku berikan kepadanya, dan aku pun bersumpah tidak akan memberikan mahar selain yang telah aku berikan kepadanya. Kemudian Rasulullah shallallahu 'alaihi wasallam berkata: \"Seumuran wanita manakah ia sekarang?\" Ia berkata; ia telah melihat uban (sudah dewasa). Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku berpendapat agar Engkau meninggalkannya.\" Kardam berkata; hal tersebut mengagetkanku, dan aku melihat kepada Rasulullah shallallahu 'alaihi wasallam. Kemudian tatkala beliau melihat rasa kagetku beliau berkata: Engkau tidak berdosa dan sahabatmu tidak berdosa.\" Abu Daud berkata; Al Qatir adalah uban. Telah menceritakan kepada kami [Ahmad bin Shalih], telah menceritakan kepada kami [Abdurrazzaq], telah mengabarkan kepada kami [Ibnu Juraij], telah mengabarkan kepadaku [Ibrahim bin Maisarah], bahwa [bibinya] telah mengabarkan kepadanya dari [seorang wanita], ia berkata; ia adalah wanita yang dipercaya dan jujur, ia berkata; ketika ayahku berada dalam sebuah peperangan pada masa jahiliyah tiba-tiba mereka merasakan panas di kaki mereka, kemudian seorang laki-laki berkata; siapa yang memberikan kedua sandalnya kepadaku maka aku akan menikahkannya dengan anak wanitaku yang lahir pertama. Lalu aku melemparkan kedua sandalku kepadanya, kemudian ia memiliki anak wanita yang telah berusia baligh, dan Ahmad bin Shalih menyebutkan seperti itu dan tidak menyebutkan kisah mengenai uban."},"1735":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ حَدَّثَنَا يَزِيدُ بْنُ الْهَادِ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ أَبِي سَلَمَةَ قَالَسَأَلْتُ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا عَنْ صَدَاقِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ ثِنْتَا عَشْرَةَ أُوقِيَّةً وَنَشٌّ فَقُلْتُ وَمَا نَشٌّ قَالَتْ نِصْفُ أُوقِيَّةٍ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad An Nufaili], telah menceritakan kepada kami [Abdul Aziz bin Muhammad], telah menceritakan kepada kami [Yazid bin Al Had] dari [Muhammad bin Ibrahim] dari [Abu Salamah]. Ia berkata; aku bertanya kepada [Aisyah] radliallahu 'anha mengenai mahar Nabi shallallahu 'alaihi wasallam, ia berkata; dua belas uqiyah dan nusy. Kemudian aku katakan; apakah nusy itu? Ia berkata; setengah uqiyah. "},"1736":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ مُحَمَّدٍ عَنْ أَبِي الْعَجْفَاءِ السُّلَمِيِّ قَالَخَطَبَنَا عُمَرُ رَحِمَهُ اللَّهُ فَقَالَ أَلَا لَا تُغَالُوا بِصُدُقِ النِّسَاءِ فَإِنَّهَا لَوْ كَانَتْ مَكْرُمَةً فِي الدُّنْيَا أَوْ تَقْوَى عِنْدَ اللَّهِ لَكَانَ أَوْلَاكُمْ بِهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا أَصْدَقَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ امْرَأَةً مِنْ نِسَائِهِ وَلَا أُصْدِقَتْ امْرَأَةٌ مِنْ بَنَاتِهِ أَكْثَرَ مِنْ ثِنْتَيْ عَشْرَةَ أُوقِيَّةً","id":"Telah menceritakan kepada kami [Muhammad bin 'Ubaid], telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Muhammad] dari [Abu Al 'Ajfa` As Sulami], ia berkata; [Umar] radliallahu 'anhu berkhutbah kepada kami, ia berkata; ketahuilah, janganlah kalian berlebihan dalam memberi mahar kepada para wanita, seandainya hal itu adalah sebuah kemuliaan di dunia atau sebagai bentuk ketakwaan di sisi Allah, niscaya orang yang paling dahulu melakukannya adalah Nabi shallallahu 'alaihi wasallam, tidaklah Rasulullah shallallahu 'alaihi wasallam memberikan mahar kepada salah seorang dari isteri-isteri beliau, dan tidak juga diberikan kepada puteri-puteri beliau jumlah mahar yang melebihi dua belas uqiyah. "},"1737":{"ar":"حَدَّثَنَا حَجَّاجُ بْنُ أَبِي يَعْقُوبَ الثَّقَفِيُّ حَدَّثَنَا مُعَلَّى بْنُ مَنْصُورٍ حَدَّثَنَا ابْنُ الْمُبَارَكِ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ أُمِّ حَبِيبَةَأَنَّهَا كَانَتْ تَحْتَ عُبَيْدِ اللَّهِ بْنِ جَحْشٍ فَمَاتَ بِأَرْضِ الْحَبَشَةِ فَزَوَّجَهَا النَّجَاشِيُّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَمْهَرَهَا عَنْهُ أَرْبَعَةَ آلَافٍ وَبَعَثَ بِهَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَعَ شُرَحْبِيلَ ابْنِ حَسَنَةَقَالَ أَبُو دَاوُد حَسَنَةُ هِيَ أُمُّهُ","id":"Telah menceritakan kepada kami [Hajjaj bin Ya'qub Ats Tsaqafi], telah menceritakan kepada kami [Mu'alla bin Manshur], telah menceritakan kepada kami [Ibnu Al Mubarak], telah menceritakan kepada kami [Ma'mar], dari [Az Zuhri] dari ['Urwah] dari [Ummu Habibah] bahwa ia pernah menjadi isteri 'Ubaidullah bin Jahsy, kemudian ia meninggal di Negeri Habasyah, lalu An Najasyi menikahkannya dengan Nabi shallallahu 'alaihi wasallam. An Najasyi memberikan mahar empat ribu, dan ia mengirimnya kepada Rasulullah shallallahu 'alaihi wasallam bersama Syurahbil bin Hasanah. Abu Daud berkata; Hasanah adalah ibunya. "},"1738":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ حَاتِمِ بْنِ بَزِيعٍ حَدَّثَنَا عَلِيُّ بْنُ الْحَسَنِ بْنِ شَقِيقٍ عَنْ ابْنِ الْمُبَارَكِ عَنْ يُونُسَ عَنْ الزُّهْرِيِّأَنَّ النَّجَاشِيَّ زَوَّجَ أُمَّ حَبِيبَةَ بِنْتَ أَبِي سُفْيَانَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى صَدَاقِ أَرْبَعَةِ آلَافِ دِرْهَمٍ وَكَتَبَ بِذَلِكَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَبِلَ","id":"Telah menceritakan kepada kami [Muhammad bin Hatim bin Bazi'], telah menceritakan kepada kami [Ali bin Al Hasan bin Syaqiq] dari [Ibnu Al Mubarak] dari [Yunus] dari [Az Zuhri] bahwa An Najasyi telah menikahkan Ummu Habibah binti Abu Sufyan dengan Rasulullah shallallahu 'alaihi wasallam dengan mahar empat ribu dirham, dan menuliskan hal tersebut kepada Rasulullah shallallahu 'alaihi wasallam, kemudian beliau menerimanya. "},"1739":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ ثَابِتٍ الْبُنَانِيِّ وَحُمَيْدٍ عَنْ أَنَسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى عَبْدَ الرَّحْمَنِ بْنَ عَوْفٍ وَعَلَيْهِ رَدْعُ زَعْفَرَانٍ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَهْيَمْ فَقَالَ يَا رَسُولَ اللَّهِ تَزَوَّجْتُ امْرَأَةً قَالَ مَا أَصْدَقْتَهَا قَالَ وَزْنَ نَوَاةٍ مِنْ ذَهَبٍ قَالَ أَوْلِمْ وَلَوْ بِشَاةٍ","id":"Telah menceritakan kepada kami [Musa bin Isma'il], telah menceritakan kepada kami [Hammad] dari [Tsabit Al Bunani], serta [Humaid] dari [Anas] bahwa Rasulullah shallallahu 'alaihi wasallam melihat Abdurrahman bin 'Auf padanya terdapat bekas minyak za'faran. Kemudian Nabi shallallahu 'alaihi wasallam berkata: \"Apakah ini?\" Lalu ia berkata; wahai Rasulullah, aku telah menikahi seorang wanita. Beliau berkata: \"Mahar apakah yang telah engkau berikan kepadanya?\" Ia berkata; emas sebesar biji kurma. Beliau berkata: \"Rayakanlah (adakanlah walimah) walaupun hanya dengan menyembelih satu ekor kambing.\""},"1740":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ جِبْرَائِيلَ الْبَغْدَادِيُّ أَخْبَرَنَا يَزِيدُ أَخْبَرَنَا مُوسَى بْنُ مُسْلِمِ بْنِ رُومَانَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَعْطَى فِي صَدَاقِ امْرَأَةٍ مِلْءَ كَفَّيْهِ سَوِيقًا أَوْ تَمْرًا فَقَدْ اسْتَحَلَّقَالَ أَبُو دَاوُد رَوَاهُ عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ صَالِحِ بْنِ رُومَانَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ مَوْقُوفًا وَرَوَاهُ أَبُو عَاصِمٍ عَنْ صَالِحِ بْنِ رُومَانَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَ كُنَّا عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَسْتَمْتِعُ بِالْقُبْضَةِ مِنْ الطَّعَامِ عَلَى مَعْنَى الْمُتْعَةِ قَالَ أَبُو دَاوُد رَوَاهُ ابْنُ جُرَيْجٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ عَلَى مَعْنَى أَبِي عَاصِمٍ","id":"Telah menceritakan kepada kami [Ishaq bin Jibrail Al Baghdadi], telah mengabarkan kepada kami [Yazid], telah mengabarkan kepada kami [Musa bin Muslim bin Ruman], dari [Abu Az Zubair] dari [Jabir bin Abdullah] bahwa Nabi shallallahu 'alaihi wasallam berkata: \"Barangsiapa yang memberi mahar seorang wanita berupa gandum atau kurma sepenuh dua telapak tangannya, maka (pemberiannya) itu ia telah menghalalkannya (menjadi mahar bagi istrinya)).\" Abu Daud berkata; hadits tersebut diriwayatkan oleh [Abdurrahman bin Mahdi] dari [Shalih bin Ruman] dari [Abu Az Zubair] dari [Jabir] secara mauquf. Dan diriwayatkan oleh [Abu 'Ashim] dari [Shalih bin Ruman] dari [Abu Az Zubair] dari [Jabir], ia berkata; kami pada zaman Rasulullah shallallahu 'alaihi wasallam menikah mut'ah dengan memberikan mahar satu genggam makanan. Abu Daud berkata; hadits tersebut diriwayatkan oleh [Ibnu Juraij] dari [Abu Az Zubair] dari [Jabir] seperti ma'na hadits Abu 'Ashim. "},"1741":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ أَبِي حَازِمِ بْنِ دِينَارٍ عَنْ سَهْلِ بْنِ سَعْدٍ السَّاعِدِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَاءَتْهُ امْرَأَةٌ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنِّي قَدْ وَهَبْتُ نَفْسِي لَكَ فَقَامَتْ قِيَامًا طَوِيلًا فَقَامَ رَجُلٌ فَقَالَ يَا رَسُولَ اللَّهِ زَوِّجْنِيهَا إِنْ لَمْ يَكُنْ لَكَ بِهَا حَاجَةٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلْ عِنْدَكَ مِنْ شَيْءٍ تُصْدِقُهَا إِيَّاهُ فَقَالَ مَا عِنْدِي إِلَّا إِزَارِي هَذَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّكَ إِنْ أَعْطَيْتَهَا إِزَارَكَ جَلَسْتَ وَلَا إِزَارَ لَكَ فَالْتَمِسْ شَيْئًا قَالَ لَا أَجِدُ شَيْئًا قَالَ فَالْتَمِسْ وَلَوْ خَاتَمًا مِنْ حَدِيدٍ فَالْتَمَسَ فَلَمْ يَجِدْ شَيْئًا فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَهَلْ مَعَكَ مِنْ الْقُرْآنِ شَيْءٌ قَالَ نَعَمْ سُورَةُ كَذَا وَسُورَةُ كَذَا لِسُوَرٍ سَمَّاهَا فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ زَوَّجْتُكَهَا بِمَا مَعَكَ مِنْ الْقُرْآنِحَدَّثَنَا أَحْمَدُ بْنُ حَفْصِ بْنِ عَبْدِ اللَّهِ حَدَّثَنِي أَبِي حَفْصُ بْنُ عَبْدِ اللَّهِ حَدَّثَنِي إِبْرَاهِيمُ بْنُ طَهْمَانَ عَنْ الْحَجَّاجِ بْنِ الْحَجَّاجِ الْبَاهِلِيِّ عَنْ عِسْلٍ عَنْ عَطَاءِ بْنِ أَبِي رَبَاحٍ عَنْ أَبِي هُرَيْرَةَ نَحْوَ هَذِهِ الْقِصَّةِ لَمْ يَذْكُرْ الْإِزَارَ وَالْخَاتَمَ فَقَالَ مَا تَحْفَظُ مِنْ الْقُرْآنِ قَالَ سُورَةَ الْبَقَرَةِ أَوْ الَّتِي تَلِيهَا قَالَ فَقُمْ فَعَلِّمْهَا عِشْرِينَ آيَةً وَهِيَ امْرَأَتُكَ حَدَّثَنَا هَارُونُ بْنُ زَيْدِ بْنِ أَبِي الزَّرْقَاءِ حَدَّثَنَا أَبِي حَدَّثَنَا مُحَمَّدُ بْنُ رَاشِدٍ عَنْ مَكْحُولٍ نَحْوَ خَبَرِ سَهْلٍ قَالَ وَكَانَ مَكْحُولٌ يَقُولُ لَيْسَ ذَلِكَ لِأَحَدٍ بَعْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Abu Hazim bin Dinar] dari [Sahl bin Sa'd As Sa'idi] bahwa Rasulullah shallallahu 'alaihi wasallam didatangi oleh seorang wanita seraya berkata; wahai Rasulullah, aku menghibahkan diriku kepadamu. Kemudian wanita tersebut berdiri lama, lalu terdapat seorang laki-laki yang berdiri dan berkata; wahai Rasulullah, nikahkan aku dengannya apabila engkau tidak butuh kepadanya. Kemudian Rasulullah shallallahu 'alaihi wasallam berkata: \"Apakah kamu memiliki sesuatu yang dapat kamu berikan kepadanya sebagai mahar?\" Orang tersebut berkata; aku tidak memiliki sesuatu kecuali sarungku ini. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila kamu memberikan sarungmu, maka kamu akan telanjang dan kamu tidak memiliki sarung, carilah sesuatu!\" Orang tersebut berkata; aku tidak mendapatkan sesuatu. Beliau berkata: \"Carilah (yang lain) walaupun hanya sebuah cincin besi!\" Kemudian orang tersebut mencari dan tidak mendapatkan sesuatu pun. Kemudian Rasulullah shallallahu 'alaihi wasallam berkata kepadanya: \"Apakah engkau hafal sebagian dari Al Qur'an?\" Orang tersebut berkata; ya, surat ini dan surat ini. Ia menyebutkan surat yang telah ia hafal. Kemudian Rasulullah shallallahu 'alaihi wasallam berkata kepadanya: \"Aku telah menikahkanmu dengan apa yang engkau miliki (hafal) dari Al Qur'an.\" Telah menceritakan kepada kami [Ahmad bin Hafsh bin Abdullah], telah menceritakan kepadaku [Abu Hafsh bin Abdullah], telah menceritakan kepadaku [Ibrahim bin Thahman] dari [Al Hajjaj bin Al Hajjaj Al Bahili] dari ['Asl] dari ['Atha` bin Abu Rabah] dari [Abu Hurairah] seperti kisah ini, namun ia tidak menyebutkan sarung dan cincin. Beliau berkata: \"Surat apakah yang engkau hafal dari Al Qur'an?\" Orang tersebut berkata; Surat Al Baqarah, atau surat yang setelahnya. Beliau berkata: \"Berdirilah dan ajarkanlah dua puluh ayat kepadanya! Ia adalah isterimu.\" Telah menceritakan kepada kami [Harun bin Zaid bin Abu Az Zarqa`], telah menceritakan kepada kami [ayahku], telah menceritakan kepada kami [Muhammad bin Rasyid] dari [Makhul] seperti hadits Sahl. Ia berkata; dan Makhul pernah berkata; hal tersebut bukan hal bagi seseorang setelah Rasulullah shallallahu 'alaihi wasallam. "},"1742":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ سُفْيَانَ عَنْ فِرَاسٍ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ عَنْ عَبْدِ اللَّهِ فِي رَجُلٍ تَزَوَّجَ امْرَأَةً فَمَاتَ عَنْهَا وَلَمْ يَدْخُلْ بِهَا وَلَمْ يَفْرِضْ لَهَا الصَّدَاقَ فَقَالَ لَهَا الصَّدَاقُ كَامِلًا وَعَلَيْهَا الْعِدَّةُ وَلَهَا الْمِيرَاثُفَقَالَ مَعْقِلُ بْنُ سِنَانٍ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى بِهِ فِي بِرْوَعَ بِنْتِ وَاشِقٍحَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ وَابْنُ مَهْدِيٍّ عَنْ سُفْيَانَ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ وَسَاقَ عُثْمَانُ مِثْلَهُ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا سَعِيدُ بْنُ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ خِلَاسٍ وَأَبِي حَسَّانَ عَنْ عَبْدِ اللَّهِ بْنِ عُتْبَةَ بْنِ مَسْعُودٍ أَنَّ عَبْدَ اللَّهِ بْنَ مَسْعُودٍ أُتِيَ فِي رَجُلٍ بِهَذَا الْخَبَرِ قَالَ فَاخْتَلَفُوا إِلَيْهِ شَهْرًا أَوْ قَالَ مَرَّاتٍ قَالَ فَإِنِّي أَقُولُ فِيهَا إِنَّ لَهَا صَدَاقًا كَصَدَاقِ نِسَائِهَا لَا وَكْسَ وَلَا شَطَطَ وَإِنَّ لَهَا الْمِيرَاثَ وَعَلَيْهَا الْعِدَّةُ فَإِنْ يَكُ صَوَابًا فَمِنْ اللَّهِ وَإِنْ يَكُنْ خَطَأً فَمِنِّي وَمِنْ الشَّيْطَانِ وَاللَّهُ وَرَسُولُهُ بَرِيئَانِ فَقَامَ نَاسٌ مِنْ أَشْجَعَ فِيهِمْ الْجَرَّاحُ وَأَبُو سِنَانٍ فَقَالُوا يَا ابْنَ مَسْعُودٍ نَحْنُ نَشْهَدُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَاهَا فِينَا فِي بِرْوَعَ بِنْتِ وَاشِقٍ وَإِنَّ زَوْجَهَا هِلَالُ بْنُ مُرَّةَ الْأَشْجَعِيُّ كَمَا قَضَيْتَ قَالَ فَفَرِحَ عَبْدُ اللَّهِ بْنُ مَسْعُودٍ فَرَحًا شَدِيدًا حِينَ وَافَقَ قَضَاؤُهُ قَضَاءَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah], telah menceritakan kepada kami [Abdurrahman bin Mahdi] dari [Sufyan] dari [Firas] dari [Asy Sya'bi] dari [Masruq] dari [Abdullah] mengenai seorang laki-laki yang menikahi seorang wanita kemudian lelaki tersebut meninggal dunia, dan belum bercampur dengannya (menggaulinya) serta belum memberikan mahar kepadanya. Kemudian beliau berkata; baginya mahar secara sempurna dan ia wajib ber'iddah serta baginya warisan. Kemudian [Ma'qil bin Sinan] berkata; aku mendengar Rasulullah shallallahu 'alaihi wasallam memutuskan dengan hal tersebut pada diri Barwa' binti Wasyiq. Telah menceritakan kepada kami [Utsman bin Abu Syaibah], telah menceritakan kepada kami [Yazid bin Harun] dan [Ibnu Mahdi] dari [Sufyan] dari [Manshur] dari [Ibrahim] dari ['Al Qamah] dari [Abdullah], dan Utsman menyebutkan seperti itu. Telah menceritakan kepada kami [Ubaidullah bin Umar], telah menceritakan kepada kami [Yazid bin Zurai'], telah menceritakan kepada kami [Sa'id bin Abu 'Arubah] dari [Qatadah] dari [Khalas] serta [Abu Hassan] dari [Abdullah bin 'Utbah bin Mas'ud] bahwa [Abdullah bin Mas'ud] dihadapkan pada masalah mengenai seorang laki-laki seperti hadits ini. Abdullah bin Utbah berkata; kemudian orang-orang datang kepadanya selama satu bulan. Atau ia mengatakan; selama beberapa kali. Abdullah bin Mas'ud berkata; sesungguhnya aku katakan mengenainya; bahwa baginya mahar seperti mahar wanita-wanita yang setara dengannya, tidak kurang dan tidak lebih, dan baginya warisan, serta berkewajiban untuk ber'iddah. Apabila (perkataan itu) benar maka berasal dari Allah, dan apabila salah maka hal tersebut berasal dariku dan dari syetan, Allah dan rasul-Nya berlepas diri. Kemudian orang-orang dari Asyja' diantara mereka adalah [Al Jarrah], dan [Abu Sinan] berkata; wahai Ibnu Mas'ud, kami bersaksi bahwa Rasulullah shallallahu 'alaihi wasallam telah memutuskan hal tersebut diantara kami mengenai diri Barwa' binti Wasyiq yang suaminya adalah Hilal bin Murrah seperti yang telah engkau putuskan. Abdullah bin 'Utbah berkata; kemudian Abdullah bin Mas'ud sangat senang sekali ketika keputusannya sama dengan keputusan Rasulullah shallallahu 'alaihi wasallam. "},"1743":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ فَارِسٍ الذُّهْلِيُّ وَمُحَمَّدُ بْنُ الْمُثَنَّى وَعُمَرُ بْنُ الْخَطَّابِ قَالَ مُحَمَّدٌ حَدَّثَنَا أَبُو الْأَصْبَغِ الْجَزَرِيُّ عَبْدُ الْعَزِيزِ بْنُ يَحْيَى أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنْ أَبِي عَبْدِ الرَّحِيمِ خَالِدِ بْنِ أَبِي يَزِيدَ عَنْ زَيْدِ بْنِ أَبِي أُنَيْسَةَ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ مَرْثَدِ بْنِ عَبْدِ اللَّهِ عَنْ عُقْبَةَ بْنِ عَامِرٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِرَجُلٍ أَتَرْضَى أَنْ أُزَوِّجَكَ فُلَانَةَ قَالَ نَعَمْ وَقَالَ لِلْمَرْأَةِ أَتَرْضَيْنَ أَنْ أُزَوِّجَكِ فُلَانًا قَالَتْ نَعَمْ فَزَوَّجَ أَحَدَهُمَا صَاحِبَهُ فَدَخَلَ بِهَا الرَّجُلُ وَلَمْ يَفْرِضْ لَهَا صَدَاقًا وَلَمْ يُعْطِهَا شَيْئًا وَكَانَ مِمَّنْ شَهِدَ الْحُدَيْبِيَةَ وَكَانَ مَنْ شَهِدَ الْحُدَيْبِيَةَ لَهُ سَهْمٌ بِخَيْبَرَ فَلَمَّا حَضَرَتْهُ الْوَفَاةُ قَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَوَّجَنِي فُلَانَةَ وَلَمْ أَفْرِضْ لَهَا صَدَاقًا وَلَمْ أُعْطِهَا شَيْئًا وَإِنِّي أُشْهِدُكُمْ أَنِّي أَعْطَيْتُهَا مِنْ صَدَاقِهَا سَهْمِي بِخَيْبَرَ فَأَخَذَتْ سَهْمًا فَبَاعَتْهُ بِمِائَةِ أَلْفٍقَالَ أَبُو دَاوُد وَزَادَ عُمَرُ بْنُ الْخَطَّابِ وَحَدِيثُهُ أَتَمُّ فِي أَوَّلِ الْحَدِيثِ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْرُ النِّكَاحِ أَيْسَرُهُ وَقَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلرَّجُلِ ثُمَّ سَاقَ مَعْنَاهُ قَالَ أَبُو دَاوُد يُخَافُ أَنْ يَكُونَ هَذَا الْحَدِيثُ مُلْزَقًا لِأَنَّ الْأَمْرَ عَلَى غَيْرِ هَذَا","id":"Telah menceritakan kepada kami [Muhammad bin Yahya bin Faris Adz Dzuhli], serta [Muhammad bin Al Mutsanna] dan [Umar bin Al Khathab], Muhammad berkata; telah menceritakan kepada kami [Abu Al Ashbagh Al Jazari Abdul Aziz bin Yahya], telah mengabarkan kepada kami [Muhammad bin Salamah] dari [Abu Abdurrahim Khalid bin Abu Yazid] dari [Zaid bin Abu Unaisah], dari [Yazid bin Abu Habib] dari [Martsad bin Abdullah] dari ['Uqbah bin 'Amir], bahwa Nabi shallallahu 'alaihi wasallam berkata kepada seorang laki-laki: \"Apakah engkau rela aku nikahkah engkau dengan Fulanah?\" Ia berkata; Iya. Beliau berkata kepada wanita tersebut: \"Apakah engkau rela aku nikahkan engkau dengan Fulan?\" Wanita tersebut berkata; Iya. Kemudian beliau menikahkan mereka berdua. Kemudian laki-laki tersebut bercampur dengannya (menggaulinya) dalam keadaan belum menentukan mahar dan belum memberikan sesuatupun kepadanya. Ia termasuk orang-orang yang menyaksikan perdamaian Al Hudaibiyah, orang yang menghadiri perdamaian Al Hudaibiyah, dan memiliki saham di Khaibar. Kemudian tatkala kematian menjemputnya ia berkata; sesungguhnya Rasulullah shallallahu 'alaihi wasallam telah menikahkanku dengan Fulanah dan aku belum menentukan mahar untuknya dan belum memberikan sesuatupun kepadanya, dan aku meminta persaksian kalian bahwa aku telah memberikan kepadanya sahamku di Khaibar sebagai mahar. Kemudian wanita tersebut mengambil saham tersebut dan menjualnya seratus ribu. Abu Daud berkata; dan [Umar bin Al Khathab] menambahkan pada awal hadits, dan haditsnya lebih sempurna; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebaik-baik pernikahan adalah yang paling mudah.\" Ia berkata; Rasulullah shallallahu 'alaihi wasallam berkata kepada laki-laki tersebut: Kemudian ia menyebutkan hadits tersebut dengan maknanya. Abu Daud berkata; hadits ini dikhawatirkan merupakan hadits tambahan karena kondisinya tidak demikian. "},"1744":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي عُبَيْدَةَ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ فِي خُطْبَةِ الْحَاجَةِ فِي النِّكَاحِ وَغَيْرِهِ ح و حَدَّثَنَا مُحَمَّدُ بْنُ سُلَيْمَانَ الْأَنْبَارِيُّ الْمَعْنَى حَدَّثَنَا وَكِيعٌ عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي الْأَحْوَصِ وَأَبِي عُبَيْدَةَ عَنْ عَبْدِ اللَّهِ قَالَعَلَّمَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خُطْبَةَ الْحَاجَةِ أَنْ الْحَمْدُ لِلَّهِ نَسْتَعِينُهُ وَنَسْتَغْفِرُهُ وَنَعُوذُ بِهِ مِنْ شُرُورِ أَنْفُسِنَا مَنْ يَهْدِ اللَّهُ فَلَا مُضِلَّ لَهُ وَمَنْ يُضْلِلْ فَلَا هَادِيَ لَهُ وَأَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ يَا أَيُّهَا الَّذِينَ آمَنُوا{ اتَّقُوا اللَّهَ الَّذِي تَسَاءَلُونَ بِهِ وَالْأَرْحَامَ إِنَّ اللَّهَ كَانَ عَلَيْكُمْ رَقِيبًا }{ يَا أَيُّهَا الَّذِينَ آمَنُوا اتَّقُوا اللَّهَ حَقَّ تُقَاتِهِ وَلَا تَمُوتُنَّ إِلَّا وَأَنْتُمْ مُسْلِمُونَ }{ يَا أَيُّهَا الَّذِينَ آمَنُوا اتَّقُوا اللَّهَ وَقُولُوا قَوْلًا سَدِيدًا يُصْلِحْ لَكُمْ أَعْمَالَكُمْ وَيَغْفِرْ لَكُمْ ذُنُوبَكُمْ وَمَنْ يُطِعْ اللَّهَ وَرَسُولَهُ فَقَدْ فَازَ فَوْزًا عَظِيمًا }لَمْ يَقُلْ مُحَمَّدُ بْنُ سُلَيْمَانَ أَنْ حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو عَاصِمٍ حَدَّثَنَا عِمْرَانُ عَنْ قَتَادَةَ عَنْ عَبْدِ رَبِّهِ عَنْ أَبِي عِيَاضٍ عَنْ ابْنِ مَسْعُودٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا تَشَهَّدَ ذَكَرَ نَحْوَهُ وَقَالَ بَعْدَ قَوْلِهِ وَرَسُولُهُ أَرْسَلَهُ بِالْحَقِّ بَشِيرًا وَنَذِيرًا بَيْنَ يَدَيْ السَّاعَةِ مَنْ يُطِعْ اللَّهَ وَرَسُولَهُ فَقَدْ رَشَدَ وَمَنْ يَعْصِهِمَا فَإِنَّهُ لَا يَضُرُّ إِلَّا نَفْسَهُ وَلَا يَضُرُّ اللَّهَ شَيْئًا","id":"Telah menceritakan kepada kami [Muhammad bin Katsir], telah mengabarkan kepada kami [Sufyan] dari [Abu Ishaq] dari [Abu 'Ubaidah] dari [Abdullah bin Mas'ud] mengenai khutbah hajah dalam pernikahan dan yang lainnya, dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Muhammad bin Sulaiman Al Anbari] secara makna, telah menceritakan kepada kami [Waki'] dari [Israil], dari [Abu Ishaq] dari [Abu Al Ahwash] dan [Abu 'Ubaidah] dari [Abdullah], ia berkata; Rasulullah shallallahu 'alaihi wasallam telah mengajarkan kepada khutbah hajah, yaitu: INNAL HAMDA LILLAAH, NAHMADUHU WA NASTA'IINUHU WA NASTAGHFIRUH, WA NA'UUDZU BILLAAHI MIN SYURUURI ANFUSINAA MAN YAHDIHILLAAHU FALAA MUDHILLALAH, WA MAN YUDHLIL FALAA HAADIYALAH. ASYHADU ANLAA ILAAHA ILLALLAAHU WA ASYHADU ANNA MUHAMMADAN 'ABDUHU WA RASUULUH. YAA AYYUHALLADZIINA AAMANUT TAQULLAAHAL LADZII TASAA-ALUUNA BIHII WAL ARHAAM, INNALLAAHA KAANA 'ALAIKUM RAQIIBAA. YAA AYYUHALLADZIINA AAMANUT TAQULLAAHA HAQQA TUQAATIHI WA LAA TAMUUTUNNA ILLAA WA ANTUM MUSLIMUUN, YAA AYYUHALLADZIINA AAMANUUT TAQULLAAHA WA QUULUU QAULAN SADIIDAA, YUSHLIH LAKUM A'MAALAKUM WA YAGHFIRLAKUM DZUNUUBAKUM WA MAYYUTHI'ILLAAHA WA RASUULAHU FAQAD FAAZA FAUZAN 'AZHIIMAA (Segala puji bagi Allah, kami memuji dan memohon pertolongan serta ampunan kepadaNya, dan berlindung kepada Allah dari keburukan diri kita, barangsiapa yang Allah beri petunjuk maka tidak ada yang dapat menyesatkannya dan barangsiapa yang Allah sesatkan, maka tidak ada yang dapat memberinya petunjuk. Aku bersaksi bahwa tidak ada tuhan yang berhak disembah kecuali Allah dan Muhammad adalah hamba serta rasulNya. Hai orang-orang yang beriman, bertakwalah kepada Allah yang dengan (mempergunakan) nama-Nya kamu saling meminta satu sama lain, dan (peliharalah) hubungan silaturrahim. Sesungguhnya Allah selalu menjaga dan mengawasi kamu. Hai orang-orang yang beriman, bertakwalah kepada Allah sebenar-benar takwa kepada-Nya; dan janganlah sekali-kali kamu mati melainkan dalam keadaan beragama Islam. Hai orang-orang yang beriman, bertakwalah kamu kepada Allah dan katakanlah perkataan yang benar, niscaya Allah memperbaiki bagimu amalan-amalanmu dan mengampuni bagimu dosa-dosamu. Dan barangsiapa mentaati Allah dan Rasul-Nya, maka sesungguhnya ia telah mendapat kemenangan yang besar(. Muhammad bin Sulaiman tidak menyebutkan khutbah tersebut. Telah menceritakan kepada kami [Muhammad bin Basysyar], telah menceritakan kepada kami [Abu 'Ashim], telah menceritakan kepada kami ['Imran] dari [Qatadah] dari [Abdu Rabbih] dari [Abu 'Iyadh] dari [Ibnu Mas'ud] bahwa Rasulullah shallallahu 'alaihi wasallam apabila bertasayahud menyebutkan seperti itu. Dan ia mengatakan setelah ucapannya: \"dan rasulNya\" yang Allah utus dengan kebenaran sebagai pemberi kabar gembira dan pemberi peringatan di hadapan Hari Kiamat. Barangsiapa yang mentaati Allah dan rasulNya maka sungguh ia telah mendapatkan petunjuk dan barangsiapa yang mendurhakai mereka berdua, maka sesungguhnya ia tidak merugikan kecuali terhadap dirinya sendiri, dan tidak merugikan Allah sedikitpun. "},"1745":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا بَدَلُ بْنُ الْمُحَبَّرِ أَخْبَرَنَا شُعْبَةُ عَنْ الْعَلَاءِ ابْنَ أَخِي شُعَيْبٍ الرَّازِيِّ عَنْ إِسْمَعِيلَ بْنِ إِبْرَاهِيمَ عَنْ رَجُلٍ مِنْ بَنِي سُلَيْمٍ قَالَخَطَبْتُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُمَامَةَ بِنْتَ عَبْدِ الْمُطَّلِبِ فَأَنْكَحَنِي مِنْ غَيْرِ أَنْ يَتَشَهَّدَ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar], telah menceritakan kepada kami [Badal bin Al Muhabbar], telah mengabarkan kepada kami [Syu'bah] dari [Al 'Ala`] anak saudara Syu'aib Ar Razi dari [Isma'il bin Ibrahim] dari [seorang laki-laki dari Bani Sulaim], ia berkata; aku meminang Umamah binti Abdul Muththalib kepada Rasulullah shallallahu 'alaihi wasallam kemudian beliau menikahkanku tanpa beliau mengucapkan syahadat. "},"1746":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ وَأَبُو كَامِلٍ قَالَا حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْتَزَوَّجَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا بِنْتُ سَبْعٍ قَالَ سُلَيْمَانُ أَوْ سِتٍّ وَدَخَلَ بِي وَأَنَا بِنْتُ تِسْعٍ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb], serta [Abu Kamil], mereka berkata; Telah menceritakan kepada kami [Hammad bin Zaid] dari [Hisyam bin 'Urwah] dari [ayahnya] dari [Aisyah], ia berkata; Rasulullah shallallahu 'alaihi wasallam menikahiku sementara aku berumur tujuh tahun. Sulaiman berkata; atau enam tahun, dan beliau bercampur denganku sementara aku berumur sembilan tahun. "},"1747":{"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ أَبِي بَكْرٍ عَنْ عَبْدِ الْمَلِكِ بْنِ أَبِي بَكْرٍ عَنْ أَبِيهِ عَنْ أُمِّ سَلَمَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمَّا تَزَوَّجَ أُمَّ سَلَمَةَ أَقَامَ عِنْدَهَا ثَلَاثًا ثُمَّ قَالَ لَيْسَ بِكِ عَلَى أَهْلِكِ هَوَانٌ إِنْ شِئْتِ سَبَّعْتُ لَكِ وَإِنْ سَبَّعْتُ لَكِ سَبَّعْتُ لِنِسَائِي","id":"Telah menceritakan kepada kami [Zuhair bin Harb], telah menceritakan kepada kami [Yahya] dari [Sufyan], ia berkata; telah menceritakan kepadaku [Muhammad bin Abu Bakr], dari [Abdul Malik bin Abu Bakr] dari [ayahnya] dari [Ummu Salamah] bahwa Rasulullah shallallahu 'alaihi wasallam tatkala menikahi Ummu Salamah beliau tinggal di rumahnya selama tiga hari, kemudian beliau berkata: \"Engkau tidaklah direndahkan dan dikurangi hak kamu oleh keluargamu (maksudnya Rasulullah shallallahu 'alaihi wasallam), apabila engkau mau maka aku akan memberimu (giliran) tujuh hari, dan apabila aku memberimu (giliran) tujuh hari, maka aku memberi isteri-isteriku (giliran) tujuh hari (juga).\""},"1748":{"ar":"حَدَّثَنَا وَهْبُ بْنُ بَقِيَّةَ وَعُثْمَانُ بْنُ أَبِي شَيْبَةَ عَنْ هُشَيْمٍ عَنْ حُمَيْدٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَلَمَّا أَخَذَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَفِيَّةَ أَقَامَ عِنْدَهَا ثَلَاثًا زَادَ عُثْمَانُ وَكَانَتْ ثَيِّبًاو قَالَ حَدَّثَنِي هُشَيْمٌ أَخْبَرَنَا حُمَيْدٌ أَخْبَرَنَا أَنَسٌ","id":"Telah menceritakan kepada kami [Wahb bin Baqiyyah], serta [Utsman bin Abu Syaibah], dari [Husyaim] dari [Humaid], dari [Anas bin Malik], ia berkata; tatkala Rasulullah shallallahu 'alaihi wasallam mengambil (menikahi) Shafiyyah beliau tinggal di rumahnya selama tiga hari. Utsman menambahkan; dan ia adalah seorang janda. dan ia berkata; telah menceritakan kepadaku [Husyaim], telah mengabarkan kepada kami [Humaid], telah mengabarkan kepada kami [Anas]. "},"1749":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا هُشَيْمٌ وَإِسْمَعِيلُ ابْنُ عُلَيَّةَ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ أَبِي قِلَابَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَإِذَا تَزَوَّجَ الْبِكْرَ عَلَى الثَّيِّبِ أَقَامَ عِنْدَهَا سَبْعًا وَإِذَا تَزَوَّجَ الثَّيِّبَ أَقَامَ عِنْدَهَا ثَلَاثًا وَلَوْ قُلْتُ إِنَّهُ رَفَعَهُ لَصَدَقْتُ وَلَكِنَّهُ قَالَ السُّنَّةُ كَذَلِكَ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah], telah menceritakan kepada kami [Husyaim], dan [Isma'il bin 'Ulayyah], dari [Khalid Al Hadzdza`] dari [Abu Qilabah] dari [Anas bin Malik], ia berkata; apabila seseorang menikahi seorang gadis sebagai madu seorang janda maka ia tinggal di rumahnya selama tujuh hari, dan apabila menikahi seorang janda maka ia tinggal di rumahnya selama tiga hari. Jika aku mengatakan ia telah merafa'kan hadits tersebut, maka aku telah benar, akan tetapi ia mengatakan; sunnah. Demikianlah. "},"1750":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِسْمَعِيلَ الطَّالَقَانِيُّ حَدَّثَنَا عَبْدَةُ حَدَّثَنَا سَعِيدٌ عَنْ أَيُّوبَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَلَمَّا تَزَوَّجَ عَلِيٌّ فَاطِمَةَ قَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْطِهَا شَيْئًا قَالَ مَا عِنْدِي شَيْءٌ قَالَ أَيْنَ دِرْعُكَ الْحُطَمِيَّةُ","id":"Telah menceritakan kepada kami [Ishaq bin Isma'il Ath Thalaqani], telah menceritakan kepada kami ['Abdah], telah menceritakan kepada kami [Sa'id], dari [Ayyub] dari [Ikrimah] dari [Ibnu Abbas], ia berkata; tatkala Ali menikahi Fathimah, Rasulullah shallallahu 'alaihi wasallam berkata kepadanya: \"Berikan sesuatu kepadanya!\" Ia berkata; aku tidak memiliki sesuatu. Beliau berkata: \"Dimanakah baju besimu luas dan berat itu?\""},"1751":{"ar":"حَدَّثَنَا كَثِيرُ بْنُ عُبَيْدٍ الْحِمْصِيُّ حَدَّثَنَا أَبُو حَيْوَةَ عَنْ شُعَيْبٍ يَعْنِي ابْنَ أَبِي حَمْزَةَ حَدَّثَنِي غَيْلَانُ بْنُ أَنَسٍ حَدَّثَنِي مُحَمَّدُ بْنُ عَبْدِ الرَّحْمَنِ بْنِ ثَوْبَانَ عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ عَلِيًّا لَمَّا تَزَوَّجَ فَاطِمَةَ بِنْتَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَرَادَ أَنْ يَدْخُلَ بِهَا فَمَنَعَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى يُعْطِيَهَا شَيْئًا فَقَالَ يَا رَسُولَ اللَّهِ لَيْسَ لِي شَيْءٌ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْطِهَا دِرْعَكَ فَأَعْطَاهَا دِرْعَهُ ثُمَّ دَخَلَ بِهَاحَدَّثَنَا كَثِيرٌ يَعْنِي ابْنَ عُبَيْدٍ حَدَّثَنَا أَبُو حَيْوَةَ عَنْ شُعَيْبٍ عَنْ غَيْلَانَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ مِثْلَهُ","id":"Telah menceritakan kepada kami [Katsir bin 'Ubaid Al Himshi], telah menceritakan kepada kami [Abu Haiwah] dari [Syu'aib bin Abu Hamzah], telah menceritakan kepadaku [Ghailan bin Anas], telah menceritakan kepadaku [Muhammad bin Abdurrahman bin Tsauban], dari [seorang laki-laki] sahabat Nabi shallallahu 'alaihi wasallam, bahwa Ali tatkala menikahi Fathimah binti Rasulullah shallallahu 'alaihi wasallam dan hendak bercampur dengannya (menggaulinya), Rasulullah shallallahu 'alaihi wasallam melarangnya hingga ia memberikan sesuatu kepadanya. Kemudian ia berkata; wahai Rasulullah, aku tidak memiliki sesuatu. Kemudian Nabi shallallahu 'alaihi wasallam berkata kepadanya: \"Berikan baju besimu kepadanya!\" kemudian Ali memberikannya kepada Fathimah, kemudian ia bercampur dengannya (menggaulinya). Telah menceritakan kepada kami [Katsir bin 'Ubaid], telah menceritakan kepada kami [Abu Haiwah], dari [Syu'aib] dari [Ghailan] dari [Ikrimah] dari [Ibnu Abbas] seperti itu. "},"1752":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ الْبَزَّازُ حَدَّثَنَا شَرِيكٌ عَنْ مَنْصُورٍ عَنْ طَلْحَةَ عَنْ خَيْثَمَةَ عَنْ عَائِشَةَ قَالَتْأَمَرَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ أُدْخِلَ امْرَأَةً عَلَى زَوْجِهَا قَبْلَ أَنْ يُعْطِيَهَا شَيْئًاقَالَ أَبُو دَاوُد وَخَيْثَمَةُ لَمْ يَسْمَعْ مِنْ عَائِشَةَ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah Al Bazzar], telah menceritakan kepada kami [Syarik], dari [Manshur] dari [Thalhah] dari [Khaitsamah] dari [Aisyah], ia berkata; Rasulullah shallallahu 'alaihi wasallam memerintahkanku agar memasukkan (menyerahkan) wanita kepada suaminya sebelum suami tersebut memberikan sesuatu kepadanya. Abu Daud berkata; dan Khaitsamah tidak mendengar dari Aisyah. "},"1753":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مَعْمَرٍ حَدَّثَنَا مُحَمَّدُ بْنُ بَكْرٍ الْبُرْسَانِيُّ أَخْبَرَنَا ابْنُ جُرَيْجٍ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّمَا امْرَأَةٍ نُكِحَتْ عَلَى صَدَاقٍ أَوْ حِبَاءٍ أَوْ عِدَّةٍ قَبْلَ عِصْمَةِ النِّكَاحِ فَهُوَ لَهَا وَمَا كَانَ بَعْدَ عِصْمَةِ النِّكَاحِ فَهُوَ لِمَنْ أُعْطِيَهُ وَأَحَقُّ مَا أُكْرِمَ عَلَيْهِ الرَّجُلُ ابْنَتُهُ أَوْ أُخْتُهُ","id":"Telah menceritakan kepada kami [Muhammad bin Ma'mar], telah menceritakan kepada kami [Muhammad bin Bakr Al Bursani], telah mengabarkan kepada kami [Ibnu Juraij] dari ['Amr bin Syu'aib] dari [ayahnya] dari [kakeknya], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap wanita yang dinikahkan dengan suatu mahar, pemberian, atau janji sebelum akad nikah, maka hal itu adalah miliknya. Adapun yang diberikan setelah akad nikah, maka hal itu adalah milik orang yang diberinya. Dan orang yang paling berhak terhadap penghormatan yang diberikan kepada seseorang adalah anak atau saudara wanita wanita.\""},"1754":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ يَعْنِي ابْنَ مُحَمَّدٍ عَنْ سُهَيْلٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا رَفَّأَ الْإِنْسَانَ إِذَا تَزَوَّجَ قَالَ بَارَكَ اللَّهُ لَكَ وَبَارَكَ عَلَيْكَ وَجَمَعَ بَيْنَكُمَا فِي خَيْرٍ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id], telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Suhail] dari [ayahnya], dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam apabila mengucapkan selamat kepada seseorang apabila ia menikah beliau mengucapkan: \"BAARAKALLAAHU LAKA WA BAARAKA 'ALAIKA WA JAMA'A BAINAKUMAA FII KHAIRIN\" (Semoga Allah memberkahimu dan senantiasa memberkahimu dan mengumpulkan kalian berdua dalam kebaikan.\""},"1755":{"ar":"حَدَّثَنَا مَخْلَدُ بْنُ خَالِدٍ وَالْحَسَنُ بْنُ عَلِيٍّ وَمُحَمَّدُ بْنُ أَبِي السَّرِيِّ الْمَعْنَى قَالُوا حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا ابْنُ جُرَيْجٍ عَنْ صَفْوَانَ بْنِ سُلَيْمٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ رَجُلٌ مِنْ الْأَنْصَارِ قَالَ ابْنُ أَبِي السَّرِيِّ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَمْ يَقُلْ مِنْ الْأَنْصَارِ ثُمَّ اتَّفَقُوا يُقَالُ لَهُ بَصْرَةُ قَالَتَزَوَّجْتُ امْرَأَةً بِكْرًا فِي سِتْرِهَا فَدَخَلْتُ عَلَيْهَا فَإِذَا هِيَ حُبْلَى فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَهَا الصَّدَاقُ بِمَا اسْتَحْلَلْتَ مِنْ فَرْجِهَا وَالْوَلَدُ عَبْدٌ لَكَ فَإِذَا وَلَدَتْ قَالَ الْحَسَنُ فَاجْلِدْهَا و قَالَ ابْنُ أَبِي السَّرِيِّ فَاجْلِدُوهَا أَوْ قَالَ فَحُدُّوهَاقَالَ أَبُو دَاوُد رَوَى هَذَا الْحَدِيثَ قَتَادَةُ عَنْ سَعِيدِ بْنِ يَزِيدَ عَنْ ابْنِ الْمُسَيَّبِ وَرَوَاهُ يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ يَزِيدَ بْنِ نُعَيْمٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ وَعَطَاءٍ الْخُرَاسَانِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ أَرْسَلُوهُ كُلُّهُمْ وَفِي حَدِيثِ يَحْيَى بْنِ أَبِي كَثِيرٍ أَنَّ بَصْرَةَ بْنَ أَكْثَمَ نَكَحَ امْرَأَةً وَكُلُّهُمْ قَالَ فِي حَدِيثِهِ جَعَلَ الْوَلَدَ عَبْدًا لَهُ حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ حَدَّثَنَا عَلِيٌّ يَعْنِي ابْنَ الْمُبَارَكِ عَنْ يَحْيَى عَنْ يَزِيدَ بْنِ نُعَيْمٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ أَنَّ رَجُلًا يُقَالُ لَهُ بَصْرَةُ بْنُ أَكْثَمَ نَكَحَ امْرَأَةً فَذَكَرَ مَعْنَاهُ زَادَ وَفَرَّقَ بَيْنَهُمَا وَحَدِيثُ ابْنِ جُرَيْجٍ أَتَمُّ","id":"Telah menceritakan kepada kami [Makhlad bin Khalid] serta [Al Hasan bin Ali] dan [Muhammad bin Abu As Sari] secara makna, mereka berkata; telah menceritakan kepada kami [Abdurrazzaq], telah mengabarkan kepada kami [Ibnu Juraij], dari [Shafwan bin Sulaim], dari [Sa'id bin Al Musayyab], dari seorang laki-laki anshar, [Ibnu Abu As Sari] berkata; yang merupakan sahabat Nabi shallallahu 'alaihi wasallam, tidak mengatakan; anshar. Kemudian mereka sepakat mengatakan; yang dipanggil Bashrah, ia berkata; aku menikahi seorang budak perawan dalam tabirnya, kemudian aku menemuinya dan ternyata ia sedang hamil. Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Baginya mahar karena farji yang telah engkau halalkan, dan anaknya adalah budakmu apabila ia telah melahirkan.\" Al Hasan berkata; cambuklah dia. Ibnu Abu As Sari berkata; cambuklah dia. Atau mengatakan; hukumlah dia. Abu Daud berkata; hadits ini telah diriwayatkan oleh [Qatadah] dari [Sa'id bin Yazid] dari [Ibnu Al Musayyab], dan telah diriwayatkan oleh [Yahya bin Abu Katsir] dari [Yazid bin Nu'aim] dari [Sa'id bin Al Musayyab] serta ['Atha` Al Khurasani], dari [Sa'id bin Al Musayyab]. Mereka semua telah memursalkannya. Dan di dalam hadits Yahya bin Abu Katsir disebutkan bahwa [Bashrah bin Aktsam] menikahi seorang wanita, dan seluruh mereka mengatakan dalam haditsnya; ia menjadikan anak tersebut sebagai budaknya. Telah menceritakan kepada kami [Muhammad bin Al Mutsanna], telah menceritakan kepada kami [Utsman bin Umar], telah menceritakan kepada kami [Ali bin Al Mubarak], dari [Yahya] dari [Yazid bin Nu'aim] dari [Sa'id bin Al Musayyab] bahwa seorang laki-laki yang dipanggil [Bashrah bin Aktsam] telah menikahi seorang wanita…. Kemudian ia menyebutkan makna hadits dan menambahkan; dan beliau memisahkan diantara mereka berdua. Hadits Ibnu Juraij lebih sempurna."},"1756":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ عَنْ النَّضْرِ بْنِ أَنَسٍ عَنْ بَشِيرِ بْنِ نَهِيكٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ كَانَتْ لَهُ امْرَأَتَانِ فَمَالَ إِلَى إِحْدَاهُمَا جَاءَ يَوْمَ الْقِيَامَةِ وَشِقُّهُ مَائِلٌ","id":"Telah menceritakan kepada kami [Abu Al Walid Ath Thayalisi], telah menceritakan kepada kami [Hammam], telah menceritakan kepada kami [Qatadah] dari [An Nadhrah bin Anas] dari [Basyir bin Nahik] dari [Abu Hurairah], dari Nabi shallallahu 'alaihi wasallam, beliau berkata: \"Barangsiapa yang memiliki dua orang isteri kemudian ia cenderung kepada salah seorang diantara keduanya, maka ia akan datang pada hari Kiamat dalam keadaan sebelah badannya miring.\""},"1757":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ عَبْدِ اللَّهِ بْنِ يَزِيدَ الْخَطْمِيِّ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْسِمُ فَيَعْدِلُ وَيَقُولُ اللَّهُمَّ هَذَا قَسْمِي فِيمَا أَمْلِكُ فَلَا تَلُمْنِي فِيمَا تَمْلِكُ وَلَا أَمْلِكُقَالَ أَبُو دَاوُد يَعْنِي الْقَلْبَ","id":"Telah menceritakan kepada kami [Musa bin Isma'il], telah menceritakan kepada kami [Hammad] dari [Ayyub] dari [Abu Qilabah] dari [Abdullah bin Yazid Al Khathmi] dari [Aisyah], ia berkata; Rasulullah shallallahu 'alaihi wasallam memberikan pembagian dan berbuat adil dalam membagi, dan beliau berkata: \"Ya Allah, inilah pembagianku yang aku mampu, maka janganlah Engkau cela aku pada sesuatu yang Engkau mampu dan tidak aku mampu.\" Abu Daud berkata; yaitu hati. "},"1758":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ يَعْنِي ابْنَ أَبِي الزِّنَادِ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ قَالَ قَالَتْ عَائِشَةُيَا ابْنَ أُخْتِي كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يُفَضِّلُ بَعْضَنَا عَلَى بَعْضٍ فِي الْقَسْمِ مِنْ مُكْثِهِ عِنْدَنَا وَكَانَ قَلَّ يَوْمٌ إِلَّا وَهُوَ يَطُوفُ عَلَيْنَا جَمِيعًا فَيَدْنُو مِنْ كُلِّ امْرَأَةٍ مِنْ غَيْرِ مَسِيسٍ حَتَّى يَبْلُغَ إِلَى الَّتِي هُوَ يَوْمُهَا فَيَبِيتَ عِنْدَهَا وَلَقَدْ قَالَتْ سَوْدَةُ بِنْتُ زَمْعَةَ حِينَ أَسَنَّتْ وَفَرِقَتْ أَنْ يُفَارِقَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا رَسُولَ اللَّهِ يَوْمِي لِعَائِشَةَ فَقَبِلَ ذَلِكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْهَا قَالَتْ نَقُولُ فِي ذَلِكَ أَنْزَلَ اللَّهُ تَعَالَى وَفِي أَشْبَاهِهَا أُرَاهُ قَالَ{ وَإِنْ امْرَأَةٌ خَافَتْ مِنْ بَعْلِهَا نُشُوزًا }","id":"Telah menceritakan kepada kami [Ahmad bin Yunus], telah menceritakan kepada kami [Abdurrahman bin Abu Az Zinad] dari [Hisyam bin 'Urwah] dari [ayahnya], ia berkata; [Aisyah] berkata; wahai anak saudariku, Rasulullah shallallahu 'alaihi wasallam tidak melebihkan sebagian kami atas sebagian yang lain dalam membagi waktu tinggalnya bersama kami. Setiap hari beliau mengelilingi kami semua dan mendekat kepada seluruh isteri tanpa menyentuh hingga sampai kepada rumah isteri yang hari itu merupakan bagiannya, kemudian beliau bermalam padanya. Sungguh Saudah binti Zam'ah ketika telah berusia lanjut dan takut ditinggalkan Rasulullah shallallahu 'alaihi wasallam, ia berkata; wahai Rasulullah, hariku untuk Aisyah. Dan Rasulullah shallallahu 'alaihi wasallam menerima hal tersebut. Ia berkata; kami katakan; mengenai hal tersebut dan orang yang semisalnya, Allah Ta'ala menurunkan ayat: \"Dan jika seorang wanita khawatir akan nusyuz.\""},"1759":{"ar":"حَدَّثَنَا يَحْيَى بْنُ مَعِينٍ وَمُحَمَّدُ بْنُ عِيسَى الْمَعْنَى قَالَا حَدَّثَنَا عَبَّادُ بْنُ عَبَّادٍ عَنْ عَاصِمٍ عَنْ مُعَاذَةَ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَ��َيْهِ وَسَلَّمَ يَسْتَأْذِنُنَا إِذَا كَانَ فِي يَوْمِ الْمَرْأَةِ مِنَّا بَعْدَمَا نَزَلَتْ{ تُرْجِي مَنْ تَشَاءُ مِنْهُنَّ وَتُؤْوِي إِلَيْكَ مَنْ تَشَاءُ }قَالَتْ مَعَاذَةُ فَقُلْتُ لَهَا مَا كُنْتِ تَقُولِينَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ كُنْتُ أَقُولُ إِنْ كَانَ ذَلِكَ إِلَيَّ لَمْ أُوثِرْ أَحَدًا عَلَى نَفْسِي","id":"Telah menceritakan kepada kami [Yahya bin Ma'in], serta [Muhammad bin Isa] secara makna, mereka berkata; telah menceritakan kepada kami ['Abbad bin 'Abbad] dari ['Ashim] dari [Mu'adzah] dari [Aisyah], ia berkata; Rasulullah shallallahu 'alaihi wasallam meminta izin kepada kami apabila berada pada hari (giliran) seorang isteri dari kami setelah turunnya ayat: \"Kamu boleh menangguhkan menggauli siapa yang kamu kehendaki di antara mereka (isteri-isterimu) dan (boleh pula) menggauli siapa yang kamu kehendaki.\" Mu'adzah berkata; kemudian aku katakan kepada Aisyah; apa yang engkau katakan kepada Rasulullah shallallahu 'alaihi wasallam? Ia berkata; aku katakan; apabila hal itu diserahkan kepadaku, maka aku tidak akan mendahulukan seorangpun atas diriku. "},"1760":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا مَرْحُومُ بْنُ عَبْدِ الْعَزِيزِ الْعَطَّارُ حَدَّثَنِي أَبُو عِمْرَانَ الْجَوْنِيُّ عَنْ يَزِيدَ بْنِ بَابَنُوسَ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ إِلَى النِّسَاءِ تَعْنِي فِي مَرَضِهِ فَاجْتَمَعْنَ فَقَالَ إِنِّي لَا أَسْتَطِيعُ أَنْ أَدُورَ بَيْنَكُنَّ فَإِنْ رَأَيْتُنَّ أَنْ تَأْذَنَّ لِي فَأَكُونَ عِنْدَ عَائِشَةَ فَعَلْتُنَّ فَأَذِنَّ لَهُ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Marhum bin Abdul Aziz Al 'Aththar], telah menceritakan kepadaku [Abu Imran Al Jauni] dari [Yazid bin Babanus] dari [Aisyah] bahwa Rasulullah shallallahu 'alaihi wasallam mengirimkan utusan kepada para isterinya ketika beliau sedang sakit, kemudian mereka berkumpul, lalu beliau berkata: \"Sesungguhnya aku tidak mampu untuk berkeliling diantara kalian, maka apabila kalian mengizinkan aku untuk berada di sisi Aisyah, maka lakukanlah.\" Kemudian mereka mengizinkan beliau. "},"1761":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ أَخْبَرَنَا ابْنُ وَهْبٍ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ أَنَّ عُرْوَةَ بْنَ الزُّبَيْرِ حَدَّثَهُ أَنَّ عَائِشَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَرَادَ سَفَرًا أَقْرَعَ بَيْنَ نِسَائِهِ فَأَيَّتُهُنَّ خَرَجَ سَهْمُهَا خَرَجَ بِهَا مَعَهُ وَكَانَ يَقْسِمُ لِكُلِّ امْرَأَةٍ مِنْهُنَّ يَوْمَهَا وَلَيْلَتَهَا غَيْرَ أَنَّ سَوْدَةَ بِنْتَ زَمْعَةَ وَهَبَتْ يَوْمَهَا لِعَائِشَةَ","id":"Telah menceritakan kepada kami [Ahmad bin 'Amr bin As Sarh], telah mengabarkan kepada kami [Ibnu Wahb] dari [Yunus] dari [Ibnu Syihab] bahwa ['Urwah bin Az Zubair] telah menceritakan kepadanya bahwa [Aisyah] isteri Nabi shallallahu 'alaihi wasallam berkata; Rasulullah shallallahu 'alaihi wasallam apabila hendak bepergian beliau mengundi diantara para isterinya, siapa diantara mereka yang keluar undiannya maka beliau keluar bersamanya. Dan beliau membagi bagian untuk setiap isteri satu hari satu malam, hanya saja Saudah binti Zam'ah telah memberikan harinya untuk Aisyah. "},"1762":{"ar":"حَدَّثَنَا عِيسَى بْنُ حَمَّادٍ أَخْبَرَنِي اللَّيْثُ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ أَبِي الْخَيْرِ عَنْ عُقْبَةَ بْنِ عَامِرٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ إِنَّ أَحَقَّ الشُّرُوطِ أَنْ تُوفُوا بِهِ مَا اسْتَحْلَلْتُمْ بِهِ الْفُرُوجَ","id":"Telah menceritakan kepada kami [Isa bin Hammad], telah mengabarkan kepadaku [Al Laits] dari [Yazid bin Abu Habib] dari [Abu Al Khair] dari ['Uqbah bin 'Amir] dari Rasulullah shallallahu 'alaihi wasallam bahwa beliau bersabda: \"Sesungguhnya syarat yang paling berhak untuk dipenuhi adalah (syarat) yang kalian gunakan untuk menghalalkan farji.\""},"1763":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَوْنٍ أَخْبَرَنَا إِسْحَقُ بْنُ يُوسُفَ عَنْ شَرِيكٍ عَنْ حُصَيْنٍ عَنْ الشَّعْبِيِّ عَنْ قَيْسِ بْنِ سَعْدٍ قَالَأَتَيْتُ الْحِيرَةَ فَرَأَيْتُهُمْ يَسْجُدُونَ لِمَرْزُبَانٍ لَهُمْ فَقُلْتُ رَسُولُ اللَّهِ أَحَقُّ أَنْ يُسْجَدَ لَهُ قَالَ فَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ إِنِّي أَتَيْتُ الْحِيرَةَ فَرَأَيْتُهُمْ يَسْجُدُونَ لِمَرْزُبَانٍ لَهُمْ فَأَنْتَ يَا رَسُولَ اللَّهِ أَحَقُّ أَنْ نَسْجُدَ لَكَ قَالَ أَرَأَيْتَ لَوْ مَرَرْتَ بِقَبْرِي أَكُنْتَ تَسْجُدُ لَهُ قَالَ قُلْتُ لَا قَالَ فَلَا تَفْعَلُوا لَوْ كُنْتُ آمِرًا أَحَدًا أَنْ يَسْجُدَ لِأَحَدٍ لَأَمَرْتُ النِّسَاءَ أَنْ يَسْجُدْنَ لِأَزْوَاجِهِنَّ لِمَا جَعَلَ اللَّهُ لَهُمْ عَلَيْهِنَّ مِنْ الْحَقِّ","id":"Telah menceritakan kepada kami ['Amr bin 'Aun], telah mengabarkan kepada kami [Ishaq bin Yusuf] dari [Syarik], dari [Hushain], dari [Asy Sya'bi] dari [Qais bin Sa'd], ia berkata; aku datang ke Al Hirah (negeri lama yang berada di Kufah), maka aku melihat mereka bersujud kepada penunggang kuda mereka yang pemberani. Lalu aku katakan; Rasulullah shallallahu 'alaihi wasallam lebih berhak untuk dilakukan sujud kepadanya. Qais bin Sa'd berkata; kemudian aku datang kepada Nabi shallallahu 'alaihi wasallam dan aku katakan; sesungguhnya aku datang ke Al Hirah dan aku melihat mereka bersujud kepada penunggang kuda mereka yang pemberani. Engkau wahai Rasulullah, lebih berhak untuk kami bersujud kepadamu. Beliau berkata: \"Bagaimana pendapatmu, seandainya engkau melewati kuburanku, apakah engkau akan bersujud kepadanya?\" Qais bin Sa'd berkata; aku katakan; tidak. Beliau bersabda: \"Jangan kalian lakukan, seandainya aku boleh memerintahkan seseorang untuk bersujud kepada seseorang, niscaya aku perintahkan para wanita agar bersujud kepada suami-suami mereka, karena hak yang telah Allah berikan atas mereka.\""},"1764":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرٍو الرَّازِيُّ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا دَعَا الرَّجُلُ امْرَأَتَهُ إِلَى فِرَاشِهِ فَأَبَتْ فَلَمْ تَأْتِهِ فَبَاتَ غَضْبَانَ عَلَيْهَا لَعَنَتْهَا الْمَلَائِكَةُ حَتَّى تُصْبِحَ","id":"Telah menceritakan kepada kami [Muhammad bin 'Amr Ar Razi], telah menceritakan kepada kami [Jarir], dari [Al A'masy], dari [Abu Hazim], dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Apabila seorang laki-laki memanggil isterinya ke ranjangnya (mengajak melakukan hubungan badan), kemudian sang istri menolak dan tidak datang kepadanya sehingga suaminya melewati malam (tidur) dalam keadaan marah, maka Malaikat akan melaknatnya hingga pagi.\""},"1765":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ أَخْبَرَنَا أَبُو قَزَعَةَ الْبَاهِلِيُّ عَنْ حَكِيمِ بْنِ مُعَاوِيَةَ الْقُشَيْرِيِّ عَنْ أَبِيهِ قَالَقُلْتُ يَا رَسُولَ اللَّهِ مَا حَقُّ زَوْجَةِ أَحَدِنَا عَلَيْهِ قَالَ أَنْ تُطْعِمَهَا إِذَا طَعِمْتَ وَتَكْسُوَهَا إِذَا اكْتَسَيْتَ أَوْ اكْتَسَبْتَ وَلَا تَضْرِبْ الْوَجْهَ وَلَا تُقَبِّحْ وَلَا تَهْجُرْ إِلَّا فِي الْبَيْتِقَالَ أَبُو دَاوُد وَلَا تُقَبِّحْ أَنْ تَقُولَ قَبَّحَكِ اللَّهُ","id":"Telah menceritakan kepada kami [Musa bin Isma'Il], telah menceritakan kepada kami [Hammad], telah mengabarkan kepada kami [Abu Qaza'ah Al Bahali], dari [Hakim bin Mu'awiyah Al Qusyairi] dari [ayahnya], ia berkata; aku katakan; wahai Rasulullah, apakah hak isteri salah seorang diantara kami atasnya? Beliau berkata: \"Engkau memberinya makan apabila engkau makan, memberinya pakaian apabila engkau berpakaian, janganlah engkau memukul wajah, jangan engkau menjelek-jelekkannya (dengan perkataan atau cacian), dan jangan engkau tinggalkan kecuali di dalam rumah.\" Abu Daud berkata; dan janganlah engkau menjelek-jelekkannya (dengan perkataan atau cacian) dengan mengatakan; semoga Allah memburukkan wajahmu. "},"1766":{"ar":"حَدَّثَنَا ابْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا بَهْزُ بْنُ حَكِيمٍ حَدَّثَنِي أَبِي عَنْ جَدِّي قَالَقُلْتُ يَا رَسُولَ اللَّهِ نِسَاؤُنَا مَا نَأْتِي مِنْهُنَّ وَمَا نَذَرُ قَالَ ائْتِ حَرْثَكَ أَنَّى شِئْتَ وَأَطْعِمْهَا إِذَا طَعِمْتَ وَاكْسُهَا إِذَا اكْتَسَيْتَ وَلَا تُقَبِّحْ الْوَجْهَ وَلَا تَضْرِبْقَالَ أَبُو دَاوُد رَوَى شُعْبَةُ تُطْعِمُهَا إِذَا طَعِمْتَ وَتَكْسُوهَا إِذَا اكْتَسَيْتَ","id":"Telah menceritakan kepada kami [Ibnu Basysyar], telah menceritakan kepada kami [Yahya bin Sa'id], telah menceritakan kepada kami [Bahz bin Hakim], telah menceritakan kepadaku [ayahku] dari [kakekku], ia berkata; aku katakan; wahai Rasulullah, apa yang boleh kami lakukan dalam menggauli istri kami dan apa yang harus kami tinggalkan? Beliau menjawab: \"Datangilah tanah tempat bercocok-tanammu itu bagaimana saja kamu kehendaki. Dan berilah mereka makan apabila engkau makan, berilah ia pakaian apabila engkau berpakaian, dan janganlah engkau menjelekkan (mencaci) wajah(nya), serta janganlah engkau memukul (wajahnya).\" Abu Daud berkata; [Syu'bah] telah meriwayatkan dengan kata; engkau memberinya makan apabila engkau makan, dan memberinya pakaian apabila engkau memakai pakaian. "},"1767":{"ar":"أَخْبَرَنِي أَحْمَدُ بْنُ يُوسُفَ الْمُهَلَّبِيُّ النَّيْسَابُورِيُّ حَدَّثَنَا عُمَرُ بْنُ عَبْدِ اللَّهِ بْنِ رَزِينٍ حَدَّثَنَا سُفْيَانُ بْنُ حُسَيْنٍ عَنْ دَاوُدَ الْوَرَّاقِ عَنْ سَعِيدِ بْنِ حَكِيمِ بْنِ مُعَاوِيَةَ عَنْ أَبِيهِ عَنْ جَدِّهِ مُعَاوِيَةَ الْقُشَيْرِيِّ قَالَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَقُلْتُ مَا تَقُولُ فِي نِسَائِنَا قَالَ أَطْعِمُوهُنَّ مِمَّا تَأْكُلُونَ وَاكْسُوهُنَّ مِمَّا تَكْتَسُونَ وَلَا تَضْرِبُوهُنَّ وَلَا تُقَبِّحُوهُنَّ","id":"Telah mengabarkan kepada kami [Ahmad bin Yusuf Al Muhalli An Naisaburi], telah menceritakan kepada kami [Umar bin Abdullah bin Razin], telah menceritakan kepada kami [Sufyan bin Husain] dari [Daud Al Warraq], dari [Sa'id bin Hakim bin Mu'awiyah], dari [ayahnya] dari [kakeknya yaitu Mu'awiyah Al Qusyairi], ia berkata; aku datang kepada Rasulullah shallallahu 'alaihi wasallam. Mu'awiyah berkata; kemudian aku katakan; bagaimana pendapat engkau mengenai isteri-isteri kami? Beliau bersabda: \"Berilah mereka makan dari apa yang kalian makan, dan berilah mereka pakaian dari apa yang kalian pakai, dan janganlah kalian memukul mereka serta menjelek-jelekkan mereka (dengan perkataan dan cacian).\""},"1768":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ عَلِيِّ بْنِ زَيْدٍ عَنْ أَبِي حُرَّةَ الرَّقَاشِيِّ عَنْ عَمِّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَإِنْ خِفْتُمْ نُشُوزَهُنَّ فَاهْجُرُوهُنَّ فِي الْمَضَاجِعِقَالَ حَمَّادٌ يَعْنِي النِّكَاحَ","id":"Telah menceritakan kepada kami [Musa bin Isma'il], telah menceritakan kepada kami [Hammad] dari [Ali bin Zaid], dari [Abu Hurrah Ar Raqasyi], dari [pamannya] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Apabila kalian mengkhawatirkan nusyuz (kedurhakaan) mereka, maka tinggalkan mereka dalam tempat-tempat tidur.\" Hammad berkata; yaitu (tidak) bercampur dengan mereka. "},"1769":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ أَبِي خَلَفٍ وَأَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ قَالَا حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ قَالَ ابْنُ السَّرْحِ عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ عَنْ إِيَاسِ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي ذُبَابٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَضْرِبُوا إِمَاءَ اللَّهِ فَجَاءَ عُمَرُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ ذَئِرْنَ النِّسَاءُ عَلَى أَزْوَاجِهِنَّ فَرَخَّصَ فِي ضَرْبِهِنَّ فَأَطَافَ بِآلِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نِسَاءٌ كَثِيرٌ يَشْكُونَ أَزْوَاجَهُنَّ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَقَدْ طَافَ بِآلِ مُحَمَّدٍ نِسَاءٌ كَثِيرٌ يَشْكُونَ أَزْوَاجَهُنَّ لَيْسَ أُولَئِكَ بِخِيَارِكُمْ","id":"Telah menceritakan kepada kami [Ahmad bin Abu Khalaf], serta [Ahmad bin 'Amr bin As Sarh], mereka berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Abdullah bin Abdullah], Ibnu As Sarh 'Ubaidullah bin Abdullah berkata; dari [Iyas bin Abdullah bin Abu Dzubab], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian memukul hamba-hamba wanita Allah (yakni, istri-istri kalian)!\" Kemudian Umar datang kepada Rasulullah shallallahu 'alaihi wasallam dan berkata; para wanita berani kepada suami-suami mereka. Kemudian beliau memberikan keringanan untuk memukul meraka. Kemudian terdapat banyak wanita yang mengelilingi keluarga Rasulullah shallallahu 'alaihi wasallam, mereka mengeluhkan para suami mereka. Kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Sungguh telah terdapat wanita banyak yang mengelilingi keluarga Muhammad dan mengeluhkan para suami mereka. Mereka bukanlah orang pilihan (terbaik) diantara kalian.\" "},"1770":{"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ دَاوُدَ بْنِ عَبْدِ اللَّهِ الْأَوْدِيِّ عَنْ عَبْدِ الرَّحْمَنِ الْمُسْلِيِّ عَنْ الْأَشْعَثِ بْنِ قَيْسٍ عَنْ عُمَرَ بْنِ الْخَطَّابِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يُسْأَلُ الرَّجُلُ فِيمَا ضَرَبَ امْرَأَتَهُ","id":"Telah menceritakan kepada kami [Zuhair bin Harb], telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Abu 'Awanah] dari [Daud bin Abdullah Al Audi] dari [Abdurrahman Al Musli] dari [Al Asy'ats bin Qais] dari [Umar bin Al Khathab] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Seorang laki-laki tidaklah ditanya kenapa ia memukul isterinya.\""},"1771":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ حَدَّثَنِي يُونُسُ بْنُ عُبَيْدٍ عَنْ عَمْرِو بْنِ سَعِيدٍ عَنْ أَبِي زُرْعَةَ عَنْ جَرِيرٍ قَالَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ نَظْرَةِ الْفَجْأَةِ فَقَالَ اصْرِفْ بَصَرَكَ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir], telah mengabarkan kepada kami [Sufyan] telah menceritakan kepadaku [Yunus bin 'Ubaid] dari ['Amr bin Sa'id] dari [Abu Zur'ah] dari [Jarir], ia berkata; aku bertanya kepada Rasulullah shallallahu 'alaihi wasallam mengenai pandangan tiba-tiba. Kemudian beliau berkata: \"Palingkan pandanganmu!\" "},"1772":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ مُوسَى الْفَزَارِيُّ أَخْبَرَنَا شَرِيكٌ عَنْ أَبِي رَبِيعَةَ الْإِيَادِيِّ عَنْ ابْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِعَلِيٍّ يَا عَلِيُّ لَا تُتْبِعْ النَّظْرَةَ النَّظْرَةَ فَإِنَّ لَكَ الْأُولَى وَلَيْسَتْ لَكَ الْآخِرَةُ","id":"Telah menceritakan kepada kami [Isma'il bin Musa Al Fazari], telah mengabarkan kepada kami [Syarik] dari [Abu Rabi'ah Al Iyadi] dari [Ibnu Buraidah] dari [ayahnya], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda kepada Ali: \"Wahai Ali, janganlah engkau ikutkan pandangan pertama dengan pandangan yang lain (berikutnya), sesungguhnya bagimu pandangan yang pertama tidak pandangan yang lainnya (berikutnya).\""},"1773":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي وَائِلٍ عَنْ ابْنِ مَسْعُودٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُبَاشِرُ الْمَرْأَةُ الْمَرْأَةَ لِتَنْعَتَهَا لِزَوْجِهَا كَأَنَّمَا يَنْظُرُ إِلَيْهَا","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Abu 'Awanah], dari [Al A'masy] dari [Abu Wail] dari [Ibnu Mas'ud], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah seorang wanita melihat kepada wanita yang lain agar dapat menyebutkan sifat-sifatnya kepada suaminya, sehingga seolah-olah sang suami melihat kepada wanita tersebut.\""},"1774":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هِشَامٌ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى امْرَأَةً فَدَخَلَ عَلَى زَيْنَبَ بِنْتِ جَحْشٍ فَقَضَى حَاجَتَهُ مِنْهَا ثُمَّ خَرَجَ إِلَى أَصْحَابِهِ فَقَالَ لَهُمْ إِنَّ الْمَرْأَةَ تُقْبِلُ فِي صُورَةِ شَيْطَانٍ فَمَنْ وَجَدَ مِنْ ذَلِكَ شَيْئًا فَلْيَأْتِ أَهْلَهُ فَإِنَّهُ يُضْمِرُ مَا فِي نَفْسِهِ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim], telah menceritakan kepada kami [Hisyam], dari [Abu Az Zubair], dari [Jabir], bahwa Nabi shallallahu 'alaihi wasallam melihat seorang wanita kemudian beliau menemui Zainab binti Jahsy dan menunaikan hajat beliau kepadanya, kemudian keluar menuju para sahabatnya dan berkata kepada mereka: \"Sesungguhnya seorang wanita itu (ketika) datang dalam bentuk syetan. Maka barangsiapa yang (setelah melihatnya) timbul pada dirinya sesuatu (syahwat) hendaknya ia mendatangi isterinya, karena hal tersebut akan melampiaskan syahwatnya (dan ketenangan pikirannya).\" "},"1775":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ حَدَّثَنَا ابْنُ ثَوْرٍ عَنْ مَعْمَرٍ أَخْبَرَنَا ابْنُ طَاوُسٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ قَالَمَا رَأَيْتُ شَيْئًا أَشْبَهَ بِاللَّمَمِ مِمَّا قَالَ أَبُو هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ كَتَبَ عَلَى ابْنِ آدَمَ حَظَّهُ مِنْ الزِّنَا أَدْرَكَ ذَلِكَ لَا مَحَالَةَ فَزِنَا الْعَيْنَيْنِ النَّظَرُ وَزِنَا اللِّسَانِ الْمَنْطِقُ وَالنَّفْسُ تَمَنَّى وَتَشْتَهِي وَالْفَرْجُ يُصَدِّقُ ذَلِكَ وَيُكَذِّبُهُحَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِكُلِّ ابْنِ آدَمَ حَظُّهُ مِنْ الزِّنَا بِهَذِهِ الْقِصَّةِ قَالَ وَالْيَدَانِ تَزْنِيَانِ فَزِنَاهُمَا الْبَطْشُ وَالرِّجْلَانِ تَزْنِيَانِ فَزِنَاهُمَا الْمَشْيُ وَالْفَمُ يَزْنِي فَزِنَاهُ الْقُبَلُ حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ عَجْلَانَ عَنْ الْقَعْقَاعِ بْنِ حَكِيمٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذِهِ الْقِصَّةِ قَالَ وَالْأُذُنُ زِنَاهَا الِاسْتِمَاعُ","id":"Telah menceritakan kepada kami [Muhammad bin 'Ubaid], telah menceritakan kepada kami [Ibnu Tsaur] dari [Ma'mar], telah mengabarkan kepada kami [Ibnu Thawus] dari [ayahnya] dari [Ibnu Abbas], ia berkata; aku tidak melihat sesuatu yang lebih mirip dengan dosa-dosa kecil daripada apa yang dikatakan [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam: \"Sesungguhnya Allah telah menetapkan bagian zina anak keturunan Adam yang pasti ia jumpai, zina kedua mata adalah melihat, zina lidah adalah mengucap, zina hati adalah berangan dan bernafsu, dan kemaluan akan membenarkan hal tersebut atau mendustakannya.\" Telah menceritakan kepada kami [Musa bin Isma'il], telah menceritakan kepada kami [Hammad] dari [Suhail bin Abu Shalih], dari [ayahnya], dari [Abu Hurairah], bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Setiap anak keturunan Adam memiliki bagiannya dari zina….\" Dengan kisah ini, beliau bersabda: \"Kedua tangan berzina dan zinanya adalah menyentuh, kedua kaki berzina dan zinanya adalah berjalan, mulut berzina dan zinanya adalah mencium.\" Telah menceritakan kepada kami [Qutaibah bin Sa'id], Telah menceritakan kepada kami [Al Laits], dari [Ibnu 'Ajlan], dari [Al Qa'qa' bin Hakim] dari [Abu Shalih] dari [Abu Hurairah], dari Nabi shallallahu 'alaihi wasallam dengan kisah ini. Beliau mengatakan: \"Dan zina telinganya adalah mendengar.\""},"1776":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ بْنِ مَيْسَرَةَ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ صَالِحٍ أَبِي الْخَلِيلِ عَنْ أَبِي عَلْقَمَةَ الْهَاشِمِيِّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ يَوْمَ حُنَيْنٍ بَعْثًا إِلَى أَوْطَاسَ فَلَقُوا عَدُوَّهُمْ فَقَاتَلُوهُمْ فَظَهَرُوا عَلَيْهِمْ وَأَصَابُوا لَهُمْ سَبَايَا فَكَأَنَّ أُنَاسًا مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَحَرَّجُوا مِنْ غِشْيَانِهِنَّ مِنْ أَجْلِ أَزْوَاجِهِنَّ مِنْ الْمُشْرِكِينَ فَأَنْزَلَ اللَّهُ تَعَالَى فِي ذَلِكَ{ وَالْمُحْصَنَاتُ مِنْ النِّسَاءِ إِلَّا مَا مَلَكَتْ أَيْمَانُكُمْ }أَيْ فَهُنَّ لَهُمْ حَلَالٌ إِذَا انْقَضَتْ عِدَّتُهُنَّ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Umar bin Maisarah], telah menceritakan kepada kami [Yazid bin Zurai'], telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Shalih Abu Al Khalil] dari [Abu 'Alqamah Al Hasyimi], dari [Abu Sa'id Al Khudri], bahwa Rasulullah shallallahu 'alaihi wasallam telah mengutus sebuah utusan pada saat perang Hunain menuju kepada Suku Authas. Kemudian mereka bertemu dengan musuh mereka, dan berperang dengan mereka. Lalu mereka mengalahkan musuh-musuh tersebut dan mendapatkan wanita-wanita tawanan. Seolah-olah beberapa orang sahabat Rasulullah shallallahu 'alaihi wasallam merasa berat untuk bercampur dengan mereka karena keberadaan suami-suami mereka dari kalangan orang-orang musyrik. Kemudian Allah Ta'ala menurunkan ayat mengenai hal tersebut: \"Dan (diharamkan juga kamu mengawini) wanita yang bersuami, kecuali budak-budak yang kamu miliki.\" Yaitu; mereka halal bagi kalian apabila telah selesai 'iddah mereka. "},"1777":{"ar":"حَدَّثَنَا النُّفَيْلِيُّ حَدَّثَنَا مِسْكِينٌ حَدَّثَنَا شُعْبَةُ عَنْ يَزِيدَ بْنِ خُمَيْرٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ جُبَيْرِ بْنِ نُفَيْرٍ عَنْ أَبِيهِ عَنْ أَبِي الدَّرْدَاءِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ فِي غَزْوَةٍ فَرَأَى امْرَأَةً مُجِحًّا فَقَالَ لَعَلَّ صَاحِبَهَا أَلَمَّ بِهَا قَالُوا نَعَمْ فَقَالَ لَقَدْ هَمَمْتُ أَنْ أَلْعَنَهُ لَعْنَةً تَدْخُلُ مَعَهُ فِي قَبْرِهِ كَيْفَ يُوَرِّثُهُ وَهُوَ لَا يَحِلُّ لَهُ وَكَيْفَ يَسْتَخْدِمُهُ وَهُوَ لَا يَحِلُّ لَهُ","id":"Telah menceritakan kepada kami [An Nufaili], telah menceritakan kepada kami [Miskin], telah menceritakan kepada kami [Syu'bah] dari [Yazid bin Khumair], dari [Abdurrahman bin Jubair bin Nufair] dari [ayahnya], dari [Abu Ad Darda`] bahwa Rasulullah shallallahu 'alaihi wasallam pernah berada dalam suatu peperangan kemudian beliau melihat seorang wanita hamil yang mendekati waktu melahirkan, kemudian beliau berkata; kemungkinan pemiliknya menggaulinya. Mereka berkata; ya. Kemudian beliau berkata: \"Sungguh aku berkeinginan untuk melaknat laki-laki tersebut dengan laknat yang ia bawa masuk dalam kuburnya. Bagaimana ia mewariskan kepada janin tersebut sementara ia tidak halal baginya (karena bukan anaknya), dan bagaimana ia memperbudaknya sementara hal tersebut tidak halal baginya (memperbudaknya sementara ia memang anaknya).\""},"1778":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَوْنٍ أَخْبَرَنَا شَرِيكٌ عَنْ قَيْسِ بْنِ وَهْبٍ عَنْ أَبِي الْوَدَّاكِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّوَرَفَعَهُ أَنَّهُ قَالَ فِي سَبَايَا أَوْطَاسَ لَا تُوطَأُ حَامِلٌ حَتَّى تَضَعَ وَلَا غَيْرُ ذَاتِ حَمْلٍ حَتَّى تَحِيضَ حَيْضَةً","id":"Telah menceritakan kepada kami ['Amr bin 'Aun], telah mengabarkan kepada kami [Syarik], dari [Qais bin Wahb] dari [Abu Al Waddak], dari [Abu Sa'id Al Khudri], dan ia memarfu'kan hadits tersebut, bahwa ia berkata mengenai wanita-wanita tawanan dari Suku Authas; wanita hamil tidak boleh digauli hingga melahirkan, dan tidak pula wanita yang tidak hamil hingga mengalami satu kali haid. "},"1779":{"ar":"حَدَّثَنَا النُّفَيْلِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ حَدَّثَنِي يَزِيدُ بْنُ أَبِي حَبِيبٍ عَنْ أَبِي مَرْزُوقٍ عَنْ حَنَشٍ الصَّنْعَانِيِّ عَنْ رُوَيْفِعِ بْنِ ثَابِتٍ الْأَنْصَارِيِّ قَالَقَامَ فِينَا خَطِيبًا قَالَ أَمَا إِنِّي لَا أَقُولُ لَكُمْ إِلَّا مَا سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يَوْمَ حُنَيْنٍ قَالَ لَا يَحِلُّ لِامْرِئٍ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ أَنْ يَسْقِيَ مَاءَهُ زَرْعَ غَيْرِهِ يَعْنِي إِتْيَانَ الْحَبَالَى وَلَا يَحِلُّ لِامْرِئٍ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ أَنْ يَقَعَ عَلَى امْرَأَةٍ مِنْ السَّبْيِ حَتَّى يَسْتَبْرِئَهَا وَلَا يَحِلُّ لِامْرِئٍ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ أَنْ يَبِيعَ مَغْنَمًا حَتَّى يُقْسَمَحَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ ابْنِ إِسْحَقَ بِهَذَا الْحَدِيثِ قَالَ حَتَّى يَسْتَبْرِئَهَا بِحَيْضَةٍ زَادَ فِيهِ بِحَيْضَةٍ وَهُوَ وَهْمٌ مِنْ أَبِي مُعَاوِيَةَ وَهُوَ صَحِيحٌ فِي حَدِيثِ أَبِي سَعِيدٍ زَادَ وَمَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلَا يَرْكَبْ دَابَّةً مِنْ فَيْءِ الْمُسْلِمِينَ حَتَّى إِذَا أَعْجَفَهَا رَدَّهَا فِيهِ وَمَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلَا يَلْبَسْ ثَوْبًا مِنْ فَيْءِ الْمُسْلِمِينَ حَتَّى إِذَا أَخْلَقَهُ رَدَّهُ فِيهِ قَالَ أَبُو دَاوُد الْحَيْضَةُ لَيْسَتْ بِمَحْفُوظَةٍ وَهُوَ وَهْمٌ مِنْ أَبِي مُعَاوِيَةَ","id":"Telah menceritakan kepada kami [An Nufaili], telah menceritakan kepada kami [Muhammad bin Salamah], dari [Muhammad bin Ishaq], telah menceritakan kepadaku [Yazid bin Abu Habib] dari [Abu Marzuq] dari [Hanasy Ash Shan'ani], dari [Rufaifi' bin Tsabit Al Anshari], ia berkata ketika berkhutbah kepada kami; ketahuilah bahwa aku tidak berbicara kepada kalian kecuali apa yang aku dengar dari Rasulullah shallallahu 'alaihi wasallam. Pada saat perang Hunain beliau berkata: \"Tidak halal bagi orang yang beriman kepada Allah dan Hari Akhir untuk menyiramkan airnya kepada tanaman orang lain -yaitu menggauli wanita-wanita yang sedang hamil\", dan tidak halal bagi seseorang yang beriman kepada Allah dan Hari Akhir untuk menggauli wanita tawanan hingga ia membiarkannya mengalami haid, dan tidaklah halal bagi seseorang yang beriman kepada Allah dan Hari Akhir untuk menjual harta rampasan perang hingga harta tersebut telah dibagikan.\" Telah menceritakan kepada kami [Sa'id bin Manshur], telah menceritakan kepada kami [Abu Mu'awiyah] dari [Ibnu Ishaq], dengan hadits ini. Ia berkata; hingga membiarkannya mengalami satu kali haid. Ia menambahkan kata; satu kali haid. Hal tersebut merupakan suatu kesalahan dari Abu Mu'awiyah, dan hal itu adalah benar dalam hadits Abu Sa'id, ia tambahkan kata: \"Barangsiapa yang beriman kepada Allah dan Hari Akhir, maka janganlah ia mengendarai hewan yang berasal dari harta rampasan perang orang-orang muslim, dan ketika telah menjadi kurus dan lemah maka ia mengembalikannya kepada harta rampasan tersebut. Dan barangsiapa yang beriman kepada Allah dan Hari Akhir maka janganlah ia memakai pakaian yang berasal dari rampasan perang orang-orang muslim, dan ketika telah usang ia mengembalikannya ke dalam rampasan perang tersebut.\" Abu Daud berkata; kata satu kali haid bukanlah sesuatu yang dihafal, hal itu adalah kesalahan dari Abu Mu'awiyah. "},"1780":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ وَعَبْدُ اللَّهِ بْنُ سَعِيدٍ قَالَا حَدَّثَنَا أَبُو خَالِدٍ يَعْنِي سُلَيْمَانَ بْنَ حَيَّانَ عَنْ ابْنِ عَجْلَانَ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا تَزَوَّجَ أَحَدُكُمْ امْرَأَةً أَوْ اشْتَرَى خَادِمًا فَلْيَقُلْ اللَّهُمَّ إِنِّي أَسْأَلُكَ خَيْرَهَا وَخَيْرَ مَا جَبَلْتَهَا عَلَيْهِ وَأَعُوذُ بِكَ مِنْ شَرِّهَا وَمِنْ شَرِّ مَا جَبَلْتَهَا عَلَيْهِ وَإِذَا اشْتَرَى بَعِيرًا فَلْيَأْخُذْ بِذِرْوَةِ سَنَامِهِ وَلْيَقُلْ مِثْلَ ذَلِكَ قَالَ أَبُو دَاوُد زَادَ أَبُو سَعِيدٍ ثُمَّ لِيَأْخُذْ بِنَاصِيَتِهَا وَلْيَدْعُ بِالْبَرَكَةِ فِي الْمَرْأَةِ وَالْخَادِمِ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah], dan [Abdullah bin Sa'id], mereka berkata; telah menceritakan kepada kami [Abu Khalid Sulaiman bin Hayyan] dari [Ibnu 'Ajlan], dari ['Amr bin Syu'aib] dari [ayahnya], dari [kakeknya], dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Apabila salah seorang diantara kalian menikah atau membeli budak maka hendaknya ia mengucapkan; ALLAAHUMMA INNII AS`ALUKA KHAIRAHAA WA KHAIRA MAA JABALTAHAA 'ALAIHI WA A'UUDZU BIKA MIN SYARRIHAA WA SYARRI MAA JABALTAHAA 'ALAIH (Ya Allah, aku memohon kepadaMu kebaikannya dan kebaikan sesuatu yang Engkau ciptakan dia padanya, dan aku berlindung kepadaMu dari keburukannya dan keburukan sesuatu yang Engkau ciptakan dia padanya). Dan apabila ia membeli unta maka hendaknya ia memegang punuknya dan mengucapkan seperti itu!\" Abu Daud berkata; Abu Sa'id menambahkan; kemudian hendaknya ia memegang ubun-ubunnya dan berdoa untuk mendapatkan berkah pada wanita dan budak. "},"1781":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ كُرَيْبٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ أَنَّ أَحَدَكُمْ إِذَا أَرَادَ أَنْ يَأْتِيَ أَهْلَهُ قَالَ بِسْمِ اللَّهِ اللَّهُمَّ جَنِّبْنَا الشَّيْطَانَ وَجَنِّبْ الشَّيْطَانَ مَا رَزَقْتَنَا ثُمَّ قُدِّرَ أَنْ يَكُونَ بَيْنَهُمَا وَلَدٌ فِي ذَلِكَ لَمْ يَضُرَّهُ شَيْطَانٌ أَبَدًا","id":"Telah menceritakan kepada kami [Muhammad bin Isa], telah menceritakan kepada kami [Jarir], dari [Manshur], dari [Salim bin Abu Al Ja'd] dari [Kuraib] dari [Ibnu Abbas], ia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang diantara kalian hendak mendatangi isterinya (mengaulinya) hendaknya mengucapkan (doa): BISMILLAAH, ALLAAHUMMA JANNIBNASY SYAITHAANA WA JANNIBISY SYAITHAANA MAA RAZAQTANAA (Dengan nama Allah, ya Allah, jauhkan kami dari syetan dan jauhkan syetan dari anak yang Engkau rizqikan kepada kami). Kemudian ditakdirkan mereka berdua memiliki anak dari hubungan tersebut, maka anak tersebut tidak akan diganggu syetan selamanya. "},"1782":{"ar":"حَدَّثَنَا هَنَّادٌ عَنْ وَكِيعٍ عَنْ سُفْيَانَ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ الْحَارِثِ بْنِ مَخْلَدٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَلْعُونٌ مَنْ أَتَى امْرَأَتَهُ فِي دُبُرِهَا","id":"Telah menceritakan kepada kami [Hannad] dari [Waki'] dari [Sufyan], dari [Suhail bin Abu Shalih] dari [Al Harits bin Makhlad] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ternaknat, orang yang menggauli isterinya pada duburnya.\""},"1783":{"ar":"حَدَّثَنَا ابْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ حَدَّثَنَا سُفْيَانُ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ قَالَ سَمِعْتُ جَابِرًا يَقُولُإِنَّ الْيَهُودَ يَقُولُونَ إِذَا جَامَعَ الرَّجُلُ أَهْلَهُ فِي فَرْجِهَا مِنْ وَرَائِهَا كَانَ وَلَدُهُ أَحْوَلَ فَأَنْزَلَ اللَّهُ سُبْحَانَهُ وَتَعَالَى{ نِسَاؤُكُمْ حَرْثٌ لَكُمْ فَأْتُوا حَرْثَكُمْ أَنَّى شِئْتُمْ }","id":"Telah menceritakan kepada kami [Ibnu Basysyar], telah menceritakan kepada kami [Abdurrahman], telah menceritakan kepada kami [Sufyan], dari [Muhammad Al Munkadir], ia berkata; saya mendengar [Jabir] berkata; sesungguhnya orang-orang Yahudi berkata; apabila seorang laki-laki menggauli isterinya pada kemaluannya dari arah belakang maka anaknya juling. Kemudian Allah subhanahu wa ta'ala menurunkan ayat: \"Isteri-isterimu adalah (seperti) tanah tempat kamu bercocok tanam, maka datangilah tanah tempat bercocok-tanammu itu bagaimana saja kamu kehendaki.\""},"1784":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ يَحْيَى أَبُو الْأَصْبَغِ حَدَّثَنِي مُحَمَّدٌ يَعْنِي ابْنَ سَلَمَةَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ أَبَانَ بْنِ صَالِحٍ عَنْ مُجَاهِدٍ عَنْ ابْنِ عَبَّاسٍ قَالَإِنَّ ابْنَ عُمَرَ وَاللَّهُ يَغْفِرُ لَهُ أَوْهَمَ إِنَّمَا كَانَ هَذَا الْحَيُّ مِنْ الْأَنْصَارِ وَهُمْ أَهْلُ وَثَنٍ مَعَ هَذَا الْحَيِّ مِنْ يَهُودَ وَهُمْ أَهْلُ كِتَابٍ وَكَانُوا يَرَوْنَ لَهُمْ فَضْلًا عَلَيْهِمْ فِي الْعِلْمِ فَكَانُوا يَقْتَدُونَ بِكَثِيرٍ مِنْ فِعْلِهِمْ وَكَانَ مِنْ أَمْرِ أَهْلِ الْكِتَابِ أَنْ لَا يَأْتُوا النِّسَاءَ إِلَّا عَلَى حَرْفٍ وَذَلِكَ أَسْتَرُ مَا تَكُونُ الْمَرْأَةُ فَكَانَ هَذَا الْحَيُّ مِنْ الْأَنْصَارِ قَدْ أَخَذُوا بِذَلِكَ مِنْ فِعْلِهِمْ وَكَانَ هَذَا الْحَيُّ مِنْ قُرَيْشٍ يَشْرَحُونَ النِّسَاءَ شَرْحًا مُنْكَرًا وَيَتَلَذَّذُونَ مِنْهُنَّ مُقْبِلَاتٍ وَمُدْبِرَاتٍ وَمُسْتَلْقِيَاتٍ فَلَمَّا قَدِمَ الْمُهَاجِرُونَ الْمَدِينَةَ تَزَوَّجَ رَجُلٌ مِنْهُمْ امْرَأَةً مِنْ الْأَنْصَارِ فَذَهَبَ يَصْنَعُ بِهَا ذَلِكَ فَأَنْكَرَتْهُ عَلَيْهِ وَقَالَتْ إِنَّمَا كُنَّا نُؤْتَى عَلَى حَرْفٍ فَاصْنَعْ ذَلِكَ وَإِلَّا فَاجْتَنِبْنِي حَتَّى شَرِيَ أَمْرُهُمَا فَبَلَغَ ذَلِكَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ نِسَاؤُكُمْ حَرْثٌ لَكُمْ فَأْتُوا حَرْثَكُمْ أَنَّى شِئْتُمْ }أَيْ مُقْبِلَاتٍ وَمُدْبِرَاتٍ وَمُسْتَلْقِيَاتٍ يَعْنِي بِذَلِكَ مَوْضِعَ الْوَلَدِ","id":"Telah menceritakan kepada kami [Abdul Aziz bin Yahya Abu Al Ashbagh], telah menceritakan kepadaku [Muhammad bin Salamah], dari [Muhammad bin Ishaq] dari [Aban bin Shalih] dari [Mujahid] dari [Ibnu Abbas], ia berkata; sesungguhnya Ibnu Umar semoga Allah mengampuninya, ia telah melakukan suatu kesalahan. Sesungguhnya terdapat sebuah kampong anshar yang merupakan para penyembah berhala, hidup bersama kampong yahudi yang merupakan ahli kitab. Dan mereka memandang bahwa orang-orang yahudi memeliki keutamaan atas mereka dalam hal ilmu. Dan mereka mengikuti kebanyakan perbuatan orang-orang yahudi. Diantara keadaan ahli kitab adalah bahwa mereka tidak menggauli isteri mereka kecuali dengan satu cara, dan hal tersebut lebih menjaga rasa malu seorang wanita. Dan orang-orang anshar ini mengikuti perbuatan mereka dalam hal tersebut. Sementara orang-orang Quraisy menggauli isteri-isteri mereka dengan cara yang mereka ingkari, orang-orang Quraisy menggauli mereka dalam keadaan menghadap dan membelakangi serta dalam keadaan terlentang. Kemudian tatkala orang-orang muhajirin datang ke Madinah, salah seorang diantara mereka menikahi seorang wanita anshar. Kemudian ia melakukan hal tersebut. Kemudian wanita anshar tersebut mengingkarinya dan berkata; sesungguhnya kami didatangi dengan satu cara, maka lakukan hal tersebut, jika tidak maka jauhilah aku! Hingga tersebar permasalahan mereka, dan hal tersebut sampai kepada Rasulullah shallallahu 'alaihi wasallam. kemudian Allah 'azza wajalla menurunkan ayat: \"Isteri-isterimu adalah (seperti) tanah tempat kamu bercocok tanam, maka datangilah tanah tempat bercocok-tanammu itu bagaimana saja kamu kehendaki.\" Yakni dalam keadaan menghadap (saling berhadapan), membelakangi dan terlentang, yaitu pada tempat diperolehnya anak (farj). "},"1785":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ أَخْبَرَنَا ثَابِتٌ الْبُنَانِيُّ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ الْيَهُودَ كَانَتْ إِذَا حَاضَتْ مِنْهُمْ امْرَأَةٌ أَخْرَجُوهَا مِنْ الْبَيْتِ وَلَمْ يُؤَاكِلُوهَا وَلَمْ يُشَارِبُوهَا وَلَمْ يُجَامِعُوهَا فِي الْبَيْتِ فَسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَلِكَ فَأَنْزَلَ اللَّهُ سُبْحَانَهُ وَتَعَالَى{ وَيَسْأَلُونَكَ عَنْ الْمَحِيضِ قُلْ هُوَ أَذًى فَاعْتَزِلُوا النِّسَاءَ فِي الْمَحِيضِ }إِلَى آخِرِ الْآيَةِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَامِعُوهُنَّ فِي الْبُيُوتِ وَاصْنَعُوا كُلَّ شَيْءٍ غَيْرَ النِّكَاحِ فَقَالَتْ الْيَهُودُ مَا يُرِيدُ هَذَا الرَّجُلُ أَنْ يَدَعَ شَيْئًا مِنْ أَمْرِنَا إِلَّا خَالَفَنَا فِيهِ فَجَاءَ أُسَيْدُ بْنُ حُضَيْرٍ وَعَبَّادُ بْنُ بِشْرٍ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَا يَا رَسُولَ اللَّهِ إِنَّ الْيَهُودَ تَقُولُ كَذَا وَكَذَا أَفَلَا نَنْكِحُهُنَّ فِي الْمَحِيضِ فَتَمَعَّرَ وَجْهُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى ظَنَنَّا أَنْ قَدْ وَجَدَ عَلَيْهِمَا فَخَرَجَا فَاسْتَقْبَلَتْهُمَا هَدِيَّةٌ مِنْ لَبَنٍ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَبَعَثَ فِي آثَارِهِمَا فَظَنَنَّا أَنَّهُ لَمْ يَجِدْ عَلَيْهِمَا","id":"Telah menceritakan kepada kami [Musa bin Isma'il], telah menceritakan kepada kami [Hammad], telah mengabarkan kepada kami [Tsabit Al Bunani], dari [Anas bin Malik] bahwa orang-orang Yahudi apabila seorang isteri mengalami haid maka mereka mengeluarkannya dari rumah, dan tidak makan bersamanya, tidak mengajaknya bermusyawarah, dan tidak menggaulinya di rumah. Kemudian Rasulullah shallallahu 'alaihi wasallam ditanya mengenai hal tersebut; kemudian Allah subhanahu wa ta'ala menurunkan ayat: \"Mereka bertanya kepadamu tentang haidh. Katakanlah: \"Haidh itu adalah suatu kotoran.\" Oleh sebab itu hendaklah kamu menjauhkan diri dari wanita di waktu haidh.\" Hingga akhir ayat. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bergaullah dengan mereka di rumah dan lakukan segala sesuatu selain bersenggama.\" Tidaklah orang ini ingin meninggalkan sesuatu yang berasal dari urusan kita melainkan untuk menyelisihi kita. Kemudian Usaid bin Hudhair serta 'Abbad bin Bisyr datang kepada Rasulullah shallallahu 'alaihi wasallam dan berkata; Wahai Rasulullah, sesungguhnya orang-orang Yahudi mengatakan demikian dan demikian, tidakkah kita bercampur dengan mereka (para isteri) di saat sedang haid? Maka merah padam wajah Rasulullah shallallahu 'alaihi wasallam hingga kami menyangka beliau telah murka kepada mereka. Kemudian mereka berdua keluar, kemudian mereka berpapasan dengan hadiah susu yang diberikan kepada Rasulullah shallallahu 'alaihi wasallam. Kemudian beliau mengirim seseorang agar mengejar mereka berdua, hingga kami menyangka bahwa beliau tidak murka kepada mereka. "},"1786":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ جَابِرِ بْنِ صُبْحٍ قَالَ سَمِعْتُ خِلَاسًا الْهَجَرِيَّ قَالَ سَمِعْتُ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا تَقُولُكُنْتُ أَنَا وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَبِيتُ فِي الشِّعَارِ الْوَاحِدِ وَأَنَا حَائِضٌ طَامِثٌ فَإِنْ أَصَابَهُ مِنِّي شَيْءٌ غَسَلَ مَكَانَهُ وَلَمْ يَعْدُهُ وَإِنْ أَصَابَ تَعْنِي ثَوْبَهُ مِنْهُ شَيْءٌ غَسَلَ مَكَانَهُ وَلَمْ يَعْدُهُ وَصَلَّى فِيهِ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Yahya] dari [Jabir bin Shubh], ia berkata; saya mendengar [Khilas Al Hajari] berkata; saya mendengar [Aisyah] radliallahu 'anha berkata; aku dan Rasulullah shallallahu 'alaihi wasallam pernah bermalam dalam satu kain, sementara aku dalam keadaan sedang haid. Apabila ada sebagian darah haidku yang mengenai beliau, maka beliau mencuci tempat yang terkena dan tidak melebihinya, dan apabila ada sebagian darah haidku yang mengenai pakaiannya maka beliau mencuci tempat yang terkena dan tidak melebihinya, dan beliau melakukan shalat dengan memakai pakaian tersebut. "},"1787":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ وَمُسَدَّدٌ قَالَا حَدَّثَنَا حَفْصٌ عَنْ الشَّيْبَانِيِّ عَنْ عَبْدِ اللَّهِ بْنِ شَدَّادٍ عَنْ خَالَتِهِ مَيْمُونَةَ بِنْتِ الْحَارِثِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا أَرَادَ أَنْ يُبَاشِرَ امْرَأَةً مِنْ نِسَائِهِ وَهِيَ حَائِضٌ أَمَرَهَا أَنْ تَتَّزِرَ ثُمَّ يُبَاشِرُهَا","id":"Telah menceritakan kepada kami [Muhammad bin Al 'Ala`] dan [Musaddad], mereka berkata; telah menceritakan kepada kami [Hafsh] dari [Asy Syaibani] dari [Abdullah bin Syaddad] dari [bibinya yaitu Maimunah binti Al Harits] bahwa Rasulullah shallallahu 'alaihi wasallam apabila hendak menggauli isterinya yang sedang haid beliau memerintahkannya agar memakai kain, kemudian beliau menggaulinya. "},"1788":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ شُعْبَةَ وَغَيْرُهُ عَنْ سَعِيدٍ حَدَّثَنِي الْحَكَمُ عَنْ عَبْدِ الْحَمِيدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ مِقْسَمٍ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الَّذِي يَأْتِي امْرَأَتَهُ وَهِيَ حَائِضٌ قَالَ يَتَصَدَّقُ بِدِينَارٍ أَوْ بِنِصْفِ دِينَارٍ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Yahya] dari [Syu'bah] dan [yang lainnya], dari [Sa'id], telah menceritakan kepadaku [Al Hakam], dari [Abdul Hamid bin Abdurrahman] dari [Miqsam] dari [Ibnu Abbas], dari Nabi shallallahu 'alaihi wasallam mengenai orang yang mendatangi isterinya dalam keadaan sedang haid: \"Ia harus bersedekah satu dinar atau setengah dinar.\""},"1789":{"ar":"حَدَّثَنَا عَبْدُ السَّلَامِ بْنُ مُطَهَّرٍ حَدَّثَنَا جَعْفَرٌ يَعْنِي ابْنَ سُلَيْمَانَ عَنْ عَلِيِّ بْنِ الْحَكَمِ الْبُنَانِيِّ عَنْ أَبِي الْحَسَنِ الْجَزَرِيِّ عَنْ مِقْسَمٍ عَنْ ابْنِ عَبَّاسٍ قَالَإِذَا أَصَابَهَا فِي الدَّمِ فَدِينَارٌ وَإِذَا أَصَابَهَا فِي انْقِطَاعِ الدَّمِ فَنِصْفُ دِينَارٍ","id":"Telah menceritakan kepada kami [Abdus Salam bin Muthahhar], telah menceritakan kepada kami [Ja'far bin Sulaiman] dari [Ali bin Al Hakam Al Bunani] dari [Abu Al Hasan Al Hazari] dari [Miqsam] dari [Ibnu Abbas], ia berkata; apabila menggaulinya ketika sedang haid makan ia bersedekah satu dinar, dan apabila menggaulinya ketika telah terhentinya darah haid (sebelum bersuci) maka ia bersedekah setengah dinar. "},"1790":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِسْمَعِيلَ الطَّالَقَانِيُّ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ عَنْ قَزَعَةَ عَنْ أَبِي سَعِيدٍذُكِرَ ذَلِكَ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعْنِي الْعَزْلَ قَالَ فَلِمَ يَفْعَلُ أَحَدُكُمْ وَلَمْ يَقُلْ فَلَا يَفْعَلْ أَحَدُكُمْ فَإِنَّهُ لَيْسَتْ مِنْ نَفْسٍ مَخْلُوقَةٍ إِلَّا اللَّهُ خَالِقُهَاقَالَ أَبُو دَاوُد قَزَعَةُ مَوْلَى زِيَادٍ","id":"Telah menceritakan kepada kami [Ishaq bin Isma'il Ath Thalaqani], telah menceritakan kepada kami [Sufyan] dari [Ibnu Abu Najih] dari [Mujahid] dari [Qaza'ah] dari [Abu Sa'id], telah disebutkan 'azl (mengeluarkan mani di luar rahim) di hadapan Rasulullah shallallahu wa'alaihi wa sallam, kemudian beliau berkata: \"Kenapa salah seorang diantara kalian melakukannya -bukan mengatakan: \"Janganlah salah seorang diantara kalian melakukannya\"-.\"Sesungguhnya tidak ada jiwa yang tercipta kecuali Allah yang menciptakannya.\" Abu Daud berkata; Qaza'ah adalah mantan budak Ziyad. "},"1791":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا أَبَانُ حَدَّثَنَا يَحْيَى أَنَّ مُحَمَّدَ بْنَ عَبْدِ الرَّحْمَنِ بْنِ ثَوْبَانَ حَدَّثَهُ أَنَّ رِفَاعَةَ حَدَّثَهُ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ رَجُلًا قَالَ يَا رَسُولَ اللَّهِ إِنَّ لِي جَارِيَةً وَأَنَا أَعْزِلُ عَنْهَا وَأَنَا أَكْرَهُ أَنْ تَحْمِلَ وَأَنَا أُرِيدُ مَا يُرِيدُ الرِّجَالُ وَإِنَّ الْيَهُودَ تُحَدِّثُ أَنَّ الْعَزْلَ مَوْءُودَةُ الصُّغْرَى قَالَ كَذَبَتْ يَهُودُ لَوْ أَرَادَ اللَّهُ أَنْ يَخْلُقَهُ مَا اسْتَطَعْتَ أَنْ تَصْرِفَهُ","id":"Telah menceritakan kepada kami [Musa bin Isma'il], telah menceritakan kepada kami [Aban], telah menceritakan kepada kami [Yahya] bahwa [Muhammad bin Abdurrahman bin Tsauban], menceritakan kepadanya bahwa [Rifa'ah] telah menceritakan kepadanya dari [Abu Sa'id Al Khudri] bahwa seseorang berkata; wahai Rasulullah, sesungguhnya aku memiliki seorang budak perempuan, dan aku melakukan 'azl terhadapnya, serta tidak ingin ia hamil, aku menginginkan apa yang diinginkan laki-laki, sementara orang-orang yahudi mengatakan; bahwa 'azl adalah pembunuhan kecil. Beliau berkata: \"Orang-orang yahudi telah berdusta, seandainya Allah menghendaki untuk menciptakannya, maka mereka tidak akan dapat berpaling darinya.\""},"1792":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ رَبِيعَةَ بْنِ أَبِي عَبْدِ الرَّحْمَنِ عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ عَنْ ابْنِ مُحَيْرِيزٍ قَالَدَخَلْتُ الْمَسْجِدَ فَرَأَيْتُ أَبَا سَعِيدٍ الْخُدْرِيَّ فَجَلَسْتُ إِلَيْهِ فَسَأَلْتُهُ عَنْ الْعَزْلِ فَقَالَ أَبُو سَعِيدٍ خَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزْوَةِ بَنِي الْمُصْطَلِقِ فَأَصَبْنَا سَبْيًا مِنْ سَبْيِ الْعَرَبِ فَاشْتَهَيْنَا النِّسَاءَ وَاشْتَدَّتْ عَلَيْنَا الْعُزْبَةُ وَأَحْبَبْنَا الْفِدَاءَ فَأَرَدْنَا أَنْ نَعْزِلَ ثُمَّ قُلْنَا نَعْزِلُ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ أَظْهُرِنَا قَبْلَ أَنْ نَسْأَلَهُ عَنْ ذَلِكَ فَسَأَلْنَاهُ عَنْ ذَلِكَ فَقَالَ مَا عَلَيْكُمْ أَنْ لَا تَفْعَلُوا مَا مِنْ نَسَمَةٍ كَائِنَةٍ إِلَى يَوْمِ الْقِيَامَةِ إِلَّا وَهِيَ كَائِنَةٌ","id":"Telah menceritakan kepada kami [Al Qa'nabi], dari [Malik] dari [Rabi'ah bin Abu Abdurrahman] dari [Muhammad bin Yahya bin Habban] dari [Ibnu Muhairiz], ia berkata; aku pernah memasuki masjid dan melihat [Abu Sa'id Al Khudri], kemudian aku duduk di sampingnya dan bertanya mengenai 'azl. Abu Sa'id berkata; aku pernah keluar bersama Rasulullah shallallahu 'alaihi wasallam ketika perang bersama Bani Mushthaliq, kemudian kami mendapatkan wanita tawanan Arab dan kami menginginkan wanita dan terasa berat kondisi kami yang kurang melakukan jima', sementara kami menginginkan tebusan, maka kami hendak melakukan 'azl. Kemudian kami mengatakan; apakah kita akan melakukan 'azl sementara Rasulullah shallallahu 'alaihi wasallam berada diantara kita sebelum kita bertanya kepada beliau mengenai hal tersebut? Lalu kami bertanya kepada beliau mengenai hal tersebut, lalu beliau berkata: \"Kalian tidak akan tertimpa sesuatu yang membahayakan kalian meski tidak melakukan 'azl, tidaklah suatu jiwa yang tercipta hingga hari Kiamat melainkan jiwa tersebut memang harus tercipta.\""},"1793":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا الْفَضْلُ بْنُ دُكَيْنٍ حَدَّثَنَا زُهَيْرٌ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَجَاءَ رَجُلٌ مِنْ الْأَنْصَارِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ لِي جَارِيَةً أَطُوفُ عَلَيْهَا وَأَنَا أَكْرَهُ أَنْ تَحْمِلَ فَقَالَ اعْزِلْ عَنْهَا إِنْ شِئْتَ فَإِنَّهُ سَيَأْتِيهَا مَا قُدِّرَ لَهَا قَالَ فَلَبِثَ الرَّجُلُ ثُمَّ أَتَاهُ فَقَالَ إِنَّ الْجَارِيَةَ قَدْ حَمَلَتْ قَالَ قَدْ أَخْبَرْتُكَ أَنَّهُ سَيَأْتِيهَا مَا قُدِّرَ لَهَا","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah], telah menceritakan kepada kami [Al Fadhl bin Dukain], telah menceritakan kepada kami [Zuhair] dari [Abu Az Zubair] dari [Jabir], ia berkata; terdapat seorang laki-laki anshar yang datang kepada Rasulullah shallallahu 'alaihi wasallam dan berkata; sesungguhnya aku memiliki seorang budak wanita, aku bercampur dengannya sementara aku tidak ingin ia hamil. Kemudian beliau berkata: \"Lakukanlah 'azl jika engkau menghendaki, sesungguhnya akan datang apa yang telah ditakdirkan baginya.\" Jabir berkata; orang tersebut tinggal beberapa saat kemudian datang kepada beliau dan berkata; sesungguhnya budak tersebut telah hamil. Beliau berkata: \"Aku telah memberitahukan kepadamu bahwa akan datang kepadanya apa yang telah ditakdirkan untuknya.\""},"1794":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا بِشْرٌ حَدَّثَنَا الْجُرَيْرِيُّ ح و حَدَّثَنَا مُؤَمَّلٌ حَدَّثَنَا إِسْمَعِيلُ ح و حَدَّثَنَا مُوسَى حَدَّثَنَا حَمَّادٌ كُلُّهُمْ عَنْ الْجُرَيْرِيِّ عَنْ أَبِي نَضْرَةَ حَدَّثَنِي شَيْخٌ مِنْ طُفَاوَةَ قَالَتَثَوَّيْتُ أَبَا هُرَيْرَةَ بِالْمَدِينَةِ فَلَمْ أَرَ رَجُلًا مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَشَدَّ تَشْمِيرًا وَلَا أَقْوَمَ عَلَى ضَيْفٍ مِنْهُ فَبَيْنَمَا أَنَا عِنْدَهُ يَوْمًا وَهُوَ عَلَى سَرِيرٍ لَهُ وَمَعَهُ كِيسٌ فِيهِ حَصًى أَوْ نَوًى وَأَسْفَلَ مِنْهُ جَارِيَةٌ لَهُ سَوْدَاءُ وَهُوَ يُسَبِّحُ بِهَا حَتَّى إِذَا أَنْفَدَ مَا فِي الْكِيسِ أَلْقَاهُ إِلَيْهَا فَجَمَعَتْهُ فَأَعَادَتْهُ فِي الْكِيسِ فَدَفَعَتْهُ إِلَيْهِ فَقَالَ أَلَا أُحَدِّثُكَ عَنِّي وَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قُلْتُ بَلَى قَالَ بَيْنَا أَنَا أُوعَكُ فِي الْمَسْجِدِ إِذْ جَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى دَخَلَ الْمَسْجِدَ فَقَالَ مَنْ أَحَسَّ الْفَتَى الدَّوْسِيَّ ثَلَاثَ مَرَّاتٍ فَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ هُوَ ذَا يُوعَكُ فِي جَانِبِ الْمَسْجِدِ فَأَقْبَلَ يَمْشِي حَتَّى انْتَهَى إِلَيَّ فَوَضَعَ يَدَهُ عَلَيَّ فَقَالَ لِي مَعْرُوفًا فَنَهَضْتُ فَانْطَلَقَ يَمْشِي حَتَّى أَتَى مَقَامَهُ الَّذِي يُصَلِّي فِيهِ فَأَقْبَلَ عَلَيْهِمْ وَمَعَهُ صَفَّانِ مِنْ رِجَالٍ وَصَفٌّ مِنْ نِسَاءٍ أَوْ صَفَّانِ مِنْ نِسَاءٍ وَصَفٌّ مِنْ رِجَالٍ فَقَالَ إِنْ أَنْسَانِي الشَّيْطَانُ شَيْئًا مِنْ صَلَاتِي فَلْيُسَبِّحْ الْقَوْمُ وَلْيُصَفِّقْ النِّسَاءُ قَالَ فَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَمْ يَنْسَ مِنْ صَلَاتِهِ شَيْئًا فَقَالَ مَجَالِسَكُمْ مَجَالِسَكُمْ زَادَ مُوسَى هَا هُنَا ثُمَّ حَمِدَ اللَّهَ تَعَالَى وَأَثْنَى عَلَيْهِ ثُمَّ قَالَ أَمَّا بَعْدُ ثُمَّ اتَّفَقُوا ثُمَّ أَقْبَلَ عَلَى الرِّجَالِ فَقَالَ هَلْ مِنْكُمْ الرَّجُلُ إِذَا أَتَى أَهْلَهُ فَأَغْلَقَ عَلَيْهِ بَابَهُ وَأَلْقَى عَلَيْهِ سِتْرَهُ وَاسْتَتَرَ بِسِتْرِ اللَّهِ قَالُوا نَعَمْ قَالَ ثُمَّ يَجْلِسُ بَعْدَ ذَلِكَ فَيَقُولُ فَعَلْتُ كَذَا فَعَلْتُ كَذَا قَالَ فَسَكَتُوا قَالَ فَأَقْبَلَ عَلَى النِّسَاءِ فَقَالَ هَلْ مِنْكُنَّ مَنْ تُحَدِّثُ فَسَكَتْنَ فَجَثَتْ فَتَاةٌ قَالَ مُؤَمَّلٌ فِي حَدِيثِهِ فَتَاةٌ كَعَابٌ عَلَى إِحْدَى رُكْ��َتَيْهَا وَتَطَاوَلَتْ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيَرَاهَا وَيَسْمَعَ كَلَامَهَا فَقَالَتْ يَا رَسُولَ اللَّهِ إِنَّهُمْ لَيَتَحَدَّثُونَ وَإِنَّهُنَّ لَيَتَحَدَّثْنَهُ فَقَالَ هَلْ تَدْرُونَ مَا مَثَلُ ذَلِكَ فَقَالَ إِنَّمَا مَثَلُ ذَلِكَ مَثَلُ شَيْطَانَةٍ لَقِيَتْ شَيْطَانًا فِي السِّكَّةِ فَقَضَى مِنْهَا حَاجَتَهُ وَالنَّاسُ يَنْظُرُونَ إِلَيْهِ أَلَا وَإِنَّ طِيبَ الرِّجَالِ مَا ظَهَرَ رِيحُهُ وَلَمْ يَظْهَرْ لَوْنُهُ أَلَا إِنَّ طِيبَ النِّسَاءِ مَا ظَهَرَ لَوْنُهُ وَلَمْ يَظْهَرْ رِيحُهُقَالَ أَبُو دَاوُد وَمِنْ هَا هُنَا حَفِظْتُهُ عَنْ مُؤَمَّلٍ وَمُوسَى أَلَا لَا يُفْضِيَنَّ رَجُلٌ إِلَى رَجُلٍ وَلَا امْرَأَةٌ إِلَى امْرَأَةٍ إِلَّا إِلَى وَلَدٍ أَوْ وَالِدٍ وَذَكَرَ ثَالِثَةً فَأُنْسِيتُهَا وَهُوَ فِي حَدِيثِ مُسَدَّدٍ وَلَكِنِّي لَمْ أُتْقِنْهُ كَمَا أُحِبُّ و قَالَ مُوسَى حَدَّثَنَا حَمَّادٌ عَنْ الْجُرَيْرِيِّ عَنْ أَبِي نَضْرَةَ عَنْ الطُّفَاوِيِّ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Bisyr], telah menceritakan kepada kami [Al Jurairi]. Dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Muammal], telah menceritakan kepada kami [Isma'il], dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Musa], telah menceritakan kepada kami [Hammad], seluruhnya dari [Al Jurairi], dari [Abu Nadhrah], telah menceritakan kepadaku [seorang Syekh dari Thufawah], ia berkata; aku datang kepada [Abu Hurairah] di Madinah dan tidak melihat seorang pun sahabat Nabi shallallahu 'alaihi wasallam yang paling rajin beribadah dan yang lebih baik dalam mengurus tamu daripada dia. Ketika aku berada di rumahnya pada suatu hari, ia sedang dalam berada di atas ranjangnya membawa kantong yang berisi kerikil atau biji kurma dan di bawahnya terdapat seorang budak wanita yang hitam, ia bertasbih menggunakan kerikil tersebut hingga setelah ia menghabiskan apa yang ada dalam kantong, ia melemparnya kepada budak tersebut yang kemudian mengumpulkannya dan mengembalikannya ke dalam kantong serta menyerahkannya kepada Abu Hurairah. Kemudian Abu Hurairah berkata; maukah aku ceritakan kepadamu dariku dan dari Rasulullah shallallahu 'alaihi wasallam? Syekh tersebut berkata; aku katakan; ya. Abu Hurairah berkata; ketika aku sedang tidak enak badan di masjid, tiba-tiba Rasulullah shallallahu 'alaihi wasallam datang hingga masuk masjid, kemudian berkata: \"Siapakah yang mengetahui seorang pemuda dari Daus?\" Beliau mengatakannya sebanyak tiga kali. Kemudian seorang laki-laki berkata; wahai Rasulullah, itu dia sedang kurang sehat badan di sebelah masjid. Kemudian beliau datang berjalan kaki hingga sampai kepadaku, lalu beliau meletakkan tangannya padaku dan mengucapkan perkataan yang baik kepadaku. Kemudian aku berdiri dan beliau pergi berjalan hingga sampai tempat beliau melakukan shalat. Beliau menghadap kepada mereka dan bersama beliau terdapat dua baris orang laki-laki dan satu baris orang wanita atau dua baris orang wanita dan satu baris orang laki-laki. Beliau berkata: \"Apabila syetan melupakanku dari sebagian shalatku, maka (untuk mengingatkannya) hendaknya (bagi) laki-laki bertasbih dan (bagi) wanita menepuk tangan.\" Abu Hurairah berkata; kemudian Rasulullah shallallahu 'alaihi wasallam melakukan shalat dan tidak lupa sedikitpun dari shalatnya, kemudian beliau berkata: \"Tetaplah kalian di tempat duduk kalian.\" Musa menambahkan kata; di sini. Kemudian beliau memuji Allah Ta'ala kemudian berkata: \"Adapun selanjutnya…..\" kemudian mereka (para perawi) sepakat dengan mengatakan; kemudian beliau menghadap kepada orang laki-laki dan berkata: \"Apakah diantara kalian ada seseorang diantara kalian seseorang yang apabila mendatangi isterinya dan menutup pintunya dan melemparkan tabirnya dan memakai tabir dari Allah?\" Mereka berkata; ya. Abu Hurairah berkata; kemudian setelah itu beliau duduk dan berkata: \"Aku melakukan demikian dan demikian.\" Abu Hurairah berkata; kemudian mereka terdiam. Abu Hurairah berkata; kemudian beliau menghadap kepada para wanita dan berkata: \"Apakah diantara kalian ada yang menceritakannya?\" kemudian mereka terdiam, lalu terdapat seorang wanita muda yang berdiri. Muammal berkata dalam haditsnya; wanita muda yang montok pada salah satu kedua pundaknya dan menaikkan lehernya agar Rasulullah shallallahu 'alaihi wasallam melihatnya dan mendengar perkataannya. Kemudian ia berkata; wahai Rasulullah, sesungguhnya para laki-laki membicarakannya dan para wanita membicarakannya. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tahukah apa permisalan seperti itu?\" kemudian beliau berkata: \"Sesungguhnya permisalan hal tersebut adalah seperti syetan wanita yang bertemu dengan syetan laki-laki di sebuah gang, kemudian syetan laki-laki tersebut menunaikan hajatnya terhadap syetan perempuan sementara orang-orang melihat kepadanya. Ketahuilah bahwa minyak laki-laki adalah yang nampak baunya dan tidak nampak warnanya, dan ketahuilah sesungguhnya minyak wanita adalah yang nampak warnanya dan tidak nampak baunya.\" Abu Daud berkata; dan dari sini aku hafal hadits tersebut dari Muammal dan Musa; \"Ketahuilah, janganlah seorang laki-laki berbaring bersama seorang laki-laki dalam satu kain, dan janganlah seorang wanita berbaring dengan seorang wanita dalam satu kain, kecuali dengan seorang anak kecil atau orang tua.\" Dan beliau menyebutkan yang ketiga, namun aku lupa yang ketiga. Dan hal tersebut terdapat dalam hadits Musaddad akan tetapi aku tidak hafal secara sempurna sebagamana yang aku inginkan. Musa berkata; telah menceritakan kepada kami [Hammad] dari [Al Jurairi] dari [Nadhrah] dari [Ath Thufawi]. "},"1795":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ حَدَّثَنَا عَمَّارُ بْنُ رُزَيْقٍ عَنْ عَبْدِ اللَّهِ بْنِ عِيسَى عَنْ عِكْرِمَةَ عَنْ يَحْيَى بْنِ يَعْمَرَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ مِنَّا مَنْ خَبَّبَ امْرَأَةً عَلَى زَوْجِهَا أَوْ عَبْدًا عَلَى سَيِّدِهِ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali], telah menceritakan kepada kami [Zaid bin Al Hubab], telah menceritakan kepada kami ['Ammar bin Ruzaiq] dari [Abdullah bin Isa] dari [Ikrimah] dari [Yahya bin Ya'mr] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bukan dari golongan kami orang yang menipu seorang wanita agar memusuhi suaminya, atau seorang budak agar memusuhi tuannya.\""},"1796":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَسْأَلْ الْمَرْأَةُ طَلَاقَ أُخْتِهَا لِتَسْتَفْرِغَ صَحْفَتَهَا وَلِتَنْكِحَ فَإِنَّمَا لَهَا مَا قُدِّرَ لَهَا","id":"Telah menceritakan kepada kami [Al Qa'nabi], dari [Malik], dari [Abu Az Zinad] dari [Al A'raj], dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah seorang wanita meminta cerai saudarinya agar ia dapat mengosongkan nampannya (menguasai apa yang ia miliki) dan agar ia dapat menikah dengan suaminya, sesungguhnya baginya apa yang ditakdirkan untuknya.\""},"1797":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا مُعَرِّفٌ عَنْ مُحَارِبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا أَحَلَّ اللَّهُ شَيْئًا أَبْغَضَ إِلَيْهِ مِنْ الطَّلَاقِ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus], telah menceritakan kepada kami [Mu'arrif] dari [Muharib], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah Allah menghalalkan sesuatu yang lebih Dia benci daripada perceraian.\""},"1798":{"ar":"حَدَّثَنَا كَثِيرُ بْنُ عُبَيْدٍ حَدَّثَنَا مُحَمَّدُ بْنُ خَالِدٍ عَنْ مُعَرِّفِ بْنِ وَاصِلٍ عَنْ مُحَارِبِ بْنِ دِثَارٍ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَبْغَضُ الْحَلَالِ إِلَى اللَّهِ تَعَالَى الطَّلَاقُ","id":"Telah menceritakan kepada kami [Katsir bin 'Ubaid], telah menceritakan kepada kami [Muhammad bin Khalid] dari [Mu'arrif bin Washil] dari [Muharib bin Ditsar] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Perkara halal yang paling Allah benci adalah perceraian.\""},"1799":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّهُ طَلَّقَ امْرَأَتَهُ وَهِيَ حَائِضٌ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَ عُمَرُ بْنُ الْخَطَّابِ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَلِكَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُرْهُ فَلْيُرَاجِعْهَا ثُمَّ لِيُمْسِكْهَا حَتَّى تَطْهُرَ ثُمَّ تَحِيضَ ثُمَّ تَطْهُرَ ثُمَّ إِنْ شَاءَ أَمْسَكَ بَعْدَ ذَلِكَ وَإِنْ شَاءَ طَلَّقَ قَبْلَ أَنْ يَمَسَّ فَتِلْكَ الْعِدَّةُ الَّتِي أَمَرَ اللَّهُ سُبْحَانَهُ أَنْ تُطَلَّقَ لَهَا النِّسَاءُحَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا اللَّيْثُ عَنْ نَافِعٍ أَنَّ ابْنَ عُمَرَ طَلَّقَ امْرَأَةً لَهُ وَهِيَ حَائِضٌ تَطْلِيقَةً بِمَعْنَى حَدِيثِ مَالِكٍ","id":"Telah menceritakan kepada kami [Al Qa'nabi], dari [Malik] dari [Nafi'] dari [Abdullah bin Umar] bahwa ia telah menceraikan isterinya yang dalam keadaan haid pada zaman Rasulullah shallallahu wa'alaihi wa sallam. Kemudian Umar bin Al Khathab bertanya kepada Rasulullah shallallahu 'alaihi wasallam mengenai hal tersebut. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Perintahkan dia agar kembali kepada isterinya kemudian menahannya (tidak menceraikannya) hingga suci, kemudian haid, kemudian suci, kemudian apabila menghendaki maka ia bisa menahannya setelah itu, dan apabila ia menghendaki maka ia boleh menceraikannya sebelum ia menggaulinya. Itulah iddah yang Allah perintahkan jika ingin mencerakan wanita (hendaknya pada kondisi tersebut).\" Telah menceritakan kepada kami [Qutaibah bin Sa'id], telah menceritakan kepada kami [Al Laits] dari [Nafi'] bahwa [Ibnu Umar] menceraikan isterinya yang sedang haid dengan satu kali cerai, sama dengan makna hadits Malik. "},"1800":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ مَوْلَى آلِ طْلَحَةَ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَأَنَّهُ طَلَّقَ امْرَأَتَهُ وَهِيَ حَائِضٌ فَذَكَرَ ذَلِكَ عُمَرُ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُرْهُ فَلْيُرَاجِعْهَا ثُمَّ لِيُطَلِّقْهَا إِذَا طَهُرَتْ أَوْ وَهِيَ حَامِلٌ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah], telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Muhammad bin Abdurrahman] mantan budak keluarga Thalhah, dari [Salim] dari [Ibnu Umar], bahwa ia telah menceraikan isterinya yang sedang haid. Kemudian Umar menceritakan hal tersebut kepada Nabi shallallahu 'alaihi wasallam. Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Perintah dia agar kembali kepadanya, kemudian menceraikannya apabila ia telah suci atau dalam keadaan hamil.\""},"1801":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا عَنْبَسَةُ حَدَّثَنَا يُونُسُ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي سَالِمُ بْنُ عَبْدِ اللَّهِ عَنْ أَبِيهِأَنَّهُ طَلَّقَ امْرَأَتَهُ وَهِيَ حَائِضٌ فَذَكَرَ ذَلِكَ عُمَرُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَغَيَّظَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَالَ مُرْهُ فَلْيُرَاجِعْهَا ثُمَّ لِيُمْسِكْهَا حَتَّى تَطْهُرَ ثُمَّ تَحِيضَ فَتَطْهُرَ ثُمَّ إِنْ شَاءَ طَلَّقَهَا طَاهِرًا قَبْلَ أَنْ يَمَسَّ فَذَلِكَ الطَّلَاقُ لِلْعِدَّةِ كَمَا أَمَرَ اللَّهُ عَزَّ وَجَلَّ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih], telah menceritakan kepada kami ['Anbasah], telah menceritakan kepada kami [Yunus] dari [Ibnu Syihab], telah mengabarkan kepadaku [Salim bin Abdullah], dari [ayahnya], bahwa ia telah menceraikan isterinya yang sedang hamil, kemudian Umar menceritakan hal tersebut kepada Rasulullah shallallahu 'alaihi wasallam. Kemudian Rasulullah shallallahu 'alaihi wasallam marah dan berkata; perintahkan dia agar kembali kepadanya dan menahannya hingga suci, kemudian haid, kemudian suci, kemudian apabila ia berkehendak maka boleh ia menceraikannya dalam keadaan suci sebelum ia menggaulinya. Maka itulah perceraian pada 'iddahnya, sebagaimana yang diperintahkan Allah 'azza wajalla. "},"1802":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ أَيُّوبَ عَنْ ابْنِ سِيرِينَ أَخْبَرَنِي يُونُسُ بْنُ جُبَيْرٍ أَنَّهُ سَأَلَ ابْنَ عُمَرَ فَقَالَكَمْ طَلَّقْتَ امْرَأَتَكَ فَقَالَ وَاحِدَةً","id":"Telah menceritakan kepada kami [Al Hasan bin Ali], telah menceritakan kepada kami [Abdurrazzaq], telah mengabarkan kepada kami [Ma'mar] dari [Ayyub] dari [Ibnu Sirin], telah mengabarkan kepadaku [Yunus bin Jubair] bahwa ia telah bertanya kepada [Ibnu Umar]; berapa kali engkau menceraikan isterimu? Ia berkata; satu kali. "},"1803":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ حَدَّثَنَا يَزِيدُ يَعْنِي ابْنَ إِبْرَاهِيمَ عَنْ مُحَمَّدِ بْنِ سِيرِينَ حَدَّثَنِي يُونُسُ بْنُ جُبَيْرٍ قَالَ سَأَلْتُ عَبْدَ اللَّهِ بْنَ عُمَرَ قَالَ قُلْتُرَجُلٌ طَلَّقَ امْرَأَتَهُ وَهِيَ حَائِضٌ قَالَ أَتَعْرِفُ عَبْدَ اللَّهِ بْنَ عُمَرَ قُلْتُ نَعَمْ قَالَ فَإِنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ طَلَّقَ امْرَأَتَهُ وَهِيَ حَائِضٌ فَأَتَى عُمَرُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَهُ فَقَالَ مُرْهُ فَلْيُرَاجِعْهَا ثُمَّ لِيُطَلِّقْهَا فِي قُبُلِ عِدَّتِهَا قَالَ قُلْتُ فَيَعْتَدُّ بِهَا قَالَ فَمَهْ أَرَأَيْتَ إِنْ عَجَزَ وَاسْتَحْمَقَ","id":"Telah menceritakan kepada kami [Al Qa'nabi], telah menceritakan kepada kami [Yazid bin Ibrahim], dari [Muhammad bin Sirin], telah menceritakan kepadaku [Yunus bin Jubair], ia berkata; aku bertanya kepada [Abdullah bin Umar], ia berkata; aku katakan; terdapat seorang laki-laki yang menceraikan isterinya dalam keadaan haid. Ia berkata; apakah engkau mengetahui Abdullah bin Umar? Aku katakan; ya. Ia berkata; sesungguhnya Abdullah bin Umar telah menceraikan isterinya yang sedang haid. Kemudian Umar datang kepada Nabi shallallahu 'alaihi wasallam dan bertanya kepadanya. Lalu beliau berkata: \"Perintahkan dia agar kembali kepadanya kemudian menceraikannya pada waktu ia menghadapi masa 'iddah.\" Abdullah bin Umar berkata; aku katakan; maka ia ber'iddah dengannya. Bagaimana apabila ia tidak mampu atau berpura-pura bersikap bodoh? "},"1804":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي أَبُو الزُّبَيْرِأَنَّهُ سَمِعَ عَبْدَ الرَّحْمَنِ بْنَ أَيْمَنَ مَوْلَى عُرْوَةَ يَسْأَلُ ابْنَ عُمَرَ وَأَبُو الزُّبَيْرِ يَسْمَعُ قَالَ كَيْفَ تَرَى فِي رَجُلٍ طَلَّقَ امْرَأَتَهُ حَائِضًا قَالَ طَلَّقَ عَبْدُ اللَّهِ بْنُ عُمَرَ امْرَأَتَهُ وَهِيَ حَائِضٌ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَ عُمَرُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ طَلَّقَ امْرَأَتَهُ وَهِيَ حَائِضٌ قَالَ عَبْدُ اللَّهِ فَرَدَّهَا عَلَيَّ وَلَمْ يَرَهَا شَيْئًا وَقَالَ إِذَا طَهُرَتْ فَلْيُطَلِّقْ أَوْ لِيُمْسِكْ قَالَ ابْنُ عُمَرَ وَقَرَأَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ يَا أَيُّهَا النَّبِيُّ إِذَا طَلَّقْتُمْ النِّسَاءَ فَطَلِّقُوهُنَّ }فِي قُبُلِ عِدَّتِهِنَّقَالَ أَبُو دَاوُد رَوَى هَذَا الْحَدِيثَ عَنْ ابْنِ عُمَرَ يُونُسُ بْنُ جُبَيْرٍ وَأَنَسُ بْنُ سِيرِينَ وَسَعِيدُ بْنُ جُبَيْرٍ وَزَيْدُ بْنُ أَسْلَمَ وَأَبُو الزُّبَيْرِ وَمَنْصُورٌ عَنْ أَبِي وَائِلٍ مَعْنَاهُمْ كُلُّهُمْ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَهُ أَنْ يُرَاجِعَهَا حَتَّى تَطْهُرَ ثُمَّ إِنْ شَاءَ طَلَّقَ وَإِنْ شَاءَ أَمْسَكَ وَكَذَلِكَ رَوَاهُ مُحَمَّدُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَ وَأَمَّا رِوَايَةُ الزُّهْرِيِّ عَنْ سَالِمٍ وَنَافِعٍ عَنْ ابْنِ عُمَرَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَهُ أَنْ يُرَاجِعَهَا حَتَّى تَطْهُرَ ثُمَّ تَحِيضَ ثُمَّ تَطْهُرَ ثُمَّ إِنْ شَاءَ طَلَّقَ وَإِنْ شَاءَ أَمْسَكَ وَرُوِيَ عَنْ عَطَاءٍ الْخُرَاسَانِيِّ عَنْ الْحَسَنِ عَنْ ابْنِ عُمَرَ نَحْوَ رِوَايَةِ نَافِعٍ وَالزُّهْرِيِّ وَالْأَحَادِيثُ كُلُّهَا عَلَى خِلَافِ مَا قَالَ أَبُو الزُّبَيْرِ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih], telah menceritakan kepada kami [Abdur Razzaq], telah mengabarkan kepada kami [Ibnu Juraij], telah mengabarkan kepadaku [Abu Az Zubair] bahwa ia mendengar Abdur Rahman bin Aiman mantan budak Urwah bertanya kepada [Ibnu Umar], dan Abu Zubair mendengar ia berkata, bagaimana pendapatmu tentang seseorang yang mentalak istrinya dalam keadaan haid, ia berkata, Abdullah bin Umar mentalak istrinya ketika dalam keadaan haid pada masa Rasulullah shallallahu 'alaihi wasallam, maka Umar bertanya kepada Rasulullah, sesungguhnya Abdullah bin Umar mentalak istri yang sedang dalam keadaan haid, Abdullah berkata, maka beliau mengembalikannya kepadaku dan tidak ada masalah atasnya, lalu beliau bersabda, \"Jika ia telah suci, maka boleh kamu cerai atau tetap menjadi istrimu.\" Kemudian Nabi shallallahu 'alaihi wasallam membaca ayat, \"Wahai Nabi! Apabila kamu menceraikan istri-istri kamu ceraikan mereka pada waktu mereka dapat (menghadapi) idahnya (yang wajar).\" Abu Daud berkata, hadits ini diriwayatkan dari Ibnu Umar, [Yunus bin Zubair], [Anas bin Sirin], [Said bin Zubair], [Zaid bin Aslam], [Abu Az Zubair], dan [Manshur] dari [Abu Wail] menurut makna mereka bahwa Nabi shallallahu 'alaihi wasallam menyuruhnya untuk merujuk istrinya kembali hingga setelah suci, ia boleh mentalaknya atau tetap menjadikannya sebagai istri. Begitu juga diriwayatkan oleh [Muhammad bin Abdur Rahman] dari [Salim] dari [Ibnu Umar]. Adapun riwayat [Zuhri] dari [Salim] dan [Nafi'] dari [Ibnu Umar] bahwa Nabi shallallahu 'alaihi wasallam memerintahkannya untuk merujuknya hingga suci, haid, dan suci kembali, (setelah itu) jika berkenan ia boleh mentalaknya atau tetap menjadikannya istri. Dan diriwayatkan dari [Atha` Al Khurasani] dari [Al Hasan] dari [Ibnu Umar] sama seperti riwayat Nafi' Az Zuhri, dan semua hadits yang diriwayatkan tersebut berseberangan dengan apa yang dikatakan Abu Az Zubair. "},"1805":{"ar":"حَدَّثَنَا بِشْرُ بْنُ هِلَالٍ أَنَّ جَعْفَرَ بْنَ سُلَيْمَانَ حَدَّثَهُمْ عَنْ يَزِيدَ الرِّشْكِ عَنْ مُطَرِّفِ بْنِ عَبْدِ اللَّهِأَنَّ عِمْرَانَ بْنَ حُصَيْنٍ سُئِلَ عَنْ الرَّجُلِ يُطَلِّقُ امْرَأَتَهُ ثُمَّ يَقَعُ بِهَا وَلَمْ يُشْهِدْ عَلَى طَلَاقِهَا وَلَا عَلَى رَجْعَتِهَا فَقَالَ طَلَّقْتَ لِغَيْرِ سُنَّةٍ وَرَاجَعْتَ لِغَيْرِ سُنَّةٍ أَشْهِدْ عَلَى طَلَاقِهَا وَعَلَى رَجْعَتِهَا وَلَا تَعُدْ","id":"Telah menceritakan kepada kami [Bisyr bin Hilal], bahwa [Ja'far Sulaiman], ia telah menceritakan kepada mereka dari [Yazid Ar Risyk], dari [Mutharrif bin Abdullah], bahwa [Imran bin Hushain] ditanya mengenai seorang laki-laki yang mencerai isterinya kemudian menggaulinya dan tidak mempersaksikan perceraiannya dan tidak pula pencabutan perceraiannya. Ia berkata; engkau mencerai tidak secara sunah dan kembali tidak secara sunah. Persaksikan atas perceraiannya dan ruju' (kembali kapadanya), dan jangan engkau ulang hal itu lagi! "},"1806":{"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا عَلِيُّ بْنُ الْمُبَارَكِ حَدَّثَنِي يَحْيَى بْنُ أَبِي كَثِيرٍ أَنَّ عُمَرَ بْنَ مُعَتِّبٍ أَخْبَرَهُ أَنَّ أَبَا حَسَنٍ مَوْلَى بَنِي نَوْفَلٍ أَخْبَرَهُأَنَّهُ اسْتَفْتَى ابْنَ عَبَّاسٍ فِي مَمْلُوكٍ كَانَتْ تَحْتَهُ مَمْلُوكَةٌ فَطَلَّقَهَا تَطْلِيقَتَيْنِ ثُمَّ عُتِقَا بَعْدَ ذَلِكَ هَلْ يَصْلُحُ لَهُ أَنْ يَخْطُبَهَا قَالَ نَعَمْ قَضَى بِذَلِكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَحَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ أَخْبَرَنَا عَلِيٌّ بِإِسْنَادِهِ وَمَعْنَاهُ بِلَا إِخْبَارٍ قَالَ ابْنُ عَبَّاسٍ بَقِيَتْ لَكَ وَاحِدَةٌ قَضَى بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَبُو دَاوُد سَمِعْت أَحْمَدَ بْنَ حَنْبَلٍ قَالَ قَالَ عَبْدُ الرَّزَّاقِ قَالَ ابْنُ الْمُبَارَكِ لِمَعْمَرٍ مَنْ أَبُو الْحَسَنِ هَذَا لَقَدْ تَحَمَّلَ صَخْرَةً عَظِيمَةً قَالَ أَبُو دَاوُد أَبُو الْحَسَنِ هَذَا رَوَى عَنْهُ الزُّهْرِيُّ قَالَ الزُّهْرِيُّ وَكَانَ مِنْ الْفُقَهَاءِ رَوَى الزُّهْرِيُّ عَنْ أَبِي الْحَسَنِ أَحَادِيثَ قَالَ أَبُو دَاوُد أَبُو الْحَسَنِ مَعْرُوفٌ وَلَيْسَ الْعَمَلُ عَلَى هَذَا الْحَدِيثِ","id":"Telah menceritakan kepada kami [Zuhair bin Harb], telah menceritakan kepada kami [Yahya bin Sa'id], telah menceritakan kepada kami [Ali bin Al Mubarak], telah menceritakan kepadaku [Yahya bin Abu Katsir], bahwa [Umar bin Mu'attib] telah mengabarkan kepadanya bahwa [Abu Hasan] mantan budak Naufal telah mengabarkan kepadanya bahwa ia meminta fatwa kepada [Ibnu Abbas] mengenai seorang budak yang memiliki isteri seorang budak wanita, kemudian ia menceraikannya dua kali. Kemudian mereka berdua dibebaskan setelah itu. Apakah boleh baginya untuk meminangnya? Ia berkata; ya. Rasulullah shallallahu 'alaihi wasallam telah memutuskan dengan hal tersebut. Telah menceritakan kepada kami [Muhammad bin Al Mutsanna], telah menceritakan kepada kami [Utsman bin Umar], telah mengabarkan kepada kami [Ali] dengan sanad dan maknanya, tanpa pengabaran. Ibnu Abbas berkata; tinggal satu kali untukmu. Rasulullah shallallahu 'alaihi wasallam telah memutuskan dengan hal tersebut. Abu Daud berkata; aku mendengar Ahmad bin Hanbal berkata; Abdurrazzaq berkata; Ibnu Al Mubarak berkata kepada Ma'mar; siapakah Abu Al Hasan ini? Ia telah memikul batu yang besar. Abu Daud berkata; Abu Al Hasan ini adalah orang yang darinya Az Zuhri meriwayatkan hadits. Az Zuhri berkata; ia termasuk diantara ulama fiqih. Az Zuhri telah meriwayatkan dari Abu Al Hasan beberapa hadits. Abu Daud berkata; Abu Al Hasan adalah orang yang dikenal. Hadits"},"1807":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مَسْعُودٍ حَدَّثَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ عَنْ مُظَاهِرٍ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ عَائِشَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ طَلَاقُ الْأَمَةِ تَطْلِيقَتَانِ وَقُرْؤُهَا حَيْضَتَانِقَالَ أَبُو عَاصِمٍ حَدَّثَنِي مُظَاهِرٌ حَدَّثَنِي الْقَاسِمُ عَنْ عَائِشَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ إِلَّا أَنَّهُ قَالَ وَعِدَّتُهَا حَيْضَتَانِ قَالَ أَبُو دَاوُد وَهُوَ حَدِيثٌ مَجْهُولٌ","id":"Telah menceritakan kepada kami [Muhammad bin Mas'ud], telah menceritakan kepada kami [Abu 'Ashim], dari [Ibnu Juraij] dari [Muzhahir] dari [Al Qasim bin Muhammad] dari [Aisyah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Talak (yang boleh dirujuk kembali) bagi budak wanita adalah dua kali talak, dan quru`nya adalah dua kali haid.\" Abu 'Ashim berkata; telah menceritakan kepadaku [Muzhahir], telah menceritakan kepadaku [Al Qasim] dari [Aisyah], dari Nabi shallallahu 'alaihi wasallam seperti itu, hanya saja ia berkata; dan 'iddahnya adalah dua kali haid. Abu Daud berkata; hadits tersebut adalah hadits majhul. "},"1808":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هِشَامٌ ح و حَدَّثَنَا ابْنُ الصَّبَّاحِ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ الصَّمَدِ قَالَا حَدَّثَنَا مَطَرٌ الْوَرَّاقُ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا طَلَاقَ إِلَّا فِيمَا تَمْلِكُ وَلَا عِتْقَ إِلَّا فِيمَا تَمْلِكُ وَلَا بَيْعَ إِلَّا فِيمَا تَمْلِكُ زَادَ ابْنُ الصَّبَّاحِ وَلَا وَفَاءَ نَذْرٍ إِلَّا فِيمَا تَمْلِكُحَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ أَخْبَرَنَا أَبُو أُسَامَةَ عَنْ الْوَلِيدِ بْنِ كَثِيرٍ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ الْحَارِثِ عَنْ عَمْرِو بْنِ شُعَيْبٍ بِإِسْنَادِهِ وَمَعْنَاهُ زَادَ مَنْ حَلَفَ عَلَى مَعْصِيَةٍ فَلَا يَمِينَ لَهُ وَمَنْ حَلَفَ عَلَى قَطِيعَةِ رَحِمٍ فَلَا يَمِينَ لَهُ حَدَّثَنَا ابْنُ السَّرْحِ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ يَحْيَى بْنِ عَبْدِ اللَّهِ بْنِ سَالِمٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ الْمَخْزُومِيِّ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي هَذَا الْخَبَرِ زَادَ وَلَا نَذْرَ إِلَّا فِيمَا ابْتُغِيَ بِهِ وَجْهُ اللَّهِ تَعَالَى ذِكْرُهُ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim], telah menceritakan kepada kami [Hisyam], dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Ibnu Ash Shabbah] telah menceritakan kepada kami [Abdul Aziz bin Abdushshamad], mereka berdua berkata; telah menceritakan kepada kami [Mathor Al Warraq], dari ['Amr bin Syu'aib], dari [ayahnya], dari [kakeknya] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"TIdak ada penceraian kecuali pada apa yang engkau miliki dan tidak ada pembebasan budak kecuali pada sesuatu yang engkau miliki, tidak ada jual beli kecuali pada sesuatu yang engkau miliki.\" Ibnu Ash Shabbah menambahkan; dan tidak boleh memenuhi nadzar kecuali pada Sesutu yang engkau miliki. Telah menceritakan kepada kami [Muhammad bin Al 'Ala`] telah mengabarkan kepada kami [Abu Usamah] dari [Al Walid bin Katsir], telah menceritakan kepadaku [Abdurrahman bin Al Harits Al Makhzumi] dari ['Amr bin Syu'aib] dengan sanadnya, sedang maknanya dengan tambahan; \"Barangsiapa yang bernadlar untuk berbuat maksiat maka tidak ada sumpah baginya, dan barang siapa yang bersumpah untuk memutus tali silaturrahim maka tidak ada sumpah baginya.\" Telah menceritakan kepada kami [Ibnu Sarh] telah mengabarkan kepada kami [Ibnu Wahb] dari [Yahya bin Abdullah bin Salim], dari [Abdurrahman bin Al Harits Al Makhzumi] dari ['Amr bin Syu'aib] dari [ayahnya] dari [kakeknya] bahwa Nabi shallallahu 'alaihi wasallam bersabda dalam hadits ini: \"Dan tidak boleh ada nadzar kecuali dalam perkara yang diharapkan dengannya wajah Allah ta'ala.\""},"1809":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ سَعْدٍ الزُّهْرِيُّ أَنَّ يَعْقُوبَ بْنَ إِبْرَاهِيمَ حَدَّثَهُمْ قَالَ حَدَّثَنَا أَبِي عَنْ ابْنِ إِسْحَقَ عَنْ ثَوْرِ بْنِ يَزِيدَ الْحِمْصِيِّ عَنْ مُحَمَّدِ بْنِ عُبَيْدِ بْنِ أَبِي صَالِحٍ الَّذِي كَانَ يَسْكُنُ إِيلِيَا قَالَ خَرَجْتُ مَعَ عَدِيِّ بْنِ عَدَيٍّ الْكِنْدِيِّ حَتَّى قَدِمْنَا مَكَّةَ فَبَعَثَنِي إِلَى صَفِيَّةَ بِنْتِ شَيْبَةَ وَكَانَتْ قَدْ حَفِظَتْ مِنْ عَائِشَةَ قَالَتْ سَمِعْتُ عَائِشَةَ تَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا طَلَاقَ وَلَا عَتَاقَ فِي غِلَاقٍقَالَ أَبُو دَاوُد الْغِلَاقُ أَظُنُّهُ فِي الْغَضَبِ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Sa'd Az Zuhri] bahwa [Ya'qub bin Ibrahim] telah menceritakan kepada mereka, ia berkata; telah menceritakan kepada kami [ayahku] dari [Ibnu Ishaq] dari [Tsaur bin Yazid Al Himshi] dari [Muhammad bin Abu Shalih] yang pernah tinggal di Iliya, ia berkata; aku pernah keluar bersama 'Adi bin 'Adi Al Kindi, hingga sampai ke Mekkah. Kemudian ia mengutusku datang kepada [Shafiyyah binti Syaibah], dan ia telah hafal hadits dari Aisyah, ia berkata; aku mendengar [Aisyah] berkata; aku telah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada (tidak sah) perceraian dan pembebasan dalam keadaan marah.\""},"1810":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ حَدَّثَنَا عَبْدُ الْعَزِيزِ يَعْنِي ابْنَ مُحَمَّدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ حَبِيبٍ عَنْ عَطَاءِ بْنِ أَبِي رَبَاحٍ عَنْ ابْنِ مَاهَكَ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ثَلَاثٌ جَدُّهُنَّ جَدٌّ وَهَزْلُهُنَّ جَدٌّ النِّكَاحُ وَالطَّلَاقُ وَالرَّجْعَةُ","id":"Telah menceritakan kepada kami [Al Qa'nabi], telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Abdurrahman bin Habib] dari ['Atho` bin Abu Rabah] dari [Ibnu Mahik] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tiga perkara, seriusnya adalah serius dan candanya adalah serius, yaitu; nikah, perceraian, dan pencabutan perceraian.\""},"1811":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ الْمَرْوَزِيُّ حَدَّثَنِي عَلِيُّ بْنُ حُسَيْنِ بْنِ وَاقِدٍ عَنْ أَبِيهِ عَنْ يَزِيدَ النَّحْوِيِّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ{ وَالْمُطَلَّقَاتُ يَتَرَبَّصْنَ بِأَنْفُسِهِنَّ ثَلَاثَةَ قُرُوءٍ وَلَا يَحِلُّ لَهُنَّ أَنْ يَكْتُمْنَ مَا خَلَقَ اللَّهُ فِي أَرْحَامِهِنَّ }الْآيَةَ وَذَلِكَ أَنَّ الرَّجُلَ كَانَ إِذَا طَلَّقَ امْرَأَتَهُ فَهُوَ أَحَقُّ بِرَجْعَتِهَا وَإِنْ طَلَّقَهَا ثَلَاثًا فَنُسِخَ ذَلِكَ وَقَالَ{ الطَّلَاقُ مَرَّتَانِ }","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad Al Marwazi], telah menceritakan kepadaku [Ali bin Husain bin Waqid] dari [ayahnya] dari [Yazid An Nahwi] dari [Ikrimah] dari [Ibnu Abbas], ia membaca ayat: \"Wanita-wanita yang ditalak hendaklah menahan diri (menunggu) tiga kali quru'. Tidak boleh bagi mereka menyembunyikan apa yang diciptakan Allah dalam rahimnya.\" Hal tersebut bahwa seorang laki-laki apabila menceraikan isterinya maka ia adalah orang yang paling berhak untuk kembali kepadanya, dan walaupun ia menceraikannya sebanyak tiga kali. Kemudian hal tersebut dihapus, dan Allah berfirman: \"Talak (yang dapat dirujuki) dua kali.\""},"1812":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي بَعْضُ بَنِي أَبِي رَافِعٍ مَوْلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ عِكْرِمَةَ مَوْلَى ابْنِ عَبَّاسٍ عَنْ ابْنِ عَبَّاسٍ قَالَطَلَّقَ عَبْدُ يَزِيدَ أَبُو رُكَانَةَ وَإِخْوَتِهِ أُمَّ رُكَانَةَ وَنَكَحَ امْرَأَةً مِنْ مُزَيْنَةَ فَجَاءَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ مَا يُغْنِي عَنِّي إِلَّا كَمَا تُغْنِي هَذِهِ الشَّعْرَةُ لِشَعْرَةٍ أَخَذَتْهَا مِنْ رَأْسِهَا فَفَرِّقْ بَيْنِي وَبَيْنَهُ فَأَخَذَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَمِيَّةٌ فَدَعَا بِرُكَانَةَ وَإِخْوَتِهِ ثُمَّ قَالَ لَجُلَسَائِهِ أَتَرَوْنَ فُلَانًا يُشْبِهُ مِنْهُ كَذَا وَكَذَا مِنْ عَبْدِ يَزِيدَ وَفُلَانًا يُشْبِهُ مِنْهُ كَذَا وَكَذَا قَالُوا نَعَمْ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِعَبْدِ يَزِيدَ طَلِّقْهَا فَفَعَلَ ثُمَّ قَالَ رَاجِعْ امْرَأَتَكَ أُمَّ رُكَانَةَ وَإِخْوَتِهِ قَالَ إِنِّي طَلَّقْتُهَا ثَلَاثًا يَا رَسُولَ اللَّهِ قَالَ قَدْ عَلِمْتُ رَاجِعْهَا وَتَلَا{ يَا أَيُّهَا النَّبِيُّ إِذَا طَلَّقْتُمْ النِّسَاءَ فَطَلِّقُوهُنَّ لِعِدَّتِهِنَّ }قَالَ أَبُو دَاوُد وَحَدِيثُ نَافِعِ بْنِ عُجَيْرٍ وَعَبْدِ اللَّهِ بْنِ عَلِيِّ بْنِ يَزِيدَ بْنِ رُكَانَةَ عَنْ أَبِيهِ عَنْ جَدِّهِ أَنَّ رُكَانَةَ طَلَّقَ امْرَأَتَهُ الْبَتَّةَ فَرَدَّهَا إِلَيْهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَصَحُّ لِأَنَّ وَلَدَ الرَّجُلِ وَأَهْلَهُ أَعْلَمُ بِهِ إِنَّ رُكَانَةَ إِنَّمَا طَلَّقَ امْرَأَتَهُ الْبَتَّةَ فَجَعَلَهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاحِدَةً","id":"Telah menceritakan kepada kami [Ahmad bin Shalih], telah menceritakan kepada kami [Abdurrazzaq], telah mengabarkan kepada kami [Ibnu Juraij] telah mengabarkan kepadaku [sebagian anak-anak Abu Rafi'] mantan budak Nabi shallallahu 'alaihi wasallam, dari [Ikrimah] mantan budak Ibnu Abbas, dari [Ibnu Abbas], ia berkata; Abdu Yazid? dan saudara-saudaranya yaitu Abu Rukanah telah mencerai Ummu Rukanah dan menikahi seorang wanita dari Muzainah, kemudian wanita tersebut datang kepada Nabi shallallahu 'alaihi wasallam dan berkata; ia tidak memberiku kepuasan kecuali seperti sehelai rambut ini. Ia mengambil sehelai rambut dari kepalanya. Maka Kemudian beliau berkata kepada orang-orang yang duduk bersamanya: \"Apakah kalian melihat Fulan menyerupai demikian dan demikian dari Abdu Yazid? dan Fulan menyerupai darinya demikian dan demikian?\" Mereka mengatakan; ya. Nabi shallallahu 'alaihi wasallam berkata kepada Abdu Yazid?: \"Ceraikan dia!\" Lalu ia melakukan hal tersebut, kemudian beliau berkata: \"Kembalilah kepada isterimu yaitu Ummu Rukanah!\" Ia berkata; sesungguhnya aku telah mencerainya tiga kali wahai Rasulullah. Beliau berkata: \"Aku telah mengetahui, kembalilah kepadanya!\" Dan beliau membacakan ayat: \"Hai Nabi, apabila kamu menceraikan isteri-isterimu maka hendaklah kamu ceraikan mereka pada waktu mereka dapat (menghadapi) iddahnya (yang wajar).\" Abu Daud berkata; dan hadits Nafi' bin 'Ujair, [Abdullah bin Ali bin Yazid? bin Rukanah] dari [ayahnya] dari [kakeknya] bahwa Rukanah telah isterinya sama sekali, kemudian Nabi shallallahu 'alaihi wasallam mengembalikannya kepada Rukanah, hadits tersebut lebih shahih karena anak seseorang dan keluarganya lebih mengetahuinya. Sesungguhnya Rukanah telah mencerai isterinya sama sekali dan Nabi shallallahu 'alaihi wasallam menjadikannya sebagai satu kali talak. "},"1813":{"ar":"حَدَّثَنَا حُمَيْدُ بْنُ مَسْعَدَةَ حَدَّثَنَا إِسْمَعِيلُ أَخْبَرَنَا أَيُّوبُ عَنْ عَبْدِ اللَّهِ بْنِ كَثِيرٍ عَنْ مُجَاهِدٍ قَالَكُنْتُ عِنْدَ ابْنِ عَبَّاسٍ فَجَاءَهُ رَجُلٌ فَقَالَ إِنَّهُ طَلَّقَ امْرَأَتَهُ ثَلَاثًا قَالَ فَسَكَتَ حَتَّى ظَنَنْتُ أَنَّهُ رَادُّهَا إِلَيْهِ ثُمَّ قَالَ يَنْطَلِقُ أَحَدُكُمْ فَيَرْكَبُ الْحُمُوقَةَ ثُمَّ يَقُولُ يَا ابْنَ عَبَّاسٍ يَا ابْنَ عَبَّاسٍ وَإِنَّ اللَّهَ قَالَ{ وَمَنْ يَتَّقِ اللَّهَ يَجْعَلْ لَهُ مَخْرَجًا }وَإِنَّكَ لَمْ تَتَّقِ اللَّهَ فَلَمْ أَجِدْ لَكَ مَخْرَجًا عَصَيْتَ رَبَّكَ وَبَانَتْ مِنْكَ امْرَأَتُكَ وَإِنَّ اللَّهَ قَالَ{ يَا أَيُّهَا النَّبِيُّ إِذَا طَلَّقْتُمْ النِّسَاءَ فَطَلِّقُوهُنَّ }فِي قُبُلِ عِدَّتِهِنَّقَالَ أَبُو دَاوُد رَوَى هَذَا الْحَدِيثَ حُمَيْدٌ الْأَعْرَجُ وَغَيْرُهُ عَنْ مُجَاهِدٍ عَنْ ابْنِ عَبَّاسٍ وَرَوَاهُ شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ وَأَيُّوبُ وَابْنُ جُرَيْجٍ جَمِيعًا عَنْ عِكْرِمَةَ بْنِ خَالِدٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ وَابْنُ جُرَيْجٍ عَنْ عَبْدِ الْحَمِيدِ بْنِ رَافِعٍ عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍ وَرَوَاهُ الْأَعْمَشُ عَنْ مَالِكِ بْنِ الْحَارِثِ عَنْ ابْنِ عَبَّاسٍ وَابْنُ جُرَيْجٍ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ ابْنِ عَبَّاسٍ كُلُّهُمْ قَالُوا فِي الطَّلَاقِ الثَّلَاثِ أَنَّهُ أَجَازَهَا قَالَ وَبَانَتْ مِنْكَ نَحْوَ حَدِيثِ إِسْمَعِيلَ عَنْ أَيُّوبَ عَنْ عَبْدِ اللَّهِ بْنِ كَثِيرٍ قَالَ أَبُو دَاوُد وَرَوَى حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ إِذَا قَالَ أَنْتِ طَالِقٌ ثَلَاثًا بِفَمٍ وَاحِدٍ فَهِيَ وَاحِدَةٌ وَرَوَاهُ إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ عَنْ أَيُّوبَ عَنْ عِكْرِمَةَ هَذَا قَوْلُهُ لَمْ يَذْكُرْ ابْنَ عَبَّاسٍ وَجَعَلَهُ قَوْلَ عِكْرِمَةَ","id":"Telah menceritakan kepada kami [Humaid bin Mas'adah], telah menceritakan kepada kami [Isma'il], telah mengabarkan kepada kami [Ayyub] dari [Abdullah bin Katsir] dari [Mujahid] ia berkata; aku pernah berada di sisi [Ibnu Abbas], kemudian terdaapat seorang laki-laki yang datang kepadanya. Lalu ia berkata bahwa ia telah mencerai isterinya sebanyak tiga kali. Mujahid berkata; kemudian ia terdiam hingga aku menyangka bahwa ia akan mengembalikan wanita tersebut kepadanya. Kemudian ia berkata; salah seorang diantara kalian pergi lalu melakukan perbuatan orang yang bodoh. Kemudian mengatakan; wahai Ibnu Abbas, wahai Ibnu Abbas! Sesungguhnya Allah telah berfirman: \"Barangsiapa yang bertakwa kepada Allah, maka Dia memberikan baginya jalan keluar.\" Sementara engkau tidak bertakwa kepada Allah, maka aku tidak mendapatkan bagimu jalan keluar. Engkau telah bermaksiat kepada Tuhanmu dan isterimu telah terceraikan sama sekali. Dan sesungguhnya Allah telah berfirman: \"Wahai nabi, apabila kalian menceraikan isteri-isteri kalian maka ceraikanlah mereka pada waktu disambutnya masa 'Iddah mereka.\" Abu Daud berkata; hadits ini diriwayatkan oleh [Humaid Al A'raj] dan yang lainnya dari [Mujahid] dari [Ibnu Abbas] dan telah diriwayatkan oleh [Syu'bah] dari ['Amr bin Murrah] dari [Sa'id bin Jubair] dari [Ibnu Abbas], [Ayyub] dan [Ibnu Juraij], seluruhnya dari [Ikrimah bin Khalid] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dan [Ibnu Juraij] dari [Abdul Hamid bin Rafi'] dari ['Atho`] dari [Ibnu Abbas] dan telah diriwayatkan oleh [Al A'masy] dari [Malik bin Al Harits] dari [Ibnu Abbas] dan [Ibnu Juraij] dari ['Amr bin Dinar] dari [Ibnu Abbas], mereka semua mengatakan mengenai talak tiga kali bahwa ia telah memperbolehkannya. Ia berkata; dan ia telah tercerai sama sekali darimu seperti hadits Isma'il dari Ayyub dari Abdullah bin Katsir. Abu Daud berkata; dan [Hammad bin Zaid] telah meriwayatkan dari [Ayyub] dari [Ikrimah] dari [Ibnu Abbas] apabila mengucapkan; engkau dicerai tiga kali, dengan satu kali ucapan maka hal tersebut adalah satu satu kali talak. Dan [Isma'il bin Ibrahim] telah meriwayatkan dari [Ayyub] dari [Ikrimah], ini adalah perkataannya, ia tidak menyebutkan Ibnu Abbas dan ia menjadikan perkataan tersebut sebagai perkataan Ikrimah."},"1814":{"ar":"وَصَارَ قَوْلُ ابْنِ عَبَّاسٍ فِيمَا حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ وَمُحَمَّدُ بْنُ يَحْيَى وَهَذَا حَدِيثُ أَحْمَدَ قَالَا حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ وَمُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ ثَوْبَانَ عَنْ مُحَمَّدِ بْنِ إِيَاسٍ أَنَّ ابْنَ عَبَّاسٍ وَأَبَا هُرَيْرَةَ وَعَبْدَ اللَّهِ بْنَ عَمْرِو بْنِ الْعَاصِسُئِلُوا عَنْ الْبِكْرِ يُطَلِّقُهَا زَوْجُهَا ثَلَاثًا فَكُلُّهُمْ قَالُوا لَا تَحِلُّ لَهُ حَتَّى تَنْكِحَ زَوْجًا غَيْرَهُقَالَ أَبُو دَاوُد رَوَى مَالِكٌ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ بُكَيْرِ بْنِ الْأَشَجِّ عَنْ مُعَاوِيَةَ بْنِ أَبِي عَيَّاشٍ أَنَّهُ شَهِدَ هَذِهِ الْقِصَّةَ حِينَ جَاءَ مُحَمَّدُ بْنُ إِيَاسِ بْنِ الْبُكَيْرِ إِلَى ابْنِ الزُّبَيْرِ وَعَاصِمِ بْنِ عُمَرَ فَسَأَلَهُمَا عَنْ ذَلِكَ فَقَالَا اذْهَبْ إِلَى ابْنِ عَبَّاسٍ وَأَبِي هُرَيْرَةَ فَإِنِّي تَرَكْتُهُمَا عِنْدَ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا ثُمَّ سَاقَ هَذَا الْخَبَرَ قَالَ أَبُو دَاوُد وَقَوْلُ ابْنِ عَبَّاسٍ هُوَ أَنَّ الطَّلَاقَ الثَّلَاثَ تَبِينُ مِنْ زَوْجِهَا مَدْخُولًا بِهَا وَغَيْرَ مَدْخُولٍ بِهَا لَا تَحِلُّ لَهُ حَتَّى تَنْكِحَ زَوْجًا غَيْرَهُ هَذَا مِثْلُ خَبَرِ الصَّرْفِ قَالَ فِيهِ ثُمَّ إِنَّهُ رَجَعَ عَنْهُ يَعْنِي ابْنَ عَبَّاسٍ","id":"Dan perkataan Ibnu Abbas ada dalam riwayat yang diceritakan [Ahmad bin Shalih] dan [Muhammad bin Yahya] kepada kami, dan ini adalah hadits Ahmad, mereka berkata; telah menceritakan kepada kami [Abdurrazzaq] dari [Ma'mar] dari [Az Zuhri], dari [Abu Salamah bin Abdurrahman bin 'Auf] dan [Muhammad bin Abadurrahman bin Tsauban] dari [Muhammad bin Iyas] bahwa [Ibnu Abas] [Abu Hurairah] dan [Abdullah bin Amr bin 'Ash], mereka ditanya mengenai seorang gadis yang dicerai suaminya tiga kali, maka seluruh mereka mengatakan; tidak halal baginya hingga wanita tersebut menikah dengan suami yang lain. Abu Daud berkata; [Malik] telah meriwayatkan dari [Yahya bin Sa'id] dari [Bukair bin Al Asyajj] dari [Mu'awiyah bin Abu 'Ayyasy] bahwa ia menyaksikan kisah ini ketika Muhammad bin Iyas bin Al Bukair datang kepada Ibnu Az Zubair dan 'Ashim bin Umar. Kemudian ia bertanya kepada mereka berdua mengenai hal tersebut. Lalu mereka berkata; pergilah kepada [Ibnu Abbas], dan [Abu Hurairah]! Sesungguhnya aku telah meninggalkan mereka berdua bersama Aisyah radliallahu 'anha. Kemudian ia menyebutkan hadits ini. Abu Daud berkata; dan pendapat Ibnu Abbas bahwa talak tiga kali berarti seorang wanita tercerai sama sekali baik sudah digauli atau belum. Wanita tersebut tidak halal baginya hingga menikah dengan suami yang lainnya, ini seperti hadits Ash Sharf, padanya ia mengatakan; kemudian Ibnu Abbas mencabut pendapatnya. "},"1815":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْمَلِكِ بْنِ مَرْوَانَ حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ غَيْرِ وَاحِدٍ عَنْ طَاوُسٍأَنَّ رَجُلًا يُقَالُ لَهُ أَبُو الصَّهْبَاءِ كَانَ كَثِيرَ السُّؤَالِ لِابْنِ عَبَّاسٍ قَالَ أَمَا عَلِمْتَ أَنَّ الرَّجُلَ كَانَ إِذَا طَلَّقَ امْرَأَتَهُ ثَلَاثًا قَبْلَ أَنْ يَدْخُلَ بِهَا جَعَلُوهَا وَاحِدَةً عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبِي بَكْرٍ وَصَدْرًا مِنْ إِمَارَةِ عُمَرَ قَالَ ابْنُ عَبَّاسٍ بَلَى كَانَ الرَّجُلُ إِذَا طَلَّقَ امْرَأَتَهُ ثَلَاثًا قَبْلَ أَنْ يَدْخُلَ بِهَا جَعَلُوهَا وَاحِدَةً عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبِي بَكْرٍ وَصَدْرًا مِنْ إِمَارَةِ عُمَرَ فَلَمَّا رَأَى النَّاسَ قَدْ تَتَابَعُوا فِيهَا قَالَ أَجِيزُوهُنَّ عَلَيْهِمْ","id":"Telah menceritakan kepada kami [Muhammad bin Abdul Malik bin Marwan], telah menceritakan kepada kami [Abu An Nu'man], telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [lebih dari satu orang] dari [Thawus] bahwa [seorang laki-laki yang dipanggil Abu Ash Shahba`] adalah orang yang sering bertanya kepada [Ibnu Abbas], ia berkata; tidakkah engkau mengetahui bahwa seseorang apabila mencerai isterinya tiga kali sebelum menggaulinya mereka menganggapnya satu kali perceraian pada zaman Rasulullah shallallahu 'alaihi wasallam, Abu Bakr, dan permulaan kepemimpinan Umar? Ibnu Abbas berkata; benar, dahulu seorang laki-laki apabila menceraikan isterinya tiga kali sebelum ia menggaulinya mereka menganggapnya satu kali pada zaman Rasulullah shallallahu 'alaihi wasallam, Abu Bakr dan permulaan kepemimpinan Umar, kemudian tatkala orang-orang melihat sering melakukan hal tersebut maka Umar berkata; terapkan tiga perceraian atas mereka."},"1816":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي ابْنُ طَاوُسٍ عَنْ أَبِيهِأَنَّ أَبَا الصَّهْبَاءِ قَالَ لِابْنِ عَبَّاسٍ أَتَعْلَمُ أَنَّمَا كَانَتْ الثَّلَاثُ تُجْعَلُ وَاحِدَةً عَلَى عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبِي بَكْرٍ وَثَلَاثًا مِنْ إِمَارَةِ عُمَرَ قَالَ ابْنُ عَبَّاسٍ نَعَمْ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih], telah menceritakan kepada kami [Abdurrazzaq], telah mengabarkan kepada kami [Ibnu Juraij], telah mengabarkan kepadaku [Ibnu Thawus], dari [ayahnya] bahwa Abu Ash Shahba` berkata kepada Ibnu Abbas; apakah engkau mengetahui bahwa tiga kali cerai dianggap satu kali pada zaman Nabi shallallahu 'alaihi wasallam, Abu Bakr, dan dihitung tiga kali pada kepemimpinan Umar. [Ibnu Abbas] berkata; ya. "},"1817":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ حَدَّثَنِي يَحْيَى بْنُ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ التَّيْمِيِّ عَنْ عَلْقَمَةَ بْنِ وَقَّاصٍ اللَّيْثِيِّ قَالَ سَمِعْتُ عُمَرَ بْنَ الْخَطَّابِ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا الْأَعْمَالُ بِالنِّيَّاتِ وَإِنَّمَا لِكُلِّ امْرِئٍ مَا نَوَى فَمَنْ كَانَتْ هِجْرَتُهُ إِلَى اللَّهِ وَرَسُولِهِ فَهِجْرَتُهُ إِلَى اللَّهِ وَرَسُولِهِ وَمَنْ كَانَتْ هِجْرَتُهُ لِدُنْيَا يُصِيبُهَا أَوْ امْرَأَةٍ يَتَزَوَّجُهَا فَهِجْرَتُهُ إِلَى مَا هَاجَرَ إِلَيْهِ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir], telah mengabarkan kepada kami [Sufyan], telah menceritakan kepadaku [Yahya bin Sa'id] dari [Muhammad bin Ibrahim At Taimi] dari ['Alqamah bin Waqqash Al Laitsi], ia berkata; aku mendengar [Umar bin Al Khathab] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya amalan itu tergantung kepada niatnya, dan bagi setiap orang akan mendapatkan sesuai apa yang telah ia niatkan. Barangsiapa yang hijrahnya kepada Allah dan RasulNya, maka hijrahnya adalah kepada Allah dan RasulullahNya, dan barangsiapa yang hijrahnya untuk dunia yang hendak ia dapatkan atau karena seorang wanita yang akan ia nikahi, maka hijrahnya akan mendapatkan sesuai apa yang ia maksudkan.\""},"1818":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ وَسُلَيْمَانُ بْنُ دَاوُدَ قَالَا أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ بْنِ كَعْبِ بْنِ مَالِكٍ أَنَّ عَبْدَ اللَّهِ بْنَ كَعْبٍ وَكَانَ قَائِدَ كَعْبٍ مِنْ بَنِيهِ حِينَ عَمِيَ قَالَ سَمِعْتُ كَعْبَ بْنَ مَالِكٍفَسَاقَ قِصَّتَهُ فِي تَبُوكَ قَالَ حَتَّى إِذَا مَضَتْ أَرْبَعُونَ مِنْ الْخَمْسِينَ إِذَا رَسُولُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْتِي فَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْمُرُكَ أَنْ تَعْتَزِلَ امْرَأَتَكَ قَالَ فَقُلْتُ أُطَلِّقُهَا أَمْ مَاذَا أَفْعَلُ قَالَ لَا بَلْ اعْتَزِلْهَا فَلَا تَقْرَبَنَّهَا فَقُلْتُ لِامْرَأَتِي الْحَقِي بِأَهْلِكِ فَكُونِي عِنْدَهُمْ حَتَّى يَقْضِيَ اللَّهُ سُبْحَانَهُ فِي هَذَا الْأَمْرِ","id":"Telah menceritakan kepada kami [Ahmad bin 'Amr bin As Sarh], serta [Sulaiman bin Daud], mereka berkata; telah mengabarkan kepada kami [Ibnu Wahb], telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab], telah mengabarkan kepadaku [Abdurrahman bin Abdullah bin Ka'bin bin Malik] bahwa [Abdullah bin Ka'bin] yang merupakan penuntun Ka'bin diantara anaknya ketika mengalami kebutaan, ia berkata; saya mendengar [Ka'b bin Malik] Kemudian ia menyebutkan kisahnya ketika terjadinya perang Tabuk, ia berkata; hingga setelah berlalu empat puluh hari dari lima puluh hari, tiba-tiba utusan Rasulullah shallallahu 'alaihi wasallam datang dan berkata; sesungguhnya Rasulullah shallallahu 'alaihi wasallam memerintahkanmu agar menjauhi isterimu. Ia berkata; apakah aku harus mencerainya atau bagaimana? Utusan tersebut berkata; tidak melainkan jauhilah dia, dan jangan engkau mendekatinya! Kemudian aku katakan kepada isteriku; kembalilah kepada keluargamu, dan tinggallah bersama mereka hingga Allah memberikan keputusan mengenai perkara ini. "},"1819":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْخَيَّرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاخْتَرْنَاهُ فَلَمْ يَعُدَّ ذَلِكَ شَيْئًا","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Abu 'Awanah] dari [Al A'masy] dari [Abu Adh Dhuha] dari [Masruq] dari [Aisyah], ia berkata; Rasulullah shallallahu 'alaihi wasallam memberiku pilihan, maka aku memilih beliau, dan hal tersebut tidak dianggap sebagai perceraian. "},"1820":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ عَنْ حَمَّادِ بْنِ زَيْدٍ قَالَ قُلْتُ لِأَيُّوبَهَلْ تَعْلَمُ أَحَدًا قَالَ بِقَوْلِ الْحَسَنِ فِي أَمْرُكِ بِيَدِكِ قَالَ لَا إِلَّا شَيْئًا حَدَّثَنَاهُ قَتَادَةُ عَنْ كَثِيرٍ مَوْلَى ابْنِ سَمُرَةَ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِنَحْوِهِقَالَ أَيُّوبُ فَقَدِمَ عَلَيْنَا كَثِيرٌ فَسَأَلْتُهُ فَقَالَ مَا حَدَّثْتُ بِهَذَا قَطُّ فَذَكَرْتُهُ لِقَتَادَةَ فَقَالَ بَلَى وَلَكِنَّهُ نَسِيَ حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هِشَامٌ عَنْ قَتَادَةَ عَنْ الْحَسَنِ فِي أَمْرُكِ بِيَدِكِ قَالَ ثَلَاثٌ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali], telah menceritakan kepada kami [Sulaiman bin Harb] dari [Hammad bin Zaid], ia berkata; aku katakan kepada [Ayyub]; apakah engkau mengetahui seseorang yang berpendapat dengan pendapat Al Hasan menganai ucapan \"Urusanmu ada di tanganmu\"? Ayyub berkata; tidak, kecuali sesuatu yang telah diceritakan [Qatadah] kepada kami, dari [Katsir] mantan budak Ibnu Samurah dari [Abu Salamah] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam dengan hadits seperti hadits tersebut. Ayyub berkata; kemudian Katsir datang kepada kami dan aku tanyakan kepadanya; ia berkata; aku tidak menceritakan demikian ini sama sekali. Kemudian hal tersebut aku ceritakan kepada Qatadah, maka Qatadah berkata; betul, akan tetapi ia lupa. Telah menceritakan kepada kami [Muslim bin Ibrahim], telah menceritakan kepada kami [Hisyam], dari [Qatadah] dari [Al Hasan] mengenai kata \"Urusanmu ada di tanganmu\", ia berkata; hal tersebut adalah tiga kali talak. "},"1821":{"ar":"حَدَّثَنَا ابْنُ السَّرْحِ وَإِبْرَاهِيمُ بْنُ خَالِدٍ الْكَلْبِيُّ أَبُو ثَوْرٍ فِي آخَرِينَ قَالُوا حَدَّثَنَا مُحَمَّدُ بْنُ إِدْرِيسَ الشَّافِعِيُّ حَدَّثَنِي عَمِّي مُحَمَّدُ بْنُ عَلِيِّ بْنِ شَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عَلِيِّ بْنِ السَّائِبِ عَنْ نَافِعِ بْنِ عُجَيْرِ بْنِ عَبْدِ يَزِيدَ بْنِ رُكَانَةَأَنَّ رُكَانَةَ بْنَ عَبْدِ يَزِيدَ طَلَّقَ امْرَأَتَهُ سُهَيْمَةَ الْبَتَّةَ فَأَخْبَرَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِذَلِكَ وَقَالَ وَاللَّهِ مَا أَرَدْتُ إِلَّا وَاحِدَةً فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاللَّهِ مَا أَرَدْتَ إِلَّا وَاحِدَةً فَقَالَ رُكَانَةُ وَاللَّهِ مَا أَرَدْتُ إِلَّا وَاحِدَةً فَرَدَّهَا إِلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَطَلَّقَهَا الثَّانِيَةَ فِي زَمَانِ عُمَرَ وَالثَّالِثَةَ فِي زَمَانِ عُثْمَانَقَالَ أَبُو دَاوُد أَوَّلُهُ لَفْظُ إِبْرَاهِيمَ وَآخِرُهُ لَفْظُ ابْنِ السَّرْحِ حَدَّثَنَا مُحَمَّدُ بْنُ يُونُسَ النَّسَائِيُّ أَنَّ عَبْدَ اللَّهِ بْنَ الزُّبَيْرِ حَدَّثَهُمْ عَنْ مُحَمَّدِ بْنِ إِدْرِيسَ حَدَّثَنِي عَمِّي مُحَمَّدُ بْنُ عَلِيٍّ عَنْ ابْنِ السَّائِبِ عَنْ نَافِعِ بْنِ عُجَيْرٍ عَنْ رُكَانَةَ بْنِ عَبْدِ يَزِيدَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذَا الْحَدِيثِ","id":"Telah menceritakan kepada kami [Ibnu As Sarh] dan [Ibrahim bin Khalid Al Kalbi Abu Tsaur] diantara orang-orang yang lain, mereka mengatakan; telah menceritakan kepada kami [Muhammad bin Idris Asy Syafi'i], telah menceritakan kepadaku [pamanku yaitu Muhammad bin Ali bin syafi'] dari [Abdullah bin Ali bin As Saib] dari [Nafi' bin 'Ujair bin Abdu Yazid? bin Rukanah], bahwa [Rukanah bin Abdu Yazid] telah menceraikan isterinya yaitu Suhaimah sama sekali, kemudian ia mengabarkan kepada Nabi shallallahu 'alaihi wasallam dengan hal tersebut. Dan ia berkata; demi Allah aku tidak berniat kecuali satu kali. Kemudian Rasulullah shallallahu 'alaihi wasallam berkata: \"Demi Allah, engkau tidak berniat kecuali satu kali.\" Kemudian Rukanah berkata; demi Allah, aku tidak berniat kecuali satu kali. Kemudian Rasulullah shallallahu 'alaihi wasallam mengembalikan isterinya kepadanya. Kemudian ia mencerainya kedua kali pada zaman Umar dan ketiga kali pada zaman Utsman. Abu Daud berkata; yang pertama adalah lafazh Ibrahim, dan yang lainnya adalah lafazh Ibnu As Sarh. Telah menceritakan kepada kami [Muhammad bin Yunus An Nasai], bahwa [Abdullah bin Az Zubair] telah menceritakan kepada mereka dari [Muhammad bin Idris] telah menceritakan kepadaku [pamanku yaitu Muhammad bin Ali] dari [Ibnu As Saib] dari [Nafi' bin 'Ujair] dari [Rukanah bin Abdu Yazid] dari Nabi shallallahu 'alaihi wasallam dengan hadits ini. "},"1822":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ الْعَتَكِيُّ حَدَّثَنَا جَرِيرُ بْنُ حَازِمٍ عَنْ الزُّبَيْرِ بْنِ سَعِيدٍ عَنْ عَبْدِ اللَّهِ بْنِ عَلِيِّ بْنِ يَزِيدَ بْنِ رُكَانَةَ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّهُ طَلَّقَ امْرَأَتَهُ الْبَتَّةَ فَأَتَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَا أَرَدْتَ قَالَ وَاحِدَةً قَالَ آللَّهِ قَالَ آللَّهِ قَالَ هُوَ عَلَى مَا أَرَدْتَقَالَ أَبُو دَاوُد وَهَذَا أَصَحُّ مِنْ حَدِيثِ ابْنِ جُرَيْجٍ أَنَّ رُكَانَةَ طَلَّقَ امْرَأَتَهُ ثَلَاثًا لِأَنَّهُمْ أَهْلُ بَيْتِهِ وَهُمْ أَعْلَمُ بِهِ وَحَدِيثُ ابْنِ جُرَيْجٍ رَوَاهُ عَنْ بَعْضِ بَنِي أَبِي رَافِعٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ","id":"Telah menceritakan kepada kami [Sulaiman bin Daud Al 'Ataki], telah menceritakan kepada kami [Jarir bin Hazim] dari [Az Zubair bin Sa'id] dari [Abdullah bin Ali bin Yazid bin Rukanah] dari [ayahnya], dari [kakeknya] bahwa ia telah mencerai isterinya sama sekali, kemudian Rasulullah shallallahu 'alaihi wasallam datang dan berkata: \"Apa yang engkau inginkan?\" ia berkata; satu kali cerai. Beliau bertanya: \"Demi Allah?\" Ia berkata; demi Allah. Beliau berkata: \"Hal itu adalah sesuai dengan apa yang engkau inginkan.\" Abu Daud berkata; hadits ini lebih shahih daripada hadits Ibnu Juraij bahwa Rukanah mencerai isterinya tiga kali karena mereka adalah penghuni rumahnya, dan mereka lebih mengetahui mengenai hal tersebut. Sedangkan hadits Ibnu Juraij telah telah ia riwayatkan dari sebagian orang dari Bani Abu Rafi' dari Ikrimah, dari Ibnu Abbas. "},"1823":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هِشَامٌ عَنْ قَتَادَةَ عَنْ زُرَارَةَ بْنِ أَوْفَى عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ تَجَاوَزَ لِأُمَّتِي عَمَّا لَمْ تَتَكَلَّمْ بِهِ أَوْ تَعْمَلْ بِهِ وَبِمَا حَدَّثَتْ بِهِ أَنْفُسَهَا","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim], telah menceritakan kepada kami [Hisyam] dari [Qatadah], dari [Zurarah bin Aufa], dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya Allah mengampuni bagi umatku apa yang belum mereka ucapkan dan belum mereka lakukan, serta sesuatu yang terbetik dalam pikirannya.\""},"1824":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ ح و حَدَّثَنَا أَبُو كَامِلٍ حَدَّثَنَا عَبْدُ الْوَاحِدِ وَخَالِدٌ الطَّحَّانُ الْمَعْنَى كُلُّهُمْ عَنْ خَالِدٍ عَنْ أَبِي تَمِيمَةَ الْهُجَيْمِيِّأَنَّ رَجُلًا قَالَ لِامْرَأَتِهِ يَا أُخَيَّةُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُخْتُكَ هِيَ فَكَرِهَ ذَلِكَ وَنَهَى عَنْهُ","id":"Telah menceritakan kepada kami [Musa bin Isma'il], telah menceritakan kepada kami [Hammad], dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Abu Kamil], telah menceritakan kepada kami [Abdul Wahid] serta [Khalid Ath Thahhan] secara makna, dari [Khalid] dari [Abu Tamimah Al Hujaimi] bahwa seorang laki-laki berkata kepada isternya; wahai saudari kecilku! Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apakah ia saudarimu?\" beliau tidak senang kepada hal tersebut, dan beliau melarang melakukan hal tersebut. "},"1825":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ إِبْرَاهِيمَ الْبَزَّازُ حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا عَبْدُ السَّلَامِ يَعْنِي ابْنَ حَرْبٍ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ أَبِي تَمِيمَةَ عَنْ رَجُلٍ مِنْ قَوْمِهِأَنَّهُ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَمِعَ رَجُلًا يَقُولُ لِامْرَأَتِهِ يَا أُخَيَّةُ فَنَهَاهُقَالَ أَبُو دَاوُد وَرَوَاهُ عَبْدُ الْعَزِيزِ بْنُ الْمُخْتَارِ عَنْ خَالِدٍ عَنْ أَبِي عُثْمَانَ عَنْ أَبِي تَمِيمَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَوَاهُ شُعْبَةُ عَنْ خَالِدٍ عَنْ رَجُلٍ عَنْ أَبِي تَمِيمَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Ibrahim Al Bazzar], telah menceritakan kepada kami [Abu Nu'aim], telah menceritakan kepada kami [Abdussalam] yaitu Ibnu Harb, dari [Khalid Al Hadzdza`] dari [Abu Tamimah] dari [seorang laki-laki dari kaumnya] bahwa ia mendengar Nabi shallallahu 'alaihi wasallam beliau mendengar seorang laki-laki berkata kepada isterinya; wahai saudariku. Kemudian beliau melarangnya. Abu Daud berkata; dan hadits tersebut diriwayatkan oleh [Abdul Aziz bin Al Mukhtar] dari [Khalid] dari [Abu Utsman] dari [Abu Tamimah] dari Nabi shallallahu 'alaihi wasallam. Dan telah diriwayatkan oleh [Syu'bah] dari [Khalid] dari [seseorang] dari [Abu Tamimah] dari Nabi shallallahu 'alaihi wasallam."},"1826":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا هِشَامٌ عَنْ مُحَمَّدٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ إِبْرَاهِيمَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَكْذِبْ قَطُّ إِلَّا ثَلَاثًا ثِنْتَانِ فِي ذَاتِ اللَّهِ تَعَالَى قَوْلُهُ{ إِنِّي سَقِيمٌ }وَقَوْلُهُ{ بَلْ فَعَلَهُ كَبِيرُهُمْ هَذَا }وَبَيْنَمَا هُوَ يَسِيرُ فِي أَرْضِ جَبَّارٍ مِنْ الْجَبَابِرَةِ إِذْ نَزَلَ مَنْزِلًا فَأُتِيَ الْجَبَّارُ فَقِيلَ لَهُ إِنَّهُ نَزَلَ هَاهُنَا رَجُلٌ مَعَهُ امْرَأَةٌ هِيَ أَحْسَنُ النَّاسِ قَالَ فَأَرْسَلَ إِلَيْهِ فَسَأَلَهُ عَنْهَا فَقَالَ إِنَّهَا أُخْتِي فَلَمَّا رَجَعَ إِلَيْهَا قَالَ إِنَّ هَذَا سَأَلَنِي عَنْكِ فَأَنْبَأْتُهُ أَنَّكِ أُخْتِي وَإِنَّهُ لَيْسَ الْيَوْمَ مُسْلِمٌ غَيْرِي وَغَيْرُكِ وَإِنَّكِ أُخْتِي فِي كِتَابِ اللَّهِ فَلَا تُكَذِّبِينِي عِنْدَهُ وَسَاقَ الْحَدِيثَقَالَ أَبُو دَاوُد رَوَى هَذَا الْخَبَرَ شُعَيْبُ بْنُ أَبِي حَمْزَةَ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna], telah menceritakan kepada kami [Abdul Wahhab], telah menceritakan kepada kami [Hisyam] dari [Muhammad] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam bahwa Ibrahim shallallahu 'alaihi wasallam tidak berdusta kecuali tiga hal, dua hal mengenai Dzat Allah ta'ala, perkataannya; sesungguhnya kau sakit, dan perkataannya; melainkan yang melakukannya adalah berhala yang besar diantara mereka, dan ketika ia berjalan di Negeri yang dipimpin oleh orang yang otoriter ketika ia singgah di suatu tempat kemudian ia dihadapkan kepada penguasa yang otoriter tersebut dan dikatakan kepada penguasa tersebut; sesungguhnya telah singgah di sini seorang laki-laki bersama seorang wanita yang paling cantik. Beliau bersabda: \"Kemudian penguasa tersebut mengirim utusan kepadanya dan bertanya mengenai wanita tersebut. Lalu Ibrahim berkata; sesungguhnya ia adalah saudariku. Kemudian tatkala Ibrahim kembali kepada isterinya ia berkata; sesungguhnya penguasa ini bertanya kepadaku mengenai dirimu, kemudian aku beritahukan kepada mereka bahwa engkau adalah saudariku. Sesungguhnya pada hari ini tidak ada seorang muslim pun kecuali aku dan engkau, dan engkau adalah saudariku dalam kitab Allah, maka janganlah engkau dustakan aku di hadapannya!\" kemudian Muhammad bin Al Mutsanna menyebutkan hadits tersebut. Abu Daud berkata; khabar ini diriwayatkan oleh [Syu'aib bin Abu Hamzah] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam seperti itu. "},"1827":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ وَمُحَمَّدُ بْنُ الْعَلَاءِ الْمَعْنَى قَالَا حَدَّثَنَا ابْنُ إِدْرِيسَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ مُحَمَّدِ بْنِ عَمْرِو بْنِ عَطَاءٍ قَالَ ابْنُ الْعَلَاءِ ابْنِ عَلْقَمَةَ بْنِ عَيَّاشٍ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ سَلَمَةَ بْنِ صَخْرٍ قَالَ ابْنُ الْعَلَاءِ الْبَيَاضِيُّ قَالَكُنْتُ امْرَأً أُصِيبُ مِنْ النِّسَاءِ مَا لَا يُصِيبُ غَيْرِي فَلَمَّا دَخَلَ شَهْرُ رَمَضَانَ خِفْتُ أَنْ أُصِيبَ مِنْ امْرَأَتِي شَيْئًا يُتَابَعُ بِي حَتَّى أُصْبِحَ فَظَاهَرْتُ مِنْهَا حَتَّى يَنْسَلِخَ شَهْرُ رَمَضَانَ فَبَيْنَا هِيَ تَخْدُمُنِي ذَاتَ لَيْلَةٍ إِذْ تَكَشَّفَ لِي مِنْهَا شَيْءٌ فَلَمْ أَلْبَثْ أَنْ نَزَوْتُ عَلَيْهَا فَلَمَّا أَصْبَحْتُ خَرَجْتُ إِلَى قَوْمِي فَأَخْبَرْتُهُمْ الْخَبَرَ وَقُلْتُ امْشُوا مَعِي إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالُوا لَا وَاللَّهِ فَانْطَلَقْتُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرْتُهُ فَقَالَ أَنْتَ بِذَاكَ يَا سَلَمَةُ قُلْتُ أَنَا بِذَاكَ يَا رَسُولَ اللَّهِ مَرَّتَيْنِ وَأَنَا صَابِرٌ لِأَمْرِ اللَّهِ فَاحْكُمْ فِيَّ مَا أَرَاكَ اللَّهُ قَالَ حَرِّرْ رَقَبَةً قُلْتُ وَالَّذِي بَعَثَكَ بِالْحَقِّ مَا أَمْلِكُ رَقَبَةً غَيْرَهَا وَضَرَبْتُ صَفْحَةَ رَقَبَتِي قَالَ فَصُمْ شَهْرَيْنِ مُتَتَابِعَيْنِ قَالَ وَهَلْ أَصَبْتُ الَّذِي أَصَبْتُ إِلَّا مِنْ الصِّيَامِ قَالَ فَأَطْعِمْ وَسْقًا مِنْ تَمْرٍ بَيْنَ سِتِّينَ مِسْكِينًا قُلْتُ وَالَّذِي بَعَثَكَ بِالْحَقِّ لَقَدْ بِتْنَا وَحْشَيْنِ مَا لَنَا طَعَامٌ قَالَ فَانْطَلِقْ إِلَى صَاحِبِ صَدَقَةِ بَنِي زُرَيْقٍ فَلْيَدْفَعْهَا إِلَيْكَ فَأَطْعِمْ سِتِّينَ مِسْكِينًا وَسْقًا مِنْ تَمْرٍ وَكُلْ أَنْتَ وَعِيَالُكَ بَقِيَّتَهَا فَرَجَعْتُ إِلَى قَوْمِي فَقُلْتُ وَجَدْتُ عِنْدَكُمْ الضِّيقَ وَسُوءَ الرَّأْيِ وَوَجَدْتُ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ السَّعَةَ وَحُسْنَ الرَّأْيِ وَقَدْ أَمَرَنِي أَوْ أَمَرَ لِي بِصَدَقَتِكُمْ زَادَ ابْنُ الْعَلَاءِ قَالَ ابْنُ إِدْرِيسَ بَيَاضَةُ بَطْنٌ مِنْ بَنِي زُرَيْقٍ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah], dan [Muhammad bin Al 'Ala`] secara makna, mereka berkata; telah menceritakan kepada kami [Ibnu Idris] dari [Muhammad bin Ishaq] dari [Muhammad bin 'Amr bin 'Atho`]. Ibnu Al 'Ala` bin 'Alqamah bin 'Ayyasy berkata; dari [Sulaiman bin Yasar] dari [Salamah bin Shakhr], ia berkata; Ibnu Al 'Ala` Al Bayadhi berkata; saya dahulu adalah orang yang sering menggauli isteri tidak seperti orang selainku yang menggauli isterinya. Tatkala telah masuk Bulan Ramadhan, saya khawatir menggauli isteriku sehingga hal itu berlanjut hingga pagi hari. Maka aku menzhihar isteriku hingga Bulan Ramadhan berlalu. Ketika pada malam hari ia membantuku tiba-tiba tersingkap sedikit darinya, maka tidak lama kemudian saya menggaulinya. Kemudian tatkala pagi hari saya keluar menuju kepada kaumku dan mengabarkan hal tersebut kepada mereka, dan saya katakan; pergilah kalian bersamaku kepada Rasulullah shallallahu 'alaihi wasallam! Lalu mereka mengatakan; tidak, demi Allah kami tidak akan pergi bersamamu. Maka saya pergi kepada Rasulullah shallallahu 'alaihi wasallam dan menceritakan hal tersebut kepada beliau. Kemudian beliau berkata: \"Wahai Salamah, apakah engkau melakukan hal ini?\" Saya katakan; saya melakukan hal ini -sebanyak dua kali-, dan saya bersabar terhadap terhadap keputusan Allah, maka putuskanlah terhadap diriku apa yang telah Allah perlihatkan kepada dirimu. Beliau bersabda: \"Bebaskan budak.\" Aku katakan; demi Dzat yang mengutusmu dengan kebenaran tidaklah saya memiliki budak selain dirinya. Beliau bersabda: \"Berpuasalah dua bulan berturut-turut!\" Lalu saya katakan; tidaklah saya tertimpa sesuatu yang menimpaku kecuali ketika saya berpuasa. Beliau bersabda: \"Berilah makan satu wasaq kurma enam puluh orang miskin.\" Lalu saya katakan; demi Dzat yang mengutusmu dengan kebenaran, sungguh kami bermalam dalam keadaan tidak memiliki makanan. Beliau berkata: \"Pergilah kepada penjaga Shadaqah Bani Zuraiq, hendaknya ia memberikannya kepadamu dan berilah makan enam puluh orang miskin satu wasaq kurma, dan makanlah sisanya bersama keluargamu.\" Kemudian saya kembali kepada kaumku dan berkata; aku dapatkan di sisi kalian kesempitan serta pendapat yang buruk, dan aku dapatkan di sisi Rasulullah shallallahu 'alaihi wasallam kelapangan dan pendapat yang baik, beliau telah memerintahkan agar aku diberi shadaqah kalian. [Ibnu Al 'Ala`] menambahkan; [Ibnu Idris] Bayadhah berkata; Marga dari Bani Zuraiq."},"1828":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا ابْنُ إِدْرِيسَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ مَعْمَرِ بْنِ عَبْدِ اللَّهِ بْنِ حَنْظَلَةَ عَنْ يُوسُفَ بْنِ عَبْدِ اللَّهِ بْنِ سَلَامٍ عَنْ خُوَيْلَةَ بِنْتِ مَالِكِ بْنِ ثَعْلَبَةَ قَالَتْظَاهَرَ مِنِّي زَوْجِي أَوْسُ بْنُ الصَّامِتِ فَجِئْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَشْكُو إِلَيْهِ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُجَادِلُنِي فِيهِ وَيَقُولُ اتَّقِي اللَّهَ فَإِنَّهُ ابْنُ عَمِّكِ فَمَا بَرِحْتُ حَتَّى نَزَلَ الْقُرْآنُ{ قَدْ سَمِعَ اللَّهُ قَوْلَ الَّتِي تُجَادِلُكَ فِي زَوْجِهَا }إِلَى الْفَرْضِ فَقَالَ يُعْتِقُ رَقَبَةً قَالَتْ لَا يَجِدُ قَالَ فَيَصُومُ شَهْرَيْنِ مُتَتَابِعَيْنِ قَالَتْ يَا رَسُولَ اللَّهِ إِنَّهُ شَيْخٌ كَبِيرٌ مَا بِهِ مِنْ صِيَامٍ قَالَ فَلْيُطْعِمْ سِتِّينَ مِسْكِينًا قَالَتْ مَا عِنْدَهُ مِنْ شَيْءٍ يَتَصَدَّقُ بِهِ قَالَتْ فَأُتِيَ سَاعَتَئِذٍ بِعَرَقٍ مِنْ تَمْرٍ قُلْتُ يَا رَسُولَ اللَّهِ فَإِنِّي أُعِينُهُ بِعَرَقٍ آخَرَ قَالَ قَدْ أَحْسَنْتِ اذْهَبِي فَأَطْعِمِي بِهَا عَنْهُ سِتِّينَ مِسْكِينًا وَارْجِعِي إِلَى ابْنِ عَمِّكِقَالَ وَالْعَرَقُ سِتُّونَ صَاعًا قَالَ أَبُو دَاوُد فِي هَذَا إِنَّهَا كَفَّرَتْ عَنْهُ مِنْ غَيْرِ أَنْ تَسْتَأْمِرَهُ قَالَ أَبُو دَاوُد وَهَذَا أَخُو عُبَادَةَ بْنِ الصَّامِتِ حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ يَحْيَى أَبُو الْأَصْبَغِ الْحَرَّانِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنْ ابْنِ إِسْحَقَ بِهَذَا الْإِسْنَادِ نَحْوَهُ إِلَّا أَنَّهُ قَالَ وَالْعَرَقُ مِكْتَلٌ يَسَعُ ثَلَاثِينَ صَاعًا قَالَ أَبُو دَاوُد وَهَذَا أَصَحُّ مِنْ حَدِيثِ يَحْيَى بْنِ آدَمَ حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا أَبَانُ حَدَّثَنَا يَحْيَى عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ قَالَ يَعْنِي بِالْعَرَقِ زِنْبِيلًا يَأْخُذُ خَمْسَةَ عَشَرَ صَاعًا","id":"Telah menceritakan kepada kami [Al Hasan bin Ali], telah menceritakan kepada kami [Yahya bin Adam], telah menceritakan kepada kami [Ibnu Idris] dari [Muhammad bin Ishaq] dari [Ma'mar bin Abdullah bin Hanzhalah] dari [Yusuf bin Abdullah bin Salam] dari [Khuwailah binti Malik bin Tsa'labah], ia berkata; suamiku yaitu Aus bin Ash Shamit menzhiharku, kemudian aku datang kepada Rasulullah shallallahu 'alaihi wasallam mengadukannya kepada beliau, sementara Rasulullah shallallahu 'alaihi wasallam berdialog denganku mengenainya, beliau berkata: \"Bertakwalah kepada Allah, ia adalah anak pamanmu!\" Tidaklah aku beranjak pergi hingga turun Al Qur'an: \"Sesungguhnya Allah telah mendengar perkataan wanita yang mengajukan gugatan kepada kamu tentang suaminya, dan mengadukan (halnya) kepada Allah. Dan Allah mendengar soal jawab antara kamu berdua. Sesungguhnya Allah Maha Mendengar lagi Maha Melihat\" hingga penyebutan kewajiban yang Allah wajibkan. Kemudian beliau berkata: \"Ia bebaskan seorang budak.\" Khuwailah berkata; ia tidak memilikinya. Beliau berkata; ia berpuasa dua bulan berturut-turut. Khuwailah berkata; wahai rasulullah, sesungguhnya ia adalah orang yang tua renta, ia tidak mampu untuk berpuasa. Beliau berkata: \"Hendaknya ia memberi makan enam orang miskin.\" Khuwailah berkata; ia tidak memiliki sesuatu yang dapat ia sedekahkan. Khuwailah berkata; kemudian pada saat itu ia diberi satu 'araq kurma. Aku katakan; wahai Rasulullah, aku akan membantunya dengan satu 'araq yang lainnya. Beliau bersabda: \"Engkau telah berbuat baik, pergilah dan berilah makan untuknya enam puluh orang miskin dan kembalilah kepada anak pamanmu.\" Ma'mar bin Abdullah bin Hanzhalah berkata; 'Araq adalah enam puluh sha'. Abu Daud berkata dalam hadits ini; sesungguhnya Khuwailah membayar kafarah untuk suaminya tanpa meminta pertimbangan darinya. Abu Daud berkata; dan orang ini adalah saudara 'Ubadah bin Ash Shamit. Telah menceritakan kepada kami [Al Hasan bin Ali], telah menceritakan kepada kami [Abdul Aziz bin Yahya Abu Al Ashbagh Al Harrani], telah menceritakan kepada kami [Muhammad bin Salamah] dari [Ibnu Ishaq] dengan sanad ini seperti itu, hanya saja ia mengatakan; dan 'araq adalah keranjang yang memuat tiga puluh sha'. Abu Daud berkata; dan hadits ini lebih shahih daripada hadits Yahya bin Adam. Telah menceritakan kepada kami Musa bin Isma'il, telah menceritakan kepada kami Aban, telah menceritakan kepada kami Yahya dari Abu Salamah bin Abdurrahman, ia berkata; yang dimaksud dengan 'araq yaitu keranjang yang muat lima belas sha'. "},"1829":{"ar":"حَدَّثَنَا ابْنُ السَّرْحِ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي ابْنُ لَهِيعَةَ وَعَمْرُو بْنُ الْحَارِثِ عَنْ بُكَيْرِ بْنِ الْأَشَجِّ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ بِهَذَا الْخَبَرِقَالَ فَأُتِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِتَمْرٍ فَأَعْطَاهُ إِيَّاهُ وَهُوَ قَرِيبٌ مِنْ خَمْسَةِ عَشَرَ صَاعًا قَالَ تَصَدَّقْ بِهَذَا قَالَ يَا رَسُولَ اللَّهِ عَلَى أَفْقَرَ مِنِّي وَمِنْ أَهْلِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلْهُ أَنْتَ وَأَهْلُكَ","id":"Telah menceritakan kepada kami [Ibnu As Sarh], telah menceritakan kepada kami [Ibnu Wahb], telah mengabarkan kepadaku [Ibnu Luhai'ah] dan ['Amr bin Al Harits] dari [Bukair bin Al Asyajj] dari [Sulaiman bin Yasar] dengan khabar ini. Ia berkata; kemudian Rasulullah shallallahu 'alaihi wasallam diberi kurma lalu beliau memberikan kurma tersebut kepadanya, dan kurma tersebut sekitar lima belas sha'. Beliau berkata: \"Bersedekahlah dengan kurma ini.\" Ia berkata; wahai Rasulullah, apakah aku harus bersedekah kepada orang yang lebih fakir daripadaku dan daripada keluargaku? Kemudian Rasulullah shallallahu 'alaihi wasallam berkata: \"Makanlah bersama keluargamu.\""},"1830":{"ar":"قَالَ أَبُو دَاوُد قَرَأْتُ عَلَى مُحَمَّدِ بْنِ وَزِيرٍ الْمِصْرِيِّ قُلْتُ لَهُ حَدَّثَكُمْ بِشْرُ بْنُ بَكْرٍ حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنَا عَطَاءٌ عَنْ أَوْسٍ أَخِي عُبَادَةَ بْنِ الصَّامِتِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْطَاهُ خَمْسَةَ عَشَرَ صَاعًا مِنْ شَعِيرٍ إِطْعَامَ سِتِّينَ مِسْكِينًاقَالَ أَبُو دَاوُد وَعَطَاءٌ لَمْ يُدْرِكْ أَوْسًا وَهُوَ مِنْ أَهْلِ بَدْرٍ قَدِيمُ الْمَوْتِ وَالْحَدِيثُ مُرْسَلٌ وَإِنَّمَا رَوَوْهُ عَنْ الْأَوْزَاعِيِّ عَنْ عَطَاءٍ أَنَّ أَوْسًا","id":"Abu Daud berkata; aku membacakan riwayat kepada [Muhammad bin Wazir Al Mishri], aku katakan kepadanya; [Bisyr bin Bakr] telah menceritakan kepada kalian, telah menceritakan kepada kami [Al Auza'i], telah menceritakan kepada kami ['Atho`] dari [Aus] saudara 'Ubadah bin Ash Shamit, bahwa Nabi shallallahu 'alaihi wasallam telah memberikan kepadanya lima belas sha' gandum untuk memberikan makan kepada enam puluh orang miskin. Abu Daud berkata; 'Atha` tidak bertemu dengan Aus, yang merupakan diantara orang yang ikut perang Badr dan telah lama meninggal. Hadits tersebut adalah hadits mursal, mereka meriwayatkannya dari Al Auza'i, dari 'Atho`, bahwa Aus. "},"1831":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ هِشَامِ بْنِ عُرْوَةَأَنَّ جَمِيلَةَ كَانَتْ تَحْتَ أَوْسِ بْنِ الصَّامِتِ وَكَانَ رَجُلًا بِهِ لَمَمٌ فَكَانَ إِذَا اشْتَدَّ لَمَمُهُ ظَاهَرَ مِنْ امْرَأَتِهِ فَأَنْزَلَ اللَّهُ تَعَالَى فِيهِ كَفَّارَةَ الظِّهَارِحَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا مُحَمَّدُ بْنُ الْفَضْلِ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ عُرْوَةَ عَنْ عَائِشَةَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Musa bin Isma'il], telah menceritakan kepada kami [Hammad] dari [Hisyam bin 'Urwah] bahwa Jamilah adalah isteri Aus bin Ash Shamit, dan ia adalah orang yang memiliki kekaguman kepada wanita, apabila telah besar kekagumannya ia menzhihar isterinya, kemudian Allah menurunkan padanya ayat mengenai kafarah zhihar. Telah menceritakan kepada kami [Harun bin Abdullah], telah menceritakan kepada kami [Muhammad bin Al Fadhl], telah menceritakan kepada kami [Hammad bin Salamah] dari [Hisyam bin 'Urwah] dari ['Urwah] dari [Aisyah] seperti itu. "},"1832":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِسْمَعِيلَ الطَّالَقَانِيُّ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا الْحَكَمُ بْنُ أَبَانَ عَنْ عِكْرِمَةَأَنَّ رَجُلًا ظَاهَرَ مِنْ امْرَأَتِهِ ثُمَّ وَاقَعَهَا قَبْلَ أَنَّ يُكَفِّرَ فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرَهُ فَقَالَ مَا حَمَلَكَ عَلَى مَا صَنَعْتَ قَالَ رَأَيْتُ بَيَاضَ سَاقِهَا فِي الْقَمَرِ قَالَ فَاعْتَزِلْهَا حَتَّى تُكَفِّرَ عَنْكَ","id":"Telah menceritakan kepada kami [Ishaq bin Isma'il Ath Thalaqani], telah menceritakan kepada kami [Sufyan], telah menceritakan kepada kami [Al Hakam bin Aban] dari [Ikrimah] bahwa seorang laki-laki telah menzhihar isterinya kemudian ia menggaulinya sebelum membayar kafarat. Kemudian ia datang kepada Nabi shallallahu 'alaihi wasallam dan mengabarkan hal tersebut kepadanya. Lalu beliau berkata: \"Apa yang mendorongmu untuk melakukan apa yang telah engkau perbuat?\" Ia berkata; aku melihat putih betisnya dalam cahaya rembulan. Beliau berkata: \"Jauhi dia hingga engkau membayar kafarah.\""},"1833":{"ar":"حَدَّثَنَا الزَّعْفَرَانِيُّ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الْحَكَمِ بْنِ أَبَانَ عَنْ عِكْرِمَةَأَنَّ رَجُلًا ظَاهَرَ مِنْ امْرَأَتِهِ فَرَأَى بَرِيقَ سَاقِهَا فِي الْقَمَرِ فَوَقَعَ عَلَيْهَا فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَهُ أَنْ يُكَفِّرَحَدَّثَنَا زِيَادُ بْنُ أَيُّوبَ حَدَّثَنَا إِسْمَعِيلُ حَدَّثَنَا الْحَكَمُ بْنُ أَبَانَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ وَلَمْ يَذْكُرْ السَّاقَ حَدَّثَنَا أَبُو كَامِلٍ أَنَّ عَبْدَ الْعَزِيزِ بْنَ الْمُخْتَارِ حَدَّثَهُمْ حَدَّثَنَا خَالِدٌ حَدَّثَنِي مُحَدِّثٌ عَنْ عِكْرِمَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِنَحْوِ حَدِيثِ سُفْيَانَ قَالَ أَبُو دَاوُد و سَمِعْت مُحَمَّدَ بْنَ عِيسَى يُحَدِّثُ بِهِ حَدَّثَنَا الْمُعْتَمِرُ قَالَ سَمِعْتُ الْحَكَمَ بْنَ أَبَانَ يُحَدِّثُ بِهَذَا الْحَدِيثِ وَلَمْ يَذْكُرْ ابْنَ عَبَّاسٍ قَالَ عَنْ عِكْرِمَةَ قَالَ أَبُو دَاوُد كَتَبَ إِلَيَّ الْحُسَيْنُ بْنُ حُرَيْثٍ قَالَ أَخْبَرَنَا الْفَضْلُ بْنُ مُوسَى عَنْ مَعْمَرٍ عَنْ الْحَكَمِ بْنِ أَبَانَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ بِمَعْنَاهُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Az Za'farani], Telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Al Hakam bin Aban] dari [Ikrimah] bahwa seorang laki-laki telah menzhihar isterinya kemudian ia melihat putih betisnya dalam cahaya rembulan, lalu ia menggaulinya, dan datang kepada Nabi shallallahu 'alaihi wasallam. Lalu beliau memerintahkannya agar membayar kafarah. Telah menceritakan kepada kami [Ziyad bin Ayyub], Telah menceritakan kepada kami [Isma'il], telah menceritakan kepada kami [Al Hakam bin Aban] dari [Ikrimah] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam seperti itu, dan ia tidak menyebutkan betis. Telah menceritakan kepada kami [Abu Kamil] bahwa [Abdul Aziz bin Al Mukhtar] telah menceritakan kepada mereka; telah menceritakan kepada kami [Khalid], telah menceritakan kepadaku [seseorang] dari [Ikrimah] dari Nabi shallallahu 'alaihi wasallam dengan hadits seperti hadits Sufyan. Abu Daud berkata; aku mendengar [Muhammad bin Isa] menceritakan mengenainya. Telah menceritakan kepada kami [Al Mu'tamir], ia berkata; aku telah mendengar [Al Hakam bin Aban], ia menceritakan dengan hadits ini dan tidak menyebutkan Ibnu Abbas. Ia mengatakannya dari [Ikrimah]. Abu Daud berkata; [Al Husain bin Huraits] menulis surat kepadaku, ia berkata; telah mengabarkan kepada kami [Al Fadhl bin Musa] dari [Ma'mar] dari [Al Hakam bin Aban], dari [Ikrimah] dari [Ibnu Abbas] secara makna dari Nabi shallallahu 'alaihi wasallam. "},"1834":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادٌ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي أَسْمَاءَ عَنْ ثَوْبَانَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّمَا امْرَأَةٍ سَأَلَتْ زَوْجَهَا طَلَاقًا فِي غَيْرِ مَا بَأْسٍ فَحَرَامٌ عَلَيْهَا رَائِحَةُ الْجَنَّةِ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb], telah menceritakan kepada kami [Hammad] dari [Ayyub] dari [Abu Qilabah] dari [Abu Asma`] dari [Tsauban], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapapun wanita yang meminta cerai kepada suaminya bukan karena kesalahan, maka haram baginya bau surga.\""},"1835":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عَمْرَةَ بِنْتِ عَبْدِ الرَّحْمَنِ بْنِ سَعْدِ بْنِ زُرَارَةَ أَنَّهَا أَخْبَرَتْهُعَنْ حَبِيبَةَ بِنْتِ سَهْلٍ الْأَنْصَارِيَّةِ أَنَّهَا كَانَتْ تَحْتَ ثَابِتِ بْنِ قَيْسِ بْنِ شَمَّاسٍ وَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ إِلَى الصُّبْحِ فَوَجَدَ حَبِيبَةَ بِنْتَ سَهْلٍ عِنْدَ بَابِهِ فِي الْغَلَسِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ هَذِهِ فَقَالَتْ أَنَا حَبِيبَةُ بِنْتُ سَهْلٍ قَالَ مَا شَأْنُكِ قَالَتْ لَا أَنَا وَلَا ثَابِتُ بْنُ قَيْسٍ لِزَوْجِهَا فَلَمَّا جَاءَ ثَابِتُ بْنُ قَيْسٍ قَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذِهِ حَبِيبَةُ بِنْتُ سَهْلٍ وَذَكَرَتْ مَا شَاءَ اللَّهُ أَنْ تَذْكُرَ وَقَالَتْ حَبِيبَةُ يَا رَسُولَ اللَّهِ كُلُّ مَا أَعْطَانِي عِنْدِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِثَابِتِ بْنِ قَيْسٍ خُذْ مِنْهَا فَأَخَذَ مِنْهَا وَجَلَسَتْ هِيَ فِي أَهْلِهَا","id":"Telah menceritakan kepada kami [Al Qa'nabi], dari [Malik] dari [Yahya bin Sa'id] dari ['Amrah binti Abdurrahman bin Sa'd bin Zurarah] bahwa ia telah mengabarkan kepadanya dari [Habibah binti Sahl Al Anshariyah] bahwa ia adalah iseri Tsabit bin Qais bin Syahs, dan Rasulullah shallallahu 'alaihi wasallam keluar untuk melakukan Shalat Subuh, kemudian beliau mendapati Habibah binti Sahl di depan pintu dalam kegelapan malam. Rasulullah shallallahu 'alaihi wasallam berkata: \"Siapakah ini?\" Habibah berkata; saya Habibah binti Sahl. Beliau berkata: \"Apakah keperluanmu?\" Ia berkata; tidak ada lagi hubungan antara saya dan Tsabit bin Qais. Kemudian tatkala Tsabit bin Qais datang, Rasulullah shallallahu 'alaihi wasallam berkata kepadanya: \"Ini adalah Habibah binti Sahl, dan ia telah menceritakan apa yang Allah kehendaki untuk disebutkan.\" Ummu Habibah berkata; wahai Rasulullah, (kuserahkan) seluruh apa yang ia berikan ada padaku. Maka Rasulullah berkata kepada Tsabit bin Qais, ambillah darinya. Kemudian ia pun mengambilnya. Dan Habibah duduk (kembali) kepada keluarganya. "},"1836":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مَعْمَرٍ حَدَّثَنَا أَبُو عَامِرٍ عَبْدُ الْمَلِكِ بْنُ عَمْرٍو حَدَّثَنَا أَبُو عَمْرٍو السَّدُوسِيُّ الْمَدِينِيُّ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرِ بْنِ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَزْمٍ عَنْ عَمْرَةَ عَنْ عَائِشَةَأَنَّ حَبِيبَةَ بِنْتَ سَهْلٍ كَانَتْ عِنْدَ ثَابِتِ بْنِ قَيْسِ بْنِ شَمَّاسٍ فَضَرَبَهَا فَكَسَرَ بَعْضَهَا فَأَتَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَ الصُّبْحِ فَاشْتَكَتْهُ إِلَيْهِ فَدَعَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَابِتًا فَقَالَ خُذْ بَعْضَ مَالِهَا وَفَارِقْهَا فَقَالَ وَيَصْلُحُ ذَلِكَ يَا رَسُولَ اللَّهِ قَالَ نَعَمْ قَالَ فَإِنِّي أَصْدَقْتُهَا حَدِيقَتَيْنِ وَهُمَا بِيَدِهَا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خُذْهُمَا وَفَارِقْهَا فَفَعَلَ","id":"Telah menceritakan kepada kami [Muhammad bin Ma'mar], telah menceritakan kepada kami [Abu 'Amir Abdul Malik bin 'Amr], telah menceritakan kepada kami [Abu 'Amr As Sadusi Al Madini], dari [Abdullah bin Abu Bakr bin Muhammad bin 'Amr bin Hazm] dari ['Amrah] dari [Aisyah] bahwa Habibah binti Sahl pernah berada di di sisi Tsabit bin Qais bin Syammas, kemudian ia memukulnya dan melukai sebagian tubuhnya. Lalu Habibah datang kepada Rasulullah shallallahu 'alaihi wasallam setelah shalat Subuh dan mengadu kepadanya. Maka Nabi shallallahu 'alaihi wasallam memanggil Tsabit dan berkata: \"Ambillah sebagian hartanya dan ceraikan dia!\" Kemudian Tsabit berkata; apakah hal tersebut boleh wahai Rasulullah? Beliau berkata: \"Ya.\" Kemudian ia berkata; sesungguhnya saya telah memberinya mahar dua kebun, dan keduanya ada di tangannya. Nabi shallallahu 'alaihi wasallam bersabda: \"Ambillah keduanya dan ceraikan dia!\" kemudian Tsabit melakukan hal tersebut. "},"1837":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحِيمِ الْبَزَّازُ حَدَّثَنَا عَلِيُّ بْنُ بَحْرٍ الْقَطَّانُ حَدَّثَنَا هِشَامُ بْنُ يُوسُفَ عَنْ مَعْمَرٍ عَنْ عَمْرِو بْنِ مُسْلِمٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ امْرَأَةَ ثَابِتِ بْنِ قَيْسٍ اخْتَلَعَتْ مِنْهُ فَجَعَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِدَّتَهَا حَيْضَةًقَالَ أَبُو دَاوُد وَهَذَا الْحَدِيثُ رَوَاهُ عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ عَمْرِو بْنِ مُسْلِمٍ عَنْ عِكْرِمَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُرْسَلًا","id":"Telah menceritakan kepada kami [Muhammad bin Abdurrahim Al Bazzar], telah menceritakan kepada kami [Ali bin Bahr Al Qaththan], telah menceritakan kepada kami [Hisyam bin Yusuf] dari [Ma'mar] dari ['Amr bin Muslim] dari [Ikrimah] dari [Ibnu Abbas] bahwa isteri Tsabit bin Qais meminta khulu' darinya. Kemudian Nabi menjadikan iddahnya adalah satu kali haid. Abu Daud berkata; dan hadits ini diriwayatkan oleh [Abdurrazzaq] dari [Ma'mar] dari ['Amr bin Muslim] dari [Ikrimah] dari Nabi shallallahu 'alaihi wasallam secara mursal. "},"1838":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَعِدَّةُ الْمُخْتَلِعَةِ حَيْضَةٌ","id":"Telah menceritakan kepada kami [Al Qa'nabi], dari [Malik] dari [Nafi'] dari [Ibnu Umar], ia berkata; orang yang meminta khulu' 'iddahnya adalah satu kali haid. "},"1839":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ مُغِيثًا كَانَ عَبْدًا فَقَالَ يَا رَسُولَ اللَّهِ اشْفَعْ لِي إِلَيْهَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا بَرِيرَةُ اتَّقِي اللَّهَ فَإِنَّهُ زَوْجُكِ وَأَبُو وَلَدِكِ فَقَالَتْ يَا رَسُولَ اللَّهِ أَتَأْمُرُنِي بِذَلِكَ قَالَ لَا إِنَّمَا أَنَا شَافِعٌ فَكَانَ دُمُوعُهُ تَسِيلُ عَلَى خَدِّهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلْعَبَّاسِ أَلَا تَعْجَبُ مِنْ حُبِّ مُغِيثٍ بَرِيرَةَ وَبُغْضِهَا إِيَّاهُ","id":"Telah menceritakan kepada kami [Musa bin Isma'il], telah menceritakan kepada kami [Hammad] dari [Khalid Al Hadzdza`] dari [Ikrimah] dari [Ibnu Abbas] bahwa Mughits adalah seorang budak, kemudian ia berkata; wahai Rasulullah, bantulah aku berbicara kepadanya! Kemudian Rasulullah shallallahu 'alaihi wasallam berkata: \"Wahai Barirah, bertakwalah kepada Allah! Sesungguhnya ia adalah suamimu, dan ayah anakmu.\" Barirah berkata; wahai Rasulullah, apakah engkau memerintahkanku untuk melakukan hal tersebut? Beliau berkata: \"Tidak, sesungguhnya aku adalah perantara.\" Sementara air mata Mughits mengalir ke pipinya. Kemudian Rasulullah shallallahu 'alaihi wasallam berkata kepada Ibnu Abbas: \"Tidakkah engkau kagum kepada kecintaan Mughits kepada Barirah, dan kebencian Barirah kepadanya?\""},"1840":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَفَّانُ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ زَوْجَ بَرِيرَةَ كَانَ عَبْدًا أَسْوَدَ يُسَمَّى مُغِيثًا فَخَيَّرَهَا يَعْنِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَمَرَهَا أَنْ تَعْتَدَّ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah], telah menceritakan kepada kami ['Affan], telah menceritakan kepada kami [Hammam], dari [Qatadah] dari [Ikrimah], dari [Ibnu Abbas] bahwa suami Barirah adalah seorang budak yang hitam yang bernama Mughits, kemudian Nabi shallallahu 'alaihi wasallam memberikan pilihan kepada Barirah, dan memerintahkannya agar ber'iddah. "},"1841":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَفِي قِصَّةِ بَرِيرَةَ قَالَتْ كَانَ زَوْجُهَا عَبْدًا فَخَيَّرَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاخْتَارَتْ نَفْسَهَا وَلَوْ كَانَ حُرًّا لَمْ يُخَيِّرْهَا","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah], telah menceritakan kepada kami [Jarir] dari [Hisyam bin Urwah], dari [ayahnya] dari [Aisyah] mengenai kisah Barirah, ia berkata; suaminya adalah seorang budak. Kemudian Rasulullah shallallahu 'alaihi wasallam memberikan pilihan kepadanya, lalu ia memilih dirinya, dan seandainya Mughits adalah orang yang merdeka, maka beliau tidak akan memberikan pilihan kepadanya. "},"1842":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا حُسَيْنُ بْنُ عَلِيٍّ وَالْوَلِيدُ بْنُ عُقْبَةَ عَنْ زَائِدَةَ عَنْ سِمَاكٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّ بَرِيرَةَ خَيَّرَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ زَوْجُهَا عَبْدًا","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah], telah menceritakan kepada kami [Husain bin Ali] serta [Al Walid bin 'Uqbah] dari [Zaidah] dari [Simak] dari [Abdurrahman bin Al Qasim] dari [ayahnya] dari [Aisyah] bahwa Barirah diberikan pilihan kepada oleh Rasulullah shallallahu 'alaihi wasallam, dan suaminya adalah seorang budak."},"1843":{"ar":"حَدَّثَنَا ابْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَأَنَّ زَوْجَ بَرِيرَةَ كَانَ حُرًّا حِينَ أُعْتِقَتْ وَأَنَّهَا خُيِّرَتْ فَقَالَتْ مَا أُحِبُّ أَنْ أَكُونَ مَعَهُ وَأَنَّ لِي كَذَا وَكَذَا","id":"Telah menceritakan kepada kami [Ibnu Katsir], telah mengabarkan kepada kami [Sufyan] dari [Manshur] dari [Ibrahim] dari [Al Aswad] dari [Aisyah] bahwa suami Barirah adalah orang yang merdeka ketika Barirah dibebaskan, dan ia diberi pilihak kemudian mengatakan; aku tidak suka tinggal bersamanya, dan aku memiliki demikian dan demikian. "},"1844":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ يَحْيَى الْحَرَّانِيُّ حَدَّثَنِي مُحَمَّدٌ يَعْنِي ابْنَ سَلَمَةَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ أَبِي جَعْفَرٍ وَعَنْ أَبَانَ بْنِ صَالِحٍ عَنْ مُجَاهِدٍ وَعَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّ بَرِيرَةَ أُعْتِقَتْ وَهِيَ عِنْدَ مُغِيثٍ عَبْدٍ لِآلِ أَبِي أَحْمَدَ فَخَيَّرَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ لَهَا إِنْ قَرِبَكِ فَلَا خِيَارَ لَكِ","id":"Telah menceritakan kepada kami [Abdul Aziz bin Yahya Al Harrani], telah menceritakan kepadaku [Muhammad bin Salamah] dari [Muhammad bin Ishaq] dari [Abu Ja'far] dari [Aban bin Shalih] dari [Mujahid] dari [Hisyam bin 'Urwah] dari [ayahnya] dari [Aisyah] bahwa Barirah telah dibebaskan sementara ia adalah isteri Mughits, seorang budak keluarga Abu Ahmad. Kemudian Rasulullah shallallahu 'alaihi wasallam diberikan pilihan kepada Barirah, dan beliau berkata kepadanya: \"Apabila ia mendekatimu, maka engkau tidak memiliki hak untuk memilih.\""},"1845":{"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ وَنَصْرُ بْنُ عَلِيٍّ قَالَ زُهَيْرٌ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عَبْدِ الْمَجِيدِ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ بْنِ مَوْهَبٍ عَنْ الْقَاسِمِ عَنْ عَائِشَةَأَنَّهَا أَرَادَتْ أَنْ تَعْتِقَ مَمْلُوكَيْنِ لَهَا زَوْجٌ قَالَ فَسَأَلَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَلِكَ فَأَمَرَهَا أَنْ تَبْدَأَ بِالرَّجُلِ قَبْلَ الْمَرْأَةِقَالَ نَصْرٌ أَخْبَرَنِي أَبُو عَلِيٍّ الْحَنَفِيُّ عَنْ عُبَيْدِ اللَّهِ","id":"Telah menceritakan kepada kami [Zuhair bin Harb] serta [Nashr bin Ali], Zuhair berkata; telah menceritakan kepada kami ['Ubaidullah bin Abdurrahman bin Mauhib] dari [Al Qasim] dari [Aisyah] bahwa ia ingin untuk membebaskan dua dua orang budak yang memiliki suami. Al Qasim berkata; kemudian Aisyah bertanya kepada Nabi shallallahu 'alaihi wasallam mengenai hal tersebut, lalu beliau memerintahkannya agar memulai dengan seorang laki-laki sebelum yang wanita. Nashr berkata; [Abu Ali Al Hanafi] telah menceritakannya dari ['Ubaidullah]. "},"1846":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ إِسْرَائِيلَ عَنْ سِمَاكٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ رَجُلًا جَاءَ مُسْلِمًا عَلَى عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ جَاءَتْ امْرَأَتُهُ مُسْلِمَةً بَعْدَهُ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّهَا قَدْ كَانَتْ أَسْلَمَتْ مَعِي فَرُدَّهَا عَلَيَّ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah], telah menceritakan kepada kami [Waki'] dari [Israil] dari [Simak] dari [Ikrimah] dari [Ibnu Abbas] bahwa seorang laki-laki datang sebagai seorang muslim pada masa Nabi shallallahu 'alaihi wasallam kemudian isterinya datang sebagai seorang muslimah setelahnya. Kemudian ia berkata; wahai Rasulullah, sesungguhnya ia telah masuk Islam bersamaku, maka kembalikanlah ia kapadaku. "},"1847":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ أَخْبَرَنِي أَبُو أَحْمَدَ عَنْ إِسْرَائِيلَ عَنْ سِمَاكٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَأَسْلَمَتْ امْرَأَةٌ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَزَوَّجَتْ فَجَاءَ زَوْجُهَا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي قَدْ كُنْتُ أَسْلَمْتُ وَعَلِمَتْ بِإِسْلَامِي فَانْتَزَعَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ زَوْجِهَا الْآخَرِ وَرَدَّهَا إِلَى زَوْجِهَا الْأَوَّلِ","id":"Telah menceritakan kepada kami [Nashr bin Ali], telah mengabarkan kepada kami [Abu Ahmad] dari [Israil] dari [Simak] dari [Ikrimah] dari [Ibnu Abbas], ia berkata; ada seorang wanita yang telah masuk Islam pada zaman Rasulullah shallallahu 'alaihi wasallam kemudian ia menikah, suaminya datang kepada Nabi shallallahu 'alaihi wasallam berkata; wahai Rasulullah, aku telah masuk Islam dan ia telah mengetahui keislamanku. Kemudian Rasulullah shallallahu 'alaihi wasallam memisahkannya dari suaminya yang lain dan mengembalikannya kepada suaminya yang pertama. "},"1848":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ ح و حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرٍو الرَّازِيُّ حَدَّثَنَا سَلَمَةُ يَعْنِي ابْنَ الْفَضْلِ ح و حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا يَزِيدُ الْمَعْنَى كُلُّهُمْ عَنْ ابْنِ إِسْحَقَ عَنْ دَاوُدَ بْنِ الْحُصَيْنِ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَرَدَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ابْنَتَهُ زَيْنَبَ عَلَى أَبِي الْعَاصِ بِالنِّكَاحِ الْأَوَّلِ لَمْ يُحْدِثْ شَيْئًا قَالَ مُحَمَّدُ بْنُ عَمْرٍو فِي حَدِيثِهِ بَعْدَ سِتِّ سِنِينَ وَقَالَ الْحَسَنُ بْنُ عَلِيٍّ بَعْدَ سَنَتَيْنِ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad An Nufaili], telah menceritakan kepada kami [Muhammad bin Salamah], dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Muhammad bin 'Amr Ar Razi], telah menceritakan kepada kami [Salamah yaitu Ibnu Al Fadh], dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Al Hasan bin Ali], telah menceritakan kepada kami [Yazid] secara makna, dan seluruh mereka berasal dari [Ibnu Ishaq], dari [Daud bin Al Hushain], dari [Ikrimah] dari [Ibnu Abbas], ia berkata; Rasulullah shallallahu 'alaihi wasallam mengembalikan anak wanitanya yaitu Zainab kepada Abu Al 'Ash dengan pernikahan yang pertama dan beliau tidak memperbarui sesuatupun. Muhammad bin 'Amr berkata dalam haditsnya; setelah enam tahun, sedangkan Al Hasan bin Ali berkata; setelah dua tahun. "},"1849":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا هُشَيْمٌ ح و حَدَّثَنَا وَهْبُ بْنُ بَقِيَّةَ أَخْبَرَنَا هُشَيْمٌ عَنْ ابْنِ أَبِي لَيْلَى عَنْ حُمَيْضَةَ بْنِ الشَّمَرْدَلِ عَنْ الْحَارِثِ بْنِ قَيْسٍ قَالَ مُسَدَّدٌ ابْنِ عُمَيْرَةَ وَقَالَ وَهْبٌ الْأَسَدِيِّ قَالَأَسْلَمْتُ وَعِنْدِي ثَمَانُ نِسْوَةٍ فَذَكَرْتُ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اخْتَرْ مِنْهُنَّ أَرْبَعًاقَالَ أَبُو دَاوُد و حَدَّثَنَا بِهِ أَحْمَدُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هُشَيْمٌ بِهَذَا الْحَدِيثِ فَقَالَ قَيْسُ بْنُ الْحَارِثِ مَكَانَ الْحَارِثِ بْنِ قَيْسٍ قَالَ أَحْمَدُ بْنُ إِبْرَاهِيمَ هَذَا هُوَ الصَّوَابُ يَعْنِي قَيْسَ بْنَ الْحَارِثِ حَدَّثَنَا أَحْمَدُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا بَكْرُ بْنُ عَبْدِ الرَّحْمَنِ قَاضِي الْكُوفَةِ عَنْ عِيسَى بْنِ الْمُخْتَارِ عَنْ ابْنِ أَبِي لَيْلَى عَنْ حُمَيْضَةَ بْنِ الشَّمَرْدَلِ عَنْ قَيْسِ بْنِ الْحَارِثِ بِمَعْنَاهُ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Husyaim], telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Wahb bin Baqiyyah], telah mengabarkan kepada kami [Husyaim] dari [Ibnu Abu Laila] dari [Humaidhah bin Asy Syamardal], dari [Al Harits bin Qais], ia berkata; Musaddad bin 'Umairah, dan telah berkata Wahb Al Asadi; aku masuk Islam delapan, kemudian aku menceritakannya kepada Nabi shallallahu 'alaihi wasallam. Nabi shallallahu 'alaihi wasallam bersabda: \"Pilihlah empat orang diantara mereka.\" Abu Daud berkata; dan [Ahmad bin Ibrahim] telah menceritakannya kepada kami, telah menceritakan kepada kami [Husyaim] dengan hadits ini, telah berkata [Qais bin Al Harits] -sebagai ganti Al Harits bin Qais, Ahmad bin Ibrahim berkata; inilah yang benar, yaitu bernama Qais bin Al Harits, telah menceritakan kepada kami [Ahmad bin Ibrahim], telah menceritakan kepada kami [Bakr bin Abdurrahman] seorang hakim di Kufah, dari [Isa bin Al Mukhtar] dari [Ibnu Abu Laila], dari [Humaishah bin Aisyah Syamardal] dari [Qais bin Al Harits] dengan maknanya. "},"1850":{"ar":"حَدَّثَنَا يَحْيَى بْنُ مَعِينٍ حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ عَنْ أَبِيهِ قَالَ سَمِعْتُ يَحْيَى بْنَ أَيُّوبَ يُحَدِّثُ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ أَبِي وَهْبٍ الْجَيْشَانِيِّ عَنْ الضَّحَّاكِ بْنِ فَيْرُوزَ عَنْ أَبِيهِ قَالَقُلْتُ يَا رَسُولَ اللَّهِ إِنِّي أَسْلَمْتُ وَتَحْتِي أُخْتَانِ قَالَ طَلِّقْ أَيَّتَهُمَا شِئْتَ","id":"Telah menceritakan kepada kami [Yahya bin Ma'in], telah menceritakan kepada kami [Wahb bin Jarir] dari [ayahnya], ia berkata; saya mendengar [Yahya bin Ayyub], menceritakan dari [Yazid bin Abu Habib], dari [Abu Wahb Al Jaisyani], dari [Adh Dhahhak bin Fairuz] dari [ayahnya], ia berkata; aku katakan; wahai Rasulullah, sesungguhnya aku telah masuk Islam, dan aku memiliki dua orang isteri yang bersaudara. Beliau berkata; ceraikan siapa diantara keduanya yang engkau kehendaki. "},"1851":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى الرَّازِيُّ أَخْبَرَنَا عِيسَى حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ جَعْفَرٍ أَخْبَرَنِي أَبِي عَنْ جَدِّي رَافِعِ بْنِ سِنَانٍأَنَّهُ أَسْلَمَ وَأَبَتْ امْرَأَتُهُ أَنْ تُسْلِمَ فَأَتَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ ابْنَتِي وَهِيَ فَطِيمٌ أَوْ شَبَهُهُ وَقَالَ رَافِعٌ ابْنَتِي قَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْعُدْ نَاحِيَةً وَقَالَ لَهَا اقْعُدِي نَاحِيَةً قَالَ وَأَقْعَدَ الصَّبِيَّةَ بَيْنَهُمَا ثُمَّ قَالَ ادْعُوَاهَا فَمَالَتْ الصَّبِيَّةُ إِلَى أُمِّهَا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ اهْدِهَا فَمَالَتْ الصَّبِيَّةُ إِلَى أَبِيهَا فَأَخَذَهَا","id":"Telah menceritakan kepada kami [Ibrahim bin Musa Ar Razi], telah mengabarkan kepadaku [Isa], telah menceritakan kepada kami [Abdul Hamid bin Ja'far], telah mengabarkan kepadaku [ayahku], dari [kakekku yaitu Rafi' bin Sinan], bahwa ia telah masuk Islam sedangkan isterinya menolak untuk masuk Islam. Kemudian wanita tersebut datang kepada Nabi shallallahu 'alaihi wasallam dan berkata; anak wanitaku ia masih menyusu -atau yang serupa dengannya. Rafi' berkata; ia adalah anak wanitaku. Beliau berkata kepada wanita tersebut; duduklah di pojok. Dan mendudukkan anak kecil tersebut diantara mereka berdua, kemudian beliau berkata; panggillah ia. Kemudian anak tersebut menuju kepada ibunya. Lalu Nabi shallallahu 'alaihi wasallam berdoa: \"Ya Allah, berilah dia petunjuk!\" kemudian anak tersebut menuju kepada ayahnya. kemudian Rafi' bin Sinan membawa anak tersebut. "},"1852":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ أَنَّ سَهْلَ بْنَ سَعْدٍ السَّاعِدِيَّ أَخْبَرَهُأَنَّ عُوَيْمِرَ بْنَ أَشْقَرَ الْعَجْلَانِيَّ جَاءَ إِلَى عَاصِمِ بْنِ عَدِيٍّ فَقَالَ لَهُ يَا عَاصِمُ أَرَأَيْتَ رَجُلًا وَجَدَ مَعَ امْرَأَتِهِ رَجُلًا أَيَقْتُلُهُ فَتَقْتُلُونَهُ أَمْ كَيْفَ يَفْعَلُ سَلْ لِي يَا عَاصِمُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَلِكَ فَسَأَلَ عَاصِمٌ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَرِهَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَسَائِلَ وَعَابَهَا حَتَّى كَبُرَ عَلَى عَاصِمٍ مَا سَمِعَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا رَجَعَ عَاصِمٌ إِلَى أَهْلِهِ جَاءَهُ عُوَيْمِرٌ فَقَالَ لَهُ يَا عَاصِمُ مَاذَا قَالَ لَكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ عَاصِمٌ لَمْ تَأْتِنِي بِخَيْرٍ ق��دْ كَرِهَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَسْأَلَةَ الَّتِي سَأَلْتُهُ عَنْهَا فَقَالَ عُوَيْمِرٌ وَاللَّهِ لَا أَنْتَهِي حَتَّى أَسْأَلَهُ عَنْهَا فَأَقْبَلَ عُوَيْمِرٌ حَتَّى أَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ وَسْطَ النَّاسِ فَقَالَ يَا رَسُولَ اللَّهِ أَرَأَيْتَ رَجُلًا وَجَدَ مَعَ امْرَأَتِهِ رَجُلًا أَيَقْتُلُهُ فَتَقْتُلُونَهُ أَمْ كَيْفَ يَفْعَلُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ أُنْزِلَ فِيكَ وَفِي صَاحِبَتِكَ قُرْآنٌ فَاذْهَبْ فَأْتِ بِهَا قَالَ سَهْلٌ فَتَلَاعَنَا وَأَنَا مَعَ النَّاسِ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا فَرَغَا قَالَ عُوَيْمِرٌ كَذَبْتُ عَلَيْهَا يَا رَسُولَ اللَّهِ إِنْ أَمْسَكْتُهَا فَطَلَّقَهَا عُوَيْمِرٌ ثَلَاثًا قَبْلَ أَنْ يَأْمُرَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ابْنُ شِهَابٍ فَكَانَتْ تِلْكَ سُنَّةُ الْمُتَلَاعِنَيْنِحَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ يَحْيَى حَدَّثَنِي مُحَمَّدٌ يَعْنِي ابْنَ سَلَمَةَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ حَدَّثَنِي عَبَّاسُ بْنُ سَهْلٍ عَنْ أَبِيهِ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِعَاصِمِ بْنِ عَدِيٍّ أَمْسِكْ الْمَرْأَةَ عِنْدَكَ حَتَّى تَلِدَ حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ سَهْلِ بْنِ سَعْدٍ السَّاعِدِيِّ قَالَ حَضَرْتُ لِعَانَهُمَا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا ابْنُ خَمْسَ عَشْرَةَ سَنَةً وَسَاقَ الْحَدِيثَ قَالَ فِيهِ ثُمَّ خَرَجَتْ حَامِلًا فَكَانَ الْوَلَدُ يُدْعَى إِلَى أُمِّهِ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah Al Qa'nabi] dari [Malik] dari [Ibnu Syihab] bahwa [Sahl bin Sa'd As Sa'idi] telah mengabarkan kepadanya bahwa 'Uwaimir bin Asyqar Al 'Ajlani telah datang kepada 'Ashim bin 'Adi, ia berkata kepadanya; wahai 'Ashim, bagaimana pendapatmu apabila seorang laki-laki mendapati seorang laki-laki bersama dengan isterinya. Apakah boleh ia membunuhnya hingga orang-orang akan membunuhnya atau bagaimana ia berbuat? Tanyakan hal tersebut kepada Rasulullah shallallahu 'alaihi wasallam wahai 'Ashim! Kemudian 'Ashim bertanya kepada Rasulullah shallallahu 'alaihi wasallam, dan beliau tidak menyukai masalah-masalah tersebut, dan mencelanya, hingga terasa berat bagi 'Ashim apa yang ia dengar dari Rasulullah shallallahu 'alaihi wasallam. Kemudian tatkala 'Ashim kembali kepada keluarganya datanglah 'Uwaimir kepadanya dan berkata; wahai 'Ashim, apa yang dikatakan Rasulullah shallallahu 'alaihi wasallam kepadamu? Kemudian 'Ashim berkata kepada 'Uwaimir; engkau tidak datang kepadaku dengan kebaikan, sungguh Rasulullah shallallahu 'alaihi wasallam tidak menyukai permasalahan yang aku tanyakan. Kemudian 'Uwaimir berkata; demi Allah, saya tidak akan berhenti hingga menanyakannya kepada Rasulullah shallallahu 'alaihi wasallam. Kemudian 'Uwaimir datang kepada Rasulullah shallallahu 'alaihi wasallam yang sedang berada di tengah orang-orang. Kemudian ia berkata; wahai Rasulullah, bagaimana pendapat anda mengenai seorang laki-laki yang mendapati seorang laki-laki bersama dengan isterinya, apakah ia membunuhnya sehingga orang-orang membunuhnya atau bagaimana ia harus berbuat? Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh telah turun wahyu mengenaimu dan isterimu. Pergi dan bawalah dia.\" [Sahl] berkata; kemudian mereka berdua saling melaknat, dan saya bersama orang-orang yang lain berada di sisi Rasulullah shallallahu 'alaihi wasallam. Kemudian tatkala 'Uwaimir selesai, ia berkata; wahai Rasulullah, saya telah berdusta apabila saya menahannya. Kemudian ia menceraikan isterinya sebanyak tiga kali talak sebelum Rasulullah shallallahu 'alaihi wasallam memerintahkannya. Ibnu Syihab berkata; maka itulah sunah orang-orang yang saling melakukan laknat. Telah menceritakan kepada kami [Abdul 'Aziz bin Yahya], telah menceritakan kepadaku [Muhammad bin Salamah] dari [Muhammad bin Ishaq], telah menceritakan kepadaku [Abbas bin Sahl] dari [ayahnya] bahwa Nabi shallallahu 'alaihi wasallam berkata kepada 'Ashim bin Adi: \"Tahanlah wanita tersebut padamu hingga ia melahirkan!\" telah menceritakan kepada kami [Ahmad bin Shalih], telah menceritakan kepada kami [Ibnu Wahb], ia berkata; telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dari [Sahl bin Sa'd As Sa'idi], ia berkata; aku menyaksikan li'an mereka berdua di sisi Nabi shallallahu 'alaihi wasallam sementara umurku lima belas tahun. Dan ia menyebutkan hadits tersebut, padanya ia mengatakan; kemudian ia keluar dalam keadaan hamil, dan anaknya dinisbatkan kepada ibunya."},"1853":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ الْوَرَكَانِيُّ أَخْبَرَنَا إِبْرَاهِيمُ يَعْنِي ابْنَ سَعْدٍ عَنْ الزُّهْرِيِّ عَنْ سَهْلِ بْنِ سَعْدٍفِي خَبَرِ الْمُتَلَاعِنَيْنِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبْصِرُوهَا فَإِنْ جَاءَتْ بِهِ أَدْعَجَ الْعَيْنَيْنِ عَظِيمَ الْأَلْيَتَيْنِ فَلَا أُرَاهُ إِلَّا قَدْ صَدَقَ وَإِنْ جَاءَتْ بِهِ أُحَيْمِرَ كَأَنَّهُ وَحَرَةٌ فَلَا أُرَاهُ إِلَّا كَاذِبًا قَالَ فَجَاءَتْ بِهِ عَلَى النَّعْتِ الْمَكْرُوهِحَدَّثَنَا مَحْمُودُ بْنُ خَالِدٍ الدِّمَشْقِيُّ حَدَّثَنَا الْفِرْيَابِيُّ عَنْ الْأَوْزَاعِيِّ عَنْ الزُّهْرِيِّ عَنْ سَهْلِ بْنِ سَعْدٍ السَّاعِدِيِّ بِهَذَا الْخَبَرِ قَالَ فَكَانَ يُدْعَى يَعْنِي الْوَلَدَ لِأُمِّهِ حَدَّثَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ عِيَاضِ بْنِ عَبْدِ اللَّهِ الْفِهْرِيِّ وَغَيْرِهِ عَنْ ابْنِ شِهَابٍ عَنْ سَهْلِ بْنِ سَعْدٍ فِي هَذَا الْخَبَرِ قَالَ فَطَلَّقَهَا ثَلَاثَ تَطْلِيقَاتٍ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَنْفَذَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ مَا صُنِعَ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُنَّةٌ قَالَ سَهْلٌ حَضَرْتُ هَذَا عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَضَتْ السُّنَّةُ بَعْدُ فِي الْمُتَلَاعِنَيْنِ أَنْ يُفَرَّقَ بَيْنَهُمَا ثُمَّ لَا يَجْتَمِعَانِ أَبَدًا","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far Al Waraki], telah mengabarkan kepada kami [Ibrahim bin Sa'd], dari [Az Zuhri] dari [Sahl bin Sa'd] mengenai hadits dua orang yang saling melaknat, ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Lihatlah dia, apabila ia melahirkan anak yang bermata hitam, berpantat besar, maka aku tidak melihat selain ia (suaminya) telah jujur, dan apabila ia melahirkan anak yang berwarna kemerahan seperti wabarah (hewan sejenis tokek) maka aku tidak melihat selain ia telah berdusta.\" Sahl bin Sa'd berkata; kemudian wanita tersebut melahirkan dengan cirri yang tidak disenangi. Telah menceritakan kepada kami [Mahmud bin Khalid Ad Dimasyqi], telah menceritakan kepada kami [Al Firyabi] dari [Al Auza'i] dari [Az Zuhri] dari [Sahl bin Sa'd As Sa'idi] dengan hadits ini. Ia berkata; maka anak tersebut dipanggil anak ibunya. Telah menceritakan kepada kami [Ahmad bin 'Amr bin As Sarh], telah menceritakan kepada kami [Ibnu Wahb] dari ['Iyadh bin Abdullah Al Fihri] dan yang lainnya, dari [Ibnu Syihab] dari [Sahl bin Sa'd] dalam hadits ini. Ia berkata; kemudian ia mencerainya tiga kali di sisi Rasulullah shallallahu 'alaihi wasallam. Dan Rasulullah shallallahu 'alaihi wasallam menjalankannya, dan apa yang dilakukan di sisi Nabi shallallahu 'alaihi wasallam adalah sunah. Sahl berkata; aku menyaksikan hal ini di sisi Rasulullah shallallahu 'alaihi wasallam sehingga berlangsunglah sunah setelah itu mengenai orang yang saling melaknat dengan dipisahkannya diantara mereka berdua, kemudian mereka tidak akan tidak berkumpul selamanya. "},"1854":{"ar":"حَدَّثَنَا مُسَدَّدٌ وَوَهْبُ بْنُ بَيَانٍ وَأَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ وَعَمْرُو بْنُ عُثْمَانَ قَالُوا حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ سَهْلِ بْنِ سَعْدٍ قَالَ مُسَدَّدٌ قَالَشَهِدْتُ الْمُتَلَاعِنَيْنِ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا ابْنُ خَمْسَ عَشْرَةَ فَفَرَّقَ بَيْنَهُمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ تَلَاعَنَا وَتَمَّ حَدِيثُ مُسَدَّدٍ وَقَالَ الْآخَرُونَ إِنَّهُ شَهِدَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَّقَ بَيْنَ الْمُتَلَاعِنَيْنِ فَقَالَ الرَّجُلُ كَذَبْتُ عَلَيْهَا يَا رَسُولَ اللَّهِ إِنْ أَمْسَكْتُهَا لَمْ يَقُلْ بَعْضُهُمْ عَلَيْهَاقَالَ أَبُو دَاوُد لَمْ يُتَابِعْ ابْنَ عُيَيْنَةَ أَحَدٌ عَلَى أَنَّهُ فَرَّقَ بَيْنَ الْمُتَلَاعِنَيْنِ حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ الْعَتَكِيُّ حَدَّثَنَا فُلَيْحٌ عَنْ الزُّهْرِيِّ عَنْ سَهْلِ بْنِ سَعْدٍ فِي هَذَا الْحَدِيثِ وَكَانَتْ حَامِلًا فَأَنْكَرَ حَمْلَهَا فَكَانَ ابْنُهَا يُدْعَى إِلَيْهَا ثُمَّ جَرَتْ السُّنَّةُ فِي الْمِيرَاثِ أَنْ يَرِثَهَا وَتَرِثَ مِنْهُ مَا فَرَضَ اللَّهُ عَزَّ وَجَلَّ لَهَا","id":"Telah menceritakan kepada kami [Musaddad], [Wahb bin Bayan], dan [Ahmad bin 'Amr bin As Sarh], serta ['Amr bin Utsman], mereka berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Sahl bin Sa'd], ia berkata; Musaddad berkata; aku menyaksikan dua orang yang saling melaknat pada zaman Rasulullah shallallahu 'alaihi wasallam sementara aku adalah orang yang berumur lima belas. Kemudian Rasulullah shallallahu 'alaihi wasallam memisahkan diantara mereka berdua ketika mereka saling melaknat. Dan selesailah hadits Musaddad, sementara yang lain mengatakan; sesungguhnya ia menyaksikan Nabi shallallahu 'alaihi wasallam memisahkan antara kedua orang yang saling melaknat, kemudian orang laki-laki yang saling melakukan laknat berkata; saya berdusta terhadapnya wahai Rasulullah, apabila saya menahannya. Dan sebagian mereka tidak mengatakan; terhadapnya. Abu Daud berkata; tidak ada seorang pun yang menyetujui Ibnu 'Uyainah bahwa beliau memisahkan antara kedua orang yang saling melaknat. Telah menceritakan kepada kami [Sulaiman bin Daud Al 'Ataki], telah menceritakan kepada kami [Fulaih] dari [Az Zuhri] dari [Sahl bin Sa'd] dalam hadits ini; dan wanita tersebut telah hamil, kemudian suaminya mengingkari janin yang ia kandung, dan anak wanita tersebut dinisbatkan kepadanya. Kemudian berlakulah sunah dalam hal warisan, bahwa anak tersebut mewarisinya dan wanita tersebut mewarisi anak itu sesuai yang telah Allah 'azza wajalla tetapkan. "},"1855":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَإِنَّا لَلَيْلَةُ جُمُعَةٍ فِي الْمَسْجِدِ إِذْ دَخَلَ رَجُلٌ مِنْ الْأَنْصَارِ فِي الْمَسْجِدِ فَقَالَ لَوْ أَنَّ رَجُلًا وَجَدَ مَعَ امْرَأَتِهِ رَجُلًا فَتَكَلَّمَ بِهِ جَلَدْتُمُوهُ أَوْ قَتَلَ قَتَلْتُمُوهُ فَإِنْ سَكَتَ سَكَتَ عَلَى غَيْظٍ وَاللَّهِ لَأَسْأَلَنَّ عَنْهُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا كَانَ مِنْ الْغَدِ أَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَهُ فَقَالَ لَوْ أَنَّ رَجُلًا وَجَدَ مَعَ امْرَأَتِهِ رَجُلًا فَتَكَلَّمَ بِهِ جَلَدْتُمُوهُ أَوْ قَتَلَ قَتَلْتُمُوهُ أَوْ سَكَتَ سَكَتَ عَلَى غَيْظٍ فَقَالَ اللَّهُمَّ افْتَحْ وَجَعَلَ يَدْعُو فَنَزَلَتْ آيَةُ اللِّعَانِ{ وَالَّذِينَ يَرْمُونَ أَزْوَاجَهُمْ وَلَمْ يَكُنْ لَهُمْ شُهَدَاءُ إِلَّا أَنْفُسُهُمْ }هَذِهِ الْآيَةَ فَابْتُلِيَ بِهِ ذَلِكَ الرَّجُلُ مِنْ بَيْنِ النَّاسِ فَجَاءَ هُوَ وَامْرَأَتُهُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَلَاعَنَا فَشَهِدَ الرَّجُلُ أَرْبَعَ شَهَادَاتٍ بِاللَّهِ إِنَّهُ لَمِنْ الصَّادِقِينَ ثُمَّ لَعَنَ الْخَامِسَةَ عَلَيْهِ إِنْ كَانَ مِنْ الْكَاذِبِينَ قَالَ فَذَهَبَتْ لِتَلْتَعِنَ فَقَالَ لَهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَهْ فَأَبَتْ فَفَعَلَتْ فَلَمَّا أَدْبَرَا قَالَ لَعَلَّهَا أَنْ تَجِيءَ بِهِ أَسْوَدَ جَعْدًا فَجَاءَتْ بِهِ أَسْوَدَ جَعْدًا","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah], telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Ibrahim] dari ['Al Qamah] dari [Abdullah bin Mas'ud], ia berkata; pernah pada suatu malam Jum'at kami berada di masjid, tiba-tiba terdapat seorang laki-laki anshar yang memasuki masjid dan berkata; seandainya seorang laki-laki mendapati laki-laki lain bersama isterinya kemudian ia membicarakannya hingga kalian mencambuknya atau ia membunuh laki-laki tersebut hingga kalian membunuhnya. Apabila ia diam maka ia diam dalam keadaan marah. Demi Allah, aku akan tanyakan hal tersebut kepada Rasulullah shallallahu wa'alaihi wa sallam. Kemudian setelah keesokan harinya ia datang kepada Rasulullah shallallahu 'alaihi wasallam dan bertanya kepadanya. Ia berkata; seandainya seorang laki-laki mendapati laki-laki lain bersama isterinya kemudian ia membicarakannya hingga kalian mencambuknya atau ia membunuh laki-laki tersebut hingga kalian membunuhnya. Kemudian beliau berdoa: \"Ya Allah, bukakanlah!\" kemudian turunlah ayat li'an: \"Dan orang-orang yang menuduh isterinya (berzina), padahal mereka tidak ada mempunyai saksi-saksi selain diri mereka sendiri.\" Kemudian laki-laki tersebut diuji di antara orang-orang. Kemudian ia datang bersama isterinya kepada Rasulullah shallallahu 'alaihi wasallam, lalu mereka saling melaknat. Laki-laki tersebut bersumpah empat kali sumpah dengan nama Allah bahwa ia termasuk diantara orang-orang yang jujur, kemudian pada sumpah yang kelima ia melaknat dirinya apabila ia termasuk diantara orang-orang yang berdusta. Ia berkata; kemudian wanita tersebut pergi untuk melakukan laknat, lalu Nabi shallallahu 'alaihi wasallam berkata kepadanya: \"Tahanlah!\" Namun wanita tersebut enggan untuk menahan diri, maka ia pun melakukan laknat. Kemudian tatkala mereka pergi beliau berkata: \"Kemungkinan wanita tersebut akan melahirkan anak yang hitam dan berambut keriting.\" Kemudian wanita tersebut ternyata melahirkan anak yang hitam dan berambut keriting. "},"1856":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ أَخْبَرَنَا هِشَامُ بْنُ حَسَّانَ حَدَّثَنِي عِكْرِمَةُ عَنْ ابْنِ عَبَّاسٍأَنَّ هِلَالَ بْنَ أُمَيَّةَ قَذَفَ امْرَأَتَهُ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِشَرِيكِ ابْنِ سَحْمَاءَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْبَيِّنَةُ أَوْ حَدٌّ فِي ظَهْرِكَ قَالَ يَا رَسُولَ اللَّهِ إِذَا رَأَى أَحَدُنَا رَجُلًا عَلَى امْرَأَتِهِ يَلْتَمِسُ الْبَيِّنَةَ فَجَعَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْبَيِّنَةُ وَإِلَّا فَحَدٌّ فِي ظَهْرِكَ فَقَالَ هِلَالٌ وَالَّذِي بَعَثَكَ بِالْحَقِّ نَبِيًّا إِنِّي لَصَادِقٌ وَلَيُنْزِلَنَّ اللَّهُ فِي أَمْرِي مَا يُبْرِئُ بِهِ ظَهْرِي مِنْ الْحَدِّ فَنَزَلَتْ{ وَالَّذِينَ يَرْمُونَ أَزْوَاجَهُمْ وَلَمْ يَكُنْ لَهُمْ شُهَدَاءُ إِلَّا أَنْفُسُهُمْ فَقَرَأَ حَتَّى بَلَغَ مِنْ الصَّادِقِينَ }فَانْصَرَفَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَرْسَلَ إِلَيْهِمَا فَجَاءَا فَقَامَ هِلَالُ بْنُ أُمَيَّةَ فَشَهِدَ وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اللَّهُ يَعْلَمُ أَنَّ أَحَدَكُمَا كَاذِبٌ فَهَلْ مِنْكُمَا مِنْ تَائِبٍ ثُمَّ قَامَتْ فَشَهِدَتْ فَلَمَّا كَانَ عِنْدَ الْخَامِسَةِ أَنَّ غَضَبَ اللَّهِ عَلَيْهَا إِنْ كَانَ مِنْ الصَّادِقِينَ وَقَالُوا لَهَا إِنَّهَا مُوجِبَةٌ قَالَ ابْنُ عَبَّاسٍ فَتَلَكَّأَتْ وَنَكَصَتْ حَتَّى ظَنَنَّا أَنَّهَا سَتَرْجِعُ فَقَالَتْ لَا أَفْضَحُ قَوْمِي سَائِرَ الْيَوْمِ فَمَضَتْ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبْصِرُوهَا فَإِنْ جَاءَتْ بِهِ أَكْحَلَ الْعَيْنَيْنِ سَابِغَ الْأَلْيَتَيْنِ خَدَلَّجَ السَّاقَيْنِ فَهُوَ لِشَرِيكِ ابْنِ سَحْمَاءَ فَجَاءَتْ بِهِ كَذَلِكَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْلَا مَا مَضَى مِنْ كِتَابِ اللَّهِ لَكَانَ لِي وَلَهَا شَأْنٌقَالَ أَبُو دَاوُد وَهَذَا مِمَّا تَفَرَّدَ بِهِ أَهْلُ الْمَدِينَةِ حَدِيثُ ابْنِ بَشَّارٍ حَدِيثُ هِلَالٍ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar], telah menceritakan kepada kami [Ibnu Abu Adi], telah mengabarkan kepada kami [Hisyam bin Hassan], telah menceritakan kepadaku [Ikrimah] dari [Ibnu Abbas] bahwa Hilal bin Umayyah menuduh isterinya berzina di hadapan Rasulullah shallallahu 'alaihi wasallam dengan Syarik bin Sahma`. Kemudian Nabi shallallahu 'alaihi wasallam berkata: \"Datangkan bukti atau engkau dicambuk punggungmu.\" Ia berkata; wahai Rasulullah, apabila salah seorang diantara kami melihat seseorang berada di atas isterinya apakah ia harus mencara bukti? Kemudian Nabi shallallahu 'alaihi wasallam berkata: \"Datangkan bukti atau engkau dicambuk punggungmu.\" Kemudian Hilal berkata; demi Dzat yang mengutusmu dengan kebenaran sebagai nabi, sungguh aku adalah orang yang jujur, dan sungguh dalam perkaraku ini Allah akan menurunkan menurunkan apa yang akan membebaskan punggungku dari hukuman. Kemudian turunlah ayat: \"Dan orang-orang yang menuduh isterinya (berzina), padahal mereka tidak ada mempunyai saksi-saksi selain diri mereka sendiri……\" kemudian beliau membacanya hingga sampat pada kata: \"……. termasuk diantara orang-orang yang benar.\" Kemudian Rasulullah shallallahu 'alaihi wasallam pergi lalu mengirimkan utusan kepda mereka berdua. Kemudin mereka datang, lalu Hilal bin Umayyah bersumpah sementara Nabi shallallahu 'alaihi wasallam bersabda: \"Allah mengetahui bahwa salah seorang diantara kalian berdusta.\" Apakah diantara kalian ada yang ingin bertaubat? Kemudian wanita tersebut berdiri dan bersumpah, kemudian tatkala telah sampai pada sumpah yang kelima; bahwa kemurkaan Allah tertimpa atasnya apabila suaminya termasuk orang-orang yang benar. Mereka berkata kepada wanita tersebut; sesungguh sumpah tersebut mengharuskan terjadinya li'an dan pemisahan antara kalian berdua. Kemudian wanita tersebut merasa ragu dan berhenti hingga kami kami menyangka bahwa ia akan mundur. Kemudian ia berkata; aku tidak akan mempermalukan kaumku sepanjang hari. Lalu ia pun melanjutkan li'annya. Kemudian Nabi shallallahu 'alaihi wasallam berkata: \"Lihatlah kepadanya, apabila ia melahirkan anak yang berwarna hitam, berpantat besar berisi dan betisnya besar dan berisi maka ia adalah milik Syarik bin Sahma`.\" Kemudian wanita tersebut melahirkan anak seperti itu. Nabi shallallahu 'alaihi wasallam bersabda: \"Seandainya tidak ada keputusan dari kitab Allah, niscaya aku dan dia memiliki urusan.\" Abu Daud berkata; hal ini adalah diantara yang hanya diriwayatkan oleh penduduk Madinah, Hadits Ibnu Basysyar adalah hadits Hilal. "},"1857":{"ar":"حَدَّثَنَا مَخْلَدُ بْنُ خَالِدٍ الشُّعَيْرِيُّ حَدَّثَنَا سُفْيَانُ عَنْ عَاصِمِ بْنِ كُلَيْبٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ رَجُلًا حِينَ أَمَرَ الْمُتَلَاعِنَيْنِ أَنْ يَتَلَاعَنَا أَنْ يَضَعَ يَدَهُ عَلَى فِيهِ عِنْدَ الْخَامِسَةِ يَقُولُ إِنَّهَا مُوجِبَةٌ","id":"Telah menceritakan kepada kami [Makhlad bin Khalid Asy Syu'airi], telah menceritakan kepada kami [Sufyan], dari ['Ashim bin Kulaib] dari [ayahnya] dari [Ibnu Abbas] bahwa Nabi shallallahu 'alaihi wasallam memerintahkan seorang laki-laki ketika beliau memerintahkan dua orang yang saling melaknat agar orang tersebut meletakkan tangannya pada mulutnya pada saat sumpah yang kelima. Beliau berkata: sesungguhnya sumpah tersebut mewajibkan laknat dan pemisahan antara mereka berdua. "},"1858":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا عَبَّادُ بْنُ مَنْصُورٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَجَاءَ هِلَالُ بْنُ أُمَيَّةَ وَهُوَ أَحَدُ الثَّلَاثَةِ الَّذِينَ تَابَ اللَّهُ عَلَيْهِمْ فَجَاءَ مِنْ أَرْضِهِ عَشِيًّا فَوَجَدَ عِنْدَ أَهْلِهِ رَجُلًا فَرَأَى بِعَيْنِهِ وَسَمِعَ بِأُذُنِهِ فَلَمْ يَهِجْهُ حَتَّى أَصْبَحَ ثُمَّ غَدَا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي جِئْتُ أَهْلِي عِشَاءً فَوَجَدْتُ عِنْدَهُمْ رَجُلًا فَرَأَيْتُ بِعَيْنَيَّ وَسَمِعْتُ بِأُذُنَيَّ فَكَرِهَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا جَاءَ بِهِ وَاشْتَدَّ عَلَيْهِ فَنَزَلَتْ{ وَالَّذِينَ يَرْمُونَ أَزْوَاجَهُمْ وَلَمْ يَكُنْ لَهُمْ شُهَدَاءُ إِلَّا أَنْفُسُهُمْ فَشَهَادَةُ أَحَدِهِمْ }الْآيَتَيْنِ كِلْتَيْهِمَا فَسُرِّيَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَبْشِرْ يَا هِلَالُ قَدْ جَعَلَ اللَّهُ عَزَّ وَجَلَّ لَكَ فَرَجًا وَمَخْرَجًا قَالَ هِلَالٌ قَدْ كُنْتُ أَرْجُو ذَلِكَ مِنْ رَبِّي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْسِلُوا إِلَيْهَا فَجَاءَتْ فَتَلَاهَا عَلَيْهِمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَذَكَّرَهُمَا وَأَخْبَرَهُمَا أَنَّ عَذَابَ الْآخِرَةِ أَشَدُّ مِنْ عَذَابِ الدُّنْيَا فَقَالَ هِلَالٌ وَاللَّهِ لَقَدْ صَدَقْتُ عَلَيْهَا فَقَالَتْ قَدْ كَذَبَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَاعِنُوا بَيْنَهُمَا فَقِيلَ لِهِلَالٍ اشْهَدْ فَشَهِدَ أَرْبَعَ شَهَادَاتٍ بِاللَّهِ إِنَّهُ لَمِنْ الصَّادِقِينَ فَلَمَّا كَانَتْ الْخَامِسَةُ قِيلَ لَهُ يَا هِلَالُ اتَّقِ اللَّهَ فَإِنَّ عَذَابَ الدُّنْيَا أَهْوَنُ مِنْ عَذَابِ الْآخِرَةِ وَإِنَّ هَذِهِ الْمُوجِبَةُ الَّتِي تُوجِبُ عَلَيْكَ الْعَذَابَ فَقَالَ وَاللَّهِ لَا يُعَذِّبُنِي اللَّهُ عَلَيْهَا كَمَا لَمْ يُجَلِّدْنِي عَلَيْهَا فَشَهِدَ الْخَامِسَةَ أَنَّ لَعْنَةَ اللَّهِ عَلَيْهِ إِنْ كَانَ مِنْ الْكَاذِبِينَ ثُمَّ قِيلَ لَهَا اشْهَدِي فَشَهِدَتْ أَرْبَعَ شَهَادَاتٍ بِاللَّهِ إِنَّهُ لَمِنْ الْكَاذِبِينَ فَلَمَّا كَانَتْ الْخَامِسَةُ قِيلَ لَهَا اتَّقِي اللَّهَ فَإِنَّ عَذَابَ الدُّنْيَا أَهْوَنُ مِنْ عَذَابِ الْآخِرَةِ وَإِنَّ هَذِهِ الْمُوجِبَةُ الَّتِي تُوجِبُ عَلَيْكِ الْعَذَابَ فَتَلَكَّأَتْ سَاعَةً ثُمَّ قَالَتْ وَاللَّهِ لَا أَفْضَحُ قَوْمِي فَشَهِدَتْ الْخَامِسَةَ أَنَّ غَضَبَ اللَّهِ عَلَيْهَا إِنْ كَانَ مِنْ الصَّادِقِينَ فَفَرَّقَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَهُمَا وَقَضَى أَنْ لَا يُدْعَى وَلَدُهَا لِأَبٍ وَلَا تُرْمَى وَلَا يُرْمَى وَلَدُهَا وَمَنْ رَمَاهَا أَوْ رَمَى وَلَدَهَا فَعَلَيْهِ الْحَدُّ وَقَضَى أَنْ لَا بَيْتَ لَهَا عَلَيْهِ وَلَا قُوتَ مِنْ أَجْلِ أَنَّهُمَا يَتَفَرَّقَانِ مِنْ غَيْرِ طَلَاقٍ وَلَا مُتَوَفَّى عَنْهَا وَقَالَ إِنْ جَاءَتْ بِهِ أُصَيْهِبَ أُرَيْصِحَ أُثُيْبِجَ حَمْشَ السَّاقَيْنِ فَهُوَ لِهِلَالٍ وَإِنْ جَاءَتْ بِهِ أَوْرَقَ جَعْدًا جُمَالِيًّا خَدَلَّجَ السَّاقَيْنِ سَابِغَ الْأَلْيَتَيْنِ فَهُوَ لِلَّذِي رُمِيَتْ بِهِ فَجَاءَتْ بِهِ أَوْرَقَ جَعْدًا جَمَالِيًّا خَدَلَّجَ السَّاقَيْنِ سَابِغَ الْأَلْيَتَيْنِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْلَا الْأَيْمَانُ لَكَانَ لِي وَلَهَا شَأْنٌقَالَ عِكْرِمَةُ فَكَانَ بَعْدَ ذَلِكَ أَمِيرًا عَلَى مُضَرَ وَمَا يُدْعَى لِأَبٍ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali], telah menceritakan kepada kami [Yazid bin Harun], telah menceritakan kepada kami ['Abbad bin Manshur] dari [Ikrimah] dari [Ibnu Abbas], ia berkata; Hilal bin Umayyah yang merupakan salah satu dari tiga orang yang Allah terima taubat mereka telah datang dari lahan yang ia miliki pada sore hari, kemudian ia mendapati seorang laki-laki bersama isterinya dan ia melihatnya dengan kedua matanya serta mendengar dengan telinganya dan tidak mengganggu serta menperingatkannya hingga pagi hari. Kemudian ia pergi kepada Rasulullah shallallahu 'alaihi wasallam dan berkata; wahai Rasulullah, sungguh saya telah datang kepada isteriku pada sore hari dan saya dapati seorang laki-laki bersamanya. Saya melihat dengan kedua mataku, dan mendengar dengan kedua telingaku. Lalu Rasulullah shallallahu 'alaihi wasallam tidak menyukai apa yang ia bawa dan terasa berat baginya. Kemudian turunlah ayat: \"Dan orang-orang yang menuduh isterinya (berzina), padahal mereka tidak ada mempunyai saksi-saksi selain diri mereka sendiri, maka persaksian orang…….\" Kemudian beliau merasakan keringanan dan berkata; bergembiralah wahai Abu Hilal, sungguh Allah 'azza wajalla telah memberikan kelapangan dan jalan keluar kepadamu. Hilal berkata; aku telah mengharapkan hal tersebut dari Tuhanku. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kirimkan utusan kepada wanita tersebut!\" kemudian wanita tersebut datang dan beliau membacakan ayat tersebut kepada mereka berdua dan mengingatkan serta mengabarkan kepada merekabahwa adzab akhirat lebih keras daripada adzab dunia. Kemudian Hilal berkata; demi Allah, sungguh aku berkata benar terhadapnya. Kemudian wanita tersebut berkata; sungguh ia telah berdusta. Maka Rasulullah shallallahu 'alaihi wasallam berkata: \"Putuskanlah diantara mereka berdua!\" kemudian dikatakan kepada Hilal; bersumpahlah! Maka ia bersumpah empat kali dengan nama Allah bahwa ia adalah termasuk diantara orang-orang yang benar. Kemudian tatkala pada sumpah kelima dikatakan kepadanya; wahai Bilal, bertakwalah kepada Allah, sesungguhnya adzab dunia lebih ringan dari pada adzab akhirat. Dan sumpah ini adalah sesuatu yang dapat menyebabkanmu mendapatkan adzab. Kemudian ia berkata; demi Allah, Allah tidak akan mengadzabku karenanya, sebagaimana beliau tidak akan mencambukku karenanya. Kemudian ia bersumpah yang kelima; bahwa laknat Allah atasnya apabila ia termasuk diantara orang-orang yang berdusta. Kemudian dikatakan kepada wanita tersebut; bersumpahlah; sesungguhnya ia termasuk diantara orang-orang yang berdusta. Kemudian tatkala pada sumpah yang kelima dikatakan kepadanya; bertakwalah kepada Allah, sesungguhnya adzab dunia lebih ringan daripada adzab akhirat, dan laknat ini adalah sesuatu yang dapat menyebabkanmu mendapatkan adzab. Kemudian wanita tersebut merasa ragu sesaat, kemudian berkata; demi Allah, aku tidak akan mempermalukan kaumku. Lalu ia pun bersumpah ke lima kali; bahwa kemurkaan Allah akan tertimpa atasnya apabila suaminya termasuk diantara orang-orang yang benar. Kemudian Rasulullah shallallahu 'alaihi wasallam memisahkan antara mereka berdua, beliau memutuskan anaknya tidaklah dipanggil anak ayahnya, dan wanita tersebut tidak boleh dituduh berzina, anaknya tidak boleh dituduh sebagai anak zina. Barangsiapa yang menuduhnya maka ia mendapatkan hukuman. Dan beliau memutuskan bahwa suami yang mantan suami tidak wajib untuk memberikan rumah serta makan bagi mantan isterinya, karena keduanya berpisah bukan karena perceraian, dan bukan karena sang suami meninggal dunia. Apabila ia melahirkan anak berwarna pirang, antara kedua pundak serta pertengahan punggung berisi, betisnya kecil, maka ia adalah milik Hilal, dan apabila ia melahirkan anak yang berkulit coklat sawo matang, berambut keriting, anggota badannya besar, betis besar dan berisi, pantat besar berisi maka ia adalah milik orang yang dituduh berbuat zina dengannya. Kemudian wanita tersebut melahirkan anak yang berkulit coklat sawo matang, berambut keriting, anggota badannya besar, betis besar dan berisi, pantat besar berisi. Rasulullah shallallahu 'alaihi wasallam berkata: \"Seandainya tidak ada sumpah niscaya aku dan dia memiliki urusan.\" Ikrimah berkata; kemudian setelah itu anak tersebut menjadi pemimpin Mudhar dan tidak dipanggil dengan menisbatkan kepada ayahnya. "},"1859":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ قَالَ سَمِعَ عَمْرٌو سَعِيدَ بْنَ جُبَيْرٍ يَقُولُ سَمِعْتُ ابْنَ عُمَرَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلْمُتَلَاعِنَيْنِ حِسَابُكُمَا عَلَى اللَّهِ أَحَدُكُمَا كَاذِبٌ لَا سَبِيلَ لَكَ عَلَيْهَا قَالَ يَا رَسُولَ اللَّهِ مَالِي قَالَ لَا مَالَ لَكَ إِنْ كُنْتَ صَدَقْتَ عَلَيْهَا فَهُوَ بِمَا اسْتَحْلَلْتَ مِنْ فَرْجِهَا وَإِنْ كُنْتَ كَذَبْتَ عَلَيْهَا فَذَلِكَ أَبْعَدُ لَكَ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal], telah menceritakan kepada kami [Sufyan bin 'Uyainah], ia berkata; saya mendengar ['Amr] dan [Sa'id bin Jubair] berkata; saya mendengar [Ibnu Umar] berkata; Rasulullah shallallahu 'alaihi wasallam berkata kepada kedua orang yang saling melaknat: \"Hisab kalian ada pada Allah, salah seorang diantara kalian berdusta. Engkau tidak memiliki kekuasaan atas dirinya.\" Laki-laki tersebut berkata; wahai Rasulullah, hartaku. Beliau berkata: \"Tidak ada harta yang menjadi hakmu, apabila engkau telah memberikan mahar kepadanya maka harta tersebut adalah sebagai ganti farji yang kalian halalkan, dan apabila engkau berdusta terhadapnya maka hal tersebut lebih jauh lagi bagimu.\""},"1860":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ حَنْبَلٍ حَدَّثَنَا إِسْمَعِيلُ حَدَّثَنَا أَيُّوبُ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَقُلْتُ لِابْنِ عُمَرَ رَجُلٌ قَذَفَ امْرَأَتَهُ قَالَ فَرَّقَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ أَخَوَيْ بَنِي الْعَجْلَانِ وَقَالَ اللَّهُ يَعْلَمُ أَنَّ أَحَدَكُمَا كَاذِبٌ فَهَلْ مِنْكُمَا تَائِبٌ يُرَدِّدُهَا ثَلَاثَ مَرَّاتٍ فَأَبَيَا فَفَرَّقَ بَيْنَهُمَا","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad bin Hanbal], telah menceritakan kepada kami [Isma'il], telah menceritakan kepada kami [Ayyub] dari [Sa'id bin Jubair], ia berkata; aku katakan kepada [Ibnu Abbas]; ada seorang laki-laki yang menuduh isterinya berbuat zina. Ia berkata; Rasulullah shallallahu 'alaihi wasallam telah memisahkan antara kedua saudara Bani Al 'Ajlan, dan beliau berkata; \"Allah mengetahui bahwa salah seorang diantara kalian berdua adalah berdusta. Apa ada diantara kalian yang hendak bertaubat?\" Beliau mengulangnya sebanyak tiga kali, namun mereka enggan untuk bertaubat, maka beliau memisahkan antara keduanya. "},"1861":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَجُلًا لَاعَنَ امْرَأَتَهُ فِي زَمَانِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَانْتَفَى مِنْ وَلَدِهَا فَفَرَّقَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَهُمَا وَأَلْحَقَ الْوَلَدَ بِالْمَرْأَةِقَالَ أَبُو دَاوُد الَّذِي تَفَرَّدَ بِهِ مَالِكٌ قَوْلُهُ وَأَلْحَقَ الْوَلَدَ بِالْمَرْأَةِ و قَالَ يُونُسُ عَنْ الزُّهْرِيِّ عَنْ سَهْلِ بْنِ سَعْدٍ فِي حَدِيثِ اللِّعَانِ وَأَنْكَرَ حَمْلَهَا فَكَانَ ابْنُهَا يُدْعَى إِلَيْهَا","id":"Telah menceritakan kepada kami [Al Qa'nabi], dari [Malik], dari [Nafi'] dari [Ibnu Umar] bahwa seorang laki-laki telah meli'an isterinya pada zaman Rasulullah shallallahu 'alaihi wasallam dan ia mengingkari anak isterinya tersebut sebagai anaknya, kemudian Rasulullah shallallahu 'alaihi wasallam memisahkan antara keduanya dan menisbatkan anak tersebut kepada isterinya. Abu Daud berkata; yang hanya diriwayatkan oleh Malik adalah ucapannya; dan menisbatkan anak tersebut kepada isterinya. [Yunus] berkata, dari [Az Zuhri], dari [Sahl bin Sa'd] dalam hadits li'an; dan ia mengingkari anak yang dikandungnya, dan anak wanita tersebut dinisbatkan kepadanya. "},"1862":{"ar":"حَدَّثَنَا ابْنُ أَبِي خَلَفٍ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ سَعِيدٍ عَنْ أَبِي هُرَيْرَةَ قَالَجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ بَنِي فَزَارَةَ فَقَالَ إِنَّ امْرَأَتِي جَاءَتْ بِوَلَدٍ أَسْوَدَ فَقَالَ هَلْ لَكَ مِنْ إِبِلٍ قَالَ نَعَمْ قَالَ مَا أَلْوَانُهَا قَالَ حُمْرٌ قَالَ فَهَلْ فِيهَا مِنْ أَوْرَقَ قَالَ إِنَّ فِيهَا لَوُرْقًا قَالَ فَأَنَّى تُرَاهُ قَالَ عَسَى أَنْ يَكُونَ نَزَعَهُ عِرْقٌ قَالَ وَهَذَا عَسَى أَنْ يَكُونَ نَزَعَهُ عِرْقٌحَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ بِإِسْنَادِهِ وَمَعْنَاهُ وَهُوَ حِينَئِذٍ يُعَرِّضُ بِأَنْ يَنْفِيَهُ حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ أَنَّ أَعْرَابِيًّا أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ امْرَأَتِي وَلَدَتْ غُلَامًا أَسْوَدَ وَإِنِّي أُنْكِرُهُ فَذَكَرَ مَعْنَاهُ","id":"Telah menceritakan kepada kami [Ibnu Abu Khalaf], telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Sa'id] dari [Abu Hurairah], ia berkata; seorang laki-laki dari Bani Fazarah datang kepada Nabi shallallahu 'alaihi wasallam dan berkata; sesungguhnya isteriku melahirkan anak yang berkulit hitam. Kemudian beliau berkata: \"Apakah engkau memiliki unta?\" Ia berkata; ya. Beliau berkata: \"Apa warnanya?\" Ia berkata; merah. Beliau berkata: \"Apakah ada diantara yang berwarna coklat sawo matang?\" ia berkata; diantaranya ada yang berwarna coklat sawo matang. Beliau berkata: \"Dari manakah menurutmu hal itu berasal?\" Ia berkata; kemungkinan kerena pengaruh keturunan. Beliau berkata: \"Dan anak ini kemungkinan ada pengaruh keturunan.\" Telah menceritakan kepada kami [Al Hasan bin Ali], telah menceritakan kepada kami [Abdurrazzaq], telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri], dengan sanad dan maknanya, dan pada saat itu menyindir untuk mengingkari anak tersebut. Telah menceritakan kepada kami [Ahmad bin Shalih], telah menceritakan kepada kami [Ibnu Wahb], telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dari [Abu Salamah], dari [Abu Hurairah] bahwa seorang badui datang kepada Nabi shallallahu 'alaihi wasallam dan berkata; sesungguhnya isteri saya telah melahirkan anak hitam, dan saya mengingkarinya. Kemudian ia menyebutkan maknanya. "},"1863":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي عَمْرٌو يَعْنِي ابْنَ الْحَارِثِ عَنْ ابْنِ الْهَادِ عَنْ عَبْدِ اللَّهِ بْنِ يُونُسَ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ حِينَ نَزَلَتْ آيَةُ الْمُتَلَاعِنَيْنِ أَيُّمَا امْرَأَةٍ أَدْخَلَتْ عَلَى قَوْمٍ مَنْ لَيْسَ مِنْهُمْ فَلَيْسَتْ مِنْ اللَّهِ فِي شَيْءٍ وَلَنْ يُدْخِلَهَا اللَّهُ جَنَّتَهُ وَأَيُّمَا رَجُلٍ جَحَدَ وَلَدَهُ وَهُوَ يَنْظُرُ إِلَيْهِ احْتَجَبَ اللَّهُ مِنْهُ وَفَضَحَهُ عَلَى رُءُوسِ الْأَوَّلِينَ وَالْآخِرِينَ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih], telah menceritakan kepada kami [Ibnu Wahb], telah mengabarkan kepadaku ['Amr bin Al Harits] dari [Ibnu Al Had] dari [Abdullah bin Yunus] dari [Sa'id Al Maburi] dari [Abu Hurairah] bahwa ia mendengar Rasulullah shallallahu 'alaihi wasallam ketika telah turun ayat mengenai li'an beliau bersabda: \"Bagi setiap wanita yang memasukkan kepada kaumnya seseorang yang bukan berasal dari mereka, maka ia bukan termasuk golongan Allah sama sekali, dan tidak akan Allah masukkan ke dalam Surga. Dan bagi setiap laki-laki yang mengingkari anaknya sementara ia mengetahui bahwa anak tersebut benar-benar anaknya, maka Allah menutup diri darinya, dan Allah akan mempermalukan dirinya di hadapan orang-orang terdahulu dan yang terakhir.\""},"1864":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا مُعْتَمِرٌ عَنْ سَلْمٍ يَعْنِي ابْنَ أَبِي الزَّيَّادِ حَدَّثَنِي بَعْضُ أَصْحَابِنَا عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ أَنَّهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا مُسَاعَاةَ فِي الْإِسْلَامِ مَنْ سَاعَى فِي الْجَاهِلِيَّةِ فَقَدْ لَحِقَ بِعَصَبَتِهِ وَمَنْ ادَّعَى وَلَدًا مِنْ غَيْرِ رِشْدَةٍ فَلَا يَرِثُ وَلَا يُورَثُ","id":"Telah menceritakan kepada kami [Ya'qub bin Ibrahim], telah menceritakan kepada kami [Mu'tamir] dari [Salm bin Abu Az Zinad], telah menceritakan kepadaku [sebagian sahabat kami], dari [Sa'id bin Jubair] dari [Ibnu Abbas], bahwa ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada perzinahan dalam Islam, barangsiapa yang melakukan zina pada masa jahiliyah maka sungguh ia telah menisbatkan anak yang terlahir kepada walinya, dan barangsiapa yang mengklaim seorang anak tanpa pernikahan yang benar, maka ia tidak mewarisi dan tidak diwarisi.\""},"1865":{"ar":"حَدَّثَنَا شَيْبَانُ بْنُ فَرُّوخَ حَدَّثَنَا مُحَمَّدُ بْنُ رَاشِدٍ ح و حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا مُحَمَّدُ بْنُ رَاشِدٍ وَهُوَ أَشْبَعُ عَنْ سُلَيْمَانَ بْنِ مُوسَى عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَإِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى أَنَّ كُلَّ مُسْتَلْحَقٍ اسْتُلْحِقَ بَعْدَ أَبِيهِ الَّذِي يُدْعَى لَهُ ادَّعَاهُ وَرَثَتُهُ فَقَضَى أَنَّ كُلَّ مَنْ كَانَ مِنْ أَمَةٍ يَمْلِكُهَا يَوْمَ أَصَابَهَا فَقَدْ لَحِقَ بِمَنْ اسْتَلْحَقَهُ وَلَيْسَ لَهُ مِمَّا قُسِمَ قَبْلَهُ مِنْ الْمِيرَاثِ شَيْءٌ وَمَا أَدْرَكَ مِنْ مِيرَاثٍ لَمْ يُقْسَمْ فَلَهُ نَصِيبُهُ وَلَا يَلْحَقُ إِذَا كَانَ أَبُوهُ الَّذِي يُدْعَى لَهُ أَنْكَرَهُ وَإِنْ كَانَ مِنْ أَمَةٍ لَمْ يَمْلِكْهَا أَوْ مِنْ حُرَّةٍ عَاهَرَ بِهَا فَإِنَّهُ لَا يَلْحَقُ بِهِ وَلَا يَرِثُ وَإِنْ كَانَ الَّذِي يُدْعَى لَهُ هُوَ ادَّعَاهُ فَهُوَ وَلَدُ زِنْيَةٍ مِنْ حُرَّةٍ كَانَ أَوْ أَمَةٍحَدَّثَنَا مَحْمُودُ بْنُ خَالِدٍ حَدَّثَنَا أَبِي عَنْ مُحَمَّدِ بْنِ رَاشِدٍ بِإِسْنَادِهِ وَمَعْنَاهُ زَادَ وَهُوَ وَلَدُ زِنَا لِأَهْلِ أُمِّهِ مَنْ كَانُوا حُرَّةً أَوْ أَمَةً وَذَلِكَ فِيمَا اسْتُلْحِقَ فِي أَوَّلِ الْإِسْلَامِ فَمَا اقْتُسِمَ مِنْ مَالٍ قَبْلَ الْإِسْلَامِ فَقَدْ مَضَى","id":"Telah menceritakan kepada kami [Syaiban bin Farrukh], telah menceritakan kepada kami [Muhammad bin Rasyid], dan telah diriwayatkan dari jalan yang jalur yang lain: Telah menceritakan kepada kami [Al Hasan bin Ali], telah menceritakan kepada kami [Yazid bin Harun], telah mengabarkan kepada kami Muhammad bin Rasyid ia adalah Asyba', dari [Sulaiman bin Musa] dari ['Amr bin Syu'aib] dari [ayahnya] dari [kakeknya], ia berkata; sesungguhnya Nabi shallallahu 'alaihi wasallam telah menetapkan bahwa setiap anak yang diklaim setelah kematian bapaknya yang diklaim oleh ahli warisnya maka beliau menetapkan bahwa setiap anak yang berasal dari seorang budak wanita yang ia miliki pada saat ia menggaulinya maka ia diikutkan bersama orang yang mengklaimnya, dan sebelum diikutkan bersama orang yang mengklaimnya ia tidak memiliki sedikitpun warisan yang telah dibagikan, dan warisan yang belum dibagikan maka ia mendapatkan bagian, dan ia tidak ikut bergabung (dengan ahli warisnya) apabila ayahnya yang kepadanya ia dinisbatkan mengingkarinya, dan apabila ia berasal dari seorang budak wanita yang tidak ia miliki atau dari wanita merdeka yang berzina dengannya maka anak tersebut tidak bergabung (dengan ahli warits), dan tidak mewarisi. Walaupun orang tersebut mengklaimnya namun anak tersebut merupakan hasil perzinahan dengan wanita merdeka atu seorang budak. Telah menceritakan kepada kami [Mahmud bin Khalid], telah menceritakan kepada kami [Ayahku] dari [Muhammad bin Rasyid] dengan sanad serta maknanya, dan ia menambahkan; dan ia adalah anak hasil perzinahan, ia untuk keluarga ibunya siapapun mereka, baik wanita merdeka atau budak wanita, dan hal tersebut mengenai anak yang diklaim pada awal Islam, maka harta yang dibagi sebelum Islam hal tersebut telah berlalu. "},"1866":{"ar":"حَدَّثَنَا مُسَدَّدٌ وَعُثْمَانُ بْنُ أَبِي شَيْبَةَ الْمَعْنَى وَابْنُ السَّرْحِ قَالُوا حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْدَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مُسَدَّدٌ وَابْنُ السَّرْحِ يَوْمًا مَسْرُورًا وَقَالَ عُثْمَانُ تُعْرَفُ أَسَارِيرُ وَجْهِهِ فَقَالَ أَيْ عَائِشَةُ أَلَمْ تَرَيْ أَنَّ مُجَزِّزًا الْمُدْلِجِيَّ رَأَى زَيْدًا وَأُسَامَةَ قَدْ غَطَّيَا رُءُوسَهُمَا بِقَطِيفَةٍ وَبَدَتْ أَقْدَامُهُمَا فَقَالَ إِنَّ هَذِهِ الْأَقْدَامَ بَعْضُهَا مِنْ بَعْضٍقَالَ أَبُو دَاوُد كَانَ أُسَامَةُ أَسْوَدَ وَكَانَ زَيْدٌ أَبْيَضَ حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ بِإِسْنَادِهِ وَمَعْنَاهُ قَالَ قَالَتْ دَخَلَ عَلَيَّ مَسْرُورًا تَبْرُقُ أَسَارِيرُ وَجْهِهِ قَالَ أَبُو دَاوُد وَأَسَارِيرُ وَجْهِهِ لَمْ يَحْفَظْهُ ابْنُ عُيَيْنَةَ قَالَ أَبُو دَاوُد أَسَارِيرُ وَجْهِهِ هُوَ تَدْلِيسٌ مِنْ ابْنِ عُيَيْنَةَ لَمْ يَسْمَعْهُ مِنْ الزُّهْرِيِّ إِنَّمَا سَمِعَ الْأَسَارِيرَ مِنْ غَيْرِهِ قَالَ وَالْأَسَارِيرُ فِي حَدِيثِ اللَّيْثِ وَغَيْرِهِ قَالَ أَبُو دَاوُد وَسَمِعْتُ أَحْمَدَ بْنَ صَالِحٍ يَقُولُ كَانَ أُسَامَةُ أَسْوَدَ شَدِيدَ السَّوَادِ مِثْلَ الْقَارِ وَكَانَ زَيْدٌ أَبْيَضَ مِثْلَ الْقُطْنِ","id":"Telah menceritakan kepada kami [Musaddad] serta [Utsman bin Abu Syaibah] secara makna, serta [Ibnu As Sarj], mereka berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari ['Urwah] dari [Aisyah], ia berkata; Rasulullah shallallahu 'alaihi wasallam menemuiku. Musaddad dan Ibnu As Sarh mengatakan; pada suatu hari dalam keadaan senang. Utsman berkata; diketahui keceriaan wajah beliau. Beliau berkata: \"Wahai Aisyah, tidakkah engkau melihat bahwa Muhazziz Al Mudliji melihat Zaid dan Usamah, mereka berdua telah menutup kepala mereka berdua menggunakan selimut, dan nampak telapak kaki mereka berdua.\" Kemudian Muhazziz berkata; sesungguhnya telapak kaki ini sebagiannya berasal dari sebagian yang lainnya. Abu Daud berkata; Usamah adalah orang yang berkulit hitam sedangkan Zaid adalah orang yang berkulit putih. Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Al Laits] dari [Ibnu Syihab] dengan sanad dan maknanya. Ia berkata; Aisyah berkata; beliau menemuiku dalam keadaan senang, rasa senang pada wajahnya bersinar. Abu Daud berkata; rasa senang pada wajahnya tidak dihafal oleh Ibnu 'Uyainah. Abu Daud berkata; kata rasa senang pada wajahnya adalah tadlis dari Ibnu 'Uyainah, ia tidak mendengarnya dari Az Zuhri, melainkan ia mendengar kata rasa senang dari selainnya. Ia berkata; dan kata rasa senang ada dalam hadits Al Laits dan yang lainnya. Abu Daud berkata; dan saya mendengar Ahmad bin Shalih berkata; Usamah adalah orang yang berkulit hitam seperti ter, sedangkan Zaid adalah orang yang putih seperti kapas. "},"1867":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ الْأَجْلَحِ عَنْ الشَّعْبِيِّ عَنْ عَبْدِ اللَّهِ بْنِ الْخَلِيلِ عَنْ زَيْدِ بْنِ أَرْقَمَ قَالَكُنْتُ جَالِسًا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَ رَجُلٌ مِنْ الْيَمَنِ فَقَالَ إِنَّ ثَلَاثَةَ نَفَرٍ مِنْ أَهْلِ الْيَمَنِ أَتَوْا عَلِيًّا يَخْتَصِمُونَ إِلَيْهِ فِي وَلَدٍ وَقَدْ وَقَعُوا عَلَى امْرَأَةٍ فِي طُهْرٍ وَاحِدٍ فَقَالَ لِاثْنَيْنِ مِنْهُمَا طِيبَا بِالْوَلَدِ لِهَذَا فَغَلَيَا ثُمَّ قَالَ لِاثْنَيْنِ طِيبَا بِالْوَلَدِ لِهَذَا فَغَلَيَا ثُمَّ قَالَ لِاثْنَيْنِ طِيبَا بِالْوَلَدِ لِهَذَا فَغَلَيَا فَقَالَ أَنْتُمْ شُرَكَاءُ مُتَشَاكِسُونَ إِنِّي مُقْرِعٌ بَيْنَكُمْ فَمَنْ قُرِعَ فَلَهُ الْوَلَدُ وَعَلَيْهِ لِصَاحِبَيْهِ ثُلُثَا الدِّيَةِ فَأَقْرَعَ بَيْنَهُمْ فَجَعَلَهُ لِمَنْ قُرِعَ فَضَحِكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى بَدَتْ أَضْرَاسُهُ أَوْ نَوَاجِذُهُ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Yahya] dari [Al Ajlah], dari [Asy Sya'bi] dari [Abdullah bin Al Khalil] dari [Zaid bin Arqam], ia berkata; aku pernah duduk bersama Nabi shallallahu 'alaihi wasallam kemudian terdapat seorang laki-laki dari Yaman yang masuk dan berkata; sesungguhnya terdapat tiga orang penduduk Yaman datang kepada Ali, mereka memperselisihkan kepada Ali mengenai anak yang dilahirkan oleh seorang wanita yang telah mereka gauli dalam satu masa suci. Kemudian Ali berkata kepada dua orang diantara mereka relakan anak itu untuk orang ini! Kemudian mereka berteriak, kemudian ia berkata; kepada dua orang; relakan anak tersebut untuk orang ini! Kemudian mereka berdua berteriak, kemudian ia berkata kepada dua orang; relakan anak tersebut untuk orang ini! Kemudian mereka berteriak. Lalu Ali berkata; kalian adalah sekutu yang saling berseteru, aku akan mengundi kalian. Barangsiapa yang keluar undiannya, maka anak tersebut adalah miliknya dan ia wajib membayar kepada kedua sahabatnya dua pertiga diyah. Kemudian Ali mengundi diantara mereka. Kemudian Rasulullah shallallahu 'alaihi wasallam tertawa hingga nampak gigi-gigi geraham beliau atau gigi-gigi seri beliau. "},"1868":{"ar":"حَدَّثَنَا خُشَيْشُ بْنُ أَصْرَمَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا الثَّوْرِيُّ عَنْ صَالِحٍ الْهَمْدَانِيِّ عَنْ الشَّعْبِيِّ عَنْ عَبْدِ خَيْرٍ عَنْ زَيْدِ بْنِ أَرْقَمَ قَالَأُتِيَ عَلِيٌّ رَضِيَ اللَّهُ عَنْهُ بِثَلَاثَةٍ وَهُوَ بِالْيَمَنِ وَقَعُوا عَلَى امْرَأَةٍ فِي طُهْرٍ وَاحِدٍ فَسَأَلَ اثْنَيْنِ أَتُقِرَّانِ لِهَذَا بِالْوَلَدِ قَالَا لَا حَتَّى سَأَلَهُمْ جَمِيعًا فَجَعَلَ كُلَّمَا سَأَلَ اثْنَيْنِ قَالَا لَا فَأَقْرَعَ بَيْنَهُمْ فَأَلْحَقَ الْوَلَدَ بِالَّذِي صَارَتْ عَلَيْهِ الْقُرْعَةُ وَجَعَلَ عَلَيْهِ ثُلُثَيْ الدِّيَةِ قَالَ فَذَكَرَ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَضَحِكَ حَتَّى بَدَتْ نَوَاجِذُهُحَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي حَدَّثَنَا شُعْبَةُ عَنْ سَلَمَةَ سَمِعَ الشَّعْبِيَّ عَنْ الْخَلِيلِ أَوْ ابْنِ الْخَلِيلِ قَالَ أُتِيَ عَلِيُّ بْنُ أَبِي طَالِبٍ رَضِيَ اللَّهُ عَنْهُ فِي امْرَأَةٍ وَلَدَتْ مِنْ ثَلَاثَةٍ نَحْوَهُ لَمْ يَذْكُرْ الْيَمَنَ وَلَا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَا قَوْلَهُ طِيبَا بِالْوَلَدِ","id":"Telah menceritakan kepada kami [Khusyaisy bin Ashram], telah menceritakan kepada kami [Abdurrazzaq], telah mengabarkan kepada kami [Ats Tsauri] dari [Shalih Al Hamdani] dari [Asy Sya'bi] dari [Abdu Khair] dari [Zaid bin Arqam], ia berkata; Ali radliallahu 'anhu dihadapkan kepadanya tiga orang pada saat ia berada di Yaman, mereka telah menggauli seorang wanita dalam satu masa suci. Kemudian Ali bertanya kepada dua orang; apakah engkau mengakui anak tersebut miliknya. Mereka berkata; tidak. Hingga Ali bertanya kepada mereka bersama, dan setiap kali ia bertanya kepada dua orang; apakah kalian mengakui anak tersebut untuknya? Mereka mengaatakan; tidak. Kemudian ia mengundi diantara mereka dan mengikutkan anak dengan orang yang keluar undiannya, dan membebankan kepadanya agar membayar dua pertiga diyah kepada kedua sahabatnya tersebut. Zaid bin Arqam berkata; kemudian hal tersebut diceritakan kepada Nabi shallallahu 'alaihi wasallam maka beliau tertawa hingga nampak gigi-gigi geraham beliau. Telah menceritakan kepada kami ['Ubaidullah bin Mu'adz], telah menceritakan kepada kami [ayahku], telah menceritakan kepada kami [Syu'bah] dari [Salamah], [Asy Sya'bi] mendengar dari [Al Khalil] atau dari Ibnu Al Khalil berkata; [Ali] radliallahu 'anhu dihadapkan pada permasalahan mengenai seorang wanita yang melahirkan dari tiga orang …. Seperti hadits tersebut, dan tidak menyebutkan Yaman, serta Nabi shallallahu 'alaihi wasallam serta perkataan beliau: \"Relakan anak tersebut!\""},"1869":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا عَنْبَسَةُ بْنُ خَالِدٍ حَدَّثَنِي يُونُسُ بْنُ يَزِيدَ قَالَ قَالَ مُحَمَّدُ بْنُ مُسْلِمِ بْنِ شِهَابٍ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبَرَتْهُأَنَّ النِّكَاحَ كَانَ فِي الْجَاهِلِيَّةِ عَلَى أَرْبَعَةِ أَنْحَاءٍ فَكَانَ مِنْهَا نِكَاحُ النَّاسِ الْيَوْمَ يَخْطُبُ الرَّجُلُ إِلَى الرَّجُلِ وَلِيَّتَهُ فَيُصْدِقُهَا ثُمَّ يَنْكِحُهَا وَنِكَاحٌ آخَرُ كَانَ الرَّجُلُ يَقُولُ لِامْرَأَتِهِ إِذَا طَهُرَتْ مِنْ طَمْثِهَا أَرْسِلِي إِلَى فُلَانٍ فَاسْتَبْضِعِي مِنْهُ وَيَعْتَزِلُهَا زَوْجُهَا وَلَا يَمَسُّهَا أَبَدًا حَتَّى يَتَبَيَّنَ حَمْلُهَا مِنْ ذَلِكَ الرَّجُلِ الَّذِي تَسْتَبْضِعُ مِنْهُ فَإِذَا تَبَيَّنَ حَمْلُهَا أَصَابَهَا زَوْجُهَا إِنْ أَحَبَّ وَإِنَّمَا يَفْعَلُ ذَلِكَ رَغْبَةً فِي نَجَابَةِ الْوَلَدِ فَكَانَ هَذَا النِّكَاحُ يُسَمَّى نِكَاحَ الِاسْتِبْضَاعِ وَنِكَاحٌ آخَرُ يَجْتَمِعُ الرَّهْطُ دُونَ الْعَشَرَةِ فَيَدْخُلُونَ عَلَى الْمَرْأَةِ كُلُّهُمْ يُصِيبُهَا فَإِذَا حَمَلَتْ وَوَضَعَتْ وَمَرَّ لَيَالٍ بَعْدَ أَنْ تَضَعَ حَمْلَهَا أَرْسَلَتْ إِلَيْهِمْ فَلَمْ يَسْتَطِعْ رَجُلٌ مِنْهُمْ أَنْ يَمْتَنِعَ حَتَّى يَجْتَمِعُوا عِنْدَهَا فَتَقُولُ لَهُمْ قَدْ عَرَفْتُمْ الَّذِي كَانَ مِنْ أَمْرِكُمْ وَقَدْ وَلَدْتُ وَهُوَ ابْنُكَ يَا فُلَانُ فَتُسَمِّي مَنْ أَحَبَّتْ مِنْهُمْ بِاسْمِهِ فَيَلْحَقُ بِهِ وَلَدُهَا وَنِكَاحٌ رَابِعٌ يَجْتَمِعُ النَّاسُ الْكَثِيرُ فَيَدْخُلُونَ عَلَى الْمَرْأَةِ لَا تَمْتَنِعُ مِمَّنْ جَاءَهَا وَهُنَّ الْبَغَايَا كُنَّ يَنْصِبْنَ عَلَى أَبْوَابِهِنَّ رَايَاتٍ يَكُنَّ عَلَمًا لِمَنْ أَرَادَهُنَّ دَخَلَ عَلَيْهِنَّ فَإِذَا حَمَلَتْ فَوَضَعَتْ حَمْلَهَا جُمِعُوا لَهَا وَدَعَوْا لَهُمْ الْقَافَةَ ثُمَّ أَلْحَقُوا وَلَدَهَا بِالَّذِي يَرَوْنَ فَالْتَاطَهُ وَدُعِيَ ابْنَهُ لَا يَمْتَنِعُ مِنْ ذَلِكَ فَلَمَّا بَعَثَ اللَّهُ مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَدَمَ نِكَاحَ أَهْلِ الْجَاهِلِيَّةِ كُلَّهُ إِلَّا نِكَاحَ أَهْلِ الْإِسْلَامِ الْيَوْمَ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih], telah menceritakan kepada kami ['Anbasah bin Khalid], telah menceritakan kepadaku [Yunus bin Yazid], ia berkata; [Muhammad bin Muslim bin Syihab] berkata; telah mengabarkan kepadaku ['Urwah bin Az Zubair], bahwa [Aisyah] radliallahu 'anha isteri Nabi shallallahu 'alaihi wasallam, ia telah mengabarkan kepadanya bahwa pernikahan pada masa jahiliyah berdasarkan empat macam, diantara pernikahan tersebut adalah pernikahan orang-orang pada zaman sekarang, yaitu seorang laki-laki melamar wali wanita seseorang kepadanya, kemudian memberinya mahar, kemudian laki-laki tersebut menikahinya. Dan pernikahan yang lain adalah seorang laki-laki berkata kepada isterinya; apabila ia telah suci dari haidnya; pergilah kepada si Fulan dan bersetebuhlah dengannya! Dan suaminya meninggalkannya serta tidak menggaulinya selamanya hingga jelas kehamilannya dari laki-laki yang telah mensetubuhinya tersebut. Kemudian apabila telah jelas kehamilannya maka suaminya menggaulinya apabila ia berkeinginan, dan ia melakukan hal tersebut karena ingin mendapatkan kecerdasan anak tersebut. Dan pernikahan ini dinamakan pernikahan istibdha', nikah yang lain adalah beberapa orang kurang dari sepuluh berkumpul dan menemui seorang wanita dan seluruh mereka menggaulinya, kemudian apabila wanita tersebut hamil dan telah melahirkan serta telah berlalu beberapa malam setelah melahirkan kandungannya, ia mengirimkan utusan kepada mereka dan tidak ada seorangpun diantara mereka yang dapat menolak hingga mereka berkumpul di hadapannya. Lalu wanita itu berkata kepada mereka; kalian telah mengetahui permasalahan kalian dahulu, sementara aku telah melahirkan, dan ia adalah anakmu wahai Fulan. Wanita tersebut menyebutkan nama orang yang ia senangi diantara mereka, maka anak tersebut mengikutinya. Dan pernikahan yang keempat adalah orang banyak berkumpul dan mendatangi wanita yang tidak menolak siapapun yang datang kepadanya, mereka adalah para pelacur dan dahulu mereka menancapkan bendera di atas pintu mereka yang menjadi tanda bagi orang yang menginginkan mereka serta menemui mereka. Kemudian apabila wanita tersebut hamil dan telah melahirkan kandungannya mereka dikumpulkan dan mereka datangkan orang yang pandai mengenai jejak, kemudian mereka menisbatkan anak tersebut kepada orang yang mereka lihat, kemudian orang tersebut mengambilnya sebagai anak dan anak tersebut dipanggil sebagai anaknya, orang tersebut tidak boleh menolaknya. Kemudian tatkala Allah mengutus Muhammad shallallahu 'alaihi wasallam, beliau menghancurkan seluruh pernikahan jahiliyah kecuali pernikahan orang Islam pada saat ini. "},"1870":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ وَمُسَدَّدٌ قَالَا حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَاخْتَصَمَ سَعْدُ بْنُ أَبِي وَقَّاصٍ وَعَبْدُ بْنُ زَمْعَةَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي ابْنِ أَمَةِ زَمْعَةَ فَقَالَ سَعْدٌ أَوْصَانِي أَخِي عُتْبَةُ إِذَا قَدِمْتُ مَكَّةَ أَنْ أَنْظُرَ إِلَى ابْنِ أَمَةِ زَمْعَةَ فَأَقْبِضَهُ فَإِنَّهُ ابْنُهُ وَقَالَ عَبْدُ بْنُ زَمْعَةَ أَخِي ابْنُ أَمَةِ أَبِي وُلِدَ عَلَى فِرَاشِ أَبِي فَرَأَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَبَهًا بَيِّنًا بِعُتْبَةَ فَقَالَ الْوَلَدُ لِلْفِرَاشِ وَلِلْعَاهِرِ الْحَجَرُ وَاحْتَجِبِي عَنْهُ يَا سَوْدَةُ زَادَ مُسَدَّدٌ فِي حَدِيثِهِ وَقَالَ هُوَ أَخُوكَ يَا عَبْدُ","id":"Telah menceritakan kepada kami [Sa'id bin Manshur], dan [Musaddad], mereka berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari ['Urwah] dari [Aisyah]; Sa'd bin Abu Waqqash dan 'Abdu bin Zam'ah berselisih kepada Rasulullah shallallahu 'alaihi wasallam mengenai anak budak wanita Zam'ah. Sa'd berkata; saudaraku 'Utbah memberiku wasiat apabila aku datang ke Mekkah agar melihat kepada anak budak wanita Zam'ah, kemudian mengambilnya karena ia adalah anaknya. Sedangkan Abdu bin Zam'ah berkata; ia adalah saudaraku, anak budak ayahku dan terlahir di tempat tidur ayahku. Kemudian Rasulullah shallallahu 'alaihi wasallam melihat kemiripannya yang sangat dengan 'Utbah. Kemudian beliau berkata; anak adalah mengikuti pemilik ranjang, dan orang yang berzina tidak mendapatkan sesuatu. Wahai Saudah berhijablah darinya. Musaddad menambahkan dalam haditsnya; dan beliau berkata; ia adalah saudaramu wahai 'Abdu. "},"1871":{"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا حُسَيْنٌ الْمُعَلِّمُ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقَامَ رَجُلٌ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّ فُلَانًا ابْنِي عَاهَرْتُ بِأُمِّهِ فِي الْجَاهِلِيَّةِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا دَعْوَةَ فِي الْإِسْلَامِ ذَهَبَ أَمْرُ الْجَاهِلِيَّةِ الْوَلَدُ لِلْفِرَاشِ وَلِلْعَاهِرِ الْحَجَرُ","id":"Telah menceritakan kepada kami [Zuhair bin Harb], telah menceritakan kepada kami [Yazid bin Harun], telah mengabarkan kepada kami [Husain Al Mu'allim] dari ['Amr bin Syu'aib] dari [ayahnya] dari [kakeknya], ia berkata; seorang laki-laki berdiri dan berkata; wahai Rasulullah, sesungguhnya Fulan adalah anakku. Aku berhubungan dengan ibunya pada masa jahiliyah. Rasulullah shallallahu 'alaihi wasallam berkata; tidak ada pengakuan dalam Islam, telah hilang urusan jahiliyah, anak mengikuti pemilik ranjang, dan orang yang berzina tidak mendapat apapun. "},"1872":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا مَهْدِيُّ بْنُ مَيْمُونٍ أَبُو يَحْيَى حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي يَعْقُوبَ عَنْ الْحَسَنِ بْنِ سَعْدٍ مَوْلَى الْحَسَنِ بْنِ عَلِيِّ بْنِ أَبِي طَالِبٍ رَضِيَ اللَّهُ عَنْهُ عَنْ رَبَاحٍ قَالَزَوَّجَنِي أَهْلِي أَمَةً لَهُمْ رُومِيَّةً فَوَقَعْتُ عَلَيْهَا فَوَلَدَتْ غُلَامًا أَسْوَدَ مِثْلِي فَسَمَّيْتُهُ عَبْدَ اللَّهِ ثُمَّ وَقَعْتُ عَلَيْهَا فَوَلَدَتْ غُلَامًا أَسْوَدَ مِثْلِي فَسَمَّيْتُهُ عُبَيْدَ اللَّهِ ثُمَّ طَبِنَ لَهَا غُلَامٌ لِأَهْلِي رُومِيٌّ يُقَالُ لَهُ يُوحَنَّهْ فَرَاطَنَهَا بِلِسَانِهِ فَوَلَدَتْ غُلَامًا كَأَنَّهُ وَزَغَةٌ مِنْ الْوَزَغَاتِ فَقُلْتُ لَهَا مَا هَذَا فَقَالَتْ هَذَا لِيُوحَنَّهْ فَرَفَعْنَا إِلَى عُثْمَانَ أَحْسَبُهُ قَالَ مَهْدِيٌّ قَالَ فَسَأَلَهُمَا فَاعْتَرَفَا فَقَالَ لَهُمَا أَتَرْضَيَانِ أَنْ أَقْضِيَ بَيْنَكُمَا بِقَضَاءِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى أَنَّ الْوَلَدَ لِلْفِرَاشِ وَأَحْسَبُهُ قَالَ فَجَلَدَهَا وَجَلَدَهُ وَكَانَا مَمْلُوكَيْنِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il], telah menceritakan kepada kami [Mahdi bin Maimun Abu Yahya], telah menceritakan kepada kami [Muhammad bin Abdullah bin Abu Ya'qub], dari [Al Hasan bin Sa'd] mantan budak Al Hasan bin Ali bin Abu Thalib radliallahu 'anhu, dari [Rabah], ia berkata; keluargaku menikahkanku dengan seorang budak wanita mereka dari Romawi, kemudian aku mencampurinya dan ia melahirkan seorang anak hitam sepertiku, lalu aku menamainya Abdullah. Kemudian aku mencampurinya dan ia melahirkan anak hitam sepertiku lalu aku menamainya 'Ubaidullah, kemudian ia mendapat perhatian budak Romawi milik keluargaku yang bernama Ruhanah dan ia berbicara kepadanya menggunakan bahasa asing. Kemudian ia melahirkan seorang anak berwarna seperti cicak, lalu aku katakan; siapakah ini? Ia berkata; ini adalah anak Yuhanah. Kemudian aku mengadukannya kepada [Utsman] -aku mengira kepada Mahdi- Rabah berkata; kemudian ia menanyakan kepada mereka berdua, dan mereka mengakuinya. Lalu Utsman berkata; apakah kalian berdua rela apabila aku memutuskan diantara kalian dengan keputusan Rasulullah shallallahu 'alaihi wasallam? Sesungguhnya Rasulullah shallallahu 'alaihi wasallam memutuskan bahwa anak mengikuti pemilik ranjang. Al Hasan berkata; kemudian ia mencambuk mereka berdua, dan mereka adalah budak. "},"1873":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ خَالِدٍ السُّلَمِيُّ حَدَّثَنَا الْوَلِيدُ عَنْ أَبِي عَمْرٍو يَعْنِي الْأَوْزَاعِيَّ حَدَّثَنِي عَمْرُو بْنُ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ عَبْدِ اللَّهِ بْنِ عَمْرٍوأَنَّ امْرَأَةً قَالَتْ يَا رَسُولَ اللَّهِ إِنَّ ابْنِي هَذَا كَانَ بَطْنِي لَهُ وِعَاءً وَثَدْيِي لَهُ سِقَاءً وَحِجْرِي لَهُ حِوَاءً وَإِنَّ أَبَاهُ طَلَّقَنِي وَأَرَادَ أَنْ يَنْتَزِعَهُ مِنِّي فَقَالَ لَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْتِ أَحَقُّ بِهِ مَا لَمْ تَنْكِحِي","id":"Telah menceritakan kepada kami [Mahmud bin Khalid As Sulami], telah menceritakan kepada kami [Al Walid] dari [Abu 'Amr Al Auza'i], telah menceritakan kepadaku ['Amr bin Syu'aib], dari [ayahnya] dari [kakeknya yaitu Abdullah bin 'Amr] bahwa seorang wanita berkata; wahai Rasulullah, sesungguhnya anakku ini, perutku adalah tempatnya, dan putting susuku adalah tempat minumnya, dan pangkuanku adalah rumahnya, sedangkan ayahnya telah menceraikannya dan ingin merampasnya dariku. Kemudian Rasulullah shallallahu 'alaihi wasallam berkata kepadanya; engkau lebih berhak terhadapnya selama engkau belum menikah. "},"1874":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْحُلْوَانِيُّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ وَأَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ أَخْبَرَنِي زِيَادٌ عَنْ هِلَالِ بْنِ أُسَامَةَ أَنَّ أَبَا مَيْمُونَةَ سَلْمَى مَوْلًى مِنْ أَهْلِ الْمَدِينَةِ رَجُلَ صِدْقٍ قَالَبَيْنَمَا أَنَا جَالِسٌ مَعَ أَبِي هُرَيْرَةَ جَاءَتْهُ امْرَأَةٌ فَارِسِيَّةٌ مَعَهَا ابْنٌ لَهَا فَادَّعَيَاهُ وَقَدْ طَلَّقَهَا زَوْجُهَا فَقَالَتْ يَا أَبَا هُرَيْرَةَ وَرَطَنَتْ لَهُ بِالْفَارِسِيَّةِ زَوْجِي يُرِيدُ أَنْ يَذْهَبَ بِابْنِي فَقَالَ أَبُو هُرَيْرَةَ اسْتَهِمَا عَلَيْهِ وَرَطَنَ لَهَا بِذَلِكَ فَجَاءَ زَوْجُهَا فَقَالَ مَنْ يُحَاقُّنِي فِي وَلَدِي فَقَالَ أَبُو هُرَيْرَةَ اللَّهُمَّ إِنِّي لَا أَقُولُ هَذَا إِلَّا أَنِّي سَمِعْتُ امْرَأَةً جَاءَتْ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا قَاعِدٌ عِنْدَهُ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنَّ زَوْجِي يُرِيدُ أَنْ يَذْهَبَ بِابْنِي وَقَدْ سَقَانِي مِنْ بِئْرِ أَبِي عِنَبَةَ وَقَدْ نَفَعَنِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَهِمَا عَلَيْهِ فَقَالَ زَوْجُهَا مَنْ يُحَاقُّنِي فِي وَلَدِي فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذَا أَبُوكَ وَهَذِهِ أُمُّكَ فَخُذْ بِيَدِ أَيِّهِمَا شِئْتَ فَأَخَذَ بِيَدِ أُمِّهِ فَانْطَلَقَتْ بِهِ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali Al Hulwani], telah menceritakan kepada kami [Abdurrazzaq], dan [Abu 'Ashim] dari [Juraij], telah mengabarkan kepadaku [Ziyad] dari [Hilal bin Usamah], bahwa [Abu Maimunah] mantan budak penduduk Madinah adalah orang yang jujur, ia berkata; tatkala aku sedang duduk bersama [Abu Hurairah], datang kepadanya seorang wanita Persia yang membawa anaknya -keduanya mengklaim lebih berhak terhadap anak tersebut-, dan suaminya telah menceraikannya. Wanita tersebut berkata menggunakan bahasa Persia; wahai Abu Hurairah, suamiku ingin pergi membawa anakku. Kemudian Abu Hurairah berkata kepadanya menggunakan bahasa asing; undilah anak tersebut. Kemudian suaminya datang dan berkata; siapakah yang menyelisihiku mengenai anakku? Kemudian Abu Hurairah berkata; Ya Allah, aku tidak mengatakan hal ini kecuali karena aku telah mendengar seorang wanita datang kepada Rasulullah shallallahu 'alaihi wasallam sementara aku duduk di sisinya, kemudian ia berkata; wahai Rasulullah shallallahu 'alaihi wasallam, sesungguhnya suamiku hendak pergi membawa anakku, sementara ia telah membantuku mengambil air dari sumur Abu 'Inabah, dan ia telah memberiku manfaat. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Undilah anak tersebut!\" kemudian suaminya berkata; siapakah yang akan menyelisihiku mengenai anakku? Kemudian Nabi shallallahu 'alaihi wasallam berkata: \"Ini adalah ayahmu dan ini adalah ibumu, gandenglah tangan salah seorang diantara mereka yang engkau kehendaki!\" kemudian ia menggandengang tangan ibunya, lalu wanita tersebut pergi membawanya. "},"1875":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ عَبْدِ الْعَظِيمِ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ عَمْرٍو حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ يَزِيدَ بْنِ الْهَادِ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ نَافِعِ بْنِ عُجَيْرٍ عَنْ أَبِيهِ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَخَرَجَ زَيْدُ بْنُ حَارِثَةَ إِلَى مَكَّةَ فَقَدِمَ بِابْنَةِ حَمْزَةَ فَقَالَ جَعْفَرٌ أَنَا آخُذُهَا أَنَا أَحَقُّ بِهَا ابْنَةُ عَمِّي وَعِنْدِي خَالَتُهَا وَإِنَّمَا الْخَالَةُ أُمٌّ فَقَالَ عَلِيٌّ أَنَا أَحَقُّ بِهَا ابْنَةُ عَمِّي وَعِنْدِي ابْنَةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهِيَ أَحَقُّ بِهَا فَقَالَ زَيْدٌ أَنَا أَحَقُّ بِهَا أَنَا خَرَجْتُ إِلَيْهَا وَسَافَرْتُ وَقَدِمْتُ بِهَا فَخَرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ حَدِيثًا قَالَ وَأَمَّا الْجَارِيَةُ فَأَقْضِي بِهَا لِجَعْفَرٍ تَكُونُ مَعَ خَالَتِهَا وَإِنَّمَا الْخَالَةُ أُمٌّحَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا سُفْيَانُ عَنْ أَبِي فَرْوَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى بِهَذَا الْخَبَرِ وَلَيْسَ بِتَمَامِهِ قَالَ وَقَضَى بِهَا لِجَعْفَرٍ وَقَالَ إِنَّ خَالَتَهَا عِنْدَهُ حَدَّثَنَا عَبَّادُ بْنُ مُوسَى أَنَّ إِسْمَعِيلَ بْنَ جَعْفَرٍ حَدَّثَهُمْ عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَقَ عَنْ هَانِئٍ وَهُبَيْرَةَ عَنْ عَلِيٍّ قَالَ لَمَّا خَرَجْنَا مِنْ مَكَّةَ تَبِعَتْنَا بِنْتُ حَمْزَةَ تُنَادِي يَا عَمُّ يَا عَمُّ فَتَنَاوَلَهَا عَلِيٌّ فَأَخَذَ بِيَدِهَا وَقَالَ دُونَكِ بِنْتَ عَمِّكِ فَحَمَلَتْهَا فَقَصَّ الْخَبَرَ قَالَ وَقَالَ جَعْفَرٌ ابْنَةُ عَمِّي وَخَالَتُهَا تَحْتِي فَقَضَى بِهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِخَالَتِهَا وَقَالَ الْخَالَةُ بِمَنْزِلَةِ الْأُمِّ","id":"Telah menceritakan kepada kami [Al Abbas bin Abdul 'Azhim], telah menceritakan kepada kami [Abdul Malik bin 'Amr], telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Yazid bin Al Had], dari [Muhammad bin Ibrahim], dari [Nafi' bin 'Ujair] dari [ayahnya] dari [Ali] radliallahu 'anhu, ia berkata; Zaid bin Haritsah pergi menuju Mekkah dan datang membawa anak wanita Hamzah, kemudian Ja'far berkata; aku akan mengambilnya, aku lebih berhak terhadapnya ia adalah anak pamanku, dan bibinya (dari pihak ibu) adalah isteriku, sesungguhnya bibi dari pihak ibu adalah sama dengan seorang ibu. Kemudian Ali berkata; aku lebih berhak terhadapnya, ia adalah anak pamanku dan anak Rasulullah shallallahu 'alaihi wasallam adalah isteriku, dan ia lebih berhak terhadapnya. Kemudian Zaid berkata; aku lebih berhak terhadapnya, aku keluar dan pergi menuju kepadanya, dan datang membawanya. Kemudian Nabi shallallahu 'alaihi wasallam lalu menyebutkan sebuah hadits, beliau berkata; adapun anak itu aku putuskan untuk Ja'far, ia akan bersama bibinya, sesungguhnya bibi dari pihak ibu adalah seperti ibu. Telah menceritakan kepada kami [Muhammad bin Isa], telah menceritakan kepada kami [Sufyan] dari [Abu Farwah] dari [Abdurrahman bin Abu Laila] dengan hadits ini tidak secara sempurna. Ia berkata; dan beliau memutuskan anak tersebut untuk Ja'far, beliau berkata: \"Sesungguhnya bibinya dari pihak ibu adalah isterinya.\" Telah menceritakan kepada kami ['Abbad bin Musa] bahwa [Isma'il bin Ja'far], ia telah menceritakan kepada mereka dari [Israil] dari [Abu Ishaq] dari [Hani`] dan [Hubairah] dari [Ali], ia berkata; kami keluar dari Mekkah, dan kami diikuti anak wanita Hamzah, ia memanggil; wahai paman, wahai paman! Kemudian Ali mengambilnya dan menggandeng tangannya. Ia berkata (kepada Fathimah); ambillah anak pamanmu! Kemudian Fathimah menggendongnya. Ali menceritakan hadits ini, ia berkata; Ja'far berkata; ia adalah anak pamanku dan bibinya dari pihak ibu adalah isteriku. Kemudian Nabi shallallahu 'alaihi wasallam memutuskan bahwa anak tersebut adalah menjadi hak bibinya dari pihak ibu, dan beliau berkata; ibu dari pihak ibu adalah seperti ibu."},"1876":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ عَبْدِ الْحَمِيدِ الْبَهْرَانِيُّ حَدَّثَنَا يَحْيَى بْنُ صَالِحٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ حَدَّثَنِي عَمْرُو بْنُ مُهَاجِرٍ عَنْ أَبِيهِ عَنْ أَسْمَاءَ بِنْتِ يَزِيدَ بْنِ السَّكَنِ الْأَنْصَارِيَّةِأَنَّهَا طُلِّقَتْ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَمْ يَكُنْ لِلْمُطَلَّقَةِ عِدَّةٌ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ حِينَ طُلِّقَتْ أَسْمَاءُ بِالْعِدَّةِ لِلطَّلَاقِ فَكَانَتْ أَوَّلَ مَنْ أُنْزِلَتْ فِيهَا الْعِدَّةُ لِلْمُطَلَّقَاتِ","id":"Telah menceritakan kepada kami [Sulaiman bin Abdul Hamid Al Bahrani], telah menceritakan kepada kami [Yahya bin Shalih], telah menceritakan kepada kami [Isma'il bin 'Ayyasy], telah menceritakan kepadaku ['Amr bin Muhajir] dari [ayahnya] dari [Asma` binti Yazid bin As Sakan Al Anshariyyah] bahwa ia telah dicerai pada zaman Rasulullah shallallahu 'alaihi wasallam dan wanita yang dicerai tidak memiliki 'iddah, kemudian Allah 'azza wajalla menurunkan wahyu mengenai 'iddah karena perceraian ketika Asma` dicerai, ia adalah wanita pertama yang karenanya diturunkan ayat tentang 'iddah wanita yang dicerai. "},"1877":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ ثَابِتٍ الْمَرْوَزِيُّ حَدَّثَنِي عَلِيُّ بْنُ حُسَيْنٍ عَنْ أَبِيهِ عَنْ يَزِيدَ النَّحْوِيِّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ{ وَالْمُطَلَّقَاتُ يَتَرَبَّصْنَ بِأَنْفُسِهِنَّ ثَلَاثَةَ قُرُوءٍ }وَقَالَ{ وَاللَّائِي يَئِسْنَ مِنْ الْمَحِيضِ مِنْ نِسَائِكُمْ إِنْ ارْتَبْتُمْ فَعِدَّتُهُنَّ ثَلَاثَةُ أَشْهُرٍ }فَنُسِخَ مِنْ ذَلِكَ وَقَالَ{ ثُمَّ طَلَّقْتُمُوهُنَّ مِنْ قَبْلِ أَنْ تَمَسُّوهُنَّ فَمَا لَكُمْ عَلَيْهِنَّ مِنْ عِدَّةٍ تَعْتَدُّونَهَا }","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad bin Tsabit Al Marwazi], telah menceritakan kepadaku [Ali bin Husain] dari [ayahnya] dari [Yazid An Nahwi] dari [Ikrimah] dari [Ibnu Abbas], ia membaca ayat: \"Wanita-wanita yang ditalak hendaklah menahan diri (menunggu) tiga kali quru'\", serta: \"Dan perempuan-perempuan yang tidak haid lagi (monopause) di antara perempuan-perempuanmu jika kamu ragu-ragu (tentang masa iddahnya), maka masa iddah mereka adalah tiga bulan.\" Kemudian sebagian darinya dihapuskan, ia membaca ayat: \"Kemudian kamu ceraikan mereka sebelum kamu mencampurinya\", maka kalian tidak memiliki hak 'Iddah atas mereka. "},"1878":{"ar":"حَدَّثَنَا سَهْلُ بْنُ مُحَمَّدِ بْنِ الزُّبَيْرِ الْعَسْكَرِيُّ حَدَّثَنَا يَحْيَى بْنُ زَكَرِيَّا بْنِ أَبِي زَائِدَةَ عَنْ صَالِحِ بْنِ صَالِحٍ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ عَنْ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَلَّقَ حَفْصَةَ ثُمَّ رَاجَعَهَا","id":"Telah menceritakan kepada kami [Sahl bin Muhammad bin Az Zubair Al Askari], telah menceritakan kepada kami [Yahya bin Zakaria bin Abu Za`idah] dari [Shalih bin Shalih] dari [Salamah bin Kuhail] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dari [Umar] bahwa Rasulullah shallallahu 'alaihi wasallam pernah mentalak Hashah lalu merujukinya kembali. "},"1879":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ عَبْدِ اللَّهِ بْنِ يَزِيدَ مَوْلَى الْأَسْوَدِ بْنِ سُفْيَانَ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ فَاطِمَةَ بِنْتِ قَيْسٍأَنَّ أَبَا عَمْرِو بْنَ حَفْصٍ طَلَّقَهَا الْبَتَّةَ وَهُوَ غَائِبٌ فَأَرْسَلَ إِلَيْهَا وَكِيلَهُ بِشَعِيرٍ فَتَسَخَّطَتْهُ فَقَالَ وَاللَّهِ مَا لَكِ عَلَيْنَا مِنْ شَيْءٍ فَجَاءَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَتْ ذَلِكَ لَهُ فَقَالَ لَهَا لَيْسَ لَكِ عَلَيْهِ نَفَقَةٌ وَأَمَرَهَا أَنْ تَعْتَدَّ فِي بَيْتِ أُمِّ شَرِيكٍ ثُمَّ قَالَ إِنَّ تِلْكَ امْرَأَةٌ يَغْشَاهَا أَصْحَابِي اعْتَدِّي فِي بَيْتِ ابْنِ أُمِّ مَكْتُومٍ فَإِنَّهُ رَجُلٌ أَعْمَى تَضَعِينَ ثِيَابَكِ وَإِذَا حَلَلْتِ فَآذِنِينِي قَالَتْ فَلَمَّا حَلَلْتُ ذَكَرْتُ لَهُ أَنَّ مُعَاوِيَةَ بْنَ أَبِي سُفْيَانَ وَأَبَا جَهْمٍ خَطَبَانِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَّا أَبُو جَهْمٍ فَلَا يَضَعُ عَصَاهُ عَنْ عَاتِقِهِ وَأَمَّا مُعَاوِيَةُ فَصُعْلُوكٌ لَا مَالَ لَهُ انْكِحِي أُسَامَةَ بْنَ زَيْدٍ قَالَتْ فَكَرِهْتُهُ ثُمَّ قَالَ انْكِحِي أُسَامَةَ بْنَ زَيْدٍ فَنَكَحْتُهُ فَجَعَلَ اللَّهُ تَعَالَى فِيهِ خَيْرًا كَثِيرًا وَاغْتَبَطْتُ بِهِحَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا أَبَانُ بْنُ يَزِيدَ الْعَطَّارُ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ حَدَّثَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ أَنَّ فَاطِمَةَ بِنْتَ قَيْسٍ حَدَّثَتْهُ أَنَّ أَبَا حَفْصِ بْنَ الْمُغِيرَةِ طَلَّقَهَا ثَلَاثًا وَسَاقَ الْحَدِيثَ فِيهِ وَأَنَّ خَالِدَ بْنَ الْوَلِيدِ وَنَفَرًا مِنْ بَنِي مَخْزُومٍ أَتَوْا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا يَا نَبِيَّ اللَّهِ إِنَّ أَبَا حَفْصِ بْنَ الْمُغِيرَةِ طَلَّقَ امْرَأَتَهُ ثَلَاثًا وَإِنَّهُ تَرَكَ لَهَا نَفَقَةً يَسِيرَةً فَقَالَ لَا نَفَقَةَ لَهَا وَسَاقَ الْحَدِيثَ وَحَدِيثُ مَالِكٍ أَتَمُّ حَدَّثَنَا مَحْمُودُ بْنُ خَالِدٍ حَدَّثَنَا الْوَلِيدُ حَدَّثَنَا أَبُو عَمْرٍو عَنْ يَحْيَى حَدَّثَنِي أَبُو سَلَمَةَ حَدَّثَتْنِي فَاطِمَةُ بِنْتُ قَيْسٍ أَنَّ أَبَا عَمْرِو بْنَ حَفْصٍ الْمَخْزُومِيَّ طَلَّقَهَا ثَلَاثًا وَسَاقَ الْحَدِيثَ وَخَبَرَ خَالِدِ بْنِ الْوَلِيدِ قَال فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَتْ لَهَا نَفَقَةٌ وَلَا مَسْكَنٌ قَالَ فِيهِ وَأَرْسَلَ إِلَيْهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ لَا تَسْبِقِينِي بِنَفْسِكِ حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ عَنْ إِسْمَاعِيلَ بْنِ جَعْفَرٍ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ فَاطِمَةَ بِنْتِ قَيْسٍ قَالَتْ كُنْتُ عِنْدَ رَجُلٍ مِنْ بَنِي مَخْزُومٍ فَطَلَّقَنِي الْبَتَّةَ ثُمَّ سَاقَ نَحْوَ حَدِيثِ مَالِكٍ قَالَ فِيهِ وَلَا تُفَوِّتِينِي بِنَفْسِكِ قَالَ أَبُو دَاوُد وَكَذَلِكَ رَوَاهُ الشَّعْبِيُّ وَالْبَهِيُّ وَعَطَاءٌ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَاصِمٍ وَأَبُو بَكْرِ بْنِ أَبِي الْجَهْمِ كُلُّهُمْ عَنْ فَاطِمَةَ بِنْتِ قَيْسٍ أَنَّ زَوْجَهَا طَلَّقَهَا ثَلَاثًا","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Abdullah bin Yazid?] mantan budak Al Aswad bin Sufyan dari [Abu Salamah bin Abdurrahman] dari [Fathimah binti Qais] bahwa Abu 'Amr bin Hafsh telah mencerainya sama sekali, sementara Abu 'Amr tidak hadir. Lalu ia mengirimkan wakilnya kepadanya dengan membawa gandum. Maka Fathimah marah kepadanya, kemudian wakil tersebut berkata; demi Allah engkau tidak mempunyai hak sedikitpun atas kami. Kemudian Fathimah datang kepada Rasulullah shallallahu 'alaihi wasallam dan menyebutkan hal tersebut kepadanya. Kemudian beliau berkata kepadanya: \"Engkau tidak memiliki hak nafkah atasnya.\" Dan beliau memerintahkannya agar ber'iddah di rumah Ummu Syarik. Kemudian beliau berkata: \"Ia adalah seorang wanita yang sering dikunjungi sahabat-sahabatku. Ber'iddahlah di rumah Ibnu Ummi Maktum. Karena ia adalah orang yang buta. Engkau bisa meletakkan pakainmu dan apabila engkau telah halal maka beritahukan kepadaku!\" Fathimah berkata; kemudian tatkala aku telah halal, aku ceritakan kepada beliau bahwa Mu'awiyah bin Abu Sufyan dan Abu Jahm telah meminangku. Kemudian Rasulullah shallallahu 'alaihi wasallam berkata: \"Adapun Abu Jahm, maka ia tidak meletakkan tongkatnya dari pundaknya, adapun Mu'awiyah, maka ia adalah orang yang miskin, tidak memiliki harta. Menikahlah dengan Usamah bin Zaid.\" Fathimah berkata; Lalu aku tidak menyukai hal tersebut, kemudian beliau berkata: \"Menikahlah dengan Usamah bin Zaid.\" Kemudian aku menikah dengannya dan Allah ta'ala menjadikan pada dirinya terdapat kebaikan yang sangat banyak. Dan aku merasa iri kepadanya. Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Aban bin Yazid? Al 'Aththar], telah menceritakan kepada kami [Yahya bin Abu Katsir] telah menceritakan kepadaku [Abu Salamah bin Abdurrahman] bahwa [Fathimah binti Qais] menceritakan kepadanya bahwa Abu Hafsh bin Al Mughirah telah menceraikannya tiga kali. Dan ia menyebutkan hadits mengenai hal tersebut. Dan Khalid bin Al Walid serta beberapa orang dari Bani Makhzum datang kepada Nabi shallallahu 'alaihi wasallam dan berkata; wahai Nabi Allah, sesungguhnya Abu Hafsh bin Al Mughirah telah menceraian isterinya sebanyak tiga kali. dan ia meninggalkan untuknya sedikit nafkah. Kemudian beliau berkata: \"Ia tidak mendapatkan nafkah.\" Dan Abu Salamah menyebutkan hadits tersebut. Dan hadits Malik lebih sempurna. Telah menceritakan kepada kami [Mahmud bin Khalid], telah menceritakan kepada kami [Al Walid], telah menceritakan kepada kami [Abu 'Amr] dari [Yahya] telah menceritakan kepadaku [Abu Salamah], telah menceritakan kepadaku [Fathimah binti Qais] bahwa Abu 'Amr bin Hafsh Al Makhzumi telah mencerainya tiga kali. Dan ia menyebutkan hadits tersebut dan hadits Khalid bin Al Walid. Ia berkata; kemudian Nabi shallallahu 'alaihi wasallam berkata; ia tidak mendapatkan nafkah, dan tempat tinggal. Kemudian Nabi shallallahu 'alaihi wasallam mengirimkan utusan mengatakan; janganlah engkau mendahuluiku mengenai dirimu! Telah menceritakan kepada kami [Qutaibah bin Sa'id] dari [Isma'il bin Ja'far] dari [Muhammad bin 'Amr] dari [Abu Salamah] dari [Fathimah binti Qais], ia berkata; aku pernah menjadi isteri seorang laki-laki dari Bani Makhzum. Kemudian ia menceraiku sama sekali (untuk selamanya) …. Kemudian ia menyebutkan hadits seperti hadits Malik. Ia berkata padanya; janganlah engkau mendahuluiku terhadap dirimu. Abu Daud berkata; dan demikianlah [Asy Sya'bi] dan [Al Bahi] serta ['Atha`] meriwayatkannya dari [Abdurrahman bin 'Ashim], dan [Abu Bakr bin Abu Al Jahm] seluruh mereka berasal dari [Fathimah binti Qais], bahwa suaminya telah mencerainya tiga kali. "},"1880":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ حَدَّثَنَا سَلَمَةُ بْنُ كُهَيْلٍ عَنْ الشَّعْبِيِّ عَنْ فَاطِمَةَ بِنْتِ قَيْسٍأَنَّ زَوْجَهَا طَلَّقَهَا ثَلَاثًا فَلَمْ يَجْعَلْ لَهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَفَقَةً وَلَا سُكْنَى","id":"Telah menceritakan kepada kami [Muhammad bin Katsir], telah mengabarkan kepada kami [Sufyan], telah menceritakan kepada kami [Salamah bin Kuhail] dari [Asy Sya'bi] dari [Fathimah binti Qais] bahwa suaminya telah mencerainya sebanyak tiga kali, dan Nabi shallallahu 'alaihi wasallam tidak memberikan nafkah dan rumah kepadanya. "},"1881":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ خَالِدٍ الرَّمْلِيُّ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ عَنْ فَاطِمَةَ بِنْتِ قَيْسٍ أَنَّهَا أَخْبَرَتْهُأَنَّهَا كَانَتْ عِنْدَ أَبِي حَفْصِ بْنِ الْمُغِيرَةِ وَأَنَّ أَبَا حَفْصِ بْنَ الْمُغِيرَةِ طَلَّقَهَا آخِرَ ثَلَاثِ تَطْلِيقَاتٍ فَزَعَمَتْ أَنَّهَا جَاءَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاسْتَفْتَتْهُ فِي خُرُوجِهَا مِنْ بَيْتِهَا فَأَمَرَهَا أَنْ تَنْتَقِلَ إِلَى ابْنِ أُمِّ مَكْتُومٍ الْأَعْمَى فَأَبَى مَرْوَانُ أَنْ يُصَدِّقَ حَدِيثَ فَاطِمَةَ فِي خُرُوجِ الْمُطَلَّقَةِ مِنْ بَيْتِهَاقَالَ عُرْوَةُ وَأَنْكَرَتْ عَائِشَةُ رَضِيَ اللَّهُ عَنْهَا عَلَى فَاطِمَةَ بِنْتِ قَيْسٍ قَالَ أَبُو دَاوُد وَكَذَلِكَ رَوَاهُ صَالِحُ بْنُ كَيْسَانَ وَابْنُ جُرَيْجٍ وَشُعَيْبُ بْنُ أَبِي حَمْزَةَ كُلُّهُمْ عَنْ الزُّهْرِيِّ قَالَ أَبُو دَاوُد وَشُعَيْبُ بْنُ أَبِي حَمْزَةَ وَاسْمُ أَبِي حَمْزَةَ دِينَارٌ وَهُوَ مَوْلَى زِيَادٍ","id":"Telah menceritakan kepada kami [Yazid bin Khalid Ar Ramli], Telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] dari [Abu Salamah] dari [Fathimah binti Qais] ia telah mengabarkan kepadanya bahwa ia dahulu adalah isteri Abu Hafsh bin Al Mughirah, dan Abu Hafsh bin Al Mughirah telah mencerainya ketiga kalinya, dan Fathimah mengaku bahwa ia datang kepada Rasulullah shallallahu 'alaihi wasallam serta meminta fatwa kepada beliau mengenai keluarnya dia dari rumahnya. Lalu beliau memerintahkannya agar berpindah ke rumah Ibnu Ummi Maktum orang yang buta. Lalu Marwan menolak mempercayai hadits Fathimah mengenai keluarnya wanita yang dicerai dari rumahnya. 'Urwah berkata; dan Aisyah radliallahu 'anha mengingkari Fathimah binti Qais. Abu Daud berkata; begitu pula hadits tersebut diriwayatkan oleh [Shalih bin Kaisan], serta [Ibnu Juraij], dan [Syu'aib bin Abu Hamzah] seluruh mereka berasal dari [Az Zuhri]. Abu Daud berkata; dan Syu'aib bin Abu Hamzah, sedangkan nama Abu Hamzah adalah Dinar, ia adalah mantan budak Ziyad. "},"1882":{"ar":"حَدَّثَنَا مَخْلَدُ بْنُ خَالِدٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ قَالَأَرْسَلَ مَرْوَانُ إِلَى فَاطِمَةَ فَسَأَلَهَا فَأَخْبَرَتْهُ أَنَّهَا كَانَتْ عِنْدَ أَبِي حَفْصٍ وَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَّرَ عَلِيَّ بْنَ أَبِي طَالِبٍ يَعْنِي عَلَى بَعْضِ الْيَمَنِ فَخَرَجَ مَعَهُ زَوْجُهَا فَبَعَثَ إِلَيْهَا بِتَطْلِيقَةٍ كَانَتْ بَقِيَتْ لَهَا وَأَمَرَ عَيَّاشَ بْنَ أَبِي رَبِيعَةَ وَالْحَارِثَ بْنَ هِشَامٍ أَنْ يُنْفِقَا عَلَيْهَا فَقَالَا وَاللَّهِ مَا لَهَا نَفَقَةٌ إِلَّا أَنْ تَكُونَ حَامِلًا فَأَتَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَا نَفَقَةَ لَكِ إِلَّا أَنْ تَكُونِي حَامِلًا وَاسْتَأْذَنَتْهُ فِي الِانْتِقَالِ فَأَذِنَ لَهَا فَقَالَتْ أَيْنَ أَنْتَقِلُ يَا رَسُولَ اللَّهِ قَالَ عِنْدَ ابْنِ أُمِّ مَكْتُومٍ وَكَانَ أَعْمَى تَضَعُ ثِيَابَهَا عِنْدَهُ وَلَا يُبْصِرُهَا فَلَمْ تَزَلْ هُنَاكَ حَتَّى مَضَتْ عِدَّتُهَا فَأَنْكَحَهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُسَامَةَ فَرَجَعَ قَبِيصَةُ إِلَى مَرْوَانَ فَأَخْبَرَهُ بِذَلِكَ فَقَالَ مَرْوَانُ لَمْ نَسْمَعْ هَذَا الْحَدِيثَ إِلَّا مِنْ امْرَأَةٍ فَسَنَأْخُذُ بِالْعِصْمَةِ الَّتِي وَجَدْنَا النَّاسَ عَلَيْهَا فَقَالَتْ فَاطِمَةُ حِينَ بَلَغَهَا ذَلِكَ بَيْنِي وَبَيْنَكُمْ كِتَابُ اللَّهِ قَالَ اللَّهُ تَعَالَى{ فَطَلِّقُوهُنَّ لِعِدَّتِهِنَّ حَتَّى لَا تَدْرِي لَعَلَّ اللَّهَ يُحْدِثُ بَعْدَ ذَلِكَ أَمْرًا }قَالَتْ فَأَيُّ أَمْرٍ يُحْدِثُ بَعْدَ الثَّلَاثِقَالَ أَبُو دَاوُد وَكَذَلِكَ رَوَاهُ يُونُسُ عَنْ الزُّهْرِيِّ وَأَمَّا الزُّبَيْدِيُّ فَرَوَى الْحَدِيثَيْنِ جَمِيعًا حَدِيثَ عُبَيْدِ اللَّهِ بِمَعْنَى مَعْمَرٍ وَحَدِيثَ أَبِي سَلَمَةَ بِمَعْنَى عُقَيْلٍ وَرَوَاهُ مُحَمَّدُ بْنُ إِسْحَقَ عَنْ الزُّهْرِيِّ أَنَّ قَبِيصَةَ بْنَ ذُؤَيْبٍ حَدَّثَهُ بِمَعْنًى دَلَّ عَلَى خَبَرِ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ حِينَ قَالَ فَرَجَعَ قَبِيصَةُ إِلَى مَرْوَانَ فَأَخْبَرَهُ بِذَلِكَ","id":"Telah menceritakan kepada kami [Makhlad bin Khalid], Telah menceritakan kepada kami [Abdurrazzaq] dari [Ma'mar] dari [Az Zuhri] dari ['Ubaidullah], ia berkata; Marwan mengirim utusan kepada [Fathimah] untuk bertanya kepadanya, kemudian Fathimah mengabarkan kepadanya bahwa ia dahulu adalah isteri Abu Hafsh, dan Nabi shallallahu 'alaihi wasallam mengangkat Ali bin Abu Thalib sebagai pemimpin sebagian (wilayah) Yaman, kemudian suaminya keluar bersamanya dan mengirimkan utusan membawa penceraiannya yang tersisa, dan memerintahkan 'Ayyasy bin Abu Rabi'ah serta Al Harits bin Hisyam agar memberikan nafkah kepadanya. Mereka berdua mengatakan; demi Allah ia tidak memiliki hak nafkah kecuali ia dalam keadaan hamil. Kemudian Fathimah datang kepada Nabi shallallahu 'alaihi wasallam, lalu beliau berkata; engkau tidak memiliki hak nafkah, kecuali apabila engkau sedang hamil. Fathimah meminta izin untuk pindah, lalu beliau mengizinkannya. Fathimah berkata; kemana aku pindah wahai Rasulullah? Beliau berkata; Rumah Ibnu Ummi Maktum. Ia adalah orang yang buta, ia dapat meletakkan pakaiannya di rumah Ibnu Ummi Maktum sementara ia tidak melihatnya. Fathimah tetap ada di sana hingga 'iddahnya habis. Kemudian Nabi shallallahu 'alaihi wasallam menikahkannya dengan Usamah, kemudian Qabishah kembali kepada Marwan dan mengabarkan hal tersebut kepadanya. Marwan berkata; kami tidak mendengar hadits ini kecuali dari seorang wanita dan kami akan mengambil sesuatu yang dipercaya yang kami dapati orang-orang ada padanya. Fathimah berkata ketika hal tersebut sampai kepadanya; antaraku dan kalian terdapat Kitab Allah, Allah ta'ala berfirman: \"maka hendaklah kamu ceraikan mereka pada waktu mereka dapat (menghadapi) iddahnya (yang wajar) \" hingga firmanNya: \"Kamu tidak mengetahui barangkali Allah mengadakan sesudah itu sesuatu hal yang baru.\" Ia berkata; sesuatu apakah yang akan Allah adakan setelah tiga kali perceraian? Abu Daud berkata; dan begitu juga hadits tersebut diriwayatkan oleh [Yunus] dari [Az Zuhri], adapun [Az Zubaidi], maka ia telah meriwayatkan dua hadits semuanya, yaitu hadits 'Ubaidullah yang seperti makna hadits Ma'mar, serta hadits [Abu Salamah] yang seperti makna hadits 'Uqail. Dan hadits tersebut diriwayatkan oleh [Muhammad bin Ishaq] dari [Az Zuhri] bahwa [Qabishah bin Dzuaib] telah menceritakan kepadanya secara makna yang menunjukkan kepada hadits 'Ubaidullah bin Abdullah ketika ia berkata; kemudian Qabishah kembali kepada Marwan dan mengabarkan hal tersebut kepadanya. "},"1883":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ أَخْبَرَنِي أَبُو أَحْمَدَ حَدَّثَنَا عَمَّارُ بْنُ رُزَيْقٍ عَنْ أَبِي إِسْحَقَ قَالَكُنْتُ فِي الْمَسْجِدِ الْجَامِعِ مَعَ الْأَسْوَدِ فَقَالَ أَتَتْ فَاطِمَةُ بِنْتُ قَيْسٍ عُمَرَ بْنَ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ قَالَ مَا كُنَّا لِنَدَعَ كِتَابَ رَبِّنَا وَسُنَّةَ نَبِيِّنَا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِقَوْلِ امْرَأَةٍ لَا نَدْرِي أَحَفِظَتْ ذَلِكَ أَمْ لَا","id":"Telah menceritakan kepada kami [Nashr bin Ali], telah mengabarkan kepadaku [Abu Ahmad], telah menceritakan kepada kami ['Ammar bin Ruzaiq] dari [Abu Ishaq], ia berkata; aku pernah berada di masjid jami' bersama [Al Aswad], kemudian ia berkata; Fathimah binti Qais datang kepada [Umar bin Al Khathab radliallahu 'anhu], kemudian Umar berkata; kami tidak akan meninggalkan Kitab Tuhan kami dan Sunnah Nabi kami shallallahu 'alaihi wasallam hanya karena perkataan seorang wanita yang tidak kami ketahui apakah ia menghafalnya atau tidak. "},"1884":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ حَدَّثَنَا ابْنُ وَهْبٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ أَبِي الزِّنَادِ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ قَالَلَقَدْ عَابَتْ ذَلِكَ عَائِشَةُ رَضِيَ اللَّهُ عَنْهَا أَشَدَّ الْعَيْبِ يَعْنِي حَدِيثَ فَاطِمَةَ بِنْتِ قَيْسٍ وَقَالَتْ إِنَّ فَاطِمَةَ كَانَتْ فِي مَكَانٍ وَحْشٍ فَخِيفَ عَلَى نَاحِيَتِهَا فَلِذَلِكَ رَخَّصَ لَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَحَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ أَنَّهُ قِيلَ لِعَائِشَةَ أَلَمْ تَرَيْ إِلَى قَوْلِ فَاطِمَةَ قَالَتْ أَمَا إِنَّهُ لَا خَيْرَ لَهَا فِي ذَلِكَ حَدَّثَنَا هَارُونُ بْنُ زَيْدٍ حَدَّثَنَا أَبِي عَنْ سُفْيَانَ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ فِي خُرُوجِ فَاطِمَةَ قَالَ إِنَّمَا كَانَ ذَلِكَ مِنْ سُوءِ الْخُلُقِ","id":"Telah menceritakan kepada kami [Sulaiman bin Daud], telah menceritakan kepada kami [Ibnu Wahb], telah menceritakan kepada kami [Abdurrahman bin Abu Az Zinad] dari [Hisyam bin 'Urwah] dari [ayahnya], ia berkata; [Aisyah radliallahu 'anha] telah mencela hal tersebut dengan keras, yaitu mencela hadits Fathimah binti Qais. Ia berkata; sesungguhnya Fathimah dahulu berada di tempat yang asing sehingga dikhawatirkan atas dirinya. Oleh karena itu Rasulullah shallallahu 'alaihi wasallam memberikan keringanan kepadanya. Telah menceritakan kepada kami Muhammad bin Katsir, telah mengabarkan kepada kami Sufyan dari Abdurrahman bin Al Qasim dari ayahnya dari 'Urwah bin Az Zubair bahwa Aisyah ditanya; bagaimana pendapatmu mengenai perkataan Fathimah? Ia berkata; ketahuilah bahwa tidak ada kebaikan baginya dalam hal tersebut. Telah menceritakan kepada kami Harun bin Zaid, telah menceritakan kepada kami ayahku, dari Sufyan, dari Yahya bin Sa'id dari Sulaiman bin Yasar mengenai keluarnya Fathimah, ia berkata; sesungguhnya hal tersebut termasuk diantara keburukan akhlaq."},"1885":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ وَسُلَيْمَانَ بْنِ يَسَارٍ أَنَّهُ سَمِعَهُمَا يَذْكُرَانِأَنَّ يَحْيَى بْنَ سَعِيدِ بْنِ الْعَاصِ طَلَّقَ بِنْتَ عَبْدِ الرَّحْمَنِ بْنِ الْحَكَمِ الْبَتَّةَ فَانْتَقَلَهَا عَبْدُ الرَّحْمَنِ فَأَرْسَلَتْ عَائِشَةُ رَضِيَ اللَّهُ عَنْهَا إِلَى مَرْوَانَ بْنِ الْحَكَمِ وَهُوَ أَمِيرُ الْمَدِينَةِ فَقَالَتْ لَهُ اتَّقِ اللَّهَ وَارْدُدْ الْمَرْأَةَ إِلَى بَيْتِهَا فَقَالَ مَرْوَانُ فِي حَدِيثِ سُلَيْمَانَ إِنَّ عَبْدَ الرَّحْمَنِ غَلَبَنِي وَقَالَ مَرْوَانُ فِي حَدِيثِ الْقَاسِمِ أَوَ مَا بَلَغَكِ شَأْنُ فَاطِمَةَ بِنْتِ قَيْسٍ فَقَالَتْ عَائِشَةُ لَا يَضُرُّكَ أَنْ لَا تَذْكُرَ حَدِيثَ فَاطِمَةَ فَقَالَ مَرْوَانُ إِنْ كَانَ بِكِ الشَّرُّ فَحَسْبُكِ مَا كَانَ بَيْنَ هَذَيْنِ مِنْ الشَّرِّ","id":"Telah menceritakan kepada kami [Al Qa'nabi], dari [Malik] dari [Yahya bin Sa'id] dari [Al Qasim bin Muhammad] serta [Sulaiman bin Yasar] bahwa ia mendengar mereka berdua menyebutkan bahwa Yahya bin Al 'Ash telah mencerai anak wanita Abdurrahman bin Al Hakam sama sekali. Kemudian Abdurrahman memindahnya, lalu [Aisyah] radliallahu 'anha mengirimkan surat kepada Marwan bin Al Hakam yang merupakan pemimpin Madinah, Aisyah berkata; bertakwalah kepada Allah, dan kembalikan wanita tersebut kerumahnya! Kemudian Marwan berkata dalam hadits Sulaiman; sesungguhnya aku tidak mampu mencegah Abdurrahman. Dan Marwan di dalam hadits Al Qasim berkata; tidakkah telah sampai kepadamu permasalahan mengenai Fathimah binti Qais? Aisyah berkata; tidak mengapa engkau tidak mengingat hadits Fathimah. Marwan berkata; apabila menurutmu hal tersebut adalah buruk maka cukuplah bagimu, keburukan yang akan terjadi pada mereka berdua (apabila anak Abdurrahman tinggal di rumah Yahya bin Al 'Ash). "},"1886":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ بْنِ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا جَعْفَرُ بْنُ بُرْقَانَ حَدَّثَنَا مَيْمُونُ بْنُ مِهْرَانَقَالَ قَدِمْتُ الْمَدِينَةَ فَدُفِعْتُ إِلَى سَعِيدِ بْنِ الْمُسَيِّبِ فَقُلْتُ فَاطِمَةُ بِنْتُ قَيْسٍ طُلِّقَتْ فَخَرَجَتْ مِنْ بَيْتِهَا فَقَالَ سَعِيدٌ تِلْكَ امْرَأَةٌ فَتَنَتْ النَّاسَ إِنَّهَا كَانَتْ لَسِنَةً فَوُضِعَتْ عَلَى يَدَيْ ابْنِ أُمِّ مَكْتُومٍ الْأَعْمَى","id":"Telah menceritakan kepada kami [Ahmad bin Abdullah bin Yunus], telah menceritakan kepada kami [Zuhair], telah menceritakan kepada kami [Ja'far bin Burqan], telah menceritakan kepada kami [Maimun bin Mihran], ia berkata; aku datang ke Madinah, kemudian aku didorong untuk pergi kepada [Sa'id bin Al Musayyab], kemudian aku katakan; Fathimah binti Qais dicerai kemudian ia keluar dari rumahnya. Kemudian Sa'id berkata; ia adalah seorang wanita yang mengfitnah manusia, dahulu ia adalah orang yang melukai manusia dengan lisannya, kemudian ia ditempatkan di rumah Ibnu Ummi Maktum orang yang buta. "},"1887":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ ابْنِ جُرَيْجٍ قَالَ أَخْبَرَنِي أَبُو الزُّبَيْرِ عَنْ جَابِرٍ قَالَطُلِّقَتْ خَالَتِي ثَلَاثًا فَخَرَجَتْ تَجُدُّ نَخْلًا لَهَا فَلَقِيَهَا رَجُلٌ فَنَهَاهَا فَأَتَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَتْ ذَلِكَ لَهُ فَقَالَ لَهَا اخْرُجِي فَجُدِّي نَخْلَكِ لَعَلَّكِ أَنْ تَصَدَّقِي مِنْهُ أَوْ تَفْعَلِي خَيْرًا","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal], telah menceritakan kepada kami [Yahya bin Sa'id], dari [Ibnu Juraij], ia berkata; telah mengabarkan kepadaku [Abu Az Zubair] dari [Jabir], ia berkata; bibiku dicerai, kemudian ia keluar untuk memetik buah kurmanya. Kemudian seorang laki-laki bertemu dengannya dan melarangnya. Lalu ia mendatangi Nabi shallallahu 'alaihi wasallam dan menyebutkan hal tersebut kepadanya. Beliau berkata kepadanya; keluarlah dan petiklah buah kurmamu, semoga engkau dapat mensedekahkan sebagian darinya, atau melakukan kebaikan. "},"1888":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ الْمَرْوَزِيُّ حَدَّثَنِي عَلِيُّ بْنُ الْحُسَيْنِ بْنِ وَاقِدٍ عَنْ أَبِيهِ عَنْ يَزِيدَ النَّحْوِيِّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ{ وَالَّذِينَ يُتَوَفَّوْنَ مِنْكُمْ وَيَذَرُونَ أَزْوَاجًا وَصِيَّةً لِأَزْوَاجِهِمْ مَتَاعًا إِلَى الْحَوْلِ غَيْرَ إِخْرَاجٍ }فَنُسِخَ ذَلِكَ بِآيَةِ الْمِيرَاثِ بِمَا فَرَضَ لَهُنَّ مِنْ الرُّبُعِ وَالثُّمُنِ وَنُسِخَ أَجَلُ الْحَوْلِ بِأَنْ جُعِلَ أَجَلُهَا أَرْبَعَةَ أَشْهُرٍ وَعَشْرًا","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad Al Marwazi], telah menceritakan kepadaku [Ali bin Al Husain bin Waqid] dari [ayahnya], dari [Yazid An Nahwi], dari [Ikrimah], dari [Ibnu Abbas]: \"Dan orang-orang yang akan meninggal dunia di antara kamu dan meninggalkan isteri, hendaklah berwasiat untuk isteri-isterinya, (yaitu) diberi nafkah hingga setahun lamanya dan tidak disuruh pindah (dari rumahnya).\" Kemudian hal tersebut dihapus dengan ayat mengenai warisan dengan bagian yang telah Allah tentukan bagi mereka, yaitu seperempat dan seperdelapan. Dan waktunya satu tahun digantikan menjadi empat bulan sepuluh hari. "},"1889":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ عَنْ حُمَيْدِ بْنِ نَافِعٍ عَنْ زَيْنَبَ بِنْتِ أَبِي سَلَمَةَ أَنَّهَا أَخْبَرَتْهُ بِهَذِهِ الْأَحَادِيثِ الثَّلَاثَةِقَالَتْ زَيْنَبُ دَخَلْتُ عَلَى أُمِّ حَبِيبَةَ حِينَ تُوُفِّيَ أَبُوهَا أَبُو سُفْيَانَ فَدَعَتْ بِطِيبٍ فِيهِ صُفْرَةٌ خَلُوقٌ أَوْ غَيْرُهُ فَدَهَنَتْ مِنْهُ جَارِيَةً ثُمَّ مَسَّتْ بِعَارِضَيْهَا ثُمَّ قَالَتْ وَاللَّهِ مَا لِي بِالطِّيبِ مِنْ حَاجَةٍ غَيْرَ أَنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَحِلُّ لِامْرَأَةٍ تُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ أَنْ تُحِدَّ عَلَى مَيِّتٍ فَوْقَ ثَلَاثِ لَيَالٍ إِلَّا عَلَى زَوْجٍ أَرْبَعَةَ أَشْهُرٍ وَعَشْرًا","id":"Telah menceritakan kepada kami [Al Qa'nabi], dari [Malik] dari [Abdullah bin Abu Bakr] dari [Humaid bin Nafi'] dari [Zainab binti Abu Salamah] bahwa ia telah mengabarkan kepadanya dengan ketiga hadits ini. Zainab berkata; aku menemui [Ummu Habibah] ketika ayahnya meninggal yaitu Abu Sufyan dengan memakai minyak wangi berwarna kuning atau yang lainnya. Kemudian ia meminyaki seorang budak wanita, kemudian ia mengusap kedua belah pipinya dan berkata; demi Allah, aku tidak butuh kepada minyak wangi, hanya saja kau mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak halal bagi seorang wanita yang beriman kepada Allah dan Hari Akhir untuk berkabung terhadap mayyit melebihi tiga malam, kecuali terhadap suami yaitu empat bulan sepuluh hari.\""},"1890":{"ar":"قَالَتْ زَيْنَبُوَدَخَلْتُ عَلَى زَيْنَبَ بِنْتِ جَحْشٍ حِينَ تُوُفِّيَ أَخُوهَا فَدَعَتْ بِطِيبٍ فَمَسَّتْ مِنْهُ ثُمَّ قَالَتْ وَاللَّهِ مَا لِي بِالطِّيبِ مِنْ حَاجَةٍ غَيْرَ أَنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ وَهُوَ عَلَى الْمِنْبَرِ لَا يَحِلُّ لِامْرَأَةٍ تُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ أَنْ تُحِدَّ عَلَى مَيِّتٍ فَوْقَ ثَلَاثِ لَيَالٍ إِلَّا عَلَى زَوْجٍ أَرْبَعَةَ أَشْهُرٍ وَعَشْرًا","id":"(\nTelah menceritakan kepada kami [Al Qa'nabi], dari [Malik] dari [Abdullah bin Abu Bakr] dari [Humaid bin Nafi'] dari [Zainab] berkata; dan aku menemui [Zainab binti Jahsy] ketika saudaranya meninggal, lalu ia meminta minyak wangi dan mengusapkan sebagian darinya, kemudian ia berkata; demi Allah, aku tidak butuh kepada minyak wangi, hanya saja aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda ketika berada di atas mimbar: \"Tidak halal bagi seorang wanita yang beriman kepada Allah dan Hari Akhir untuk berkabung terhadap mayyit melebihi tiga malam, kecuali terhadap suaminya yaitu empat bulan sepuluh hari.\""},"1891":{"ar":"قَالَتْ زَيْنَبُ وَسَمِعْتُ أُمِّي أُمَّ سَلَمَةَ تَقُولُجَاءَتْ امْرَأَةٌ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنَّ ابْنَتِي تُوُفِّيَ عَنْهَا زَوْجُهَا وَقَدْ اشْتَكَتْ عَيْنَهَا أَفَنَكْحَلُهَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا مَرَّتَيْنِ أَوْ ثَلَاثًا كُلُّ ذَلِكَ يَقُولُ لَا ثُمَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا هِيَ أَرْبَعَةُ أَشْهُرٍ وَعَشْرٌ وَقَدْ كَانَتْ إِحْدَاكُنَّ فِي الْجَاهِلِيَّةِ تَرْمِي بِالْبَعْرَةِ عَلَى رَأْسِ الْحَوْلِقَالَ حُمَيْدٌ فَقُلْتُ لِزَيْنَبَ وَمَا تَرْمِي بِالْبَعْرَةِ عَلَى رَأْسِ الْحَوْلِ فَقَالَتْ زَيْنَبُ كَانَتْ الْمَرْأَةُ إِذَا تُوُفِّيَ عَنْهَا زَوْجُهَا دَخَلَتْ حِفْشًا وَلَبِسَتْ شَرَّ ثِيَابِهَا وَلَمْ تَمَسَّ طِيبًا وَلَا شَيْئًا حَتَّى تَمُرَّ بِهَا سَنَةٌ ثُمَّ تُؤْتَى بِدَابَّةٍ حِمَارٍ أَوْ شَاةٍ أَوْ طَائِرٍ فَتَفْتَضُّ بِهِ فَقَلَّمَا تَفْتَضُّ بِشَيْءٍ إِلَّا مَاتَ ثُمَّ تَخْرُجُ فَتُعْطَى بَعْرَةً فَتَرْمِي بِهَا ثُمَّ تُرَاجِعُ بَعْدُ مَا شَاءَتْ مِنْ طِيبٍ أَوْ غَيْرِهِ قَالَ أَبُو دَاوُد الْحِفْشُ بَيْتٌ صَغِيرٌ","id":"Telah menceritakan kepada kami [Al Qa'nabi], dari [Malik] dari [Abdullah bin Abu Bakr] dari [Humaid bin Nafi'] dari  [Zainab] berkata; dan saya mendengar [Ibuku yaitu Ummu Salamah] berkata; seorang wanita telah datang kepada Rasulullah shallallahu 'alaihi wasallam dan berakata; wahai Rasulullah, sesungguhnya anak wanitaku telah ditinggal mati suaminya dan ia sedang sakit mata, apakah aku boleh untuk mencelakinya? Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya 'Iddah itu empat bulan sepuluh hari dan salah satu dari mereka dilempari kotoran binatang di penghujung tahun.\" Humaid berkata; kemudian saya katakan kepada Zainab; kenapa ia melempar kotoran binatang pada penghujung tahun? Zainab berkata; seorang wanita apabila ditinggal mati suaminya ia masuk ke rumah kecil dan buruk, memakai pakaian yang terburuk serta tidak mengusap minyak wangi atau apapun hingga lewat satu tahun. Kemudian didatangkan kepadanya binatang, keledai atau kambing atau burung kemudian ia memegangnya, jarang sekali ia menyentuh sesuatu kecuali sesuatu tersebut akan mati. Kemudian ia keluar dan diberi kotoran binatang kemudian ia melemparkannya dan kembali memakai setelah itu apa saja yang ia kehendaki berupa minyak wangi atau yang lainnya. Abu Daud berkata; Hifsy adalah rumah kecil."},"1892":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ سَعْدِ بْنِ إِسْحَقَ بْنِ كَعْبِ بْنِ عَجْرَةَ عَنْ عَمَّتِهِ زَيْنَبَ بِنْتِ كَعْبِ بْنِ عَجْرَةَ أَنَّ الْفُرَيْعَةَ بِنْتَ مَالِكِ بْنِ سِنَانٍ وَهِيَ أُخْتُ أَبِي سَعِيدٍ الْخُدْرِيِّأَخْبَرَتْهَا أَنَّهَا جَاءَتْ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَسْأَلُهُ أَنْ تَرْجِعَ إِلَى أَهْلِهَا فِي بَنِي خُدْرَةَ فَإِنَّ زَوْجَهَا خَرَجَ فِي طَلَبِ أَعْبُدٍ لَهُ أَبَقُوا حَتَّى إِذَا كَانُوا بِطَرَفِ الْقَدُومِ لَحِقَهُمْ فَقَتَلُوهُ فَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ أَرْجِعَ إِلَى أَهْلِي فَإِنِّي لَمْ يَتْرُكْنِي فِي مَسْكَنٍ يَمْلِكُهُ وَلَا نَفَقَةٍ قَالَتْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَعَمْ قَالَتْ فَخَرَجْتُ حَتَّى إِذَا كُنْتُ فِي الْحُجْرَةِ أَوْ فِي الْمَسْجِدِ دَعَانِي أَوْ أَمَرَ بِي فَدُعِيتُ لَهُ فَقَالَ كَيْفَ قُلْتِ فَرَدَدْتُ عَلَيْهِ الْقِصَّةَ الَّتِي ذَكَرْتُ مِنْ شَأْنِ زَوْجِي قَالَتْ فَقَالَ امْكُثِي فِي بَيْتِكِ حَتَّى يَبْلُغَ الْكِتَابُ أَجَلَهُ قَالَتْ فَاعْتَدَدْتُ فِيهِ أَرْبَعَةَ أَشْهُرٍ وَعَشْرًاقَالَتْ فَلَمَّا كَانَ عُثْمَانُ بْنُ عَفَّانَ أَرْسَلَ إِلَيَّ فَسَأَلَنِي عَنْ ذَلِكَ فَأَخْبَرْتُهُ فَاتَّبَعَهُ وَقَضَى بِهِ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah Al Qa'nabi], dari [Malik] dari [Sa'd bin Ishaq bin Ka'bin bin 'Ajrah] dari [bibinya yaitu Zainab binti Ka'bin bin 'Ajrah] bahwa [Al Furai'ah binti Malik bin Sinan] yang merupakan saudari Abu Sa'id Al Kudri telah mengabarkan kepadanya bahwa ia datang kepada Rasulullah shallallahu 'alaihi wasallam meminta izin kepada beliau untuk kembali kepada keluarganya di antara Bani Khudrah, karena suaminya keluar mencari beberapa budaknya yang melarikan diri hingga setelah mereka berada di Tharaf Al Qadum ia bertemu dengan mereka lalu mereka membunuhnya. Aku meminta izin kepada Rasulullah shallallahu 'alaihi wasallam untuk kembali kepada keluargaku, karena ia tidak meninggalkanku ada dalam tempat tinggal yang ia miliki dan tidak memberikan nafkah. Ia berkata; kemudian aku keluar hingga setelah sampai di sebuah ruangan atau di masjid, beliau memanggilku dan memerintahkan agar aku datang. Kemudian aku beliau berkata: \"Apa yang engkau katakan?\" kemudian aku kembali menyebutkan kisah yang telah saya sebutkan, mengenai keadaan suamiku. Ia berkata; lalu beliau berkata: \"Tinggallah di rumahmu hingga selesai masa 'iddahmu.\" Ia berkata; kemudian aku ber'iddah di tempat tersebut selama empat puluh bulan sepuluh hari. Ia berkata; kemudian tatkala Utsman mengirimkan surat kepadaku, ia bertanya mengenai hal tersebut, lalu aku khabarkan kepadanya, lalu ia mengikutinya dan memberikan keputusan dengannya. "},"1893":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ الْمَرْوَزِيُّ حَدَّثَنَا مُوسَى بْنُ مَسْعُودٍ حَدَّثَنَا شِبْلٌ عَنْ ابْنِ أَبِي نَجِيحٍ قَالَ قَالَ عَطَاءٌ قَالَ ابْنُ عَبَّاسٍنَسَخَتْ هَذِهِ الْآيَةُ عِدَّتَهَا عِنْدَ أَهْلِهَا فَتَعْتَدُّ حَيْثُ شَاءَتْ وَهُوَ قَوْلُ اللَّهِ تَعَالَى{ غَيْرَ إِخْرَاجٍ }قَالَ عَطَاءٌ إِنْ شَاءَتْ اعْتَدَّتْ عِنْدَ أَهْلِهِ وَسَكَنَتْ فِي وَصِيَّتِهَا وَإِنْ شَاءَتْ خَرَجَتْ لِقَوْلِ اللَّهِ تَعَالَى{ فَإِنْ خَرَجْنَ فَلَا جُنَاحَ عَلَيْكُمْ فِيمَا فَعَلْنَ }قَالَ عَطَاءٌ ثُمَّ جَاءَ الْمِيرَاثُ فَنَسَخَ السُّكْنَى تَعْتَدُّ حَيْثُ شَاءَتْ","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad Al Marwazi], telah menceritakan kepada kami [Musa bin Mas'ud], telah menceritakan kepada kami [Syibl] dari [Ibnu Abu Najih], ia berkata; ['Atho`] berkata; [Ibnu Abbas] berkata; ayat ini menghapus 'iddahnya di rumah keluarganya, kemudian ia ber'iddah di tempat yang ia kehendaki. Hal tersebut adalah firman Allah ta'ala: \"dengan tidak mengeluarkan dari rumahnya.\" 'Atha` berkata; apabila ia menghendaki maka ia ber'iddah di rumah keluarganya dan tinggal dalam wasiatnya, dan apabila ia menghendaki maka ia keluar. Berdasarkan firman Allah ta'ala: \"Akan tetapi jika mereka pindah (sendiri), maka tidak ada dosa bagimu (wali atau waris dari yang meninggal) membiarkan mereka berbuat.\" 'Atha` berkata; kemudian datang ayat mengenai warisan dan menghapuskan pemberian tempat tinggal sehingga ia ber'iddah ditempat yang ia kehendaki. "},"1894":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ الدَّوْرَقِيُّ حَدَّثَنَا يَحْيَى بْنُ أَبِي بُكَيْرٍ حَدَّثَنَا إِبْرَاهِيمُ بْنُ طَهْمَانَ حَدَّثَنِي هِشَامُ بْنُ حَسَّانَ ح و حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْجَرَّاحِ الْقُهِسْتَانِيُّ عَنْ عَبْدِ اللَّهِ يَعْنِي ابْنَ بَكْرٍ السَّهْمِيَّ عَنْ هِشَامٍ وَهَذَا لَفْظُ ابْنِ الْجَرَّاحِ عَنْ حَفْصَةَ عَنْ أُمِّ عَطِيَّةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تُحِدُّ الْمَرْأَةُ فَوْقَ ثَلَاثٍ إِلَّا عَلَى زَوْجٍ فَإِنَّهَا تُحِدُّ عَلَيْهِ أَرْبَعَةَ أَشْهُرٍ وَعَشْرًا وَلَا تَلْبَسُ ثَوْبًا مَصْبُوغًا إِلَّا ثَوْبَ عَصْبٍ وَلَا تَكْتَحِلُ وَلَا تَمَسُّ طِيبًا إِلَّا أَدْنَى طُهْرَتِهَا إِذَا طَهُرَتْ مِنْ مَحِيضِهَا بِنُبْذَةٍ مِنْ قُسْطٍ أَوْ أَظْفَارٍ قَالَ يَعْقُوبُ مَكَانَ عَصْبٍ إِلَّا مَغْسُولًا وَزَادَ يَعْقُوبُ وَلَا تَخْتَضِبُحَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ وَمَالِكُ بْنُ عَبْدِ الْوَاحِدِ الْمِسْمَعِيُّ قَالَا حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ عَنْ هِشَامٍ عَنْ حَفْصَةَ عَنْ أُمِّ عَطِيَّةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذَا الْحَدِيثِ وَلَيْسَ فِي تَمَامِ حَدِيثِهِمَا قَالَ الْمِسْمَعِيُّ قَالَ يَزِيدُ وَلَا أَعْلَمُهُ إِلَّا قَالَ فِيهِ وَلَا تَخْتَضِبُ وَزَادَ فِيهِ هَارُونُ وَلَا تَلْبَسُ ثَوْبًا مَصْبُوغًا إِلَّا ثَوْبَ عَصْبٍ","id":"Telah menceritakan kepada kami [Ya'qub bin Ibrahim Ad Dauraqi], telah menceritakan kepada kami [Yahya bin Abu Bukair], telah menceritakan kepada kami [Ibrahim bin Thahman] telah menceritakan kepadaku [Hisyam bin Hassan], dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Abdullah bin Al Jarrah Al Quhistani], dari [Abdullah bin Bakr As Sahmi], dari [Hisyam], dan ini adalah lafazh Ibnu Al Jarrah, dari [Hafshah] dari [Ummu 'Athiyyah] bahwa Nabi shallallahu 'alaihi wasallam berkata; tidak boleh seorang wanita ber'iddah di atas tiga hari kecuali terhadap suami, maka ia ber'iddah terhadapnya selama empat bulan sepuluh hari, dan tidak memakai baju yang dicelup kecuali kain serban, dan ia tidak memakai celak, serta tidak mengusap minyak wangi, kecuali ketika mendekati kesuciannya apabila ia telah bersuci dari haidnya menggunakan sepotong kayu gaharu atau minyak wangi. Abu Ya'qub berkata; tempat serban, kecuali yang dicuci. Ya'qub menambahkan; dan tidak boleh memakai semir. Telah menceritakan kepada kami [Harun bin Abdullah], serta [Malik bin Abdul Wahid Al Misma'i], mereka berkata; telah menceritakan kepada kami [Yazid bin Harun] dari [Hisyam] dari [Hafshah] dari [Ummu 'Athiyyah] dari Nabi shallallahu 'alaihi wasallam dengan hadits ini dan bukan pada kelanjutan hadits keduanya. Al Masma'i berkata; Yazid berkata; dan aku tidak mengetahuinya kecuali ia berkata dalam hadits tersebut; dan tidak boleh ia memakai semir. Dan Harun menambahkan padanya; dan tidak boleh memakai pakaian yang dicelup kecuali kain serban. "},"1895":{"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا يَحْيَى بْنُ أَبِي بُكَيْرٍ حَدَّثَنَا إِبْرَاهِيمُ بْنُ طَهْمَانَ حَدَّثَنِي بُدَيْلٌ عَنْ الْحَسَنِ بْنِ مُسْلِمٍ عَنْ صَفِيَّةَ بِنْتِ شَيْبَةَ عَنْ أُمِّ سَلَمَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ الْمُتَوَفَّى عَنْهَا زَوْجُهَا لَا تَلْبَسُ الْمُعَصْفَرَ مِنْ الثِّيَابِ وَلَا الْمُمَشَّقَةَ وَلَا الْحُلِيَّ وَلَا تَخْتَضِبُ وَلَا تَكْتَحِلُ","id":"Telah menceritakan kepada kami [Zuhair bin Harb], Telah menceritakan kepada kami [Yahya bin Abu Bukair], telah menceritakan kepada kami [Ibrahim bin Thahman], telah menceritakan kepadaku [Budail] dari [Al Hasan bin Muslim], dari [Shafiyyah binti Syaibah] dari [Ummu Salamah] isteri Nabi shallallahu 'alaihi wasallam dari Nabi shallallahu 'alaihi wasallam bahwa beliau berkata: \"Seorang wanita yang ditinggal mati suaminya tidak boleh memakai pakaian yang diwarnai dengan warna kuning kemerahan, pakaian yang diwarnai dengan tanah liat merah, perhiasan, serta tidak tidak boleh memakai semir dan celak.\""},"1896":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي مَخْرَمَةُ عَنْ أَبِيهِ قَالَ سَمِعْتُ الْمُغِيرَةَ بْنَ الضَّحَّاكِ يَقُولُ أَخْبَرَتْنِي أُمُّ حَكِيمٍ بِنْتُ أَسِيدٍ عَنْ أُمِّهَاأَنَّ زَوْجَهَا تُوُفِّيَ وَكَانَتْ تَشْتَكِي عَيْنَيْهَا فَتَكْتَحِلُ بِالْجِلَاءِ قَالَ أَحْمَدُ الصَّوَابُ بِكُحْلِ الْجِلَاءِ فَأَرْسَلَتْ مَوْلَاةً لَهَا إِلَى أُمِّ سَلَمَةَ فَسَأَلَتْهَا عَنْ كُحْلِ الْجِلَاءِ فَقَالَتْ لَا تَكْتَحِلِي بِهِ إِلَّا مِنْ أَمْرٍ لَا بُدَّ مِنْهُ يَشْتَدُّ عَلَيْكِ فَتَكْتَحِلِينَ بِاللَّيْلِ وَتَمْسَحِينَهُ بِالنَّهَارِ ثُمَّ قَالَتْ عِنْدَ ذَلِكَ أُمُّ سَلَمَةَ دَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ تُوُفِّيَ أَبُو سَلَمَةَ وَقَدْ جَعَلْتُ عَلَى عَيْنِي صَبْرًا فَقَالَ مَا هَذَا يَا أُمَّ سَلَمَةَ فَقُلْتُ إِنَّمَا هُوَ صَبْرٌ يَا رَسُولَ اللَّهِ لَيْسَ فِيهِ طِيبٌ قَالَ إِنَّهُ يَشُبُّ الْوَجْهَ فَلَا تَجْعَلِيهِ إِلَّا بِاللَّيْلِ وَتَنْزَعِينَهُ بِالنَّهَارِ وَلَا تَمْتَشِطِي بِالطِّيبِ وَلَا بِالْحِنَّاءِ فَإِنَّهُ خِضَابٌ قَالَتْ قُلْتُ بِأَيِّ شَيْءٍ أَمْتَشِطُ يَا رَسُولَ اللَّهِ قَالَ بِالسِّدْرِ تُغَلِّفِينَ بِهِ رَأْسَكِ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih], telah menceritakan kepada kami [Ibnu Wahb], telah mengabarkan kepadaku [Makhramah] dari [ayahnya], ia berkata; saya mendengar [Al Mughirah bin Adh Dhahhak] berkata; telah mengabarkan kepadaku [Ummu Hakim binti Usaid] dari [ibunya] bahwa [suaminya] telah meninggal dunia dan ia sedang sakit mata, lalu ia bercelak menggunakan itsmid, kemudian ia berkata; janganlah engkau bercelak menggunakannya kecuali karena suatu perkara yang tidak bisa dihindari dan darurat, maka engkau bercelak pada malam hari, dan engkau hilangkan pada siang hari. Kemudian [Ummu Salamah] berkata pada saat itu; Rasulullah shallallahu 'alaihi wasallam pernah menemuiku ketika Abu Salamah meninggal dan aku telah memakai shabir pada mataku. Kemudian beliau berkata; apa ini wahai Ummu Salamah? Lalu aku katakan; itu adalah shabir wahai Rasulullah, tidak ada padanya minyak wangi. Beliau berkata; sesungguhnya itu akan dapat meremajakan wajah, maka janganlah engkau memakainya kecuali pada malam hari, dan menghilangkannya pada siang hari. Dan janganlah engkau bersisir menggunakan minyak wangi serta pacar, karena sesungguhnya hal itu merupakan semir. Ummu Salamah berkata; aku katakan; dengan apakah aku bersisir wahai Rasulullah? Beliau berkata; dengan daun bidara, dengannya menutupi rambutmu. "},"1897":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ الْمَهْرِيُّ أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ حَدَّثَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ عُتْبَةَ أَنَّ أَبَاهُ كَتَبَ إِلَى عُمَرَ بْنِ عَبْدِ اللَّهِ بْنِ الْأَرْقَمِ الزُّهْرِيِّيَأْمُرُهُ أَنْ يَدْخُلَ عَلَى سُبَيْعَةَ بِنْتِ الْحَارِثِ الْأَسْلَمِيَّةِ فَيَسْأَلَهَا عَنْ حَدِيثِهَا وَعَمَّا قَالَ لَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ اسْتَفْتَتْهُ فَكَتَبَ عُمَرُ بْنُ عَبْدِ اللَّهِ إِلَى عَبْدِ اللَّهِ بْنِ عُتْبَةَ يُخْبِرُهُ أَنَّ سُبَيْعَةَ أَخْبَرَتْهُ أَنَّهَا كَانَتْ تَحْتَ سَعْدِ بْنِ خَوْلَةَ وَهُوَ مِنْ بَنِي عَامِرِ بْنِ لُؤَيٍّ وَهُوَ مِمَّنْ شَهِدَ بَدْرًا فَتُوُفِّيَ عَنْهَا فِي حَجَّةِ الْوَدَاعِ وَهِيَ حَامِلٌ فَلَمْ تَنْشَبْ أَنْ وَضَعَتْ حَمْلَهَا بَعْدَ وَفَاتِهِ فَلَمَّا تَعَلَّتْ مِنْ نِفَاسِهَا تَجَمَّلَتْ لِلْخُطَّابِ فَدَخَلَ عَلَيْهَا أَبُو السَّنَابِلِ بْنُ بَعْكَكٍ رَجُلٌ مِنْ بَنِي عَبْدِ الدَّارِ فَقَالَ لَهَا مَا لِي أَرَاكِ مُتَجَمِّلَةً لَعَلَّكِ تَرْتَجِينَ النِّكَاحَ إِنَّكِ وَاللَّهِ مَا أَنْتِ بِنَاكِحٍ حَتَّى تَمُرَّ عَلَيْكِ أَرْبَعَةُ أَشْهُرٍ وَعَشْرٌ قَالَتْ سُبَيْعَةُ فَلَمَّا قَالَ لِي ذَلِكَ جَمَعْتُ عَلَيَّ ثِيَابِي حِينَ أَمْسَيْتُ فَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلْتُهُ عَنْ ذَلِكَ فَأَفْتَانِي بِأَنِّي قَدْ حَلَلْتُ حِينَ وَضَعْتُ حَمْلِي وَأَمَرَنِي بِالتَّزْوِيجِ إِنْ بَدَا لِيقَالَ ابْنُ شِهَابٍ وَلَا أَرَى بَأْسًا أَنْ تَتَزَوَّجَ حِينَ وَضَعَتْ وَإِنْ كَانَتْ فِي دَمِهَا غَيْرَ أَنَّهُ لَا يَقْرَبُهَا زَوْجُهَا حَتَّى تَطْهُرَ","id":"Telah menceritakan kepada kami [Sulaiman bin Daud Al Mahri], telah mengabarkan kepada kami [Ibnu Wahb], telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab], telah menceritakan kepadaku ['Ubaidullah bin Abdullah bin 'Utbah] bahwa [ayahnya] menulis surat kepada [Umar bin Abdullah bin Al Arqam Az Zuhri] memerintahkan kepadanya agar menemui [Subai'ah binti Al Harits Al Aslamiyyah], kemudian bertanya kepadanya mengenai haditsnya, dan mengenai apa yang dikatakan Rasulullah shallallahu 'alaihi wasallam kepadanya ketika ia meminta fatwa kepada beliau. Kemudian Umar bin Al Khathab bin Abdullah menulis surat kepada Abdullah bin 'Utbah mengabarkan kepadanya bahwa Subai'ah telah mengabarkan kepadanya bahwa ia dahulu adalah isteri Sa'd bin Haulah sementara ia termasuk diantara Bani 'Amir bin Luai, dan ia termasuk diantara orang-orang yang menghadiri perang Badr. Kemudian ia meninggal pada Haji Wada' sementara Subai'ah sedang hamil, dan tidak lama kemudian ia melahirkan kandungannya setelah kematian suaminya. Kemudian tatkala ia telah selesai dari nifasnya maka ia berhias diri untuk orang-orang yang akan meminang. Kemudian Abu As Sanabil bin Ba'kak yang merupakan seorang laki-laki dari Bani Abdu Ad Dar menemuinya dan berkata; ada apa aku melihatmu berhias diri? Kemungkinan engkau ingin menikah. Demi Allah engkau tidak boleh menikah hingga berlalu empat bulan sepuluh hari. Subai'ah berkata; kemudian tatkala ia mengatakan hal tersebut kepadaku maka aku kumpulkan pakaianku pada sore hari kemudian aku mendatangi Rasulullah shallallahu 'alaihi wasallam dan bertanya kepadanya mengenai hal tersebut. Lalu beliau memberiku fatwa bahwa aku telah halal ketika telah melahirkan kandunganku dan beliau memerintahkanku untuk menikah apabila aku menginginkan. Ibnu Syihab berkata; saya melihat tidak mengapa ia menikah ketika telah melahirkan, walaupun ia masih kena darah hanya saja ia tidak didekati oleh suaminya hingga ia bersih. "},"1898":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ وَمُحَمَّدُ بْنُ الْعَلَاءِ قَالَ عُثْمَانُ حَدَّثَنَا وَقَالَ ابْنُ الْعَلَاءِ أَخْبَرَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا الْأَعْمَشُ عَنْ مُسْلِمٍ عَنْ مَسْرُوقٍ عَنْ عَبْدِ اللَّهِ قَالَمَنْ شَاءَ لَاعَنْتُهُ لَأُنْزِلَتْ سُورَةُ النِّسَاءِ الْقُصْرَى بَعْدَ الْأَرْبَعَةِ الْأَشْهُرِ وَعَشْرًا","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah], dan [Muhammad bin Al 'Ala`], Utsman ia berkata; telah menceritakan kepada kami, dan Ibnu Al 'Ala` berkata; telah mengabarkan kepada kami [Abu Mu'awiyah], telah menceritakan kepada kami [Al A'masy] dari [Muslim] dari [Masruq] dari [Abdullah], ia berkata; barang siapa yang menghendaki maka akan aku ajak ia untuk saling melaknat. Sungguh surat An Nisa` tentang talak telah turun setelah ayat mengenai 'iddah empat bulan dan sepuluh hari. "},"1899":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ أَنَّ مُحَمَّدَ بْنَ جَعْفَرٍ حَدَّثَهُمْ ح و حَدَّثَنَا ابْنُ الْمُثَنَّى حَدَّثَن��ا عَبْدُ الْأَعْلَى عَنْ سَعِيدٍ عَنْ مَطَرٍ عَنْ رَجَاءِ بْنِ حَيْوَةَ عَنْ قَبِيصَةَ بْنِ ذُؤَيْبٍ عَنْ عَمْرِو بْنِ الْعَاصِ قَالَلَا تُلَبِّسُوا عَلَيْنَا سُنَّةً قَالَ ابْنُ الْمُثَنَّى سُنَّةَ نَبِيِّنَا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِدَّةُ الْمُتَوَفَّى عَنْهَا أَرْبَعَةُ أَشْهُرٍ وَعَشْرٌ يَعْنِي أُمَّ الْوَلَدِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] bahwa [Muhammad bin Ja'far] telah menceritakan kepada mereka. Dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Ibnu Al Mutsanna], telah menceritakan kepada kami [Abdul A'la], dari [Sa'id] dari [Mathar] dari [Raja` bin Haiwah], dari [Qabishah bin Dzuaib] dari ['Amr bin Al 'Ash], ia berkata; janganlah kalian kaburkan sunah atas kami! -Ibnu Al Mutsanna berkata; sunah Nabi kita shallallahu 'alaihi wasallam-, 'iddah orang yang wanita yang ditinggal mati suaminya adalah empat bulan sepuluh hari, yang dimaksud adalah Ummu Al Walad (budak wanita yang melahirkan anak tuannya). "},"1900":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ رَجُلٍ طَلَّقَ امْرَأَتَهُ يَعْنِي ثَلَاثًا فَتَزَوَّجَتْ زَوْجًا غَيْرَهُ فَدَخَلَ بِهَا ثُمَّ طَلَّقَهَا قَبْلَ أَنْ يُوَاقِعَهَا أَتَحِلُّ لِزَوْجِهَا الْأَوَّلِ قَالَتْ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَحِلُّ لِلْأَوَّلِ حَتَّى تَذُوقَ عُسَيْلَةَ الْآخَرِ وَيَذُوقَ عُسَيْلَتَهَا","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Ibrahim] dari [Al Aswad], dari [Aisyah], ia berkata; Rasulullah shallallahu 'alaihi wasallam ditanya mengenai seorang laki-laki yang mencerai isterinya tiga kali, kemudian wanita tersebut menikah dengan laki-laki yang lain dan bertemu muka dengannya kemudian ia mencerainya sebelum mencampuri, maka apakah ia halal bagi suaminya yang pertama? Aisyah berkata; tidak. Nabi shallallahu 'alaihi wasallam berkata: \"Ia tidak halal bagi suaminya yang pertama hingga ia merasakan manisnya (hubungan kenikmatan) suaminya yang lain, dan ia (sang suami) juga merasakan manisnya (hubungan kenikmatan dengannya).\""},"1901":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ أَبِي وَائِلٍ عَنْ عَمْرِو بْنِ شُرَحْبِيلَ عَنْ عَبْدِ اللَّهِ قَالَقُلْتُ يَا رَسُولَ اللَّهِ أَيُّ الذَّنْبِ أَعْظَمُ قَالَ أَنْ تَجْعَلَ لِلَّهِ نِدًّا وَهُوَ خَلَقَكَ قَالَ فَقُلْتُ ثُمَّ أَيٌّ قَالَ أَنْ تَقْتُلَ وَلَدَكَ مَخَافَةَ أَنْ يَأْكُلَ مَعَكَ قَالَ قُلْتُ ثُمَّ أَيٌّ قَالَ أَنْ تُزَانِيَ حَلِيلَةَ جَارِكَ قَالَ وَأَنْزَلَ اللَّهُ تَعَالَى تَصْدِيقَ قَوْلِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ وَالَّذِينَ لَا يَدْعُونَ مَعَ اللَّهِ إِلَهًا آخَرَ وَلَا يَقْتُلُونَ النَّفْسَ الَّتِي حَرَّمَ اللَّهُ إِلَّا بِالْحَقِّ وَلَا يَزْنُونَ }الْآيَةَ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir], telah mengabarkan kepada kami [Sufyan] dari [Manshur] dari [Abu Wail], dari ['Amr bin Syarahbil] dari [Abdullah], ia berkata; aku berkata; wahai Rasulullah, dosa apakah yang paling besar? Beliau berkata: \"Engkau jadikan bagi Allah tandingan sementara Dia adalah Yang telah menciptakanmu.\" Abdullah berkata; aku katakan; kemudian apa? Beliau berkata: \"Engkau membunuh anakmu karena khawatir makan bersamamu.\" Ia berkata; aku katakan; kemudian apalagi? Beliau berkata; \"Engkau berzina dengan isteri tetanggamu.\" Ia berkata; dan Allah ta'ala menurunkan pembenaran terhadap perkataan Nabi shallallahu 'alaihi wasallam: \"Dan orang-orang yang tidak menyembah tuhan yang lain beserta Allah dan tidak membunuh jiwa yang diharamkan Allah (membunuhnya) kecuali dengan (alasan) yang benar, dan tidak berzina.\""},"1902":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ إِبْرَاهِيمَ عَنْ حَجَّاجٍ عَنْ ابْنِ جُرَيْجٍ قَالَ وَأَخْبَرَنِي أَبُو الزُّبَيْرِ أَنَّهُ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُجَاءَتْ مِسْكِينَةٌ لِبَعْضِ الْأَنْصَارِ فَقَالَتْ إِنَّ سَيِّدِي يُكْرِهُنِي عَلَى الْبِغَاءِ فَنَزَلَ فِي ذَلِكَ{ وَلَا تُكْرِهُوا فَتَيَاتِكُمْ عَلَى الْبِغَاءِ }","id":"Telah menceritakan kepada kami [Ahmad bin Ibrahim] dari [Hajjaj] dari [Ibnu Juraij], ia berkata; dan telah mengabarkan kepadaku [Abu Az Zubairi] bahwa ia telah mendengar [Jabir bin Abdullah] berkata; seorang wanita miskin milik sebagian orang anshar datang dan berkata; sesungguhnya tuanku telah memaksaku untuk melacur. Kemudian turunlah mengenai hal tersebut, ayat: \"Dan janganlah kalian memaksakan budak-budak wanita kalian untuk melacur!\""},"1903":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا مُعْتَمِرٌ عَنْ أَبِيهِ{ وَمَنْ يُكْرِهُّنَّ فَإِنَّ اللَّهَ مِنْ بَعْدِ إِكْرَاهِهِنَّ غَفُورٌ رَحِيمٌ }قَالَ قَالَ سَعِيدُ بْنُ أَبِي الْحَسَنِ غَفُورٌ لَهُنَّ الْمُكْرَهَاتِ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Mu'adz], dari [Mu'tamir], dari [ayahnya]: \"Dan barangsiapa yang memaksa mereka, maka sesungguhnya Allah adalah Maha Pengampun lagi Maha Penyayang (kepada mereka) sesudah mereka dipaksa itu.\" Ia berkata; [Sa'id bin Abu Al Hasan] berkata; Maha Pengampun kepada para wanita yang dipaksa tersebut. "},"1904":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ شَبُّوَيْهِ حَدَّثَنِي عَلِيُّ بْنُ حُسَيْنِ بْنِ وَاقِدٍ عَنْ أَبِيهِ عَنْ يَزِيدَ النَّحْوِيِّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ{ يَا أَيُّهَا الَّذِينَ آمَنُوا كُتِبَ عَلَيْكُمْ الصِّيَامُ كَمَا كُتِبَ عَلَى الَّذِينَ مِنْ قَبْلِكُمْ }فَكَانَ النَّاسُ عَلَى عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا صَلَّوْا الْعَتَمَةَ حَرُمَ عَلَيْهِمْ الطَّعَامُ وَالشَّرَابُ وَالنِّسَاءُ وَصَامُوا إِلَى الْقَابِلَةِ فَاخْتَانَ رَجُلٌ نَفْسَهُ فَجَامَعَ امْرَأَتَهُ وَقَدْ صَلَّى الْعِشَاءَ وَلَمْ يُفْطِرْ فَأَرَادَ اللَّهُ عَزَّ وَجَلَّ أَنْ يَجْعَلَ ذَلِكَ يُسْرًا لِمَنْ بَقِيَ وَرُخْصَةً وَمَنْفَعَةً فَقَالَ سُبْحَانَهُ{ عَلِمَ اللَّهُ أَنَّكُمْ كُنْتُمْ تَخْتَانُونَ أَنْفُسَكُمْ }الْآيَةَ وَكَانَ هَذَا مِمَّا نَفَعَ اللَّهُ بِهِ النَّاسَ وَرَخَّصَ لَهُمْ وَيَسَّرَ","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad bin Syabbuwaih], telah menceritakan kepadaku [Ali bin Husain bin Waqid] dari [ayahnya] dari [Yazid An Nahwi] dari [Ikrimah] dari [Ibnu Abbas]: \"Hai orang-orang yang beriman, diwajibkan atas kamu berpuasa sebagaimana diwajibkan atas orang-orang sebelum kamu.\" Dahulu orang-orang pada zaman Nabi shallallahu 'alaihi wasallam apabila mereka melakukan Shalat Isya` haram atas mereka untuk makan dan minum serta bercampur dengan isteri, dan mereka berpuasa hingga besok. Kemudian terdapat seseorang tidak dapat menahan hawa nafsunya kemudian ia mencampuri isterinya setelah melakukan Shalat 'Isya` dan belum berbuka. Kemudian Allah 'azza wajalla hendak menjadikan hal tersebut sebagai kemudahan bagi waktu yang selanjutnya serta sebagai keringanan dan manfaat. Allah Yang Maha Suci berfirman: \"Allah mengetahui bahwasanya kamu tidak dapat menahan nafsumu.\" Dan hal ini termasuk diantara manfaat yang Allah berikan kepada manusia dan Allah beri keringanan serta kemudahan bagi mereka. "},"1905":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيِّ بْنِ نَصْرٍ الْجَهْضَمِيُّ أَخْبَرَنَا أَبُو أَحْمَدَ أَخْبَرَنَا إِسْرَائِيلُ عَنْ أَبِي إِسْحَقَ عَنْ الْبَرَاءِ قَالَكَانَ الرَّجُلُ إِذَا صَامَ فَنَامَ لَمْ يَأْكُلْ إِلَى مِثْلِهَا وَإِنَّ صِرْمَةَ بْنَ قَيْسٍ الْأَنْصَارِيَّ أَتَى امْرَأَتَهُ وَكَانَ صَائِمًا فَقَالَ عِنْدَكِ شَيْءٌ قَالَتْ لَا لَعَلِّي أَذْهَبُ فَأَطْلُبُ لَكَ شَيْئًا فَذَهَبَتْ وَغَلَبَتْهُ عَيْنُهُ فَجَاءَتْ فَقَالَتْ خَيْبَةً لَكَ فَلَمْ يَنْتَصِفْ النَّهَارُ حَتَّى غُشِيَ عَلَيْهِ وَكَانَ يَعْمَلُ يَوْمَهُ فِي أَرْضِهِ فَذَكَرَ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَزَلَتْ{ أُحِلَّ لَكُمْ لَيْلَةَ الصِّيَامِ الرَّفَثُ إِلَى نِسَائِكُمْ قَرَأَ إِلَى قَوْلِهِ مِنْ الْفَجْرِ }","id":"Telah menceritakan kepada kami [Nashr bin Ali bin Nashr Al Jahdhami], telah mengabarkan kepada kami [Abu Ahmad], telah mengabarkan kepada kami [Israil] dari [Abu Ishaq], dari [Al Bara`], ia berkata; dahulu seseorang apabila telah berpuasa ia tidur dan tidak makan hingga keesokan hari. Sesungguhnya Shirmah bin Qais Al Anshari datang kepada isterinya dan ia dalam keadaan berpuasa, ia berkata; apakah engkau memiliki sesuatu? Isterinya berkata; tidak, mungkin aku bisa pergi dan mencari sesuatu untukmu. Kemudian ia pergi dan Shirmah telah tertidur, lalu isterinya datang dan berkata; merugi engkau. Kemudian sebelum tengah hari ia pingsan, dan ia pada hari itu sedang bekerja di lahan tanahnya. Kemudian ia menyebutkan hal tersebut kepada Nabi shallallahu 'alaihi wasallam. Kemudian turunlah ayat: \"Dihalalkan bagi kamu pada malam hari bulan puasa bercampur dengan isteri-isteri kamu.\" Beliau membacanya hingga firmannya: \"yaitu fajar.\""},"1906":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا بَكْرٌ يَعْنِي ابْنَ مُضَرَ عَنْ عَمْرِو بْنِ الْحَارِثِ عَنْ بُكَيْرٍ عَنْ يَزِيدَ مَوْلَى سَلَمَةَ عَنْ سَلَمَةَ بْنِ الْأَكْوَعِ قَالَلَمَّا نَزَلَتْ هَذِهِ الْآيَةُ{ وَعَلَى الَّذِينَ يُطِيقُونَهُ فِدْيَةٌ طَعَامُ مِسْكِينٍ }كَانَ مَنْ أَرَادَ مِنَّا أَنْ يُفْطِرَ وَيَفْتَدِيَ فَعَلَ حَتَّى نَزَلَتْ هَذِهِ الْآيَةُ الَّتِي بَعْدَهَا فَنَسَخَتْهَا","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id], Telah menceritakan kepada kami [Bakr bin Mudhar] dari ['Amr bin Al Harits] dari [Bukair] dari [Yazid] mantan budak Salamah bin Al Akwa', dari [Salamah bin Al Akwa] 'ia berkata; tatkala telah turun ayat ini: WA 'ALALLADZII YUTHIIQUUNAHU FIDYATUN THA'AAMU MISKIIN (dan bagi orang yang berat menjalankannya, wajib membayar fidyah, yaitu memberi makan seorang miskin), maka barangsiapa diantara kami yang hendak berbuka dan membayar fidyah, ia boleh melakukannya, hingga turunlah ayat yang setelahnya, dan menggantikan hukum ayat tersebut. "},"1907":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ حَدَّثَنِي عَلِيُّ بْنُ حُسَيْنٍ عَنْ أَبِيهِ عَنْ يَزِيدَ النَّحْوِيِّ عَنْ عِكْرَمَةَ عَنْ ابْنِ عَبَّاسٍ{ وَعَلَى الَّذِينَ يُطِيقُونَهُ فِدْيَةٌ طَعَامُ مِسْكِينٍ }فَكَانَ مَنْ شَاءَ مِنْهُمْ أَنْ يَفْتَدِيَ بِطَعَامِ مِسْكِينٍ افْتَدَى وَتَمَّ لَهُ صَوْمُهُ فَقَالَ{ فَمَنْ تَطَوَّعَ خَيْرًا فَهُوَ خَيْرٌ لَهُ وَأَنْ تَصُومُوا خَيْرٌ لَكُمْ }و قَالَ{ فَمَنْ شَهِدَ مِنْكُمْ الشَّهْرَ فَلْيَصُمْهُ وَمَنْ كَانَ مَرِيضًا أَوْ عَلَى سَفَرٍ فَعِدَّةٌ مِنْ أَيَّامٍ أُخَرَ }","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad], telah menceritakan kepadaku [Ali bin Husain], dari [ayahnya], dari [Yazid An Nahwi] dari [Ikrimah] dari [Ibnu Abbas]: WA 'ALALLADZII YUTHIIQUUNAHU FIDYATUN THA'AAMU MISKIIN (dan bagi orang yang berat menjalankanya, wajib membayar fidyah, yaitu memberi makan seorang miskin), maka barangsiapa diantara mereka yang hendak membayar fidyah dengan memberi makan orang miskin, ia boleh ia membayar fidyah dan telah sempurna baginya puasanya. Kemudian Allah berfirman: \"Barangsiapa yang dengan kerelaan hati mengerjakan kebajikan, maka itulah yang lebih baik baginya. Dan berpuasa lebih baik bagimu jika kamu mengetahui.\" Dan firmanNya: \"barangsiapa di antara kamu hadir (di negeri tempat tinggalnya) di bulan itu, maka hendaklah ia berpuasa pada bulan itu, dan barangsiapa sakit atau dalam perjalanan (lalu ia berbuka), maka (wajiblah baginya berpuasa), sebanyak hari yang ditinggalkannya itu, pada hari-hari yang lain.\""},"1908":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا أَبَانُ حَدَّثَنَا قَتَادَةُ أَنَّ عِكْرِمَةَ حَدَّثَهُ أَنَّ ابْنَ عَبَّاسٍ قَالَأُثْبِتَتْ لِلْحُبْلَى وَالْمُرْضِعِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il], telah menceritakan kepada kami [Aban], telah menceritakan kepada kami [Qatadah] bahwa [Ikrimah] telah menceritakan kepadanya, bahwa [Ibnu Abbas] berkata; fidyah tersebut ditetapkan bagi orang yang hamil dan yang menyusui. "},"1909":{"ar":"حَدَّثَنَا ابْنُ الْمُثَنَّى حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ عَزْرَةَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ{ وَعَلَى الَّذِينَ يُطِيقُونَهُ فِدْيَةٌ طَعَامُ مِسْكِينٍ }قَالَ كَانَتْ رُخْصَةً لِلشَّيْخِ الْكَبِيرِ وَالْمَرْأَةِ الْكَبِيرَةِ وَهُمَا يُطِيقَانِ الصِّيَامَ أَنْ يُفْطِرَا وَيُطْعِمَا مَكَانَ كُلِّ يَوْمٍ مِسْكِينًا وَالْحُبْلَى وَالْمُرْضِعُ إِذَا خَافَتَاقَالَ أَبُو دَاوُد يَعْنِي عَلَى أَوْلَادِهِمَا أَفْطَرَتَا وَأَطْعَمَتَا","id":"Telah menceritakan kepada kami [Ibnu Al Mutsanna], telah menceritakan kepada kami [Ibnu Abu Adi] dari [Sa'id] dari [Qatadah], dari ['Azrah] dari [Sa'id bin Jubair] dari [Ibnu Abbas]: WA 'ALALLADZII YUTHIIQUUNAHU FIDYATUN THA'AAMU MISKIIN (dan bagi orang yang berat menjalankanya, wajib membayar fidyah, yaitu memberi makan seorang miskin), ia berkata; hal tersebut merupakan keringanan bagi laki-laki tua dan wanita tua, dan mereka -sementara kedua mampu melakukan puasa- agar berbuka dan memberi makan setiap hari satu orang miskin, dan keringanan bagi orang yang hamil dan menyusui apabila merasa khawatir. Abu Daud berkata; yaitu khawatir kepada anak mereka berdua, maka mereka berbuka dan memberi makan. "},"1910":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا شُعْبَةُ عَنْ الْأَسْوَدِ بْنِ قَيْسٍ عَنْ سَعِيدِ بْنِ عَمْرٍو يَعْنِي ابْنَ سَعِيدِ بْنِ الْعَاصِ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّا أُمَّةٌ أُمِّيَّةٌ لَا نَكْتُبُ وَلَا نَحْسُبُ الشَّهْرُ هَكَذَا وَهَكَذَا وَهَكَذَا وَخَنَسَ سُلَيْمَانُ أُصْبُعَهُ فِي الثَّالِثَةِ يَعْنِي تِسْعًا وَعِشْرِينَ وَثَلَاثِينَ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb], telah menceritakan kepada kami [Syu'bah] dari [Al Aswad bin Qais] dari [Sa'id bin 'Amr bin Sa'id bin Al 'Ash] dari [Ibnu Umar], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya kami adalah umat yang ummi yang tidak dapat menulis, dan tidak menghitung bulan demikian, demikian dan demikian.\" Dan Sulaiman menggenggam satu jarinya pada hitungan yang ketiga; artinya adalah berjumlah dua puluh sembilan dan tiga puluh. "},"1911":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ الْعَتَكِيُّ حَدَّثَنَا حَمَّادٌ حَدَّثَنَا أَيُّوبُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الشَّهْرُ تِسْعٌ وَعِشْرُونَ فَلَا تَصُومُوا حَتَّى تَرَوْهُ وَلَا تُفْطِرُوا حَتَّى تَرَوْهُ فَإِنْ غُمَّ عَلَيْكُمْ فَاقْدُرُوا لَهُ ثَلَاثِينَقَالَ فَكَانَ ابْنُ عُمَرَ إِذَا كَانَ شَعْبَانُ تِسْعًا وَعِشْرِينَ نَظَرَ لَهُ فَإِنْ رُئِيَ فَذَاكَ وَإِنْ لَمْ يُرَ وَلَمْ يَحُلْ دُونَ مَنْظَرِهِ سَحَابٌ وَلَا قَتَرَةٌ أَصْبَحَ مُفْطِرًا فَإِنْ حَالَ دُونَ مَنْظَرِهِ سَحَابٌ أَوْ قَتَرَةٌ أَصْبَحَ صَائِمًا قَالَ فَكَانَ ابْنُ عُمَرَ يُفْطِرُ مَعَ النَّاسِ وَلَا يَأْخُذُ بِهَذَا الْحِسَابِ حَدَّثَنَا حُمَيْدُ بْنُ مَسْعَدَةَ حَدَّثَنَا عَبْدُ الْوَهَّابِ حَدَّثَنِي أَيُّوبُ قَالَ كَتَبَ عُمَرُ بْنُ عَبْدِ الْعَزِيزِ إِلَى أَهْلِ الْبَصْرَةِ بَلَغَنَا عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَ حَدِيثِ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَادَ وَإِنَّ أَحْسَنَ مَا يُقْدَرُ لَهُ أَنَّا إِذَا رَأَيْنَا هِلَالَ شَعْبَانَ لِكَذَا وَكَذَا فَالصَّوْمُ إِنْ شَاءَ اللَّهُ لِكَذَا وَكَذَا إِلَّا أَنْ تَرَوْا الْهِلَالَ قَبْلَ ذَلِكَ","id":"Telah menceritakan kepada kami [Sulaiman bin Daud Al 'Ataki], telah menceritakan kepada kami [Hammad], telah menceritakan kepada kami [Ayyub], dari [Nafi'] dari [Ibnu Umar], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Satu bulan adalah dua puluh sembilan, maka janganlah kalian berpuasa hingga melihatnya dan janganlah berbuka (berhari raya) hingga melihatnya, kemudian apabila tertutup awan maka hitunglah tiga puluh.\" Sulaiman berkata; dan Ibnu Umar apabila Bulan Sya'bah adalah dua puluh sembilan maka ia berpuasa, apabila terlihat maka itulah Ramadhan, dan apabila tidak terlihat dan tidak terhalangi oleh awan serta debu maka pagi harinya ia dalam keadaan berbuka, dan apabila terhalang awan atau debu untuk melihatnya maka di pagi hari dalam keadaan berpuasa. Ia berkata; dan Ibnu Umar berbuka bersama orang-orang dan tidak mengambil perhitungan ini. Telah menceritakan kepada kami [Humaid bin Mas'adah], telah menceritakan kepada kami [Abdul Wahhab], telah menceritakan kepadaku [Ayyub], ia berkata; [Umar bin Abdul Aziz] menulis surat kepada penduduk Bashrah mengatakan; telah sampai kepada kami dari Rasulullah shallallahu 'alaihi wasallam …. Seperti hadits tersebut Ibnu Umar, dari Nabi shallallahu 'alaihi wasallam. Ia menambahkan; dan sesungguhnya sebaik-baik hitungan adalah apabila kami melihat Hilal Sya'ban demikian dan demikian maka puasa insya Allah demikian dan demikian, kecuali apabila kalian melihat Hilal sebelum itu. "},"1912":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ عَنْ ابْنِ أَبِي زَائِدَةَ عَنْ عِيسَى بْنِ دِينَارٍ عَنْ أَبِيهِ عَنْ عَمْرِو بْنِ الْحَارِثِ بْنِ أَبِي ضِرَارٍ عَنْ ابْنِ مَسْعُودٍ قَالَلَمَا صُمْنَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تِسْعًا وَعِشْرِينَ أَكْثَرَ مِمَّا صُمْنَا مَعَهُ ثَلَاثِينَ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] dari [Ibnu Abu Zaidah], dari [Isa bin Dinar] dari [ayahnya], dari ['Amr bin Al Harits bin Abu Dhirar] dari [Ibnu Mas'ud], ia berkata; sungguh kami berpuasa bersama Nabi shallallahu 'alaihi wasallam dua puluh sembilan hari lebih sering daripada kami berpuasa bersamanya tiga puluh hari. "},"1913":{"ar":"حَدَّثَنَا مُسَدَّدٌ أَنَّ يَزِيدَ بْنَ زُرَيْعٍ حَدَّثَهُمْ حَدَّثَنَا خَالِدٌ الْحَذَّاءُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرَةَ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ شَهْرَا عِيدٍ لَا يَنْقُصَانِ رَمَضَانُ وَذُو الْحِجَّةِ","id":"Telah menceritakan kepada kami [Musaddad] bahwa [Yazid bin Zurai'] telah menceritakan kepada mereka; telah menceritakan kepada kami [Khalid Al Hadzdza`] dari [Abdurrahman bin Abu Bakrah] dari [ayahnya] dari Nabi shallallahu 'alaihi wasallam beliau berkata: \"Dua bulan 'Id tidaklah berkurang (pahalanya) yaitu Bulan Ramadhan (setelahnya adalah 'Idul Fithri), dan Bulan Dzul Hijjah (padanya 'Idul Adlha).\""},"1914":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ حَدَّثَنَا حَمَّادٌ فِي حَدِيثِ أَيُّوبَ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ أَبِي هُرَيْرَةَذَكَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيهِ قَالَ وَفِطْرُكُمْ يَوْمَ تُفْطِرُونَ وَأَضْحَاكُمْ يَوْمَ تُضَحُّونَ وَكُلُّ عَرَفَةَ مَوْقِفٌ وَكُلُّ مِنًى مَنْحَرٌ وَكُلُّ فِجَاجِ مَكَّةَ مَنْحَرٌ وَكُلُّ جَمْعٍ مَوْقِفٌ","id":"Telah menceritakan kepada kami [Muhammad bin 'Ubaid], telah menceritakan kepada kami [Hammad] dalam hadits [Ayyub] dari [Muhammad bin Al Munkadir] dari [Abu Hurairah], Nabi shallallahu 'alaihi wasallam menyebutkan padanya, beliau berkata: \"Dan Fithri kalian adalah hari kalian berbuka, adlha kalian adalah hari kalian menyembelih, dan seluruh 'Arafah adalah tempat berwukuf, seluruh Mina adalah tempat menyembelih, dan seluruh jalan Mekkah adalah tempat untuk menyembelih dan seluruh Muzdalifah adalah tempat wukuf.\""},"1915":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنِي مُعَاوِيَةُ بْنُ صَالِحٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَيْسٍ قَالَ سَمِعْتُ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا تَقُولُكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَحَفَّظُ مِنْ شَعْبَانَ مَا لَا يَتَحَفَّظُ مِنْ غَيْرِهِ ثُمَّ يَصُومُ لِرُؤْيَةِ رَمَضَانَ فَإِنْ غُمَّ عَلَيْهِ عَدَّ ثَلَاثِينَ يَوْمًا ثُمَّ صَامَ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal], telah menceritakan kepadaku [Abdurrahman bin Mahdi], telah menceritakan kepadaku [Mu'awiyah bin Shalih] dari [Abdullah bin Abu Qais], ia berkata; saya mendengar [Aisyah] radliallahu 'anha berkata; Rasulullah shallallahu 'alaihi wasallam memperhatikan Bulan Sya'ban tidak seperti perhatian beliau kepada selainnya, kemudian beliau berpuasa karena melihat Ramadhan, apabila terhalang untuk melihatnya maka beliau menggenapkan bilangan tiga puluh hari kemudian beliau berpuasa. "},"1916":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ الْبَزَّازُ حَدَّثَنَا جَرِيرُ بْنُ عَبْدِ الْحَمِيدِ الضَّبِّيُّ عَنْ مَنْصُورِ بْنِ الْمُعْتَمِرِ عَنْ رِبْعِيِّ بْنِ حِرَاشٍ عَنْ حُذَيْفَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُقَدِّمُوا الشَّهْرَ حَتَّى تَرَوْا الْهِلَالَ أَوْ تُكْمِلُوا الْعِدَّةَ ثُمَّ صُومُوا حَتَّى تَرَوْا الْهِلَالَ أَوْ تُكْمِلُوا الْعِدَّةَقَالَ أَبُو دَاوُد وَرَوَاهُ سُفْيَانُ وَغَيْرُهُ عَنْ مَنْصُورٍ عَنْ رِبْعِيٍّ عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يُسَمِّ حُذَيْفَةَ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah Al Bazzar], telah menceritakan kepada kami [Jarir bin Abdul Hamid Adh Dhabbi] dari [Manshur bin Al Mu'tamir], dari [Rib'i bin Hirasy] dari [Hudzaifah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Janganlah kalian mendahului bulan hingga melihat Hilal, atau kalian menyempurnakan bilangan, kemudian berpuasalah hingga kalian melihat Hilal atau menyempurnakan bilangan.\" Abu Daud berkata; dan hadits tersebut telah diriwayatkan oleh [Sufyan] dan [yang lainnya], dari [Manshur] dari [Rib'i] dari [seorang sahabat Nabi shallallahu 'alaihi wasallam], dan ia tidak menyebutkan Hudzaifah. "},"1917":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا حُسَيْنٌ عَنْ زَائِدَةَ عَنْ سِمَاكٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُقَدِّمُوا الشَّهْرَ بِصِيَامِ يَوْمٍ وَلَا يَوْمَيْنِ إِلَّا أَنْ يَكُونَ شَيْءٌ يَصُومُهُ أَحَدُكُمْ وَلَا تَصُومُوا حَتَّى تَرَوْهُ ثُمَّ صُومُوا حَتَّى تَرَوْهُ فَإِنْ حَالَ دُونَهُ غَمَامَةٌ فَأَتِمُّوا الْعِدَّةَ ثَلَاثِينَ ثُمَّ أَفْطِرُوا وَالشَّهْرُ تِسْعٌ وَعِشْرُونَقَالَ أَبُو دَاوُد رَوَاهُ حَاتِمُ بْنُ أَبِي صَغِيرَةَ وَشُعْبَةُ وَالْحَسَنُ بْنُ صَالِحٍ عَنْ سِمَاكٍ بِمَعْنَاهُ لَمْ يَقُولُوا ثُمَّ أَفْطِرُوا قَالَ أَبُو دَاوُد وَهُوَ حَاتِمُ بْنُ مُسْلِمٍ ابْنُ أَبِي صَغِيرَةَ وَأَبُو صَغِيرَةَ زَوْجُ أُمِّهِ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali], telah menceritakan kepada kami [Husain], dari [Zaidah] dari [Simak] dari [Ikrimah] dari [Ibnu Abbas], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian mendahului bulan dengan puasa satu hari ataupun dua hari, kecuali salah seorang diantara kalian biasa melakukannya, dan janganlah kalian berpuasa hingga melihatnya (hilal), kemudian berpuasalah hingga kalian melihatnya. Kemudian apabila terhalang oleh awan maka sempurnakan hitungan menjadi tiga puluh hari. Kemudian berbukalah! Satu bulan adalah dua puluh sembilan.\" Abu Daud berkata; hadits tersebut diriwayatkan oleh [Hatim bin Abu Shaghirah] serta [Syu'bah], dan [Al Hasan bin Shalih] dari [Simak] semakna dengannya, mereka tidak mengatakan; kemudian berbukalah! Abu Daud berkata; ia adalah Hatim bin Muslim anak Abu Shaghirah, sementara Abu Shaghirah adalah suami ibunya. "},"1918":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ ثَابِتٍ عَنْ مُطَرِّفٍ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ وَسَعِيدٍ الْجُرَيْرِيِّ عَنْ أَبِي الْعَلَاءِ عَنْ مُطَرِّفٍ عَنْ عِمْرَانَ بْنِ حُصَيْنٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِرَجُلٍ هَلْ صُمْتَ مِنْ شَهْرِ شَعْبَانَ شَيْئًا قَالَ لَا قَالَ فَإِذَا أَفْطَرْتَ فَصُمْ يَوْمًا وَقَالَ أَحَدُهُمَا يَوْمَيْنِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il], telah menceritakan kepada kami [Hammad] dari [Tsabit] dari [Mutharrif] dari ['Imran bin Hushain] serta [Sa'id Al Jurairi], dari [Abu Al 'Ala`], dari [Mutharrif] dari [Imran bin Hushain] bahwa Rasulullah shallallahu 'alaihi wasallam berkata kepada seorang laki-laki; apakah engkau berpuasa pada Bulan Sya'ban? Ia berkata; tidak. Beliau berkata; apabila engkau berbuka maka berpuasalah satu hari. Salah seorang diantara mereka berdua mengatakan; dua hari. "},"1919":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْعَلَاءِ الزُّبَيْدِيُّ مِنْ كِتَابِهِ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْعَلَاءِ عَنْ أَبِي الْأَزْهَرِ الْمُغِيرَةِ بْنِ فَرْوَةَ قَالَقَامَ مُعَاوِيَةُ فِي النَّاسِ بِدَيْرِ مِسْحَلٍ الَّذِي عَلَى بَابِ حِمْصَ فَقَالَ أَيُّهَا النَّاسُ إِنَّا قَدْ رَأَيْنَا الْهِلَالَ يَوْمَ كَذَا وَكَذَا وَأَنَا مُتَقَدِّمٌ فَمَنْ أَحَبَّ أَنْ يَفْعَلَهُ فَلْيَفْعَلْهُ قَالَ فَقَامَ إِلَيْهِ مَالِكُ بْنُ هُبَيْرَةَ السَّبَئِيُّ فَقَالَ يَا مُعَاوِيَةُ أَشَيْءٌ سَمِعْتَهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمْ شَيْءٌ مِنْ رَأْيِكَ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ صُومُوا الشَّهْرَ وَسِرَّهُحَدَّثَنَا سُلَيْمَانُ بْنُ عَبْدِ الرَّحْمَنِ الدِّمَشْقِيُّ فِي هَذَا الْحَدِيثِ قَالَ قَالَ الْوَلِيدُ سَمِعْتُ أَبَا عَمْرٍو يَعْنِي الْأَوْزَاعِيَّ يَقُولُ سِرُّهُ أَوَّلُهُ حَدَّثَنَا أَحْمَدُ بْنُ عَبْدِ الْوَاحِدِ حَدَّثَنَا أَبُو مُسْهِرٍ قَالَ كَانَ سَعِيدٌ يَعْنِي ابْنَ عَبْدِ الْعَزِيزِ يَقُولُ سِرُّهُ أَوَّلُهُ قَالَ أَبُو دَاوُد وَقَالَ بَعْضُهُمْ سِرُّهُ وَسَطُهُ وَقَالُوا آخِرُهُ","id":"Telah menceritakan kepada kami [Ibrahim bin Al 'Ala` Az Zubaidi] dari kitabnya, telah menceritakan kepada kami [Al Walid bin Muslim], telah menceritakan kepada kami [Abdullah bin Al 'Ala`], dari [Abu Al Azhar Al Mughirah bin Firwah], ia berkata; [Mu'awiyah] berdiri diantara orang-orang di Dair Mishal yang berada di depan pintu Himsh, ia berkata; wahai para manusia; sesungguhnya kami telah melihat Hilal pada hari ini dan ini, dan aku akan mendahului. Barang siapa yang ingin melakukannya maka hendaknya ia melakukannya. Al Mughirah berkata; kemudian Malik bin Hubairah As Sabai berdiri di sampingnya dan berkata; wahai Mu'awiyah, apakah hal tersebut sesuatu yang engkau dengar dari Rasulullah shallallahu 'alaihi wasallam atau sesuatu yang berasal dari pendapatmu? Ia berkata; aku mendengarnya dari Rasulullah shallallahu wa'alaihi wa sallam. Mereka berkata; berpuasalah pada bulan tersebut dan sirrnya (awalnya). Telah menceritakan kepada kami Sulaiman bin Abdurrahman Ad Dimasyqi, mengenai hadits ini, ia berkata; Al Walid berkata; saya mendengar Abu 'Amr Al Auza'i berkata; sirrnya yaitu awalnya. Abu Daud berkata; sebagian mereka mengatakan sirrnya adalah pertengahannya, sedangkan yang lain mengatakan; akhirnya. "},"1920":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا إِسْمَعِيلُ يَعْنِي ابْنَ جَعْفَرٍ أَخْبَرَنِي مُحَمَّدُ بْنُ أَبِي حَرْمَلَةَ أَخْبَرَنِي كُرَيْبٌأَنَّ أُمَّ الْفَضْلِ ابْنَةَ الْحَارِثِ بَعَثَتْهُ إِلَى مُعَاوِيَةَ بِالشَّامِ قَالَ فَقَدِمْتُ الشَّامَ فَقَضَيْتُ حَاجَتَهَا فَاسْتَهَلَّ رَمَضَانُ وَأَنَا بِالشَّامِ فَرَأَيْنَا الْهِلَالَ لَيْلَةَ الْجُمُعَةِ ثُمَّ قَدِمْتُ الْمَدِينَةَ فِي آخِرِ الشَّهْرَ فَسَأَلَنِي ابْنُ عَبَّاسٍ ثُمَّ ذَكَرَ الْهِلَالَ فَقَالَ مَتَى رَأَيْتُمْ الْهِلَالَ قُلْتُ رَأَيْتُهُ لَيْلَةَ الْجُمُعَةِ قَالَ أَنْتَ رَأَيْتَهُ قُلْتُ نَعَمْ وَرَآهُ النَّاسُ وَصَامُوا وَصَامَ مُعَاوِيَةُ قَالَ لَكِنَّا رَأَيْنَاهُ لَيْلَةَ السَّبْتِ فَلَا نَزَالُ نَصُومُهُ حَتَّى نُكْمِلَ الثَّلَاثِينَ أَوْ نَرَاهُ فَقُلْتُ أَفَلَا تَكْتَفِي بِرُؤْيَةِ مُعَاوِيَةَ وَصِيَامِهِ قَالَ لَا هَكَذَا أَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Musa bin Isma'il], telah menceritakan kepada kami [Isma'il bin Ja'far], telah mengabarkan kepadaku [Muhammad bin Abu Harmalah], telah mengabarkan kepadaku [Kuraib], bahwa Ummu Al Fadhl binti Al Harits telah mengutusnya pergi kepada Mu'awiyah di Syam. Ia berkata; aku datang ke Syam, dan menunaikan keperluannya, kemudian telah nampak hilal Ramadhan sementara aku berada di Syam. Kami melihat hilal pada malam Jum'at kemudian aku datang ke Madinah pada akhir bulan. Lalu Ibnu Abbas bertanya kepadaku. -kemudian ia menyebutkan hilal. Kemudian [Ibnu Abbas] berkata; kapan kalian melihat hilal? Aku katakan; aku melihatnya pada malam Jum'at. Ia berkata; apakah engkau melihatnya? Aku katakan; ya, dan orang-orang melihatnya. Mereka berpuasa dan Mu'awiyah pun berpuasa. Ibnu Abbas berkata; akan tetapi kami melihatnya pada malam sabtu, dan kami masih berpuasa hingga kami menyempurnakan tiga puluh hari atau kami melihat hilal. Aku katakan; tidakkah engkau cukup dengan (ru`yah) yang dilihat Mu'awiyah dan puasanya? Ia berkata; tidak, demikianlah Rasulullah shallallahu 'alaihi wasallam memerintahkan kami. "},"1921":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنِي أَبِي حَدَّثَنَا الْأَشْعَثُ عَنْ الْحَسَنِفِي رَجُلٍ كَانَ بِمِصْرٍ مِنْ الْأَمْصَارِ فَصَامَ يَوْمَ الِاثْنَيْنِ وَشَهِدَ رَجُلَانِ أَنَّهُمَا رَأَيَا الْهِلَالَ لَيْلَةَ الْأَحَدِ فَقَالَ لَا يَقْضِي ذَلِكَ الْيَوْمَ الرَّجُلُ وَلَا أَهْلُ مِصْرِهِ إِلَّا أَنْ يَعْلَمُوا أَنَّ أَهْلَ مِصْرٍ مِنْ أَمْصَارِ الْمُسْلِمِينَ قَدْ صَامُوا يَوْمَ الْأَحَدِ فَيَقْضُونَهُ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Mu'adz], telah mengabarkan kepada kami [Ayahku] telah menceritakan kepadaku [Al Asy'ats] dari [Al Hasan] mengenai seorang laki-laki yang berada di sebuah negeri diantara beberapa negeri, kemudian ia berpuasa Hari Senin, dan dua orang laki-laki bersaksi bahwa mereka berdua telah melihat hilal pada malam Ahad. Kemudian Al Hasan berkata; tidaklah laki-laki tersebut dan penduduk negerinya mengqadha` hari tersebut kecuali mereka mengetahui bahwa penduduk suatu negeri diantara negeri-negeri muslimin telah melakukan puasa pada hari Ahad, maka mereka mengqadha`nya. "},"1922":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ عَنْ عَمْرِو بْنِ قَيْسٍ عَنْ أَبِي إِسْحَقَ عَنْ صِلَةَ قَالَكُنَّا عِنْدَ عَمَّارٍ فِي الْيَوْمِ الَّذِي يُشَكُّ فِيهِ فَأَتَى بِشَاةٍ فَتَنَحَّى بَعْضُ الْقَوْمِ فَقَالَ عَمَّارٌ مَنْ صَامَ هَذَا الْيَوْمَ فَقَدْ عَصَى أَبَا الْقَاسِمِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair], telah menceritakan kepada kami [Abu Khalid Al Ahmar] dari ['Amr bin Qais] dari [Abu Ishaq], dari [Shilah], ia berkata; kami pernah berada bersama ['Ammar] pada hari yang diragukan, kemudian ia membawa seekor kambing dan sebagian orang menyingkir. Kemudian 'Ammar berkata; barangsiapa yang berpuasa pada hari ini maka sungguh ia telah durhaka kepada Abu Al Qasim (Nabi Muhammad shallallahu 'alaihi wasallam). "},"1923":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تُقَدِّمُوا صَوْمَ رَمَضَانَ بِيَوْمٍ وَلَا يَوْمَيْنِ إِلَّا أَنْ يَكُونَ صَوْمٌ يَصُومُهُ رَجُلٌ فَلْيَصُمْ ذَلِكَ الصَّوْمَ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim], telah menceritakan kepada kami [Hisyam], dari [Yahya bin Abu Katsir] dari [Abu Salamah], dari [Abu Hurairah], dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Janganlah kalian mendahului puasa Ramadhan satu hari atau dua hari, kecuali puasa yang biasa dilakukan oleh seseorang, maka silahkan ia melakukan puasa tersebut!\""},"1924":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ تَوْبَةَ الْعَنْبَرِيِّ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ أَبِي سَلَمَةَ عَنْ أُمِّ سَلَمَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ لَمْ يَكُنْ يَصُومُ مِنْ السَّنَةِ شَهْرًا تَامًّا إِلَّا شَعْبَانَ يَصِلُهُ بِرَمَضَانَ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal], telah menceritakan kepada kami [Muhammad bin Ja'far], telah menceritakan kepada kami [Syu'bah], dari [Taubah Al 'Anbari] dari [Muhammad bin Ibrahim] dari [Abu Salamah] dari [Ummu Salamah] dari Nabi shallallahu 'alaihi wasallam bahwa ia tidak pernah berpuasa sunah satu bulan penuh kecuali Bulan Sya'ban, beliau menyambungnya dengan Ramadhan. "},"1925":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ قَالَقَدِمَ عَبَّادُ بْنُ كَثِيرٍ الْمَدِينَةَ فَمَالَ إِلَى مَجْلِسِ الْعَلَاءِ فَأَخَذَ بِيَدِهِ فَأَقَامَهُ ثُمَّ قَالَ اللَّهُمَّ إِنَّ هَذَا يُحَدِّثُ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا انْتَصَفَ شَعْبَانُ فَلَا تَصُومُوافَقَالَ الْعَلَاءُ اللَّهُمَّ إِنَّ أَبِي حَدَّثَنِي عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِذَلِكَ قَالَ أَبُو دَاوُد رَوَاهُ الثَّوْرِيُّ وَشِبْلُ بْنُ الْعَلَاءِ وَأَبُو عُمَيْسٍ وَزُهَيْرُ بْنُ مُحَمَّدٍ عَنْ الْعَلَاءِ قَالَ أَبُو دَاوُد وَكَانَ عَبْدُ الرَّحْمَنِ لَا يُحَدِّثُ بِهِ قُلْتُ لِأَحْمَدَ لِمَ قَالَ لِأَنَّهُ كَانَ عِنْدَهُ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَصِلُ شَعْبَانَ بِرَمَضَانَ وَقَالَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خِلَافَهُ قَالَ أَبُو دَاوُد وَلَيْسَ هَذَا عِنْدِي خِلَافُهُ وَلَمْ يَجِئْ بِهِ غَيْرُ الْعَلَاءِ عَنْ أَبِيهِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id], telah menceritakan kepada kami [Abdul Aziz bin Muhammad], ia berkata; 'Abbad bin Katsir datang ke Madinah kemudian ia datang ke Majelis Al 'Ala` dan menggandeng tangannya dan mengajaknya berdiri, kemudian berkata; ya Allah, orang ini telah menceritakan dari [ayahnya] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam berkata: \"Apabila telah berlalu setengah dari bulan Sya'ban, maka janganlah kalian berpuasa!\" kemudian [Al 'Ala`] berkata; ya Allah, sesungguhnya [ayahku] telah menceritakan kepadaku dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam seperti itu. Abu Daud berkata; hadits tersebut diriwayatkan oleh [Ats Tsuri], [Syibl bin Al 'Ala`], [Abu 'Umais], serta [Zuhair bin Muhammad], dari [Al 'Ala`]. Abu Daud berkata; dan Abdurrahman tidak menceritakannya. Aku katakan kepada Ahmad; mengapa ia mengatakan menurutnya bahwa Nabi shallallahu 'alaihi wasallam menyambung Sya'ban dengan Ramadhan sementara Abu Hurairah mengatakan dari Nabi shallallahu 'alaihi wasallam sesuatu yang menyelisihinya? Abu Daud berkata; menurutku hal ini tidaklah menyelisihinya, dan tidak ada yang meriwayatkannya selain Al 'Ala` dari ayahnya."},"1926":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحِيمِ أَبُو يَحْيَى الْبَزَّازُ حَدَّثَنَا سَعِيدُ بْنُ سُلَيْمَانَ حَدَّثَنَا عَبَّادٌ عَنْ أَبِي مَالِكٍ الْأَشْجَعِيِّ حَدَّثَنَا حُسَيْنُ بْنُ الْحَارِثِ الْجَدَلِيُّ مِنْ جَدِيلَةَ قَيْسٍأَنَّ أَمِيرَ مَكَّةَ خَطَبَ ثُمَّ قَالَ عَهِدَ إِلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نَنْسُكَ لِلرُّؤْيَةِ فَإِنْ لَمْ نَرَهُ وَشَهِدَ شَاهِدَا عَدْلٍ نَسَكْنَا بِشَهَادَتِهِمَا فَسَأَلْتُ الْحُسَيْنَ بْنَ الْحَارِثِ مَنْ أَمِيرُ مَكَّةَ قَالَ لَا أَدْرِي ثُمَّ لَقِيَنِي بَعْدُ فَقَالَ هُوَ الْحَارِثُ بْنُ حَاطِبٍ أَخُو مُحَمَّدِ بْنِ حَاطِبٍ ثُمَّ قَالَ الْأَمِيرُ إِنَّ فِيكُمْ مَنْ هُوَ أَعْلَمُ بِاللَّهِ وَرَسُولِهِ مِنِّي وَشَهِدَ هَذَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَوْمَأَ بِيَدِهِ إِلَى رَجُلٍ قَالَ الْحُسَيْنُ فَقُلْتُ لِشَيْخٍ إِلَى جَنْبِي مَنْ هَذَا الَّذِي أَوْمَأَ إِلَيْهِ الْأَمِيرُ قَالَ هَذَا عَبْدُ اللَّهِ بْنُ عُمَرَ وَصَدَقَ كَانَ أَعْلَمَ بِاللَّهِ مِنْهُ فَقَالَ بِذَلِكَ أَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Abdurrahim Abu Yahya Al Bazzaz], telah menceritakan kepada kami [Sa'id bin Sulaiman], telah menceritakan kepada kami ['Abbad], dari [Abu Malik Al Asyja'i], telah menceritakan kepada kami [Husain bin Al Harits Al Jadali] yang berasal dari Jadilah Qais, bahwa Amir Mekkah telah berkhutbah, ia berkata; Rasulullah shallallahu 'alaihi wasallam berwasiat kepada kami agar berkurban ketika melihat hilal, dan apabila kami tidak melihatnya dan terdapat dua orang adil yang bersaksi maka kami berkurban dengan persaksian mereka berdua. Kemudian aku bertanya kepada Al Husain bin Al Harits, siapakah Amir Mekkah tersebut? Ia berkata; saya tidak tahu. Kemudian ia bertemu denganku setelah itu dan berkata; ia adalah [Al Harits bin Hathib] saudara Muhammad bin Hathib. Kemudian Amir tersebut berkata; sesungguhnya diantara kalian terdapat orang yang lebih mengetahui mengenai Allah dan rasulNya daripada diriku. Dan orang ini telah menyaksikan hal ini dari Rasulullah shallallahu wa'alaihi wa sallam. Amir tersebut menunjuk dengan tangannya kepada seorang laki-laki. Al Husain berkata; aku bertanya kepada orang tua yang ada di sampingku; siapakah orang yang ditunjuk oleh Amir tersebut? Ia berkata; orang ini adalah Abdullah bin Umar, dan Amir tersebut benar. Ia adalah orang yang lebih tahu mengenai Allah daripada dirinya. Ibnu Umar berkata; demikianlah Rasulullah shallallahu 'alaihi wasallam memerintahkan kami. "},"1927":{"ar":"حَدَّثَنَا مُسَدَّدٌ وَخَلَفُ بْنُ هِشَامٍ الْمُقْرِئُ قَالَا حَدَّثَنَا أَبُو عَوَانَةَ عَنْ مَنْصُورٍ عَنْ رِبْعِيِّ بْنِ حِرَاشٍ عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَاخْتَلَفَ النَّاسُ فِي آخِرِ يَوْمٍ مِنْ رَمَضَانَ فَقَدِمَ أَعْرَابِيَّانِ فَشَهِدَا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِاللَّهِ لَأَهَلَّا الْهِلَالَ أَمْسِ عَشِيَّةً فَأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ النَّاسَ أَنْ يُفْطِرُوا زَادَ خَلَفٌ فِي حَدِيثِهِ وَأَنْ يَغْدُوا إِلَى مُصَلَّاهُمْ","id":"Telah menceritakan kepada kami [Musaddad], serta [Khalaf bin Hisyam Al Muqri`], mereka berkata; telah menceritakan kepada kami [Abu 'Awanah] dari [Manshur] dari [Rib'i bin Hirasy] dari [seorang sahabat Nabi shallallahu 'alaihi wasallam], ia berkata; orang-orang berselisih mengenai akhir hari Ramadhan. Kemudian terdapat dua orang badui yang datang dan memberikan persaksian di hadapan Nabi shallallahu 'alaihi wasallam dengan nama Allah, sungguh mereka telah menyaksikan Hilal kemarin sore. Kemudian Rasulullah shallallahu 'alaihi wasallam memerintahkan orang-orang agar berbuka. Khalaf menambahkan dalam haditsnya; dan agar mereka pergi ke lapangan. "},"1928":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَكَّارِ بْنِ الرَّيَّانِ حَدَّثَنَا الْوَلِيدُ يَعْنِي ابْنَ أَبِي ثَوْرٍ ح و حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا الْحُسَيْنُ يَعْنِي الْجُعْفِيَّ عَنْ زَائِدَةَ الْمَعْنَى عَنْ سِمَاكٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَجَاءَ أَعْرَابِيٌّ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنِّي رَأَيْتُ الْهِلَالَ قَالَ الْحَسَنُ فِي حَدِيثِهِ يَعْنِي رَمَضَانَ فَقَالَ أَتَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ قَالَ نَعَمْ قَالَ أَتَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ قَالَ نَعَمْ قَالَ يَا بِلَالُ أَذِّنْ فِي النَّاسِ فَلْيَصُومُوا غَدًا","id":"Telah menceritakan kepada kami [Muhammad bin Bakkar bin Ar Rayyan], telah menceritakan kepada kami [Al Walid bin Abu Tsaur], dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Al Hasan bin Ali], telah menceritakan kepada kami [Al Husain Al Ju'fi] dari [Zaidah] secara makna, dari [Simak], dari [Ikrimah] dari [Ibnu Abbas], ia berkata; seorang badui telah datang kepada Nabi shallallahu 'alaihi wasallam dan berkata; sesungguhnya aku telah melihat Hilal -Al Hasan dalam haditsnya mengatakan; yaitu Hilal Ramadhan-, kemudian beliau berkata; apakah engkau bersaksi bahwa tidak ada tuhan yang berhak disembah disembah kecuali Allah? Ia berkata; ya. Beliau berkata; apakah engkau bersaksi bahwa Muhammad adalah Rasulullah? Ia berkata; ya. Beliau berkata; wahai Bilal, umumkan kepada orang-orang agar mereka berpuasa besok. "},"1929":{"ar":"حَدَّثَنِي مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ عِكْرِمَةَأَنَّهُمْ شَكُّوا فِي هِلَالِ رَمَضَانَ مَرَّةً فَأَرَادُوا أَنْ لَا يَقُومُوا وَلَا يَصُومُوا فَجَاءَ أَعْرَابِيٌّ مِنْ الْحَرَّةِ فَشَهِدَ أَنَّهُ رَأَى الْهِلَالَ فَأُتِيَ بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَتَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنِّي رَسُولُ اللَّهِ قَالَ نَعَمْ وَشَهِدَ أَنَّهُ رَأَى الْهِلَالَ فَأَمَرَ بِلَالًا فَنَادَى فِي النَّاسِ أَنْ يَقُومُوا وَأَنْ يَصُومُواقَالَ أَبُو دَاوُد رَوَاهُ جَمَاعَةٌ عَنْ سِمَاكٍ عَنْ عِكْرِمَةَ مُرْسَلًا وَلَمْ يَذْكُرْ الْقِيَامَ أَحَدٌ إِلَّا حَمَّادُ بْنُ سَلَمَةَ","id":"Telah menceritakan kepada kami [Musa bin Isma'il], telah menceritakan kepada kami [Hammad] dari [Simak bin Harb] dari [Ikrimah] bahwa mereka pada suatu kali merasa ragu mengenai hilal Ramadhan, kemudian mereka berkeinginan untuk tidak melakukan shalat malam dan tidak berpuasa. Lalu terdapat seorang badui datang dari Al Harrah dan bersaksi bahwa ia telah melihat Hilal, kemudian ia dihadapkan kepada Nabi shallallahu 'alaihi wasallam. Beliau berkata: \"Apakah engkau bersaksi bahwa tidak ada tuhan yang berhak disembah kecuali Allah dan aku adalah Rasulullah?\" Orang tersebut berkata; ya. Dan ia bersaksi bahwa dia telah melihat Hilal, lalu beliau memerintahkan Bilal agar mengumumkan diantara manusia agar mereka melakukan shalat malam dan berpuasa. Abu Daud berkata; hadits tersebut diriwayatkan oleh sekelompok orang dari Simak, dari Ikrimah secara mursal, dan tidak ada seorangpun yang menyebutkan \"shalat malam\" kecuali Hammad bin Salamah. "},"1930":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ خَالِدٍ وَعَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ السَّمْرَقَنْدِيُّ وَأَنَا لِحَدِيثِهِ أَتْقَنُ قَالَا حَدَّثَنَا مَرْوَانُ هُوَ ابْنُ مُحَمَّدٍ عَنْ عَبْدِ اللَّهِ بْنِ وَهْبٍ عَنْ يَحْيَى بْنِ عَبْدِ اللَّهِ بْنِ سَالِمٍ عَنْ أَبِي بَكْرِ بْنِ نَافِعٍ عَنْ أَبِيهِ عَنْ ابْنِ عُمَرَ قَالَتَرَاءَى النَّاسُ الْهِلَالَ فَأَخْبَرْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنِّي رَأَيْتُهُ فَصَامَهُ وَأَمَرَ النَّاسَ بِصِيَامِهِ","id":"Telah menceritakan kepada kami [Mahmud bin Khalid] serta [Abdullah bin Abdurrahman As Samarqandi], dan aku lebih yakin kepada haditsnya, mereka berkata; telah menceritakan kepada kami [Marwan bin Muhammad] dari [Abdullah bin Wahb] dari [Yahya bin Abdullah bin Salim] dari [Abu Bakr bin Nafi'] dari [ayahnya] dari [Ibnu Umar], ia berkata; orang-orang berusaha untuk melihat hilal, kemudian aku beritahukan kepada Rasulullah shallallahu 'alaihi wasallam bahwa aku telah melihatnya. Kemudian beliau berpuasa dan memerintahkan orang-orang agar berpuasa. "},"1931":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ مُوسَى بْنِ عَلِيِّ بْنِ رَبَاحٍ عَنْ أَبِيهِ عَنْ أَبِي قَيْسٍ مَوْلَى عَمْرِو بْنِ الْعَاصِ عَنْ عَمْرِو بْنِ الْعَاصِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ فَصْلَ مَا بَيْنَ صِيَامِنَا وَصِيَامِ أَهْلِ الْكِتَابِ أَكْلَةُ السَّحَرِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Abdullah bin Al Mubarak], dari [Musa bin Ali Rabah], dari [ayahnya] dari [Abu Qais] mantan budak 'Amr bin Al 'Ash, dari ['Amr bin Al 'Ash], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya pembeda antara puasa kita dan puasa ahli kitab adalah makan sahur.\""},"1932":{"ar":"حَدَّثَنَا عَمْرُو بْنُ مُحَمَّدٍ النَّاقِدُ حَدَّثَنَا حَمَّادُ بْنُ خَالِدٍ الْخَيَّاطُ حَدَّثَنَا مُعَاوِيَةُ بْنُ صَالِحٍ عَنْ يُونُسَ بْنِ سَيْفٍ عَنْ الْحَارِثِ بْنِ زِيَادٍ عَنْ أَبِي رُهْمٍ عَنْ الْعِرْبَاضِ بْنِ سَارِيَةَ قَالَدَعَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى السَّحُورِ فِي رَمَضَانَ فَقَالَ هَلُمَّ إِلَى الْغَدَاءِ الْمُبَارَكِ","id":"Telah menceritakan kepada kami ['Amr bin Muhammad An Naqid], telah menceritakan kepada kami [Hammad bin Khalid Al Khayyath], telah menceritakan kepada kami [Mu'awiyah bin Shalih] dari [Yunus bin Saif], dari [Al Harits bin Ziyad] dari [Abu Ruhm] dari [Al 'Irbadh bin Sariyah], ia berkata; Rasulullah shallallahu 'alaihi wasallam mengundangku untuk makan sahur pada Bulan Ramadhan, beliau berkata; \"Kemarilah untuk makan siang yang mendapat berkah!\""},"1933":{"ar":"حَدَّثَنَا عُمَرُ بْنُ الْحُسَيْنِ بْنِ إِبْرَاهِيمَ حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي الْوَزِيرِ أَبُو الْمُطَرِّفِ حَدَّثَنَا مُحَمَّدُ بْنُ مُوسَى عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نِعْمَ سَحُورُ الْمُؤْمِنِ التَّمْرُ","id":"Telah menceritakan kepada kami [Umar bin Al Husain bin Ibrahim], telah menceritakan kepada kami [Muhammad bin Abu Al Wazir Abu Al Mutharrif], telah menceritakan kepada kami [Muhammad bin Musa] dari [Sa'id Al Maqburi] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sebaik-baik (makanan) sahur bagi seorang mukmin adalah kurma.\""},"1934":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ عَبْدِ اللَّهِ بْنِ سَوَادَةَ الْقُشَيْرِيِّ عَنْ أَبِيهِ سَمِعْتُ سَمُرَةَ بْنَ جُنْدُبٍ يَخْطُبُ وَهُوَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَمْنَعَنَّ مِنْ سُحُورِكُمْ أَذَانُ بِلَالٍ وَلَا بَيَاضُ الْأُفْقِ الَّذِي هَكَذَا حَتَّى يَسْتَطِيرَ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Hammad bin Zaid], dari [Abdullah bin Sawadah Al Qusyairi] dari [ayahnya], saya mendengar [Samurah bin Jundab] berkhutbah, ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah Adzan Bilal dan putih di ufuk yang demikian menghalangi dari sahur kalian hingga cahayanya telah menyebar dan meluas di ufuk.\""},"1935":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ التَّيْمِيِّ ح و حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا سُلَيْمَانُ التَّيْمِيُّ عَنْ أَبِي عُثْمَانَ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَمْنَعَنَّ أَحَدَكُمْ أَذَانُ بِلَالٍ مِنْ سُحُورِهِ فَإِنَّهُ يُؤَذِّنُ أَوْ قَالَ يُنَادِي لِيَرْجِعَ قَائِمُكُمْ وَيَنْتَبِهَ نَائِمُكُمْ وَلَيْسَ الْفَجْرُ أَنْ يَقُولَ هَكَذَاقَالَ مُسَدَّدٌ وَجَمَعَ يَحْيَى كَفَّيْهِ حَتَّى يَقُولَ هَكَذَا وَمَدَّ يَحْيَى بِأُصْبُعَيْهِ السَّبَّابَتَيْنِ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Yahya] dari [At Taimi], dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Ahmad bin Yunus], telah menceritakan kepada kami [Zuhair], telah menceritakan kepada kami [Sulaiman At Taimi] dari [Abu Utsman] dari [Abdullah bin Mas'ud], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah Adzan Bilal menghalangi salah seorang dari kalian dari makan sahurnya, karena ia mengumandangkan adzan -atau beliau mengatakan; menyeru- agar orang yang melakukan shalat kembali dan orang yang tidur terjaga. Fajar tidaklah seperti ini.\" Musaddad berkata; Yahya menggabungkan kedua telapak tangannya hingga berkata; seperti ini. Dan Yahya membentangkan kedua jari telunjuknya. "},"1936":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا مُلَازِمُ بْنُ عَمْرٍو عَنْ عَبْدِ اللَّهِ بْنِ النُّعْمَانِ حَدَّثَنِي قَيْسُ بْنُ طَلْقٍ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُوا وَاشْرَبُوا وَلَا يَهِيدَنَّكُمْ السَّاطِعُ الْمُصْعِدُ فَكُلُوا وَاشْرَبُوا حَتَّى يَعْتَرِضَ لَكُمْ الْأَحْمَرُقَالَ أَبُو دَاوُد هَذَا مِمَّا تَفَرَّدَ بِهِ أَهْلُ الْيَمَامَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Isa], telah menceritakan kepada kami [Mulazim bin 'Amr] dari [Abdullah bin An Nu'man], telah menceritakan kepadaku [Qais bin Thalq] dari [ayahnya], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Makan dan minumlah dan janganlah menghalangi kalian sinar yang tinggi (yakni, terangnya fajar kadzib). Makan dan minumlah hingga nampak bagi kalian warna merah.\" Abu Daud berkata; ini adalah diantara yang hanya diriwayatkan oleh penduduk Al Yamamah. "},"1937":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا حُصَيْنُ بْنُ نُمَيْرٍ ح و حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا ابْنُ إِدْرِيسَ الْمَعْنَى عَنْ حُصَيْنٍ عَنْ الشَّعْبِيِّ عَنْ عَدِيِّ بْنِ حَاتِمٍ قَالَلَمَّا نَزَلَتْ هَذِهِ الْآيَةُ{ حَتَّى يَتَبَيَّنَ لَكُمْ الْخَيْطُ الْأَبْيَضُ مِنْ الْخَيْطِ الْأَسْوَدِ }قَالَ أَخَذْتُ عِقَالًا أَبْيَضَ وَعِقَالًا أَسْوَدَ فَوَضَعْتُهُمَا تَحْتَ وِسَادَتِي فَنَظَرْتُ فَلَمْ أَتَبَيَّنْ فَذَكَرْتُ ذَلِكَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَضَحِكَ فَقَالَ إِنَّ وِسَادَكَ لَعَرِيضٌ طَوِيلٌ إِنَّمَا هُوَ اللَّيْلُ وَالنَّهَارُو قَالَ عُثْمَانُ إِنَّمَا هُوَ سَوَادُ اللَّيْلِ وَبَيَاضُ النَّهَارِ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Hushain bin Numair], dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Utsman bin Abu Syaibah], telah menceritakan kepada kami [Ibnu Idris] secara makna, dari [Hushain] dari [Asy Sya'bi] dari [Adi bin Hatim], ia berkata; tatkala turun ayat ini: \"Hingga terang bagimu benang putih dari benang hitam.\" Maka aku mengambil tali putih dan tali hitam dan aku letakkan keduanya di bawah bantalku, lalu aku lihat dan belum juga nampak. Lalu aku ceritakan hal tersebut kepada Rasulullah shallallahu 'alaihi wasallam, maka beliau tertawa dan berkata; sesungguhnya bantalmu lebar dan panjang. Sesungguhnya yang dimaksud benang hitam dan putih tersebut adalah malam dan siang. Utsman berkata; sesungguhnya hal tersebut adalah gelapnya malam dan putihnya siang. "},"1938":{"ar":"حَدَّثَنَا عَبْدُ الْأَعْلَى بْنُ حَمَّادٍ حَدَّثَنَا حَمَّادٌ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا سَمِعَ أَحَدُكُمْ النِّدَاءَ وَالْإِنَاءُ عَلَى يَدِهِ فَلَا يَضَعْهُ حَتَّى يَقْضِيَ حَاجَتَهُ مِنْهُ","id":"Telah menceritakan kepada kami [Abdul A'la bin Hammad], telah menceritakan kepada kami [Hammad] Telah menceritakan kepada kami [Muhammad bin 'Amr] dari [Abu Salamah], dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang diantara kalian mendengar adzan, sedangkan bejana (makanan) masih ada di tangannya, maka janganlah ia meletakkannya hingga ia menyelesaikan hajatnya (sahurnya).\""},"1939":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا هِشَامٌ ح و حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ دَاوُدَ عَنْ هِشَامٍ الْمَعْنَى قَالَ هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَاصِمِ بْنِ عُمَرَ عَنْ أَبِيهِ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا جَاءَ اللَّيْلُ مِنْ هَا هُنَا وَذَهَبَ النَّهَارُ مِنْ هَا هُنَا زَادَ مُسَدَّدٌ وَغَابَتْ الشَّمْسُ فَقَدْ أَفْطَرَ الصَّائِمُ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal], telah menceritakan kepada kami [Waki'], telah menceritakan kepada kami [Hisyam], dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Abdullah bin Daud] dari [Hisyam] secara makna, Hisyam bin 'Urwah berkata; dari [ayahnya], dari ['Ashim bin Umar], dari [ayahnya], ia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Apabila Malam telah datang dari sini dan siang telah pergi -Musaddad menambahkan; dan matahari telah tenggelam- maka sungguh orang yang berpuasa telah berbuka.\""},"1940":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ الْوَاحِدِ حَدَّثَنَا سُلَيْمَانُ الشَّيْبَانِيُّ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ أَبِي أَوْفَى يَقُولُسِرْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ صَائِمٌ فَلَمَّا غَرَبَتْ الشَّمْسُ قَالَ يَا بِلَالُ انْزِلْ فَاجْدَحْ لَنَا قَالَ يَا رَسُولَ اللَّهِ لَوْ أَمْسَيْتَ قَالَ انْزِلْ فَاجْدَحْ لَنَا قَالَ يَا رَسُولَ اللَّهِ إِنَّ عَلَيْكَ نَهَارًا قَالَ انْزِلْ فَاجْدَحْ لَنَا فَنَزَلَ فَجَدَحَ فَشَرِبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَالَ إِذَا رَأَيْتُمْ اللَّيْلَ قَدْ أَقْبَلَ مِنْ هَا هُنَا فَقَدْ أَفْطَرَ الصَّائِمُ وَأَشَارَ بِأُصْبُعِهِ قِبَلَ الْمَشْرِقِ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Abdul Wahid], telah menceritakan kepada kami [Sulaiman Asy Syaibni], ia berkata; saya mendengar [Abdullah bin Abu Aufa] berkata; kami berjalan bersama Rasulullah shallallahu 'alaihi wasallam sementara beliau sedang berpuasa, kemudian tatkala matahari telah tenggelam beliau berkata; wahai Bilal, turun dan aduklah untuk kami. Ia berkata; wahai Rasulullah, seandainya anda menunggu hingga masuk sore hari dengan sempurna! Beliau berkata: \"Turun dan aduklah untuk kami!\" Ia berkata; wahai Rasulullah, sesungguhnya anda masih berada pada siang hari. Beliau berkata: \"Turun dan aduklah untuk kami!\" Kemudian ia turun dan mengaduk. Lalu Rasulullah shallallahu 'alaihi wasallam minum kemudian bersabda: \"Apabila kalian melihat malam telah datang dari sini, maka orang yang berpuasa telah berbuka.\" Beliau menunjuk dengan jarinya ke arah timur. "},"1941":{"ar":"حَدَّثَنَا وَهْبُ بْنُ بَقِيَّةَ عَنْ خَالِدٍ عَنْ مُحَمَّدٍ يَعْنِي ابْنَ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَزَالُ الدِّينُ ظَاهِرًا مَا عَجَّلَ النَّاسُ الْفِطْرَ لِأَنَّ الْيَهُودَ وَالنَّصَارَى يُؤَخِّرُونَ","id":"Telah menceritakan kepada kami [Wahb bin Baqiyyah] dari [Khalid] dari [Muhammad bin 'Amr] dari [Abu Salamah] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau berkata: \"Agama ini akan senantiasa nampak selama orang-orang (kaum muslimin) menyegerakan berbuka, karena orang-orang yahudi dan nashrani menundanya.\""},"1942":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ عُمَارَةَ بْنِ عُمَيْرٍ عَنْ أَبِي عَطِيَّةَ قَالَدَخَلْتُ عَلَى عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا أَنَا وَمَسْرُوقٌ فَقُلْنَا يَا أُمَّ الْمُؤْمِنِينَ رَجُلَانِ مِنْ أَصْحَابِ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحَدُهُمَا يُعَجِّلُ الْإِفْطَارَ وَيُعَجِّلُ الصَّلَاةَ وَالْآخَرُ يُؤَخِّرُ الْإِفْطَارَ وَيُؤَخِّرُ الصَّلَاةَ قَالَتْ أَيُّهُمَا يُعَجِّلُ الْإِفْطَارَ وَيُعَجِّلُ الصَّلَاةَ قُلْنَا عَبْدُ اللَّهِ قَالَتْ كَذَلِكَ كَانَ يَصْنَعُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Abu Mu'awiyah], dari [Al A'masy], dari ['Umarah bin 'Umair] dari [Abu 'Athiyyah], ia berkata; aku menemui [Aisyah] radliallahu 'anhu bersama dengan Masruq, lalu kami katakana; wahai Ummul mukminin, ada dua orang sahabat Muhammad shallallahu 'alaihi wasallam, salah seorang diantara mereka menyegerakan berbuka dan menyegerakan shalat, sedangkan yang lain menunda berbuka dan menunda shalat. Aisyah berkata; siapakah diantara mereka berdua yang menyegerakan berbuka dan menyegerakan shalat? Kami katakan; Abdullah. Ia berkata; demikianlah dahulu Rasulullah shallallahu 'alaihi wasallam melakukan. "},"1943":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ زِيَادٍ عَنْ عَاصِمٍ الْأَحْوَلِ عَنْ حَفْصَةَ بِنْتِ سِيرِينَ عَنْ الرَّبَابِ عَنْ سَلْمَانَ بْنِ عَامِرٍ عَمِّهَا قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا كَانَ أَحَدُكُمْ صَائِمًا فَلْيُفْطِرْ عَلَى التَّمْرِ فَإِنْ لَمْ يَجِدْ التَّمْرَ فَعَلَى الْمَاءِ فَإِنَّ الْمَاءَ طَهُورٌ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Abdul Wahid bin Ziyad] dari ['Ashim Al Ahwal], dari [Hafshah binti Sirin] dari [Ar Rabab] dari [Salman bin 'Amir yang merupakan pamannya], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang diantara kalian sedang berpuasa, maka hendaknya ia berbuka dengan kurma, apabila ia tidak mendapatkan kurma hendaknya dengan air, karena sesungguhnya air dapat membersihkan (zhahir dan batin, atau menghilangkan rasa haus).\""},"1944":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا جَعْفَرُ بْنُ سُلَيْمَانَ حَدَّثَنَا ثَابِتٌ الْبُنَانِيُّ أَنَّهُ سَمِعَ أَنَسَ بْنَ مَالِكٍ يَقُولُكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُفْطِرُ عَلَى رُطَبَاتٍ قَبْلَ أَنْ يُصَلِّيَ فَإِنْ لَمْ تَكُنْ رُطَبَاتٌ فَعَلَى تَمَرَاتٍ فَإِنْ لَمْ تَكُنْ حَسَا حَسَوَاتٍ مِنْ مَاءٍ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal], telah menceritakan kepada kami [Abdurrazzaq], telah menceritakan kepada kami [Ja'far bin Sulaiman], telah menceritakan kepada kami [Tsabit Al Bunani] bahwa ia telah mendengar [Anas bin Malik] berkata; dahulu Rasulullah shallallahu 'alaihi wasallam berbuka dengan beberapa ruthab (kurma yang belum masak) sebelum melakukan shalat, jika tidak dengan air maka dengan beberapa kurma, dan apabila tidak ada kurma maka beliau menghisap air beberapa kali. "},"1945":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ يَحْيَى أَبُو مُحَمَّدٍ حَدَّثَنَا عَلِيُّ بْنُ الْحَسَنِ أَخْبَرَنِي الْحُسَيْنُ بْنُ وَاقِدٍ حَدَّثَنَا مَرْوَانُ يَعْنِي ابْنَ سَالِمٍ الْمُقَفَّعَ قَالَرَأَيْتُ ابْنَ عُمَرَ يَقْبِضُ عَلَى لِحْيَتِهِ فَيَقْطَعُ مَا زَادَ عَلَى الْكَفِّ وَقَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَفْطَرَ قَالَ ذَهَبَ الظَّمَأُ وَابْتَلَّتْ الْعُرُوقُ وَثَبَتَ الْأَجْرُ إِنْ شَاءَ اللَّهُ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad bin Yahya Abu Muhammad], telah menceritakan kepada kami [Ali bin Al Hasan], telah mengabarkan kepadaku [Al Husain bin Waqid], telah menceritakan kepada kami [Marwan bin Salim Al Muqaffa'], ia berkata; saya melihat [Ibnu Umar] menggenggam jenggotnya dan memotong jenggot yang melebihi telapak tangan. Dan ia berkata; dahulu Rasulullah shallallahu 'alaihi wasallam apabila berbuka beliau mengucapkan: DZAHABAZH ZHAMAA`U WABTALLATIL 'URUUQU WA TSABATIL AJRU IN SYAA-ALLAAH (Telah hilang dahaga, dan telah basah tenggorokan, dan telah tetap pahala insya Allah). "},"1946":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا هُشَيْمٌ عَنْ حُصَيْنٍ عَنْ مُعَاذِ بْنِ زُهْرَةَ أَنَّهُ بَلَغَهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا أَفْطَرَ قَالَ اللَّهُمَّ لَكَ صُمْتُ وَعَلَى رِزْقِكَ أَفْطَرْتُ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Husyaim], dari [Hushain] dari [Mu'adz bin Zuhrah], bahwa telah sampai kepadanya bahwa Nabi shallallahu 'alaihi wasallam apabila berbuka beliau mengucapkan: ALLAAHUMMA LAKA SHUMTU WA 'ALAA RIZQIKA AFTHARTU (Ya Allah, untukMu aku berpuasa, dan dengan rizqiMu aku berbuka). "},"1947":{"ar":"حَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ وَمُحَمَّدُ بْنُ الْعَلَاءِ الْمَعْنَى قَالَا حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ فَاطِمَةَ بِنْتِ الْمُنْذِرِ عَنْ أَسْمَاءَ بِنْتِ أَبِي بَكْرٍ قَالَتْأَفْطَرْنَا يَوْمًا فِي رَمَضَانَ فِي غَيْمٍ فِي عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ طَلَعَتْ الشَّمْسُقَالَ أَبُو أُسَامَةَ قُلْتُ لِهِشَامٍ أُمِرُوا بِالْقَضَاءِ قَ��لَ وَبُدٌّ مِنْ ذَلِكَ","id":"Telah menceritakan kepada kami [Harun bin Abdullah] dan [Muhammad bin Al 'Ala`] secara makna, mereka berkata; telah menceritakan kepada kami [Abu Usamah], telah menceritakan kepada kami [Hisyam bin 'Urwah], dari [Fathimah binti Al Mundzir], dari [Asma` binti Abu Bakr], ia berkata; pada suatu hari kami berbuka pada Bulan Ramadhan dalam cuaca yang mendung pada zaman Rasulullah shallallahu 'alaihi wasallam kemudian matahari nampak. Abu Usamah berkata; aku katakan kepada Hisyam; apakah mereka diperintahkan untuk mengqadha`? Ia menjawab, Ia harus mengqadha`nya. "},"1948":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الْوِصَالِ قَالُوا فَإِنَّكَ تُوَاصِلُ يَا رَسُولَ اللَّهِ قَالَ إِنِّي لَسْتُ كَهَيْئَتِكُمْ إِنِّي أُطْعَمُ وَأُسْقَى","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah Al Qa'nabi], dari [Malik] dari [Nafi'] dari [Ibnu Umar] bahwa Rasulullah shallallahu 'alaihi wasallam telah melarang dari wishal, mereka berkata; anda melakukan wishal wahai Rasulullah. Beliau berkata; sesungguhnya aku tidak seperti kalian, aku diberimakan dan minum. "},"1949":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ أَنَّ بَكْرَ بْنَ مُضَرَ حَدَّثَهُمْ عَنْ ابْنِ الْهَادِ عَنْ عَبْدِ اللَّهِ بْنِ خَبَّابٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تُوَاصِلُوا فَأَيُّكُمْ أَرَادَ أَنْ يُوَاصِلَ فَلْيُوَاصِلْ حَتَّى السَّحَرَ قَالُوا فَإِنَّكَ تُوَاصِلُ قَالَ إِنِّي لَسْتُ كَهَيْئَتِكُمْ إِنَّ لِي مُطْعِمًا يُطْعِمُنِي وَسَاقِيًا يَسْقِينِي","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] bahwa [Abu Bakr bin Mudhar] telah menceritakan kepada mereka, dari [Ibnu Al Had] dari [Abdullah bin Khabbab] dari [Abu Sa'id Al Khudri] bahwa ia telah mendengar Rasulullah shallallahu 'alaihi wasallam berkata: \"Janganlah kalian melakukan puasa wishal, barangsiapa diantara kalian yang menghendaki untuk melakukan wishal maka hendaknya ia melakukannya hingga waktu sahur.\" Mereka berkata; anda melakukannya. Beliau berkata: \"Sesungguhnya aku tidak seperti kalian, aku memiliki Pemberi makan dan Pemberi minum.\""},"1950":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ الْمَقْبُرِيِّ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ لَمْ يَدَعْ قَوْلَ الزُّورِ وَالْعَمَلَ بِهِ فَلَيْسَ لِلَّهِ حَاجَةٌ أَنْ يَدَعَ طَعَامَهُ وَشَرَابَهُو قَالَ أَحْمَدُ فَهِمْتُ إِسْنَادَهُ مِنْ ابْنِ أَبِي ذِئْبٍ وَأَفْهَمَنِي الْحَدِيثَ رَجُلٌ إِلَى جَنْبِهِ أُرَاهُ ابْنَ أَخِيهِ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus], telah menceritakan kepada kami [Ibnu Abu Dzi`bin], dari [Al Maqburi], dari [ayahnya] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang tidak meninggalkan perkataan palsu dan pengamalannya, maka Allah tidak butuh ia meninggalkan makan dan minumnya.\" Ahmad berkata; aku memahami sanadnya dari Ibnu Abu Dzi`bin, dan seseorang yang ada di sampingku yang aku kira adalah anak saudaranya telah memahamkan hadits tersebut kepadaku. "},"1951":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الصِّيَامُ جُنَّةٌ إِذَا كَانَ أَحَدُكُمْ صَائِمًا فَلَا يَرْفُثْ وَلَا يَجْهَلْ فَإِنْ امْرُؤٌ قَاتَلَهُ أَوْ شَاتَمَهُ فَلْيَقُلْ إِنِّي صَائِمٌ إِنِّي صَائِمٌ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah Al Qa'nabi], dari [Malik] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam berkata: \"Puasa adalah tameng, apabila salah seorang diantara kalian berpuasa maka janganlah ia berkata kotor, dan melakukan perbuatan bodoh. Apabila terdapat seseorang memusuhinya atau mencelanya maka hendaknya ia mengatakan; aku sedang berpuasa.\""},"1952":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ حَدَّثَنَا شَرِيكٌ ح و حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ عَنْ عَاصِمِ بْنِ عُبَيْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ عَامِرِ بْنِ رَبِيعَةَ عَنْ أَبِيهِ قَالَ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْتَاكُ وَهُوَ صَائِمٌ زَادَ مُسَدَّدٌ مَا لَا أَعُدُّ وَلَا أُحْصِي","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah], telah menceritakan kepada kami [Syarik], dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Yahya] dari [Sufyan] dari ['Ashim bin 'Ubaidullah] dari [Abdullah bin 'Amir bin Rabi'ah] dari [ayahnya], ia berkata; saya melihat Rasulullah shallallahu 'alaihi wasallam memakai siwak sementara beliau sedang berpuasa. Musaddad menambahkan; yang tidak dapat aku hitung. "},"1953":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ سُمَيٍّ مَوْلَى أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ بَعْضِ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ النَّاسَ فِي سَفَرِهِ عَامَ الْفَتْحِ بِالْفِطْرِ وَقَالَ تَقَوَّوْا لِعَدُوِّكُمْ وَصَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَبُو بَكْرٍ قَالَ الَّذِي حَدَّثَنِي لَقَدْ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْعَرْجِ يَصُبُّ عَلَى رَأْسِهِ الْمَاءَ وَهُوَ صَائِمٌ مِنْ الْعَطَشِ أَوْ مِنْ الْحَرِّ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah Al Qa'nabi], dari [Malik] dari [Sumai] mantan budak Abu Bakr bin Abdurrahman, dari [Abu Bakr bin Abdurrahman] dari [sebagian sahabat Nabi shallallahu 'alaihi wasallam], beliau bersabda: \"Aku melihat Rasulullah shallallahu 'alaihi wasallam memerintahkan orang-orang ketika dalam perjalanannya pada tahun penaklukan Mekkah untuk berbuka.\" Beliau berkata: \"Perkuatlah tubuh kalian untuk menghadapi musuh!\" sementara Rasulullah shallallahu 'alaihi wasallam berpuasa. Abu Bakr berkata; telah berkata orang yang telah menceritakan kepadaku; sungguh aku telah melihat Rasulullah shallallahu 'alaihi wasallam di Al 'Arj menuangkan air ke kepalanya karena haus atau panas, sementara beliau sedang berpuasa. "},"1954":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنِي يَحْيَى بْنُ سُلَيْمٍ عَنْ إِسْمَعِيلَ بْنِ كَثِيرٍ عَنْ عَاصِمِ بْنِ لَقِيطِ بْنِ صَبْرَةَ عَنْ أَبِيهِ لَقِيطِ بْنِ صَبْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَالِغْ فِي الِاسْتِنْشَاقِ إِلَّا أَنْ تَكُونَ صَائِمًا","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Yahya bin Sulaim] dari [Isma'I bin Katsir] dari ['Ashim bin Laqith bin Shabrah] dari [ayahnya yaitu Laqith bin Shabrah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bersungguh-sungguh dalam beristinsyaq (memasukkan air ke hidung ketika berwudhu) kecuali ketika engkau sedang berpuasa.\""},"1955":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ هِشَامٍ ح و حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا حَسَنُ بْنُ مُوسَى حَدَّثَنَا شَيْبَانُ جَمِيعًا عَنْ يَحْيَى عَنْ أَبِي قِلَابَةَ عَنْ أَبِي أَسْمَاءَ يَعْنِي الرَّحَبِيَّ عَنْ ثَوْبَانَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَفْطَرَ الْحَاجِمُ وَالْمَحْجُومُ قَالَ شَيْبَانُ أَخْبَرَنِي أَبُو قِلَابَةَ أَنَّ أَبَا أَسْمَاءَ الرَّحَبِيَّ حَدَّثَهُ أَنَّ ثَوْبَانَ مَوْلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبَرَهُ أَنَّهُ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا حَسَنُ بْنُ مُوسَى حَدَّثَنَا شَيْبَانُ عَنْ يَحْيَى قَالَ حَدَّثَنِي أَبُو قِلَابَةَ الْجَرْمِيُّ أَنَّهُ أَخْبَرَهُ أَنَّ شَدَّادَ بْنَ أَوْسٍ بَيْنَمَا هُوَ يَمْشِي مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Yahya] dari [Hisyam], dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Ahmad bin Hanbal], telah menceritakan kepada kami [Hasan bin Musa], telah menceritakan kepada kami [Syaiban], dari [Yahya] dari [Abu Qilabah], dari [Abu Asma` Ar Rahabi] dari [Tsauban] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Telah batal puasa orang yang berbekam dan orang yang dibekam.\" [Syaiban] berkata; telah mengabarkan kepadaku [Abu Qilabah] bahwa [Asma` Ar Rahabi] telah menceritakan kepadanya bahwa [Tsauban] mantan budak Rasulullah shallallahu 'alaihi wasallam telah mengabarkan kepadanya bahwa ia telah mendengar Nabi shallallahu 'alaihi wasallam. Telah menceritakan kepada kami [Ahmad bin Hanbal], telah menceritakan kepada kami [Hasan bin Musa], telah menceritakan kepada kami [Syaiban] dari [Yahya], ia berkata; telah menceritakan kepadaku [Abu Qilabah Al jarmi], bahwa ia telah mengabarkan kepadanya bahwa [Syaddad bin Aus] ketika berjalan bersama Nabi shallallahu 'alaihi wasallam ….. kemudian ia menyebutkan seperti itu."},"1956":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا أَيُّوبُ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي الْأَشْعَثِ عَنْ شَدَّادِ بْنِ أَوْسٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَى عَلَى رَجُلٍ بِالْبَقِيعِ وَهُوَ يَحْتَجِمُ وَهُوَ آخِذٌ بِيَدِي لِثَمَانِ عَشْرَةَ خَلَتْ مِنْ رَمَضَانَ فَقَالَ أَفْطَرَ الْحَاجِمُ وَالْمَحْجُومُ قَالَ أَبُو دَاوُد وَرَوَى خَالِدٌ الْحَذَّاءُ عَنْ أَبِي قِلَابَةَ بِإِسْنَادِ أَيُّوبَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Musa bin Isma'il], telah menceritakan kepada kami [Wuhaib], telah menceritakan kepada kami [Ayyub] dari [Abu Qilabah] dari [Abu Al Asy'ats] dari [Syaddad bin Aus] bahwa Rasulullah shallallahu 'alaihi wasallam datang kepada seseorang di Baqi' sementara orang tersebut sedang berbekam, sementara beliau menggandeng tanganku- selama delapan belas hari yang telah berlalu pada Bulan Ramadhan. Kemudian beliau berkata: \"Telah batal puasa orang yang membekam dan yang dibekam.\" Abu Daud berkata; dan [Khalid Al Hadzdza`] telah meriwayatkan dari [Abu Qilabah] dengan sanad Ayyub seperti itu. "},"1957":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا مُحَمَّدُ بْنُ بَكْرٍ وَعَبْدُ الرَّزَّاقِ ح و حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا إِسْمَعِيلُ يَعْنِي ابْنَ إِبْرَاهِيمَ عَنْ ابْنِ جُرَيْجٍ أَخْبَرَنِي مَكْحُولٌ أَنَّ شَيْخًا مِنْ الْحَيِّ قَالَ عُثْمَانُ فِي حَدِيثِهِ مُصَدَّقٌ أَخْبَرَهُ أَنَّ ثَوْبَانَ مَوْلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبَرَهُ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَفْطَرَ الْحَاجِمُ وَالْمَحْجُومُ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal], telah menceritakan kepada kami [Muhammad bin Bakr] serta [Abdurrazzaq], dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Utsman bin Abu Syaibah], telah menceritakan kepada kami [Isma'il bin Ibrahim] dari [Ibnu Juraij], telah mengabarkan kepadaku [Makhul] bahwa [seorang tua] dari sebuah kampong, -Utsman berkata dalam haditsnya; orang yang dipercaya- telah mengabarkan kepadanya bahwa [Tsauban] mantan budak Rasulullah shallallahu 'alaihi wasallam telah mengabarkan kepadanya bahwa Nabi shallallahu 'alaihi wasallam berkata: \"Telah batal puasa orang yang membekam dan yang dibekam.\""},"1958":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ خَالِدٍ حَدَّثَنَا مَرْوَانُ حَدَّثَنَا الْهَيْثَمُ بْنُ حُمَيْدٍ أَخْبَرَنَا الْعَلَاءُ بْنُ الْحَارِثِ عَنْ مَكْحُولٍ عَنْ أَبِي أَسْمَاءَ الرَّحَبِيِّ عَنْ ثَوْبَانَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَفْطَرَ الْحَاجِمُ وَالْمَحْجُومُقَالَ أَبُو دَاوُد وَرَوَاهُ ابْنُ ثَوْبَانَ عَنْ أَبِيهِ عَنْ مَكْحُولٍ بِإِسْنَادِهِ مِثْلَهُ","id":"Telah menceritakan kepada kami [Mahmud bin Khalid], telah menceritakan kepada kami [Marwan], telah menceritakan kepada kami [Al Haitsam bin Humaid], telah mengabarkan kepada kami [Al 'Ala` bin Al Harits] dari [Makhul] dari [Abu Asma` Ar Rahabi] dari [Tsauban] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Telah batal puasa orang yang membekam dan yang dibekam.\" Abu Daud berkata; hadits tersebut diriwayatkan oleh [Ibnu Tsauban] dari [ayahnya] dari [Makhul] dengan sanadnya seperti itu. "},"1959":{"ar":"حَدَّثَنَا أَبُو مَعْمَرٍ عَبْدُ اللَّهِ بْنُ عُمَرَ حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ أَيُّوبَ عَنْ عِكرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ احْتَجَمَ وَهُوَ صَائِمٌقَالَ أَبُو دَاوُد رَوَاهُ وُهَيْبُ بْنُ خَالِدٍ عَنْ أَيُّوبَ بِإِسْنَادِهِ مِثْلَهُ وَجَعْفَرُ بْنُ رَبِيعَةَ وَهِشَامُ بْنُ حَسَّانَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ مِثْلَهُ","id":"Telah menceritakan kepada kami [Abu Ma'mar Abdullah bin Umar], telah menceritakan kepada kami [Abdul Warits] dari [Ayyub] dari [Ikrimah] dari [Ibnu Abbas] bahwa Rasulullah shallallahu 'alaihi wasallam berbekam sementara beliau dalam keadaan berpuasa. Abu Daud berkata; hadits tersebut diriwayatkan oleh [Wuhaib bin Khalid] dari [Ayyub] dengan sanadnya seperti itu, serta diriwayatkan oleh [Ja'far bin Rabi'ah] serta [Hisyam bin Hassan] dari [Ikrimah] dari [Ibnu Abbas] seperti itu. "},"1960":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ يَزِيدَ بْنِ أَبِي زِيَادٍ عَنْ مِقْسَمٍ عَنْ ابْنِ عَبَّاسٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ احْتَجَمَ وَهُوَ صَائِمٌ مُحْرِمٌ","id":"Telah menceritakan kepada kami [Hafsh bin Umar], Telah menceritakan kepada kami [Syu'bah] dari [Yazid bin Abu Ziyad] dari [Miqsam] dari [Ibnu Abbas], bhwa Rasulullah shallallahu 'alaihi wasallam berbekam sementara beliau dalam keadaan sedang berbekam dan berihram. "},"1961":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ سُفْيَانَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَابِسٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى حَدَّثَنِي رَجُلٌ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الْحِجَامَةِ وَالْمُوَاصَلَةِ وَلَمْ يُحَرِّمْهُمَا إِبْقَاءً عَلَى أَصْحَابِهِ فَقِيلَ لَهُ يَا رَسُولَ اللَّهِ إِنَّكَ تُوَاصِلُ إِلَى السَّحَرِ فَقَالَ إِنِّي أُوَاصِلُ إِلَى السَّحَرِ وَرَبِّي يُطْعِمُنِي وَيَسْقِينِي","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal], telah menceritakan kepada kami [Abdurrahman bin Mahdi] dari [Sufyan] dari [Abdurrahman bin 'Abis] dari [Abdurrahman bin Abu Laila], telah menceritakan kepadaku [seorang sahabat] Nabi shallallahu 'alaihi wasallam bahwa Rasulullah shallallahu 'alaihi wasallam telah melarang dari berbekam serta berpuasa wishal dan beliau tidak mengharamkannya sebagai belas kasih kepada para sahabatnya. Kemudian dikatakan kepada beliau; wahai Rasulullah, anda melakukan wishal hingga waktu sahur. Maka beliau berkata: \"Aku melakukan (puasa) wishal hingga waktu sahur dan Tuhanku memberiku makan dan minum.\""},"1962":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ حَدَّثَنَا سُلَيْمَانُ يَعْنِي ابْنَ الْمُغِيرَةِ عَنْ ثَابِتٍ قَالَ قَالَ أَنَسٌمَا كُنَّا نَدَعُ الْحِجَامَةَ لِلصَّائِمِ إِلَّا كَرَاهِيَةَ الْجَهْدِ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah], telah menceritakan kepada kami [Sulaiman bin Al Mughirah] dari [Tsabit], ia berkata; [Anas] berkata; kami tidak akan meninggalkan bekam bagi orang yang berpuasa, kecuali karena tidak menginginkan kondisi payah. "},"1963":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ رَجُلٍ مِنْ أَصْحَابِهِ عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يُفْطِرُ مَنْ قَاءَ وَلَا مَنْ احْتَلَمَ وَلَا مَنْ احْتَجَمَ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] telah mengabarkan kepada kami [Sufyan] dari [Zaid bin Aslam] dari [seorang laki-laki sahabatnya] dari [seorang sahabat Nabi shallallahu 'alaihi wasallam], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah batal puasa orang yang muntah, orang yang bermimpi, dan orang yang berbekam.\""},"1964":{"ar":"حَدَّثَنَا النُّفَيْلِيُّ حَدَّثَنَا عَلِيُّ بْنُ ثَابِتٍ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ النُّعْمَانِ بْنِ مَعْبَدِ بْنِ هَوْذَةَ عَنْ أَبِيهِ عَنْ جَدِّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ أَمَرَ بِالْإِثْمِدِ الْمُرَوَّحِ عِنْدَ النَّوْمِ وَقَالَ لِيَتَّقِهِ الصَّائِمُقَالَ أَبُو دَاوُد قَالَ لِي يَحْيَى بْنُ مَعِينٍ هُوَ حَدِيثٌ مُنْكَرٌ يَعْنِي حَدِيثَ الْكُحْلِ","id":"Telah menceritakan kepada kami [An Nufaili], telah menceritakan kepada kami [Ali bin Tsabit], telah menceritakan kepadaku [Abdurrahman bin An Nu'man bin Ma'bad bin Haudzah] dari [ayahnya], dari [kakeknya] dari Nabi shallallahu 'alaihi wasallam bahwa beliau memerintahkan untuk memakai Itsmid yang berminyak wangi ketika hendak tidur. Dan beliau berkata: \"Dan orang yang berpuasa hendaknya menghindarinya.\" Abu Daud berkata; Yahya bin Ma'in telah mengatakan kepadaku; hadits tersebut adalah hadits munkar, yaitu hadits mengenai celak. "},"1965":{"ar":"حَدَّثَنَا وَهْبُ بْنُ بَقِيَّةَ أَخْبَرَنَا أَبُو مُعَاوِيَةَ عَنْ عُتْبَةَ أَبِي مُعَاذٍ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي بَكْرِ بْنِ أَنَسٍ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّهُ كَانَ يَكْتَحِلُ وَهُوَ صَائِمٌ","id":"Telah menceritakan kepada kami [Wahb bin Baqiyyah], telah mengabarkan kepada kami [Abu Mu'awiyah] dari ['Utbah Abu Mu'adz] dari [Ubaidillah bin Abu Bakr] bin Anas dari [Anas bin Malik] bahwa ia memakai celak sementara beliau dalam keadaan berpuasa. "},"1966":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الْمُخَرِّمِيُّ وَيَحْيَى بْنُ مُوسَى الْبَلْخِيُّ قَالَا حَدَّثَنَا يَحْيَى بْنُ عِيسَى عَنْ الْأَعْمَشِ قَالَمَا رَأَيْتُ أَحَدًا مِنْ أَصْحَابِنَا يَكْرَهُ الْكُحْلَ لِلصَّائِمِوَكَانَ إِبْرَاهِيمُ يُرَخِّصُ أَنْ يَكْتَحِلَ الصَّائِمُ بِالصَّبِرِ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah Al Mukharrimi] dan [Yahya bin Musa Al Balkhi], mereka berdua mengatakan; telah menceritakan kepada kami [Yahya bin Isa] dari [Al A'masy], ia berkata; aku tidak melihat seorang pun dari para sahabat kita yang membenci celak bagi orang yang berpuasa. Dan Ibrahim memberikan keringanan agar orang yang berpuasa bercelak menggunakan shabir. "},"1967":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عِيسَى بْنُ يُونُسَ حَدَّثَنَا هِشَامُ بْنُ حَسَّانَ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ ذَرَعَهُ قَيْءٌ وَهُوَ صَائِمٌ فَلَيْسَ عَلَيْهِ قَضَاءٌ وَإِنْ اسْتَقَاءَ فَلْيَقْضِ قَالَ أَبُو دَاوُد رَوَاهُ أَيْضًا حَفْصُ بْنُ غِيَاثٍ عَنْ هِشَامٍ مِثْلَهُ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Isa bin Yunus], telah menceritakan kepada kami [Hisyam bin Hassan] dari [Muhammad bin Sirin] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang muntah tanpa disengaja ketika sedang berpuasa, maka ia tidak berkewajiban untuk mengqadha`, dan apabila ia sengaja untuk muntah maka hendaknya ia mengqadha`.\" Abu Daud berkata; hadits tersebut diriwayatkan juga oleh [Hafsh bin Ghiyats] dari [Hisyam] seperti itu. "},"1968":{"ar":"حَدَّثَنَا أَبُو مَعْمَرٍ عَبْدُ اللَّهِ بْنُ عَمْرٍو حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا الْحُسَيْنُ عَنْ يَحْيَى حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ عَمْرٍو الْأَوْزَاعِيُّ عَنْ يَعِيشَ بْنِ الْوَلِيدِ بْنِ هِشَامٍ أَنَّ أَبَاهُ حَدَّثَهُ حَدَّثَنِي مَعْدَانُ بْنُ طَلْحَةَ أَنَّ أَبَا الدَّرْدَاءِ حَدَّثَهُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَاءَ فَأَفْطَرَ فَلَقِيتُ ثَوْبَانَ مَوْلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مَسْجِدِ دِمَشْقَ فَقُلْتُ إِنَّ أَبَا الدَّرْدَاءِ حَدَّثَنِي أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَاءَ فَأَفْطَرَ قَالَ صَدَقَ وَأَنَا صَبَبْتُ لَهُ وَضُوءَهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abu Ma'mar Abdullah bin 'Amr], telah menceritakan kepada kami [Abdul Warits], telah menceritakan kepada kami [Al Husain] dari [Yahya], telah menceritakan kepadaku [Abdurrahman bin 'Amr Al Auza'i] dari [Ya'isy bin Al Walid bin Hisyam] bahwa [ayahnya] telah menceritakan kepadanya; telah menceritakan kepadaku [Ma'dan bin Thalhah] bahwa [Abu Ad Darda`] telah menceritakan kepadanya bahwa Rasulullah shallallahu 'alaihi wasallam muntah kemudian beliau berbuka. Kemudian aku bertemu dengan [Tsauban] mantan budak Rasulullah shallallahu 'alaihi wasallam di masjid Damaskus. Kemudian aku katakan; sesungguhnya Abu Ad Darda` telah menceritakan kepadaku bahwa Rasulullah shallallahu 'alaihi wasallam muntah kemudia beliau berbuka. Tsauban berkata; ia telah benar, dan aku yang menuangkan untuk beliau tempat wudhunya shallallahu 'alaihi wasallam. "},"1969":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ وَعَلْقَمَةَ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُقَبِّلُ وَهُوَ صَائِمٌ وَيُبَاشِرُ وَهُوَ صَائِمٌ وَلَكِنَّهُ كَانَ أَمْلَكَ لِإِرْبِهِ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy], dari [Ibrahim] dari [Al Aswad] dan ['Alqamah] dari [Aisyah], ia berkata; Rasulullah shallallahu 'alaihi wasallam mencium (istrinya) dalam keadaan sedang berpuasa. Dan juga memeluk (istrinya) dalam keadaan sedang berpuasa, akan tetapi beliau adalah orang yang paling dapat menahan nafsunya. "},"1970":{"ar":"حَدَّثَنَا أَبُو تَوْبَةَ الرَّبِيعُ بْنُ نَافِعٍ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ زِيَادِ بْنِ عِلَاقَةَ عَنْ عَمْرِو بْنِ مَيْمُونٍ عَنْ عَائِشَةَ قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُقَبِّلُ فِي شَهْرِ الصَّوْمِ","id":"Telah menceritakan kepada kami [Abu Taubah Ar Rabi' bin Nafi'], telah menceritakan kepada kami [Abu Al Ahwash] dari [Ziyad bin 'Alaqah] dari ['Amr bin Maimun] dari [Aisyah], ia berkata; Nabi shallallahu 'alaihi wasallam mencium (istrinya) pada bulan puasa. "},"1971":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ عَنْ طَلْحَةَ بْنِ عَبْدِ اللَّهِ يَعْنِي ابْنَ عُثْمَانَ الْقُرَشِيَّ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُقَبِّلُنِي وَهُوَ صَائِمٌ وَأَنَا صَائِمَةٌ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir], telah mengabarkan kepada kami [Sufyan], dari [Sa'd bin Ibrahim] dari [Thalhah bin Abdullah bin Utsman Al Qurasyi] dari [Aisyah] radliallahu 'anha, ia berkata; Rasulullah shallallahu 'alaihi wasallam pernah menciumku sementara beliau dalam keadaan berpuasa dan aku juga berpuasa. "},"1972":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا اللَّيْثُ ح و حَدَّثَنَا عِيسَى بْنُ حَمَّادٍ أَخْبَرَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ بُكَيْرِ بْنِ عَبْدِ اللَّهِ عَنْ عَبْدِ الْمَلِكِ بْنِ سَعِيدٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَ قَالَ عُمَرُ بْنُ الْخَطَّابِهَشَشْتُ فَقَبَّلْتُ وَأَنَا صَائِمٌ فَقُلْتُ يَا رَسُولَ اللَّهِ صَنَعْتُ الْيَوْمَ أَمْرًا عَظِيمًا قَبَّلْتُ وَأَنَا صَائِمٌ قَالَ أَرَأَيْتَ لَوْ مَضْمَضْتَ مِنْ الْمَاءِ وَأَنْتَ صَائِمٌ قَالَ عِيسَى بْنُ حَمَّادٍ فِي حَدِيثِهِ قُلْتُ لَا بَأْسَ بِهِ ثُمَّ اتَّفَقَا قَالَ فَمَهْ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus], telah menceritakan kepada kami [Al Laits], dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Isa bin Hammad], telah mengabarkan kepada kami [Al Laits bin Sa'd] dari [Bukair bin Abdullah], dari [Abdul Malik bin Sa'id] dari [Jabir bin Abdullah], ia berkata; [Umar bin Al Khathab] berkata; aku merasakan senang lalu aku mencium (istriku) sementara aku dalam keadaan berpuasa. Lalu aku katakan; wahai Rasulullah, pada hari ini aku telah melakukan suatu perkara yang besar. Saya mencium (istriku) sementara saya sedang berpuasa. Beliau berkata: \"Bagaimana pendapatmu apabila engkau berkumur-kumur menggunakan air sementara engkau sedang berpuasa?\" Isa bin Hammad berkata dalam haditsnya; aku katakan; tidak mengapa. Kemudian keduanya bersepakat mengatakan; beliau berkata; tahanlah! "},"1973":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا مُحَمَّدُ بْنُ دِينَارٍ حَدَّثَنَا سَعْدُ بْنُ أَوْسٍ الْعَبْدِيُّ عَنْ مِصْدَعٍ أَبِي يَحْيَى عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُقَبِّلُهَا وَهُوَ صَائِمٌ وَيَمُصُّ لِسَانَهَاقَالَ ابْنُ الْأَعْرَابِيِّ هَذَا الْإِسْنَادُ لَيْسَ بِصَحِيحٍ","id":"Telah menceritakan kepada kami [Muhammad bin Isa], telah menceritakan kepada kami [Muhammad bin Dinar], telah menceritakan kepada kami [Sa'd bin Aus Al 'Abdi] dari [Mishda' Abu Yahya] dari [Aisyah] bahwa Nabi shallallahu 'alaihi wasallam menciumnya sementara beliau sedang berpuasa, dan mengisap lidahnya. Ibnu Al A'rabi berkata; sanad ini tidak shahih. "},"1974":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ حَدَّثَنَا أَبُو أَحْمَدَ يَعْنِي الزُّبَيْرِيَّ أَخْبَرَنَا إِسْرَائِيلُ عَنْ أَبِي الْعَنْبَسِ عَنْ الْأَغَرِّ عَنْ أَبِي هُرَيْرَةَأَنَّ رَجُلًا سَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْمُبَاشَرَةِ لِلصَّائِمِ فَرَخَّصَ لَهُ وَأَتَاهُ آخَرُ فَسَأَلَهُ فَنَهَاهُ فَإِذَا الَّذِي رَخَّصَ لَهُ شَيْخٌ وَالَّذِي نَهَاهُ شَابٌّ","id":"Telah menceritakan kepada kami [Nashr bin Ali], telah menceritakan kepada kami [Abu Ahmad yaitu Az Zubairi], telah mengabarkan kepada kami [Israil] dari [Abu Al 'Anbas] dari [Al Aghar] dari [Abu Hurairah] bahwa seoerang laki-laki bertanya kepada Nabi shallallahu 'alaihi wasallam mengenai cumbuan orang yang berpuasa, lalu beliau memberikan keringanan kepadanya. Dan orang yang lain datang kepada beliau dan bertanya mengenainya, lalu beliau melarangnya. Ternyata orang yang beliau beri keringanan adalah orang yang sudah tua, sedangkan orang yang beliau larang adalah orang yang masih muda. "},"1975":{"ar":"حَدَّثَنَا الْقَعْن��بِيُّ عَنْ مَالِكٍ ح و حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ إِسْحَقَ الْأَذْرَمِيُّ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ مَالِكٍ عَنْ عَبْدِ رَبِّهِ بْنِ سَعِيدٍ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ بْنِ هِشَامٍ عَنْ عَائِشَةَ وَأُمِّ سَلَمَةَ زَوْجَيْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُمَا قَالَتَا كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصْبِحُ جُنُبًا قَالَ عَبْدُ اللَّهِ الْأَذْرَمِيُّ فِي حَدِيثِهِ فِي رَمَضَانَ مِنْ جِمَاعٍ غَيْرِ احْتِلَامٍ ثُمَّ يَصُومُ قَالَ أَبُو دَاوُد وَمَا أَقَلَّ مَنْ يَقُولُ هَذِهِ الْكَلِمَةَ يَعْنِي يُصْبِحُ جُنُبًا فِي رَمَضَانَ وَإِنَّمَا الْحَدِيثُ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصْبِحُ جُنُبًا وَهُوَ صَائِمٌ","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik], dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Abdullah bin Muhammad bin Ishaq Al Adzrami], telah menceritakan kepada kami [Abdurrahman bin Mahdi] dari [Malik] dari [Abdu Rabbih bin Sa'id] dari [Abu Bakr bin Abdurrahman bin Al Harits bin Hisyam] dari [Aisyah] dan [Ummu Salamah] isteri Nabi shallallahu 'alaihi wasallam bahwa mereka berdua mengatakan; Rasulullah shallallahu 'alaihi wasallam pernah pada suatu pagi dalam keadaan junub. Abdulllah bin Al Adzrami dalam haditsnya, pada Bulan Ramadhan karena jima' bukan karena mimpi, kemudian beliau berpuasa. Abu Daud berkata; betapa sedikit orang yang mengucapkan kata ini yaitu pada suatu pagi dalam keadaan junub pada Bulan Ramadhan. Sesungguhnya hadits tersebut adalah; bahwa Nabi shallallahu 'alaihi wasallam pada suatu pagi dalam keadaan junub, sementara beliau sedang berpuasa. "},"1976":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ يَعْنِي الْقَعْنَبِيَّ عَنْ مَالِكٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ مَعْمَرٍ الْأَنْصَارِيِّ عَنْ أَبِي يُونُسَ مَوْلَى عَائِشَةَ عَنْ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ رَجُلًا قَالَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ وَاقِفٌ عَلَى الْبَابِ يَا رَسُولَ اللَّهِ إِنِّي أُصْبِحُ جُنُبًا وَأَنَا أُرِيدُ الصِّيَامَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا أُصْبِحُ جُنُبًا وَأَنَا أُرِيدُ الصِّيَامَ فَأَغْتَسِلُ وَأَصُومُ فَقَالَ الرَّجُلُ يَا رَسُولَ اللَّهِ إِنَّكَ لَسْتَ مِثْلَنَا قَدْ غَفَرَ اللَّهُ لَكَ مَا تَقَدَّمَ مِنْ ذَنْبِكَ وَمَا تَأَخَّرَ فَغَضِبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ وَاللَّهِ إِنِّي لَأَرْجُو أَنْ أَكُونَ أَخْشَاكُمْ لِلَّهِ وَأَعْلَمَكُمْ بِمَا أَتَّبِعُ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah Al Qa'nabi] dari [Malik] dari [Abdullah bin Abdurrahman bin Ma'mar Al Anshari] dari [Abu Yunus] mantan budak Aisyah, dari [Aisyah] isteri Nabi shallallahu 'alaihi wasallam bahwa seorang laki-laki berkata kepada Rasulullah shallallahu 'alaihi wasallam sementara beliau berdiri di depan pintu; wahai Rasulullah sesungguhnya saya pada suatu pagi dalam keadaan junub dan saya ingin berpuasa. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dan aku pernah pada suatu pagi dalam keadaan junub dan ingin berpuasa, lalu aku mandi dan berpuasa.\" Kemudian orang tersebut berkata; wahai Rasulullah, sesungguhnya engkau tidak seperti kami, Allah telah mengampuni dosamu yang telah lalu dan yang akan datang. Kemudian Rasulullah shallallahu 'alaihi wasallam marah dan berkata: \"Demi Allah aku berharap menjadi orang yang paling takut diantara kalian kepada Allah, dan orang yang paling mengerti apa yang aku ikuti.\""},"1977":{"ar":"حَدَّثَنَا مُسَدَّدٌ وَمُحَمَّدُ بْنُ عِيسَى الْمَعْنَى قَالَا حَدَّثَنَا سُفْيَانُ قَالَ مُسَدَّدٌ حَدَّثَنَا الزُّهْرِيُّ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ قَالَأَتَى رَجُلٌ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ هَلَكْتُ فَقَالَ مَا شَأْنُكَ قَالَ وَقَعْتُ عَلَى امْرَأَتِي فِي رَمَضَانَ قَالَ فَهَلْ تَجِدُ مَا تُعْتِقُ رَقَبَةً قَالَ لَا قَالَ فَهَلْ تَسْتَطِيعُ أَنْ تَصُومَ شَهْرَيْنِ مُتَتَابِعَيْنِ قَالَ لَا قَالَ فَهَلْ تَسْتَطِيعُ أَنْ تُطْعِمَ سِتِّينَ مِسْكِينًا قَالَ لَا قَالَ اجْلِسْ فَأُتِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِعَرَقٍ فِيهِ تَمْرٌ فَقَالَ تَصَدَّقْ بِهِ فَقَالَ يَا رَسُولَ اللَّهِ مَا بَيْنَ لَابَتَيْهَا أَهْلُ بَيْتٍ أَفْقَرُ مِنَّا فَضَحِكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى بَدَتْ ثَنَايَاهُ قَالَ فَأَطْعِمْهُ إِيَّاهُمْ و قَالَ مُسَدَّدٌ فِي مَوْضِعٍ آخَرَ أَنْيَابُهُحَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ بِهَذَا الْحَدِيثِ بِمَعْنَاهُ زَادَ الزُّهْرِيُّ وَإِنَّمَا كَانَ هَذَا رُخْصَةً لَهُ خَاصَّةً فَلَوْ أَنَّ رَجُلًا فَعَلَ ذَلِكَ الْيَوْمَ لَمْ يَكُنْ لَهُ بُدٌّ مِنْ التَّكْفِيرِ قَالَ أَبُو دَاوُد رَوَاهُ اللَّيْثُ بْنُ سَعْدٍ وَالْأَوْزَاعِيُّ وَمَنْصُورُ بْنُ الْمُعْتَمِرِ وَعِرَاكُ بْنُ مَالِكٍ عَلَى مَعْنَى ابْنِ عُيَيْنَةَ زَادَ فِيهِ الْأَوْزَاعِيُّ وَاسْتَغْفِرْ اللَّهَ","id":"Telah menceritakan kepada kami [Musaddad] dan [Muhammad bin Isa] secara makna, mereka berkata; telah menceritakan kepada kami [Sufyan], Musaddad berkata; telah menceritakan kepada kami [Az Zuhri] dari [Humaid bin Abdurrahman] dari [Abu Hurairah], ia berkata; seorang laki-laki datang kepada Nabi shallallahu 'alaihi wasallam dan berkata; aku telah binasa. Kemudian beliau berkata: \"Ada apa denganmu?\" Ia berkata; aku telah menggauli isteriku pada Bulan Ramadhan. Beliau berkata: \"Apakah engkau mendapatkan sesuatu untuk membebaskan budak?\" Ia berkata; tidak. Beliau berkata: \"Apakah engkau mampu untuk melakukan puasa dua bulan berturut-turut?\" Ia berkata; tidak. Beliau berkata: \"Apakah engkau mampu untuk memberi makan enam orang miskin?\" ia berkata; tidak. Beliau berkata: \"Duduklah.\" Kemudian diberikan kepada Nabi shallallahu 'alaihi wasallam satu kerangjang yang berisi kurma, kemudian beliau berkata; bersedekahlah dengan ini. Lalu orang tersebut berkata; wahai Rasulullah, tidak ada diantara dua daerah yang berbatu hitam (yaitu Madinah) keluarga yang lebih fakir daripada kami. Kemudian Rasulullah shallallahu 'alaihi wasallam tertawa hingga terlihat gigi-gigi serinya, beliau bersabda: \"Berikanlah makan mereka dengannya.\" Musaddad berkata pada tempat yang lain; gigi-gigi taring beliau. Telah menceritakan kepada kami [Al Hasan bin Ali], telah menceritakan kepada kami [Abdurrazzaq] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dengan hadits ini dengan maknanya. Az Zuhri menambahkan; dan sesungguhnya hal ini merupakan keringanan khusus untuknya, seandainya seseorang melakukan hal tersebut sekarang maka ia harus membayar kafarah. Abu Daud berkata; hadits tersebut diriwayatkan oleh [Al Laits bin Sa'd], [Al Auza'i], [Manshur bin Al Mu'tamir] dan ['Arak bin Malik] seperti makna hadits 'Uyainah. Al Auza'i menambahkan padanya; dan memohonlah ampunan kepada Allah!"},"1978":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَجُلًا أَفْطَرَ فِي رَمَضَانَ فَأَمَرَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُعْتِقَ رَقَبَةً أَوْ يَصُومَ شَهْرَيْنِ مُتَتَابِعَيْنِ أَوْ يُطْعِمَ سِتِّينَ مِسْكِينًا قَالَ لَا أَجِدُ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اجْلِسْ فَأُتِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِعَرَقٍ فِيهِ تَمْرٌ فَقَالَ خُذْ هَذَا فَتَصَدَّقْ بِهِ فَقَالَ يَا رَسُولَ اللَّهِ مَا أَحَدٌ أَحْوَجُ مِنِّي فَضَحِكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى بَدَتْ أَنْيَابُهُ وَقَالَ لَهُ كُلْهُقَالَ أَبُو دَاوُد رَوَاهُ ابْنُ جُرَيْجٍ عَنْ الزُّهْرِيِّ عَلَى لَفْظِ مَالِكٍ أَنَّ رَجُلًا أَفْطَرَ وَقَالَ فِيهِ أَوْ تُعْتِقَ رَقَبَةً أَوْ تَصُومَ شَهْرَيْنِ أَوْ تُطْعِمَ سِتِّينَ مِسْكِينًا حَدَّثَنَا جَعْفَرُ بْنُ مُسَافِرٍ حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ حَدَّثَنَا هِشَامُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ قَالَ جَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفْطَرَ فِي رَمَضَانَ بِهَذَا الْحَدِيثِ قَالَ فَأُتِيَ بِعَرَقٍ فِيهِ تَمْرٌ قَدْرُ خَمْسَةَ عَشَرَ صَاعًا وَقَالَ فِيهِ كُلْهُ أَنْتَ وَأَهْلُ بَيْتِكَ وَصُمْ يَوْمًا وَاسْتَغْفِرْ اللَّهَ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] dari [Malik] dari [Ibnu Syihab] dari [Humaid bin Abdurrahman] dari [Abu Hurairah] bahwa seorang laki-laki telah berbuka pada Bulan Ramadhan, kemudian Rasulullah shallallahu 'alaihi wasallam memerintahkannya agar memerdekakan budak atau berpuasa dua bulan berturut-turut atau memberi makan enam puluh orang miskin. Ia berkata; aku tidak mendapatinya. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Duduklah!\" Lalu Rasulullah shallallahu 'alaihi wasallam diberi keranjang yang berisi kurma, kemudian beliau berkata; ambillah ini. Dan bersedekahlah dengannya! Kemudian orang tersebut berkata; wahai Rasulullah, tidak ada seorang pun yang lebih membutuhkan daripada diriku. Maka Rasulullah shallallahu 'alaihi wasallam tertawa hingga nampak gigi-gigi taring beliau. Dan beliau berkata kepadanya; \"Makanlah!\" Abu Daud berkata; hadits tersebut diriwayatkan oleh [Ibnu Juraij] dari [Az Zuhri] seperti lafazh Malik; bahwa seorang laki-laki telah berbuka… dan padanya ia menyebutkan: \"atau engkau membebaskan budak, atau berpuasa dua bulan berturut-turut atau memberi makan enam orang miskin.\" Telah menceritakan kepada kami [Ja'far bin Musafir], telah menceritakan kepada kami [Ibnu Abu Fudaik], telah menceritakan kepada kami [Hisyam bin Sa'd] dari [Ibnu Syihab] dari [Abu Salamah bin Abdurrahman] dari [Abu Hurairah], ia berkata; seorang laki-laki telah datang kepada Nabi shallallahu 'alaihi wasallam, ia telah berbuka pada Bulan Ramadhan dengan hadits ini. Ia berkata; kemudian Rasulullah shallallahu 'alaihi wasallam diberi kerangjang yang berisi kurma seukuran lima belas sha'. Dalam hadits tersebut beliau mengatakan; makanlah engkau dan penghuni rumahmu dan berpuasalah satu hari dan mintalah ampun kepada Allah. "},"1979":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ الْمَهْرِيُّ أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ أَنَّ عَبْدَ الرَّحْمَنِ بْنَ الْقَاسِمِ حَدَّثَهُ أَنَّ مُحَمَّدَ بْنَ جَعْفَرِ بْنِ الزُّبَيْرِ حَدَّثَهُ أَنَّ عَبَّادَ بْنَ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ حَدَّثَهُ أَنَّهُ سَمِعَ عَائِشَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَقُولُأَتَى رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْمَسْجِدِ فِي رَمَضَانَ فَقَالَ يَا رَسُولَ اللَّهِ احْتَرَقْتُ فَسَأَلَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا شَأْنُهُ قَالَ أَصَبْتُ أَهْلِي قَالَ تَصَدَّقْ قَالَ وَاللَّهِ مَا لِي شَيْءٌ وَلَا أَقْدِرُ عَلَيْهِ قَالَ اجْلِسْ فَجَلَسَ فَبَيْنَمَا هُوَ عَلَى ذَلِكَ أَقْبَلَ رَجُلٌ يَسُوقُ حِمَارًا عَلَيْهِ طَعَامٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيْنَ الْمُحْتَرِقُ آنِفًا فَقَامَ الرَّجُلُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَصَدَّقْ بِهَذَا فَقَالَ يَا رَسُولَ اللَّهِ أَعَلَى غَيْرِنَا فَوَاللَّهِ إِنَّا لَجِيَاعٌ مَا لَنَا شَيْءٌ قَالَ كُلُوهُحَدَّثَنَا مُحَمَّدُ بْنُ عَوْفٍ حَدَّثَنَا سَعِيدُ بْنُ أَبِي مَرْيَمَ حَدَّثَنَا ابْنُ أَبِي الزِّنَادِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ عَنْ مُحَمَّدِ بْنِ جَعْفَرِ بْنِ الزُّبَيْرِ عَنْ عَبَّادِ بْنِ عَبْدِ اللَّهِ عَنْ عَائِشَةَ بِهَذِهِ الْقِصَّةِ قَالَ فَأُتِيَ بِعَرَقٍ فِيهِ عِشْرُونَ صَاعًا","id":"Telah menceritakan kepada kami [Sulaiman bin Daud Al Mahri], telah mengabarkan kepada kami [Ibnu Wahb], telah mengabarkan kepadaku ['Amr bin Al Harits] bahwa [Abdurrahman bin Al Qasim] telah menceritakan kepada bahwa [Muhammad bin Ja'far bin Az Zubair] telah menceritakan kepadanya bahwa ['Abbad bin Abdullah bin Az Zubair] telah menceritakan kepadanya bahwa ia mendengar [Aisyah] isteri Nabi shallallahu 'alaihi wasallam berkata; seorang laki-laki telah datang kepada Nabi shallallahu 'alaihi wasallam di Masjid pada Bulan Ramadhan, kemudian berkata; wahai Rasulullah, aku telah melakukan dosa yang akan mengakibatkan terbakar di neraka. Kemudian Nabi shallallahu 'alaihi wasallam bertanya kepadanya; kenapa engkau? Ia berkata; aku telah mencampuri isteriku. Beliau berkata: \"Bersedekahlah!\" Ia berkata; demi Allah, aku tidak memiliki sesuatu, dan tidak mampu melakukannya. Beliau berkata: \"Duduklah!\" Kemudian orang tersebut duduk, tatkala ia dalam keadaan seperti itu terdapat seorang laki-laki yang menuntun onta yang membawa makanan. Kemudian Rasulullah shallallahu 'alaihi wasallam berkata; \"Dimanakah orang yang telah melakukan dosa tadi?\" kemudian terdapat seorang laki-laki yang berdiri, lalu Rasulullah shallallahu 'alaihi wasallam berkata: \"Bersedekahlah dengan ini!\" Apakah aku harus bersedekah kepada selainku? Demi Allah kami adalah orang-orang yang lapar, kami tidak memiliki sesuatu. Beliau berkata: \"Makanlah!\" Telah menceritakan kepada kami [Muhammad bin 'Auf], telah menceritakan kepada kami [Sa'id bin Abu Maryam], telah menceritakan kepada kami [Ibnu Abu Az Zinad], dari [Abdurrahman bin Al Harits] dari [Muhammad bin Ja'far bin Az Zubair] dari ['Abbad bin Abdullah], dari [Aisyah] dengan kisah ini. Ia berkata; kemudian beliau diberi sebuah keranjang yang berisi dua puluh sha' kurma. "},"1980":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا شُعْبَةُ ح و حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ قَالَ أَخْبَرَنَا شُعْبَةُ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ عُمَارَةَ بْنِ عُمَيْرٍ عَنْ ابْنِ مُطَوِّسٍ عَنْ أَبِيهِ قَالَ ابْنُ كَثِيرٍ عَنْ أَبِي الْمُطَوِّسِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَفْطَرَ يَوْمًا مِنْ رَمَضَانَ فِي غَيْرِ رُخْصَةٍ رَخَّصَهَا اللَّهُ لَهُ لَمْ يَقْضِ عَنْهُ صِيَامُ الدَّهْرِحَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ سُفْيَانَ حَدَّثَنِي حَبِيبٌ عَنْ عُمَارَةَ عَنْ ابْنِ الْمُطَوِّسِ قَالَ فَلَقِيتُ ابْنَ الْمُطَوِّسِ فَحَدَّثَنِي عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَ حَدِيثِ ابْنِ كَثِيرٍ وَسُلَيْمَانَ قَالَ أَبُو دَاوُد وَاخْتُلِفَ عَلَى سُفْيَانَ وَشُعْبَةَ عَنْهُمَا ابْنُ الْمُطَوِّسِ وَأَبُو الْمُطَوِّسِ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb], ia berkata; telah menceritakan kepada kami [Syu'bah], dan telah diriwayatkan dengan jalur yang lain: Telah menceritakan kepada kami [Muhammad bin Katsir], ia berkata; telah mengabarkan kepada kami [Syu'bah] dari [Habib bin Abu Tsabit] dari ['Umarah bin 'Umair] dari [Ibnu Muthawwis] dari [ayahnya], [Ibnu Katsir] berkata; dari [Abu Al Muthawwis] dari [ayahnya], dari [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang berbuka satu hari pada Bulan Ramadhan bukan karena sebuah rukhshah (keringanan) yang telah Allah berikan kepadanya, maka puasa satu tahun tidaklah mampu menggantikannya.\" Telah menceritakan kepada kami [Ahmad bin Hanbal], telah menceritakan kepada kami [Yahya bin Sa'id] dari [Sufyan], telah menceritakan kepadaku [Habib] dari ['Umarah] dari [Ibnu Al Muthawwis], ia berkata; kemudian aku bertemu dengan [Ibnu Al Muthawwis] dan ia menceritakan kepadaku dari [ayahnya], dari [Abu Hurairah], ia berkata; Nabi shallallahu 'alaihi wasallam bersabda:... Seperti hadits Ibnu Katsir dan Sulaiman. Abu Daud berkata; dan telah diperselisihkan riwayat dari Sufyan dan Syu'bah: Ibnu Al Muthawwis serta Abu Al Muthawwis."},"1981":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ أَيُّوبَ وَحَبِيبٍ وَهِشَامٍ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ قَالَجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي أَكَلْتُ وَشَرِبْتُ نَاسِيًا وَأَنَا صَائِمٌ فَقَالَ اللَّهُ أَطْعَمَكَ وَسَقَاكَ","id":"Telah menceritakan kepada kami [Musa bin Isma'il], telah menceritakan kepada kami [Hammad] dari [Ayyub] dan [Habib] serta [Hisyam], dari [Muhammad bin Sirin] dari [Abu Hurairah], ia berkata; seseorang telah datang kepada Nabi shallallahu 'alaihi wasallam dan berkata; wahai Rasulullah, sesungguhnya aku telah makan dan minum karena lupa sementara aku sedang berpuasa. Kemudian beliau berkata: \"Allah telah memberimu makan dan minum.\""},"1982":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ أَنَّهُ سَمِعَ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا تَقُولُإِنْ كَانَ لَيَكُونُ عَلَيَّ الصَّوْمُ مِنْ رَمَضَانَ فَمَا أَسْتَطِيعُ أَنْ أَقْضِيَهُ حَتَّى يَأْتِيَ شَعْبَانُ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah Al Qa'nabi], dari [Malik] dari [Yahya bin Sa'id] dari [Abu Salamah bin Abdurrahman] bahwa ia telah mendengar [Aisyah] radliallahu 'anha berkata; sesungguhnya aku berkewajiban melakukan puasa Ramadhan dan aku tidak mampu melakukannya hingga datang Bulan Sya'ban. "},"1983":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي جَعْفَرٍ عَنْ مُحَمَّدِ بْنِ جَعْفَرِ بْنِ الزُّبَيْرِ عَنْ عُرْوَةَ عَنْ عَائِشَةَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ مَاتَ وَعَلَيْهِ صِيَامٌ صَامَ عَنْهُ وَلِيُّهُ قَالَ أَبُو دَاوُد هَذَا فِي النَّذْرِ وَهُوَ قَوْلُ أَحْمَدَ بْنِ حَنْبَلٍ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih], telah menceritakan kepada kami [Ibnu Wahb], telah mengabarkan kepadaku ['Amr bin Al Harits] dari ['Ubaidullah bin Abu Ja'far] dari [Muhammad bin Ja'far bin Az Zubair] dari ['Urwah] dari [Aisyah] bahwa Nabi shallallahu 'alaihi wasallam berkata: \"Barangsiapa yang meninggal dalam keadaan berkewajiban melakukan puasa, maka walinya berpuasa untuknya.\" Abu Daud berkata; hal ini mengenai puasa nadzar, dan hal tersebut adalah pendapat Ahmad bin Hanbal. "},"1984":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ أَبِي حُصَيْنٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَ إِذَا مَرِضَ الرَّجُلُ فِي رَمَضَانَ ثُمَّ مَاتَ وَلَمْ يَصُمْ أُطْعِمَ عَنْهُ وَلَمْ يَكُنْ عَلَيْهِ قَضَاءٌ وَإِنْ كَانَ عَلَيْهِ نَذْرٌ قَضَى عَنْهُ وَلِيُّهُ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir], telah mengabarkan kepada kami [Sufyan] dari [Abu Hushain] dari [Sa'id bin Jubair] dari [Ibnu Abbas], ia berkata; apabila seseorang sakit pada Bulan Ramadhan kemudian meninggal dan belum melakukan puasa maka diberikan makan untuknya dan ia tidak berkewajiban untuk mengqadha`, dan apabila ia memiliki kewajiban nadzar maka walinya yang mengqadha` untuknya. "},"1985":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ وَمُسَدَّدٌ قَالَا حَدَّثَنَا حَمَّادٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّ حَمْزَةَ الْأَسْلَمِيَّ سَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي رَجُلٌ أَسْرُدُ الصَّوْمَ أَفَأَصُومُ فِي السَّفَرِ قَالَ صُمْ إِنْ شِئْتَ وَأَفْطِرْ إِنْ شِئْتَ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb], serta [Musaddad], mereka berkata; telah menceritakan kepada kami [Hammad], dari [Hisyam bin 'Urwah] dari [ayahnya], dari [Aisyah] bahwa Hamzah Al Aslami telah bertanya kepada Nabi shallallahu 'alaihi wasallam, ia berkata; wahia Rasulullah, saya adalah seorang laki-laki yang melakukan puasa secara berturut-turut, apakah saya boleh berpuasa ketika sedang bersafar? Beliau berkata: \"Berpuasalah jika engkau menghendaki dan berbukalah jika engkau menghendaki!\""},"1986":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْمَجِيدِ الْمَدَنِيُّ قَالَ سَمِعْتُ حَمْزَةَ بْنَ مُحَمَّدِ بْنِ حَمْزَةَ الْأَسْلَمِيَّ يَذْكُرُ أَنَّ أَبَاهُ أَخْبَرَهُ عَنْ جَدِّهِ قَالَ قُلْتُيَا رَسُولَ اللَّهِ إِنِّي صَاحِبُ ظَهْرٍ أُعَالِجُهُ أُسَافِرُ عَلَيْهِ وَأَكْرِيهِ وَإِنَّهُ رُبَّمَا صَادَفَنِي هَذَا الشَّهْرُ يَعْنِي رَمَضَانَ وَأَنَا أَجِدُ الْقُوَّةَ وَأَنَا شَابٌّ وَأَجِدُ بِأَنْ أَصُومَ يَا رَسُولَ اللَّهِ أَهْوَنَ عَلَيَّ مِنْ أَنْ أُؤَخِّرَهُ فَيَكُونُ دَيْنًا أَفَأَصُومُ يَا رَسُولَ اللَّهِ أَعْظَمُ لِأَجْرِي أَوْ أُفْطِرُ قَالَ أَيُّ ذَلِكَ شِئْتَ يَا حَمْزَةُ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad An Nufaili], telah menceritakan kepada kami [Muhammad bin Abdul Majid Al Madani], ia berkata; saya mendengar [Hamzah bin Muhammad bin Hamzah Al Aslami] menyebutkan bahwa [ayahnya] telah mengabarkan kepadanya dari [kakeknya], ia berkata; aku katakan; wahai Rasulullah, aku adalah orang memiliki hewan kendaraan, aku menggunakannya, bersafar dengan mengendarainya serta menyewakannya. Terkadang aku menemui Bulan Ramadhan ini, aku kuat dan masih muda, serta saya dapati bahwa berpuasa lebih ringan bagiku daripada menundanya sehingga menjadi hutang wahai Rasulullah. Maka apakah dengan berpuasa pahalaku lebih besar atau aku berbuka wahai Rasulullah? Beliau berkata: \"Apapun yang engkau kehendaki, wahai Hamzah.\""},"1987":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ مَنْصُورٍ عَنْ مُجَاهِدٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ قَالَخَرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْمَدِينَةِ إِلَى مَكَّةَ حَتَّى بَلَغَ عُسْفَانَ ثُمَّ دَعَا بِإِنَاءٍ فَرَفَعَهُ إِلَى فِيهِ لِيُرِيَهُ النَّاسَ وَذَلِكَ فِي رَمَضَانَ فَكَانَ ابْنُ عَبَّاسٍ يَقُولُ قَدْ صَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَفْطَرَ فَمَنْ شَاءَ صَامَ وَمَنْ شَاءَ أَفْطَرَ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Abu 'Uwanah], dari [Manshur], dari [Mujahid] dari [Thawus] dari [Ibnu Abbas], ia berkata; Nabi shallallahu 'alaihi wasallam keluar dari Madinah menuju ke Mekkah hinggga sampai ke 'Usfan, kemudian beliau meminta bejana dan mengangkatnya ke mulut beliau agar orang-orang melihatnya. Dan hal tersebut terjadi pada Bulan Ramadhan. Ibnu Abbas berkata; Nabi shallallahu 'alaihi wasallam telah berpuasa dan berbuka, barangsiapa yang berkehendak maka ia berpuasa dan barangsiapa yang berkehendak maka ia berbuka. "},"1988":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زَائِدَةُ عَنْ حُمَيْدٍ الطَّوِيلِ عَنْ أَنَسٍ قَالَسَافَرْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي رَمَضَانَ فَصَامَ بَعْضُنَا وَأَفْطَرَ بَعْضُنَا فَلَمْ يَعِبْ الصَّائِمُ عَلَى الْمُفْطِرِ وَلَا الْمُفْطِرُ عَلَى الصَّائِمِ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus], telah menceritakan kepada kami [Zaidah] dari [Humaid Ath Thawil], dari [Anas], ia berkata; kami pernah bersafar bersama Rasulullah shallallahu 'alaihi wasallam pada Bulan Ramadhan, lalu sebagian kami ada yang berpuasa dan sebagian dari kami ada yang berbuka, dan orang yang berpuasa tidak mencela orang yang berbuka dan orang yang berbuka tidak mencela orang yang berpuasa. "},"1989":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ وَوَهْبُ بْنُ بَيَانٍ الْمَعْنَى قَالَا حَدَّثَنَا ابْنُ وَهْبٍ حَدَّثَنِي مُعَاوِيَةُ عَنْ رَبِيعَةَ بْنِ يَزِيدَ أَنَّهُ حَدَّثَهُ عَنْ قَزَعَةَ قَالَأَتَيْتُ أَبَا سَعِيدٍ الْخُدْرِيَّ وَهُوَ يُفْتِي النَّاسَ وَهُمْ مُكِبُّونَ عَلَيْهِ فَانْتَظَرْتُ خَلْوَتَهُ فَلَمَّا خَلَا سَأَلْتُهُ عَنْ صِيَامِ رَمَضَانَ فِي السَّفَرِ فَقَالَ خَرَجْنَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي رَمَضَانَ عَامَ الْفَتْحِ فَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصُومُ وَنَصُومُ حَتَّى بَلَغَ مَنْزِلًا مِنْ الْمَنَازِلِ فَقَالَ إِنَّكُمْ قَدْ دَنَوْتُمْ مِنْ عَدُوِّكُمْ وَالْفِطْرُ أَقْوَى لَكُمْ فَأَصْبَحْنَا مِنَّا الصَّائِمُ وَمِنَّا الْمُفْطِرُ قَالَ ثُمَّ سِرْنَا فَنَزَلْنَا مَنْزِلًا فَقَالَ إِنَّكُمْ تُصَبِّحُونَ عَدُوَّكُمْ وَالْفِطْرُ أَقْوَى لَكُمْ فَأَفْطِرُوا فَكَانَتْ عَزِيمَةً مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ أَبُو سَعِيدٍ ثُمَّ لَقَدْ رَأَيْتُنِي أَصُومُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَبْلَ ذَلِكَ وَبَعْدَ ذَلِكَ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih], dan [Wahb bin Bayan] secara makna, mereka berkata; telah menceritakan kepada kami [Ibnu Wahb], telah menceritakan kepadaku [Mu'awiyah] dari [Rabi'ah bin Yazid] bahwa ia telah menceritakan kepadanya dari [Qaza'ah], ia berkata; aku datang kepada [Abu Sa'id Al Khudri] dan beliau sedang berfatwa kepada manusia sementara mereka berkumpul di hadapannya, maka aku menunggu kesendiriannya. Kemudian tatkala ia telah sendirian aku bertanya kepadanya mengenai puasa Ramadhan dalam perjalanan. Lalu ia berkata; kami pernah keluar bersama Nabi shallallahu 'alaihi wasallam pada Bulan Ramadhan pada tahun penaklukan Mekkah, dan Rasulullah shallallahu 'alaihi wasallam berpuasa dan kami pun berpuasa hingga beliau sampai sebuah tempat diantara tempat-tempat persinggahan. Kemudian beliau berkata; sesungguhnya kalian telah mendekati musuh dan berbuka adalah lebih kuat untuk kalian. Maka pada paginya diantara kami ada yang berpuasa dan diantara kami ada yang berbuka, peperangan tersebut merupakan tekad Rasulullah shallallahu wa'alaihi wa sallam. Abu Sa'id berkata; aku lihat diriku melakukan puasa bersama Nabi shallallahu 'alaihi wasallam sebelum itu dan setelah itu. "},"1990":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا شُعْبَةُ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ يَعْنِي ابْنَ سَعْدِ بْنِ زُرَارَةَ عَنْ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَسَنٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى رَجُلًا يُظَلَّلُ عَلَيْهِ وَالزِّحَامُ عَلَيْهِ فَقَالَ لَيْسَ مِنْ الْبِرِّ الصِّيَامُ فِي السَّفَرِ","id":"Telah menceritakan kepada kami [Abu Al Walid Ath Thayalisi], telah menceritakan kepada kami [Syu'bah] dari [Muhammad bin Abdurrahman bin Sa'd bin Zurarah] dari [Muhammad bin 'Amr bin Hasan] dari [Jabir bin Abdullah] bahwa Rasulullah shallallahu 'alaihi wasallam pernah melihat seorang laki-laki yang dinaungi dan orang-orang mengerumuninya, lalu beliau berkata: \"Bukanlah termasuk kebaikan berpuasa dalam perjalanan.\""},"1991":{"ar":"حَدَّثَنَا شَيْبَانُ بْنُ فَرُّوخَ حَدَّثَنَا أَبُو هِلَالٍ الرَّاسِبِيُّ حَدَّثَنَا ابْنُ سَوَادَةَ الْقُشَيْرِيُّ عَنْ أَنَسِ بْنِ مَالِكٍ رَجُلٌ مِنْ بَنِي عَبْدِ اللَّهِ بْنِ كَعْبٍ إِخْوَةِ بَنِي قُشَيْرٍ قَالَأَغَارَتْ عَلَيْنَا خَيْلٌ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَانْتَهَيْتُ أَوْ قَالَ فَانْطَلَقْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَأْكُلُ فَقَالَ اجْلِسْ فَأَصِبْ مِنْ طَعَامِنَا هَذَا فَقُلْتُ إِنِّي صَائِمٌ قَالَ اجْلِسْ أُحَدِّثْكَ عَنْ الصَّلَاةِ وَعَنْ الصِّيَامِ إِنَّ اللَّهَ تَعَالَى وَضَعَ شَطْرَ الصَّلَاةِ أَوْ نِصْفَ الصَّلَاةِ وَالصَّوْمَ عَنْ الْمُسَافِرِ وَعَنْ الْمُرْضِعِ أَوْ الْحُبْلَى وَاللَّهِ لَقَدْ قَالَهُمَا جَمِيعًا أَوْ أَحَدَهُمَا قَالَ فَتَلَهَّفَتْ نَفْسِي أَنْ لَا أَكُونَ أَكَلْتُ مِنْ طَعَامِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Syaiban bin Farrukh], telah menceritakan kepada kami [Abu Hilal Ar Rasibi], telah menceritakan kepada kami [Ibnu Sawadah Al Qusyairi] dari [Anas bin Malik] mengatakan; terdapat seorang laki-laki dari Bani Abdullah bin Ka'bin saudara Bani Qusyair, ia berkata; para penunggang kuda Rasulullah shallallahu 'alaihi wasallam telah menyerang kaum kami, kemudian aku sampai -atau ia mengatakan; aku pergi- kepada Rasulullah shallallahu 'alaihi wasallam, sementara beliau sedang makan. Kemudian beliau berkata: \"Duduklah dan makanlah sebagian makanan kami ini!\" kemudian aku katakan; saya sedang berpuasa. Beliau berkata: \"Duduklah! Aku ceritakan kepadamu mengenai shalat dan puasa. Sesungguhnya Allah ta'ala telah menggugurkan setengah shalat serta puasa dari seorang musafir, wanita yang menyusui dan wanita yang hamil.\" Demi Allah, beliau telah mengatakan keduanya semua atau salah satu dari keduanya. Ia berkata; hatiku membisikkan agar aku tidak makan sebagian dari makanan Rasulullah shallallahu 'alaihi wasallam. "},"1992":{"ar":"حَدَّثَنَا مُؤَمَّلُ بْنُ الْفَضْلِ حَدَّثَنَا الْوَلِيدُ حَدَّثَنَا سَعِيدُ بْنُ عَبْدِ الْعَزِيزِ حَدَّثَنِي إِسْمَعِيلُ بْنُ عُبَيْدِ اللَّهِ حَدَّثَتْنِي أُمُّ الدَّرْدَاءِ عَنْ أَبِي الدَّرْدَاءِ قَالَ خَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَعْضِ غَزَوَاتِهِ فِي حَرٍّ شَدِيدٍ حَتَّى إِنَّ أَحَدَنَا لَيَضَعُ يَدَهُ عَلَى رَأْسِهِ أَوْ كَفَّهُ عَلَى رَأْسِهِ مِنْ شِدَّةِ الْحَرِّ مَا فِينَا صَائِمٌ إِلَّا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَبْدُ اللَّهِ بْنُ رَوَاحَةَ","id":"Telah menceritakan kepada kami [Muammal bin Al Fadhl], telah menceritakan kepada kami [Al Walid], telah menceritakan kepada kami [Sa'id bin Abdul Aziz], telah menceritakan kepadaku [Isma'il bin 'Ubaidullah], telah menceritakan kepadaku [Ummu Ad Darda`] dari [Abu Darda`], ia berkata; kami pernah keluar bersama Rasulullah shallallahu 'alaihi wasallam dalam sebagian peperangan pada hari yang sangat panas hingga salah seorang diantara kami meletakkan tangannya atau telapak tangannya di atas kepalanya karena sangat panas. Tidak ada diantara kami yang berpuasa selain Rasulullah shallallahu 'alaihi wasallam, dan Abdullah bin Rawahah. "},"1993":{"ar":"حَدَّثَنَا حَامِدُ بْنُ يَحْيَى حَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ ح و حَدَّثَنَا عُقْبَةُ بْنُ مُكْرَمٍ حَدَّثَنَا أَبُو قُتَيْبَةَ الْمَعْنَى قَالَا حَدَّثَنَا عَبْدُ الصَّمَدِ بْنُ حَبِيبِ بْنِ عَبْدِ اللَّهِ الْأَزْدِيُّ حَدَّثَنِي حَبِيبُ بْنُ عَبْدِ اللَّهِ قَالَ سَمِعْتُ سِنَانَ بْنَ سَلَمَةَ بْنِ الْمُحَبَّقِ الْهُذَلِيِّ يُحَدِّثُ عَنْ أَبِيهِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كَانَتْ لَهُ حَمُولَةٌ تَأْوِي إِلَى شِبَعٍ فَلْيَصُمْ رَمَضَانَ حَيْثُ أَدْرَكَهُ حَدَّثَنَا نَصْرُ بْنُ الْمُهَاجِرِ حَدَّثَنَا عَبْدُ الصَّمَدِ بْنُ عَبْدِ الْوَارِثِ حَدَّثَنَا عَبْدُ الصَّمَدِ بْنُ حَبِيبٍ قَالَ حَدَّثَنِي أَبِي عَنْ سِنَانِ بْنِ سَلَمَةَ عَنْ سَلَمَةَ بْنِ الْمُحَبَّقِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَدْرَكَهُ رَمَضَانُ فِي السَّفَرِ فَذَكَرَ مَعْنَاهُ","id":"Telah menceritakan kepada kami [Hamid bin Yahya], telah menceritakan kepada kami [Hasyim bin Al Qasim], dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami ['Uqbah bin Mukram], telah menceritakan kepada kami [Abu Qutaibah] secara makna, mereka berdua berkata; telah menceritakan kepada kami [Abdushshamad bin Habib bin Abdullah Al Azdi], telah menceritakan kepadaku [Habib bin Abdullah], ia berkata; saya mendengar [Sinan bin Salamah bin Al Muhabbaq Al Hudzali], menceritakan dari [ayahnya], ia berkata; Rasulullah shallallahu wa'alaihi wa sallam bersabda: \"Barangsiapa yang memiliki bekal dan mampu singgah dalam keadaan kenyang, maka hendaknya ia berpuasa Ramadhan dimana pun ia mendapatinya.\" Telah menceritakan kepada kami [Nashr bin Al Muhajir], telah menceritakan kepada kami [Abdushshamad bin Abdul Warits], telah menceritakan kepada kami [Abdushshamad bin Habib], ia berkata; telah menceritakan kepadaku [ayahku], dari [Sinan bin Salamah] dari [Salamah bin Al Muhabbaq], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang mendapati Bulan Ramadhan ketika dalam perjalanan….\" Kemudian ia menyebutkan hadits tersebut secara makna. "},"1994":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ يَزِيدَ ح و حَدَّثَنَا جَعْفَرُ بْنُ مُسَافِرٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَحْيَى الْمَعْنَى حَدَّثَنِي سَعِيدُ بْنُ أَبِي أَيُّوبَ وَزَادَ جَعْفَرٌ وَاللَّيْثُ حَدَّثَنِي يَزِيدُ بْنُ أَبِي حَبِيبٍ أَنَّ كُلَيْبَ بْنَ ذُهْلٍ الْحَضْرَمِيَّ أَخْبَرَهُ عَنْ عُبَيْدٍ قَالَ جَعْفَرٌ ابْنُ جَبْرٍ قَالَ كُنْتُ مَعَ أَبِي بَصْرَةَ الْغِفَارِيِّ صَاحِبِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفِينَةٍ مِنْ الْفُسْطَاطِ فِي رَمَضَانَ فَرُفِعَ ثُمَّ قُرِّبَ غَدَاهُ قَالَ جَعْفَرٌ فِي حَدِيثِهِ فَلَمْ يُجَاوِزْ الْبُيُوتَ حَتَّى دَعَا بِالسُّفْرَةِ قَالَ اقْتَرِبْ قُلْتُ أَلَسْتَ تَرَى الْبُيُوتَ قَالَ أَبُو بَصْرَةَ أَتَرْغَبُ عَنْ سُنَّةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ جَعْفَرٌ فِي حَدِيثِهِ فَأَكَلَ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Umar], telah menceritakan kepadaku [Abdullah bin Yazid], dan telah diriwayatkan dari jalur yang lain: Telah menceritakan kepada kami [Ja'far bin Musafir], telah menceritakan kepada kami [Abdullah bin Yahya] secara makna, telah menceritakan kepadaku [Sa'id bin Abu Ayyub] -dan [Ja'far] serta [Al Laits] menambahkan; telah menceritakan kepadaku [Yazid bin Abu Habib] - bahwa [Kulaib bin Dzuhail Al Hadhrami], telah mengabarkan kepadanya dari ['Ubaid], ia berkata; Ja'far bin Jabr berkata; aku pernah bersama [Abu Bashrah Al Ghifari] seorang sahabat Nabi shallallahu 'alaihi wasallam dalam sebuah kapal dari Al Fusthath pada Bulan Ramadhan, kemudian dihidangkan makan siangnya. Ja'far dalam haditsnya mengatakan; ia belum melewati rumah-rumah hingga ia meminta sufrah (makanan musafir). Ia berkata; mendekatlah. Aku katakan; bukankah engkau melihat rumah-rumah tersebut? Abu Bashrah mengatakan; apakah engkau membenci sunah Rasulullah shallallahu 'alaihi wasallam? Ja'far dalam haditsnya berkata; kemudian ia memakannya. "},"1995":{"ar":"حَدَّثَنَا عِيسَى بْنُ حَمَّادٍ أَخْبَرَنَا اللَّيْثُ يَعْنِي ابْنَ سَعْدٍ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ أَبِي الْخَيْرِ عَنْ مَنْصُورٍ الْكَلْبِيِّ أَنَّ دِحْيَةَ بْنَ خَلِيفَةَ خَرَجَ مِنْ قَرْيَةٍ مِنْ دِمَشْقَ مَرَّةً إِلَى قَدْرِ قَرْيَةِ عُقْبَةَ مِنْ الْفُسْطَاطِ وَذَلِكَ ثَلَاثَةُ أَمْيَالٍ فِي رَمَضَانَ ثُمَّ إِنَّهُ أَفْطَرَ وَأَفْطَرَ مَعَهُ نَاسٌ وَكَرِهَ آخَرُونَ أَنْ يُفْطِرُوا فَلَمَّا رَجَعَ إِلَى قَرْيَتِهِ قَالَ وَاللَّهِ لَقَدْ رَأَيْتُ الْيَوْمَ أَمْرًا مَا كُنْتُ أَظُنُّ أَنِّي أَرَاهُ إِنَّ قَوْمًا رَغِبُوا عَنْ هَدْيِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَصْحَابِهِ يَقُولُ ذَلِكَ لِلَّذِينَ صَامُوا ثُمَّ قَالَ عِنْدَ ذَلِكَ اللَّهُمَّ اقْبِضْنِي إِلَيْكَ","id":"Telah menceritakan kepada kami [Isa bin Hammad], telah mengabarkan kepada kami [Al Laits bin Sa'd] dari [Yazid bin Abu Habib] dari [Abu Al Khair], dari [Manshur Al Kalbi] bahwa [Dahyah bin Khalifah] suatu kali keluar dari sebuah desa dari Damaskus menuju tempat yang berjarak seukuran menuju desa 'Uqbah di Al Fusthath, dan hal tersebut jaraknya adalah tiga mil, pada Bulan Ramadhan. Kemudian ia berbuka dan orang-orang pun berbuka berasamanya. Sementara yang lainnya tidak senang untuk berbuka. Kemudian tatkala telah kembali ke desanya ia berkata; demi Allah sungguh aku pada hari ini telah melihat suatu perkara yagn tidak aku sangka, aku melihat beberapa orang telah membenci petunjuk Rasulullah shallallahu 'alaihi wasallam dan para sahabatnya. Ia mengatakan hal tersebut kepada orang-orang yang berpuasa, kemudian pada saat itu ia berkata; ya Allah, matikan aku menuju kepadaMu! "},"1996":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا الْمُعْتَمِرُ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍأَنَّ ابْنَ عُمَرَ كَانَ يَخْرُجُ إِلَى الْغَابَةِ فَلَا يُفْطِرُ وَلَا يَقْصِرُ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Al Mu'tamir] dari ['Ubaidullah] dari [Nafi'] bahwa [Ibnu Umar] pernah keluar menuju sebuah hutan dan tidak berbuka dan tidak mengqashar. "},"1997":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ الْمُهَلَّبِ بْنِ أَبِي حَبِيبَةَ حَدَّثَنَا الْحَسَنُ عَنْ أَبِي بَكْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَقُولَنَّ أَحَدُكُمْ إِنِّي صُمْتُ رَمَضَانَ كُلَّهُ وَقُمْتُهُ كُلَّهُ فَلَا أَدْرِي أَكَرِهَ التَّزْكِيَةَ أَوْ قَالَ لَا بُدَّ مِنْ نَوْمَةٍ أَوْ رَقْدَةٍ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Yahya] dari [Al Muhallab bin Abu Habibah], telah menceritakan kepada kami [Al Hasan] dari [Abu Bakrah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah salah seorang diantara kalian mengatakan aku pasti melakukan puasa Ramadhan seluruhnya dan akan melakukan shalat malam seluruhnya.\" Aku tidak mengetahui apakah beliau sika suka perekomendasian diri atau beliau mengatakan harus tidur terlebih dahulu. "},"1998":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ وَزُهَيْرُ بْنُ حَرْبٍ وَهَذَا حَدِيثُهُ قَالَا حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ أَبِي عُبَيْدٍ قَالَشَهِدْتُ الْعِيدَ مَعَ عُمَرَ فَبَدَأَ بِالصَّلَاةِ قَبْلَ الْخُطْبَةِ ثُمَّ قَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ صِيَامِ هَذَيْنِ الْيَوْمَيْنِ أَمَّا يَوْمُ الْأَضْحَى فَتَأْكُلُونَ مِنْ لَحْمِ نُسُكِكُمْ وَأَمَّا يَوْمُ الْفِطْرِ فَفِطْرُكُمْ مِنْ صِيَامِكُمْ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id], serta [Zuhair bin Harb], dan ini adalah haditsnya, mereka berdua mengatakan; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri], dari [Abu 'Ubaid], ia berkata; aku menghadiri 'Id bersama [Umar], beliau memulai shalat sebelum berkhutbah kemudian berkata; sesungguhnya Rasulullah shallallahu 'alaihi wasallam melarang dari berpuasa pada dua hari ini, adapun hari Adlha, maka kalian makan sebagian dari daging sembelihan kalian, adapun hari Fithri maka merupakan berbuka kalian dari puasa. "},"1999":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا عَمْرُو بْنُ يَحْيَى عَنْ أَبِيهِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ صِيَامِ يَوْمَيْنِ يَوْمِ الْفِطْرِ وَيَوْمِ الْأَضْحَى وَعَنْ لِبْسَتَيْنِ الصَّمَّاءِ وَأَنْ يَحْتَبِيَ الرَّجُلُ فِي الثَّوْبِ الْوَاحِدِ وَعَنْ الصَّلَاةِ فِي سَاعَتَيْنِ بَعْدَ الصُّبْحِ وَبَعْدَ الْعَصْرِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il], telah menceritakan kepada kami [Wuhaib], telah menceritakan kepada kami ['Amr bin Yahya] dari [ayahnya] dari [Abu Sa'id Al Khudri], ia berkata; Rasulullah shallallahu wa'alaihi wa sallam melarang berpuasa pada dua hari yaitu hari 'Idul Fithri dan hari 'Idul Adlha, dan melarang memakai dua pakaian shamma` (pakaian yang menutup dari atas hingga bawah dan tidak memiliki lubang keluar untuk tangan) dan duduk dengan melipat kaki tegak dan mengikat kaki tersebut dan pantatnya dengan satu kain, dan melarang melakukan shalat dalam dua waktu yaitu setelah Shalat Subuh dan setelah Shalat Ashar. "},"2000":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ يَزِيدَ بْنِ الْهَادِ عَنْ أَبِي مُرَّةَ مَوْلَى أُمِّ هَانِئٍأَنَّهُ دَخَلَ مَعَ عَبْدِ اللَّهِ بْنِ عَمْرٍو عَلَى أَبِيهِ عَمْرِو بْنِ الْعَاصِ فَقَرَّبَ إِلَيْهِمَا طَعَامًا فَقَالَ كُلْ فَقَالَ إِنِّي صَائِمٌ فَقَالَ عَمْرٌو كُلْ فَهَذِهِ الْأَيَّامُ الَّتِي كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْمُرُنَا بِإِفْطَارِهَا وَيَنْهَانَا عَنْ صِيَامِهَاقَالَ مَالِكٌ وَهِيَ أَيَّامُ التَّشْرِيقِ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah Al Qa'nabi], dari [Malik] dari [Yazid bin Al Had], dari [Abu Murrah] mantan budak Ummu Hani` bahwa ia ia bersama Abdullah bin 'Amr menemui ayahnya yaitu ['Amr bin Al 'Ash], kemudian ia mendekatkan makanan kepada keduanya lalu berkata; makanlah. Lalu Abu Murrah berkata; sesungguhnya saya sedang berpuasa. Kemudian 'Amr berkata; makanlah, ini adalah hari yang kami diperintahkan Rasulullah shallallahu 'alaihi wasallam agar berbuka dan melarang kami untuk melakukan puasa padanya. Malik berkata; hari-hari tersebut adalah hari-hari Tasyriq. "}};
